      END SUBROUTINE DWEPDF
      SUBROUTINE DWEPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE DOUBLE WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE DOUBLE WEIBULL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL REAL X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (C/2)*X*EXP(-ABS(X)**C)
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, CHAPTER 21
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO DWEPPF IS ',   &
             'OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO DWEPPF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      MINMAX=1
      IF(P.EQ.0.5)THEN
        PPF=0.0
      ELSEIF(P.LT.0.5)THEN
        ARG1=2.0*(0.5-P)
        CALL WEIPPF(ARG1,GAMMA,MINMAX,PPF)
        PPF=-PPF
      ELSE
        ARG1=2.0*(P-0.5)
        CALL WEIPPF(ARG1,GAMMA,MINMAX,PPF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DWEPPF
      SUBROUTINE DWERAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE DOUBLE WEIBULL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE DOUBLE WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NON E.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF DOUBLE WEIBULL ',   &
             'RANDOM NUMBERS IS NON-POSITIVE')
   15 FORMAT('***** ERROR--THE SPECIFIED VALUE OF GAMMA FOR THE ',   &
             'DOUBLE WEIBULL RANDOM NUMBERS IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N DOUBLE WEIBULL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL DWEPPF(X(I),GAMMA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DWERAN
      SUBROUTINE DXADD (X, IX, Y, IY, Z, IZ, IERROR)
!***BEGIN PROLOGUE  DXADD
!***PURPOSE  To provide double-precision floating-point arithmetic
!            with an extended exponent range.
!***LIBRARY   SLATEC
!***CATEGORY  A3D
!***TYPE      DOUBLE PRECISION (XADD-S, DXADD-D)
!***KEYWORDS  EXTENDED-RANGE DOUBLE-PRECISION ARITHMETIC
!***AUTHOR  Lozier, Daniel W., (NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY)
!           Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!     DOUBLE PRECISION X, Y, Z
!     INTEGER IX, IY, IZ
!
!                  FORMS THE EXTENDED-RANGE SUM  (Z,IZ) =
!                  (X,IX) + (Y,IY).  (Z,IZ) IS ADJUSTED
!                  BEFORE RETURNING. THE INPUT OPERANDS
!                  NEED NOT BE IN ADJUSTED FORM, BUT THEIR
!                  PRINCIPAL PARTS MUST SATISFY
!                  RADIX**(-2L).LE.ABS(X).LE.RADIX**(2L),
!                  RADIX**(-2L).LE.ABS(Y).LE.RADIX**(2L).
!
!***SEE ALSO  DXSET
!***REFERENCES  (NONE)
!***ROUTINES CALLED  DXADJ
!***COMMON BLOCKS    DXBLK2
!***REVISION HISTORY  (YYMMDD)
!   820712  DATE WRITTEN
!   881020  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXADD
      DOUBLE PRECISION X, Y, Z
      INTEGER IX, IY, IZ
      DOUBLE PRECISION RADIX, RADIXL, RAD2L, DLG10R
      INTEGER L, L2, KMAX
      COMMON /DXBLK2/ RADIX, RADIXL, RAD2L, DLG10R, L, L2, KMAX
      SAVE /DXBLK2/
      DOUBLE PRECISION S, T
!
!   THE CONDITIONS IMPOSED ON L AND KMAX BY THIS SUBROUTINE
! ARE
!     (1) 1 .LT. L .LE. 0.5D0*LOGR(0.5D0*DZERO)
!
!     (2) NRADPL .LT. L .LE. KMAX/6
!
!     (3) KMAX .LE. (2**NBITS - 4*L - 1)/2
!
! THESE CONDITIONS MUST BE MET BY APPROPRIATE CODING
! IN SUBROUTINE DXSET.
!
!***FIRST EXECUTABLE STATEMENT  DXADD
      IERROR=0
      IF (X.NE.0.0D0) GO TO 10
      Z = Y
      IZ = IY
      GO TO 220
   10 IF (Y.NE.0.0D0) GO TO 20
      Z = X
      IZ = IX
      GO TO 220
   20 CONTINUE
      IF (IX.GE.0 .AND. IY.GE.0) GO TO 40
      IF (IX.LT.0 .AND. IY.LT.0) GO TO 40
      IF (ABS(IX).LE.6*L .AND. ABS(IY).LE.6*L) GO TO 40
      IF (IX.GE.0) GO TO 30
      Z = Y
      IZ = IY
      GO TO 220
   30 CONTINUE
      Z = X
      IZ = IX
      GO TO 220
   40 I = IX - IY
!CCCC IF (I) 80, 50, 90
      IF(I.LT.0)GO TO 80
      IF(I.GT.0)GO TO 90
      IF (ABS(X).GT.1.0D0 .AND. ABS(Y).GT.1.0D0) GO TO 60
      IF (ABS(X).LT.1.0D0 .AND. ABS(Y).LT.1.0D0) GO TO 70
      Z = X + Y
      IZ = IX
      GO TO 220
   60 S = X/RADIXL
      T = Y/RADIXL
      Z = S + T
      IZ = IX + L
      GO TO 220
   70 S = X*RADIXL
      T = Y*RADIXL
      Z = S + T
      IZ = IX - L
      GO TO 220
   80 S = Y
      IS = IY
      T = X
      GO TO 100
   90 S = X
      IS = IX
      T = Y
  100 CONTINUE
!
!  AT THIS POINT, THE ONE OF (X,IX) OR (Y,IY) THAT HAS THE
! LARGER AUXILIARY INDEX IS STORED IN (S,IS). THE PRINCIPAL
! PART OF THE OTHER INPUT IS STORED IN T.
!
      I1 = ABS(I)/L
      I2 = MOD(ABS(I),L)
      IF (ABS(T).GE.RADIXL) GO TO 130
      IF (ABS(T).GE.1.0D0) GO TO 120
      IF (RADIXL*ABS(T).GE.1.0D0) GO TO 110
      J = I1 + 1
      T = T*RADIX**(L-I2)
      GO TO 140
  110 J = I1
      T = T*RADIX**(-I2)
      GO TO 140
  120 J = I1 - 1
      IF (J.LT.0) GO TO 110
      T = T*RADIX**(-I2)/RADIXL
      GO TO 140
  130 J = I1 - 2
      IF (J.LT.0) GO TO 120
      T = T*RADIX**(-I2)/RAD2L
  140 CONTINUE
!
!  AT THIS POINT, SOME OR ALL OF THE DIFFERENCE IN THE
! AUXILIARY INDICES HAS BEEN USED TO EFFECT A LEFT SHIFT
! OF T.  THE SHIFTED VALUE OF T SATISFIES
!
!       RADIX**(-2*L) .LE. ABS(T) .LE. 1.0D0
!
! AND, IF J=0, NO FURTHER SHIFTING REMAINS TO BE DONE.
!
      IF (J.EQ.0) GO TO 190
      IF (ABS(S).GE.RADIXL .OR. J.GT.3) GO TO 150
      IF (ABS(S).GE.1.0D0) GO TO (180, 150, 150), J
      IF (RADIXL*ABS(S).GE.1.0D0) GO TO (180, 170, 150), J
      GO TO (180, 170, 160), J
  150 Z = S
      IZ = IS
      GO TO 220
  160 S = S*RADIXL
  170 S = S*RADIXL
  180 S = S*RADIXL
  190 CONTINUE
!
!   AT THIS POINT, THE REMAINING DIFFERENCE IN THE
! AUXILIARY INDICES HAS BEEN USED TO EFFECT A RIGHT SHIFT
! OF S.  IF THE SHIFTED VALUE OF S WOULD HAVE EXCEEDED
! RADIX**L, THEN (S,IS) IS RETURNED AS THE VALUE OF THE
! SUM.
!
      IF (ABS(S).GT.1.0D0 .AND. ABS(T).GT.1.0D0) GO TO 200
      IF (ABS(S).LT.1.0D0 .AND. ABS(T).LT.1.0D0) GO TO 210
      Z = S + T
      IZ = IS - J*L
      GO TO 220
  200 S = S/RADIXL
      T = T/RADIXL
      Z = S + T
      IZ = IS - J*L + L
      GO TO 220
  210 S = S*RADIXL
      T = T*RADIXL
      Z = S + T
      IZ = IS - J*L - L
  220 CALL DXADJ(Z, IZ,IERROR)
      RETURN
      END SUBROUTINE DXADD 
      SUBROUTINE DXADJ (X, IX, IERROR)
!***BEGIN PROLOGUE  DXADJ
!***PURPOSE  To provide double-precision floating-point arithmetic
!            with an extended exponent range.
!***LIBRARY   SLATEC
!***CATEGORY  A3D
!***TYPE      DOUBLE PRECISION (XADJ-S, DXADJ-D)
!***KEYWORDS  EXTENDED-RANGE DOUBLE-PRECISION ARITHMETIC
!***AUTHOR  Lozier, Daniel W., (NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY)
!           Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!     DOUBLE PRECISION X
!     INTEGER IX
!
!                  TRANSFORMS (X,IX) SO THAT
!                  RADIX**(-L) .LE. ABS(X) .LT. RADIX**L.
!                  ON MOST COMPUTERS THIS TRANSFORMATION DOES
!                  NOT CHANGE THE MANTISSA OF X PROVIDED RADIX IS
!                  THE NUMBER BASE OF DOUBLE-PRECISION ARITHMETIC.
!
!***SEE ALSO  DXSET
!***REFERENCES  (NONE)
!***ROUTINES CALLED  XERMSG
!***COMMON BLOCKS    DXBLK2
!***REVISION HISTORY  (YYMMDD)
!   820712  DATE WRITTEN
!   881020  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!           CALLs to XERROR changed to CALLs to XERMSG.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXADJ
      DOUBLE PRECISION X
      INTEGER IX
      DOUBLE PRECISION RADIX, RADIXL, RAD2L, DLG10R
      INTEGER L, L2, KMAX
      COMMON /DXBLK2/ RADIX, RADIXL, RAD2L, DLG10R, L, L2, KMAX
      SAVE /DXBLK2/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!   THE CONDITION IMPOSED ON L AND KMAX BY THIS SUBROUTINE
! IS
!     2*L .LE. KMAX
!
! THIS CONDITION MUST BE MET BY APPROPRIATE CODING
! IN SUBROUTINE DXSET.
!
!***FIRST EXECUTABLE STATEMENT  DXADJ
      IERROR=0
      IF (X.EQ.0.0D0) GO TO 50
      IF (ABS(X).GE.1.0D0) GO TO 20
      IF (RADIXL*ABS(X).GE.1.0D0) GO TO 60
      X = X*RAD2L
      IF (IX.LT.0) GO TO 10
      IX = IX - L2
      GO TO 70
   10 IF (IX.LT.-KMAX+L2) GO TO 40
      IX = IX - L2
      GO TO 70
   20 IF (ABS(X).LT.RADIXL) GO TO 60
      X = X/RAD2L
      IF (IX.GT.0) GO TO 30
      IX = IX + L2
      GO TO 70
   30 IF (IX.GT.KMAX-L2) GO TO 40
      IX = IX + L2
      GO TO 70
   40 CONTINUE
!CC40 CALL XERMSG ('SLATEC', 'DXADJ', 'overflow in auxiliary index',
!CCCC+             207, 1)
      IERROR=207
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
  901 FORMAT('***** ERROR FROM DXADJ, OVERFLOW IN AUXILIARY INDEX.')
      RETURN
   50 IX = 0
   60 IF (ABS(IX).GT.KMAX) GO TO 40
   70 RETURN
      END SUBROUTINE DXADJ 
      SUBROUTINE DXLEGF (DNU1, NUDIFF, MU1, MU2, THETA, ID, PQA, IPQA,   &
         IERROR)
!***BEGIN PROLOGUE  DXLEGF
!***PURPOSE  Compute normalized Legendre polynomials and associated
!            Legendre functions.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XLEGF-S, DXLEGF-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!
!   DXLEGF: Extended-range Double-precision Legendre Functions
!
!   A feature of the DXLEGF subroutine for Legendre functions is
! the use of extended-range arithmetic, a software extension of
! ordinary floating-point arithmetic that greatly increases the
! exponent range of the representable numbers. This avoids the
! need for scaling the solutions to lie within the exponent range
! of the most restrictive manufacturer's hardware. The increased
! exponent range is achieved by allocating an integer storage
! location together with each floating-point storage location.
!
!   The interpretation of the pair (X,I) where X is floating-point
! and I is integer is X*(IR**I) where IR is the internal radix of
! the computer arithmetic.
!
!   This subroutine computes one of the following vectors:
!
! 1. Legendre function of the first kind of negative order, either
!    a. P(-MU1,NU,X), P(-MU1-1,NU,X), ..., P(-MU2,NU,X) or
!    b. P(-MU,NU1,X), P(-MU,NU1+1,X), ..., P(-MU,NU2,X)
! 2. Legendre function of the second kind, either
!    a. Q(MU1,NU,X), Q(MU1+1,NU,X), ..., Q(MU2,NU,X) or
!    b. Q(MU,NU1,X), Q(MU,NU1+1,X), ..., Q(MU,NU2,X)
! 3. Legendre function of the first kind of positive order, either
!    a. P(MU1,NU,X), P(MU1+1,NU,X), ..., P(MU2,NU,X) or
!    b. P(MU,NU1,X), P(MU,NU1+1,X), ..., P(MU,NU2,X)
! 4. Normalized Legendre polynomials, either
!    a. PN(MU1,NU,X), PN(MU1+1,NU,X), ..., PN(MU2,NU,X) or
!    b. PN(MU,NU1,X), PN(MU,NU1+1,X), ..., PN(MU,NU2,X)
!
! where X = COS(THETA).
!
!   The input values to DXLEGF are DNU1, NUDIFF, MU1, MU2, THETA,
! and ID. These must satisfy
!
!    DNU1 is DOUBLE PRECISION and greater than or equal to -0.5;
!    NUDIFF is INTEGER and non-negative;
!    MU1 is INTEGER and non-negative;
!    MU2 is INTEGER and greater than or equal to MU1;
!    THETA is DOUBLE PRECISION and in the half-open interval (0,PI/2];
!    ID is INTEGER and equal to 1, 2, 3 or 4;
!
! and  additionally either NUDIFF = 0 or MU2 = MU1.
!
!   If ID=1 and NUDIFF=0, a vector of type 1a above is computed
! with NU=DNU1.
!
!   If ID=1 and MU1=MU2, a vector of type 1b above is computed
! with NU1=DNU1, NU2=DNU1+NUDIFF and MU=MU1.
!
!   If ID=2 and NUDIFF=0, a vector of type 2a above is computed
! with NU=DNU1.
!
!   If ID=2 and MU1=MU2, a vector of type 2b above is computed
! with NU1=DNU1, NU2=DNU1+NUDIFF and MU=MU1.
!
!   If ID=3 and NUDIFF=0, a vector of type 3a above is computed
! with NU=DNU1.
!
!   If ID=3 and MU1=MU2, a vector of type 3b above is computed
! with NU1=DNU1, NU2=DNU1+NUDIFF and MU=MU1.
!
!   If ID=4 and NUDIFF=0, a vector of type 4a above is computed
! with NU=DNU1.
!
!   If ID=4 and MU1=MU2, a vector of type 4b above is computed
! with NU1=DNU1, NU2=DNU1+NUDIFF and MU=MU1.
!
!   In each case the vector of computed Legendre function values
! is returned in the extended-range vector (PQA(I),IPQA(I)). The
! length of this vector is either MU2-MU1+1 or NUDIFF+1.
!
!   Where possible, DXLEGF returns IPQA(I) as zero. In this case the
! value of the Legendre function is contained entirely in PQA(I),
! so it can be used in subsequent computations without further
! consideration of extended-range arithmetic. If IPQA(I) is nonzero,
! then the value of the Legendre function is not representable in
! floating-point because of underflow or overflow. The program that
! calls DXLEGF must test IPQA(I) to ensure correct usage.
!
!   IERROR is an error indicator. If no errors are detected, IERROR=0
! when control returns to the calling routine. If an error is detected,
! IERROR is returned as nonzero. The calling routine must check the
! value of IERROR.
!
!   If IERROR=210 or 211, invalid input was provided to DXLEGF.
!   If IERROR=201,202,203, or 204, invalid input was provided to DXSET.
!   If IERROR=205 or 206, an internal consistency error occurred in
! DXSET (probably due to a software malfunction in the library routine
! I1MACH).
!   If IERROR=207, an overflow or underflow of an extended-range number
! was detected in DXADJ.
!   If IERROR=208, an overflow or underflow of an extended-range number
! was detected in DXC210.
!
!***SEE ALSO  DXSET
!***REFERENCES  Olver and Smith, Associated Legendre Functions on the
!                 Cut, J Comp Phys, v 51, n 3, Sept 1983, pp 502--518.
!               Smith, Olver and Lozier, Extended-Range Arithmetic and
!                 Normalized Legendre Polynomials, ACM Trans on Math
!                 Softw, v 7, n 1, March 1981, pp 93--105.
!***ROUTINES CALLED  DXPMU, DXPMUP, DXPNRM, DXPQNU, DXQMU, DXQNU, DXRED,
!                    DXSET, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!           CALLs to XERROR changed to CALLs to XERMSG.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXLEGF
      DOUBLE PRECISION PQA,DNU1,DNU2,SX,THETA,X,PI2
      DIMENSION PQA(*),IPQA(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  DXLEGF
      IERROR=0
      CALL DXSET (0, 0, 0.0D0, 0,IERROR)
      IF (IERROR.NE.0) RETURN
      PI2=2.D0*ATAN(1.D0)
!
!        ZERO OUTPUT ARRAYS
!
      L=(MU2-MU1)+NUDIFF+1
      DO 290 I=1,L
        PQA(I)=0.D0
        IPQA(I)=0
  290 CONTINUE
!
!        CHECK FOR VALID INPUT VALUES
!
      IF(NUDIFF.LT.0) GO TO 400
      IF(DNU1.LT.-.5D0) GO TO 400
      IF(MU2.LT.MU1) GO TO 400
      IF(MU1.LT.0) GO TO 400
      IF(THETA.LE.0.D0.OR.THETA.GT.PI2) GO TO 420
      IF(ID.LT.1.OR.ID.GT.4) GO TO 400
      IF((MU1.NE.MU2).AND.(NUDIFF.GT.0)) GO TO 400
!
!        IF DNU1 IS NOT AN INTEGER, NORMALIZED P(MU,DNU,X)
!        CANNOT BE CALCULATED.  IF DNU1 IS AN INTEGER AND
!        MU1.GT.DNU2 THEN ALL VALUES OF P(+MU,DNU,X) AND
!        NORMALIZED P(MU,NU,X) WILL BE ZERO.
!
      DNU2=DNU1+NUDIFF
      IF((ID.EQ.3).AND.(MOD(DNU1,1.D0).NE.0.D0)) GO TO 295
      IF((ID.EQ.4).AND.(MOD(DNU1,1.D0).NE.0.D0)) GO TO 400
      IF((ID.EQ.3.OR.ID.EQ.4).AND.MU1.GT.DNU2) RETURN
  295 CONTINUE
!
      X=COS(THETA)
      SX=1.D0/SIN(THETA)
      IF(ID.EQ.2) GO TO 300
      IF(MU2-MU1.LE.0) GO TO 360
!
!        FIXED NU, VARIABLE MU
!        CALL DXPMU TO CALCULATE P(-MU1,NU,X),....,P(-MU2,NU,X)
!
      CALL DXPMU(DNU1,DNU2,MU1,MU2,THETA,X,SX,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      GO TO 380
!
  300 IF(MU2.EQ.MU1) GO TO 320
!
!        FIXED NU, VARIABLE MU
!        CALL DXQMU TO CALCULATE Q(MU1,NU,X),....,Q(MU2,NU,X)
!
      CALL DXQMU(DNU1,DNU2,MU1,MU2,THETA,X,SX,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      GO TO 390
!
!        FIXED MU, VARIABLE NU
!        CALL DXQNU TO CALCULATE Q(MU,DNU1,X),....,Q(MU,DNU2,X)
!
  320 CALL DXQNU(DNU1,DNU2,MU1,THETA,X,SX,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      GO TO 390
!
!        FIXED MU, VARIABLE NU
!        CALL DXPQNU TO CALCULATE P(-MU,DNU1,X),....,P(-MU,DNU2,X)
!
  360 CALL DXPQNU(DNU1,DNU2,MU1,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
!
!        IF ID = 3, TRANSFORM P(-MU,NU,X) VECTOR INTO
!        P(MU,NU,X) VECTOR.
!
  380 IF(ID.EQ.3) CALL DXPMUP(DNU1,DNU2,MU1,MU2,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
!
!        IF ID = 4, TRANSFORM P(-MU,NU,X) VECTOR INTO
!        NORMALIZED P(MU,NU,X) VECTOR.
!
      IF(ID.EQ.4) CALL DXPNRM(DNU1,DNU2,MU1,MU2,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
!
!        PLACE RESULTS IN REDUCED FORM IF POSSIBLE
!        AND RETURN TO MAIN PROGRAM.
!
  390 DO 395 I=1,L
      CALL DXRED(PQA(I),IPQA(I),IERROR)
      IF (IERROR.NE.0) RETURN
  395 CONTINUE
      RETURN
!
!        *****     ERROR TERMINATION     *****
!
  400 CONTINUE
!CCCC CALL XERMSG ('SLATEC', 'DXLEGF',
!CCCC+             'DNU1, NUDIFF, MU1, MU2, or ID not valid', 210, 1)
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
  901 FORMAT('***** ERROR FROM DXLEGF, INVALID INPUT ARGUMENTS.')
      IERROR=210
      RETURN
  420 CONTINUE
!CCCC CALL XERMSG ('SLATEC', 'DXLEGF', 'THETA out of range', 211, 1)
      WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
  902 FORMAT('***** ERROR FROM DXLEGF, THETA OUT OF RANGE.')
      IERROR=211
      RETURN
      END SUBROUTINE DXLEGF 
      SUBROUTINE DXNRMP (NU, MU1, MU2, DARG, MODE, DPN, IPN, ISIG,   &
         IERROR)
!***BEGIN PROLOGUE  DXNRMP
!***PURPOSE  Compute normalized Legendre polynomials.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XNRMP-S, DXNRMP-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Lozier, Daniel W., (NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY)
!           Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!
!        SUBROUTINE TO CALCULATE NORMALIZED LEGENDRE POLYNOMIALS
!        (XNRMP is single-precision version)
!        DXNRMP calculates normalized Legendre polynomials of varying
!        order and fixed argument and degree. The order MU and degree
!        NU are non-negative integers and the argument is real. Because
!        the algorithm requires the use of numbers outside the normal
!        machine range, this subroutine employs a special arithmetic
!        called extended-range arithmetic. See J.M. Smith, F.W.J. Olver,
!        and D.W. Lozier, Extended-Range Arithmetic and Normalized
!        Legendre Polynomials, ACM Transactions on Mathematical Soft-
!        ware, 93-105, March 1981, for a complete description of the
!        algorithm and special arithmetic. Also see program comments
!        in DXSET.
!
!        The normalized Legendre polynomials are multiples of the
!        associated Legendre polynomials of the first kind where the
!        normalizing coefficients are chosen so as to make the integral
!        from -1 to 1 of the square of each function equal to 1. See
!        E. Jahnke, F. Emde and F. Losch, Tables of Higher Functions,
!        McGraw-Hill, New York, 1960, p. 121.
!
!        The input values to DXNRMP are NU, MU1, MU2, DARG, and MODE.
!        These must satisfy
!          1. NU .GE. 0 specifies the degree of the normalized Legendre
!             polynomial that is wanted.
!          2. MU1 .GE. 0 specifies the lowest-order normalized Legendre
!             polynomial that is wanted.
!          3. MU2 .GE. MU1 specifies the highest-order normalized Leg-
!             endre polynomial that is wanted.
!         4a. MODE = 1 and -1.0D0 .LE. DARG .LE. 1.0D0 specifies that
!             Normalized Legendre(NU, MU, DARG) is wanted for MU = MU1,
!             MU1 + 1, ..., MU2.
!         4b. MODE = 2 and -3.14159... .LT. DARG .LT. 3.14159... spec-
!             ifies that Normalized Legendre(NU, MU, COS(DARG)) is
!             wanted for MU = MU1, MU1 + 1, ..., MU2.
!
!        The output of DXNRMP consists of the two vectors DPN and IPN
!        and the error estimate ISIG. The computed values are stored as
!        extended-range numbers such that
!             (DPN(1),IPN(1))=NORMALIZED LEGENDRE(NU,MU1,DX)
!             (DPN(2),IPN(2))=NORMALIZED LEGENDRE(NU,MU1+1,DX)
!                .
!                .
!             (DPN(K),IPN(K))=NORMALIZED LEGENDRE(NU,MU2,DX)
!        where K = MU2 - MU1 + 1 and DX = DARG or COS(DARG) according
!        to whether MODE = 1 or 2. Finally, ISIG is an estimate of the
!        number of decimal digits lost through rounding errors in the
!        computation. For example if DARG is accurate to 12 significant
!        decimals, then the computed function values are accurate to
!        12 - ISIG significant decimals (except in neighborhoods of
!        zeros).
!
!        The interpretation of (DPN(I),IPN(I)) is DPN(I)*(IR**IPN(I))
!        where IR is the internal radix of the computer arithmetic. When
!        IPN(I) = 0 the value of the normalized Legendre polynomial is
!        contained entirely in DPN(I) and subsequent double-precision
!        computations can be performed without further consideration of
!        extended-range arithmetic. However, if IPN(I) .NE. 0 the corre-
!        sponding value of the normalized Legendre polynomial cannot be
!        represented in double-precision because of overflow or under-
!        flow. THE USER MUST TEST IPN(I) IN HIS/HER PROGRAM. In the case
!        that IPN(I) is nonzero, the user could rewrite his/her program
!        to use extended range arithmetic.
!
!
!
!        The interpretation of (DPN(I),IPN(I)) can be changed to
!        DPN(I)*(10**IPN(I)) by calling the extended-range subroutine
!        DXCON. This should be done before printing the computed values.
!        As an example of usage, the Fortran coding
!              J = K
!              DO 20 I = 1, K
!              CALL DXCON(DPN(I), IPN(I),IERROR)
!              IF (IERROR.NE.0) RETURN
!              PRINT 10, DPN(I), IPN(I)
!           10 FORMAT(1X, D30.18 , I15)
!              IF ((IPN(I) .EQ. 0) .OR. (J .LT. K)) GO TO 20
!              J = I - 1
!           20 CONTINUE
!        will print all computed values and determine the largest J
!        such that IPN(1) = IPN(2) = ... = IPN(J) = 0. Because of the
!        change of representation caused by calling DXCON, (DPN(I),
!        IPN(I)) for I = J+1, J+2, ... cannot be used in subsequent
!        extended-range computations.
!
!        IERROR is an error indicator. If no errors are detected,
!        IERROR=0 when control returns to the calling routine. If
!        an error is detected, IERROR is returned as nonzero. The
!        calling routine must check the value of IERROR.
!
!        If IERROR=212 or 213, invalid input was provided to DXNRMP.
!        If IERROR=201,202,203, or 204, invalid input was provided
!        to DXSET.
!        If IERROR=205 or 206, an internal consistency error occurred
!        in DXSET (probably due to a software malfunction in the
!        library routine I1MACH).
!        If IERROR=207, an overflow or underflow of an extended-range
!        number was detected in DXADJ.
!        If IERROR=208, an overflow or underflow of an extended-range
!        number was detected in DXC210.
!
!***SEE ALSO  DXSET
!***REFERENCES  Smith, Olver and Lozier, Extended-Range Arithmetic and
!                 Normalized Legendre Polynomials, ACM Trans on Math
!                 Softw, v 7, n 1, March 1981, pp 93--105.
!***ROUTINES CALLED  DXADD, DXADJ, DXRED, DXSET, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   820712  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!           CALLs to XERROR changed to CALLs to XERMSG.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXNRMP
      INTEGER NU, MU1, MU2, MODE, IPN, ISIG
      DOUBLE PRECISION DARG, DPN
      DIMENSION DPN(*), IPN(*)
      DOUBLE PRECISION C1,C2,P,P1,P2,P3,S,SX,T,TX,X,DK
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
! CALL DXSET TO INITIALIZE EXTENDED-RANGE ARITHMETIC (SEE DXSET
! LISTING FOR DETAILS)
!***FIRST EXECUTABLE STATEMENT  DXNRMP
      IERROR=0
      CALL DXSET (0, 0, 0.0D0, 0,IERROR)
      IF (IERROR.NE.0) RETURN
!
!        TEST FOR PROPER INPUT VALUES.
!
      IF (NU.LT.0) GO TO 110
      IF (MU1.LT.0) GO TO 110
      IF (MU1.GT.MU2) GO TO 110
      IF (NU.EQ.0) GO TO 90
      IF (MODE.LT.1 .OR. MODE.GT.2) GO TO 110
      GO TO (10, 20), MODE
   10 IF (ABS(DARG).GT.1.0D0) GO TO 120
      IF (ABS(DARG).EQ.1.0D0) GO TO 90
      X = DARG
      SX = SQRT((1.0D0+ABS(X))*((0.5D0-ABS(X))+0.5D0))
      TX = X/SX
      ISIG = INT(LOG10(2.0D0*NU*(5.0D0+TX**2)))
      GO TO 30
   20 IF (ABS(DARG).GT.4.0D0*ATAN(1.0D0)) GO TO 120
      IF (DARG.EQ.0.0D0) GO TO 90
      X = COS(DARG)
      SX = ABS(SIN(DARG))
      TX = X/SX
      ISIG = INT(LOG10(2.0D0*NU*(5.0D0+ABS(DARG*TX))))
!
!        BEGIN CALCULATION
!
   30 MU = MU2
      I = MU2 - MU1 + 1
!
!        IF MU.GT.NU, NORMALIZED LEGENDRE(NU,MU,X)=0.
!
   40 IF (MU.LE.NU) GO TO 50
      DPN(I) = 0.0D0
      IPN(I) = 0
      I = I - 1
      MU = MU - 1
      IF (I .GT. 0) GO TO 40
      ISIG = 0
      GO TO 160
   50 MU = NU
!
!        P1 = 0. = NORMALIZED LEGENDRE(NU,NU+1,X)
!
      P1 = 0.0D0
      IP1 = 0
!
!        CALCULATE P2 = NORMALIZED LEGENDRE(NU,NU,X)
!
      P2 = 1.0D0
      IP2 = 0
      P3 = 0.5D0
      DK = 2.0D0
      DO 60 J=1,NU
        P3 = ((DK+1.0D0)/DK)*P3
        P2 = P2*SX
        CALL DXADJ(P2, IP2,IERROR)
        IF (IERROR.NE.0) RETURN
        DK = DK + 2.0D0
   60 CONTINUE
      P2 = P2*SQRT(P3)
      CALL DXADJ(P2, IP2,IERROR)
      IF (IERROR.NE.0) RETURN
      S = 2.0D0*TX
      T = 1.0D0/NU
      IF (MU2.LT.NU) GO TO 70
      DPN(I) = P2
      IPN(I) = IP2
      I = I - 1
      IF (I .EQ. 0) GO TO 140
!
!        RECURRENCE PROCESS
!
   70 P = MU*T
      C1 = 1.0D0/SQRT((1.0D0-P+T)*(1.0D0+P))
      C2 = S*P*C1*P2
      C1 = -SQRT((1.0D0+P+T)*(1.0D0-P))*C1*P1
      CALL DXADD(C2, IP2, C1, IP1, P, IP,IERROR)
      IF (IERROR.NE.0) RETURN
      MU = MU - 1
      IF (MU.GT.MU2) GO TO 80
!
!        STORE IN ARRAY DPN FOR RETURN TO CALLING ROUTINE.
!
      DPN(I) = P
      IPN(I) = IP
      I = I - 1
      IF (I .EQ. 0) GO TO 140
   80 P1 = P2
      IP1 = IP2
      P2 = P
      IP2 = IP
      IF (MU.LE.MU1) GO TO 140
      GO TO 70
!
!        SPECIAL CASE WHEN X=-1 OR +1, OR NU=0.
!
   90 K = MU2 - MU1 + 1
      DO 100 I=1,K
        DPN(I) = 0.0D0
        IPN(I) = 0
  100 CONTINUE
      ISIG = 0
      IF (MU1.GT.0) GO TO 160
      ISIG = 1
      DPN(1) = SQRT(NU+0.5D0)
      IPN(1) = 0
      IF (MOD(NU,2).EQ.0) GO TO 160
      IF (MODE.EQ.1 .AND. DARG.EQ.1.0D0) GO TO 160
      IF (MODE.EQ.2) GO TO 160
      DPN(1) = -DPN(1)
      GO TO 160
!
!          ERROR PRINTOUTS AND TERMINATION.
!
  110 CONTINUE
!CCCC CALL XERMSG ('SLATEC', 'DXNRMP', 'NU, MU1, MU2 or MODE not valid',
!CCCC+             212, 1)
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
  901 FORMAT('***** ERROR FROM DXNRMP, INVALID INOUT ARGUMENTS.')
      IERROR=212
      RETURN
  120 CONTINUE
!CCCC CALL XERMSG ('SLATEC', 'DXNRMP', 'DARG out of range', 213, 1)
      WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
  902 FORMAT('***** ERROR FROM DXNRMP, FIRST ARGUMENT OUT OF RANGE.')
      IERROR=213
      RETURN
!
!        RETURN TO CALLING PROGRAM
!
  140 K = MU2 - MU1 + 1
      DO 150 I=1,K
        CALL DXRED(DPN(I),IPN(I),IERROR)
        IF (IERROR.NE.0) RETURN
  150 CONTINUE
  160 RETURN
      END SUBROUTINE DXNRMP 
      SUBROUTINE DXPMU (NU1, NU2, MU1, MU2, THETA, X, SX, ID, PQA, IPQA,   &
         IERROR)
!***BEGIN PROLOGUE  DXPMU
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            Method: backward mu-wise recurrence for P(-MU,NU,X) for
!            fixed nu to obtain P(-MU2,NU1,X), P(-(MU2-1),NU1,X), ...,
!            P(-MU1,NU1,X) and store in ascending mu order.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XPMU-S, DXPMU-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADD, DXADJ, DXPQNU
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXPMU
      DOUBLE PRECISION PQA,NU1,NU2,P0,X,SX,THETA,X1,X2
      DIMENSION PQA(*),IPQA(*)
!
!        CALL DXPQNU TO OBTAIN P(-MU2,NU,X)
!
!***FIRST EXECUTABLE STATEMENT  DXPMU
      IERROR=0
      CALL DXPQNU(NU1,NU2,MU2,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      P0=PQA(1)
      IP0=IPQA(1)
      MU=MU2-1
!
!        CALL DXPQNU TO OBTAIN P(-MU2-1,NU,X)
!
      CALL DXPQNU(NU1,NU2,MU,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      N=MU2-MU1+1
      PQA(N)=P0
      IPQA(N)=IP0
      IF(N.EQ.1) GO TO 300
      PQA(N-1)=PQA(1)
      IPQA(N-1)=IPQA(1)
      IF(N.EQ.2) GO TO 300
      J=N-2
  290 CONTINUE
!
!        BACKWARD RECURRENCE IN MU TO OBTAIN
!              P(-MU2,NU1,X),P(-(MU2-1),NU1,X),....P(-MU1,NU1,X)
!              USING
!              (NU-MU)*(NU+MU+1.)*P(-(MU+1),NU,X)=
!                2.*MU*X*SQRT((1./(1.-X**2))*P(-MU,NU,X)-P(-(MU-1),NU,X)
!
      X1=2.D0*MU*X*SX*PQA(J+1)
      X2=-(NU1-MU)*(NU1+MU+1.D0)*PQA(J+2)
      CALL DXADD(X1,IPQA(J+1),X2,IPQA(J+2),PQA(J),IPQA(J),IERROR)
      IF (IERROR.NE.0) RETURN
      CALL DXADJ(PQA(J),IPQA(J),IERROR)
      IF (IERROR.NE.0) RETURN
      IF(J.EQ.1) GO TO 300
      J=J-1
      MU=MU-1
      GO TO 290
  300 RETURN
      END SUBROUTINE DXPMU 
      SUBROUTINE DXPMUP (NU1, NU2, MU1, MU2, PQA, IPQA, IERROR)
!***BEGIN PROLOGUE  DXPMUP
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            This subroutine transforms an array of Legendre functions
!            of the first kind of negative order stored in array PQA
!            into Legendre functions of the first kind of positive
!            order stored in array PQA. The original array is destroyed.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XPMUP-S, DXPMUP-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADJ
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXPMUP
      DOUBLE PRECISION DMU,NU,NU1,NU2,PQA,PROD
      DIMENSION PQA(*),IPQA(*)
!***FIRST EXECUTABLE STATEMENT  DXPMUP
      IERROR=0
      NU=NU1
      MU=MU1
      DMU=MU
      N=INT(NU2-NU1+.1D0)+(MU2-MU1)+1
      J=1
      IF(MOD(REAL(NU),1.).NE.0.) GO TO 210
  200 IF(DMU.LT.NU+1.D0) GO TO 210
      PQA(J)=0.D0
      IPQA(J)=0
      J=J+1
      IF(J.GT.N) RETURN
!        INCREMENT EITHER MU OR NU AS APPROPRIATE.
      IF(NU2-NU1.GT..5D0) NU=NU+1.D0
      IF(MU2.GT.MU1) MU=MU+1
      GO TO 200
!
!        TRANSFORM P(-MU,NU,X) TO P(MU,NU,X) USING
!        P(MU,NU,X)=(NU-MU+1)*(NU-MU+2)*...*(NU+MU)*P(-MU,NU,X)*(-1)**MU
!
  210 PROD=1.D0
      IPROD=0
      K=2*MU
      IF(K.EQ.0) GO TO 222
      DO 220 L=1,K
        PROD=PROD*(DMU-NU-L)
        CALL DXADJ(PROD,IPROD,IERROR)
  220 CONTINUE
      IF (IERROR.NE.0) RETURN
  222 CONTINUE
      DO 240 I=J,N
      IF(MU.EQ.0) GO TO 225
      PQA(I)=PQA(I)*PROD*(-1)**MU
      IPQA(I)=IPQA(I)+IPROD
      CALL DXADJ(PQA(I),IPQA(I),IERROR)
      IF (IERROR.NE.0) RETURN
  225 IF(NU2-NU1.GT..5D0) GO TO 230
      PROD=(DMU-NU)*PROD*(-DMU-NU-1.D0)
      CALL DXADJ(PROD,IPROD,IERROR)
      IF (IERROR.NE.0) RETURN
      MU=MU+1
      DMU=DMU+1.D0
      GO TO 240
  230 PROD=PROD*(-DMU-NU-1.D0)/(DMU-NU-1.D0)
      CALL DXADJ(PROD,IPROD,IERROR)
      IF (IERROR.NE.0) RETURN
      NU=NU+1.D0
  240 CONTINUE
      RETURN
      END SUBROUTINE DXPMUP 
      SUBROUTINE DXPNRM (NU1, NU2, MU1, MU2, PQA, IPQA, IERROR)
!***BEGIN PROLOGUE  DXPNRM
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            This subroutine transforms an array of Legendre functions
!            of the first kind of negative order stored in array PQA
!            into normalized Legendre polynomials stored in array PQA.
!            The original array is destroyed.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XPNRM-S, DXPNRM-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADJ
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXPNRM
      DOUBLE PRECISION C1,DMU,NU,NU1,NU2,PQA,PROD
      DIMENSION PQA(*),IPQA(*)
!***FIRST EXECUTABLE STATEMENT  DXPNRM
      IERROR=0
      L=INT((MU2-MU1)+(NU2-NU1+1.5D0))
      MU=MU1
      DMU=MU1
      NU=NU1
!
!         IF MU .GT.NU, NORM P =0.
!
      J=1
  500 CONTINUE
      IF(DMU.LE.NU) GO TO 505
      PQA(J)=0.D0
      IPQA(J)=0
      J=J+1
      IF(J.GT.L) RETURN
!
!        INCREMENT EITHER MU OR NU AS APPROPRIATE.
!
      IF(MU2.GT.MU1) DMU=DMU+1.D0
      IF(NU2-NU1.GT..5D0) NU=NU+1.D0
      GO TO 500
!
!         TRANSFORM P(-MU,NU,X) INTO NORMALIZED P(MU,NU,X) USING
!              NORM P(MU,NU,X)=
!                 SQRT((NU+.5)*FACTORIAL(NU+MU)/FACTORIAL(NU-MU))
!                              *P(-MU,NU,X)
!
  505 CONTINUE
      PROD=1.D0
      IPROD=0
      K=2*MU
      IF(K.LE.0) GO TO 520
      DO 510 I=1,K
        PROD=PROD*SQRT(NU+DMU+1.D0-I)
        CALL DXADJ(PROD,IPROD,IERROR)
  510 CONTINUE
      IF (IERROR.NE.0) RETURN
  520 CONTINUE
      DO 540 I=J,L
      C1=PROD*SQRT(NU+.5D0)
      PQA(I)=PQA(I)*C1
      IPQA(I)=IPQA(I)+IPROD
      CALL DXADJ(PQA(I),IPQA(I),IERROR)
      IF (IERROR.NE.0) RETURN
      IF(NU2-NU1.GT..5D0) GO TO 530
      IF(DMU.GE.NU) GO TO 525
      PROD=SQRT(NU+DMU+1.D0)*PROD
      IF(NU.GT.DMU) PROD=PROD*SQRT(NU-DMU)
      CALL DXADJ(PROD,IPROD,IERROR)
      IF (IERROR.NE.0) RETURN
      MU=MU+1
      DMU=DMU+1.D0
      GO TO 540
  525 PROD=0.D0
      IPROD=0
      MU=MU+1
      DMU=DMU+1.D0
      GO TO 540
  530 PROD=SQRT(NU+DMU+1.D0)*PROD
      IF(NU.NE.DMU-1.D0) PROD=PROD/SQRT(NU-DMU+1.D0)
      CALL DXADJ(PROD,IPROD,IERROR)
      IF (IERROR.NE.0) RETURN
      NU=NU+1.D0
  540 CONTINUE
      RETURN
      END SUBROUTINE DXPNRM 
      SUBROUTINE DXPQNU (NU1, NU2, MU, THETA, ID, PQA, IPQA, IERROR)
!***BEGIN PROLOGUE  DXPQNU
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            This subroutine calculates initial values of P or Q using
!            power series, then performs forward nu-wise recurrence to
!            obtain P(-MU,NU,X), Q(0,NU,X), or Q(1,NU,X). The nu-wise
!            recurrence is stable for P for all mu and for Q for mu=0,1.
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XPQNU-S, DXPQNU-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADD, DXADJ, DXPSI
!***COMMON BLOCKS    DXBLK1
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXPQNU
      DOUBLE PRECISION A,NU,NU1,NU2,PQ,PQA,DXPSI,R,THETA,W,X,X1,X2,XS,   &
       Y,Z
      DOUBLE PRECISION DI,DMU,PQ1,PQ2,FACTMU,FLOK
      DIMENSION PQA(*),IPQA(*)
      COMMON /DXBLK1/ NBITSF
      SAVE /DXBLK1/
!
!        J0, IPSIK, AND IPSIX ARE INITIALIZED IN THIS SUBROUTINE.
!        J0 IS THE NUMBER OF TERMS USED IN SERIES EXPANSION
!        IN SUBROUTINE DXPQNU.
!        IPSIK, IPSIX ARE VALUES OF K AND X RESPECTIVELY
!        USED IN THE CALCULATION OF THE DXPSI FUNCTION.
!
!***FIRST EXECUTABLE STATEMENT  DXPQNU
      IERROR=0
      J0=NBITSF
      IPSIK=1+(NBITSF/10)
      IPSIX=5*IPSIK
      IPQ=0
!        FIND NU IN INTERVAL [-.5,.5) IF ID=2  ( CALCULATION OF Q )
      NU=MOD(NU1,1.D0)
      IF(NU.GE..5D0) NU=NU-1.D0
!        FIND NU IN INTERVAL (-1.5,-.5] IF ID=1,3, OR 4  ( CALC. OF P )
      IF(ID.NE.2.AND.NU.GT.-.5D0) NU=NU-1.D0
!        CALCULATE MU FACTORIAL
      K=MU
      DMU=MU
      IF(MU.LE.0) GO TO 60
      FACTMU=1.D0
      IF=0
      DO 50 I=1,K
        FACTMU=FACTMU*I
        CALL DXADJ(FACTMU,IF,IERROR)
   50 CONTINUE
      IF (IERROR.NE.0) RETURN
   60 IF(K.EQ.0) FACTMU=1.D0
      IF(K.EQ.0) IF=0
!
!        X=COS(THETA)
!        Y=SIN(THETA/2)**2=(1-X)/2=.5-.5*X
!        R=TAN(THETA/2)=SQRT((1-X)/(1+X)
!
      X=COS(THETA)
      Y=SIN(THETA/2.D0)**2
      R=TAN(THETA/2.D0)
!
!        USE ASCENDING SERIES TO CALCULATE TWO VALUES OF P OR Q
!        FOR USE AS STARTING VALUES IN RECURRENCE RELATION.
!
      PQ2=0.0D0
      DO 100 J=1,2
      IPQ1=0
      IF(ID.EQ.2) GO TO 80
!
!        SERIES FOR P ( ID = 1, 3, OR 4 )
!        P(-MU,NU,X)=1./FACTORIAL(MU)*SQRT(((1.-X)/(1.+X))**MU)
!                *SUM(FROM 0 TO J0-1)A(J)*(.5-.5*X)**J
!
      IPQ=0
      PQ=1.D0
      A=1.D0
      IA=0
      DO 65 I=2,J0
      DI=I
      A=A*Y*(DI-2.D0-NU)*(DI-1.D0+NU)/((DI-1.D0+DMU)*(DI-1.D0))
      CALL DXADJ(A,IA,IERROR)
      IF (IERROR.NE.0) RETURN
      IF(A.EQ.0.D0) GO TO 66
      CALL DXADD(PQ,IPQ,A,IA,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
   65 CONTINUE
   66 CONTINUE
      IF(MU.LE.0) GO TO 90
      X2=R
      X1=PQ
      K=MU
      DO 77 I=1,K
        X1=X1*X2
        CALL DXADJ(X1,IPQ,IERROR)
   77 CONTINUE
      IF (IERROR.NE.0) RETURN
      PQ=X1/FACTMU
      IPQ=IPQ-IF
      CALL DXADJ(PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      GO TO 90
!
!        Z=-LN(R)=.5*LN((1+X)/(1-X))
!
   80 Z=-LOG(R)
      W=DXPSI(NU+1.D0,IPSIK,IPSIX)
      XS=1.D0/SIN(THETA)
!
!        SERIES SUMMATION FOR Q ( ID = 2 )
!        Q(0,NU,X)=SUM(FROM 0 TO J0-1)((.5*LN((1+X)/(1-X))
!    +DXPSI(J+1,IPSIK,IPSIX)-DXPSI(NU+1,IPSIK,IPSIX)))*A(J)*(.5-.5*X)**J
!
!        Q(1,NU,X)=-SQRT(1./(1.-X**2))+SQRT((1-X)/(1+X))
!             *SUM(FROM 0 T0 J0-1)(-NU*(NU+1)/2*LN((1+X)/(1-X))
!                 +(J-NU)*(J+NU+1)/(2*(J+1))+NU*(NU+1)*
!     (DXPSI(NU+1,IPSIK,IPSIX)-DXPSI(J+1,IPSIK,IPSIX))*A(J)*(.5-.5*X)**J
!
!        NOTE, IN THIS LOOP K=J+1
!
      PQ=0.D0
      IPQ=0
      IA=0
      A=1.D0
      DO 85 K=1,J0
      FLOK=K
      IF(K.EQ.1) GO TO 81
      A=A*Y*(FLOK-2.D0-NU)*(FLOK-1.D0+NU)/((FLOK-1.D0+DMU)*(FLOK-1.D0))
      CALL DXADJ(A,IA,IERROR)
      IF (IERROR.NE.0) RETURN
   81 CONTINUE
      IF(MU.GE.1) GO TO 83
      X1=(DXPSI(FLOK,IPSIK,IPSIX)-W+Z)*A
      IX1=IA
      CALL DXADD(PQ,IPQ,X1,IX1,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      GO TO 85
   83 X1=(NU*(NU+1.D0)*(Z-W+DXPSI(FLOK,IPSIK,IPSIX))+(NU-FLOK+1.D0)   &
        *(NU+FLOK)/(2.D0*FLOK))*A
      IX1=IA
      CALL DXADD(PQ,IPQ,X1,IX1,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
   85 CONTINUE
      IF(MU.GE.1) PQ=-R*PQ
      IXS=0
      IF(MU.GE.1) CALL DXADD(PQ,IPQ,-XS,IXS,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      IF(J.EQ.2) MU=-MU
      IF(J.EQ.2) DMU=-DMU
   90 IF(J.EQ.1) PQ2=PQ
      IF(J.EQ.1) IPQ2=IPQ
      NU=NU+1.D0
  100 CONTINUE
      K=0
      IF(NU-1.5D0.LT.NU1) GO TO 120
      K=K+1
      PQA(K)=PQ2
      IPQA(K)=IPQ2
      IF(NU.GT.NU2+.5D0) RETURN
  120 PQ1=PQ
      IPQ1=IPQ
      IF(NU.LT.NU1+.5D0) GO TO 130
      K=K+1
      PQA(K)=PQ
      IPQA(K)=IPQ
      IF(NU.GT.NU2+.5D0) RETURN
!
!        FORWARD NU-WISE RECURRENCE FOR F(MU,NU,X) FOR FIXED MU
!        USING
!        (NU+MU+1)*F(MU,NU,X)=(2.*NU+1)*F(MU,NU,X)-(NU-MU)*F(MU,NU-1,X)
!        WHERE F(MU,NU,X) MAY BE P(-MU,NU,X) OR IF MU IS REPLACED
!        BY -MU THEN F(MU,NU,X) MAY BE Q(MU,NU,X).
!        NOTE, IN THIS LOOP, NU=NU+1
!
  130 X1=(2.D0*NU-1.D0)/(NU+DMU)*X*PQ1
      X2=(NU-1.D0-DMU)/(NU+DMU)*PQ2
      CALL DXADD(X1,IPQ1,-X2,IPQ2,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      CALL DXADJ(PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      NU=NU+1.D0
      PQ2=PQ1
      IPQ2=IPQ1
      GO TO 120
!
      END SUBROUTINE DXPQNU 
      DOUBLE PRECISION FUNCTION DXPSI (A, IPSIK, IPSIX)
!***BEGIN PROLOGUE  DXPSI
!***SUBSIDIARY
!***PURPOSE  To compute values of the Psi function for DXLEGF.
!***LIBRARY   SLATEC
!***CATEGORY  C7C
!***TYPE      DOUBLE PRECISION (XPSI-S, DXPSI-D)
!***KEYWORDS  PSI FUNCTION
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  (NONE)
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXPSI
      DOUBLE PRECISION A,B,C,CNUM,CDENOM
      DIMENSION CNUM(12),CDENOM(12)
      SAVE CNUM, CDENOM
!
!        CNUM(I) AND CDENOM(I) ARE THE ( REDUCED ) NUMERATOR
!        AND 2*I*DENOMINATOR RESPECTIVELY OF THE 2*I TH BERNOULLI
!        NUMBER.
!
      DATA CNUM(1),CNUM(2),CNUM(3),CNUM(4),CNUM(5),CNUM(6),CNUM(7),   &
      CNUM(8),CNUM(9),CNUM(10),CNUM(11),CNUM(12)   &
          / 1.D0,     -1.D0,    1.D0,     -1.D0, 1.D0,   &
         -691.D0,  1.D0,     -3617.D0, 43867.D0, -174611.D0, 77683.D0,   &
         -236364091.D0/
      DATA CDENOM(1),CDENOM(2),CDENOM(3),CDENOM(4),CDENOM(5),CDENOM(6),   &
       CDENOM(7),CDENOM(8),CDENOM(9),CDENOM(10),CDENOM(11),CDENOM(12)   &
      /12.D0,120.D0,   252.D0,   240.D0,132.D0,   &
        32760.D0, 12.D0,  8160.D0, 14364.D0, 6600.D0, 276.D0, 65520.D0/
!***FIRST EXECUTABLE STATEMENT  DXPSI
      N=MAX(0,IPSIX-INT(A))
      B=N+A
      K1=IPSIK-1
!
!        SERIES EXPANSION FOR A .GT. IPSIX USING IPSIK-1 TERMS.
!
      C=0.D0
      DO 12 I=1,K1
        K=IPSIK-I
        C=(C+CNUM(K)/CDENOM(K))/B**2
   12 CONTINUE
      DXPSI=LOG(B)-(C+.5D0/B)
      IF(N.EQ.0) GO TO 20
      B=0.D0
!
!        RECURRENCE FOR A .LE. IPSIX.
!
      DO 15 M=1,N
        B=B+1.D0/(N-M+A)
   15 CONTINUE
      DXPSI=DXPSI-B
   20 RETURN
      END FUNCTION DXPSI 
      SUBROUTINE DXQMU (NU1, NU2, MU1, MU2, THETA, X, SX, ID, PQA, IPQA,   &
         IERROR)
!***BEGIN PROLOGUE  DXQMU
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            Method: forward mu-wise recurrence for Q(MU,NU,X) for fixed
!            nu to obtain Q(MU1,NU,X), Q(MU1+1,NU,X), ..., Q(MU2,NU,X).
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XQMU-S, DXQMU-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADD, DXADJ, DXPQNU
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXQMU
      DIMENSION PQA(*),IPQA(*)
      DOUBLE PRECISION DMU,NU,NU1,NU2,PQ,PQA,PQ1,PQ2,SX,X,X1,X2
      DOUBLE PRECISION THETA
!***FIRST EXECUTABLE STATEMENT  DXQMU
      IERROR=0
      MU=0
!
!        CALL DXPQNU TO OBTAIN Q(0.,NU1,X)
!
      CALL DXPQNU(NU1,NU2,MU,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      PQ2=PQA(1)
      IPQ2=IPQA(1)
      MU=1
!
!        CALL DXPQNU TO OBTAIN Q(1.,NU1,X)
!
      CALL DXPQNU(NU1,NU2,MU,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      NU=NU1
      K=0
      MU=1
      DMU=1.D0
      PQ1=PQA(1)
      IPQ1=IPQA(1)
      IF(MU1.GT.0) GO TO 310
      K=K+1
      PQA(K)=PQ2
      IPQA(K)=IPQ2
      IF(MU2.LT.1) GO TO 330
  310 IF(MU1.GT.1) GO TO 320
      K=K+1
      PQA(K)=PQ1
      IPQA(K)=IPQ1
      IF(MU2.LE.1) GO TO 330
  320 CONTINUE
!
!        FORWARD RECURRENCE IN MU TO OBTAIN
!                  Q(MU1,NU,X),Q(MU1+1,NU,X),....,Q(MU2,NU,X) USING
!             Q(MU+1,NU,X)=-2.*MU*X*SQRT(1./(1.-X**2))*Q(MU,NU,X)
!                               -(NU+MU)*(NU-MU+1.)*Q(MU-1,NU,X)
!
      X1=-2.D0*DMU*X*SX*PQ1
      X2=(NU+DMU)*(NU-DMU+1.D0)*PQ2
      CALL DXADD(X1,IPQ1,-X2,IPQ2,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      CALL DXADJ(PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      PQ2=PQ1
      IPQ2=IPQ1
      PQ1=PQ
      IPQ1=IPQ
      MU=MU+1
      DMU=DMU+1.D0
      IF(MU.LT.MU1) GO TO 320
      K=K+1
      PQA(K)=PQ
      IPQA(K)=IPQ
      IF(MU2.GT.MU) GO TO 320
  330 RETURN
      END SUBROUTINE DXQMU 
      SUBROUTINE DXQNU (NU1, NU2, MU1, THETA, X, SX, ID, PQA, IPQA,   &
         IERROR)
!***BEGIN PROLOGUE  DXQNU
!***SUBSIDIARY
!***PURPOSE  To compute the values of Legendre functions for DXLEGF.
!            Method: backward nu-wise recurrence for Q(MU,NU,X) for
!            fixed mu to obtain Q(MU1,NU1,X), Q(MU1,NU1+1,X), ...,
!            Q(MU1,NU2,X).
!***LIBRARY   SLATEC
!***CATEGORY  C3A2, C9
!***TYPE      DOUBLE PRECISION (XQNU-S, DXQNU-D)
!***KEYWORDS  LEGENDRE FUNCTIONS
!***AUTHOR  Smith, John M., (NBS and George Mason University)
!***ROUTINES CALLED  DXADD, DXADJ, DXPQNU
!***REVISION HISTORY  (YYMMDD)
!   820728  DATE WRITTEN
!   890126  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXQNU
      DIMENSION PQA(*),IPQA(*)
      DOUBLE PRECISION DMU,NU,NU1,NU2,PQ,PQA,PQ1,PQ2,SX,X,X1,X2
      DOUBLE PRECISION THETA,PQL1,PQL2
!***FIRST EXECUTABLE STATEMENT  DXQNU
      IERROR=0
      K=0
      PQ2=0.0D0
      IPQ2=0
      PQL2=0.0D0
      IPQL2=0
      IF(MU1.EQ.1) GO TO 290
      MU=0
!
!        CALL DXPQNU TO OBTAIN Q(0.,NU2,X) AND Q(0.,NU2-1,X)
!
      CALL DXPQNU(NU1,NU2,MU,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      IF(MU1.EQ.0) RETURN
      K=INT((NU2-NU1+1.5D0))
      PQ2=PQA(K)
      IPQ2=IPQA(K)
      PQL2=PQA(K-1)
      IPQL2=IPQA(K-1)
  290 MU=1
!
!        CALL DXPQNU TO OBTAIN Q(1.,NU2,X) AND Q(1.,NU2-1,X)
!
      CALL DXPQNU(NU1,NU2,MU,THETA,ID,PQA,IPQA,IERROR)
      IF (IERROR.NE.0) RETURN
      IF(MU1.EQ.1) RETURN
      NU=NU2
      PQ1=PQA(K)
      IPQ1=IPQA(K)
      PQL1=PQA(K-1)
      IPQL1=IPQA(K-1)
  300 MU=1
      DMU=1.D0
  320 CONTINUE
!
!        FORWARD RECURRENCE IN MU TO OBTAIN Q(MU1,NU2,X) AND
!              Q(MU1,NU2-1,X) USING
!              Q(MU+1,NU,X)=-2.*MU*X*SQRT(1./(1.-X**2))*Q(MU,NU,X)
!                   -(NU+MU)*(NU-MU+1.)*Q(MU-1,NU,X)
!
!              FIRST FOR NU=NU2
!
      X1=-2.D0*DMU*X*SX*PQ1
      X2=(NU+DMU)*(NU-DMU+1.D0)*PQ2
      CALL DXADD(X1,IPQ1,-X2,IPQ2,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      CALL DXADJ(PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      PQ2=PQ1
      IPQ2=IPQ1
      PQ1=PQ
      IPQ1=IPQ
      MU=MU+1
      DMU=DMU+1.D0
      IF(MU.LT.MU1) GO TO 320
      PQA(K)=PQ
      IPQA(K)=IPQ
      IF(K.EQ.1) RETURN
      IF(NU.LT.NU2) GO TO 340
!
!              THEN FOR NU=NU2-1
!
      NU=NU-1.D0
      PQ2=PQL2
      IPQ2=IPQL2
      PQ1=PQL1
      IPQ1=IPQL1
      K=K-1
      GO TO 300
!
!         BACKWARD RECURRENCE IN NU TO OBTAIN
!              Q(MU1,NU1,X),Q(MU1,NU1+1,X),....,Q(MU1,NU2,X)
!              USING
!              (NU-MU+1.)*Q(MU,NU+1,X)=
!                       (2.*NU+1.)*X*Q(MU,NU,X)-(NU+MU)*Q(MU,NU-1,X)
!
  340 PQ1=PQA(K)
      IPQ1=IPQA(K)
      PQ2=PQA(K+1)
      IPQ2=IPQA(K+1)
  350 IF(NU.LE.NU1) RETURN
      K=K-1
      X1=(2.D0*NU+1.D0)*X*PQ1/(NU+DMU)
      X2=-(NU-DMU+1.D0)*PQ2/(NU+DMU)
      CALL DXADD(X1,IPQ1,X2,IPQ2,PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      CALL DXADJ(PQ,IPQ,IERROR)
      IF (IERROR.NE.0) RETURN
      PQ2=PQ1
      IPQ2=IPQ1
      PQ1=PQ
      IPQ1=IPQ
      PQA(K)=PQ
      IPQA(K)=IPQ
      NU=NU-1.D0
      GO TO 350
      END SUBROUTINE DXQNU 
      SUBROUTINE DXRED (X, IX, IERROR)
!***BEGIN PROLOGUE  DXRED
!***PURPOSE  To provide double-precision floating-point arithmetic
!            with an extended exponent range.
!***LIBRARY   SLATEC
!***CATEGORY  A3D
!***TYPE      DOUBLE PRECISION (XRED-S, DXRED-D)
!***KEYWORDS  EXTENDED-RANGE DOUBLE-PRECISION ARITHMETIC
!***AUTHOR  Lozier, Daniel W., (NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY)
!           Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!     DOUBLE PRECISION X
!     INTEGER IX
!
!                  IF
!                  RADIX**(-2L) .LE. (ABS(X),IX) .LE. RADIX**(2L)
!                  THEN DXRED TRANSFORMS (X,IX) SO THAT IX=0.
!                  IF (X,IX) IS OUTSIDE THE ABOVE RANGE,
!                  THEN DXRED TAKES NO ACTION.
!                  THIS SUBROUTINE IS USEFUL IF THE
!                  RESULTS OF EXTENDED-RANGE CALCULATIONS
!                  ARE TO BE USED IN SUBSEQUENT ORDINARY
!                  DOUBLE-PRECISION CALCULATIONS.
!
!***SEE ALSO  DXSET
!***REFERENCES  (NONE)
!***ROUTINES CALLED  (NONE)
!***COMMON BLOCKS    DXBLK2
!***REVISION HISTORY  (YYMMDD)
!   820712  DATE WRITTEN
!   881020  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXRED
      DOUBLE PRECISION X
      INTEGER IX
      DOUBLE PRECISION RADIX, RADIXL, RAD2L, DLG10R, XA
      INTEGER L, L2, KMAX
      COMMON /DXBLK2/ RADIX, RADIXL, RAD2L, DLG10R, L, L2, KMAX
      SAVE /DXBLK2/
!
!***FIRST EXECUTABLE STATEMENT  DXRED
      IERROR=0
      IF (X.EQ.0.0D0) GO TO 90
      XA = ABS(X)
      IF (IX.EQ.0) GO TO 70
      IXA = ABS(IX)
      IXA1 = IXA/L2
      IXA2 = MOD(IXA,L2)
      IF (IX.GT.0) GO TO 40
   10 CONTINUE
      IF (XA.GT.1.0D0) GO TO 20
      XA = XA*RAD2L
      IXA1 = IXA1 + 1
      GO TO 10
   20 XA = XA/RADIX**IXA2
      IF (IXA1.EQ.0) GO TO 70
      DO 30 I=1,IXA1
        IF (XA.LT.1.0D0) GO TO 100
        XA = XA/RAD2L
   30 CONTINUE
      GO TO 70
!
   40 CONTINUE
      IF (XA.LT.1.0D0) GO TO 50
      XA = XA/RAD2L
      IXA1 = IXA1 + 1
      GO TO 40
   50 XA = XA*RADIX**IXA2
      IF (IXA1.EQ.0) GO TO 70
      DO 60 I=1,IXA1
        IF (XA.GT.1.0D0) GO TO 100
        XA = XA*RAD2L
   60 CONTINUE
   70 IF (XA.GT.RAD2L) GO TO 100
      IF (XA.GT.1.0D0) GO TO 80
      IF (RAD2L*XA.LT.1.0D0) GO TO 100
   80 X = SIGN(XA,X)
   90 IX = 0
  100 RETURN
      END SUBROUTINE DXRED 
      SUBROUTINE DXSET (IRAD, NRADPL, DZERO, NBITS, IERROR)
!***BEGIN PROLOGUE  DXSET
!***PURPOSE  To provide double-precision floating-point arithmetic
!            with an extended exponent range.
!***LIBRARY   SLATEC
!***CATEGORY  A3D
!***TYPE      DOUBLE PRECISION (XSET-S, DXSET-D)
!***KEYWORDS  EXTENDED-RANGE DOUBLE-PRECISION ARITHMETIC
!***AUTHOR  Lozier, Daniel W., (NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY)
!           Smith, John M., (NBS and George Mason University)
!***DESCRIPTION
!
!   SUBROUTINE  DXSET  MUST BE CALLED PRIOR TO CALLING ANY OTHER
! EXTENDED-RANGE SUBROUTINE. IT CALCULATES AND STORES SEVERAL
! MACHINE-DEPENDENT CONSTANTS IN COMMON BLOCKS. THE USER MUST
! SUPPLY FOUR CONSTANTS THAT PERTAIN TO HIS PARTICULAR COMPUTER.
! THE CONSTANTS ARE
!
!          IRAD = THE INTERNAL BASE OF DOUBLE-PRECISION
!                 ARITHMETIC IN THE COMPUTER.
!        NRADPL = THE NUMBER OF RADIX PLACES CARRIED IN
!                 THE DOUBLE-PRECISION REPRESENTATION.
!         DZERO = THE SMALLEST OF 1/DMIN, DMAX, DMAXLN WHERE
!                 DMIN = THE SMALLEST POSITIVE DOUBLE-PRECISION
!                 NUMBER OR AN UPPER BOUND TO THIS NUMBER,
!                 DMAX = THE LARGEST DOUBLE-PRECISION NUMBER
!                 OR A LOWER BOUND TO THIS NUMBER,
!                 DMAXLN = THE LARGEST DOUBLE-PRECISION NUMBER
!                 SUCH THAT LOG10(DMAXLN) CAN BE COMPUTED BY THE
!                 FORTRAN SYSTEM (ON MOST SYSTEMS DMAXLN = DMAX).
!         NBITS = THE NUMBER OF BITS (EXCLUSIVE OF SIGN) IN
!                 AN INTEGER COMPUTER WORD.
!
! ALTERNATIVELY, ANY OR ALL OF THE CONSTANTS CAN BE GIVEN
! THE VALUE 0 (0.0D0 FOR DZERO). IF A CONSTANT IS ZERO, DXSET TRIES
! TO ASSIGN AN APPROPRIATE VALUE BY CALLING I1MACH
! (SEE P.A.FOX, A.D.HALL, N.L.SCHRYER, ALGORITHM 528 FRAMEWORK
! FOR A PORTABLE LIBRARY, ACM TRANSACTIONS ON MATH SOFTWARE,
! V.4, NO.2, JUNE 1978, 177-188).
!
!   THIS IS THE SETTING-UP SUBROUTINE FOR A PACKAGE OF SUBROUTINES
! THAT FACILITATE THE USE OF EXTENDED-RANGE ARITHMETIC. EXTENDED-RANGE
! ARITHMETIC ON A PARTICULAR COMPUTER IS DEFINED ON THE SET OF NUMBERS
! OF THE FORM
!
!               (X,IX) = X*RADIX**IX
!
! WHERE X IS A DOUBLE-PRECISION NUMBER CALLED THE PRINCIPAL PART,
! IX IS AN INTEGER CALLED THE AUXILIARY INDEX, AND RADIX IS THE
! INTERNAL BASE OF THE DOUBLE-PRECISION ARITHMETIC.  OBVIOUSLY,
! EACH REAL NUMBER IS REPRESENTABLE WITHOUT ERROR BY MORE THAN ONE
! EXTENDED-RANGE FORM.  CONVERSIONS BETWEEN  DIFFERENT FORMS ARE
! ESSENTIAL IN CARRYING OUT ARITHMETIC OPERATIONS.  WITH THE CHOICE
! OF RADIX WE HAVE MADE, AND THE SUBROUTINES WE HAVE WRITTEN, THESE
! CONVERSIONS ARE PERFORMED WITHOUT ERROR (AT LEAST ON MOST COMPUTERS).
! (SEE SMITH, J.M., OLVER, F.W.J., AND LOZIER, D.W., EXTENDED-RANGE
! ARITHMETIC AND NORMALIZED LEGENDRE POLYNOMIALS, ACM TRANSACTIONS ON
! MATHEMATICAL SOFTWARE, MARCH 1981).
!
!   AN EXTENDED-RANGE NUMBER  (X,IX)  IS SAID TO BE IN ADJUSTED FORM IF
! X AND IX ARE ZERO OR
!
!           RADIX**(-L) .LE. ABS(X) .LT. RADIX**L
!
! IS SATISFIED, WHERE L IS A COMPUTER-DEPENDENT INTEGER DEFINED IN THIS
! SUBROUTINE. TWO EXTENDED-RANGE NUMBERS IN ADJUSTED FORM CAN BE ADDED,
! SUBTRACTED, MULTIPLIED OR DIVIDED (IF THE DIVISOR IS NONZERO) WITHOUT
! CAUSING OVERFLOW OR UNDERFLOW IN THE PRINCIPAL PART OF THE RESULT.
! WITH PROPER USE OF THE EXTENDED-RANGE SUBROUTINES, THE ONLY OVERFLOW
! THAT CAN OCCUR IS INTEGER OVERFLOW IN THE AUXILIARY INDEX. IF THIS
! IS DETECTED, THE SOFTWARE CALLS XERROR (A GENERAL ERROR-HANDLING
! FORTRAN SUBROUTINE PACKAGE).
!
!   MULTIPLICATION AND DIVISION IS PERFORMED BY SETTING
!
!                 (X,IX)*(Y,IY) = (X*Y,IX+IY)
! OR
!                 (X,IX)/(Y,IY) = (X/Y,IX-IY).
!
! PRE-ADJUSTMENT OF THE OPERANDS IS ESSENTIAL TO AVOID
! OVERFLOW OR  UNDERFLOW OF THE PRINCIPAL PART. SUBROUTINE
! DXADJ (SEE BELOW) MAY BE CALLED TO TRANSFORM ANY EXTENDED-
! RANGE NUMBER INTO ADJUSTED FORM.
!
!   ADDITION AND SUBTRACTION REQUIRE THE USE OF SUBROUTINE DXADD
! (SEE BELOW).  THE INPUT OPERANDS NEED NOT BE IN ADJUSTED FORM.
! HOWEVER, THE RESULT OF ADDITION OR SUBTRACTION IS RETURNED
! IN ADJUSTED FORM.  THUS, FOR EXAMPLE, IF (X,IX),(Y,IY),
! (U,IU),  AND (V,IV) ARE IN ADJUSTED FORM, THEN
!
!                 (X,IX)*(Y,IY) + (U,IU)*(V,IV)
!
! CAN BE COMPUTED AND STORED IN ADJUSTED FORM WITH NO EXPLICIT
! CALLS TO DXADJ.
!
!   WHEN AN EXTENDED-RANGE NUMBER IS TO BE PRINTED, IT MUST BE
! CONVERTED TO AN EXTENDED-RANGE FORM WITH DECIMAL RADIX.  SUBROUTINE
! DXCON IS PROVIDED FOR THIS PURPOSE.
!
!   THE SUBROUTINES CONTAINED IN THIS PACKAGE ARE
!
!     SUBROUTINE DXADD
! USAGE
!                  CALL DXADD(X,IX,Y,IY,Z,IZ,IERROR)
!                  IF (IERROR.NE.0) RETURN
! DESCRIPTION
!                  FORMS THE EXTENDED-RANGE SUM  (Z,IZ) =
!                  (X,IX) + (Y,IY).  (Z,IZ) IS ADJUSTED
!                  BEFORE RETURNING. THE INPUT OPERANDS
!                  NEED NOT BE IN ADJUSTED FORM, BUT THEIR
!                  PRINCIPAL PARTS MUST SATISFY
!                  RADIX**(-2L).LE.ABS(X).LE.RADIX**(2L),
!                  RADIX**(-2L).LE.ABS(Y).LE.RADIX**(2L).
!
!     SUBROUTINE DXADJ
! USAGE
!                  CALL DXADJ(X,IX,IERROR)
!                  IF (IERROR.NE.0) RETURN
! DESCRIPTION
!                  TRANSFORMS (X,IX) SO THAT
!                  RADIX**(-L) .LE. ABS(X) .LT. RADIX**L.
!                  ON MOST COMPUTERS THIS TRANSFORMATION DOES
!                  NOT CHANGE THE MANTISSA OF X PROVIDED RADIX IS
!                  THE NUMBER BASE OF DOUBLE-PRECISION ARITHMETIC.
!
!     SUBROUTINE DXC210
! USAGE
!                  CALL DXC210(K,Z,J,IERROR)
!                  IF (IERROR.NE.0) RETURN
! DESCRIPTION
!                  GIVEN K THIS SUBROUTINE COMPUTES J AND Z
!                  SUCH THAT  RADIX**K = Z*10**J, WHERE Z IS IN
!                  THE RANGE 1/10 .LE. Z .LT. 1.
!                  THE VALUE OF Z WILL BE ACCURATE TO FULL
!                  DOUBLE-PRECISION PROVIDED THE NUMBER
!                  OF DECIMAL PLACES IN THE LARGEST
!                  INTEGER PLUS THE NUMBER OF DECIMAL
!                  PLACES CARRIED IN DOUBLE-PRECISION DOES NOT
!                  EXCEED 60. DXC210 IS CALLED BY SUBROUTINE
!                  DXCON WHEN NECESSARY. THE USER SHOULD
!                  NEVER NEED TO CALL DXC210 DIRECTLY.
!
!     SUBROUTINE DXCON
! USAGE
!                  CALL DXCON(X,IX,IERROR)
!                  IF (IERROR.NE.0) RETURN
! DESCRIPTION
!                  CONVERTS (X,IX) = X*RADIX**IX
!                  TO DECIMAL FORM IN PREPARATION FOR
!                  PRINTING, SO THAT (X,IX) = X*10**IX
!                  WHERE 1/10 .LE. ABS(X) .LT. 1
!                  IS RETURNED, EXCEPT THAT IF
!                  (ABS(X),IX) IS BETWEEN RADIX**(-2L)
!                  AND RADIX**(2L) THEN THE REDUCED
!                  FORM WITH IX = 0 IS RETURNED.
!
!     SUBROUTINE DXRED
! USAGE
!                  CALL DXRED(X,IX,IERROR)
!                  IF (IERROR.NE.0) RETURN
! DESCRIPTION
!                  IF
!                  RADIX**(-2L) .LE. (ABS(X),IX) .LE. RADIX**(2L)
!                  THEN DXRED TRANSFORMS (X,IX) SO THAT IX=0.
!                  IF (X,IX) IS OUTSIDE THE ABOVE RANGE,
!                  THEN DXRED TAKES NO ACTION.
!                  THIS SUBROUTINE IS USEFUL IF THE
!                  RESULTS OF EXTENDED-RANGE CALCULATIONS
!                  ARE TO BE USED IN SUBSEQUENT ORDINARY
!                  DOUBLE-PRECISION CALCULATIONS.
!
!***REFERENCES  Smith, Olver and Lozier, Extended-Range Arithmetic and
!                 Normalized Legendre Polynomials, ACM Trans on Math
!                 Softw, v 7, n 1, March 1981, pp 93--105.
!***ROUTINES CALLED  I1MACH, XERMSG
!***COMMON BLOCKS    DXBLK1, DXBLK2, DXBLK3
!***REVISION HISTORY  (YYMMDD)
!   820712  DATE WRITTEN
!   881020  Revised to meet SLATEC CML recommendations.  (DWL and JMS)
!   901019  Revisions to prologue.  (DWL and WRB)
!   901106  Changed all specific intrinsics to generic.  (WRB)
!           Corrected order of sections in prologue and added TYPE
!           section.  (WRB)
!           CALLs to XERROR changed to CALLs to XERMSG.  (WRB)
!   920127  Revised PURPOSE section of prologue.  (DWL)
!***END PROLOGUE  DXSET
      INTEGER IRAD, NRADPL, NBITS
      DOUBLE PRECISION DZERO, DZEROX
      COMMON /DXBLK1/ NBITSF
      SAVE /DXBLK1/
      DOUBLE PRECISION RADIX, RADIXL, RAD2L, DLG10R
      INTEGER L, L2, KMAX
      COMMON /DXBLK2/ RADIX, RADIXL, RAD2L, DLG10R, L, L2, KMAX
      SAVE /DXBLK2/
      INTEGER NLG102, MLG102, LG102
      COMMON /DXBLK3/ NLG102, MLG102, LG102(21)
      SAVE /DXBLK3/
      INTEGER IFLAG
      SAVE IFLAG
!
      DIMENSION LOG102(20), LGTEMP(20)
      SAVE LOG102
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!
!   LOG102 CONTAINS THE FIRST 60 DIGITS OF LOG10(2) FOR USE IN
! CONVERSION OF EXTENDED-RANGE NUMBERS TO BASE 10 .
      DATA LOG102 /301,029,995,663,981,195,213,738,894,724,493,026,768,   &
       189,881,462,108,541,310,428/
!
! FOLLOWING CODING PREVENTS DXSET FROM BEING EXECUTED MORE THAN ONCE.
! THIS IS IMPORTANT BECAUSE SOME SUBROUTINES (SUCH AS DXNRMP AND
! DXLEGF) CALL DXSET TO MAKE SURE EXTENDED-RANGE ARITHMETIC HAS
! BEEN INITIALIZED. THE USER MAY WANT TO PRE-EMPT THIS CALL, FOR
! EXAMPLE WHEN I1MACH IS NOT AVAILABLE. SEE CODING BELOW.
      DATA IFLAG /0/
!***FIRST EXECUTABLE STATEMENT  DXSET
      IERROR=0
      IF (IFLAG .NE. 0) RETURN
      IRADX = IRAD
      NRDPLC = NRADPL
      DZEROX = DZERO
      IMINEX = 0
      IMAXEX = 0
      NBITSX = NBITS
! FOLLOWING 5 STATEMENTS SHOULD BE DELETED IF I1MACH IS
! NOT AVAILABLE OR NOT CONFIGURED TO RETURN THE CORRECT
! MACHINE-DEPENDENT VALUES.
      IF (IRADX .EQ. 0) IRADX = I1MACH (10)
      IF (NRDPLC .EQ. 0) NRDPLC = I1MACH (14)
      IF (DZEROX .EQ. 0.0D0) IMINEX = I1MACH (15)
      IF (DZEROX .EQ. 0.0D0) IMAXEX = I1MACH (16)
      IF (NBITSX .EQ. 0) NBITSX = I1MACH (8)
      IF (IRADX.EQ.2) GO TO 10
      IF (IRADX.EQ.4) GO TO 10
      IF (IRADX.EQ.8) GO TO 10
      IF (IRADX.EQ.16) GO TO 10
!CCCC CALL XERMSG ('SLATEC', 'DXSET', 'IMPROPER VALUE OF IRAD', 201, 1)
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
  901 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF IRAD.')
      IERROR=201
      RETURN
   10 CONTINUE
      LOG2R=0
      IF (IRADX.EQ.2) LOG2R = 1
      IF (IRADX.EQ.4) LOG2R = 2
      IF (IRADX.EQ.8) LOG2R = 3
      IF (IRADX.EQ.16) LOG2R = 4
      NBITSF=LOG2R*NRDPLC
      RADIX = IRADX
      DLG10R = LOG10(RADIX)
      IF (DZEROX .NE. 0.0D0) GO TO 14
      LX = MIN ((1-IMINEX)/2, (IMAXEX-1)/2)
      GO TO 16
   14 CONTINUE
      LX = INT(0.5D0*LOG10(DZEROX)/DLG10R)
! RADIX**(2*L) SHOULD NOT OVERFLOW, BUT REDUCE L BY 1 FOR FURTHER
! PROTECTION.
      LX=LX-1
   16 CONTINUE
      L2 = 2*LX
      IF (LX.GE.4) GO TO 20
!CCCC CALL XERMSG ('SLATEC', 'DXSET', 'IMPROPER VALUE OF DZERO', 202, 1)
      WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
  902 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF DZERO.')
      IERROR=202
      RETURN
   20 CONTINUE
      L = LX
      RADIXL = RADIX**L
      RAD2L = RADIXL**2
!    IT IS NECESSARY TO RESTRICT NBITS (OR NBITSX) TO BE LESS THAN SOME
! UPPER LIMIT BECAUSE OF BINARY-TO-DECIMAL CONVERSION. SUCH CONVERSION
! IS DONE BY DXC210 AND REQUIRES A CONSTANT THAT IS STORED TO SOME FIXED
! PRECISION. THE STORED CONSTANT (LOG102 IN THIS ROUTINE) PROVIDES
! FOR CONVERSIONS ACCURATE TO THE LAST DECIMAL DIGIT WHEN THE INTEGER
! WORD LENGTH DOES NOT EXCEED 63. A LOWER LIMIT OF 15 BITS IS IMPOSED
! BECAUSE THE SOFTWARE IS DESIGNED TO RUN ON COMPUTERS WITH INTEGER WORD
! LENGTH OF AT LEAST 16 BITS.
      IF (15.LE.NBITSX .AND. NBITSX.LE.63) GO TO 30
!CCCC CALL XERMSG ('SLATEC', 'DXSET', 'IMPROPER VALUE OF NBITS', 203, 1)
      WRITE(ICOUT,913)
      CALL DPWRST('XXX','BUG ')
  913 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF NBITS.')
      IERROR=203
      RETURN
   30 CONTINUE
      KMAX = 2**(NBITSX-1) - L2
      NB = (NBITSX-1)/2
      MLG102 = 2**NB
      IF (1.LE.NRDPLC*LOG2R .AND. NRDPLC*LOG2R.LE.120) GO TO 40
!CCCC CALL XERMSG ('SLATEC', 'DXSET', 'IMPROPER VALUE OF NRADPL', 204,
!CCCC+             1)
      WRITE(ICOUT,903)
      CALL DPWRST('XXX','BUG ')
  903 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF NRADPL.')
      IERROR=204
      RETURN
   40 CONTINUE
      NLG102 = NRDPLC*LOG2R/NB + 3
      NP1 = NLG102 + 1
!
!   AFTER COMPLETION OF THE FOLLOWING LOOP, IC CONTAINS
! THE INTEGER PART AND LGTEMP CONTAINS THE FRACTIONAL PART
! OF LOG10(IRADX) IN RADIX 1000.
      IC = 0
      DO 50 II=1,20
        I = 21 - II
        IT = LOG2R*LOG102(I) + IC
        IC = IT/1000
        LGTEMP(I) = MOD(IT,1000)
   50 CONTINUE
!
!   AFTER COMPLETION OF THE FOLLOWING LOOP, LG102 CONTAINS
! LOG10(IRADX) IN RADIX MLG102. THE RADIX POINT IS
! BETWEEN LG102(1) AND LG102(2).
      LG102(1) = IC
      DO 80 I=2,NP1
        LG102X = 0
        DO 70 J=1,NB
          IC = 0
          DO 60 KK=1,20
            K = 21 - KK
            IT = 2*LGTEMP(K) + IC
            IC = IT/1000
            LGTEMP(K) = MOD(IT,1000)
   60     CONTINUE
          LG102X = 2*LG102X + IC
   70   CONTINUE
        LG102(I) = LG102X
   80 CONTINUE
!
! CHECK SPECIAL CONDITIONS REQUIRED BY SUBROUTINES...
      IF (NRDPLC.LT.L) GO TO 90
!CCCC CALL XERMSG ('SLATEC', 'DXSET', 'NRADPL .GE. L', 205, 1)
      WRITE(ICOUT,904)
      CALL DPWRST('XXX','BUG ')
  904 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF NRADPL.')
      IERROR=205
      RETURN
   90 IF (6*L.LE.KMAX) GO TO 100
!CCCC CALL XERMSG ('SLATEC', 'DXSET', '6*L .GT. KMAX', 206, 1)
      WRITE(ICOUT,905)
      CALL DPWRST('XXX','BUG ')
  905 FORMAT('***** ERROR FROM DXSET, IMPROPER VALUE OF L.')
      IERROR=206
      RETURN
  100 CONTINUE
      IFLAG = 1
      RETURN
      END SUBROUTINE DXSET 
      SUBROUTINE D3DEDC(X,Y,Z,N,   &
                        X3DEYE,Y3DEYE,Z3DEYE,   &
                        D3DCXX,D3DCXY,D3DCXZ,   &
                        D3DCYX,D3DCYY,D3DCYZ,   &
                        D3DCZX,D3DCZY,D3DCZZ,   &
                        TERMXX,TERMXY,TERMXZ,   &
                        TERMYX,TERMYY,TERMYZ,   &
                        TERMZX,TERMZY,TERMZZ,   &
                        IBUGPL,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE DIRECTION COSINES
!              WHICH WILL BE NEEDED TO ROTATE
!              THE 3-D DATA CLOUD ONTO A 2-D PLANE.
!     NOTE--THE DN.. ARE DIRECTION NUMBERS.
!           THE DC.. ARE DIRECTION COSINES.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--MARCH     1979.
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
!
      CHARACTER*4 IBUGPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3DE'
      ISUBN2='DC  '
      IERROR='NO'
!
      EPS=0.0000001
!
      IF(IBUGPL.EQ.'OFF'.AND.ISUBRO.NE.'DEDC')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3DEDC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGPL,ISUBRO,IERROR,N
   52 FORMAT('IBUGPL,ISUBRO,IERROR,N = ',3(A4,2X),I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)X3DEYE,Y3DEYE,Z3DEYE
   61 FORMAT('X3DEYE, Y3DEYE, Z3DEYE  = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 70 II=1,N
        WRITE(ICOUT,73)II,X(II),Y(II),Z(II)
   73   FORMAT('II,X(II),Y(II),Z(II) = ',I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
   70 CONTINUE
   90 CONTINUE
!
!               *********************************************************
!               **  GENERAL DISCUSSION--                               **
!               **  DETERMINE (IN ORIGINAL COORDINATE SYSTEM VALUES)   **
!               **  WHERE THE DATA POINTS FALL ON THE VISUAL PLANE.    **
!               **  FOR EACH (XD,YD,ZD) DATA POINT,                    **
!               **  DETERMINE WHERE THE VISUAL RAY FROM                **
!               **  THE DATA POINT TO OUR EYE                          **
!               **  STRIKES THE VISUAL (PERSPECTIVE) PLANE.            **
!               **  THE VISUAL PLANE IS THAT PLANE                     **
!               **  WHICH IS NORMAL TO OUR EYE                         **
!               **  AND WHICH CONTAINS THE AVERAGE POINT (XM,YM,ZM).   **
!               **  THE EQUATION OF THE VISUAL PLANE IS                **
!               **  (X3DEYE-XM)(X-XM) + (Y3DEYE-YM)(Y-YM) +
!               **                    + (Z3DEYE-YM)(Z-ZM) = 0          **
!               **  WHERE X, Y, Z ARE THE DUMMY VARIABLES              **
!               **  REPRESENTING ANY POINT (X,Y,Z) ON THAT PLANE.      **
!               **  THIS EQUATION MUST BE SOLVED FOR X, Y, AND Z.      **
!               **  THE EQUATIONS OF THE LINE FROM THE DATA POINT
!               **  (XD,YD,ZD)
!               **  TO OUR EYE (X3DEYE,Y3DEYE,Z3DEYE) ARE
!               **  (X-XD)/(X3DEYE-XD) = (Y-YD)/(Y3DEYE-YD)
!               **                     = (Z-ZD)/(Z3DEYE-ZD)
!               **  WHERE (XD,YD,ZD) REPRESENTS A DATA POINT.           **
!               **  THE VISUAL PLANE EQUATION AND THE LINE EQUATIONS    **
!               **  MUST BE COMBINED TO SOLVE FOR THE VALUES (X,Y,Z)    **
!               **  ON THE VISUAL PLANE AS OUR EYE SEES THEM.           **
!               **********************************************************
!
!               **********************************************************
!               **  THE FINAL PLOT STATEMENT WILL INVOLVE
!               **  ONLY 2 VECTORS.
!               **  AT THE MOMENT, THE POINTS (XP,YP,ZP)
!               **  ON THE VISUAL PLANE ARE DEFINED
!               **  BY 3 COORDINATE VALUES.
!               **  TO REDUCE THE 3 COORDINATE VALUES
!               **  TO 2 COORDINATE VALUES,
!               **  WE MUST ROTATE THE VISUAL PLANE
!               **  SO THAT IT IS PARALLEL TO THE ORIGINAL XZ PLANE.
!               **  TO CARRY OUT SUCH A ROTATION, WE MUST
!               **  DETERMINE THE DIRECTION NUMBERS AND DIRECTION COSINES
!               **  OF THE NEW AXES IN TERMS OF THE OLD COORDINATE SYSTEM.
!               **  THE NEW Y AXIS WILL (BY CONSTRUCTION) BE
!               **  ON THE NORMAL LINE TRAVELING FROM
!               **  THE AVERAGE POINT (XM,YM,ZM) TO OUR EYE POINT
!               **  (X3DEYE,Y3DEYE,Z3DEYE)
!               **  AND WILL THEREFORE HAVE DIRECTIONS NUMBERS
!               **  X3DEYE, Y3DEYE, Z3DEYE
!               **  THE NEW Z AXIS WILL BE PERPENDICULAR TO THE NEW Y AXIS
!               **  AND WILL RESIDE IN THE PLANE CONTAINING THE
!               **  THE FOLLOWING 3 POINTS--
!               **      1) THE AVERAGE POINT (XM,YM,ZM)
!               **      2) THE EYE POINT (X3DEYE,Y3DEYE,Z3DEYE)
!               **      3) SOME POINT (SAY (XM,YM,ZM+1)) OF THE OLD Z AXIS
!               **         DISPLACED OVER SO AS TO EMANATE FROM (XM,YM,ZM).
!               **  THE ABOVE 3 POINTS DEFINE A VERTICAL PLANE.
!               **  THE PURPOSE OF THE VERTICAL PLANE IS TO DEFINE
!               **  WHICH DIRECTION IS 'UP' IN THE FINAL PICTURE.
!               **  THE EQUATION OF THE VERTICAL PLANE IS
!               **  (A-XM)(X-XM) + (B-YM)(Y-YM) + (C-ZM)(Z-ZM) = 0 .
!               **  THIS EQUATION MUST BE SOLVED FOR A, B, AND C.
!               **  WITHOUT LOSS OF GENERALITY, A MAY BE INITIALLY SET TO 1.
!               **  THE SOLUTION TURNS OUT TO BE
!               **      A = 1
!               **      B = -X3DEYE/Y3DEYE
!               **      C = 0
!               **  NOTE, HOWEVER, THAT THESE A, B, AND C VALUES
!               **  FOR THIS VERTICAL PLANE WILL BE IDENTICAL TO THE
!               **  DIRECTION NUMBERS FOR THE NORMAL TO THIS VERTICAL PLANE
!               **  WHICH IS IDENTICALLY THE NEW X AXIS
!               **  AND SO THE ABOVE A, B, AND C VALUES DEFINE THE DIRECTION
!               **  DIRECTION NUMBERS FOR THE NEW X AXIS.
!               **  TO SOLVE FOR THE DIRECTION NUMBERS FOR THE NEW Z AXIS,
!               **  WE SEEK 3 DIRECTION NUMBERS D, E, AND F
!               **  WHICH MUST BE PERPENDICULAR TO BOTH THE
!               **  NEW Y AXIS (WITH DIRECTION NUMBERS X3DEYE, Y3DEYE,
!               **  AND Z3DEYE)
!               **  AND THE NEW X AXIS (WITH DIRECTION NUMBERS A, B, AND C ABOVE
!               **  WITHOUT LOSS OF GENERALITY, D MAY BE INITIALLY SET TO 1.
!               **  NOTE THAT WHENEVER 2 LINES ARE PERPENDICULAR,
!               **  THE INNER PRODUCT OF THE DIRECTION NUMBERS MUST = 0.
!               **  WITHOUT LOSS OF GENERALITY, D MAY BE INITIALLY SET TO 1.
!               **  INCORPORATING THE 2 INNER PRODUCT EQUATIONS,
!               **  WE MAY SOLVE FOR E AND F.
!               **  THE SOLUTIONS TURN OUT TO BE
!               **      D = 1
!               **      E = Y3DEYE/X3DEYE
!               **      F = (-X3DEYE*X3DEYE - Y3DEYE*Y3DEYE) / (X3DEYE*Z3DEYE)
!               **
!               **  IN SUMMARY, THE DIRECTION NUMBERS FOR THE 3 NEW AXES
!               **  MAY BE WRITTEN AS
!               **      NEW X AXIS:  Y3DEYE       -X3DEYE     0
!               **      NEW Y AXIS:  X3DEYE       Y3DEYE      Z3DEYE
!               **      NEW Z AXIS:  -X3DEYE*Z3DEYE   -Y3DEYE*Z3DEYE
!               **                                        X3DEYE*X3DEYE+Y3DEYE
!               **  NOTE THAT BY INSPECTION WE SEE RETROSPECTIVELY
!               **  THAT THE 3 INNER PRODUCTS ALL = 0
!               **  AND SO THE 3 DEFINED AXES ARE ALL PERPENDICULAR
!               **  (AS THEY SHOULD BE).
!               **
!               **  THE CORRESPONDING DIRECTION COSINES
!               **  ARE GOTTEN BY NORMALIZATION TO UNITY;
!               **  LET US SYMBOLICALLY REPRESENT THEM BY--
!               **      D3DCXX   D3DCXY   D3DCXZ
!               **      D3DCYX   D3DCYY   D3DCYZ
!               **      D3DCZX   D3DCZY   D3DCZZ
!               **  THE ABOVE RESULTS WERE ACTUALLY ARRIVED AT
!               **  (AND ARE VALID FOR) BY DISPLACING THE OLD ORIGIN
!               **  FROM (0,0,0) TO (XM,YM,ZM).
!               **  THIS SIMPLIFIES THE EQUATIONS CONSIDERABLY.
!               **
!               **  GIVEN THAT WE NOW HAVE THE DIRECTION COSINES
!               **  OF THE NEW AXES IN TERMS OF THE OLD COORDINATES,
!               **  WE MAKE USE OF
!               **  EISENHART (COORDINATE GEOMETRY, PAGE 160) WHICH STATES
!               **  THAT THE LINEAR TRANSFORMATION THAT IS NEEDED TO CARRY OUT
!               **  THE ROTATION FROM THE VISUAL PLANE TO THE XZ PLANE
!               **  IS GIVEN BY
!               **      XT = XM + D3DCXX(X-XM) + D3DCXY(Y-YM) + D3DCXZ(Z-ZM)
!               **      YT = YM + D3DCYX(X-XM) + D3DCYY(Y-YM) + D3DCYZ(Z-ZM)
!               **      ZT = ZM + D3DCZX(X-XM) + D3DCZY(Y-YM) + D3DCZZ(Z-ZM)
!               **
!               **  NOTE THAT BY INSPECTION OF THE ABOVE TRANSFORMATION
!               **  IT IS SEEN THAT (XM,YM,ZM) IS MAPPED INTO (XM,YM,ZM)
!               **  (AS IT SHOULD BE).
!               **  NOTE ALSO THAT THE EYE POINT AND ANY POINT ALONG THE LINE
!               **  OF SIGHT WOULD HAVE BEEN MAPPED INTO (XM,YM,ZM)
!               **  AS IT SHOULD BE.
!               **  NOTE ALSO THAT ALL POINTS ON THE VISUAL PLANE
!               **  SINCE THEY SATISFY
!               **     (X3DEYE-XM)(X-XM) + (Y3DEYE-YM)(Y-YM) + (Z3DEYE-ZM)(Z-ZM)
!               **     = 0
!               **  GETS MAPPED INTO THE CONSTANT YT VALUE OF YT = YM
!               **  AND SO THE TRANSFORMED PLOT SURFACE IS ONE WHICH
!               **  IS PARALLEL TO THE XZ PLANE BUT IS DISPLACED
!               **  YM UNITS OUT FROM THE XZ PLANE.
!               **  THIS PLOT PLANE WILL CONTAIN THE POINT (XM,YM,ZM).
!               ****************************************************************
!
      ISTEPN='31'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DEDC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DNXX=Y3DEYE
      DNXY=-X3DEYE
      DNXZ=0.0
      DNYX=X3DEYE
      DNYY=Y3DEYE
      DNYZ=Z3DEYE
      DNZX=-X3DEYE*Z3DEYE
      DNZY=-Y3DEYE*Z3DEYE
      DNZZ=X3DEYE*X3DEYE+Y3DEYE*Y3DEYE
!
      ARGX=DNXX**2+DNXY**2+DNXZ**2
      ARGY=DNYX**2+DNYY**2+DNYZ**2
      ARGZ=DNZX**2+DNZY**2+DNZZ**2
      DENOMX=0.0
      DENOMY=0.0
      DENOMZ=0.0
      IF(ARGX.GT.0.0)DENOMX=SQRT(ARGX)
      IF(ARGY.GT.0.0)DENOMY=SQRT(ARGY)
      IF(ARGZ.GT.0.0)DENOMZ=SQRT(ARGZ)
!
!     ***** 15 LINES OF CODE TO CHECK FOR DIVISION BY 0 ADDED AUGUST 1983 *****
!
      D3DCXX=CPUMAX
      D3DCXY=CPUMAX
      D3DCXZ=CPUMAX
      IF(DENOMX.EQ.0.0)GO TO 1119
      D3DCXX=DNXX/DENOMX
      D3DCXY=DNXY/DENOMX
      D3DCXZ=DNXZ/DENOMX
 1119 CONTINUE
!
      D3DCYX=CPUMAX
      D3DCYY=CPUMAX
      D3DCYZ=CPUMAX
      IF(DENOMY.EQ.0.0)GO TO 1129
      D3DCYX=DNYX/DENOMY
      D3DCYY=DNYY/DENOMY
      D3DCYZ=DNYZ/DENOMY
 1129 CONTINUE
!
      D3DCZX=CPUMAX
      D3DCZY=CPUMAX
      D3DCZZ=CPUMAX
      IF(DENOMZ.EQ.0.0)GO TO 1139
      D3DCZX=DNZX/DENOMZ
      D3DCZY=DNZY/DENOMZ
      D3DCZZ=DNZZ/DENOMZ
 1139 CONTINUE
!
!     THE FOLLOWING IS FROM EIDE ET AL (1985),
!     ENGINEERING GRAPHICS FUNDAMENTALS
!     PAGE 386-387, FORMULA 17.42.
!     ALPHA IS THE ANGLE FROM MY XY (= BOTTTOM) PLANE TO THE EYE VECTOR
!     BETA  IS THE ANGLE FROM MY YZ (= LEFT) TO THE EYE VECTOR
!     (NOTE DIFFERENCE HERE TO EIDE'S NOTATION, HIS Z = MY Y, & VV.)
!
      ARGALP=X3DEYE**2+Y3DEYE**2+Z3DEYE**2
      DENALP=0.0
      IF(ARGALP.GT.0.0)DENALP=SQRT(ARGALP)
      SINALP=Z3DEYE/DENALP
      COSALP=SQRT(1.0-SINALP**2)
!
      SINBET=0.0
      COSBET=1.0
      DENBET=0.0
      ARGBET=X3DEYE**2+Y3DEYE**2
      IF(ARGBET.LE.EPS)GO TO 1159
      IF(ARGBET.GT.EPS)DENBET=SQRT(ARGBET)
      SINBET=X3DEYE/DENBET
      COSBET=SQRT(1.0-SINBET**2)
 1159 CONTINUE
!
      TERMXX=COSBET
      TERMXY=(-SINBET)
      TERMXZ=0.0
!
      TERMYX=COSALP*SINBET
      TERMYY=COSALP*COSBET
      TERMYZ=SINALP
!
      TERMZX=(-SINALP*SINBET)
      TERMZY=(-SINALP*COSBET)
      TERMZZ=COSALP
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGPL.EQ.'OFF'.AND.ISUBRO.NE.'DEDC')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3DEDC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGPL,ISUBRO,IERROR
 9012 FORMAT('IBUGPL,ISUBRO,IERROR = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)X3DEYE,Y3DEYE,Z3DEYE
 9013 FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)DNXX,DNXY,DNXZ
 9021 FORMAT('DNXX,DNXY,DNXZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)DNYX,DNYY,DNYZ
 9022 FORMAT('DNYX,DNYY,DNYZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)DNYX,DNYY,DNYZ
 9023 FORMAT('DNZX,DNZY,DNZZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9024)D3DCXX,D3DCXY,D3DCXZ
 9024 FORMAT('D3DCXX,D3DCXY,D3DCXZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9025)D3DCYX,D3DCYY,D3DCYZ
 9025 FORMAT('D3DCYX,D3DCYY,D3DCYZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9026)D3DCZX,D3DCZY,D3DCZZ
 9026 FORMAT('D3DCZX,D3DCZY,D3DCZZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9034)TERMXX,TERMXY,TERMXZ
 9034 FORMAT('TERMXX,TERMXY,TERMXZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9035)TERMYX,TERMYY,TERMYZ
 9035 FORMAT('TERMYX,TERMYY,TERMYZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9036)TERMZX,TERMZY,TERMZZ
 9036 FORMAT('TERMZX,TERMZY,TERMZZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3DEDC
      SUBROUTINE D3DELI(X,Y,Z,N,   &
      XEYE0,YEYE0,ZEYE0,   &
      XORIG,YORIG,ZORIG,   &
      X3DMIN,Y3DMIN,Z3DMIN,   &
      X3DMAX,Y3DMAX,Z3DMAX,   &
      X3DMID,Y3DMID,Z3DMID,   &
      X3DRAN,Y3DRAN,Z3DRAN,   &
      X3DEYE,Y3DEYE,Z3DEYE,   &
      X3DORI,Y3DORI,Z3DORI,   &
      XPRIME,YPRIME,ZPRIME,   &
      IBUGPL,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE MIN, MAX, MID, AND RANGE OF THE RAW DATA.
!              COMPUTE EYE COORDINATES.
!              COMPUTE ORIGIN COORDINATES
!              COMPUTE VISUAL EXTREME POINTS ON THE
!                 ORTHOGNORMAL PLANE THROUGH (X3DMID,Y3DMID,Z3DMID)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--MARCH     1979.
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
!
      DIMENSION XPRIME(*)
      DIMENSION YPRIME(*)
      DIMENSION ZPRIME(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3DE'
      ISUBN2='LI  '
      IERROR='NO'
!
      EPS=0.0000001
!
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3DELI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGPL,ISUBRO,IERROR
   52 FORMAT('IBUGPL,ISUBRO,IERROR = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)XEYE0,YEYE0,ZEYE0
   61 FORMAT('XEYE0, YEYE0, ZEYE0  = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)XORIG,YORIG,ZORIG
   62 FORMAT('XORIG, YORIG, ZORIG  = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,71)N
   71 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 72 I=1,N
      WRITE(ICOUT,73)I,X(I),Y(I),Z(I)
   73 FORMAT('I,X(I),Y(I),Z(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   72 CONTINUE
   90 CONTINUE
!
!               ************************************************
!               **  STEP 11--                                 **
!               **  COMPUTE THE MIN AND MAX OF THE RAW DATA.  **
!               ************************************************
!
      ISTEPN='11'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      X3DMIN=X(1)
      X3DMAX=X(1)
      Y3DMIN=Y(1)
      Y3DMAX=Y(1)
      Z3DMIN=Z(1)
      Z3DMAX=Z(1)
!
      DO 1100 I=1,N
      IF(X(I).LT.X3DMIN)X3DMIN=X(I)
      IF(X(I).GT.X3DMAX)X3DMAX=X(I)
      IF(Y(I).LT.Y3DMIN)Y3DMIN=Y(I)
      IF(Y(I).GT.Y3DMAX)Y3DMAX=Y(I)
      IF(Z(I).LT.Z3DMIN)Z3DMIN=Z(I)
      IF(Z(I).GT.Z3DMAX)Z3DMAX=Z(I)
 1100 CONTINUE
      X3DRAN=X3DMAX-X3DMIN
      Y3DRAN=Y3DMAX-Y3DMIN
      Z3DRAN=Z3DMAX-Z3DMIN
!
!               *******************************************
!               **  STEP 12--                            **
!               **  COMPUTE MIDRANGES FOR THE X, Y,      **
!               **  AND Z VECTORS.                       **
!               **  THIS WILL DEFINE THE 'MIDDLE POINT'  **
!               **  OF THE 3-D PLOT.                     **
!               *******************************************
!
      ISTEPN='12'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      X3DMID=(X3DMIN+X3DMAX)/2.0
      Y3DMID=(Y3DMIN+Y3DMAX)/2.0
      Z3DMID=(Z3DMIN+Z3DMAX)/2.0
!
!               *******************************************
!               **  STEP 13--                            **
!               **  COMPUTE EYE COORDINATES.             88
!               **  IF (XEYE0,YEYE0,ZEYE0) IS UNDEFINED  **
!               **  (THAT IS,    = CPU MINIMUM),         **
!               **  THEN COMPUTE DEFAULT VALUES.         **
!               *******************************************
!
      ISTEPN='13'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      X3DEYE=XEYE0
      Y3DEYE=YEYE0
      Z3DEYE=ZEYE0
      IF(XEYE0.LE.CPUMIN)X3DEYE=X3DMAX+3.0*X3DRAN
      IF(YEYE0.LE.CPUMIN)Y3DEYE=Y3DMAX+3.0*Y3DRAN
      IF(ZEYE0.LE.CPUMIN)Z3DEYE=Z3DMAX+3.0*Z3DRAN
!
!               ***************************************************
!               **  STEP 14--                                    **
!               **  COMPUTE THE ENDPONTS OF THE 3-PRONGED AXIS.  **
!               ***************************************************
!
      ISTEPN='14'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      FACTOR=1.25
!
      X3DORI=XORIG
      Y3DORI=YORIG
      Z3DORI=ZORIG
      IF(XORIG.EQ.CPUMIN)X3DORI=X3DMIN
      IF(YORIG.EQ.CPUMIN)Y3DORI=Y3DMIN
      IF(ZORIG.EQ.CPUMIN)Z3DORI=Z3DMIN
!
      XPRIME(1)=X3DORI
      YPRIME(1)=Y3DORI
      ZPRIME(1)=Z3DORI
!
      XPRIME(2)=X3DORI+FACTOR*X3DRAN
      YPRIME(2)=Y3DORI
      ZPRIME(2)=Z3DORI
!
      XPRIME(3)=X3DORI
      YPRIME(3)=Y3DORI
      ZPRIME(3)=Z3DORI
!
      XPRIME(4)=X3DORI
      YPRIME(4)=Y3DORI+FACTOR*Y3DRAN
      ZPRIME(4)=Z3DORI
!
      XPRIME(5)=X3DORI
      YPRIME(5)=Y3DORI
      ZPRIME(5)=Z3DORI
!
      XPRIME(6)=X3DORI
      YPRIME(6)=Y3DORI
      ZPRIME(6)=Z3DORI+FACTOR*Z3DRAN
!
!               ***************************************************************
!               **  STEP 15--                                                **
!               **  DETERMINE 3 POINTS WHICH WILL DEFINE EXTREMAL POINTS     **
!               **  ON THE VISUAL PLANE.                                     **
!               **  THIS IS NEEDED SO THAT THE UNDERLYING GRAPHICS SOFTWARE  **
!               **  WILL SHOW A CLOSE POINT/CLOUD/FIGURE                     **
!               **  AS BEING LARGE IN APPEARANCE,                            **
!               **  AND A DISTANT POINT/CLOUD/FIGURE                         **
!               **  AS BEING SMALL IN APPEARANCE.                            **
!               **  SUCH A STEP IS NECESSARY BECAUSE THE                     **
!               **  UNDERLYING GRAPHICS SOFTWARE WILL BY DEFAULT             **
!               **  GIVE FULL RESOLUTION TO ALL DATA CLOUDS/FIGRUES          **
!               **  WHICH WILL HAVE THE NET EFFECT OF                        **
!               **  ALL DATA CLOUDS/FIGURES BEING LARGE.                     **
!               **  THE 3 CALCULATED EXTREMAL POINTS WILL NEVER              **
!               **  EXPLICITELY APPEAR ON THE PLOT (THEY WILL                **
!               **  HAVE A BLANK PLOT CHARAXCTER AUTOMATICALLY);             **
!               **  THERE EXISTENCE ONLY SERVES TO ASSURE THAT THE           **
!               **  PLOT WINDOW IS APPROPRIATELY STRETCHED.                  **
!               ***************************************************************
!
!               ************************************************************
!               **  STEP 15.1--                                           **
!               **  DEFINE THE PERIPHERAL VISION ANGLE.                   **
!               **  THIS HAS BEEN SET TO 60 DEGREES                       **
!               **  (30   DEGREES ABOVE THE NORMAL LINE                   **
!               **  TO THE VISUAL PLANE AND 30   DEGREES BELOW            **
!               **  THE NORMAL LINE TO THE PLANE).                        **
!               **  COMPUTE THE RADIUS OF THE CIRCLE ON THE VISUAL PLANE  **
!               **  WHICH IS JUST AT THE EDGE OF VISIBILITY--             **
!               **  THE LARGER THE PERIPHERAL ANGLE,                      **
!               **  THE LARGER THE RADIUS, AND VICE VERSA.                **
!               ************************************************************
!
      ISTEPN='15.1'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      THETA=3.1415926/12.0
      ARG=(X3DEYE-X3DMID)**2+(Y3DEYE-Y3DMID)**2+(Z3DEYE-Z3DMID)**2
      DIST=0.0
      IF(ARG.GT.0.0)DIST=SQRT(ARG)
      RADIUS=DIST*TAN(THETA)
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 1519
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1511)
 1511 FORMAT('***** FROM THE MIDDLE OF D3DELI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1512)THETA,ARG,DIST,RADIUS
 1512 FORMAT('THETA,ARG,DIST,RADIUS = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
 1519 CONTINUE
!
!               ***********************************************************
!               **  STEP 15.2--                                          **
!               **  DETERMINE THE 2 POINTS ON THIS CIRCLE OF VISIBILITY  **
!               **  WHICH INTERSECT WITH THE X = X3DMID PLANE.             **
!               ***********************************************************
!
      ISTEPN='15.2'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      XD=X3DMID
      YD1=Y3DMID
      YD2=Y3DMID
      ZD1=Z3DMID
      ZD2=Z3DMID
!
!     ***** 7 LINES OF CODE TO ADJUST FOR DIVISION BY 0 ADDED AUGUST 1983 *****
      XDEL=X3DEYE-X3DMID
      IF(XDEL.EQ.0.0)XDEL=EPS
      YDEL=Y3DEYE-Y3DMID
      IF(YDEL.EQ.0.0)YDEL=EPS
      ZDEL=Z3DEYE-Z3DMID
      IF(ZDEL.EQ.0.0)ZDEL=EPS
!
      DISC=1.0+(ZDEL/YDEL)**2
      DENOM=0.0
      IF(DISC.GT.0.0)DENOM=SQRT(DISC)
      IF(DISC.LT.0.0)GO TO 1520
      ZD1=Z3DMID+RADIUS/DENOM
      ZD2=Z3DMID+RADIUS/(-DENOM)
      YD1=CPUMIN
      IF(YDEL.NE.0.0)YD1=Y3DMID-ZDEL*(ZD1-Z3DMID)/YDEL
      YD2=CPUMAX
      IF(YDEL.NE.0.0)YD2=Y3DMID-ZDEL*(ZD2-Z3DMID)/YDEL
 1520 CONTINUE
!
      XPRIME(7)=X3DMID
      YPRIME(7)=YD1
      ZPRIME(7)=ZD1
!
      XPRIME(8)=X3DMID
      YPRIME(8)=YD2
      ZPRIME(8)=ZD2
!
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 1529
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1521)X3DMID,RADIUS
 1521 FORMAT('X3DMID,RADIUS = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1522)DISC,DENOM
 1522 FORMAT('DISC,DENOM = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1523)XD,YD1,YD2,ZD1,ZD2
 1523 FORMAT('XD,YD1,YD2,ZD1,ZD2 = ',5E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1524)XPRIME(7),YPRIME(7),ZPRIME(7)
 1524 FORMAT('XPRIME(7),YPRIME(7),ZPRIME(7)    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1525)XPRIME(8),YPRIME(8),ZPRIME(8)
 1525 FORMAT('XPRIME(8),YPRIME(8),ZPRIME(8)    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 1529 CONTINUE
!
!               ***********************************************************
!               **  STEP 15.3--                                          **
!               **  DETERMINE THE 2 POINTS ON THIS CIRCLE OF VISIBILITY  **
!               **  WHICH INTERSECT WITH THE Y = Y3DMID PLANE.             **
!               ***********************************************************
!
      ISTEPN='15.3'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      XD1=X3DMID
      XD2=X3DMID
      YD=Y3DMID
      ZD1=Z3DMID
      ZD2=Z3DMID
!
!     ***** 3 LINES OF CODE TO CHECK FOR DIVISION BY 0 ADDED AUGUST 1983 *****
      DISC=CPUMAX
      IF(XDEL.NE.0.0)DISC=1.0+(ZDEL/XDEL)**2
      DENOM=0.0
      IF(DISC.GT.0.0)DENOM=SQRT(DISC)
      IF(DISC.LT.0.0)GO TO 1530
      ZD1=Z3DMID+RADIUS/DENOM
      ZD2=Z3DMID+RADIUS/(-DENOM)
      XD1=CPUMIN
      IF(XDEL.NE.0.0)XD1=X3DMID-ZDEL*(ZD1-Z3DMID)/XDEL
      XD2=CPUMAX
      IF(XDEL.NE.0.0)XD2=X3DMID-ZDEL*(ZD2-Z3DMID)/XDEL
!
 1530 CONTINUE
      XPRIME(9)=XD1
      YPRIME(9)=Y3DMID
      ZPRIME(9)=ZD1
!
      XPRIME(10)=XD2
      YPRIME(10)=Y3DMID
      ZPRIME(10)=ZD2
!
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 1539
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1531)Y3DMID,RADIUS
 1531 FORMAT('Y3DMID,RADIUS = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1532)DISC,DENOM
 1532 FORMAT('DISC,DENOM = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1533)XD1,XD2,YD,ZD1,ZD2
 1533 FORMAT('XD1,XD2,YD,ZD1,ZD2 = ',5E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1534)XPRIME(9),YPRIME(9),ZPRIME(9)
 1534 FORMAT('XPRIME(9),YPRIME(9),ZPRIME(9)    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1535)XPRIME(10),YPRIME(10),ZPRIME(10)
 1535 FORMAT('XPRIME(10),YPRIME(10),ZPRIME(10) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 1539 CONTINUE
!
!               ***********************************************************
!               **  STEP 15.4--                                          **
!               **  DETERMINE THE 2 POINTS ON THIS CIRCLE OF VISIBILITY  **
!               **  WHICH INTERSECT WITH THE Z = Z3DMID PLANE.             **
!               ***********************************************************
!
      ISTEPN='15.4'
      IF(IBUGPL.EQ.'ON'.OR.ISUBRO.EQ.'DELI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      XD1=X3DMID
      XD2=X3DMID
      YD1=Y3DMID
      YD2=Y3DMID
      ZD=Z3DMID
!
!     ***** 3 LINES OF CODE TO CHECK FOR DIVISION BY 0 ADDED AUGUST 1983 *****
      DISC=CPUMAX
      IF(YDEL.NE.0.0)DISC=1.0+(XDEL/YDEL)**2
      DENOM=0.0
      IF(DISC.GT.0.0)DENOM=SQRT(DISC)
      IF(DISC.LT.0.0)GO TO 1540
      XD1=X3DMID+RADIUS/DENOM
      XD2=X3DMID+RADIUS/(-DENOM)
      YD1=CPUMIN
      IF(YDEL.NE.0.0)YD1=Y3DMID-XDEL*(XD1-X3DMID)/YDEL
      YD2=CPUMAX
      IF(YDEL.NE.0.0)YD2=Y3DMID-XDEL*(XD2-X3DMID)/YDEL
!
 1540 CONTINUE
      XPRIME(11)=XD1
      YPRIME(11)=YD1
      ZPRIME(11)=Z3DMID
!
      XPRIME(12)=XD2
      YPRIME(12)=YD2
      ZPRIME(12)=Z3DMID
!
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 1549
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1541)Z3DMID,RADIUS
 1541 FORMAT('Z3DMID,RADIUS = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1542)DISC,DENOM
 1542 FORMAT('DISC,DENOM = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1543)XD1,XD2,YD1,YD2,ZD
 1543 FORMAT('XD1,XD2,YD1,YD2,ZD = ',5E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1544)XPRIME(11),YPRIME(11),ZPRIME(11)
 1544 FORMAT('XPRIME(11),YPRIME(11),ZPRIME(11) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1545)XPRIME(12),YPRIME(12),ZPRIME(12)
 1545 FORMAT('XPRIME(12),YPRIME(12),ZPRIME(12) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 1549 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGPL.NE.'ON'.AND.ISUBRO.NE.'DELI')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3DELI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGPL,ISUBRO,IERROR
 9012 FORMAT('IBUGPL,ISUBRO,IERROR = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)N
 9021 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,N
      WRITE(ICOUT,9023)I,X(I),Y(I),Z(I)
 9023 FORMAT('I,X(I),Y(I),Z(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
      WRITE(ICOUT,9031)X3DMIN,Y3DMIN,Z3DMIN
 9031 FORMAT('X3DMIN,Y3DMIN,Z3DMIN       = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)X3DMAX,Y3DMAX,Z3DMAX
 9032 FORMAT('X3DMAX,Y3DMAX,Z3DMAX       = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9033)X3DMID,Y3DMID,Z3DMID
 9033 FORMAT('X3DMID,Y3DMID,Z3DMID       = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9034)X3DRAN,Y3DRAN,Z3DRAN
 9034 FORMAT('X3DRAN,Y3DRAN,Z3DRAN = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)XEYE0,YEYE0,ZEYE0
 9041 FORMAT('XEYE0,YEYE0,ZEYE0    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9042)X3DEYE,Y3DEYE,Z3DEYE
 9042 FORMAT('X3DEYE,Y3DEYE,Z3DEYE       = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9043)XORIG,YORIG,ZORIG
 9043 FORMAT('XORIG,YORIG,ZORIG    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9044)X3DORI,Y3DORI,Z3DORI
 9044 FORMAT('X3DORI,Y3DORI,Z3DORI = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 9051 I=1,12
      WRITE(ICOUT,9052)I,XPRIME(I),YPRIME(I),ZPRIME(I)
 9052 FORMAT('I,XPRIME(I),YPRIME(I),ZPRIME(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9051 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3DELI
      SUBROUTINE D3DEMD(X,Y,Z,TEMP,N,   &
      XDELMN,YDELMN,ZDELMN)
!
!     PURPOSE--COMPUTE MINIMUM DIFFERENCE
!              BETWEEN X VALUES,
!              BETWEEN Y VALUES,
!              BETWEEN Z VALUES.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/11
!     ORIGINAL VERSION--OCTOBER   1979.
!     UPDATED         --JULY      1989.  CHAR*4 STATEMETN FOR IWRITE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1989
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION TEMP(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3DE'
      ISUBN2='MD  '
!
      IF(IBUGG4.NE.'ON'.AND.ISUBG4.NE.'DEMD')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3DEMD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG4,ISUBG4,IERRG4
   52 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,71)N
   71 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 72 I=1,N
      WRITE(ICOUT,73)I,X(I),Y(I),Z(I)
   73 FORMAT('I,X(I),Y(I),Z(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   72 CONTINUE
   90 CONTINUE
!
!               ************************************************
!               **  STEP 11--                                 **
!               **  COMPUTE MINIMUM DIFFERENCES               **
!               ************************************************
!
      ISTEPN='11'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'DEMD')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
      XDELMN=CPUMAX
      CALL DISTIN(X,N,IWRITE,TEMP,NTEMP,IBUGG4,IERRG4)
      CALL SORT(TEMP,NTEMP,TEMP)
      IF(NTEMP.LE.1)XDELMN=0.0
      IF(NTEMP.LE.1)GO TO 1190
      DO 1100 I=2,NTEMP
      IM1=I-1
      DEL=TEMP(I)-TEMP(IM1)
      IF(DEL.LE.0.0)GO TO 1100
      IF(DEL.LT.XDELMN)XDELMN=DEL
 1100 CONTINUE
 1190 CONTINUE
!
      YDELMN=CPUMAX
      CALL DISTIN(Y,N,IWRITE,TEMP,NTEMP,IBUGG4,IERRG4)
      CALL SORT(TEMP,NTEMP,TEMP)
      IF(NTEMP.LE.1)YDELMN=0.0
      IF(NTEMP.LE.1)GO TO 1290
      DO 1200 I=2,NTEMP
      IM1=I-1
      DEL=TEMP(I)-TEMP(IM1)
      IF(DEL.LE.0.0)GO TO 1200
      IF(DEL.LT.YDELMN)YDELMN=DEL
 1200 CONTINUE
 1290 CONTINUE
!
      ZDELMN=CPUMAX
      CALL DISTIN(Z,N,IWRITE,TEMP,NTEMP,IBUGG4,IERRG4)
      CALL SORT(TEMP,NTEMP,TEMP)
      IF(NTEMP.LE.1)ZDELMN=0.0
      IF(NTEMP.LE.1)GO TO 1390
      DO 1300 I=2,NTEMP
      IM1=I-1
      DEL=TEMP(I)-TEMP(IM1)
      IF(DEL.LE.0.0)GO TO 1300
      IF(DEL.LT.ZDELMN)ZDELMN=DEL
 1300 CONTINUE
 1390 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGG4.NE.'ON'.AND.ISUBG4.NE.'DEMD')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3DEMD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)N,NTEMP
 9021 FORMAT('N,NTEMP = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,N
      WRITE(ICOUT,9023)I,X(I),Y(I),Z(I),TEMP(I)
 9023 FORMAT('I,X(I),Y(I),Z(I),TEMP(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
      WRITE(ICOUT,9031)XDELMN,YDELMN,ZDELMN
 9031 FORMAT('XDELMN,YDELMN,ZDELMN = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3DEMD
      SUBROUTINE D3DRBA(XRAW,YRAW,ZRAW,NP,   &
                        PX,PY,PZ,PX2,PY2,PZ2,PX3,PY3,   &
                        ICASPL,ICAS3D,ISORSW,   &
                        IBA2SW,ABA2WI,ABA2BA,   &
                        IBA2BL,IBA2BC,IBA2BR,IBA2BG,IBA2BB,PBA2BT,   &
                        IBA2FS,IBA2FC,IBA2FR,IBA2FG,IBA2FB,   &
                        IBA2PT,IBA2PL,IBA2PC,IBA2PR,IBA2PG,IBA2PB,   &
                        IBA2TY,IBA2DI,PBA2PS,PBA2PT,   &
                        XDELMN,YDELMN,ZDELMN,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IX1TSC,IY1TSC)
!
!     PURPOSE--FOR A GENERAL GRAPHICS DEVICE, AND FOR EACH VALUE IN
!              X(.), DRAW A BAR (= VERTICAL OR HORIZONTAL BAR) FROM THE
!              BASE POINT ABA2BA TO THE POINT Y(.).  DO SO FOR A
!              SPECIFIED BAR LINE TYPE, LINES COLOR, AND LINE THICKNESS.
!     NOTE--THE VARIABLES PY(.) AND PX(.) ARE DUMMY VARIABLES WHICH ARE
!           USED IN THE INTERMEDIATE CALCULATIONS AND WHOSE DIMENSIONS
!           ARE DEFINED (FOR EASY OF CHANGE) BACK IN THE MAIN ROUTINE.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87.5
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --MAY       1987.
!     UPDATED         --MARCH     1988. TO FIX PROBLEM WHEREBY ONLY FIRST BAR
!                                       HAD PROPER PATTERN (STOLNICKI).
!     UPDATED         --SEPTEMBER 1988. RENUMBER
!     UPDATED         --APRIL     1992. ASP2BA  TO  ABA2BA
!     UPDATED         --APRIL     1992. IPATTT TO IPATT
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 ISORSW
      CHARACTER*4 IBA2SW
      CHARACTER*4 IBA2BL
      CHARACTER*4 IBA2BC
      CHARACTER*4 IBA2FS
      CHARACTER*4 IBA2FC
      CHARACTER*4 IBA2PT
      CHARACTER*4 IBA2PL
      CHARACTER*4 IBA2PC
      CHARACTER*4 IBA2TY
      CHARACTER*4 IBA2DI
      CHARACTER*4 IX1TSC
      CHARACTER*4 IY1TSC
      CHARACTER*4 ITYPE
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT
      CHARACTER*4 ICOL
!CCCC CHARACTER*4 ICOLF
!CCCC CHARACTER*4 ICOLP
      CHARACTER*4 IDIR
      CHARACTER*4 ICASE
!
      CHARACTER*4 IHORPA
      CHARACTER*4 IVERPA
      CHARACTER*4 IDUPPA
      CHARACTER*4 IDDOPA
!
!CCCC CHARACTER*4 IFIGSV
!
      DIMENSION XRAW(*)
      DIMENSION YRAW(*)
      DIMENSION ZRAW(*)
      DIMENSION PX(*)
      DIMENSION PY(*)
      DIMENSION PZ(*)
      DIMENSION PX2(*)
      DIMENSION PY2(*)
      DIMENSION PZ2(*)
      DIMENSION PX3(*)
      DIMENSION PY3(*)
!
      DIMENSION XVECT(2)
      DIMENSION YVECT(2)
      DIMENSION ZVECT(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      J=0
      HOLD=1.0
      ABASE=0.0
      PBASE=0.0
      PBASE2=0.0
      PLEFT=0.0
      PRIGHT=0.0
      AWIDTH=0.0
      PWIDTH=0.0
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      FYMIN=FY1MIN
      FYMAX=FY1MAX
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRBA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRBA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,ICAS3D,ISORSW,NP
   53   FORMAT('ICASPL,ICAS3D,ISORSW,NP = ',3(A4,2X),3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)XDELMN,YDELMN,ZDELMN
   54   FORMAT('XDELMN,YDELMN,ZDELMN = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(NP.GT.3)THEN
          DO 65 I=1,3
            WRITE(ICOUT,66)I,XRAW(I),YRAW(I),ZRAW(I)
   66       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   65     CONTINUE
          NPM2=NP-2
          DO 67 I=NPM2,NP
            WRITE(ICOUT,68)I,XRAW(I),YRAW(I),ZRAW(I)
   68       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   67     CONTINUE
        ENDIF
        WRITE(ICOUT,71)IBA2SW,ABA2WI,ABA2BA
   71   FORMAT('IBA2SW,ABA2WI,ABA2BA = ',A4,2X,2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)IBA2BL,IBA2BC,PBA2BT,IBA2BR,IBA2BG,IBA2BB
   72   FORMAT('IBA2BL,IBA2BC,PBA2BT,IBA2BR,IBA2BG,IBA2BB = ',   &
               2(A4,2X),G15.7,3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)IBA2FS,IBA2FC,IBA2FR,IBA2FG,IBA2FB
   73   FORMAT('IBA2FS,IBA2FC,IBA2FR,IBA2FG,IBA2FB = ',2(A4,2X),3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,74)IBA2PT,IBA2PL,IBA2PC,IBA2TY,IBA2DI,PBA2PS,PBA2PT
   74   FORMAT('IBA2PT,IBA2PL,IBA2PC,IBA2TY,IBA2DI,PBA2PS,PBA2PT = ',   &
               5(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)IBA2PR,IBA2PG,IBA2PB
   75   FORMAT('IBA2PR,IBA2PG,IBA2PB = ',3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)X3DEYE,Y3DEYE,Z3DEYE
   81   FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,84)PXMIN,PXMAX,PYMIN,PYMAX
   84   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,85)FX1MIN,FX1MAX,FY1MIN,FY1MAX
   85   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,86)IX1TSC,IY1TSC
   86   FORMAT('IX1TSC,IY1TSC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IBUGG4,ISUBG4,IERRG4
   89   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 11--                                  **
!               **  IF CALLED FOR, SORT THE DATA               **
!               **  ACCORDING TO THE HORIZONTAL AXIS VARIABLE  **
!               *************************************************
!
      IDIR=IBA2DI
!
      IF(ISORSW.EQ.'OFF'  .OR. ICASPL.EQ.'PIEC' .OR.   &
         ICAS3D.EQ.'ON'   .OR. ICASPL.EQ.'CONT')THEN
        DO 1160 I=1,NP
          PX(I)=XRAW(I)
          PY(I)=YRAW(I)
          PZ(I)=ZRAW(I)
 1160   CONTINUE
      ENDIF
!
!               ************************************************
!               **  STEP 12--                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,        **
!               **  CHECK THAT ALL DATA POINTS ARE POSITIVE.  **
!               ************************************************
!
      IF(IX1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'H')THEN
          IF(ABA2BA.LE.0.0)HOLD=ABA2BA
          IF(ABA2BA.LE.0.0)GO TO 1250
        ENDIF
!
        IF(ISORSW.EQ.'ON')THEN
          J=1
          IF(PX(J).LE.0.0)GO TO 1250
          GO TO 1290
        ELSE
          DO 1235 I=1,NP
            J=I
            IF(PX(J).LE.0.0)GO TO 1250
 1235     CONTINUE
          GO TO 1290
        ENDIF
!
 1250   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1251)
 1251   FORMAT('***** ERROR IN D3DRBA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1252)
 1252   FORMAT('      THE LOG OF A NON-POSITIVE DATA VALUE WAS ',   &
               'ENCOUNTERED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1254)
 1254   FORMAT('      IN FORMING A PLOT.  DATA MAY NOT BE ZERO OR ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1255)
 1255   FORMAT('      WHEN A LOG SCALE PLOT IS USED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1256)PX(J)
 1256   FORMAT('      THE VALUE = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1257)
 1257   FORMAT('      THIS VALUE CAME FROM THE HORIZONTAL AXIS ',   &
               'VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1259)
 1259   FORMAT('      CORRECTIVE ACTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1260)
 1260   FORMAT('      CHANGE DATA OR CHANGE LIMITS.')
        CALL DPWRST('XXX','BUG ')
        IERRG4='YES'
        GO TO 9000
!
      ENDIF
 1290 CONTINUE
!
      IF(IY1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'V')THEN
          IF(ABA2BA.LE.0.0)HOLD=ABA2BA
          IF(ABA2BA.LE.0.0)GO TO 1350
        ENDIF
!
        IF(ISORSW.EQ.'ON')THEN
          J=1
          IF(PY(J).LE.0.0)HOLD=PY(J)
          IF(PY(J).LE.0.0)GO TO 1350
          GO TO 1390
        ELSE
          DO 1335 I=1,NP
            J=I
            IF(PY(J).LE.0.0)HOLD=PY(J)
            IF(PY(J).LE.0.0)GO TO 1350
 1335     CONTINUE
          GO TO 1390
        ENDIF
!
 1350   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1251)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1252)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1254)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1255)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1256)HOLD
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1357)
 1357   FORMAT('      THIS VALUE CAME FROM THE VERTICAL AXIS VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1259)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1260)
        CALL DPWRST('XXX','BUG ')
        IERRG4='YES'
      ENDIF
!
 1390 CONTINUE
!
!               ******************************************
!               **  STEP 40--                           **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,  **
!               **  TRANSFORM THE DATA                  **
!               ******************************************
!
      ABASE=ABA2BA
      AWIDTH=ABA2WI
!
      WIDTHX=AWIDTH
      IF(WIDTHX.EQ.CPUMIN.AND.XDELMN.LE.0.0)WIDTHX=1.0
      IF(WIDTHX.EQ.CPUMIN.AND.XDELMN.GT.0.0)WIDTHX=XDELMN
      WIDTHY=AWIDTH
      IF(WIDTHY.EQ.CPUMIN.AND.YDELMN.LE.0.0)WIDTHY=1.0
      IF(WIDTHY.EQ.CPUMIN.AND.YDELMN.GT.0.0)WIDTHY=YDELMN
      WIDTHZ=AWIDTH
      IF(WIDTHZ.EQ.CPUMIN.AND.ZDELMN.LE.0.0)WIDTHZ=1.0
      IF(WIDTHZ.EQ.CPUMIN.AND.ZDELMN.GT.0.0)WIDTHZ=ZDELMN
!
      IF(IX1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'H')ABASE=LOG10(ABASE)
        DO 4015 I=1,NP
          PX(I)=LOG10(PX(I))
 4015   CONTINUE
      ENDIF
!
      IF(IY1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'V')ABASE=LOG10(ABASE)
        DO 4025 I=1,NP
          PY(I)=LOG10(PY(I))
 4025   CONTINUE
      ENDIF
!
!               *******************************
!               **  STEP 60--                **
!               **  PREPARE TO MAKE VARIOUS  **
!               **  LINE SETTINGS            **
!               *******************************
!
      ITYPE='LINE'
!
!               **********************************************
!               **  STEP 61--                               **
!               **  TRANSLATE THE CHARACTER REPRESENTATION  **
!               **  OF THE LINE PATTERN                     **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      IPATT=IBA2BL
      CALL GRTRPA(ITYPE,IPATT,PXSPA,PYSPA,   &
      JPATT,IHORPA,IVERPA,IDUPPA,IDDOPA,PXSPA2,PYSPA2)
!
!               *******************************
!               **  STEP 62--                **
!               **  SET THE LINE PATTERN     **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
      CALL GRSEPA(ITYPE,IPATT,PXSPA,PYSPA,   &
      JPATT,IHORPA,IVERPA,IDUPPA,IDDOPA,PXSPA2,PYSPA2)
!
!               **********************************************
!               **  STEP 63--                               **
!               **  TRANSLATE THE  DESIRED                  **
!               **  LINE THICKNESS                          **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      PTHICK=PBA2BT
      CALL GRTRTH(ITYPE,PTHICK,JTHICK,PTHIC2)
!
!               *******************************
!               **  STEP 64--                **
!               **  SET THE LINE THICKNESS   **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
      CALL GRSETH(ITYPE,PTHICK,JTHICK,PTHIC2)
!
!               **********************************************
!               **  STEP 65--                               **
!               **  TRANSLATE THE CHARACTER REPRESENTATION  **
!               **  OF THE LINE COLOR                       **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      ICASE='LINE'
      ICOLR=IBA2BR
      ICOLG=IBA2BG
      ICOLB=IBA2BB
      CALL GRTRC2(ICOLR,ICOLG,ICOLB,ARED,AGREEN,ABLUE,   &
                  AALPHA,IRGBFL)
      IF(IRGBFL.EQ.1)THEN
        CALL GRSEC2(ICASE,IRGBFL,ARED,AGREEN,ABLUE,AALPHA)
      ELSE
        ICOL=IBA2BC
        CALL GRTRCO(ITYPE,ICOL,JCOL)
!
!               *******************************
!               **  STEP 66--                **
!               **  SET THE LINE COLOR       **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
        CALL GRSECO(ITYPE,ICOL,JCOL)
      ENDIF
!
!               **************************************************
!               **  STEP 71--                                   **
!               **  FOR EACH RAW 3-D DATA POINT--               **
!               **     1) MAKE THE BAR                          **
!               **     2) TRANSLATE IT TO 2 DIMENSIONS          **
!               **     3) TRANSLATE IT TO 0-100 UNITS           **
!               **     4) CLIP THE BAR   IF NEEDED              **
!               **     5) DRAW OUT THE BAR                      **
!               **************************************************
!
      IFIG='GENE'
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      IF(IX1TSC.EQ.'LOG')FXMIN=LOG10(FX1MIN)
      IF(IX1TSC.EQ.'LOG')FXMAX=LOG10(FX1MAX)
!
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      IF(IY1TSC.EQ.'LOG')FYMIN=LOG10(FY1MIN)
      IF(IY1TSC.EQ.'LOG')FYMAX=LOG10(FY1MAX)
!
      FXRANG=FXMAX-FXMIN
      FYRANG=FYMAX-FYMIN
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
!
      BASEX=ABASE
      BASEY=ABASE
      BASEZ=ABASE
!
      DO 7100 I=1,NP
!
        CALL D3MKBA(PX,PY,PZ,NP,I,   &
                    IDIR,WIDTHX,WIDTHY,WIDTHZ,   &
                    BASEX,BASEY,BASEZ,   &
                    XVECT,YVECT,ZVECT,IXNEAR,IXFAR,   &
                    IYNEAR,IYFAR,IZNEAR,IZFAR,   &
                    PX2,PY2,PZ2,NP2)
!
        CALL D3TR32(PX2,PY2,PZ2,NP2,PX3,PY3,NP3)
!
        CALL D3TRXP(PX3,PY3,NP3,IDIR,ABASE,   &
                    FXMIN,FXMAX,FXRANG,FYMIN,FYMAX,FYRANG,   &
                    PXMIN,PXMAX,PXRANG,PYMIN,PYMAX,PYRANG,   &
                    PX3,PY3,NP3,PBASE)
!
        CALL DPSQUE(PX3,PY3,NP3,PXMIN,PXMAX,PYMIN,PYMAX)
!
      CALL GRDRPL(PX3,PY3,NP3,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,IRGBFL,   &
                  JPATTT,JTHICK,PTHIC2,JCOL)
!
 7100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRBA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRBA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9042)WIDTHX,WIDTHY,WIDTHZ
 9042   FORMAT('WIDTHX,WIDTHY,WIDTHZ = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9043)BASEX,BASEY,BASEZ
 9043   FORMAT('BASEX,BASEY,BASEZ    = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9044)PXMIN,PXMAX,PYMIN,PYMAX
 9044   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9045)FX1MIN,FX1MAX,FY1MIN,FY1MAX
 9045   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9046)FXMIN,FXMAX,FYMIN,FYMAX
 9046   FORMAT('FXMIN,FXMAX,FYMIN,FYMAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)PTHICK,JTHICK,PTHIC2
 9053   FORMAT('PTHICK,JTHICK,PTHIC2 = ',G15.7,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9054)ICOL,JCOL,IDIR
 9054   FORMAT('ICOL,JCOL,IDIR = ',A4,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9069)IFIG,ITYPE,IERRG4,IPATT,JPATT
 9069   FORMAT('IFIG,ITYPE,IBUGG4,IPATT,JPATT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRBA
      SUBROUTINE D3DRCH(XRAW,YRAW,ZRAW,PX,PY,PZ,NP,PY2,PX2,NP2,   &
                        X3D2,   &
                        ICASPL,ICAS3D,ISORSW,   &
                        ICH2PA,ICH2FO,ICH2CA,ICH2JU,ICH2DI,ACH2AN,   &
                        ICH2FI,ICH2CO,ICH2CR,ICH2CG,ICH2CB,   &
                        PCH2HE,PCH2WI,PCH2TH,PCH2HO,PCH2VO,   &
                        ITEXSP,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IX1TSC,IY1TSC,   &
                        IMPSW2,AMPSCH,AMPSCW)
!
!     PURPOSE--FOR A GENERAL GRAPHICS DEVICE, DRAW A CHARACTER TRACE OF
!              Y(.) VERSUS X(.), THAT IS, DRAW A SPECIFIED MARKER
!              (= CHARACTER) TYPE AT EACH OF THE PLOT POINTS.
!     NOTE--THE VARIABLES PY(.) AND PX(.) ARE DUMMY VARIABLES
!           WHICH ARE USED IN THE INTERMEDIATE CALCULATIONS
!           AND WHOSE DIMENSIONS ARE DEFINED (FOR EASY OF CHANGE)
!           BACK IN THE MAIN ROUTINE.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --DECEMBER  1987. INDEPENDENT CONTROL OF CHAR WIDTH.
!     UPDATED         --SEPTEMBER 1988. LOG/WEIBULL CHECK AS A SUBROUTINE
!     UPDATED         --SEPTEMBER 1988. RENUMBER
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 ISORSW
      CHARACTER*24 ICH2PA
      CHARACTER*4 ICH2FO
      CHARACTER*4 ICH2CA
      CHARACTER*4 ICH2JU
      CHARACTER*4 ICH2DI
      CHARACTER*4 ICH2FI
      CHARACTER*4 ICH2CO
      CHARACTER*4 ITEXSP
      CHARACTER*4 IX1TSC
      CHARACTER*4 IY1TSC
!
      CHARACTER*4 IFIG
      CHARACTER*24 IPATT
      CHARACTER*4 IFONT
      CHARACTER*4 ICASE
      CHARACTER*4 IJUST
      CHARACTER*4 IDIR
      CHARACTER*4 IFILL
      CHARACTER*4 ICOL
      CHARACTER*24 ISYMBL
      CHARACTER*4 ISPAC
      CHARACTER*4 IMPSW2
      CHARACTER*4 ICASAX
!
      DIMENSION XRAW(*)
      DIMENSION YRAW(*)
      DIMENSION ZRAW(*)
      DIMENSION PX(*)
      DIMENSION PY(*)
      DIMENSION PZ(*)
      DIMENSION PY2(*)
      DIMENSION PX2(*)
      DIMENSION X3D2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      AHUNDR=100.0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRCH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,ICAS3D,ISORSW,NP
   53   FORMAT('ICASPL,ICAS3D,ISORSW,NP = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(NP.GT.3)THEN
          DO 65 I=1,3
            WRITE(ICOUT,66)I,XRAW(I),YRAW(I),ZRAW(I)
   66       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   65     CONTINUE
          NPM2=NP-2
          DO 67 I=NPM2,NP
            WRITE(ICOUT,68)I,XRAW(I),YRAW(I),ZRAW(I)
   68       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   67     CONTINUE
        ENDIF
        WRITE(ICOUT,74)ICH2PA,ACH2AN,ICH2CR,ICH2CG,ICH2CB
   74   FORMAT('ICH2PA,ACH2AN,ICH2CR,ICH2CG,ICH2CB = ',A24,2X,G15.7,3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)ICH2FO,ICH2JU,ICH2DI,ICH2FI,ICH2CO,ITEXSP
   75   FORMAT('ICH2FO,ICH2JU,ICH2DI,ICH2FI,ICH2CO,ITEXSP = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)PCH2HE,PCH2WI
   81   FORMAT('PCH2HE,PCH2WI = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,83)PCH2TH,PCH2VO,PCH2HO
   83   FORMAT('PCH2TH,PCH2VO,PCH2HO= ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,85)PXMIN,PXMAX,PYMIN,PYMAX
   85   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,86)FX1MIN,FX1MAX,FY1MIN,FY1MAX
   86   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,87)IX1TSC,IY1TSC
   87   FORMAT('IX1TSC,IY1TSC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IBUGG4,ISUBG4,IERRG4
   89   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 10--                                  **
!               **  IF CALLED FOR, SORT THE DATA               **
!               **  ACCORDING TO THE HORIZONTAL AXIS VARIABLE  **
!               *************************************************
!
      IF(ISORSW.EQ.'OFF' .OR. ICASPL.EQ.'PIEC' .OR.   &
         ICAS3D.EQ.'ON')THEN
        DO 1160 I=1,NP
          PX(I)=XRAW(I)
          PY(I)=YRAW(I)
          PZ(I)=ZRAW(I)
 1160   CONTINUE
      ENDIF
!
!
!               **********************************************************
!               **  STEP 21--                                           **
!               **  IF A NON-LINEAR SCALE PLOT IS CALLED FOR,           **
!               **  CHECK THAT ALL   HORIZ. AXIS DATA POINTS            **
!               **  ARE IN VALID RANGE.                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,                  **
!               **  CHECK THAT ALL   HORIZ.  AXIS DATA POINTS ARE > 0.  **
!               **  IF A WEIBULL SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   HORIZ. AXIS DATA POINTS ARE        **
!               **  STRICTLY > 0 AND STRICTLY < 100                     **
!               **********************************************************
!
!               ******************************************
!               **  STEP 41--                           **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,  **
!               **  TRANSFORM THE DATA                  **
!               ******************************************
!
!               ******************************************
!               **  STEP 42--                           **
!               **  IF A WEIBULL SCALE PLOT IS CALLED   **
!               **  FOR, TRANSFORM THE DATA             **
!               ******************************************
!
      IF(IX1TSC.EQ.'LOG')THEN
        ICASAX='2DHO'
        CALL CKLOSC(PX,NP,ISORSW,ICASAX,   &
                    ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        DO 4115 I=1,NP
          PX(I)=LOG10(PX(I))
 4115   CONTINUE
      ELSEIF(IX1TSC.EQ.'WEIB')THEN
        ICASAX='2DHO'
        CALL CKPRSC(PX,NP,ISORSW,ICASAX,   &
                    ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        DO 4215 I=1,NP
          PX(I)=LOG(LOG(AHUNDR/(AHUNDR-PX(I))))
 4215   CONTINUE
      ENDIF
!
!               **********************************************************
!               **  STEP 22--                                           **
!               **  IF A NON-LINEAR SCALE PLOT IS CALLED FOR,           **
!               **  CHECK THAT ALL   VERT.  AXIS DATA POINTS            **
!               **  ARE IN VALID RANGE.                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,                  **
!               **  CHECK THAT ALL   VERT.   AXIS DATA POINTS ARE > 0.  **
!               **  IF A WEIBULL SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   VERT.  AXIS DATA POINTS ARE        **
!               **  STRICTLY > 0 AND STRICTLY < 100                     **
!               **********************************************************
!
      IF(IY1TSC.EQ.'LOG')THEN
        ICASAX='2DVE'
        CALL CKLOSC(PY,NP,ISORSW,ICASAX,   &
                    ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        DO 4125 I=1,NP
          PY(I)=LOG10(PY(I))
 4125   CONTINUE
      ELSEIF(IY1TSC.EQ.'WEIB')THEN
        ICASAX='2DVE'
        CALL CKPRSC(PY,NP,ISORSW,ICASAX,   &
                    ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        DO 4225 I=1,NP
          PY(I)=LOG(LOG(AHUNDR/(AHUNDR-PY(I))))
 4225   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 51--                                   **
!               **  FORM THE CHARACTERS IN RAW 3-D SPACE.       **
!               **************************************************
!
!               **************************************************
!               **  STEP 52--                                   **
!               **  IF HIDDEN LINE REMOVAL IS ON,               **
!               **  DETERMINE IF ANY PART                       **
!               **  OF THE CHARACTER IS VISIBLE;                **
!               **  FORM SUBCHARACTERS.                         **
!               **************************************************
!
!               **************************************************
!               **  STEP 53--                                   **
!               **  TRANSLATE THE VISIBLE SUB-CHARACTERS        **
!               **  FROM THE RAW 3-D SPACE                      **
!               **  TO THE FINAL VISUAL 2-D PLANE.              **
!               **************************************************
!
      CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
!
!               *****************************************************
!               **  STEP 54--                                      **
!               **  TRANSLATE THE 2-D PLANE DATA POINTS            **
!               **  INTO STANDARDIZED (0.0 TO 100.0) COORDINATES.  **
!               *****************************************************
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      IF(IX1TSC.EQ.'LOG')FXMIN=LOG10(FX1MIN)
      IF(IX1TSC.EQ.'LOG')FXMAX=LOG10(FX1MAX)
      IF(IX1TSC.EQ.'WEIB')FXMIN=LOG(LOG(AHUNDR/(AHUNDR-FX1MIN)))
      IF(IX1TSC.EQ.'WEIB')FXMAX=LOG(LOG(AHUNDR/(AHUNDR-FX1MAX)))
!
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      IF(IY1TSC.EQ.'LOG')FYMIN=LOG10(FY1MIN)
      IF(IY1TSC.EQ.'LOG')FYMAX=LOG10(FY1MAX)
      IF(IY1TSC.EQ.'WEIB')FYMIN=LOG(LOG(AHUNDR/(AHUNDR-FY1MIN)))
      IF(IY1TSC.EQ.'WEIB')FYMAX=LOG(LOG(AHUNDR/(AHUNDR-FY1MAX)))
!
      FXRANG=FXMAX-FXMIN
      FYRANG=FYMAX-FYMIN
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
      DO 5410 I=1,NP
        FXRATI=(PX(I)-FXMIN)/FXRANG
        FYRATI=(PY(I)-FYMIN)/FYRANG
        PX(I)=PXMIN+FXRATI*PXRANG
        PY(I)=PYMIN+FYRATI*PYRANG
 5410 CONTINUE
!
      DO 5420 I=1,NP
        PX(I)=PX(I)+PCH2HO
        PY(I)=PY(I)+PCH2VO
 5420 CONTINUE
!
!               ***********************************************
!               **  STEP 60--                                **
!               **  WRITE OUT THE MARKERS (PLOT CHARACTERS)  **
!               **  AT THE PLOT POINTS                       **
!               ***********************************************
!
      IFIG='GENE'
      IPATT=ICH2PA
      IFONT=ICH2FO
      ICASE=ICH2CA
      IJUST=ICH2JU
      IDIR=ICH2DI
      ANGLE=ACH2AN
      IFILL=ICH2FI
      ICOL=ICH2CO
      ICOLR=ICH2CR
      ICOLG=ICH2CG
      ICOLB=ICH2CB
      PHEIGH=PCH2HE
!CCCC PWIDTH=0.5*PHEIGH
!CCCC PWIDTH=PHEIGH*(ANUMVP/ANUMHP)      DECEMBER 1987  TEST
      PWIDTH=PCH2WI
      PVEGAP=PHEIGH/2.0
      PHOGAP=PWIDTH/2.0
      PTHICK=PCH2TH
      ISYMBL=ICH2PA
      ISPAC=ITEXSP
!
      CALL DPCLCH(PX,PY,NP,PX2,PY2,NP2,X3D2,   &
                  PXMIN,PXMAX,PYMIN,PYMAX,   &
                  ISORSW,   &
                  IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                  IMPSW2,AMPSCH,AMPSCW,   &
                  ISYMBL,ISPAC)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.NE.'DRCH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9045)PXMIN,PXMAX,PYMIN,PYMAX
 9045   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9059)IBUGG4,ISUBG4,IERRG4
 9059   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRCH
      SUBROUTINE D3DRFL(ICASPL,ICAS3D,FRAM3D,   &
                        X3DMIN,X3DMAX,Y3DMIN,Y3DMAX,Z3DMIN,Z3DMAX,   &
                        IX1FSW,IX2FSW,IY1FSW,IY2FSW,   &
                        IX1FPA,IX2FPA,IY1FPA,IY2FPA,   &
                        IX1FCO,IX2FCO,IY1FCO,IY2FCO,   &
                        IX1FC2,IX2FC2,IY1FC2,IY2FC2,   &
                        PFRATH)
!     PURPOSE--DRAW THE 3 TO 8 (IF CALLED FOR) 3-D FRAME LINES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93.10
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1993.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 FRAM3D
      CHARACTER*4 IX1FSW
      CHARACTER*4 IX2FSW
      CHARACTER*4 IY1FSW
      CHARACTER*4 IY2FSW
      CHARACTER*4 IX1FPA
      CHARACTER*4 IX2FPA
      CHARACTER*4 IY1FPA
      CHARACTER*4 IY2FPA
      CHARACTER*4 IX1FCO
      CHARACTER*4 IX2FCO
      CHARACTER*4 IY1FCO
      CHARACTER*4 IY2FCO
!
      DIMENSION IX1FC2(3)
      DIMENSION IX2FC2(3)
      DIMENSION IY1FC2(3)
      DIMENSION IY2FC2(3)
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION PX(100)
      DIMENSION PY(100)
      DIMENSION PZ(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRFL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRFL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)X3DMIN,X3DMAX,Y3DMIN,Y3DMAX,Z3DMIN,Z3DMAX
   52   FORMAT('X3DMIN,X3DMAX,Y3DMIN,Y3DMAX,Z3DMIN,Z3DMAX = ',6F10.5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASPL,ICAS3D,FRAM3D,PFRATH
   55   FORMAT('ICASPL,ICAS3D,FRAM3D,PFRATH = ',3(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)IX1FSW,IX2FSW,IY1FSW,IY2FSW
   61   FORMAT('IX1FSW,IX2FSW,IY1FSW,IY2FSW = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)IX1FPA,IX2FPA,IY1FPA,IY2FPA
   62   FORMAT('IX1FPA,IX2FPA,IY1FPA,IY2FPA = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IX1FCO,IX2FCO,IY1FCO,IY2FCO
   63   FORMAT('IX1FCO,IX2FCO,IY1FCO,IY2FCO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IX1FC2(1),IX2FC2(1),IY1FC2(1),IY2FC2(1)
   64   FORMAT('IX1FC2(1),IX2FC2(1),IY1FC2(1),IY2FC2(1) = ',4I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IBUGG4,ISUBG4,IERRG4
   65   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICOLR=-99
      ICOLG=-99
      ICOLB=-99
!
      IF(ICASPL.EQ.'PIEC')GO TO 9000
      IF(ICASPL.EQ.'STAR')GO TO 9000
!
      IFIG='LINE'
      PTHICK=PFRATH
!
!               *********************************************
!               **  STEP 1--                               **
!               **  IF CALLED FOR,                         **
!               **  DRAW OUT THE "3 PRONG" FRAME           **
!               *********************************************
!
      IF(FRAM3D.EQ.'3PRO')THEN
         PX(1)=X3DMIN
         PX(2)=X3DMAX
         PX(3)=X3DMIN
         PX(4)=X3DMIN
         PX(5)=X3DMIN
         PX(6)=X3DMIN
!
         PY(1)=Y3DMIN
         PY(2)=Y3DMIN
         PY(3)=Y3DMIN
         PY(4)=Y3DMIN
         PY(5)=Y3DMIN
         PY(6)=Y3DMAX
!
         PZ(1)=Z3DMIN
         PZ(2)=Z3DMIN
         PZ(3)=Z3DMIN
         PZ(4)=Z3DMAX
         PZ(5)=Z3DMIN
         PZ(6)=Z3DMIN
         NP=6
         IPATT=IX1FPA
         ICOL=IX1FCO
         ICOLR=IX1FC2(1)
         ICOLG=IX1FC2(2)
         ICOLB=IX1FC2(3)
         IFLAG='ON'
!
         CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
         CALL D3SCAL(PX,PY,NP)
         CALL DPDRPL(PX,PY,NP,   &
                     IFIG,IPATT,PTHICK,   &
                     ICOL,ICOLR,ICOLG,ICOLB,   &
                     JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      ENDIF
!
!               *********************************************
!               **  STEP 2--                               **
!               **  IF CALLED FOR,                         **
!               **  DRAW OUT THE "3 PLANE" STYLE FRAME     **
!               *********************************************
!
      IF(FRAM3D.EQ.'3PLA')THEN
         PX(1)=X3DMIN
         PX(2)=X3DMAX
         PX(3)=X3DMAX
         PX(4)=X3DMIN
         PX(5)=X3DMIN
         PX(6)=X3DMIN
         PX(7)=X3DMIN
         PX(8)=X3DMIN
         PX(9)=X3DMIN
         PX(10)=X3DMAX
         PX(11)=X3DMAX
         PX(12)=X3DMIN
         PX(13)=X3DMIN
!
         PY(1)=Y3DMIN
         PY(2)=Y3DMIN
         PY(3)=Y3DMIN
         PY(4)=Y3DMIN
         PY(5)=Y3DMIN
         PY(6)=Y3DMAX
         PY(7)=Y3DMAX
         PY(8)=Y3DMIN
         PY(9)=Y3DMIN
         PY(10)=Y3DMIN
         PY(11)=Y3DMAX
         PY(12)=Y3DMAX
         PY(13)=Y3DMIN
!
         PZ(1)=Z3DMIN
         PZ(2)=Z3DMIN
         PZ(3)=Z3DMAX
         PZ(4)=Z3DMAX
         PZ(5)=Z3DMIN
         PZ(6)=Z3DMIN
         PZ(7)=Z3DMAX
         PZ(8)=Z3DMAX
         PZ(9)=Z3DMIN
         PZ(10)=Z3DMIN
         PZ(11)=Z3DMIN
         PZ(12)=Z3DMIN
         PZ(13)=Z3DMIN
         NP=13
         IPATT=IX1FPA
         ICOLR=IX1FC2(1)
         ICOLG=IX1FC2(2)
         ICOLB=IX1FC2(3)
         IFLAG='ON'
         CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
         CALL D3SCAL(PX,PY,NP)
         CALL DPDRPL(PX,PY,NP,   &
                     IFIG,IPATT,PTHICK,   &
                     ICOL,ICOLR,ICOLG,ICOLB,   &
                     JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      ENDIF
!
!               *********************************************
!               **  STEP 3--                               **
!               **  IF CALLED FOR,                         **
!               **  DRAW OUT THE "BOX" STYLE FRAME         **
!               *********************************************
!
      IF(FRAM3D.EQ.'BOX')THEN
         PX(1)=X3DMIN
         PX(2)=X3DMAX
         PX(3)=X3DMAX
         PX(4)=X3DMIN
         PX(5)=X3DMIN
         PX(6)=X3DMIN
         PX(7)=X3DMIN
         PX(8)=X3DMIN
         PX(9)=X3DMIN
         PX(10)=X3DMAX
         PX(11)=X3DMAX
         PX(12)=X3DMAX
         PX(13)=X3DMAX
         PX(14)=X3DMAX
         PX(15)=X3DMIN
         PX(16)=X3DMAX
         PX(17)=X3DMAX
         PX(18)=X3DMIN
         PX(19)=X3DMIN
!
         PY(1)=Y3DMIN
         PY(2)=Y3DMIN
         PY(3)=Y3DMIN
         PY(4)=Y3DMIN
         PY(5)=Y3DMIN
         PY(6)=Y3DMAX
         PY(7)=Y3DMAX
         PY(8)=Y3DMIN
         PY(9)=Y3DMIN
         PY(10)=Y3DMIN
         PY(11)=Y3DMAX
         PY(12)=Y3DMAX
         PY(13)=Y3DMIN
         PY(14)=Y3DMAX
         PY(15)=Y3DMAX
         PY(16)=Y3DMAX
         PY(17)=Y3DMAX
         PY(18)=Y3DMAX
         PY(19)=Y3DMIN
!
         PZ(1)=Z3DMIN
         PZ(2)=Z3DMIN
         PZ(3)=Z3DMAX
         PZ(4)=Z3DMAX
         PZ(5)=Z3DMIN
         PZ(6)=Z3DMIN
         PZ(7)=Z3DMAX
         PZ(8)=Z3DMAX
         PZ(9)=Z3DMIN
         PZ(10)=Z3DMIN
         PZ(11)=Z3DMIN
         PZ(12)=Z3DMAX
         PZ(13)=Z3DMAX
         PZ(14)=Z3DMAX
         PZ(15)=Z3DMAX
         PZ(16)=Z3DMAX
         PZ(17)=Z3DMIN
         PZ(18)=Z3DMIN
         PZ(19)=Z3DMIN
         NP=19
         IPATT=IX1FPA
         ICOL=IX1FCO
         ICOLR=IX1FC2(1)
         ICOLG=IX1FC2(2)
         ICOLB=IX1FC2(3)
         IFLAG='ON'
         CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
         CALL D3SCAL(PX,PY,NP)
         CALL DPDRPL(PX,PY,NP,   &
                     IFIG,IPATT,PTHICK,   &
                     ICOL,ICOLR,ICOLG,ICOLB,   &
                     JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      ENDIF
!
!               *********************************************
!               **  STEP 4--                               **
!               **  IF CALLED FOR,                         **
!               **  DRAW OUT THE "ZIGZAG" FRAME            **
!               *********************************************
!
      IF(FRAM3D.EQ.'ZIGZ')THEN
         PX(1)=X3DMIN
         PX(2)=X3DMIN
         PX(3)=X3DMAX
         PX(4)=X3DMAX
!
         PY(1)=Y3DMAX
         PY(2)=Y3DMAX
         PY(3)=Y3DMAX
         PY(4)=Y3DMIN
!
         PZ(1)=Z3DMAX
         PZ(2)=Z3DMIN
         PZ(3)=Z3DMIN
         PZ(4)=Z3DMIN
         NP=4
         IPATT=IX1FPA
         ICOL=IX1FCO
         ICOLR=IX1FC2(1)
         ICOLG=IX1FC2(2)
         ICOLB=IX1FC2(3)
         IFLAG='ON'
         CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
         CALL D3SCAL(PX,PY,NP)
         CALL DPDRPL(PX,PY,NP,   &
                     IFIG,IPATT,PTHICK,   &
                     ICOL,ICOLR,ICOLG,ICOLB,   &
                     JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRFL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRFL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9025)IERRG4
 9025   FORMAT('IERRG4 = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRFL
      SUBROUTINE D3DRFR(ICASPL,ICAS3D,FRAM3D,   &
                        X3DMIN,X3DMAX,Y3DMIN,Y3DMAX,Z3DMIN,Z3DMAX,   &
                        IVGMSW,IHGMSW)
!
!     PURPOSE--DRAW 3-D FRAME LINES (ALONG WITH TIC MARKS,
!              TIC MARK LABELS, AND GRID LINES
!              FOR A PLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1993.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 FRAM3D
      CHARACTER*4 IVGMSW
      CHARACTER*4 IHGMSW
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRFR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRFR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IMANUF,IMODEL,ICASPL,ICAS3D
   52   FORMAT('IMANUF,IMODEL,ICASPL,ICAS3D = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)IBUGG4,ISUBG4,IERRG4
   55   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************
!               **  STEP 1--                 **
!               **  FILL  THE MARGIN REGION  **
!               *******************************
!
      IFLAG=0
      IF(IMARC2(1).LT.0 .OR. IMARC2(1).LT.0 .OR.   &
         IMARC2(3).LT.0)THEN
        IFLAG=0
      ELSE
        IF(IMARC2(1).NE.IBACC2(1))IFLAG=1
        IF(IMARC2(2).NE.IBACC2(2))IFLAG=1
        IF(IMARC2(3).NE.IBACC2(3))IFLAG=1
      ENDIF
      IF(IMARCO.NE.IBACCO)IFLAG=1
      IF(IFLAG.EQ.1)   &
      CALL DPFIMA(PXMIN,PYMIN,PXMAX,PYMAX,   &
                  ICASPL,ICAS3D,   &
                  IMARCO,IMARC2,IRGBFL)
!
!               ****************************
!               **  STEP 2--              **
!               **  DRAW THE FRAME LINES  **
!               ****************************
!
      CALL D3DRFL(ICASPL,ICAS3D,FRAM3D,   &
                  X3DMIN,X3DMAX,Y3DMIN,Y3DMAX,Z3DMIN,Z3DMAX,   &
                  IX1FSW,IX2FSW,IY1FSW,IY2FSW,   &
                  IX1FPA,IX2FPA,IY1FPA,IY2FPA,   &
                  IX1FCO,IX2FCO,IY1FCO,IY2FCO,   &
                  IX1FC2,IX2FC2,IY1FC2,IY2FC2,   &
                  PFRATH)
!
!               **************************
!               **  STEP 3--            **
!               **  DRAW THE TIC MARKS  **
!               **************************
!
      CALL DPDRTM(PXMIN,PYMIN,PXMAX,PYMAX,   &
                  FX1MIN,FY1MIN,FX1MAX,FY1MAX,   &
                  ICASPL,ICAS3D,   &
                  IX1FSW,IX2FSW,IY1FSW,IY2FSW,   &
                  IX1TSW,IX2TSW,IY1TSW,IY2TSW,   &
                  PX1COO,PX2COO,PY1COO,PY2COO,   &
                  NX1COO,NX2COO,NY1COO,NY2COO,   &
                  PX1CMN,PX2CMN,PY1CMN,PY2CMN,   &
                  NX1CMN,NX2CMN,NY1CMN,NY2CMN,   &
                  PX1TLE,PX2TLE,PY1TLE,PY2TLE,   &
                  PTICTH,PMNTFA,   &
                  IX1TJU,IX2TJU,IY1TJU,IY2TJU,   &
                  IX1TCO,IX2TCO,IY1TCO,IY2TCO,   &
                  IX1TC2,IX2TC2,IY1TC2,IY2TC2)
!
!               *************************************
!               **  STEP 4--                       **
!               **  WRITE OUT THE TIC MARK LABELS  **
!               *************************************
!
      CALL DPWRTL(ICASPL,ICAS3D)
!
!               ***************************
!               **  STEP 5--             **
!               **  DRAW THE GRID LINES  **
!               ***************************
!
      CALL DPDRGL(PXMIN,PYMIN,PXMAX,PYMAX,   &
                  FX1MIN,FY1MIN,FX1MAX,FY1MAX,   &
                  ICASPL,ICAS3D,   &
                  IVGRSW,IHGRSW,   &
                  IVGMSW,IHGMSW,   &
                  PX1COO,PX2COO,PY1COO,PY2COO,   &
                  X1COOR,X2COOR,Y1COOR,Y2COOR,   &
                  NX1COO,NX2COO,NY1COO,NY2COO,   &
                  PX1CMN,PX2CMN,PY1CMN,PY2CMN,   &
                  X1COMN,X2COMN,Y1COMN,Y2COMN,   &
                  NX1CMN,NX2CMN,NY1CMN,NY2CMN,   &
                  IVGRPA,IHGRPA,IVGRCO,IHGRCO,IVGRC2,IHGRC2,   &
                  PVGRTH,PHGRTH,   &
                  PX1TOL,PX1TOR,PY1TOB,PY1TOT)
!CCC ABOVE LINE ADDED MAY, 1990 (FOR TIC OFFSETS)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRFR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRFR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IERRG4
 9015   FORMAT('IERRG4 = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRFR
      SUBROUTINE D3DRSP(XRAW,YRAW,ZRAW,NP,   &
                        PX,PY,PZ,PX2,PY2,PZ2,PX3,PY3,   &
                        ICASPL,ICAS3D,ISORSW,   &
                        ISP2LI,ISP2CO,ISP2CR,ISP2CG,ISP2CB,   &
                        ISP2DI,PSP2TH,ASP2BA,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IX1TSC,IY1TSC)
!
!     PURPOSE--FOR A GENERAL GRAPHICS DEVICE, AND FOR EACH VALUE IN
!              X(.), DRAW A SPIKE (= A VERTICAL OR HORIZONTAL LINE
!              SEGMENT) FROM THE BASE POINT ASP2BA TO THE POINT Y(.).
!              DO SO FOR A SPECIFIED SPIKE LINE TYPE, LINES COLOR,
!              LINE DIRECTION, AND LINE THICKNESS.
!     NOTE--THE VARIABLES PY(.) AND PX(.) ARE DUMMY VARIABLES
!           WHICH ARE USED IN THE INTERMEDIATE CALCULATIONS
!           AND WHOSE DIMENSIONS ARE DEFINED (FOR EASY OF CHANGE)
!           BACK IN THE MAIN ROUTINE.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED--APRIL     1987.
!     UPDATED         --SEPTEMBER 1988. RENUMBER
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 ISORSW
      CHARACTER*4 ISP2LI
      CHARACTER*4 ISP2CO
      CHARACTER*4 ISP2DI
      CHARACTER*4 IX1TSC
      CHARACTER*4 IY1TSC
!
      CHARACTER*4 ITYPE
      CHARACTER*4 IFIG
      CHARACTER*4 IPATTT
      CHARACTER*4 ICOL
      CHARACTER*4 IDIR
      CHARACTER*4 ICASE
!
!     6/23/86
!     HOW COME THE FOLLOWING 4 VARIABLES ARE NOT CARRIED
!     AS INPUT TO THIS SUBROUTINE--NOT NEEDED???
!     CHECK ON THIS.
!
      CHARACTER*4 IHORPA
      CHARACTER*4 IVERPA
      CHARACTER*4 IDUPPA
      CHARACTER*4 IDDOPA
!
      DIMENSION XRAW(*)
      DIMENSION YRAW(*)
      DIMENSION ZRAW(*)
      DIMENSION PX(*)
      DIMENSION PY(*)
      DIMENSION PZ(*)
      DIMENSION PX2(*)
      DIMENSION PY2(*)
      DIMENSION PZ2(*)
      DIMENSION PX3(*)
      DIMENSION PY3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      J=0
      HOLD=1.0
      ABASE=0.0
      PBASE=0.0
      PBASE2=0.0
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      FYMIN=FY1MIN
      FYMAX=FY1MAX
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRSP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRSP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,ICAS3D,ISORSW,NP
   53   FORMAT('ICASPL,ICAS3D,ISORSW,NP = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(NP.GT.3)THEN
          DO 65 I=1,3
            WRITE(ICOUT,66)I,XRAW(I),YRAW(I),ZRAW(I)
   66       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   65     CONTINUE
          NPM2=NP-2
          DO 67 I=NPM2,NP
            WRITE(ICOUT,68)I,XRAW(I),YRAW(I),ZRAW(I)
   68       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   67     CONTINUE
        ENDIF
        WRITE(ICOUT,72)ISP2LI,ISP2CO,ISP2DI
   72   FORMAT('ISP2LI,ISP2CO,ISP2DI= ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)PSP2TH,ASP2BA,ISP2CR,ISP2CG,ISP2CB
   73   FORMAT('PSP2TH,ASP2BA,ISP2CR,ISP2CG,ISP2CB = ',2G15.7,3I6)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NP
          WRITE(ICOUT,82)I,PX3(I),PY3(I)
   82     FORMAT('I,PX3(I),PY3(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,84)PXMIN,PXMAX,PYMIN,PYMAX
   84   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,85)FX1MIN,FX1MAX,FY1MIN,FY1MAX
   85   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,86)IX1TSC,IY1TSC
   86   FORMAT('IX1TSC,IY1TSC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IBUGG4,ISUBG4,IERRG4
   89   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 11--                                  **
!               **  IF CALLED FOR, SORT THE DATA               **
!               **  ACCORDING TO THE HORIZONTAL AXIS VARIABLE  **
!               *************************************************
!
      IDIR=ISP2DI
!
      IF(ISORSW.EQ.'OFF' .OR. ICASPL.EQ.'PIEC' .OR.   &
         ICAS3D.EQ.'ON'  .OR. ICASPL.EQ.'CONT')THEN
        DO 1160 I=1,NP
          PX(I)=XRAW(I)
          PY(I)=YRAW(I)
          PZ(I)=ZRAW(I)
 1160   CONTINUE
      ENDIF
!
!               ************************************************
!               **  STEP 12--                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,        **
!               **  CHECK THAT ALL DATA POINTS ARE POSITIVE.  **
!               ************************************************
!
!               ******************************************
!               **  STEP 40--                           **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,  **
!               **  TRANSFORM THE DATA                  **
!               ******************************************
!
!
      ABASE=ASP2BA
      IF(IX1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'H')THEN
          IF(ASP2BA.LE.0.0)HOLD=ASP2BA
          IF(ASP2BA.LE.0.0)GO TO 1250
        ENDIF
!
        IF(ISORSW.EQ.'ON')THEN
          J=1
          IF(PX(J).LE.0.0)GO TO 1250
        ELSE
          DO 1235 I=1,NP
            J=I
            IF(PX(J).LE.0.0)GO TO 1250
 1235     CONTINUE
        ENDIF
        GO TO 1290
!
 1250   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1251)
 1251   FORMAT('***** ERROR IN 3-D SPIKES (D3DRSP)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1252)
 1252   FORMAT('      THE LOG OF A NON-POSITIVE DATA VALUE WAS ',   &
               'ENCOUNTERED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1254)
 1254   FORMAT('      IN FORMING A PLOT.  DATA MAY NOT BE ZERO OR ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1255)
 1255   FORMAT('      WHEN A LOG SCALE PLOT IS USED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1256)PX(J)
 1256   FORMAT('      THE VALUE = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1257)
 1257   FORMAT('      THIS VALUE CAME FROM THE HORIZONTAL AXIS ',   &
               'VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1259)
 1259   FORMAT('      CORRECTIVE ACTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1260)
 1260   FORMAT('      CHANGE DATA OR CHANGE LIMITS.')
        CALL DPWRST('XXX','BUG ')
        IERRG4='YES'
        IF(IDIR.EQ.'H')ABASE=LOG10(ABASE)
!
 1290   CONTINUE
        DO 4015 I=1,NP
          PX(I)=LOG10(PX(I))
 4015   CONTINUE
!
      ENDIF
!
      IF(IY1TSC.EQ.'LOG')THEN
        IF(IDIR.EQ.'V')THEN
          IF(ASP2BA.LE.0.0)HOLD=ASP2BA
          IF(ASP2BA.LE.0.0)GO TO 1350
        ENDIF
!
        IF(ISORSW.EQ.'ON')THEN
          J=1
          IF(PY(J).LE.0.0)HOLD=PY(J)
          IF(PY(J).LE.0.0)GO TO 1350
        ELSE
          DO 1335 I=1,NP
            J=I
            IF(PY(J).LE.0.0)HOLD=PY(J)
            IF(PY(J).LE.0.0)GO TO 1350
 1335     CONTINUE
        ENDIF
        GO TO 1390
!
 1350   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1251)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1252)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1254)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1255)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1256)HOLD
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1357)
 1357   FORMAT('      THIS VALUE CAME FROM THE VERTICAL AXIS VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1259)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1260)
        CALL DPWRST('XXX','BUG ')
        IERRG4='YES'
        GO TO 9000
!
 1390   CONTINUE
!
        IF(IDIR.EQ.'V')ABASE=LOG10(ABASE)
        DO 4025 I=1,NP
          PY(I)=LOG10(PY(I))
 4025   CONTINUE
!
      ENDIF
                                                                                                                                  
!
!
!
!               *******************************
!               **  STEP 60--                **
!               **  PREPARE TO MAKE VARIOUS  **
!               **  LINE SETTINGS            **
!               *******************************
!
      ITYPE='LINE'
!
!               **********************************************
!               **  STEP 61--                               **
!               **  TRANSLATE THE CHARACTER REPRESENTATION  **
!               **  OF THE LINE PATTERN                     **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      IPATTT=ISP2LI
      CALL GRTRPA(ITYPE,IPATTT,PXSPA,PYSPA,   &
      JPATTT,IHORPA,IVERPA,IDUPPA,IDDOPA,PXSPA2,PYSPA2)
!
!               *******************************
!               **  STEP 62--                **
!               **  SET THE LINE PATTERN     **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
      CALL GRSEPA(ITYPE,IPATTT,PXSPA,PYSPA,   &
      JPATTT,IHORPA,IVERPA,IDUPPA,IDDOPA,PXSPA2,PYSPA2)
!
!               **********************************************
!               **  STEP 63--                               **
!               **  TRANSLATE THE  DESIRED                  **
!               **  LINE THICKNESS                          **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      PTHICK=PSP2TH
      CALL GRTRTH(ITYPE,PTHICK,JTHICK,PTHIC2)
!
!               *******************************
!               **  STEP 64--                **
!               **  SET THE LINE THICKNESS   **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
      CALL GRSETH(ITYPE,PTHICK,JTHICK,PTHIC2)
!
!               **********************************************
!               **  STEP 65--                               **
!               **  TRANSLATE THE CHARACTER REPRESENTATION  **
!               **  OF THE LINE COLOR                       **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      ICOL=ISP2CO
      ICASE='LINE'
      ICOLR=ISP2CR
      ICOLG=ISP2CG
      ICOLB=ISP2CB
      CALL GRTRC2(ICOLR,ICOLG,ICOLB,ARED,AGREEN,ABLUE,   &
                  AALPHA,IRGBFL)
      IF(IRGBFL.EQ.1)THEN
        CALL GRSEC2(ICASE,IRGBFL,ARED,AGREEN,ABLUE,AALPHA)
      ELSE
        CALL GRTRCO(ITYPE,ICOL,JCOL)
!
!               *******************************
!               **  STEP 66--                **
!               **  SET THE LINE COLOR       **
!               **  ON THE GRAPHICS DEVICE.  **
!               *******************************
!
        CALL GRSECO(ITYPE,ICOL,JCOL)
      ENDIF
!
!               **************************************************
!               **  STEP 71--                                   **
!               **  FOR EACH RAW 3-D DATA POINT--               **
!               **     1) MAKE THE SPIKE                        **
!               **     2) TRANSLATE IT TO 2 DIMENSIONS          **
!               **     3) TRANSLATE IT TO 0-100 UNITS           **
!               **     4) CLIP THE SPIKE IF NEEDED              **
!               **     5) DRAW OUT THE SPIKE                    **
!               **************************************************
!
!
      IFIG='GENE'
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      IF(IX1TSC.EQ.'LOG')FXMIN=LOG10(FX1MIN)
      IF(IX1TSC.EQ.'LOG')FXMAX=LOG10(FX1MAX)
!
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      IF(IY1TSC.EQ.'LOG')FYMIN=LOG10(FY1MIN)
      IF(IY1TSC.EQ.'LOG')FYMAX=LOG10(FY1MAX)
!
      FXRANG=FXMAX-FXMIN
      FYRANG=FYMAX-FYMIN
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
      DO 7100 I=1,NP
!
        CALL D3MKSP(PX,PY,PZ,NP,I,   &
                    IDIR,   &
                    ABASE,ABASE,ABASE,   &
                    PX2,PY2,PZ2,NP2)
!
        CALL D3TR32(PX2,PY2,PZ2,NP2,PX3,PY3,NP3)
!
        CALL D3TRXP(PX3,PY3,NP3,IDIR,ABASE,   &
                    FXMIN,FXMAX,FXRANG,FYMIN,FYMAX,FYRANG,   &
                    PXMIN,PXMAX,PXRANG,PYMIN,PYMAX,PYRANG,   &
                    PX3,PY3,NP3,PBASE)
!
        CALL DPSQUE(PX3,PY3,NP3,PXMIN,PXMAX,PYMIN,PYMAX)
!
        CALL GRDRPL(PX3,PY3,NP3,   &
                    IFIG,IPATTT,PTHICK,   &
                    ICOL,ICOLF,ICOLG,ICOLB,IRGBFL,   &
                    JPATTT,JTHICK,PTHIC2,JCOL)
!
 7100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRSP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRSP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ITYPE,IFIG,IERRG4,HOLD,NP2,NP3
 9014   FORMAT('ITYPE,IFIG,IERRG4,HOLD,NP2,NP3 = ',3(A4,2X),G15.7,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9044)PXMIN,PXMAX,PYMIN,PYMAX
 9044   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9045)FX1MIN,FX1MAX,FY1MIN,FY1MAX
 9045   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9046)FXMIN,FXMAX,FYMIN,FYMAX
 9046   FORMAT('FXMIN,FXMAX,FYMIN,FYMAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9052)IPATTT,JPATTT
 9052   FORMAT('IPATTT,JPATTT = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)PTHICK,JTHICK,PTHIC2
 9053   FORMAT('PTHICK,JTHICK,PTHIC2 = ',E15.7,I8,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9054)ICOL,JCOL,IDIR
 9054   FORMAT('ICOL,JCOL,IDIR = ',A4,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRSP
      SUBROUTINE D3DRTR(XRAW,YRAW,ZRAW,PX,PY,PZ,NP,PY2,PX2,NP2,   &
                        PY3,PX3,NP3,   &
                        ICASPL,ICAS3D,ISORSW,   &
                        ILI2PA,ILI2CO,ILI2CR,ILI2CG,ILI2CB,PLI2TH,   &
                        ARE2BA,IRE2FS,IRE2FC,IRE2FR,IRE2FG,IRE2FB,   &
                        IRE2PT,IRE2PL,IRE2PC,IRE2PR,IRE2PG,IRE2PB,   &
                        PRE2PT,PRE2PS,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IX1TSC,IY1TSC)
!
!     PURPOSE--FOR A GENERAL GRAPHICS DEVICE,
!              DRAW A SINGLE TRACE OF Y(.) VERSUS X(.)
!              FOR A SPECIFIED LINE TYPE, COLOR, AND THICKNESS.
!              AND (IF CALLED FOR) FILL IN BELOW/ABOVE THE TRACE
!              TO THE BASE LINE ARE2BA.
!     NOTE--THE VARIABLES PY(.) AND PX(.) ARE DUMMY VARIABLES
!           WHICH ARE USED IN THE INTERMEDIATE CALCULATIONS
!           AND WHOSE DIMENSIONS ARE DEFINED (FOR EASY OF CHANGE)
!           BACK IN THE MAIN ROUTINE.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --FEBRUARY  1988. STAR PLOT
!     UPDATED         --SEPTEMBER 1988. LOG/WEIBULL CHECK AS A SUBROUTINE
!     UPDATED         --SEPTEMBER 1988. RENUMBER
!     UPDATED         --AUGUST    1992. CALL TO DPFIRE
!     UPDATED         --JULY      1993. NORMAL SCALE (JJF)
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAS3D
      CHARACTER*4 ISORSW
!
      CHARACTER*4 ILI2PA
      CHARACTER*4 ILI2CO
!
      CHARACTER*4 IRE2FS
      CHARACTER*4 IRE2FC
      CHARACTER*4 IRE2PT
      CHARACTER*4 IRE2PL
      CHARACTER*4 IRE2PC
!
      CHARACTER*4 IX1TSC
      CHARACTER*4 IY1TSC
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT
      CHARACTER*4 ICOL
!
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
!
      CHARACTER*4 ICASAX
!
!CCCC AUGUST 1992.
      CHARACTER*4 IPATT2
!
      DIMENSION XRAW(*)
      DIMENSION YRAW(*)
      DIMENSION ZRAW(*)
      DIMENSION PX(*)
      DIMENSION PY(*)
      DIMENSION PZ(*)
      DIMENSION PY2(*)
      DIMENSION PX2(*)
      DIMENSION PY3(*)
      DIMENSION PX3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HOLD=1.0
      ABASE=0.0
      PBASE=0.0
      PBASE2=0.0
      PLEFT=0.0
      PRIGHT=0.0
      AWIDTH=0.0
      PWIDTH=0.0
      FYRATI=0.0
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      AHUNDR=100.0
      ABASE2=0.0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRTR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF D3DRTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISORSW,ICASPL,ICAS3D,NP,NP3
   52   FORMAT('ISORSW,ICASPL,ICAS3D,NP,NP3 = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 45 I=1,NP3
          WRITE(ICOUT,46)I,PX3(I),PY3(I)
   46     FORMAT('I,PX3(I),PY3(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   45   CONTINUE
        IF(NP.GT.3)THEN
          DO 65 I=1,3
            WRITE(ICOUT,66)I,XRAW(I),YRAW(I),ZRAW(I)
   66       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   65     CONTINUE
          NPM2=NP-2
          DO 67 I=NPM2,NP
            WRITE(ICOUT,68)I,XRAW(I),YRAW(I),ZRAW(I)
   68       FORMAT('I,XRAW(I),YRAW(I),ZRAW(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   67     CONTINUE
        ENDIF
        WRITE(ICOUT,71)ILI2PA,ILI2CO,PLI2TH,ILI2CR,ILI2CG,ILI2CB
   71   FORMAT('ILI2PA,ILI2CO,PLI2TH,ILI2CR,ILI2CG,ILI2CB = ',   &
               A4,2X,A4,G15.7,3I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)IRE2FS,IRE2FC,ARE2BA
   73   FORMAT('IRE2FS,IRE2FC,ARE2BA = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,74)IRE2PT,IRE2PL,IRE2PC,PRE2PT,PRE2PS
   74   FORMAT('IRE2PT,IRE2PL,IRE2PC,PRE2PT,PRE2PS = ',   &
               3(A4,2X),2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,84)PXMIN,PXMAX,PYMIN,PYMAX
   84   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,85)FX1MIN,FX1MAX,FY1MIN,FY1MAX
   85   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,86)IX1TSC,IY1TSC
   86   FORMAT('IX1TSC,IY1TSC = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IBUGG4,ISUBG4,IERRG4
   89   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 11--                                  **
!               **  IF CALLED FOR, SORT THE DATA               **
!               **  ACCORDING TO THE HORIZONTAL AXIS VARIABLE  **
!               *************************************************
!               ******************************************
!               **  STEP 41--                           **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,  **
!               **  TRANSFORM THE DATA                  **
!               ******************************************
!
!               ******************************************
!               **  STEP 42--                           **
!               **  IF A WEIBULL SCALE PLOT IS CALLED   **
!               **  FOR TRANSFORM THE DATA              **
!               ******************************************
!
!               ******************************************
!               **  STEP 43--                           **
!               **  IF A NORMAL  SCALE PLOT IS CALLED   **
!               **  FOR TRANSFORM THE DATA              **
!               ******************************************
!
      IF(ISORSW.EQ.'OFF'  .OR. ICASPL.EQ.'PIEC' .OR.   &
         ICASPL.EQ.'STAR' .OR. ICAS3D.EQ.'ON'   .OR.   &
         ICASPL.EQ.'CONT')THEN
        DO 1160 I=1,NP
          PX(I)=XRAW(I)
          PY(I)=YRAW(I)
          PZ(I)=ZRAW(I)
 1160   CONTINUE
      ENDIF
!
!               **********************************************************
!               **  STEP 21--                                           **
!               **  IF A NON-LINEAR SCALE PLOT IS CALLED FOR,           **
!               **  CHECK THAT ALL   HORIZ. AXIS DATA POINTS            **
!               **  ARE IN VALID RANGE.                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,                  **
!               **  CHECK THAT ALL   HORIZ.  AXIS DATA POINTS ARE > 0.  **
!               **  IF A WEIBULL SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   HORIZ. AXIS DATA POINTS ARE        **
!               **  IF A NORMAL SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   HORIZ. AXIS DATA POINTS ARE        **
!               **  STRICTLY > 0 AND STRICTLY < 100                     **
!               **********************************************************
!
      IF(IX1TSC.EQ.'LOG')THEN
        ICASAX='2DHO'
        CALL CKLOSC(PX,NP,ISORSW,ICASAX,ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        DO 4115 I=1,NP
          PX(I)=LOG10(PX(I))
 4115   CONTINUE
      ELSEIF(IX1TSC.EQ.'WEIB')THEN
        ICASAX='2DHO'
        DO 4215 I=1,NP
          PX(I)=LOG(LOG(AHUNDR/(AHUNDR-PX(I))))
 4215   CONTINUE
      ELSEIF(IX1TSC.EQ.'NORM')THEN
        ICASAX='2DHO'
        DO 4315 I=1,NP
          CALL NORCDF(PX(I),ATEMP)
          PX(I)=AHUNDR*ATEMP
 4315   CONTINUE
      ENDIF
!
!               **********************************************************
!               **  STEP 22--                                           **
!               **  IF A NON-LINEAR SCALE PLOT IS CALLED FOR,           **
!               **  CHECK THAT ALL   VERT.  AXIS DATA POINTS            **
!               **  ARE IN VALID RANGE.                                 **
!               **  IF A LOG SCALE PLOT IS CALLED FOR,                  **
!               **  CHECK THAT ALL   VERT.   AXIS DATA POINTS ARE > 0.  **
!               **  IF A WEIBULL SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   VERT.  AXIS DATA POINTS ARE        **
!               **  STRICTLY > 0 AND STRICTLY < 100                     **
!               **  IF A NORMAL  SCALE PLOT IS CALLED FOR,              **
!               **  CHECK THAT ALL   VERT.  AXIS DATA POINTS ARE        **
!               **  STRICTLY > 0 AND STRICTLY < 100                     **
!               **********************************************************
!
      ABASE=ARE2BA
      IF(IY1TSC.EQ.'LOG')THEN
        ICASAX='2DVE'
        CALL CKLOSC(PY,NP,ISORSW,ICASAX,ISUBG4,IBUGG4,IERRG4)
        IF(IERRG4.EQ.'YES')GO TO 9000
        IF(ABASE.NE.CPUMAX.AND.ABASE.GT.0.0)ABASE=LOG10(ABASE)
        IF(ABASE.NE.CPUMAX.AND.ABASE.LE.0.0)ABASE=1.0
        DO 4125 I=1,NP
          PY(I)=LOG10(PY(I))
 4125   CONTINUE
      ELSEIF(IY1TSC.EQ.'WEIB')THEN
        ICASAX='2DVE'
        IF(ABASE.NE.CPUMAX.AND.ABASE.GT.0.0.AND.ABASE.LT.AHUNDR)   &
           ABASE2=LOG(LOG(AHUNDR/(AHUNDR-ABASE)))
        IF(ABASE.NE.CPUMAX.AND.ABASE.LE.0.0)ABASE2=0.1
        IF(ABASE.NE.CPUMAX.AND.ABASE.GE.AHUNDR)ABASE2=0.1
        ABASE=ABASE2
        DO 4225 I=1,NP
          PY(I)=LOG(LOG(AHUNDR/(AHUNDR-PY(I))))
 4225   CONTINUE
      ELSEIF(IY1TSC.EQ.'NORM')THEN
        ICASAX='2DVE'
        CALL NORCDF(ABASE,ATEMP)
        IF(ABASE.NE.CPUMAX.AND.ABASE.GT.0.0.AND.ABASE.LT.AHUNDR)   &
           ABASE2=AHUNDR*ATEMP
        IF(ABASE.NE.CPUMAX.AND.ABASE.LE.0.0)ABASE2=0.1
        IF(ABASE.NE.CPUMAX.AND.ABASE.GE.AHUNDR)ABASE2=0.1
        ABASE=ABASE2
        DO 4325 I=1,NP
          CALL NORCDF(PY(I),ATEMP)
          PY(I)=AHUNDR*ATEMP
 4325   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 51--                                   **
!               **  FORM THE TRACE IN RAW 3-D SPACE.            **
!               **************************************************
!
!               **************************************************
!               **  STEP 52--                                   **
!               **  IF HIDDEN LINE REMOVAL IS ON,               **
!               **  DETERMINE IF ANY PART                       **
!               **  OF THE TRACE IS VISIBLE;                    **
!               **  FORM SUBTRACES.                             **
!               **************************************************
!
!               **************************************************
!               **  STEP 53--                                   **
!               **  TRANSLATE THE VISIBLE SUB-TRACES            **
!               **  FROM THE RAW 3-D SPACE                      **
!               **  TO THE FINAL VISUAL 2-D PLANE.              **
!               **************************************************
!
      CALL D3TR32(PX,PY,PZ,NP,PX,PY,NP)
!
!               *****************************************************
!               **  STEP 54--                                      **
!               **  TRANSLATE THE 2-D PLANE DATA POINTS            **
!               **  INTO STANDARDIZED (0.0 TO 100.0) COORDINATES.  **
!               *****************************************************
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      CALL NORCDF(FX1MIN,ATEMP)
      IF(IX1TSC.EQ.'LOG')THEN
        FXMIN=LOG10(FX1MIN)
        FXMAX=LOG10(FX1MAX)
      ELSEIF(IX1TSC.EQ.'WEIB')THEN
        FXMIN=LOG(LOG(AHUNDR/(AHUNDR-FX1MIN)))
        FXMAX=LOG(LOG(AHUNDR/(AHUNDR-FX1MAX)))
      ELSEIF(IX1TSC.EQ.'NORM')THEN
        FXMIN=AHUNDR*ATEMP
        CALL NORCDF(FX1MAX,ATEMP)
        FXMAX=AHUNDR*ATEMP
      ENDIF
!
      FYMIN=FY1MIN
      FYMAX=FY1MAX
      CALL NORCDF(FY1MIN,ATEMP)
      IF(IY1TSC.EQ.'LOG')THEN
        FYMIN=LOG10(FY1MIN)
        FYMAX=LOG10(FY1MAX)
      ELSEIF(IY1TSC.EQ.'WEIB')THEN
        FYMIN=LOG(LOG(AHUNDR/(AHUNDR-FY1MIN)))
        FYMAX=LOG(LOG(AHUNDR/(AHUNDR-FY1MAX)))
      ELSEIF(IY1TSC.EQ.'NORM')THEN
        FYMIN=AHUNDR*ATEMP
        CALL NORCDF(FY1MAX,ATEMP)
        FYMAX=AHUNDR*ATEMP
      ENDIF
!
      FXRANG=FXMAX-FXMIN
      FYRANG=FYMAX-FYMIN
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
      DO 5410 I=1,NP
        FXRATI=(PX(I)-FXMIN)/FXRANG
        FYRATI=(PY(I)-FYMIN)/FYRANG
        PX(I)=PXMIN+FXRATI*PXRANG
        PY(I)=PYMIN+FYRATI*PYRANG
 5410 CONTINUE
      IF(ABASE.NE.CPUMAX)FYRATI=(ABASE-FYMIN)/FYRANG
      IF(ABASE.NE.CPUMAX)PBASE=PYMIN+FYRATI*PYRANG
!
!               **************************************
!               **  STEP 60--                       **
!               **  IF CALLED FOR,                  **
!               **  FILL OVER/UNDER THE TRACE       **
!               **  (BUT CLIP FIRST, IF NECESSARY)  **
!               **************************************
!
      IFIG='GENE'
!
      IF(IRE2FS.EQ.'OFF')GO TO 6190
      IPATT=IRE2PT
      PTHICK=PRE2PT
      PXGAP=PRE2PS
      PYGAP=PRE2PS
      ICOLF=IRE2FC
      ICOLFR=IRE2FR
      ICOLFG=IRE2FG
      ICOLFB=IRE2FB
      ICOLP=IRE2PC
      ICOLPR=IRE2PR
      ICOLPG=IRE2PG
      ICOLPB=IRE2PB
      IPATT2='SOLI'
!
      CALL DPSQUE(PX,PY,NP,PXMIN,PXMAX,PYMIN,PYMAX)
!
      IF(ABASE.EQ.CPUMAX)GO TO 6110
      GO TO 6120
!
 6110 CONTINUE
      DO 6115 I=1,NP
        PX2(I)=PX(I)
        PY2(I)=PY(I)
 6115 CONTINUE
      NP2=NP+1
      PX2(NP2)=PX(1)
      PY2(NP2)=PY(1)
!
      DO 6116 J=1,NP2
        IF(PX2(J).LT.PXMIN)PX2(J)=PXMIN
        IF(PX2(J).GT.PXMAX)PX2(J)=PXMAX
        IF(PY2(J).LT.PYMIN)PY2(J)=PYMIN
        IF(PY2(J).GT.PYMAX)PY2(J)=PYMAX
 6116 CONTINUE
!
      CALL DPFIRE(PX2,PY2,NP2,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
!
      GO TO 6190
!
 6120 CONTINUE
      PBASE2=PBASE
      IF(PBASE2.LT.PYMIN.AND.(PYMIN-PBASE2).LE.0.0001)PBASE2=PYMIN
      IF(PBASE2.GT.PYMAX.AND.(PBASE2-PYMAX).LE.0.0001)PBASE2=PYMAX
!
      NP2=5
      NPM1=NP-1
      IF(NPM1.LE.0)GO TO 6190
      DO 6125 I=1,NPM1
        IP1=I+1
!
        PLEFT=PX(I)
        PRIGHT=PX(IP1)
        IF(PLEFT.LT.PXMIN.AND.(PXMIN-PLEFT).LE.0.0001)PLEFT=PXMIN
        IF(PRIGHT.GT.PXMAX.AND.(PRIGHT-PXMAX).LE.0.0001)PRIGHT=PXMAX
!
        IF(PRIGHT.LT.PXMIN)GO TO 6125
        IF(PLEFT.GT.PXMAX)GO TO 6125
        IF(PY(I).LT.PYMIN.AND.PBASE2.LT.PYMIN)GO TO 6125
        IF(PY(I).GT.PYMAX.AND.PBASE2.GT.PYMAX)GO TO 6125
!
        PX2(1)=PLEFT
        PX2(2)=PRIGHT
        PX2(3)=PRIGHT
        PX2(4)=PLEFT
        PX2(5)=PLEFT
!
        PY2(1)=PBASE2
        PY2(2)=PBASE2
        PY2(3)=PY(IP1)
        PY2(4)=PY(I)
        PY2(5)=PBASE2
!
        DO 6126 J=1,NP2
          IF(PX2(J).LT.PXMIN)PX2(J)=PXMIN
          IF(PX2(J).GT.PXMAX)PX2(J)=PXMAX
          IF(PY2(J).LT.PYMIN)PY2(J)=PYMIN
          IF(PY2(J).GT.PYMAX)PY2(J)=PYMAX
 6126   CONTINUE
!
        CALL DPFIRE(PX2,PY2,NP2,   &
                    IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                    ICOLF,ICOLFR,ICOLFG,ICOLBB,   &
                    ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                    IPATT2)
 6125 CONTINUE
!
      GO TO 6190
!
 6190 CONTINUE
!
!               *****************************************
!               **  STEP 70--                          **
!               **  DRAW OUT THE TRACE                 **
!               **  (BUT CLIP IT FIRST, IF NECESSARY)  **
!               *****************************************
!
      IFIG='GENE'
      IPATT=ILI2PA
      PTHICK=PLI2TH
      ICOL=ILI2CO
      ICOLR=ILI2CR
      ICOLG=ILI2CG
      ICOLB=ILI2CB
!
!CCCC PX3 AND PY3 COMMENTED OUT IN DPCLTR, SO TREAT AS
!CCCC SCALAR HERE FOR NOW.
!
      CALL DPCLTR(PX,PY,NP,PX2,PY2,NP2,   &
                  PXMIN,PXMAX,PYMIN,PYMAX,   &
                  ISORSW,IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'DRTR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF D3DRTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)ARE2BA
 9032   FORMAT('ARE2BA = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9046)FXMIN,FXMAX,FYMIN,FYMAX
 9046   FORMAT('FXMIN,FXMAX,FYMIN,FYMAX= ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9049)IBUGG4,ISUBG4,IERRG4
 9049   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE D3DRTR
      SUBROUTINE D3MKBA(XRAW,YRAW,ZRAW,NRAW,IRAW,IDIR,   &
                        WIDTHX,WIDTHY,WIDTHZ,   &
                        BASEX,BASEY,BASEZ,   &
                        XVECT,YVECT,ZVECT,IXNEAR,IXFAR,IYNEAR,IYFAR,   &
                        IZNEAR,IZFAR,   &
                        XBAR,YBAR,ZBAR,NBAR)
!
!     PURPOSE--GIVEN A SINGLE POINT (XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW))
!              IN 3-SPACE, AND AN EYE POSITION,
!              MAKE (= CONSTRUCT) A 3-D BAR.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISIONBAR
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--SEPTEMBER 1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDIR
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION XRAW(*)
      DIMENSION YRAW(*)
      DIMENSION ZRAW(*)
!
      DIMENSION XVECT(*)
      DIMENSION YVECT(*)
      DIMENSION ZVECT(*)
!
      DIMENSION XBAR(*)
      DIMENSION YBAR(*)
      DIMENSION ZBAR(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3MK'
      ISUBN2='BA  '
!
      IF(IBUGG4.NE.'ON'.AND.ISUBG4.NE.'MKBA')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3MKBA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG4,ISUBG4,IERRG4
   52 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDIR
   53 FORMAT('IDIR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)WIDTHX,WIDTHY,WIDTHZ
   54 FORMAT('WIDTHX,WIDTHY,WIDTHZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)BASEX,BASEY,BASEZ
   55 FORMAT('BASEX,BASEY,BASEZ    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)X3DEYE,Y3DEYE,Z3DEYE
   56 FORMAT('X3DEYE,Y3DEYE,Z3DEYE    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)XVECT(1),YVECT(1),ZVECT(1)
   61 FORMAT('XVECT(1),YVECT(1),ZVECT(1) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)XVECT(2),YVECT(2),ZVECT(2)
   62 FORMAT('XVECT(2),YVECT(2),ZVECT(2) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)IXNEAR,IXFAR,IYNEAR,IYFAR,IZNEAR,IZFAR
   63 FORMAT('IXNEAR,IXFAR,IYNEAR,IYFAR,IZNEAR,IZFAR = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,71)NRAW,IRAW
   71 FORMAT('NRAW,IRAW = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,72)IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW)
   72 FORMAT('IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************************************
!               **  MAKE (= CONSTRUCT) A BAR.                 **
!               **************************************************
!
!               **************************************************
!               **  STEP 11-                                    **
!               **  FIND THE NEAREST (TO THE EYE) VERTEX        **
!               **  OF OF THE 8 VERTICES OF THE 3-D BAR         **
!               **************************************************
!
      X0=XRAW(IRAW)
      Y0=YRAW(IRAW)
      Z0=ZRAW(IRAW)
!
      IF(IDIR.EQ.'V')GO TO 1110
      IF(IDIR.EQ.'H1')GO TO 1120
      IF(IDIR.EQ.'H2')GO TO 1130
      GO TO 1110
!
 1110 CONTINUE
      XVECT(1)=X0-WIDTHX/2.0
      XVECT(2)=X0+WIDTHX/2.0
      YVECT(1)=Y0-WIDTHY/2.0
      YVECT(2)=Y0+WIDTHY/2.0
      ZVECT(1)=BASEZ
      ZVECT(2)=Z0
      GO TO 1150
!
 1120 CONTINUE
      XVECT(1)=BASEX
      XVECT(2)=X0
      YVECT(1)=Y0-WIDTHY/2.0
      YVECT(2)=Y0+WIDTHY/2.0
      ZVECT(1)=Z0-WIDTHZ/2.0
      ZVECT(2)=Z0+WIDTHZ/2.0
      GO TO 1150
!
 1130 CONTINUE
      XVECT(1)=X0-WIDTHX/2.0
      XVECT(2)=X0+WIDTHX/2.0
      YVECT(1)=BASEY
      YVECT(2)=Y0
      ZVECT(1)=Z0-WIDTHZ/2.0
      ZVECT(2)=Z0+WIDTHZ/2.0
      GO TO 1150
!
 1150 CONTINUE
!
      DISTSQ=CPUMAX
      DO 1151 IX=1,2
      XVECT2=XVECT(IX)
      DO 1152 IY=1,2
      YVECT2=YVECT(IY)
      DO 1153 IZ=1,2
      ZVECT2=ZVECT(IZ)
      DISTS2=(XVECT2-X3DEYE)**2+(YVECT2-Y3DEYE)**2+(ZVECT2-Z3DEYE)**2
      IF(DISTS2.LT.DISTSQ)GO TO 1155
      GO TO 1153
 1155 CONTINUE
      IXNEAR=IX
      IYNEAR=IY
      IZNEAR=IZ
 1153 CONTINUE
 1152 CONTINUE
 1151 CONTINUE
!
      IXFAR=1
      IF(IXNEAR.EQ.1)IXFAR=2
      IYFAR=1
      IF(IYNEAR.EQ.1)IYFAR=2
      IZFAR=1
      IF(IZNEAR.EQ.1)IZFAR=2
!
      XBAR(1)=XVECT(IXNEAR)
      XBAR(2)=XVECT(IXNEAR)
      XBAR(3)=XVECT(IXNEAR)
      XBAR(4)=XVECT(IXNEAR)
      XBAR(5)=XVECT(IXNEAR)
      YBAR(1)=YVECT(IYNEAR)
      YBAR(2)=YVECT(IYNEAR)
      YBAR(3)=YVECT(IYFAR)
      YBAR(4)=YVECT(IYFAR)
      YBAR(5)=YVECT(IYNEAR)
      ZBAR(1)=ZVECT(IZNEAR)
      ZBAR(2)=ZVECT(IZFAR)
      ZBAR(3)=ZVECT(IZFAR)
      ZBAR(4)=ZVECT(IZNEAR)
      ZBAR(5)=ZVECT(IZNEAR)
!
      XBAR(6)=XVECT(IXNEAR)
      XBAR(7)=XVECT(IXFAR)
      XBAR(8)=XVECT(IXFAR)
      XBAR(9)=XVECT(IXNEAR)
      XBAR(10)=XVECT(IXNEAR)
      YBAR(6)=YVECT(IYNEAR)
      YBAR(7)=YVECT(IYNEAR)
      YBAR(8)=YVECT(IYNEAR)
      YBAR(9)=YVECT(IYNEAR)
      YBAR(10)=YVECT(IYNEAR)
      ZBAR(6)=ZVECT(IZNEAR)
      ZBAR(7)=ZVECT(IZNEAR)
      ZBAR(8)=ZVECT(IZFAR)
      ZBAR(9)=ZVECT(IZFAR)
      ZBAR(10)=ZVECT(IZNEAR)
!
      XBAR(11)=XVECT(IXNEAR)
      XBAR(12)=XVECT(IXNEAR)
      XBAR(13)=XVECT(IXFAR)
      XBAR(14)=XVECT(IXFAR)
      XBAR(15)=XVECT(IXNEAR)
      YBAR(11)=YVECT(IYNEAR)
      YBAR(12)=YVECT(IYFAR)
      YBAR(13)=YVECT(IYFAR)
      YBAR(14)=YVECT(IYNEAR)
      YBAR(15)=YVECT(IYNEAR)
      ZBAR(11)=ZVECT(IZNEAR)
      ZBAR(12)=ZVECT(IZNEAR)
      ZBAR(13)=ZVECT(IZNEAR)
      ZBAR(14)=ZVECT(IZNEAR)
      ZBAR(15)=ZVECT(IZNEAR)
!
      NBAR=15
!
!               *****************
!               **  EXIT.      **
!               *****************
!
      IF(IBUGG4.NE.'ON'.AND.ISUBG4.NE.'MKBA')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3MKBA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDIR
 9013 FORMAT('IDIR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)WIDTHX,WIDTHY,WIDTHZ
 9014 FORMAT('WIDTHX,WIDTHY,WIDTHZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)BASEX,BASEY,BASEZ
 9015 FORMAT('BASEX,BASEY,BASEZ    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)X3DEYE,Y3DEYE,Z3DEYE
 9016 FORMAT('X3DEYE,Y3DEYE,Z3DEYE    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)XVECT(1),YVECT(1),ZVECT(1)
 9021 FORMAT('XVECT(1),YVECT(1),ZVECT(1) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)XVECT(2),YVECT(2),ZVECT(2)
 9022 FORMAT('XVECT(2),YVECT(2),ZVECT(2) = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)IXNEAR,IXFAR,IYNEAR,IYFAR,IZNEAR,IZFAR
 9023 FORMAT('IXNEAR,IXFAR,IYNEAR,IYFAR,IZNEAR,IZFAR = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)NRAW,IRAW
 9031 FORMAT('NRAW,IRAW = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW)
 9032 FORMAT('IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)NBAR
 9041 FORMAT('NBAR = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9042 I=1,NBAR
      WRITE(ICOUT,9043)I,XBAR(I),YBAR(I),ZBAR(I)
 9043 FORMAT('I,XBAR(I),YBAR(I),ZBAR(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9042 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3MKBA
      SUBROUTINE D3MKSP(XRAW,YRAW,ZRAW,NRAW,IRAW,   &
      IDIR,   &
      BASEX,BASEY,BASEZ,   &
      XSPIKE,YSPIKE,ZSPIKE,NSPIKE)
!
!     PURPOSE--GIVEN A SINGLE POINT (XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW))
!              IN 3-SPACE,
!              MAKE (= CONSTRUCT) A 3-D SPIKE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISIONSPIKE
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--SEPTEMBER 1988.
!     UPDATED         --APRIL   1992.  BASE2 TO BASEX/Y/Z
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDIR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
