   53 FORMAT('NRAW,IRAW = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)IDIR
   61 FORMAT('IDIR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)BASEX,BASEY,BASEZ
   62 FORMAT('BASEX,BASEY,BASEZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW)
   63 FORMAT('IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,71)X3DEYE,Y3DEYE,Z3DEYE
   71 FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************************************
!               **  STEP 11-                                    **
!               **  MAKE (= CONSTRUCT) A SPIKE.                 **
!               **************************************************
!
      IF(IDIR.EQ.'V')GO TO 1110
      IF(IDIR.EQ.'HX')GO TO 1120
      IF(IDIR.EQ.'HY')GO TO 1130
      GO TO 1110
!
 1110 CONTINUE
      XSPIKE(1)=XRAW(IRAW)
      YSPIKE(1)=YRAW(IRAW)
!CCCC THE FOLLOWING LINE WAS FIXED    APRIL 1992 (ALAN)
!CCCC ZSPIKE(1)=BASE2
      ZSPIKE(1)=BASEZ
      GO TO 1150
!
 1120 CONTINUE
!CCCC THE FOLLOWING LINE WAS FIXED    APRIL 1992 (ALAN)
!CCCC XSPIKE(1)=BASE2
      XSPIKE(1)=BASEX
      YSPIKE(1)=YRAW(IRAW)
      ZSPIKE(1)=ZRAW(IRAW)
      GO TO 1150
!
 1130 CONTINUE
      XSPIKE(1)=XRAW(IRAW)
!CCCC THE FOLLOWING LINE WAS FIXED    APRIL 1992 (ALAN)
!CCCC YSPIKE(1)=BASE2
      YSPIKE(1)=BASEY
      ZSPIKE(1)=ZRAW(IRAW)
      GO TO 1150
!
 1150 CONTINUE
!
      XSPIKE(2)=XRAW(IRAW)
      YSPIKE(2)=YRAW(IRAW)
      ZSPIKE(2)=ZRAW(IRAW)
!
      NSPIKE=2
!
!               *****************
!               **  EXIT.      **
!               *****************
!
      IF(IBUGG4.NE.'ON'.AND.ISUBG4.NE.'MKSP')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3MKSP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDIR
 9013 FORMAT('IDIR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)BASEX,BASEY,BASEZ
 9014 FORMAT('BASEX,BASEY,BASEZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)NRAW,IRAW
 9021 FORMAT('NRAW,IRAW = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW)
 9022 FORMAT('IRAW,XRAW(IRAW),YRAW(IRAW),ZRAW(IRAW) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)X3DEYE,Y3DEYE,Z3DEYE
 9031 FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)NSPIKE
 9041 FORMAT('NSPIKE = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9042 I=1,NSPIKE
      WRITE(ICOUT,9043)I,XSPIKE(I),YSPIKE(I),ZSPIKE(I)
 9043 FORMAT('I,XSPIKE(I),YSPIKE(I),ZSPIKE(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9042 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3MKSP
      SUBROUTINE D3SCAL(PX,PY,NP)
!
!     PURPOSE--EXECUTE A SCALING AND TRANSLATION
!      OF 3D POINTS THAT HAVE ALREADY
!     BEEN TRANSLATED INTO 2D VALUES
!     BUT NOW NEED TO BE SCALED AND TRANSLATED
!     TO PROPER 0 TO 100 SCREEN VALUES.
!     WRITTEN BY--JAMES J. FILLIBEN
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/10
!     ORIGINAL VERSION--SEPTEMBER 1993.
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1993.
!
!-----COMMON STATEMENTS-----------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION PX(*)
      DIMENSION PY(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3SC'
      ISUBN2='AL  '
!
      FXMIN=FX1MIN
      FXMAX=FX1MAX
      FYMIN=FY1MIN
      FYMAX=FY1MAX
!
      FXRANG=FXMAX-FXMIN
      FYRANG=FYMAX-FYMIN
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
      DO 1000 I=1,NP
      FXRATI=(PX(I)-FXMIN)/FXRANG
      FYRATI=(PY(I)-FYMIN)/FYRANG
      PX(I)=PXMIN+FXRATI*PXRANG
      PY(I)=PYMIN+FYRATI*PYRANG
 1000 CONTINUE
!
      RETURN
      END SUBROUTINE D3SCAL
      SUBROUTINE D3TR32(X,Y,Z,N,XT,ZT,NT)
!
!     PURPOSE--EXECUTE A 3-D TRANSFORMATION
!              (ORTHOGRAPHIC OR PERSPECTIVE)
!              WHICH TAKES A 3-D DATA CLOUD
!              AND MAPS IN ONTO A 2-D PLANE
!              (IDENTICALLY THE ORIGINAL XZ PLANE).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--MARCH     1979.
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1988.
!     UPDATE          --JUNE      1990.  COMPILE ERROR IN A WRITE STATEMENT
!
!-----COMMON STATEMENTS-----------------------------------------------
!
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION XT(*)
      DIMENSION ZT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3TR'
      ISUBN2='32  '
      IERRG4='NO'
!
      EPS=0.0000001
      TERMZX=0.0
      TERMZY=0.0
      TERMZZ=0.0
      TERMXX=0.0
      TERMXY=0.0
      TERMXZ=0.0
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TR32')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3TR32--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG4,ISUBG4,IERRG4
   52 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)I3DPRO
   53 FORMAT('I3DPRO = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)X3DEYE,Y3DEYE,Z3DEYE
   54 FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)X3DMID,Y3DMID,Z3DMID
   55 FORMAT('X3DMID,Y3DMID,Z3DMID = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)D3DCXX,D3DCXY,D3DCXZ
   64 FORMAT('D3DCXX,D3DCXY,D3DCXZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,65)D3DCYX,D3DCYY,D3DCYZ
   65 FORMAT('D3DCYX,D3DCYY,D3DCYZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,66)D3DCZX,D3DCZY,D3DCZZ
   66 FORMAT('D3DCZX,D3DCZY,D3DCZZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,71)N
   71 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 72 I=1,N
      WRITE(ICOUT,73)I,X(I),Y(I),Z(I)
   73 FORMAT('I,X(I),Y(I),Z(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   72 CONTINUE
   90 CONTINUE
!
!               *********************************************************
!               **  GENERAL DISCUSSION--                               **
!               **  DETERMINE (IN ORIGINAL COORDINATE SYSTEM VALUES)   **
!               **  WHERE THE DATA POINTS FALL ON THE VISUAL PLANE.    **
!               **  FOR EACH (XD,YD,ZD) DATA POINT,                    **
!               **  DETERMINE WHERE THE VISUAL RAY FROM                **
!               **  THE DATA POINT TO OUR EYE                          **
!               **  STRIKES THE VISUAL (PERSPECTIVE) PLANE.            **
!               **  THE VISUAL PLANE IS THAT PLANE                     **
!               **  WHICH IS NORMAL TO OUR EYE                         **
!               **  AND WHICH CONTAINS THE AVERAGE POINT (XM,YM,ZM).   **
!               **  THE EQUATION OF THE VISUAL PLANE IS                **
!               **  (X3DEYE-XM)(X-XM) + (Y3DEYE-YM)(Y-YM) +
!               **                    + (Z3DEYE-YM)(Z-ZM) = 0          **
!               **  WHERE X, Y, Z ARE THE DUMMY VARIABLES              **
!               **  REPRESENTING ANY POINT (X,Y,Z) ON THAT PLANE.      **
!               **  THIS EQUATION MUST BE SOLVED FOR X, Y, AND Z.      **
!               **  THE EQUATIONS OF THE LINE FROM THE DATA POINT
!               **  (XD,YD,ZD)
!               **  TO OUR EYE (X3DEYE,Y3DEYE,Z3DEYE) ARE
!               **  (X-XD)/(X3DEYE-XD) = (Y-YD)/(Y3DEYE-YD)
!               **                     = (Z-ZD)/(Z3DEYE-ZD)
!               **  WHERE (XD,YD,ZD) REPRESENTS A DATA POINT.           **
!               **  THE VISUAL PLANE EQUATION AND THE LINE EQUATIONS    **
!               **  MUST BE COMBINED TO SOLVE FOR THE VALUES (X,Y,Z)    **
!               **  ON THE VISUAL PLANE AS OUR EYE SEES THEM.           **
!               **********************************************************
!
!               **********************************************************
!               **  THE FINAL PLOT STATEMENT WILL INVOLVE
!               **  ONLY 2 VECTORS.
!               **  AT THE MOMENT, THE POINTS (XP,YP,ZP)
!               **  ON THE VISUAL PLANE ARE DEFINED
!               **  BY 3 COORDINATE VALUES.
!               **  TO REDUCE THE 3 COORDINATE VALUES
!               **  TO 2 COORDINATE VALUES,
!               **  WE MUST ROTATE THE VISUAL PLANE
!               **  SO THAT IT IS PARALLEL TO THE ORIGINAL XZ PLANE.
!               **  TO CARRY OUT SUCH A ROTATION, WE MUST
!               **  DETERMINE THE DIRECTION NUMBERS AND DIRECTION COSINES
!               **  OF THE NEW AXES IN TERMS OF THE OLD COORDINATE SYSTEM.
!               **  THE NEW Y AXIS WILL (BY CONSTRUCTION) BE
!               **  ON THE NORMAL LINE TRAVELING FROM
!               **  THE AVERAGE POINT (XM,YM,ZM) TO OUR EYE POINT
!               **  (X3DEYE,Y3DEYE,Z3DEYE)
!               **  AND WILL THEREFORE HAVE DIRECTIONS NUMBERS
!               **  X3DEYE, Y3DEYE, Z3DEYE
!               **  THE NEW Z AXIS WILL BE PERPENDICULAR TO THE NEW Y AXIS
!               **  AND WILL RESIDE IN THE PLANE CONTAINING THE
!               **  THE FOLLOWING 3 POINTS--
!               **      1) THE AVERAGE POINT (XM,YM,ZM)
!               **      2) THE EYE POINT (X3DEYE,Y3DEYE,Z3DEYE)
!               **      3) SOME POINT (SAY (XM,YM,ZM+1)) OF THE OLD Z AXIS
!               **         DISPLACED OVER SO AS TO EMANATE FROM (XM,YM,ZM).
!               **  THE ABOVE 3 POINTS DEFINE A VERTICAL PLANE.
!               **  THE PURPOSE OF THE VERTICAL PLANE IS TO DEFINE
!               **  WHICH DIRECTION IS 'UP' IN THE FINAL PICTURE.
!               **  THE EQUATION OF THE VERTICAL PLANE IS
!               **  (A-XM)(X-XM) + (B-YM)(Y-YM) + (C-ZM)(Z-ZM) = 0 .
!               **  THIS EQUATION MUST BE SOLVED FOR A, B, AND C.
!               **  WITHOUT LOSS OF GENERALITY, A MAY BE INITIALLY SET TO 1.
!               **  THE SOLUTION TURNS OUT TO BE
!               **      A = 1
!               **      B = -X3DEYE/Y3DEYE
!               **      C = 0
!               **  NOTE, HOWEVER, THAT THESE A, B, AND C VALUES
!               **  FOR THIS VERTICAL PLANE WILL BE IDENTICAL TO THE
!               **  DIRECTION NUMBERS FOR THE NORMAL TO THIS VERTICAL PLANE
!               **  WHICH IS IDENTICALLY THE NEW X AXIS
!               **  AND SO THE ABOVE A, B, AND C VALUES DEFINE THE DIRECTION
!               **  DIRECTION NUMBERS FOR THE NEW X AXIS.
!               **  TO SOLVE FOR THE DIRECTION NUMBERS FOR THE NEW Z AXIS,
!               **  WE SEEK 3 DIRECTION NUMBERS D, E, AND F
!               **  WHICH MUST BE PERPENDICULAR TO BOTH THE
!               **  NEW Y AXIS (WITH DIRECTION NUMBERS X3DEYE, Y3DEYE,
!               **  AND Z3DEYE)
!               **  AND THE NEW X AXIS (WITH DIRECTION NUMBERS A, B, AND C ABOVE
!               **  WITHOUT LOSS OF GENERALITY, D MAY BE INITIALLY SET TO 1.
!               **  NOTE THAT WHENEVER 2 LINES ARE PERPENDICULAR,
!               **  THE INNER PRODUCT OF THE DIRECTION NUMBERS MUST = 0.
!               **  WITHOUT LOSS OF GENERALITY, D MAY BE INITIALLY SET TO 1.
!               **  INCORPORATING THE 2 INNER PRODUCT EQUATIONS,
!               **  WE MAY SOLVE FOR E AND F.
!               **  THE SOLUTIONS TURN OUT TO BE
!               **      D = 1
!               **      E = Y3DEYE/X3DEYE
!               **      F = (-X3DEYE*X3DEYE - Y3DEYE*Y3DEYE) / (X3DEYE*Z3DEYE)
!               **
!               **  IN SUMMARY, THE DIRECTION NUMBERS FOR THE 3 NEW AXES
!               **  MAY BE WRITTEN AS
!               **      NEW X AXIS:  Y3DEYE       -X3DEYE     0
!               **      NEW Y AXIS:  X3DEYE       Y3DEYE      Z3DEYE
!               **      NEW Z AXIS:  -X3DEYE*Z3DEYE   -Y3DEYE*Z3DEYE
!               **                                        X3DEYE*X3DEYE+Y3DEYE
!               **  NOTE THAT BY INSPECTION WE SEE RETROSPECTIVELY
!               **  THAT THE 3 INNER PRODUCTS ALL = 0
!               **  AND SO THE 3 DEFINED AXES ARE ALL PERPENDICULAR
!               **  (AS THEY SHOULD BE).
!               **
!               **  THE CORRESPONDING DIRECTION COSINES
!               **  ARE GOTTEN BY NORMALIZATION TO UNITY;
!               **  LET US SYMBOLICALLY REPRESENT THEM BY--
!               **      D3DCXX   D3DCXY   D3DCXZ
!               **      D3DCYX   D3DCYY   D3DCYZ
!               **      D3DCZX   D3DCZY   D3DCZZ
!               **  THE ABOVE RESULTS WERE ACTUALLY ARRIVED AT
!               **  (AND ARE VALID FOR) BY DISPLACING THE OLD ORIGIN
!               **  FROM (0,0,0) TO (XM,YM,ZM).
!               **  THIS SIMPLIFIES THE EQUATIONS CONSIDERABLY.
!               **
!               **  GIVEN THAT WE NOW HAVE THE DIRECTION COSINES
!               **  OF THE NEW AXES IN TERMS OF THE OLD COORDINATES,
!               **  WE MAKE USE OF
!               **  EISENHART (COORDINATE GEOMETRY, PAGE 160) WHICH STATES
!               **  THAT THE LINEAR TRANSFORMATION THAT IS NEEDED TO CARRY OUT
!               **  THE ROTATION FROM THE VISUAL PLANE TO THE XZ PLANE
!               **  IS GIVEN BY
!               **      XT = XM + D3DCXX(X-XM) + D3DCXY(Y-YM) + D3DCXZ(Z-ZM)
!               **      YT = YM + D3DCYX(X-XM) + D3DCYY(Y-YM) + D3DCYZ(Z-ZM)
!               **      ZT = ZM + D3DCZX(X-XM) + D3DCZY(Y-YM) + D3DCZZ(Z-ZM)
!               **
!               **  NOTE THAT BY INSPECTION OF THE ABOVE TRANSFORMATION
!               **  IT IS SEEN THAT (XM,YM,ZM) IS MAPPED INTO (XM,YM,ZM)
!               **  (AS IT SHOULD BE).
!               **  NOTE ALSO THAT THE EYE POINT AND ANY POINT ALONG THE LINE
!               **  OF SIGHT WOULD HAVE BEEN MAPPED INTO (XM,YM,ZM)
!               **  AS IT SHOULD BE.
!               **  NOTE ALSO THAT ALL POINTS ON THE VISUAL PLANE
!               **  SINCE THEY SATISFY
!               **     (X3DEYE-XM)(X-XM) + (Y3DEYE-YM)(Y-YM) + (Z3DEYE-ZM)(Z-ZM)
!               **     = 0
!               **  GETS MAPPED INTO THE CONSTANT YT VALUE OF YT = YM
!               **  AND SO THE TRANSFORMED PLOT SURFACE IS ONE WHICH
!               **  IS PARALLEL TO THE XZ PLANE BUT IS DISPLACED
!               **  YM UNITS OUT FROM THE XZ PLANE.
!               **  THIS PLOT PLANE WILL CONTAIN THE POINT (XM,YM,ZM).
!               ****************************************************************
!
!               **************************************************
!               **  STEP 11--                                   **
!               **  BRANCH TO THE APPROPRIATE                   **
!               **  TRANSFORMATION                              **
!               **************************************************
!
      ISTEPN='11'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NT=N
!
      XDEL=X3DEYE-X3DMID
      IF(XDEL.EQ.0.0)XDEL=EPS
      YDEL=Y3DEYE-Y3DMID
      IF(YDEL.EQ.0.0)YDEL=EPS
      ZDEL=Z3DEYE-Z3DMID
      IF(ZDEL.EQ.0.0)ZDEL=EPS
!
      IF(I3DPRO.EQ.'ORTH')GO TO 2100
      GO TO 3100
!
!               **************************************************
!               **  STEP 21--                                   **
!               **  TREAT THE ORTHOGRAPHIC TRANSFORMATION CASE  **
!               **************************************************
!
 2100 CONTINUE
!
      ISTEPN='21'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     THE FOLLOWING IS INCORRECT (XM FOR X(I) ETC.)
!CCCC MAY 1996.  NP12 IS UNDEFINED.  USE NT.
!CCCC DO2110I=1,NP12
      DO 2110 I=1,NT
!
!     ***** 5 LINES OF CODE TO ADJUST FOR DIVISION BY 0 ADDED AUGUST 1983 *****
!CCCC A11=XDEL
!CCCC A12=YDEL
!CCCC A13=ZDEL
!CCCC A23=Y3DEYE-Y3DMID
!CCCC IF(A23.EQ.0.0)A21=EPS
!CCCC A23=-(X3DEYE-X3DMID)
!CCCC IF(A23.EQ.0.0)A22=EPS
!CCCC A23=0.0
!CCCC A31=0.0
!CCCC A32=Z3DEYE-Z3DMID
!CCCC IF(A32.EQ.0.0)A32=EPS
!CCCC A33=-(Y3DEYE-Y3DMID)
!CCCC IF(A33.EQ.0.0)A33=EPS
!
!CCCC R1=XDEL*X3DMID+YDEL*Y3DMID+ZDEL*Z3DMID
!CCCC R2=(Y3DEYE-Y3DMID)*X3DMID-(X3DEYE-X3DMID)*YM
!CCCC R3=(Z3DEYE-Z3DMID)*Y3DMID-(Y3DEYE-Y3DMID)*Z3DMID
!
!CCCC P12=-A23/A11
!CCCC P13=-A32/(P12*A12+A23)
!
!CCCC ZPI=(P13*(P12*R1+R2)+R3)/
!CCCC1(P13*P12*A13+A33)
!CCCC YPI=(R3-A33*ZPI)/A32
!CCCC XPI=(R2-A23*YPI)/A21
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')
!CCCC1WRITE(ICOUT,2111)I,XPI,YPI,ZPI
!2111 FORMAT('I,XPI,YPI,ZPI = ',I8,3E15.7)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')
!CCCC1CALL DPWRST('XXX','BUG ')
!
!CCCC DELX=XPI-X3DMID
!CCCC DELY=YPI-Y3DMID
!CCCC DELZ=ZPI-Z3DMID
!CCCC XT(I)=X3DMID+D3DCXX*DELX+D3DCXY*DELY+D3DCXZ*DELZ
!CCCC YT(I)=Y3DMID+D3DCYX*DELX+D3DCYY*DELY+D3DCYZ*DELZ
!CCCC ZT(I)=X3DMID+D3DCZX*DELX+D3DCZY*DELY+D3DCZZ*DELZ
      DELX=X(I)-X3DMID
      DELY=Y(I)-Y3DMID
      DELZ=Z(I)-Z3DMID
      XT(I)=X3DMID+TERMXX*DELX+TERMXY*DELY+TERMXZ*DELZ
      ZT(I)=X3DMID+TERMZX*DELX+TERMZY*DELY+TERMZZ*DELZ
!
 2110 CONTINUE
      GO TO 9000
!
!               **************************************************
!               **  STEP 31--                                   **
!               **  TREAT THE PERSPECTIVE TRANSFORMATION CASE   **
!               **************************************************
!
 3100 CONTINUE
!
      ISTEPN='31'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 3110 I=1,N
!
!     ***** 5 LINES OF CODE TO ADJUST FOR DIVISION BY 0 ADDED AUGUST 1983 *****
      A11=XDEL
      A12=YDEL
      A13=ZDEL
      A21=Y3DEYE-Y(I)
      IF(A21.EQ.0.0)A21=EPS
      A22=-(X3DEYE-X(I))
      IF(A22.EQ.0.0)A22=EPS
      A23=0.0
      A31=0.0
      A32=Z3DEYE-Z(I)
      IF(A32.EQ.0.0)A32=EPS
      A33=-(Y3DEYE-Y(I))
      IF(A33.EQ.0.0)A33=EPS
!
      R1=XDEL*X3DMID+YDEL*Y3DMID+ZDEL*Z3DMID
      R2=(Y3DEYE-Y(I))*X(I)-(X3DEYE-X(I))*Y(I)
      R3=(Z3DEYE-Z(I))*Y(I)-(Y3DEYE-Y(I))*Z(I)
!
      P12=-A21/A11
      P13=-A32/(P12*A12+A22)
!
      ZPI=(P13*(P12*R1+R2)+R3)/   &
      (P13*P12*A13+A33)
      YPI=(R3-A33*ZPI)/A32
      XPI=(R2-A22*YPI)/A21
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')   &
      WRITE(ICOUT,3111)I,XPI,YPI,ZPI
 3111 FORMAT('I,XPI,YPI,ZPI = ',I8,3E15.7)
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'TR32')   &
      CALL DPWRST('XXX','BUG ')
!
      DELX=XPI-X3DMID
      DELY=YPI-Y3DMID
      DELZ=ZPI-Z3DMID
      XT(I)=X3DMID+D3DCXX*DELX+D3DCXY*DELY+D3DCXZ*DELZ
!CCCC YT(I)=Y3DMID+D3DCYX*DELX+D3DCYY*DELY+D3DCYZ*DELZ
      ZT(I)=X3DMID+D3DCZX*DELX+D3DCZY*DELY+D3DCZZ*DELZ
!
 3110 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TR32')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3TR32--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)I3DPRO
 9013 FORMAT('I3DPRO = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IBUGG4,ISUBG4,IERRG4
 9014 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)X3DEYE,Y3DEYE,Z3DEYE
 9015 FORMAT('X3DEYE,Y3DEYE,Z3DEYE = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)X3DMID,Y3DMID,Z3DMID
 9016 FORMAT('X3DMID,Y3DMID,Z3DMID = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9024)D3DCXX,D3DCXY,D3DCXZ
 9024 FORMAT('D3DCXX,D3DCXY,D3DCXZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9025)D3DCYX,D3DCYY,D3DCYZ
 9025 FORMAT('D3DCYX,D3DCYY,D3DCYZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9026)D3DCZX,D3DCZY,D3DCZZ
 9026 FORMAT('D3DCZX,D3DCZY,D3DCZZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)XDEL,YDEL,ZDEL
 9031 FORMAT('XDEL,YDEL,ZDEL = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)A11,A12,A13
 9032 FORMAT('A11,A12,A13    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9033)A21,A22,A23
 9033 FORMAT('A21,A22,A23    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9034)A31,A32,A33
 9034 FORMAT('A31,A32,A33    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9035)R1,R2,R3
 9035 FORMAT('R1,R2,R3       = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9036)P12,P13
 9036 FORMAT('P12,P13        = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9037)XPI,YPI,ZPI
 9037 FORMAT('XPI,YPI,ZPI    = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9038)DELX,DELY,DELZ
 9038 FORMAT('DELX,DELY,DELZ = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9039)XT(N),ZT(N)
 9039 FORMAT('XT(N),ZT(N)    = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)N,NT
 9041 FORMAT('N,NT = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9042 I=1,N
      WRITE(ICOUT,9043)I,X(I),Y(I),Z(I),XT(I),ZT(I)
 9043 FORMAT('I,X(I),Y(I),Z(I),XT(I),ZT(I) = ',I8,5E11.3)
      CALL DPWRST('XXX','BUG ')
 9042 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3TR32
      SUBROUTINE D3TRXP(X,Y,N,IDIR,ABASE,   &
      FXMIN,FXMAX,FXRANG,FYMIN,FYMAX,FYRANG,   &
      PXMIN,PXMAX,PXRANG,PYMIN,PYMAX,PYRANG,   &
      PX,PY,NP,PBASE)
!
!     PURPOSE--TRANSLATE 2-D RAW OR INTERMEDIATE DATA
!              INTO 2-D VISUAL PLANE (0 TO 100) DATA
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--SEPTEMBER 1988.
!
!-----COMMON STATEMENTS-----------------------------------------------
!
      INCLUDE 'DPCO3D.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDIR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION PX(*)
      DIMENSION PY(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='D3TR'
      ISUBN2='XP  '
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TRXP')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF D3TRXP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG4,ISUBG4,IERRG4
   52 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)FXMIN,FXMAX,FXRANG
   53 FORMAT('FXMIN,FXMAX,FXRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)FYMIN,FYMAX,FYRANG
   54 FORMAT('FYMIN,FYMAX,FYRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)PXMIN,PXMAX,PXRANG
   55 FORMAT('PXMIN,PXMAX,PXRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)PYMIN,PYMAX,PYRANG
   56 FORMAT('PYMIN,PYMAX,PYRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,57)ABASE
   57 FORMAT('ABASE = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)N,IDIR
   61 FORMAT('N,IDIR = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 62 I=1,N
      WRITE(ICOUT,63)I,X(I),Y(I)
   63 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   62 CONTINUE
   90 CONTINUE
!
!               *****************************************************
!               **  STEP 11--                                      **
!               **  TRANSLATE THE 2-D PLANE DATA POINTS            **
!               **  INTO STANDARDIZED (0.0 TO 100.0) COORDINATES.  **
!               *****************************************************
!
      NP=N
!
      DO 1110 I=1,N
      FXRATI=(X(I)-FXMIN)/FXRANG
      FYRATI=(Y(I)-FYMIN)/FYRANG
      PX(I)=PXMIN+FXRATI*PXRANG
      PY(I)=PYMIN+FYRATI*PYRANG
 1110 CONTINUE
!
      IF(IDIR.EQ.'V')GO TO 1120
      GO TO 1129
 1120 CONTINUE
      FYRATI=(ABASE-FYMIN)/FYRANG
      PBASE=PYMIN+FYRATI*PYRANG
 1129 CONTINUE
!
      IF(IDIR.EQ.'H')GO TO 1130
      GO TO 1139
 1130 CONTINUE
      FXRATI=(ABASE-FXMIN)/FXRANG
      PBASE=PXMIN+FXRATI*PXRANG
 1139 CONTINUE
!
!               **************************************************
!               **  STEP 90--                                   **
!               **  EXIT.                                       **
!               **************************************************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TRXP')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF D3TRXP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)FXMIN,FXMAX,FXRANG
 9013 FORMAT('FXMIN,FXMAX,FXRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)FYMIN,FYMAX,FYRANG
 9014 FORMAT('FYMIN,FYMAX,FYRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PXMIN,PXMAX,PXRANG
 9015 FORMAT('PXMIN,PXMAX,PXRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)PYMIN,PYMAX,PYRANG
 9016 FORMAT('PYMIN,PYMAX,PYRANG = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)ABASE
 9017 FORMAT('ABASE = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)N,NP,IDIR
 9021 FORMAT('N,NP,IDIR = ',2I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,N
      WRITE(ICOUT,9023)I,X(I),Y(I),PX(I),PY(I)
 9023 FORMAT('I,X(I),Y(I),PX(I),PY(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE D3TRXP
      FUNCTION E1 (X)
!***BEGIN PROLOGUE  E1
!***PURPOSE  Compute the exponential integral E1(X).
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C5
!***TYPE      SINGLE PRECISION (E1-S, DE1-D)
!***KEYWORDS  E1 FUNCTION, EXPONENTIAL INTEGRAL, FNLIB,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! E1 calculates the single precision exponential integral, E1(X), for
! positive single precision argument X and the Cauchy principal value
! for negative X.  If principal values are used everywhere, then, for
! all X,
!
!    E1(X) = -Ei(-X)
! or
!    Ei(X) = -E1(-X).
!
!
! Series for AE11       on the interval -1.00000D-01 to  0.
!                                        with weighted error   1.76E-17
!                                         log weighted error  16.75
!                               significant figures required  15.70
!                                    decimal places required  17.55
!
!
! Series for AE12       on the interval -2.50000D-01 to -1.00000D-01
!                                        with weighted error   5.83E-17
!                                         log weighted error  16.23
!                               significant figures required  15.76
!                                    decimal places required  16.93
!
!
! Series for E11        on the interval -4.00000D+00 to -1.00000D+00
!                                        with weighted error   1.08E-18
!                                         log weighted error  17.97
!                               significant figures required  19.02
!                                    decimal places required  18.61
!
!
! Series for E12        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   3.15E-18
!                                         log weighted error  17.50
!                        approx significant figures required  15.8
!                                    decimal places required  18.10
!
!
! Series for AE13       on the interval  2.50000D-01 to  1.00000D+00
!                                        with weighted error   2.34E-17
!                                         log weighted error  16.63
!                               significant figures required  16.14
!                                    decimal places required  17.33
!
!
! Series for AE14       on the interval  0.          to  2.50000D-01
!                                        with weighted error   5.41E-17
!                                         log weighted error  16.27
!                               significant figures required  15.38
!                                    decimal places required  16.97
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CSEVL, INITS, R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770701  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891115  Modified prologue description.  (WRB)
!   891115  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
