      DATA AE13CS( 8) /   -.000001885368984916E0 /
      DATA AE13CS( 9) /    .000000374943193568E0 /
      DATA AE13CS(10) /   -.000000076823455870E0 /
      DATA AE13CS(11) /    .000000016143270567E0 /
