      DATA AE13CS(13) /    .000000000758754209E0 /
      DATA AE13CS(14) /   -.000000000168864333E0 /
      DATA AE13CS(15) /    .000000000038145706E0 /
      DATA AE13CS(16) /   -.000000000008733026E0 /
      DATA AE13CS(17) /    .000000000002023672E0 /
      DATA AE13CS(18) /   -.000000000000474132E0 /
      DATA AE13CS(19) /    .000000000000112211E0 /
      DATA AE13CS(20) /   -.000000000000026804E0 /
      DATA AE13CS(21) /    .000000000000006457E0 /
      DATA AE13CS(22) /   -.000000000000001568E0 /
      DATA AE13CS(23) /    .000000000000000383E0 /
      DATA AE13CS(24) /   -.000000000000000094E0 /
      DATA AE13CS(25) /    .000000000000000023E0 /
      DATA AE14CS( 1) /   -.1892918000753017E0 /
      DATA AE14CS( 2) /   -.08648117855259871E0 /
      DATA AE14CS( 3) /    .00722410154374659E0 /
      DATA AE14CS( 4) /   -.00080975594575573E0 /
      DATA AE14CS( 5) /    .00010999134432661E0 /
      DATA AE14CS( 6) /   -.00001717332998937E0 /
      DATA AE14CS( 7) /    .00000298562751447E0 /
      DATA AE14CS( 8) /   -.00000056596491457E0 /
      DATA AE14CS( 9) /    .00000011526808397E0 /
      DATA AE14CS(10) /   -.00000002495030440E0 /
      DATA AE14CS(11) /    .00000000569232420E0 /
      DATA AE14CS(12) /   -.00000000135995766E0 /
      DATA AE14CS(13) /    .00000000033846628E0 /
      DATA AE14CS(14) /   -.00000000008737853E0 /
      DATA AE14CS(15) /    .00000000002331588E0 /
      DATA AE14CS(16) /   -.00000000000641148E0 /
      DATA AE14CS(17) /    .00000000000181224E0 /
      DATA AE14CS(18) /   -.00000000000052538E0 /
      DATA AE14CS(19) /    .00000000000015592E0 /
      DATA AE14CS(20) /   -.00000000000004729E0 /
      DATA AE14CS(21) /    .00000000000001463E0 /
      DATA AE14CS(22) /   -.00000000000000461E0 /
      DATA AE14CS(23) /    .00000000000000148E0 /
      DATA AE14CS(24) /   -.00000000000000048E0 /
      DATA AE14CS(25) /    .00000000000000016E0 /
      DATA AE14CS(26) /   -.00000000000000005E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  E1
      IF (FIRST) THEN
         ETA = 0.1*R1MACH(3)
         NTAE11 = INITS (AE11CS, 39, ETA)
         NTAE12 = INITS (AE12CS, 25, ETA)
         NTE11 = INITS (E11CS, 19, ETA)
         NTE12 = INITS (E12CS, 16, ETA)
         NTAE13 = INITS (AE13CS, 25, ETA)
         NTAE14 = INITS (AE14CS, 26, ETA)
!
         XMAXT = -LOG (R1MACH(1))
         XMAX = XMAXT - LOG(XMAXT)
      ENDIF
      FIRST = .FALSE.
!
      IF (X.GT.(-10.)) GO TO 20
!
! E1(X) = -EI(-X) FOR X .LE. -10.
!
      E1 = EXP(-X)/X * (1.+CSEVL (20./X+1., AE11CS, NTAE11))
      RETURN
!
 20   IF (X.GT.(-4.0)) GO TO 30
!
! E1(X) = -EI(-X) FOR -10. .LT. X .LE. -4.
!
      E1 = EXP(-X)/X * (1.+CSEVL ((40./X+7.)/3., AE12CS, NTAE12))
      RETURN
!
 30   IF (X.GT.(-1.0)) GO TO 40
!
! E1(X) = -EI(-X) FOR -4. .LT. X .LE. -1.
!
      E1 = -LOG(ABS(X)) + CSEVL ((2.*X+5.)/3., E11CS, NTE11)
      RETURN
!
 40   IF (X.GT.1.) GO TO 50
      IF (X .EQ. 0.) THEN
        WRITE(ICOUT,41)
   41   FORMAT('***** ERORR FROM E1, X IS ZER0.  *******')
        CALL DPWRST('XXX','BUG ')
        E1=0.0
        RETURN
      ENDIF
!
! E1(X) = -EI(-X) FOR -1. .LT. X .LE. 1.,  X .NE. 0.
!
      E1 = (-LOG(ABS(X)) - 0.6875 + X) + CSEVL (X, E12CS, NTE12)
      RETURN
!
 50   IF (X.GT.4.) GO TO 60
!
! E1(X) = -EI(-X) FOR 1. .LT. X .LE. 4.
!
      E1 = EXP(-X)/X * (1.+CSEVL ((8./X-5.)/3., AE13CS, NTAE13))
      RETURN
!
 60   IF (X.GT.XMAX) GO TO 70
!
! E1(X) = -EI(-X) FOR 4. .LT. X .LE. XMAX
!
      E1 = EXP(-X)/X * (1. + CSEVL (8./X-1., AE14CS, NTAE14))
      RETURN
!
! E1(X) = -EI(-X) FOR X .GT. XMAX
!
 70   CONTINUE
      WRITE(ICOUT,71)
      CALL DPWRST('XXX','BUG ')
   71 FORMAT('***** WARNING FROM E1, UNDERFLOW BECAUSE THE ',   &
             'VALUE OF X IS SO LARGE.  ****')
      E1 = 0.
      RETURN
!
      END FUNCTION E1 
      SUBROUTINE EA(NEWFLG,SVALUE,LIMEXP,RESULT,ABSERR,EPSTAB,IERR)
!   PART OF QAGI CODE.
!***BEGIN PROLOGUE  EA
!***DATE WRITTEN   800101  (YYMMDD)
!***REVISION DATE  871208   (YYMMDD)
!***CATEGORY NO.  E5
!***KEYWORDS  CONVERGENCE ACCELERATION,EPSILON ALGORITHM,EXTRAPOLATION
!***AUTHOR  PIESSENS, ROBERT, APPLIED MATH. AND PROGR. DIV. -
!             K. U. LEUVEN
!           DE DONCKER-KAPENGA, ELISE,WESTERN MICHIGAN UNIVERSITY
!           KAHANER, DAVID K., NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!           STARKENBURG, C. B., NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!***PURPOSE  Given a slowly convergent sequence, this routine attempts
!            to extrapolate nonlinearly to a better estimate of the
!            sequence's limiting value, thus improving the rate of
!            convergence. Routine is based on the epsilon algorithm
!            of P. Wynn. An estimate of the absolute error is also
!            given.
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  EA
      REAL ABSERR,DELTA1,DELTA2,DELTA3,EPRN,EPSTAB(*),   &
         ERROR,ERR1,ERR2,ERR3,E0,E1,E2,E3,RELPR,RES,RESULT,   &
         RES3LA(3),R1MACH,SS,SVALUE,TOL1,TOL2,TOL3
      INTEGER I,IB,IB2,IE,IERR,IN,K1,K2,K3,LIMEXP,N,NEWELM,NUM,NRES
      LOGICAL NEWFLG
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  EA
      IF(LIMEXP.LT.3) THEN
        IERR = 1
!CCCC   CALL XERROR('LIMEXP IS LESS THAN 3',21,1,1)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,901)
  901   FORMAT('***** ERROR--NUMERICAL INTEGRATION ROUTINE EA (CALLED ',   &
               'BY QAGI ROUTINE).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,903)
  903   FORMAT('      LIMEXP IS LESS THAN 3.')
        CALL DPWRST('XXX','BUG ')
        GO TO 110
      ENDIF
      IERR = 0
      RES3LA(1)=EPSTAB(LIMEXP+5)
      RES3LA(2)=EPSTAB(LIMEXP+6)
      RES3LA(3)=EPSTAB(LIMEXP+7)
      RESULT=SVALUE
      IF(NEWFLG) THEN
        N=1
        NRES=0
        NEWFLG=.FALSE.
        EPSTAB(N)=SVALUE
        ABSERR=ABS(RESULT)
        GO TO 100
      ELSE
        N=INT(EPSTAB(LIMEXP+3))
        NRES=INT(EPSTAB(LIMEXP+4))
        IF(N.EQ.2) THEN
          EPSTAB(N)=SVALUE
          ABSERR=.6E+01*ABS(RESULT-EPSTAB(1))
          GO TO 100
        ENDIF
      ENDIF
      EPSTAB(N)=SVALUE
      RELPR=R1MACH(4)
      EPRN=1.0E+01*RELPR
      EPSTAB(N+2)=EPSTAB(N)
      NEWELM=(N-1)/2
      NUM=N
      K1=N
      DO 40 I=1,NEWELM
        K2=K1-1
        K3=K1-2
        RES=EPSTAB(K1+2)
        E0=EPSTAB(K3)
        E1=EPSTAB(K2)
        E2=RES
        DELTA2=E2-E1
        ERR2=ABS(DELTA2)
        TOL2=MAX(ABS(E2),ABS(E1))*RELPR
        DELTA3=E1-E0
        ERR3=ABS(DELTA3)
        TOL3=MAX(ABS(E1),ABS(E0))*RELPR
        IF(ERR2.GT.TOL2.OR.ERR3.GT.TOL3) GO TO 10
!
!           IF E0, E1 AND E2 ARE EQUAL TO WITHIN MACHINE
!           ACCURACY, CONVERGENCE IS ASSUMED.
!           RESULT=E2
!           ABSERR=ABS(E1-E0)+ABS(E2-E1)
!
        RESULT=RES
        ABSERR=ERR2+ERR3
        GO TO 50
   10   IF(I.NE.1) THEN
          E3=EPSTAB(K1)
          EPSTAB(K1)=E1
          DELTA1=E1-E3
          ERR1=ABS(DELTA1)
          TOL1=MAX(ABS(E1),ABS(E3))*RELPR
!
!           IF TWO ELEMENTS ARE VERY CLOSE TO EACH OTHER, OMIT
!           A PART OF THE TABLE BY ADJUSTING THE VALUE OF N
!
          IF(ERR1.LE.TOL1.OR.ERR2.LE.TOL2.OR.ERR3.LE.TOL3) GO TO 20
          SS=0.1E+01/DELTA1+0.1E+01/DELTA2-0.1E+01/DELTA3
        ELSE
          EPSTAB(K1)=E1
          IF(ERR2.LE.TOL2.OR.ERR3.LE.TOL3) GO TO 20
          SS=0.1E+01/DELTA2-0.1E+01/DELTA3
        ENDIF
!
!           TEST TO DETECT IRREGULAR BEHAVIOUR IN THE TABLE, AND
!           EVENTUALLY OMIT A PART OF THE TABLE ADJUSTING THE VALUE
!           OF N
!
        IF(ABS(SS*E1).GT.0.1E-03) GO TO 30
   20   N=I+I-1
        IF(NRES.EQ.0) THEN
          ABSERR=ERR2+ERR3
          RESULT=RES
        ELSE IF(NRES.EQ.1) THEN
          RESULT=RES3LA(1)
        ELSE IF(NRES.EQ.2) THEN
          RESULT=RES3LA(2)
        ELSE
          RESULT=RES3LA(3)
        ENDIF
        GO TO 50
!
!           COMPUTE A NEW ELEMENT AND EVENTUALLY ADJUST
!           THE VALUE OF RESULT
!
   30   RES=E1+0.1E+01/SS
        EPSTAB(K1)=RES
        K1=K1-2
        IF(NRES.EQ.0) THEN
          ABSERR=ERR2+ABS(RES-E2)+ERR3
          RESULT=RES
          GO TO 40
        ELSE IF(NRES.EQ.1) THEN
          ERROR=.6E+01*(ABS(RES-RES3LA(1)))
        ELSE IF(NRES.EQ.2) THEN
          ERROR=.2E+01*(ABS(RES-RES3LA(2))+ABS(RES-RES3LA(1)))
        ELSE
          ERROR=ABS(RES-RES3LA(3))+ABS(RES-RES3LA(2))   &
                +ABS(RES-RES3LA(1))
        ENDIF
        IF(ERROR.GT.1.0E+01*ABSERR) GO TO 40
        ABSERR=ERROR
        RESULT=RES
   40 CONTINUE
!
!           COMPUTE ERROR ESTIMATE
!
        IF(NRES.EQ.1) THEN
          ABSERR=.6E+01*(ABS(RESULT-RES3LA(1)))
        ELSE IF(NRES.EQ.2) THEN
          ABSERR=.2E+01*ABS(RESULT-RES3LA(2))+ABS(RESULT-RES3LA(1))
        ELSE IF(NRES.GT.2) THEN
          ABSERR=ABS(RESULT-RES3LA(3))+ABS(RESULT-RES3LA(2))   &
                +ABS(RESULT-RES3LA(1))
        ENDIF
!
!           SHIFT THE TABLE
!
   50 IF(N.EQ.LIMEXP) N=2*(LIMEXP/2)-1
      IB=1
      IF((NUM/2)*2.EQ.NUM) IB=2
      IE=NEWELM+1
      DO 60 I=1,IE
        IB2=IB+2
        EPSTAB(IB)=EPSTAB(IB2)
        IB=IB2
   60 CONTINUE
      IF(NUM.EQ.N) GO TO 80
      IN=NUM-N+1
      DO 70 I=1,N
        EPSTAB(I)=EPSTAB(IN)
        IN=IN+1
   70 CONTINUE
!
!           UPDATE RES3LA
!
   80 IF(NRES.EQ.0) THEN
        RES3LA(1)=RESULT
      ELSE IF(NRES.EQ.1) THEN
        RES3LA(2)=RESULT
      ELSE IF(NRES.EQ.2) THEN
        RES3LA(3)=RESULT
      ELSE
        RES3LA(1)=RES3LA(2)
        RES3LA(2)=RES3LA(3)
        RES3LA(3)=RESULT
      ENDIF
      ABSERR=MAX(ABSERR,EPRN*ABS(RESULT))
      NRES=NRES+1
  100 N=N+1
!     IF(N.LE.3) ABSERR = R1MACH(2) * (0.1D-03)
      EPSTAB(LIMEXP+3)=REAL(N)
      EPSTAB(LIMEXP+4)=REAL(NRES)
      EPSTAB(LIMEXP+5)=RES3LA(1)
      EPSTAB(LIMEXP+6)=RES3LA(2)
      EPSTAB(LIMEXP+7)=RES3LA(3)
  110 RETURN
      END SUBROUTINE EA
      FUNCTION EI (X)
!***BEGIN PROLOGUE  EI
!***PURPOSE  Compute the exponential integral Ei(X).
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C5
!***TYPE      SINGLE PRECISION (EI-S, DEI-D)
!***KEYWORDS  EI FUNCTION, EXPONENTIAL INTEGRAL, FNLIB,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! EI calculates the single precision exponential integral, Ei(X), for
! positive single precision argument X and the Cauchy principal value
! for negative X.  If principal values are used everywhere, then, for
! all X,
!
!    Ei(X) = -E1(-X)
! or
!    E1(X) = -Ei(-X).
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  E1
!***REVISION HISTORY  (YYMMDD)
!   770401  DATE WRITTEN
!   891115  Modified prologue description.  (WRB)
!   891115  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!***END PROLOGUE  EI
!***FIRST EXECUTABLE STATEMENT  EI
      EI = -E1(-X)
!
      RETURN
      END FUNCTION EI 
      SUBROUTINE EDGEF (NK,FC,GC,XX,YY,BFK,CDFX,POI,POJ,EPS3,IFLAG,L)
!
!--- COMPUTE THE BETA C.D.F.'S BY A RECURRENCE RELATION ALONG THE EDGES
!--- I = IMIN AND J = JMIN OF A GRID.  THE CORRESPONDING COMPONENTS OF
!--- THE F" C.D.F. ARE INCLUDED IN THE SUMMATION.  TERMS WHICH MIGHT
!--- CAUSE UNDERFLOW ARE SET TO ZERO.
!
      DIMENSION BFK(*),POI(*),POJ(*)
      DOUBLE PRECISION DARG,DEUFLO,DLNGAM
      DATA DEUFLO / -30.0D0 /
      EPS3=0.000001
      IFLAG=0
      FD = FC-1.0
      K = MAX0(L,MIN0(NK,INT((GC-1.0)*XX/YY-FD)))
      FK = FD+REAL(K)
!CCCC CALL CDFBET (XX,FK,GC,EPS3,IFLAG,BFK(K))
      CALL BETCDF(XX,FK,GC,BFK(K))
!CCCC IF (IFLAG.NE.0) RETURN
      IF (L.EQ.1) BFK(K) = 1.0-BFK(K)
      IF (NK.EQ.1) GO TO 40
      DARG = DBLE(FK)*DLOG(DBLE(XX))+DBLE(GC)*DLOG(DBLE(YY))-   &
         DLOG(DBLE(FK))+DLNGAM(DBLE(FK+GC))-DLNGAM(DBLE(FK))-   &
         DLNGAM(DBLE(GC))
      IF (DARG.LT.DEUFLO) THEN
         DK = 0.0
      ELSE
         DK = SNGL(DEXP(DARG))*(-1.0)**L
      ENDIF
      IF (K.GE.NK) GO TO 20
      BFK(K+1) = BFK(K)-DK
      DI = DK
      KFLAG = 1
      DO 10 I = K+1, NK-1
         IF (KFLAG.EQ.1) THEN
            DI = DI*(FD+GC+REAL(I-1))*XX/(FD+REAL(I))
            IF (DK+DI.EQ.DK) THEN
               KFLAG = 0
               DI = 0.0
            ENDIF
         ENDIF
         BFK(I+1) = BFK(I)-DI
   10 CONTINUE
   20 DI = DK
      KFLAG = 1
      DO 30 I = K-1, L, -1
         IF (KFLAG.EQ.1) THEN
            DI = DI*(FC+REAL(I))/((FD+GC+REAL(I))*XX)
            IF (DK+DI.EQ.DK) THEN
               KFLAG = 0
               DI = 0.0
            ENDIF
         ENDIF
         BFK(I) = BFK(I+1)+DI
   30 CONTINUE
   40 DO 50 I = L, NK
         CDFX = CDFX+POI(I)*POJ(1)*BFK(I)
   50 CONTINUE
      RETURN
      END SUBROUTINE EDGEF 
      SUBROUTINE EDGET(NK,FC,GC,XX,YY,BFK,CDFX,POI,POJ,EPS3,IFLAG,L)
!CCCC CONVERT TO DOUBLE PRECISION.  SINGLE PRECISION GIVES INACCURATE
!CCCC RESULTS FOR 32-BIT MACHINES.
!
!--- COMPUTE THE BETA C.D.F.'S BY A RECURRENCE RELATION ALONG THE EDGES
!--- I = IMIN AND J = JMIN OF A GRID.  THE CORRESPONDING COMPONENTS OF
!--- THE T" C.D.F. ARE INCLUDED IN THE SUMMATION.  TERMS WHICH MIGHT
!--- CAUSE UNDERFLOW ARE SET TO ZERO.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      DIMENSION BFK(*),POI(*),POJ(*)
!CCCC DOUBLE PRECISION DARG,DEUFLO,DLNGAM
      DATA DEUFLO / -69.0D0 /
!
      EPS3=0.0
!
      FD = FC-1.0D0
      K = MAX0(L,MIN0(NK,INT((GC-1.0D0)*XX/YY-FD)))
      FK = FD+DBLE(K)
!CCCC CALL BETCDF(SNGL(XX),SNGL(FK),SNGL(GC),ATEMP)
      BFK(K)=DBETAI(XX,FK,GC)
!
      IF (IFLAG.NE.0) RETURN
      IF (L.EQ.1) BFK(K) = 1.0D0-BFK(K)
      IF (NK.EQ.1) GO TO 40
      DARG = FK*DLOG(XX)+GC*DLOG(YY)-   &
         DLOG(FK)+DLNGAM(FK+GC)-DLNGAM(FK)-   &
         DLNGAM(GC)
      IF (DARG.LT.DEUFLO) THEN
         DK = 0.0D0
      ELSE
         DK = DEXP(DARG)*(-1.0D0)**L
      ENDIF
      IF (K.GE.NK) GO TO 20
      BFK(K+1) = BFK(K)-DK
      DI = DK
      KFLAG = 1
      DO 10 I = K+1, NK-1
         IF (KFLAG.EQ.1) THEN
            DI = DI*(FD+GC+DBLE(I-1))*XX/(FD+DBLE(I))
            IF (DK+DI.EQ.DK) THEN
               KFLAG = 0
               DI = 0.0D0
            ENDIF
         ENDIF
         BFK(I+1) = BFK(I)-DI
   10 CONTINUE
   20 DI = DK
      KFLAG = 1
      DO 30 I = K-1, L, -1
         IF (KFLAG.EQ.1) THEN
            DI = DI*(FC+DBLE(I))/((FD+GC+DBLE(I))*XX)
            IF (DK+DI.EQ.DK) THEN
               KFLAG = 0
               DI = 0.0D0
            ENDIF
         ENDIF
         BFK(I) = BFK(I+1)+DI
   30 CONTINUE
   40 DO 50 I = L, NK
         CDFX = CDFX+POI(I)*POJ(1)*BFK(I)
   50 CONTINUE
      RETURN
      END SUBROUTINE EDGET
      SUBROUTINE EDGVER(EDGE1,EDGE2,NEDGE,Y,X,NVERT,IWRITE,   &
      Y2,X2,TAG,NOUT,   &
      IBUGA3,IERROR)
!
!     PURPOSE--GIVEN A LIST OF EDGES AND A SET OF ORIGINAL
!              VERTICES, GENERATE A NEW LIST OF VERTICES
!              CORRESPONDING TO THE EDGES.  NOTE THAT A
!              NUMBER OF COMBINATORIC/COMPUTATIONAL GEOMETRY
!              ALGORITHMS WORK WITH EDGES.  THIS IS A UTILITY
!              ROUTINE THAT MAKES IT EASIER TO PLOT THESE EDGES.
!     EXAMPLES--LET Y2 X2 TAG = EDGES TO VERTICES EDGE1 EDGE2 Y X
!     INPUT  ARGUMENTS--EDGE1  VECTOR IDENTIFYING FIRST VERTEX IN EDGE
!                       EDGE2  VECTOR IDENTIFYING SECOND VERTEX IN EDGE
!                       Y      Y-AXIS VECTOR
!                       X      X-AXIS VECTOR
!                       NEDGE  NUMBER OF EDGES
!                       NVERT  NUMBER OF VERTICES
!     OUTPUT ARGUMENTS--Y2     Y-AXIS VECTOR OF THE NEW VERTICES
!                       X2     X-AXIS VECTOR OF THE NEW VERTICES
!                       TAG    VECTOR IDENTIFYING PAIRS OF VERTICES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL    2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION EDGE1(*)
      DIMENSION EDGE2(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION TAG(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EDGV'
      ISUBN2='ER  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EDGVER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,NEDGE,NVERT
   52   FORMAT('IBUGA3,IWRITE,NEDGE,NVERT = ',A4,2X,A4,2X,2I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NEDGE
          WRITE(ICOUT,56)I,EDGE1(I),EDGE2(I)
   56     FORMAT('I,EDGE1(I),EDGE2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NVERT
          WRITE(ICOUT,66)I,Y(I),X(I)
   66     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1: CHECK THAT VERTICES ARE IN  **
!               **          THE RANGE (1,NVERT)         **
!               ******************************************
!
      DO 100 I=1,NEDGE
        ITEMP1=INT(EDGE1(I)+0.01)
        IF(ITEMP1.LT.1 .OR. ITEMP1.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR FROM EDGES TO VERTICES--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)I
  103     FORMAT('      THE FIRST VERTEX FOR EDGE ',I8,' IS LESS ',   &
                 'THAN ONE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
  105     FORMAT('      OR GREATER THAN THE NUMBER OF VERTICES (',I8,   &
                 ').')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ITEMP2=INT(EDGE2(I)+0.01)
        IF(ITEMP2.LT.1 .OR. ITEMP2.GT.NVERT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)I
  113     FORMAT('      THE SECOND VERTEX FOR EDGE ',I8,' IS LESS THAN')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)NVERT
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
  100 CONTINUE
!
      ICNT1=0
      ICNT2=0
      DO 200 I=1,NEDGE
        ICNT2=ICNT2+1
        ITEMP1=INT(EDGE1(I)+0.01)
        ITEMP2=INT(EDGE2(I)+0.01)
        ICNT1=ICNT1+1
        Y2(ICNT1)=Y(ITEMP1)
        X2(ICNT1)=X(ITEMP1)
        TAG(ICNT1)=REAL(ICNT2)
        ICNT1=ICNT1+1
        Y2(ICNT1)=Y(ITEMP2)
        X2(ICNT1)=X(ITEMP2)
        TAG(ICNT1)=REAL(ICNT2)
  200 CONTINUE
!
      NOUT=ICNT1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF EDGVER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NOUT
 9014   FORMAT('NOUT = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NOUT
          WRITE(ICOUT,9016)I,Y2(I),X2(I),TAG(I)
 9016     FORMAT('I,Y2(I),X2(I),TAG(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EDGVER
      SUBROUTINE EEWCDF(X,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE END-EFFECTS WEIBULL DISTRIBUTION.
!              THIS DISTRIBUTION IS USED IN MODELING FAILURES OF
!              CARBON FIBERS UNDER STRESS.  THE CDF IS DEFINED AS:
!
!              F(X,L,S1,G1,L2,S2,G2) =
!                 1 - EXP[-L*(X/S1)**G1 - (X/S2)**G2]
!                     X, L, S1, G1, S2, G2 > 0
!
!             HERE, S1 AND G1 ARE THE SCALE AND SHAPE PARAMETERS
!             OF A WEIBULL DISTRIBUTION THAT MODELS "TRUE" FLAWS
!             AND S2 AND G2 ARE SCALE AND SHAPE PARAMETERS OF A
!             WEIBULL DISTRIBUTION THAT MODELS "END EFFECTS".  L
!             IS THE LENGTH OF THE FIBER (THIS SHOULD TYPICALLY BE
!             A KNOWN, FIXED VALUE).  NOTE THAT END-EFFECTS TYPICALLY
!             BECOME LESS PROMINENT AS THE FIBER LENGTH INCREASES
!             SINCE THE FIBER IS MORE LIKELY TO CONTAIN A FATAL FLAW.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --AL     = FIBER LENGTH
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE END-EFFECTS WEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,SCALE1,SCALE2,AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.7
!     ORIGINAL VERSION--JULY      2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR EEWCDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR EEWCDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR EEWCDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR EEWCDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE FIBER LENGTH PARAMETER FOR EEWCDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(X.LE.0.0D0)THEN
        CDF=0.0D0
      ELSE
        DTERM1=-AL*(X/SCALE1)**GAMMA1
        DTERM2=(X/SCALE2)**GAMMA2
        CDF=DEXP(DTERM1 - DTERM2)
        CDF=1.0D0 - CDF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWCDF
      SUBROUTINE EEWCD2(X,NX,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                        CDF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE END-EFFECTS WEIBULL DISTRIBUTION.
!              THIS DISTRIBUTION IS USED IN MODELING FAILURES OF
!              CARBON FIBERS UNDER STRESS.  THE CDF IS DEFINED AS:
!
!              F(X,L,S1,G1,L2,S2,G2) =
!                 1 - EXP[-L*(X/S1)**G1 - (X/S2)**G2]
!                     X, L, S1, G1, S2, G2 > 0
!
!             HERE, S1 AND G1 ARE THE SCALE AND SHAPE PARAMETERS
!             OF A WEIBULL DISTRIBUTION THAT MODELS "TRUE" FLAWS
!             AND S2 AND G2 ARE SCALE AND SHAPE PARAMETERS OF A
!             WEIBULL DISTRIBUTION THAT MODELS "END EFFECTS".  L
!             IS THE LENGTH OF THE FIBER (THIS SHOULD TYPICALLY BE
!             A KNOWN, FIXED VALUE).  NOTE THAT END-EFFECTS TYPICALLY
!             BECOME LESS PROMINENT AS THE FIBER LENGTH INCREASES
!             SINCE THE FIBER IS MORE LIKELY TO CONTAIN A FATAL FLAW.
!
!             THE EEWCDF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!             VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!             MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!             APPROACH.  THAT IS
!
!              F(X;L,GAMMA1,SCALE1,GAMMA2,SCALE2) = SUM[i=1 to NI]
!                  [p(i)*EEFCDF(X;L(i),GAMMA1,SCALE1,GAMMA2,SCALE2)]
!
!              WHERE NI IS THE NUMBER OF DISTINCT VALUES FOR L.
!
!              THIS ROUTINE ASSUMES THAT THE SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--X      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE CUMULATIVE DISTRIBUTION FUNCTION IS
!                                TO BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR X.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--PDF    = A VARIABLE CONTAINING THE CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION VALUES
!             CDF FOR THE END-EFFECTS WEIBULL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,SCALE1,SCALE2,AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--EEWCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.10
!     ORIGINAL VERSION--NOVEMBER  2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION CDF(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'WCD2')THEN
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EEWCD2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN END EFFECTS WEIBULL CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED CDF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED CDF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,21)
   21   FORMAT('      THE SCALE(1) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE GAMMA(1) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)
   25   FORMAT('      THE SCALE(2) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,27)
   27   FORMAT('      THE GAMMA(2) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DSUM1=0.0D0
      DO 60 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,62)I
   62     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,64)LI(I)
   64     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,67)I
   67     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,68)
   68     FORMAT('      IS OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,69)PI(I)
   69     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   60 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE CDF BY SUMMING OVER THE L(I) CASES
!
      DO 100 I=1,NX
        IF(X(I).LE.ALOC)THEN
          CDF(I)=0.0D0
          GO TO 100
        ENDIF
        DSUM1=0.0D0
        DO 200 J=1,NI
          DTERM1=X(I)-ALOC
          CALL EEWCDF(DTERM1,LI(J),GAMMA1,SCALE1,GAMMA2,SCALE2,DTERM2)
          DSUM1=DSUM1 + PI(J)*DTERM2
  200   CONTINUE
        CDF(I)=DSUM1
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWCD2
      SUBROUTINE EEWPDF(X,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILUITY DENSITY
!              FUNCTION VALUE FOR THE END-EFFECTS WEIBULL DISTRIBUTION.
!              THIS DISTRIBUTION IS USED IN MODELING FAILURES OF
!              CARBON FIBERS UNDER STRESS.  THE PDF IS DEFINED AS:
!
!              f(X,L,S1,G1,L2,S2,G2) =
!                 [L*G1*X**(G1-1)/S1**G1 + G2*X**(G2-1)/S2**G2]*
!                 EXP[-L*(X/S1)**G1 - (X/S2)**G2]
!                 X, L, S1, G1, S2, G2 > 0
!
!             HERE, S1 AND G1 ARE THE SCALE AND SHAPE PARAMETERS
!             OF A WEIBULL DISTRIBUTION THAT MODELS "TRUE" FLAWS
!             AND S2 AND G2 ARE SCALE AND SHAPE PARAMETERS OF A
!             WEIBULL DISTRIBUTION THAT MODELS "END EFFECTS".  L
!             IS THE LENGTH OF THE FIBER (THIS SHOULD TYPICALLY BE
!             A KNOWN, FIXED VALUE).  NOTE THAT END-EFFECTS TYPICALLY
!             BECOME LESS PROMINENT AS THE FIBER LENGTH INCREASES
!             SINCE THE FIBER IS MORE LIKELY TO CONTAIN A FATAL FLAW.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --AL     = FIBER LENGTH
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY DENSITY
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUE PDF
!             FOR THE END-EFFECTS WEIBULL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,SCALE1,SCALE2,AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.7
!     ORIGINAL VERSION--JULY      2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,55)
   55   FORMAT('***** ERROR--THE FIRST ARGUMENT TO EEWPDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR EEWPDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR EEWPDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR EEWPDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR EEWPDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE FIBER LENGTH PARAMETER FOR EEWPDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DTERM1=AL*GAMMA1*(X**(GAMMA1-1.0D0))/(SCALE1**GAMMA1)
      DTERM2=GAMMA2*(X**(GAMMA2-1.0D0))/(SCALE2**GAMMA2)
      DTERM3=-AL*(X/SCALE1)**GAMMA1
      DTERM4=(X/SCALE2)**GAMMA2
      PDF=(DTERM1 + DTERM2)*DEXP(DTERM3 - DTERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWPDF
      SUBROUTINE EEWPD2(X,NX,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                        PDF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILUITY DENSITY
!              FUNCTION VALUE FOR THE END-EFFECTS WEIBULL DISTRIBUTION.
!              THIS DISTRIBUTION IS USED IN MODELING FAILURES OF
!              CARBON FIBERS UNDER STRESS.  THE PDF IS DEFINED AS:
!
!              f(X,L,S1,G1,L2,S2,G2) =
!                 [L*G1*X**(G1-1)/S1**G1 + G2*X**(G2-1)/S2**G2]*
!                 EXP[-L*(X/S1)**G1 - (X/S2)**G2]
!                 X, L, S1, G1, S2, G2 > 0
!
!             HERE, S1 AND G1 ARE THE SCALE AND SHAPE PARAMETERS
!             OF A WEIBULL DISTRIBUTION THAT MODELS "TRUE" FLAWS
!             AND S2 AND G2 ARE SCALE AND SHAPE PARAMETERS OF A
!             WEIBULL DISTRIBUTION THAT MODELS "END EFFECTS".  L
!             IS THE LENGTH OF THE FIBER (THIS SHOULD TYPICALLY BE
!             A KNOWN, FIXED VALUE).  NOTE THAT END-EFFECTS TYPICALLY
!             BECOME LESS PROMINENT AS THE FIBER LENGTH INCREASES
!             SINCE THE FIBER IS MORE LIKELY TO CONTAIN A FATAL FLAW.
!
!             THE EEWPDF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!             VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!             MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!             APPROACH.  THAT IS
!
!              f(X;L,GAMMA1,SCALE1,GAMMA2,SCALE2) = SUM[i=1 to NI]
!                  [p(i)*EEFPDF(X;L(i),GAMMA1,SCALE1,GAMMA2,SCALE2)]
!
!              WHERE NI IS THE NUMBER OF DISTINCT VALUES FOR L.
!
!              THIS ROUTINE ASSUMES THAT THE SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--X      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE PROBABILITY DENSITY FUNCTION IS TO
!                                BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR X.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--PDF    = A VARIABLE CONTAINING THE PROBABILITY
!                                DENSITY FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUE PDF
!             FOR THE END-EFFECTS WEIBULL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,SCALE1,SCALE2,AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--EEWPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.10
!     ORIGINAL VERSION--NOVEMBER  2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION PDF(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IERROR='NO'
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN END EFFECTS WEIBULL PDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED PDF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED PDF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,21)
   21   FORMAT('      THE SCALE(1) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE GAMMA(1) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)
   25   FORMAT('      THE SCALE(2) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,27)
   27   FORMAT('      THE GAMMA(2) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DO 50 I=1,NX
        IF(X(I).LE.ALOC)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,55)I
   55     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE INPUT ',   &
                 'ARGUMENT IS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,56)
   56     FORMAT('      LESS THAN OR EQUAL TO THE VALUE OF THE ',   &
                 'LOCATION PARAMETER')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,58)X(I)
   58     FORMAT('      THE VALUE OF X(I)                    = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,59)ALOC
   59     FORMAT('      THE VALUE OF THE LOCATION PARAMETER  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
   50 CONTINUE
!
      DSUM1=0.0D0
      DO 60 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,62)I
   62     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,64)LI(I)
   64     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,67)I
   67     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,68)
   68     FORMAT('      IS OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,69)PI(I)
   69     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   60 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE PDF BY SUMMING OVER THE L(I) CASES
!
      DO 100 I=1,NX
        DSUM1=0.0D0
        DO 200 J=1,NI
          DTERM1=X(I)-ALOC
          CALL EEWPDF(DTERM1,LI(J),GAMMA1,SCALE1,GAMMA2,SCALE2,DTERM2)
          DSUM1=DSUM1 + PI(J)*DTERM2
  200   CONTINUE
        PDF(I)=DSUM1
  100 CONTINUE
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'WPDF')THEN
        WRITE(ICOUT,9010)
 9010   FORMAT('****** AT THE END OF EEWPD2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE EEWPD2
      SUBROUTINE EEWPPF(P,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE END-EFFECTS WEIBULL DISTRIBUTION.
!              THIS DISTRIBUTION IS USED IN MODELING FAILURES OF
!              CARBON FIBERS UNDER STRESS.  THE CDF IS DEFINED AS:
!
!              F(X,L,S1,G1,L2,S2,G2) =
!                 1 - EXP[-L*(X/S1)**G1 - (X/S2)**G2]
!                     X, L, S1, G1, S2, G2 > 0
!
!             HERE, S1 AND G1 ARE THE SCALE AND SHAPE PARAMETERS
!             OF A WEIBULL DISTRIBUTION THAT MODELS "TRUE" FLAWS
!             AND S2 AND G2 ARE SCALE AND SHAPE PARAMETERS OF A
!             WEIBULL DISTRIBUTION THAT MODELS "END EFFECTS".  L
!             IS THE LENGTH OF THE FIBER (THIS SHOULD TYPICALLY BE
!             A KNOWN, FIXED VALUE).  NOTE THAT END-EFFECTS TYPICALLY
!             BECOME LESS PROMINENT AS THE FIBER LENGTH INCREASES
!             SINCE THE FIBER IS MORE LIKELY TO CONTAIN A FATAL FLAW.
!
!             THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!             INVERTING THE CDF FUNCTION.
!
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --AL     = FIBER LENGTH
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE END-EFFECTS WEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,SCALE1,SCALE2,AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.7
!     ORIGINAL VERSION--JULY      2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS /0.000000001/
      DATA DSIG /1.0D-9/
      DATA MAXIT /2000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,55)
   55   FORMAT('***** ERROR--THE FIRST ARGUMENT TO EEWPPF IS OUTSIDE ',   &
               'THE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR EEWPPF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR EEWPPF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR EEWPPF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR EEWPPF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE FIBER LENGTH PARAMETER FOR EEWPPF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(P.LE.0.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ENDIF
!
!     COMPUTE PPF NUMERICALLY
!
!
!     FIND BRACKETING INTERVAL.
!
      DXL=0.0D0
      DXINC=MAX(SCALE1,SCALE2)
      IF(DXINC.LT.1.0D0)DXINC=1.0D0
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      DXR=DXL+DXINC
      IF(DXL.LE.0.0D0)DXL=0.0D0
      IF(DXR.LE.0.0D0)DXR=DXL+DXINC
      CALL EEWCDF(DXL,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,CDFL)
      CALL EEWCDF(DXR,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        DXL=DXR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        DXL=DXL-DXINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0D0
        GO TO 9000
      ENDIF
   96 FORMAT('***** ERROR--EEWPPF UNABLE TO FIND BRACKETING INTERVAL')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      DFXL = -P
      DFXR = 1.0D0 - P
  105 CONTINUE
      DX = (DXL+DXR)*0.5D0
      CALL EEWCDF(DX,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,DCDF)
      DP1=DCDF
      DPPF=DX
      PPF=DPPF
      DFCS = DP1 - P
      IF(DFCS*DFXL.GT.0.0D0)GO TO 110
      DXR = DX
      DFXR = DFCS
      GO TO 115
  110 CONTINUE
      DXL = DX
      DFXL = DFCS
  115 CONTINUE
      DXRML = DXR - DXL
      IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)GO TO 9000
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--EEWPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWPPF
      SUBROUTINE EEWPP2(P,NX,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                        PPF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE END EFFECTS WEIBULL
!              DISTRIBUTION.
!
!              THE EEWPPF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!              VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!              MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!              APPROACH.  EEWPP2 COMPUTES THE PPF FUNCTION BY
!              NUMERICALLY INVERTING THE CUMULATIVE DISTRIBUTION
!              FUNCTION.
!
!              THIS ROUTINE ASSUMES THAT THE LOCATION/SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--P      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR P.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --SCALE1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!                     --SCALE2 = SCALE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--PPF    = A VARIABLE CONTAINING THE PERCENT POINT
!                                FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUES.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--EEWCD2.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.11
!     ORIGINAL VERSION--NOVEMBER  2010.
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      DOUBLE PRECISION P(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION PPF(*)
!
      DOUBLE PRECISION DCDF(1)
      DOUBLE PRECISION DX(1)
!
      DOUBLE PRECISION LMIN
      DOUBLE PRECISION LMAX
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS /1.0D-14/
      DATA DSIG /1.0D-14/
      DATA MAXIT /1000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN END EFFECTS WEIBULL PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED PPF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED PPF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,21)
   21   FORMAT('      THE SCALE(1) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE GAMMA(1) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)
   25   FORMAT('      THE SCALE(2) PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,27)
   27   FORMAT('      THE GAMMA(2) SHAPE PARAMETER IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DSUM1=0.0D0
      DO 50 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)I
   52     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,54)LI(I)
   54     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,57)I
   57     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,58)
   58     FORMAT('      OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,59)PI(I)
   59     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   50 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE PPF BY NUMERICALLY INVERTING THE CDF FUNCTION
!
      NTEMP=1
      LMIN=LI(1)
      LMAX=LI(1)
      DO 90 I=1,NI
        IF(LI(I).LT.LMIN)LMIN=LI(I)
        IF(LI(I).GT.LMAX)LMAX=LI(I)
   90 CONTINUE
!
      DO 100 I=1,NX
        DP=P(I)
!
        IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)I
  105     FORMAT('      FOR ROW ',I8,' THE PROBABILITY PARAMETER (P) ',   &
                 'IS OUTSIDE THE (0,1) INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,106)DP
  106     FORMAT('      THE VALUE OF P  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(1.0D0 - DP.LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,108)I
  108     FORMAT('      FOR ROW ',I8,' THE PROBABILITY PARAMETER (P) ',   &
                 'IS TOO CLOSE TO 1 TO COMPUTE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,106)DP
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        IF(DP.EQ.0.0D0)THEN
          PPF(I)=ALOC
          GO TO 100
        ENDIF
!
!       STEP 1: FIND BRACKETING INTERVAL
!
        CALL EEWPPF(DP,LMIN,GAMMA1,SCALE1,GAMMA2,SCALE2,DTERM1)
        DTERM1=ALOC + DTERM1
        CALL EEWPPF(DP,LMAX,GAMMA1,SCALE1,GAMMA2,SCALE2,DTERM2)
        DTERM2=ALOC + DTERM2
        DXL=MIN(DTERM1,DTERM2)
        DXR=MAX(DTERM1,DTERM2)
        IF(DXL.EQ.DXR)THEN
          PPF(I)=DXL
          GO TO 100
        ENDIF
        NTEMP=1
        DX(1)=DXL
        CALL EEWCD2(DX,NTEMP,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                    DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DCDFL=DCDF(1)
        DX(1)=DXR
        CALL EEWCD2(DX,NTEMP,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                    DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DCDFR=DCDF(1)
!
        IF(DCDFL.LT.DP .AND. DCDFR.LT.DP)THEN
          PPF(I)=CPUMIN
          GO TO 100
        ELSEIF(DCDFL.GT.DP .AND. DCDFR.GT.DP)THEN
          PPF(I)=CPUMIN
          GO TO 100
        ENDIF
!
!       STEP 2: BISECTION METHOD
!
        IC = 0
        DFXL = -DP
        DFXR = 1.0D0 - DP
  205   CONTINUE
        DX(1)=(DXL+DXR)*0.5D0
        CALL EEWCD2(DX,NTEMP,LI,PI,NI,GAMMA1,SCALE1,GAMMA2,SCALE2,ALOC,   &
                    DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DP1=DCDF(1)
        DPPF=DX(1)
        DFCS = DP1 - DP
!
        IF(DFCS*DFXL.GT.0.0D0)THEN
          DXL = DX(1)
          DFXL = DFCS
        ELSE
          DXR = DX(1)
          DFXR = DFCS
        ENDIF
!
        DXRML = DXR - DXL
        IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)THEN
          PPF(I)=DPPF
          GO TO 100
        ENDIF
!
!       STEP 3: ERROR MESSAGE FOR NO CONVERGENCE
!
        IC = IC + 1
        IF(IC.LE.MAXIT)GO TO 205
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,230)I,DP
  230   FORMAT('      FOR ROW ',I8,' (P = ',G15.7,'), THERE WAS ',   &
               'NO CONVERGENCE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,233)
  233   FORMAT('      LAST VALUE OBTAINED WILL BE USED.')
        CALL DPWRST('XXX','BUG ')
        PPF(I)=DPPF
        GO TO 100
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWPP2
      SUBROUTINE EMPQUA(X,NX,IWRITE,Y,U,NY,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE EMPIRICAL QUANTILE FUNCTION OF A VARIABLE--
!              THE FORMULA IS:
!
!                 Qhat(u) = (N*u - j + (1/2))*X(j+1) +
!                           (j + (1/2) - N*u)*X(j)
!
!                           (2-j-1)/(2*N) <= u < (2*j+1)/(2*n)
!                           j = 1, 2, ... n-1
!
!               THIS WILL BE COMPUTED FOR A SPECIFIED NUMBER OF
!               EQUI-SPACED POINTS BETWEEN THE LOWER AND UPPER LIMITS.
!
!     REFERENCE--"MIL-HDBK-17-1F Volume 1: Guidelines for Characterization
!                of Structural Materials", Depeartment of Defense,
!                chapter 8, 2002.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/2
!     ORIGINAL VERSION--FEBRUARY  2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION U(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EMPQ'
      ISUBN2='UA  '
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PQUA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EMPQUA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWRITE,IBUGA3,NX
   52   FORMAT('IWRITE,IBUGA3,NX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  SORT THE DATA                   **
!               **************************************
!
      CALL SORT(X,NX,X)
!
      NY=0
      AN=REAL(NX)
      IF(NX.GT.1000)THEN
        NINC=1
      ELSE
        NTOT=1000
        AINC=REAL(NTOT)/REAL(NX)
        NINC=INT(AINC+0.5)
        IF(NINC.LE.0)NINC=1
      ENDIF
!
      DO 100 J=1,NX-1
        AJ=REAL(J)
        ALOW=(2.0*AJ - 1.0)/(2.0*AN)
        AUPP=(2.0*AJ + 1.0)/(2.0*AN)
        IF(NINC.EQ.1)THEN
          AMID=(ALOW+AUPP)/2.0
          NY=NY+1
          TERM1=AN*AMID - AJ + 0.5
          TERM2=AJ + 0.5 - AN*AMID
          U(NY)=AMID
          Y(NY)=TERM1*X(J+1) + TERM2*X(J)
        ELSE
          AINC=(AUPP-ALOW)/REAL(NINC)
          DO 200 K=1,NINC
            AVAL=ALOW + REAL(K-1)*AINC
            NY=NY+1
            TERM1=AN*AVAL - AJ + 0.5
            TERM2=AJ + 0.5 - AN*AVAL
            U(NY)=AVAL
            Y(NY)=TERM1*X(J+1) + TERM2*X(J)
  200     CONTINUE
        ENDIF
  100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PQUA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EMPQUA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NX,NY
 9013   FORMAT('IERROR,NX,NY = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NY
          WRITE(ICOUT,9016)I,U(I),Y(I)
 9016     FORMAT('I,U(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EMPQUA
      SUBROUTINE EMPTIQ(X,NX,IWRITE,AIQHAT,TIQHAT,U,QUHAT,NY,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE INFORMATIVE QUANTILE (IQ) FUNCTION.
!
!              THE EMPIRICAL QUANTILE FUNCTION OF A VARIABLE IS
!              COMPUTED WITH THE FORMULA:
!
!                 Qhat(u) = (N*u - j + (1/2))*X(j+1) +
!                           (j + (1/2) - N*u)*X(j)
!
!                           (2-j-1)/(2*N) <= u < (2*j+1)/(2*n)
!                           j = 1, 2, ... n-1
!
!               THIS WILL BE COMPUTED FOR A SPECIFIED NUMBER OF
!               EQUI-SPACED POINTS BETWEEN THE LOWER AND UPPER LIMITS.
!
!               THE ESTIMATED IQ FUNCTION IS DEFINED AS:
!
!                 IQHAT(u) = (QHAT(u) - QHAT(0.5))/
!                            {2*(QHAT(0.75) - QHAT(0.25))}
!
!               THE ESTIMATED TRUNCATED IQ FUNCTION IS DEFINED AS:
!
!                 TIQHAT(u) = (QHAT(u) - QHAT(0.5))/
!                             {2*(QHAT(0.75) - QHAT(0.25))} -1 < IQHAT(u) <= 1
!
!                             -1                                 IQHAT(u) <= -1
!                             +1                                 IQHAT(u) >  +1
!
!     REFERENCE--"MIL-HDBK-17-1F Volume 1: Guidelines for Characterization
!                of Structural Materials", Depeartment of Defense,
!                chapter 8, 2002.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/03
!     ORIGINAL VERSION--MARCH     2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL LININ3
      EXTERNAL LININ3
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION QUHAT(*)
      DIMENSION AIQHAT(*)
      DIMENSION TIQHAT(*)
      DIMENSION U(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EMPT'
      ISUBN2='IQ  '
      IERROR='NO'
!
      QU50=0.0
      QU25=0.0
      QU75=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PTIQ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EMPTIQ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWRITE,IBUGA3,NX
   52   FORMAT('IWRITE,IBUGA3,NX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************************************
!               **  COMPUTE THE EMPIRICAL QUANTILE FUNCTION  **
!               ***********************************************
!
      CALL SORT(X,NX,X)
!
      NY=0
      AN=REAL(NX)
      IF(NX.GT.1000)THEN
        NINC=1
      ELSE
        NTOT=1000
        AINC=REAL(NTOT)/REAL(NX)
        NINC=INT(AINC+0.5)
        IF(NINC.LE.0)NINC=1
      ENDIF
!
      DO 100 J=1,NX-1
        AJ=REAL(J)
        ALOW=(2.0*AJ - 1.0)/(2.0*AN)
        AUPP=(2.0*AJ + 1.0)/(2.0*AN)
        IF(NINC.EQ.1)THEN
          AMID=(ALOW+AUPP)/2.0
          NY=NY+1
          TERM1=AN*AMID - AJ + 0.5
          TERM2=AJ + 0.5 - AN*AMID
          U(NY)=AMID
          QUHAT(NY)=TERM1*X(J+1) + TERM2*X(J)
        ELSE
          AINC=(AUPP-ALOW)/REAL(NINC)
          DO 200 K=1,NINC
            AVAL=ALOW + REAL(K-1)*AINC
            NY=NY+1
            TERM1=AN*AVAL - AJ + 0.5
            TERM2=AJ + 0.5 - AN*AVAL
            U(NY)=AVAL
            QUHAT(NY)=TERM1*X(J+1) + TERM2*X(J)
  200     CONTINUE
        ENDIF
  100 CONTINUE
!
!               *****************************************************
!               **  NOW COMPUTE THE INFORMATIVE QUANTILE FUNCTION  **
!               *****************************************************
!
!      SEARCH THE LIST FOR THE CLOSEST MATCH TO U = 0.5, .25, and .75
!
      IFLAG1=0
      IFLAG2=0
      DO 300 I=1,NY-1
        IF(U(I).LE.0.25 .AND. U(I+1).GE.0.25 .AND. IFLAG1.EQ.0)THEN
          AVAL=0.25
          QU25=LININ3(U(I),QUHAT(I),U(I+1),QUHAT(I+1),AVAL,   &
                      IBUGA3,ISUBRO,IERROR)
          IFLAG1=1
        ELSEIF(U(I).LE.0.5 .AND. U(I+1).GE.0.5 .AND. IFLAG2.EQ.0)THEN
          AVAL=0.50
          QU50=LININ3(U(I),QUHAT(I),U(I+1),QUHAT(I+1),AVAL,   &
                      IBUGA3,ISUBRO,IERROR)
          IFLAG2=1
        ELSEIF(U(I).LE.0.75 .AND. U(I+1).GE.0.75)THEN
          AVAL=0.75
          QU75=LININ3(U(I),QUHAT(I),U(I+1),QUHAT(I+1),AVAL,   &
                      IBUGA3,ISUBRO,IERROR)
          GO TO 309
        ENDIF
  300 CONTINUE
  309 CONTINUE
!
      DO 400 I=1,NY
        AIQHAT(I)=(QUHAT(I) - QU50)/(2.0*(QU75 - QU25))
        IF(AIQHAT(I).LE.-1.0)THEN
          TIQHAT(I)=-1.0
        ELSEIF(AIQHAT(I).GT.1.0)THEN
          TIQHAT(I)=1.0
        ELSE
          TIQHAT(I)=AIQHAT(I)
        ENDIF
  400  CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PTIQ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EMPTIQ--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NX,NY,QU25,QU50,QU75
 9013   FORMAT('IERROR,NX,NY,QU25,QU50,QU75 = ',A4,2X,2I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NY
          WRITE(ICOUT,9016)I,U(I),QUHAT(I),AIQHAT(I),TIQHAT(I)
 9016     FORMAT('I,U(I),QUHAT(I),AIQHAT(I),TIQHAT(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EMPTIQ
      SUBROUTINE EN(X,ULAB,XREF,UREF,N,IWRITE,ENOUT,   &
                    IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE EN STATISTIC:
!
!                 EN(i) = (x(i) - XREF)/SQRT(U(lab)**2 + U(ref)**2)
!
!              WHERE
!
!                   XREF    = THE ASSIGNED VALUE (DETERMINED FROM A
!                             REFERENCE LABORATORY)
!                   U(ref)  = THE EXPANDED UNCERTAINTY FOR THE ASSIGNED
!                             VALUE
!                   U(lab)  = THE EXPANDED UNCERTAINTY FOR THE LAB
!
!              NOTE THAT SINCE THE LAB UNCERTAINTY CAN VARY DEPENDING
!              ON THE LAB, THIS IS INPUT AS A VECTOR RATHER THAN A
!              PARAMETER.  XREF AND UREF ARE INPUT AS PARAMETERS SINCE
!              THEY ARE FIXED FOR ALL LABS.  ULAB EFFECTIVELY ACTS AS
!              AS A PROXY FOR LAB-ID, SO NO NEED TO INPUT THIS AS A
!              SEPARATE VALUE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --ULAB   = THE SINGLE PRECISION VECTOR OF
!                                LAB EXPANDED UNCERTAINTIES
!                     --XREF   = THE SINGLE PRECISION VALUE CONTAINING
!                                THE ASSIGNED VALUE
!                     --UREF   = THE SINGLE PRECISION VALUE CONTAINING
!                                THE EXPANDED UNCERTAINTY FOR THE
!                                ASSIGNED VALUE
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--ENOUT  = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED EN VALUES.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE SAMPLE EN
!             VALUES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--ISO 13528, FIRST EDITION, STATISTICAL METHODS FOR USE
!                IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                2005, PP. 27-28.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.1
!     ORIGINAL VERSION--JANUARY   2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION ULAB(*)
      DIMENSION ENOUT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EN  '
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EN  ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,XREF,UREF
   52   FORMAT('IBUGA3,N = ',A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),ULAB(I)
   56     FORMAT('I,X(I),ULAB(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************
!               **  COMPUTE EN    **
!               ********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN EN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE VARIABLE FOR')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      WHICH THE MEAN IS TO BE COMPUTED MUST BE AT ',   &
               'LEAST 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(UREF.LT.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE REFERENCE EXPANDED UNCERTAINTY IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)UREF
  127   FORMAT('      THE REFERENCE EXPANDED UNCERTAINTY = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************
!               **  STEP 2--           **
!               **  COMPUTE THE EN     **
!               *************************
!
      DO 200 I=1,N
        UTEMP1=ULAB(I)
        UTEMP2=UTEMP1**2 + UREF**2
!
        IF(UTEMP1.LT.0.0 .OR. UTEMP2.LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,222)
  222     FORMAT('      EITHER THE LAB EXPANDED UNCERTAINTY IS ',   &
                 'NEGATIVE OR')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,224)
  224     FORMAT('      BOTH THE LAB EXPANDED UNCERTAINTY AND THE ',   &
                 'EXPANDED')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,226)
  226     FORMAT('      REFERENCE UNCERTAINTY ARE ZERO.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,127)UREF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,227)ULAB(I)
  227     FORMAT('      THE LAB EXPANDED UNCERTAINTY = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        ENOUT(I)=(X(I) - XREF)/SQRT(UTEMP1**2 + UREF**2)
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N
  811   FORMAT('THE NUMBER OF EN VALUES GENERATED = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EN  ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF EN--')
        CALL DPWRST('XXX','BUG ')
        DO 9012 I=1,N
          WRITE(ICOUT,9015)I,X(I),ULAB(I),ENOUT(I)
 9015     FORMAT('I,X(I),ULAB(I),ENOUT(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9012   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EN
      SUBROUTINE ENTROP(X,N,IWRITE,ICASE,XE,XMEAN,XVAR,XSD,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES SHANNON'S ENTROPY
!              STATISTIC, AND ALTERNATIVELY THE MEAN, VARIANCE
!              AND STANDARD DEVIATION.  ENTROPY HAS DIFFERENT
!              DEFINITIONS IN DIFFERENT FIELDS, SO WE REFER TO
!              THESE AS "SHANNON ENTROPY" TO DISTINGUISH
!              THAT WE ARE REFERRING TO SHANNON'S DEFINITION.
!
!                 1) SHANNON'S ENTROPY:
!
!                      E = -SUM[i=1 to k][p(i)*LOG(p(i))]
!
!                    WHERE p(i)*LOG(p(i)) = 0 FOR p(i) = 0
!
!                 2) MEAN OF SHANNON'S ENTROPY:
!
!                     U = SUM[i=1 to k][i*p(i)]
!
!                 3) VARIANCE OF SHANNON'S ENTROPY:
!
!                     SIGMA^2 = SUM[i=1 to k][(i-U)**2*p(i)]
!
!                 4) SD OF SHANNON'S ENTROPY:
!
!                     SIGMA = SQRT(SIGMA^2)
!
!              THE p(i) IS THE PROBABILITY OF THE i-THE VALUE.
!              THESE SHOULD SUM TO 1.  IF THE VALUES IN X DO NOT
!              SUM TO 1, THEN ASSUME THAT THE X DENOTE A FREQUENCY
!              TABLE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XE     = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SHANNON'S ENTROPY.
!                     --XMEAN  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED MEAN OF SHANNON'S ENTROPY.
!                     --XVAR   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED VARIANCE OF SHANNON'S ENTROPY.
!                     --XSD    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SD OF SHANNON'S ENTROPY.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE ENTROPY.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SHANNON (1948), "A MATHEMATICAL THEORY OF
!                 COMMUNICATION", BELL SYSTEM TECHNICAL JOURNAL,
!                 Vol. 27, PP. 379-423.
!               --CRESSIE (1993), "STATISTICS FOR SPATIAL DATA: REVISED
!                 EDITION", WILEY, p. 1.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2021.03
!     ORIGINAL VERSION--MARCH     2021.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DU
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DVAL
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ENTR'
      ISUBN2='OP  '
      IERROR='NO'
!
      XE=CPUMIN
      XMEAN=CPUMIN
      XVAR=CPUMIN
      XSD=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TROP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MEAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ISHALB,N
   52   FORMAT('IBUGA3,ISUBRO,ISHALB,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN SHANNON ENTROPY--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DSUM=0.0D0
      DO 120 I=1,N
        IF(X(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,122)I,X(I)
  122     FORMAT('      THE ',I8,'-TH OBSERVATION IS NEGATIVE (',   &
                 G15.7,').')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        DSUM=DSUM + DBLE(X(I))
  120 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TROP')THEN
        WRITE(ICOUT,126)DSUM
  126   FORMAT('AFTER 120: DSUM = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DEPS=1.0D-7
      IF(DSUM.LT.1.0D0-DEPS)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,132)
  132   FORMAT('      THE SUM OF THE OBSERVATIONS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,134)N,DSUM
  134   FORMAT('      THE SUM OF THE ',I8,' OBSERVATIONS IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(DSUM.GT.1.0D0+DEPS)THEN
!
!       SUM GREATER THAN ONE.  DIVIDE ALL OBSERVATIONS BY THE SUM
!
        DO 140 I=1,N
          DX=DBLE(X(I))
          DVAL=DX/DSUM
          X(I)=REAL(DVAL)
  140   CONTINUE
      ENDIF
!
!               ***************************
!               **  STEP 2--             **
!               **  COMPUTE THE ENTROPY  **
!               ***************************
!
      DSUM=0.0D0
      DU=0.0D0
      DO 200 I=1,N
        DX=DBLE(X(I))
        IF(DX.GT.0.0D0)THEN
          IF(ISHALB.EQ.'10  ')THEN
            DXLOG=DLOG(DX)/DLOG(10.0D0)
          ELSEIF(ISHALB.EQ.'2   ')THEN
            DXLOG=DLOG(DX)/DLOG(2.0D0)
          ELSE
            DXLOG=DLOG(DX)
          ENDIF
          DSUM=DSUM+DX*DXLOG
          DU=DU+DBLE(I)*DX
        ENDIF
  200 CONTINUE
      XE=-REAL(DSUM)
      XMEAN=REAL(XE)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TROP')THEN
        WRITE(ICOUT,206)DSUM,DU,XE,XMEAN
  206   FORMAT('AFTER 200: DSUM,DU,XE,XMEAN = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DVAR=0.0D0
      DO 300 I=1,N
        DX=DBLE(X(I))
        IF(DX.GT.0.0D0)THEN
          DVAR=DVAR+(DBLE(I)-DU)**2*DX
        ENDIF
  300 CONTINUE
      XVAR=REAL(DVAR)
      XSD=REAL(DSQRT(DVAR))
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TROP')THEN
        WRITE(ICOUT,306)DVAR
  306   FORMAT('AFTER 300: DVAR = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICASE.EQ.'ENTR')THEN
          WRITE(ICOUT,811)N,XE
  811     FORMAT('THE SHANNON ENTROPY OF THE ',I8,' OBSERVATIONS = ',   &
                 G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'MEAN')THEN
          WRITE(ICOUT,813)N,XMEAN
  813     FORMAT('THE MEAN OF THE SHANNON ENTROPY OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'VARI')THEN
          WRITE(ICOUT,815)N,XVAR
  815     FORMAT('THE VARIANCE OF THE SHANNON ENTROPY OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'SD')THEN
          WRITE(ICOUT,817)N,XSD
  817     FORMAT('THE STANDARD DEVIATION OF THE SHANNON ENTROPY OF ',   &
                 'THE ',I8,' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,819)ICASE
  819     FORMAT('CASE ',A4,' IS NOT RECOGNIZED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TROP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF ENTROP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,XE,XMEAN,XVAR,XSD
 9012   FORMAT('IERROR,XE,XMEAN,XVAR,XSD = ',A4,2X,4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE ENTROP
      DOUBLE PRECISION FUNCTION ENVJ(N,X)
      DOUBLE PRECISION X
      ENVJ=0.5D0*DLOG10(6.28D0*N)-N*DLOG10(1.36D0*X/N)
      RETURN
      END FUNCTION ENVJ
      DOUBLE PRECISION FUNCTION EPLFUN (DB)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE ESTIMATE OF B
!              FOR THE EXPONENTIAL LAW (NUMBER OF FAILURES CASE).
!              THIS FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 SUM[i=1 to n][X(i)] + N/Bhat -
!                 N*X(n)/(1 - EXP(-BHAT*X(n)) = 0
!
!              WITH
!
!                 N        = NUMBER OF FAILURE TIMES
!                 Bhat     = POINT ESTIMATE OF B
!                 X        = VECTOR OF FAILURE TIMES
!
!              NOTE THAT THE SUM[X(I)] AND X(N) ARE COMPUTED IN
!              DPMLEL AND PASSED VIA COMMON BLOCK.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--EXPONENTIAL LAW MAXIMUM LIKELIHOOD Y CENSOR
!     REFERENCE--TOBIAS AND TRINDADE, "APPLIED RELIABILITY", SECOND
!                EDITION, PP. 363-365.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DB
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTEND
      DOUBLE PRECISION DXSUM
      DOUBLE PRECISION DXN
      COMMON/EPLCOM/DXSUM,DXN,DTEND,DN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      EPLFUN=DXSUM + (DN/DB) - DN*DXN/(1.0D0 - DEXP(-DB*DXN))
!
      RETURN
      END FUNCTION EPLFUN 
      DOUBLE PRECISION FUNCTION EPLFU2 (DB)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE ESTIMATE OF B
!              FOR THE EXPONENTIAL LAW (TIME CENSORED CASE).
!              THIS FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 SUM[i=1 to n][X(i)] + N/Bhat -
!                 N*T/(1 - EXP(-BHAT*T)) = 0
!
!              WITH
!
!                 N        = NUMBER OF FAILURE TIMES
!                 Bhat     = POINT ESTIMATE OF B
!                 X        = VECTOR OF FAILURE TIMES
!                 T        = CENSORING TIME
!
!              NOTE THAT THE SUM[X(I)] AND T ARE COMPUTED IN
!              DPMLEL AND PASSED VIA COMMON BLOCK.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--EXPONENTIAL LAW MAXIMUM LIKELIHOOD Y CENSOR
!     REFERENCE--TOBIAS AND TRINDADE, "APPLIED RELIABILITY", SECOND
!                EDITION, PP. 363-365.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DB
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTEND
      DOUBLE PRECISION DXSUM
      DOUBLE PRECISION DXN
      COMMON/EPLCOM/DXSUM,DXN,DTEND,DN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      EPLFU2=DXSUM + (DN/DB) - DN*DTEND/(1.0D0 - DEXP(-DB*DTEND))
!
      RETURN
      END FUNCTION EPLFU2 
      SUBROUTINE EUCDIS(AMAT,AMAT2,MAXROM,MAXCOM,NR1,NC1,   &
                        ICASE,ICASE2,P,IWRITE,   &
                        TEMP1,TEMP2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE EUCLIDEAN DISTANCE OF A
!              MATRIX.  THE FORMULA IS:
!
!                 D(ij)=SQRT{SUM[k=1 to p][(X(ik) - X(jk))**2)}
!
!              ALTERNATIVELY (BASED ON ICASE2), THE FOLLOWING DISTANCE
!              MATRICES CAN BE COMPUTED:
!
!              MINKOWSKY DISTANCE:
!
!                 D(ij)=SUM[k=1 to p][(ABS|(X(ik) - X(jk))|**P)**(1/P)]
!
!              BLOCK (OR MANHATTAN) DISTANCE:
!
!                 D(ij)=SUM[k=1 to p][|X(ik) - X(jk)|]
!
!              CANBERRA DISTANCE:
!
!                 D(ij)=SUM[k=1 to p][|X(ik) - X(jk)|/
!                       (|X(i)| + |Y(i)|)]
!
!              CHEBYCHEV DISTANCE:
!
!                 D(ij)=MAX[k=1 to p][|X(ik) - X(jk)|]
!
!              COSINE SIMILARITY:
!
!                 S(ij) = SUM[k=1 to p][X(ik)*Y(ik)]/
!                         {SQRT(SUM[k=1 to p][X(ik)**2])*
!                          SQRT(SUM[k=1 to p][X(ik)**2])}
!
!             COSINE DISTANCE:
!
!                D(ij) = 1 - COSINE SIMILARITY(ij)
!
!             ANGULAR COSINE DISTANCE:
!
!                D(ij) = 1 - COSINE SIMILARITY(ij)
!
!             JACCARD SIMILARITY:
!
!                J(ij) = SUM[k=1 to n][MIN(X(ik),Y(ik))/
!                        SUM[k=1 to n][MAX(X(ik),Y(ik))]
!
!             JACCARD DISTANCE:
!
!                D(ij) = 1 - JACCARD SIMILARITY(ij)
!
!             HAMMING DISTANCE:
!
!                D(ij) = NUMBER OF ELEMENTS THAT DIFFER IN X AND Y
!
!             PEARSON DISTANCE:
!
!                D(ij) = (1 - R(I,J))/2  (R = CORRELATION COEFFICIENT)
!
!             PEARSON SIMILARITY:
!
!                S(ij) = 1 - PEARSON DISTANCE
!
!     INPUT  ARGUMENTS--AMAT   = THE SINGLE PRECISION MATRIX
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT
!     OUTPUT ARGUMENTS--AMAT2    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE EUCLIDEAN DISTANCES.
!     OUTPUT--MATRIX OF EUCLIDEAN DISTANCES
!     NOTE--THIS ROUTINE ASSUMES THE ERROR CHECKING (FOR EQUAL
!           ROWS AND COLUMNS, MATCHING DIMENSIONS FOR X AND AMAT)
!           IS DONE BT THE CALLING SUBROUTINE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.6
!     ORIGINAL VERSION--JUNE      1998.
!     UPDATED         --AUGUST    2018. INCORPORATE ADDITIONAL DISTANCE
!                                       METRICS (ICASE2)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 ICASE2
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DYM1
      DOUBLE PRECISION DYM2
!
      DIMENSION AMAT(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EUCD'
      ISUBN2='IS  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDIS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EUCDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ICASE,ICASE2,NR1,NC1
   52   FORMAT('IBUGA3,ICASE,ICASE2,NR1,NC1 = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **  COMPUTE DISTANCE           *
!               ********************************
!
      IF(ICASE.EQ.'ROW ')THEN
        DO 5860 I=1,NR1
          DO 5861 J=1,I
            DSUM=0.0D0
            DSUM2=0.0D0
            DSUM3=0.0D0
            IF(ICASE2.EQ.'EUCL')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5862 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DSUM=DSUM+(DYM1-DYM2)**2
 5862           CONTINUE
                AMAT2(I,J)=REAL(DSQRT(DSUM))
              ENDIF
            ELSEIF(ICASE2.EQ.'MINK')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5863 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DSUM=DSUM + DABS(DYM1-DYM2)**DBLE(P)
 5863           CONTINUE
                AMAT2(I,J)=REAL(DSUM**(1.0D0/DBLE(P)))
              ENDIF
            ELSEIF(ICASE2.EQ.'BLOC')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5864 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DSUM=DSUM+DABS(DYM1-DYM2)
 5864           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'HAMM')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 55869 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  IF(DYM1.NE.DYM2)DSUM=DSUM+1.0D0
55869           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'CHEB')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DSUM2=0.0D0
                DO 5865 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DSUM=DSUM+DABS(DYM1-DYM2)
 5865           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'COSS' .OR. ICASE2.EQ.'COSD' .OR.   &
                   ICASE2.EQ.'ACSS' .OR. ICASE2.EQ.'ACSD')THEN
              IF(I.EQ.J)THEN
                IF(ICASE2.EQ.'COSD' .OR. ICASE2.EQ.'ACSD')THEN
                  AMAT2(I,J)=0.0
                ELSE
                  AMAT2(I,J)=1.0
                ENDIF
              ELSE
                IFLAG=1
                DO 5866 K=1,NC1
                  IF(ICASE2.EQ.'COSD')THEN
                    IF(AMAT(I,K).LT.0.0 .OR. AMAT(J,K).LT.0.0)THEN
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8001)
 8001                 FORMAT('****** ERROR IN MATRIX DISTANCE--')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8003)
 8003                 FORMAT('       COSINE DISTANCE NOT SUPPORTED ',   &
                             'FOR NEGATIVE VALUES.')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8005)I,K,AMAT(I,K)
 8005                 FORMAT('        ROW ',I6,' COLUMN ',I6,' HAS ',   &
                             'THE VALUE ',E15.7)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8005)J,K,AMAT(J,K)
                      CALL DPWRST('XXX','BUG ')
                      IERROR='YES'
                      GO TO 9000
                    ENDIF
                  ENDIF
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DTEMP=DYM1*DYM2
                  DSUM=DSUM + DTEMP
                  DTEMP=DYM1*DYM1
                  DSUM2=DSUM2 + DTEMP
                  DTEMP=DYM2*DYM2
                  DSUM3=DSUM3 + DTEMP
 5866           CONTINUE
!
                IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDIS')THEN
                  WRITE(ICOUT,15861)I,J,DSUM,DSUM2,DSUM3
15861             FORMAT('I,J,DSUM,DSUM2,DSUM3 = ',2I6,3G15.7)
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                IF(DSUM2.GT.0.0D0 .AND. DSUM3.GT.0.0D0)THEN
                  DTEMP=DSUM/(DSQRT(DSUM2)*DSQRT(DSUM3))
                  AMAT2(I,J)=REAL(DTEMP)
                  IF(ICASE2.EQ.'COSD')THEN
                    AMAT2(I,J)=1.0 - AMAT2(I,J)
                  ELSEIF(ICASE2.EQ.'ACSD')THEN
                    AFACT=1.0
                    IF(IFLAG.EQ.1)AFACT=2.0
                    AMAT2(I,J)=AFACT*ACOS(AMAT2(I,J))/PI
                  ELSEIF(ICASE2.EQ.'ACSS')THEN
                    AFACT=1.0
                    IF(IFLAG.EQ.1)AFACT=2.0
                    AMAT2(I,J)=1.0 - AFACT*ACOS(AMAT2(I,J))/PI
                  ENDIF
                ELSE
                  AMAT2(I,J)=CPUMIN
                ENDIF
              ENDIF
            ELSEIF(ICASE2.EQ.'JACS' .OR. ICASE2.EQ.'JACD')THEN
              IF(I.EQ.J)THEN
                IF(ICASE2.EQ.'JASD')THEN
                  AMAT2(I,J)=0.0
                ELSE
                  AMAT2(I,J)=1.0
                ENDIF
              ELSE
                DO 5867 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DTEMP=MIN(DYM1,DYM2)
                  DSUM=DSUM + DTEMP
                  DTEMP=MAX(DYM1,DYM2)
                  DSUM2=DSUM2 + DTEMP
 5867           CONTINUE
                AMAT2(I,J)=REAL(DSUM/DSUM2)
                IF(ICASE2.EQ.'JACD')THEN
                  AMAT2(I,J)=1.0 - AMAT2(I,J)
                ENDIF
              ENDIF
            ELSEIF(ICASE2.EQ.'PDIS' .OR. ICASE2.EQ.'PSIM')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
                IF(ICASE2.EQ.'PSIM')AMAT2(I,J)=1.0
              ELSE
                DO 5868 K=1,NC1
                  TEMP1(K)=AMAT(I,K)
                  TEMP2(K)=AMAT(J,K)
 5868           CONTINUE
                CALL CORR(TEMP1,TEMP2,NC1,IWRITE,ACORR,IBUGA3,IERROR)
                AMAT2(I,J)=(1.0 - ACORR)/2.0
                IF(ICASE2.EQ.'PSIM')AMAT2(I,J)=1.0 - AMAT2(I,J)
              ENDIF
            ELSEIF(ICASE2.EQ.'CANB')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5869 K=1,NC1
                  DYM1=AMAT(I,K)
                  DYM2=AMAT(J,K)
                  DSUM=DSUM+DABS(DYM1-DYM2)/   &
                       (DABS(DYM1)+DABS(DYM2))
 5869           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ENDIF
            AMAT2(J,I)=AMAT2(I,J)
 5861     CONTINUE
 5860   CONTINUE
      ELSEIF(ICASE.EQ.'COLU')THEN
        DO 5960 I=1,NC1
          DO 5961 J=1,I
            DSUM=0.0D0
            DSUM2=0.0D0
            DSUM3=0.0D0
            IF(ICASE2.EQ.'EUCL')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5962 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DSUM=DSUM+(DYM1-DYM2)**2
 5962           CONTINUE
                AMAT2(I,J)=REAL(DSQRT(DSUM))
              ENDIF
            ELSEIF(ICASE2.EQ.'MINK')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5963 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DSUM=DSUM + DABS(DYM1-DYM2)**DBLE(P)
 5963           CONTINUE
                AMAT2(I,J)=REAL(DSUM**(1.0D0/DBLE(P)))
              ENDIF
            ELSEIF(ICASE2.EQ.'BLOC')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5964 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DSUM=DSUM+DABS(DYM1-DYM2)
 5964           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'HAMM')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 55969 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  IF(DYM1.NE.DYM2)DSUM=DSUM+1.0D0
55969           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'CHEB')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5965 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DTEMP=DABS(DYM1-DYM2)
                  IF(DTEMP.GT.DSUM)DSUM=DTEMP
 5965           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ELSEIF(ICASE2.EQ.'COSS' .OR. ICASE2.EQ.'COSD' .OR.   &
                   ICASE2.EQ.'ACSS' .OR. ICASE2.EQ.'ACSD')THEN
              IF(I.EQ.J)THEN
                IF(ICASE2.EQ.'COSD' .OR. ICASE2.EQ.'ACSD')THEN
                  AMAT2(I,J)=0.0
                ELSE
                  AMAT2(I,J)=1.0
                ENDIF
              ELSE
                IFLAG=1
                DO 5966 K=1,NR1
                  IF(ICASE2.EQ.'COSD')THEN
                    IF(AMAT(K,I).LT.0.0 .OR. AMAT(K,J).LT.0.0)THEN
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8001)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8003)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8005)K,I,AMAT(K,I)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,8005)K,J,AMAT(K,J)
                      CALL DPWRST('XXX','BUG ')
                      IERROR='YES'
                      GO TO 9000
                    ENDIF
                  ENDIF
                  IF(AMAT(K,I).LT.0.0)IFLAG=0
                  IF(AMAT(K,J).LT.0.0)IFLAG=0
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DTEMP=DYM1*DYM2
                  DSUM=DSUM + DTEMP
                  DTEMP=DYM1*DYM1
                  DSUM2=DSUM2 + DTEMP
                  DTEMP=DYM2*DYM2
                  DSUM3=DSUM3 + DTEMP
 5966           CONTINUE
!
                IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDIS')THEN
                  WRITE(ICOUT,15861)I,J,DSUM,DSUM2,DSUM3
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                IF(DSUM2.GT.0.0D0 .AND. DSUM3.GT.0.0D0)THEN
                  DTEMP=DSUM/(SQRT(DSUM2)*SQRT(DSUM3))
                  AMAT2(I,J)=REAL(DTEMP)
                  IF(ICASE2.EQ.'COSD')THEN
                    AMAT2(I,J)=1.0 - AMAT2(I,J)
                  ELSEIF(ICASE2.EQ.'ACSD')THEN
                    AFACT=1.0
                    IF(IFLAG.EQ.1)AFACT=2.0
                    AMAT2(I,J)=AFACT*ACOS(AMAT2(I,J))/PI
                  ELSEIF(ICASE2.EQ.'ACSS')THEN
                    AFACT=1.0
                    IF(IFLAG.EQ.1)AFACT=2.0
                    AMAT2(I,J)=1.0 - AFACT*ACOS(AMAT2(I,J))/PI
                  ENDIF
                ELSE
                  AMAT2(I,J)=CPUMIN
                ENDIF
              ENDIF
            ELSEIF(ICASE2.EQ.'JACS' .OR. ICASE2.EQ.'JACD')THEN
              IF(I.EQ.J)THEN
                IF(ICASE2.EQ.'JACD')THEN
                  AMAT2(I,J)=0.0
                ELSE
                  AMAT2(I,J)=1.0
                ENDIF
              ELSE
                DO 5967 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DTEMP=MIN(DYM1,DYM2)
                  DSUM=DSUM + DTEMP
                  DTEMP=MAX(DYM1,DYM2)
                  DSUM2=DSUM2 + DTEMP
 5967           CONTINUE
                AMAT2(I,J)=REAL(DSUM/DSUM2)
                IF(ICASE2.EQ.'JACD')THEN
                  AMAT2(I,J)=1.0 - AMAT2(I,J)
                ENDIF
              ENDIF
            ELSEIF(ICASE2.EQ.'PDIS' .OR. ICASE2.EQ.'PSIM')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
                IF(ICASE2.EQ.'PSIM')AMAT2(I,J)=1.0
              ELSE
                DO 5968 K=1,NR1
                  TEMP1(K)=AMAT(K,I)
                  TEMP2(K)=AMAT(K,J)
 5968           CONTINUE
                CALL CORR(TEMP1,TEMP2,NR1,IWRITE,ACORR,IBUGA3,IERROR)
                AMAT2(I,J)=(1.0 - ACORR)/2.0
                IF(ICASE2.EQ.'PSIM')AMAT2(I,J)=1.0 - AMAT2(I,J)
              ENDIF
            ELSEIF(ICASE2.EQ.'CANB')THEN
              IF(I.EQ.J)THEN
                AMAT2(I,J)=0.0
              ELSE
                DO 5969 K=1,NR1
                  DYM1=AMAT(K,I)
                  DYM2=AMAT(K,J)
                  DSUM=DSUM+DABS(DYM1-DYM2)/   &
                       (DABS(DYM1)+DABS(DYM2))
 5969           CONTINUE
                AMAT2(I,J)=REAL(DSUM)
              ENDIF
            ENDIF
            AMAT2(J,I)=AMAT2(I,J)
 5961     CONTINUE
 5960   CONTINUE
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)
  811   FORMAT('THE DISTANCE/SIMILARITY MATRIX HAS BEEN CALCULATED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EUCDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 IROW=1,NR1
          DO 9030 ICOL=1,NC1
            WRITE(ICOUT,9022)IROW,ICOL,AMAT2(IROW,ICOL)
 9022       FORMAT('IROW,ICOL,AMAT2(IROW,ICOL) = ',2I6,G15.7)
            CALL DPWRST('XXX','BUG ')
 9030     CONTINUE
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EUCDIS
      SUBROUTINE EUCDI2(Y1,Y2,N,ICASE,P,IWRITE,ADIST,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE EUCLIDEAN DISTANCE BETWEEN
!              TWO VECTORS.  THE FORMULA IS:
!
!                 D=SQRT{SUM[i=1 to n][(Y1(i) - Y2(i))**2)}
!
!              ALTERNATIVELY (BASED ON ICASE), THE FOLLOWING DISTANCES
!              CAN BE COMPUTED:
!
!              MINKOWSKY DISTANCE:
!
!                 D=SUM[i=1 to n][(ABS|(Y1(i) - Y2(i))|**P)**(1/P)]
!
!              BLOCK (OR MANHATTAN) DISTANCE:
!
!                 D=SUM[i=1 to n][|Y1(i) - Y2(i)|]
!
!              CANBERRA DISTANCE:
!
!                 D=SUM[i=1 to n][|Y1(i) - Y2(i)|/
!                       (|Y1(i)| + |Y2(i)|)]
!
!              CHEBYCHEV DISTANCE:
!
!                 D=MAX[i=1 to n][|Y1(i) - Y2(i)|]
!
!              COSINE SIMILARITY:
!
!                 S=SUM[i=1 to n][Y1(i)*Y2(i)]/
!                   {SQRT(SUM[i=1 to n][Y1(i)**2])*
!                   SQRT(SUM[i=1 to n][Y1(i)**2])}
!
!              COSINE DISTANCE:
!
!                 D = 1 - COSINE SIMILARITY
!
!              ANGULAR COSINE DISTANCE:
!
!                 D = 1 - COSINE SIMILARITY
!
!              JACCARD SIMILARITY:
!
!                 J = SUM[i=1 to n][MIN(Y1(i),Y2(i))/
!                     SUM[i=1 to n][MAX(Y1(ik),Y2(i))]
!
!              JACCARD DISTANCE:
!
!                 D = 1 - JACCARD SIMILARITY
!
!              HAMMING DISTANCE:
!
!                 D = NUMBER OF ELEMENTS THAT DIFFER IN Y1 AND Y2
!
!              PEARSON DISTANCE:
!
!                 D = (1 - R)/2  (R = CORRELATION COEFFICIENT)
!
!              PEARSON SIMILARITY:
!
!                 S = 1 - PEARSON DISTANCE
!
!              THIS IS A VARIANT OF EUCDIS.  THE DISTINCTION IS THAT
!              THIS ROUTINE WORKS ON TWO VECTORS WHILE EUCDIS WORKS WITH
!              A MATRIX.
!     INPUT  ARGUMENTS--Y1     = A SINGLE PRECISION VECTOR
!                     --Y2     = A SINGLE PRECISION VECTOR
!                     --N      = THE INTEGER NUMBER OF ROWS IN Y1 AND Y2
!     OUTPUT ARGUMENTS--ADIST  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED DISTANCE.
!     OUTPUT--A SCALAR VALUE CONTAINING THE DISTANCE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024/07
!     ORIGINAL VERSION--JULY      2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DYM1
      DOUBLE PRECISION DYM2
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EUCD'
      ISUBN2='I2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EUCDI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,ICASE,ICASE,N
   52   FORMAT('ISUBRO,IBUGA3,ICASE,ICASE,N = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,N
          WRITE(ICOUT,62)I,Y1(I),Y2(I)
   62     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!               ********************************
!               **  COMPUTE DISTANCE           *
!               ********************************
!
      DSUM=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      ADIST=CPUMIN
!
      IF(ICASE.EQ.'EUC')THEN
        DO 5962 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DSUM=DSUM+(DYM1-DYM2)**2
 5962   CONTINUE
        ADIST=REAL(DSQRT(DSUM))
      ELSEIF(ICASE.EQ.'MINK')THEN
        DO 5963 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DSUM=DSUM + DABS(DYM1-DYM2)**DBLE(P)
 5963   CONTINUE
        ADIST=REAL(DSUM**(1.0D0/DBLE(P)))
      ELSEIF(ICASE.EQ.'BLOC')THEN
        DO 5964 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DSUM=DSUM+DABS(DYM1-DYM2)
 5964   CONTINUE
        ADIST=REAL(DSUM)
      ELSEIF(ICASE.EQ.'HAMM')THEN
        DO 55969 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          IF(DYM1.NE.DYM2)DSUM=DSUM+1.0D0
55969   CONTINUE
        ADIST=REAL(DSUM)
      ELSEIF(ICASE.EQ.'CHEB')THEN
        DO 5965 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DTEMP=DABS(DYM1-DYM2)
          IF(DTEMP.GT.DSUM)DSUM=DTEMP
 5965   CONTINUE
        ADIST=REAL(DSUM)
      ELSEIF(ICASE.EQ.'COSS' .OR. ICASE.EQ.'COSD' .OR.   &
             ICASE.EQ.'ACSS' .OR. ICASE.EQ.'ACSD')THEN
        IFLAG=1
        DO 5966 I=1,N
          IF(ICASE.EQ.'COSD')THEN
            IF(Y1(I).LT.0.0 .OR. Y2(I).LT.0.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,8001)
 8001         FORMAT('****** ERROR IN DISTANCE--')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,8003)
 8003         FORMAT('       COSINE DISTANCE NOT SUPPORTED ',   &
                     'FOR NEGATIVE VALUES.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,8005)I,Y1(I),Y2(I)
 8005         FORMAT('        ROW, Y1(I), Y2(I) = ',I6,2G15.7)
              CALL DPWRST('XXX','BUG ')
              IERROR='YES'
              GO TO 9000
            ENDIF
          ENDIF
          IF(Y1(I).LT.0.0)IFLAG=0
          IF(Y2(I).LT.0.0)IFLAG=0
          DYM1=Y1(I)
          DYM2=Y2(I)
          DTEMP=DYM1*DYM2
          DSUM=DSUM + DTEMP
          DTEMP=DYM1*DYM1
          DSUM2=DSUM2 + DTEMP
          DTEMP=DYM2*DYM2
          DSUM3=DSUM3 + DTEMP
 5966   CONTINUE
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDI2')THEN
          WRITE(ICOUT,15861)I,DSUM,DSUM2,DSUM3
15861     FORMAT('I,DSUM,DSUM2,DSUM3 = ',I6,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(DSUM2.GT.0.0D0 .AND. DSUM3.GT.0.0D0)THEN
          DTEMP=DSUM/(SQRT(DSUM2)*SQRT(DSUM3))
          ADIST=REAL(DTEMP)
          IF(ICASE.EQ.'COSD')THEN
            ADIST=1.0 - ADIST
          ELSEIF(ICASE.EQ.'ACSD')THEN
            AFACT=1.0
            IF(IFLAG.EQ.1)AFACT=2.0
            ADIST=AFACT*ACOS(ADIST)/PI
          ELSEIF(ICASE.EQ.'ACSS')THEN
            AFACT=1.0
            IF(IFLAG.EQ.1)AFACT=2.0
            ADIST=1.0 - AFACT*ACOS(ADIST)/PI
          ENDIF
        ELSE
          ADIST=CPUMIN
        ENDIF
      ELSEIF(ICASE.EQ.'JACS' .OR. ICASE.EQ.'JACD')THEN
        DO 5967 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DTEMP=MIN(DYM1,DYM2)
          DSUM=DSUM + DTEMP
          DTEMP=MAX(DYM1,DYM2)
          DSUM2=DSUM2 + DTEMP
 5967   CONTINUE
        ADIST=REAL(DSUM/DSUM2)
        IF(ICASE.EQ.'JACD')THEN
          ADIST=1.0 - ADIST
        ENDIF
      ELSEIF(ICASE.EQ.'PDIS' .OR. ICASE.EQ.'PSIM')THEN
        CALL CORR(Y1,Y2,N,IWRITE,ACORR,IBUGA3,IERROR)
        ADIST=(1.0 - ACORR)/2.0
        IF(ICASE.EQ.'PSIM')ADIST=1.0 - ADIST
      ELSEIF(ICASE.EQ.'CANB')THEN
        DO 5969 I=1,N
          DYM1=Y1(I)
          DYM2=Y2(I)
          DSUM=DSUM+DABS(DYM1-DYM2)/(DABS(DYM1)+DABS(DYM2))
 5969   CONTINUE
        ADIST=REAL(DSUM)
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)ADIST
  811   FORMAT('THE COMPUTED DISTANCE = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CDI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EUCDI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,ADIST
 9012   FORMAT('IERROR,ADIST = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE EUCDI2
      SUBROUTINE EULERB(N,EN)
!
!       ======================================
!       Purpose: Compute Euler number En
!       Input :  n --- Serial number
!       Output:  EN(n) --- En
!       ======================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
        DIMENSION EN(0:N)
!
        HPI=2.0D0/3.141592653589793D0
        DO 1 I=0,N
          EN(I)=0.0D0
 1      CONTINUE
!
        EN(0)=1.0D0
        EN(2)=-1.0D0
        IF(N.LE.3)RETURN
        R1=-4.0D0*HPI**3
!
        IFLAG=0
!
        DO 20 M=4,N,2
           IF(IFLAG.EQ.1)THEN
             EN(M)=DBLE(CPUMAX)
             GO TO 20
           ENDIF
           R1=-R1*(M-1)*M*HPI*HPI
           R2=1.0D0
!CCCC      ISGN=1.0D0
           ISGN=1
           DO 10 K=3,1000,2
              ISGN=-ISGN
              S=(1.0D0/K)**(M+1)
              R2=R2+ISGN*S
              IF (S.LT.1.0D-15) GO TO  29
10         CONTINUE
29         CONTINUE
           EN(M)=R1*R2
           IF(EN(M).GE.DBLE(CPUMAX))THEN
             IFLAG=1
             EN(M)=DBLE(CPUMAX)
             WRITE(ICOUT,90)M
             CALL DPWRST('XXX','BUG ')
90           FORMAT('***** EULER NUMBERS: OVERFLOW AT N = ',I8)
           ENDIF
20      CONTINUE
!
        RETURN
        END
      SUBROUTINE EULERP(X,N,EN)
!
!       ======================================
!       Purpose: Compute Euler polynomial of order n for X
!       Input :  n --- Order of Euler polynomial
!                x --- value at which to compute the polynomial
!       Output:  EN--- computed value
!       ======================================
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      DIMENSION DTEMP(200)
!
      INCLUDE 'DPCOP2.INC'
!
      SUM=0.0D0
      DO 100 I=0,N/2
        CALL EULERB(2*I,DTEMP)
        TERM2=DTEMP(2*I+1)
        TERM1=DBINOM(N,2*I)
        IF(X-0.5D0.EQ.0.0D0 .AND. N-2*I.EQ.0)THEN
          TERM3=1.0D0
        ELSE
          TERM3=(X-0.5D0)**(N-2*I)
        ENDIF
        SUM=SUM + TERM1*TERM2*TERM3/DBLE(2**(2*I))
  100 CONTINUE
      EN=SUM
!
      RETURN
      END SUBROUTINE EULERP
      SUBROUTINE EXCHNG (X, M, Y, N, SX, SY)
!
!        ALGORITHM AS 304.2 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Exchanges the sample data.  Assumes both X and Y have been
!        previously dimensioned to at least max(M, N) elements
!
!        DATAPLOT NOTE: UTILITY ROUTINE USED BY THE FISHER TWO SAMPLE
!                       RANDOMIZATION TEST
!
      INTEGER M, N
      REAL X(*), Y(*), SX, SY
!
      INTEGER C, K
      REAL TEMP
!
      TEMP = SX
      SX = SY
      SY = TEMP
!
      C = MIN(M, N)
      DO 10 K = 1, C
         TEMP = X(K)
         X(K) = Y(K)
         Y(K) = TEMP
   10 CONTINUE
      IF (M .GT. N) THEN
         DO 20 K = C+1, M
            Y(K) = X(K)
   20    CONTINUE
         N = M
         M = C
      ELSE IF (M .LT. N) THEN
         DO 30 K = C+1, N
            X(K) = Y(K)
   30    CONTINUE
         M = N
         N = C
      END IF
!
      RETURN
      END SUBROUTINE EXCHNG 
      SUBROUTINE EXINT (X, N, KODE, M, TOL, EN, NZ, IERR)
!***BEGIN PROLOGUE  EXINT
!***PURPOSE  Compute an M member sequence of exponential integrals
!            E(N+K,X), K=0,1,...,M-1 for N .GE. 1 and X .GE. 0.
!***LIBRARY   SLATEC
!***CATEGORY  C5
!***TYPE      SINGLE PRECISION (EXINT-S, DEXINT-D)
!***KEYWORDS  EXPONENTIAL INTEGRAL, SPECIAL FUNCTIONS
!***AUTHOR  Amos, D. E., (SNLA)
!***DESCRIPTION
!
!         EXINT computes M member sequences of exponential integrals
!         E(N+K,X), K=0,1,...,M-1 for N .GE. 1 and X .GE. 0.  The
!         exponential integral is defined by
!
!         E(N,X)=integral on (1,infinity) of EXP(-XT)/T**N
!
!         where X=0.0 and N=1 cannot occur simultaneously.  Formulas
!         and notation are found in the NBS Handbook of Mathematical
!         Functions (ref. 1).
!
!         The power series is implemented for X .LE. XCUT and the
!         confluent hypergeometric representation
!
!                     E(A,X) = EXP(-X)*(X**(A-1))*U(A,A,X)
!
!         is computed for X .GT. XCUT.  Since sequences are computed in
!         a stable fashion by recurring away from X, A is selected as
!         the integer closest to X within the constraint N .LE. A .LE.
!         N+M-1.  For the U computation, A is further modified to be the
!         nearest even integer.  Indices are carried forward or
!         backward by the two term recursion relation
!
!                     K*E(K+1,X) + X*E(K,X) = EXP(-X)
!
!         once E(A,X) is computed.  The U function is computed by means
!         of the backward recursive Miller algorithm applied to the
!         three term contiguous relation for U(A+K,A,X), K=0,1,...
!         This produces accurate ratios and determines U(A+K,A,X), and
!         hence E(A,X), to within a multiplicative constant C.
!         Another contiguous relation applied to C*U(A,A,X) and
!         C*U(A+1,A,X) gets C*U(A+1,A+1,X), a quantity proportional to
!         E(A+1,X).  The normalizing constant C is obtained from the
!         two term recursion relation above with K=A.
!
!     Description of Arguments
!
!         Input
!           X       X .GT. 0.0 for N=1 and  X .GE. 0.0 for N .GE. 2
!           N       order of the first member of the sequence, N .GE. 1
!                   (X=0.0 and N=1 is an error)
!           KODE    a selection parameter for scaled values
!                   KODE=1   returns        E(N+K,X), K=0,1,...,M-1.
!                       =2   returns EXP(X)*E(N+K,X), K=0,1,...,M-1.
!           M       number of exponential integrals in the sequence,
!                   M .GE. 1
!           TOL     relative accuracy wanted, ETOL .LE. TOL .LE. 0.1
!                   ETOL = single precision unit roundoff = R1MACH(4)
!
!         Output
!           EN      a vector of dimension at least M containing values
!                   EN(K) = E(N+K-1,X) or EXP(X)*E(N+K-1,X), K=1,M
!                   depending on KODE
!           NZ      underflow indicator
!                   NZ=0   a normal return
!                   NZ=M   X exceeds XLIM and an underflow occurs.
!                          EN(K)=0.0E0 , K=1,M returned on KODE=1
!           IERR    error flag
!                   IERR=0, normal return, computation completed
!                   IERR=1, input error,   no computation
!                   IERR=2, error,         no computation
!                           algorithm termination condition not met
!
!***REFERENCES  M. Abramowitz and I. A. Stegun, Handbook of
!                 Mathematical Functions, NBS AMS Series 55, U.S. Dept.
!                 of Commerce, 1955.
!               D. E. Amos, Computation of exponential integrals, ACM
!                 Transactions on Mathematical Software 6, (1980),
!                 pp. 365-377 and pp. 420-428.
!***ROUTINES CALLED  I1MACH, PSIXN, R1MACH
!***REVISION HISTORY  (YYMMDD)
!   800501  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   910408  Updated the REFERENCES section.  (WRB)
!   920207  Updated with code with a revision date of 880811 from
!           D. Amos.  Included correction of argument list.  (WRB)
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  EXINT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      REAL             A,AA,AAMS,AH,AK,AT,B,BK,BT,CC,CNORM,CT,EM,EMX,EN,   &
                       ETOL,FNM,FX,PT,P1,P2,S,TOL,TX,X,XCUT,XLIM,XTOL,Y,   &
                       YT,Y1,Y2
      REAL             PSIXN
      INTEGER I,IC,ICASE,ICT,IERR,IK,IND,IX,I1M,JSET,K,KK,KN,KODE,KS,M,   &
              ML,MU,N,ND,NM,NZ
      DIMENSION EN(*), A(99), B(99), Y(2)
!***FIRST EXECUTABLE STATEMENT  EXINT
      IERR = 0
      NZ = 0
      ML = 0
      ETOL = MAX(R1MACH(4),0.5E-18)
      IF (X.LT.0.0E0) IERR = 1
      IF (N.LT.1) IERR = 1
      IF (KODE.LT.1 .OR. KODE.GT.2) IERR = 1
      IF (M.LT.1) IERR = 1
      IF (TOL.LT.ETOL .OR. TOL.GT.0.1E0) IERR = 1
      IF (X.EQ.0.0E0 .AND. N.EQ.1) IERR = 1
      IF (IERR.NE.0) RETURN
      I1M = -I1MACH(12)
      PT = 2.3026E0*R1MACH(5)*I1M
      XLIM = PT - 6.907755E0
      BT = PT + (N+M-1)
      IF (BT.GT.1000.0E0) XLIM = PT - LOG(BT)
!
      XCUT = 2.0E0
      IF (ETOL.GT.2.0E-7) XCUT = 1.0E0
      IF (X.GT.XCUT) GO TO 100
      IF (X.EQ.0.0E0 .AND. N.GT.1) GO TO 80
!-----------------------------------------------------------------------
!     SERIES FOR E(N,X) FOR X.LE.XCUT
!-----------------------------------------------------------------------
      TX = X + 0.5E0
      IX = INT(TX)
!-----------------------------------------------------------------------
!     ICASE=1 MEANS INTEGER CLOSEST TO X IS 2 AND N=1
!     ICASE=2 MEANS INTEGER CLOSEST TO X IS 0,1, OR 2 AND N.GE.2
!-----------------------------------------------------------------------
      ICASE = 2
      IF (IX.GT.N) ICASE = 1
      NM = N - ICASE + 1
      ND = NM + 1
      IND = 3 - ICASE
      MU = M - IND
      ML = 1
      KS = ND
      FNM = NM
      S = 0.0E0
      XTOL = 3.0E0*TOL
      IF (ND.EQ.1) GO TO 10
      XTOL = 0.3333E0*TOL
      S = 1.0E0/FNM
   10 CONTINUE
      AA = 1.0E0
      AK = 1.0E0
      IC = 35
      IF (X.LT.ETOL) IC = 1
      DO 50 I=1,IC
        AA = -AA*X/AK
        IF (I.EQ.NM) GO TO 30
        S = S - AA/(AK-FNM)
        IF (ABS(AA).LE.XTOL*ABS(S)) GO TO 20
        AK = AK + 1.0E0
        GO TO 50
   20   CONTINUE
        IF (I.LT.2) GO TO 40
        IF (ND-2.GT.I .OR. I.GT.ND-1) GO TO 60
        AK = AK + 1.0E0
        GO TO 50
   30   S = S + AA*(-LOG(X)+PSIXN(ND))
        XTOL = 3.0E0*TOL
   40   AK = AK + 1.0E0
   50 CONTINUE
      IF (IC.NE.1) GO TO 340
   60 IF (ND.EQ.1) S = S + (-LOG(X)+PSIXN(1))
      IF (KODE.EQ.2) S = S*EXP(X)
      EN(1) = S
      EMX = 1.0E0
      IF (M.EQ.1) GO TO 70
      EN(IND) = S
      AA = KS
      IF (KODE.EQ.1) EMX = EXP(-X)
      GO TO (220, 240), ICASE
   70 IF (ICASE.EQ.2) RETURN
      IF (KODE.EQ.1) EMX = EXP(-X)
      EN(1) = (EMX-S)/X
      RETURN
   80 CONTINUE
      DO 90 I=1,M
        EN(I) = 1.0E0/(N+I-2)
   90 CONTINUE
      RETURN
!-----------------------------------------------------------------------
!     BACKWARD RECURSIVE MILLER ALGORITHM FOR
!              E(N,X)=EXP(-X)*(X**(N-1))*U(N,N,X)
!     WITH RECURSION AWAY FROM N=INTEGER CLOSEST TO X.
!     U(A,B,X) IS THE SECOND CONFLUENT HYPERGEOMETRIC FUNCTION
!-----------------------------------------------------------------------
  100 CONTINUE
      EMX = 1.0E0
      IF (KODE.EQ.2) GO TO 130
      IF (X.LE.XLIM) GO TO 120
      NZ = M
      DO 110 I=1,M
        EN(I) = 0.0E0
  110 CONTINUE
      RETURN
  120 EMX = EXP(-X)
  130 CONTINUE
      IX = INT(X+0.5E0)
      KN = N + M - 1
      IF (KN.LE.IX) GO TO 140
      IF (N.LT.IX .AND. IX.LT.KN) GO TO 170
      IF (N.GE.IX) GO TO 160
      GO TO 340
  140 ICASE = 1
      KS = KN
      ML = M - 1
      MU = -1
      IND = M
      IF (KN.GT.1) GO TO 180
  150 KS = 2
      ICASE = 3
      GO TO 180
  160 ICASE = 2
      IND = 1
      KS = N
      MU = M - 1
      IF (N.GT.1) GO TO 180
      IF (KN.EQ.1) GO TO 150
      IX = 2
  170 ICASE = 1
      KS = IX
      ML = IX - N
      IND = ML + 1
      MU = KN - IX
  180 CONTINUE
      IK = KS/2
      AH = IK
      JSET = 1 + KS - (IK+IK)
!-----------------------------------------------------------------------
!     START COMPUTATION FOR
!              EN(IND) = C*U( A , A ,X)    JSET=1
!              EN(IND) = C*U(A+1,A+1,X)    JSET=2
!     FOR AN EVEN INTEGER A.
!-----------------------------------------------------------------------
      IC = 0
      AA = AH + AH
      AAMS = AA - 1.0E0
      AAMS = AAMS*AAMS
      TX = X + X
      FX = TX + TX
      AK = AH
      XTOL = TOL
      IF (TOL.LE.1.0E-3) XTOL = 20.0E0*TOL
      CT = AAMS + FX*AH
      EM = (AH+1.0E0)/((X+AA)*XTOL*SQRT(CT))
      BK = AA
      CC = AH*AH
!-----------------------------------------------------------------------
!     FORWARD RECURSION FOR P(IC),P(IC+1) AND INDEX IC FOR BACKWARD
!     RECURSION
!-----------------------------------------------------------------------
      P1 = 0.0E0
      P2 = 1.0E0
  190 CONTINUE
      IF (IC.EQ.99) GO TO 340
      IC = IC + 1
      AK = AK + 1.0E0
      AT = BK/(BK+AK+CC+IC)
      BK = BK + AK + AK
      A(IC) = AT
      BT = (AK+AK+X)/(AK+1.0E0)
      B(IC) = BT
      PT = P2
      P2 = BT*P2 - AT*P1
      P1 = PT
      CT = CT + FX
      EM = EM*AT*(1.0E0-TX/CT)
      IF (EM*(AK+1.0E0).GT.P1*P1) GO TO 190
      ICT = IC
      KK = IC + 1
      BT = TX/(CT+FX)
      Y2 = (BK/(BK+CC+KK))*(P1/P2)*(1.0E0-BT+0.375E0*BT*BT)
      Y1 = 1.0E0
!-----------------------------------------------------------------------
!     BACKWARD RECURRENCE FOR
!              Y1=             C*U( A ,A,X)
!              Y2= C*(A/(1+A/2))*U(A+1,A,X)
!-----------------------------------------------------------------------
      DO 200 K=1,ICT
        KK = KK - 1
        YT = Y1
        Y1 = (B(KK)*Y1-Y2)/A(KK)
        Y2 = YT
  200 CONTINUE
!-----------------------------------------------------------------------
!     THE CONTIGUOUS RELATION
!              X*U(B,C+1,X)=(C-B)*U(B,C,X)+U(B-1,C,X)
!     WITH  B=A+1 , C=A IS USED FOR
!              Y(2) = C * U(A+1,A+1,X)
!     X IS INCORPORATED INTO THE NORMALIZING RELATION
!-----------------------------------------------------------------------
      PT = Y2/Y1
      CNORM = 1.0E0 - PT*(AH+1.0E0)/AA
      Y(1) = 1.0E0/(CNORM*AA+X)
      Y(2) = CNORM*Y(1)
      IF (ICASE.EQ.3) GO TO 210
      EN(IND) = EMX*Y(JSET)
      IF (M.EQ.1) RETURN
      AA = KS
      GO TO (220, 240), ICASE
!-----------------------------------------------------------------------
!     RECURSION SECTION  N*E(N+1,X) + X*E(N,X)=EMX
!-----------------------------------------------------------------------
  210 EN(1) = EMX*(1.0E0-Y(1))/X
      RETURN
  220 K = IND - 1
      DO 230 I=1,ML
        AA = AA - 1.0E0
        EN(K) = (EMX-AA*EN(K+1))/X
        K = K - 1
  230 CONTINUE
      IF (MU.LE.0) RETURN
      AA = KS
  240 K = IND
      DO 250 I=1,MU
        EN(K+1) = (EMX-X*EN(K))/AA
        AA = AA + 1.0E0
        K = K + 1
  250 CONTINUE
      RETURN
  340 CONTINUE
      IERR = 2
      RETURN
      END SUBROUTINE EXINT 
      DOUBLE PRECISION FUNCTION erfdp(x)
!CCCC RENAME TO AVOID CONFLICT WITH INTRINSIC "ERF" ROUTINE
!CCCC DOUBLE PRECISION FUNCTION erf(x)
!-----------------------------------------------------------------------
!             EVALUATION OF THE REAL ERROR FUNCTION
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION ax,bot,c,t,top,x2
!     ..
!     .. Local Arrays ..
      DOUBLE PRECISION a(5),b(3),p(8),q(8),r(5),s(4)
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,exp,sign
!     ..
!     .. Data statements ..
!-------------------------
!-------------------------
!-------------------------
!-------------------------
      DATA c/.564189583547756D0/
      DATA a(1)/.771058495001320D-04/,a(2)/-.133733772997339D-02/,   &
           a(3)/.323076579225834D-01/,a(4)/.479137145607681D-01/,   &
           a(5)/.128379167095513D+00/
      DATA b(1)/.301048631703895D-02/,b(2)/.538971687740286D-01/,   &
           b(3)/.375795757275549D+00/
      DATA p(1)/-1.36864857382717D-07/,p(2)/5.64195517478974D-01/,   &
           p(3)/7.21175825088309D+00/,p(4)/4.31622272220567D+01/,   &
           p(5)/1.52989285046940D+02/,p(6)/3.39320816734344D+02/,   &
           p(7)/4.51918953711873D+02/,p(8)/3.00459261020162D+02/
      DATA q(1)/1.00000000000000D+00/,q(2)/1.27827273196294D+01/,   &
           q(3)/7.70001529352295D+01/,q(4)/2.77585444743988D+02/,   &
           q(5)/6.38980264465631D+02/,q(6)/9.31354094850610D+02/,   &
           q(7)/7.90950925327898D+02/,q(8)/3.00459260956983D+02/
      DATA r(1)/2.10144126479064D+00/,r(2)/2.62370141675169D+01/,   &
           r(3)/2.13688200555087D+01/,r(4)/4.65807828718470D+00/,   &
           r(5)/2.82094791773523D-01/
      DATA s(1)/9.41537750555460D+01/,s(2)/1.87114811799590D+02/,   &
           s(3)/9.90191814623914D+01/,s(4)/1.80124575948747D+01/
!     ..
!     .. Executable Statements ..
!-------------------------
      ax = abs(x)
      IF (ax.GT.0.5D0) GO TO 10
      t = x*x
      top = ((((a(1)*t+a(2))*t+a(3))*t+a(4))*t+a(5)) + 1.0D0
      bot = ((b(1)*t+b(2))*t+b(3))*t + 1.0D0
      erfdp = x* (top/bot)
      RETURN
!
   10 IF (ax.GT.4.0D0) GO TO 20
      top = ((((((p(1)*ax+p(2))*ax+p(3))*ax+p(4))*ax+p(5))*ax+p(6))*ax+   &
            p(7))*ax + p(8)
      bot = ((((((q(1)*ax+q(2))*ax+q(3))*ax+q(4))*ax+q(5))*ax+q(6))*ax+   &
            q(7))*ax + q(8)
      erfdp = 0.5D0 + (0.5D0-exp(-x*x)*top/bot)
      IF (x.LT.0.0D0) erfdp = -erfdp
      RETURN
!
   20 IF (ax.GE.5.8D0) GO TO 30
      x2 = x*x
      t = 1.0D0/x2
      top = (((r(1)*t+r(2))*t+r(3))*t+r(4))*t + r(5)
      bot = (((s(1)*t+s(2))*t+s(3))*t+s(4))*t + 1.0D0
      erfdp = (c-top/ (x2*bot))/ax
      erfdp = 0.5D0 + (0.5D0-exp(-x2)*erfdp)
      IF (x.LT.0.0D0) erfdp = -erfdp
      RETURN
!
   30 erfdp = sign(1.0D0,x)
      RETURN
      END FUNCTION erfdp
      DOUBLE PRECISION FUNCTION erfc1(ind,x)
!-----------------------------------------------------------------------
!         EVALUATION OF THE COMPLEMENTARY ERROR FUNCTION
!
!          ERFC1(IND,X) = ERFC(X)            IF IND = 0
!          ERFC1(IND,X) = EXP(X*X)*ERFC(X)   OTHERWISE
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION x
      INTEGER ind
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION ax,bot,c,e,t,top,w
!     ..
!     .. Local Arrays ..
      DOUBLE PRECISION a(5),b(3),p(8),q(8),r(5),s(4)
!     ..
!     .. External Functions ..
      DOUBLE PRECISION exparg
      EXTERNAL exparg
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dble,exp
!     ..
!     .. Data statements ..
!-------------------------
!-------------------------
!-------------------------
!-------------------------
      DATA c/.564189583547756D0/
      DATA a(1)/.771058495001320D-04/,a(2)/-.133733772997339D-02/,   &
           a(3)/.323076579225834D-01/,a(4)/.479137145607681D-01/,   &
           a(5)/.128379167095513D+00/
      DATA b(1)/.301048631703895D-02/,b(2)/.538971687740286D-01/,   &
           b(3)/.375795757275549D+00/
      DATA p(1)/-1.36864857382717D-07/,p(2)/5.64195517478974D-01/,   &
           p(3)/7.21175825088309D+00/,p(4)/4.31622272220567D+01/,   &
           p(5)/1.52989285046940D+02/,p(6)/3.39320816734344D+02/,   &
           p(7)/4.51918953711873D+02/,p(8)/3.00459261020162D+02/
      DATA q(1)/1.00000000000000D+00/,q(2)/1.27827273196294D+01/,   &
           q(3)/7.70001529352295D+01/,q(4)/2.77585444743988D+02/,   &
           q(5)/6.38980264465631D+02/,q(6)/9.31354094850610D+02/,   &
           q(7)/7.90950925327898D+02/,q(8)/3.00459260956983D+02/
      DATA r(1)/2.10144126479064D+00/,r(2)/2.62370141675169D+01/,   &
           r(3)/2.13688200555087D+01/,r(4)/4.65807828718470D+00/,   &
           r(5)/2.82094791773523D-01/
      DATA s(1)/9.41537750555460D+01/,s(2)/1.87114811799590D+02/,   &
           s(3)/9.90191814623914D+01/,s(4)/1.80124575948747D+01/
!     ..
!     .. Executable Statements ..
!-------------------------
!
!                     ABS(X) .LE. 0.5
!
      ax = abs(x)
      IF (ax.GT.0.5D0) GO TO 10
      t = x*x
      top = ((((a(1)*t+a(2))*t+a(3))*t+a(4))*t+a(5)) + 1.0D0
      bot = ((b(1)*t+b(2))*t+b(3))*t + 1.0D0
      erfc1 = 0.5D0 + (0.5D0-x* (top/bot))
      IF (ind.NE.0) erfc1 = exp(t)*erfc1
      RETURN
!
!                  0.5 .LT. ABS(X) .LE. 4
!
   10 IF (ax.GT.4.0D0) GO TO 20
      top = ((((((p(1)*ax+p(2))*ax+p(3))*ax+p(4))*ax+p(5))*ax+p(6))*ax+   &
            p(7))*ax + p(8)
      bot = ((((((q(1)*ax+q(2))*ax+q(3))*ax+q(4))*ax+q(5))*ax+q(6))*ax+   &
            q(7))*ax + q(8)
      erfc1 = top/bot
      GO TO 40
!
!                      ABS(X) .GT. 4
!
   20 IF (x.LE.-5.6D0) GO TO 60
      IF (ind.NE.0) GO TO 30
      IF (x.GT.100.0D0) GO TO 70
      IF (x*x.GT.-exparg(1)) GO TO 70
!
   30 t = (1.0D0/x)**2
      top = (((r(1)*t+r(2))*t+r(3))*t+r(4))*t + r(5)
      bot = (((s(1)*t+s(2))*t+s(3))*t+s(4))*t + 1.0D0
      erfc1 = (c-t*top/bot)/ax
!
!                      FINAL ASSEMBLY
!
   40 IF (ind.EQ.0) GO TO 50
      IF (x.LT.0.0D0) erfc1 = 2.0D0*exp(x*x) - erfc1
      RETURN
                                                                                                                                  
   50 w = dble(x)*dble(x)
      t = w
      e = w - dble(t)
      erfc1 = ((0.5D0+ (0.5D0-e))*exp(-t))*erfc1
      IF (x.LT.0.0D0) erfc1 = 2.0D0 - erfc1
      RETURN
!
!             LIMIT VALUE FOR LARGE NEGATIVE X
!
   60 erfc1 = 2.0D0
      IF (ind.NE.0) erfc1 = 2.0D0*exp(x*x)
      RETURN
!
!             LIMIT VALUE FOR LARGE POSITIVE X
!                       WHEN IND = 0
!
   70 erfc1 = 0.0D0
      RETURN
                                                                                                                                  
      END FUNCTION erfc1
      SUBROUTINE ERRCDF(X,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE ERROR (OR EXPONENTIAL POWER OR
!              GENERAL ERROR OR SUBBOTIN) DISTRIBUTION.  NOTE THAT
!              THERE ARE SEVERAL DIFFERENT PARAMETERIZATIONS OF
!              THIS DISTRIBUTION.  WE USE THE ONE FROM THE
!              TADIKAMALLA PAPER (SEE REFERENCE BELOW).  SPECIFICALLY,
!              THE PDF IS:
!              F(X,ALPHA)=EXP(-|X|**ALPHA)/[2*ALPHA(1+1/ALPHA)]
!                         -INFINITY < X < INFINITY, ALPHA >= 1
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!              AT THE VALUE ALPHA.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X CAN BE ANY REAL NUMBER
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALPHA SHOULD BE >= 1..
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE >= 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DGAMMA, DGAMI
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--PANDU R. RADIKAMALLA, "RANDOM SAMPLING FROM THE
!                 EXPONENTIAL POWER DISTRIBUTION", JOURNAL OF THE
!                 AMERICAN STATISTICAL ASSOCIATION, SEPTEMBER, 1980,
!                 PAGES 683-686.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION",
!                 WILEY, 1994.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION", WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,DALPHA,DGAMMA,DGAMI,DCDF
      DOUBLE PRECISION DTERM1, DTERM2
      EXTERNAL DGAMI
      EXTERNAL DGAMMA
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL ERROR--THE SHAPE PARAMETER FOR THE ERROR')
   16 FORMAT('      CDF FUNCTION IS LESS THAN ONE.')
   46 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.8)
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
!
!  ALPHA=1 IS DOUBLE EXPONENTIAL
!  ALPHA=2 IS NORMAL
!
      IF(ALPHA.LE.1.00005)THEN
        CALL DEXCDF(X,CDF)
        GO TO 9999
      ELSEIF(ALPHA.EQ.2.0)THEN
        CALL NORCDF(X,CDF)
        GO TO 9999
      ENDIF
!
      IF(X.EQ.0.0)THEN
        CDF=0.5
        GO TO 9999
      ELSEIF(X.GT.0.0)THEN
        DTERM1=-DX*DGAMI(1.0D0/DALPHA,DX**DALPHA)
        DTERM2=2.0D0*DALPHA*(DX**DALPHA)**(1.0D0/DALPHA)*   &
               DGAMMA(1.0D0+1.0D0/DALPHA)
        DCDF=0.5D0 - DTERM1/DTERM2
      ELSE
        DX=-DX
        DTERM1=-DX*DGAMI(1.0D0/DALPHA,DX**DALPHA)
        DTERM2=2.0D0*DALPHA*(DX**DALPHA)**(1.0D0/DALPHA)*   &
               DGAMMA(1.0D0+1.0D0/DALPHA)
        DCDF=0.5D0 + DTERM1/DTERM2
      ENDIF
!
      CDF=REAL(DCDF)
 9999 CONTINUE
      RETURN
      END SUBROUTINE ERRCDF
      SUBROUTINE ERRPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE ERROR (OR EXPONENTIAL POWER OR
!              GENERAL ERROR OR SUBBOTIN) DISTRIBUTION.  NOTE THAT
!              THERE ARE SEVERAL DIFFERENT PARAMETERIZATIONS OF
!              THIS DISTRIBUTION.  WE USE THE ONE FROM THE
!              TADIKAMALLA PAPER (SEE REFERENCE BELOW).  SPECIFICALLY,
!              THE PDF IS:
!              F(X,ALPHA)=EXP(-|X|**ALPHA)/[2*ALPHA(1+1/ALPHA)]
!                         -INFINITY < X < INFINITY, ALPHA >= 1
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!              AT THE VALUE ALPHA.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X CAN BE ANY REAL NUMBER
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALPHA SHOULD BE >= 1..
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE >= 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--PANDU R. RADIKAMALLA, "RANDOM SAMPLING FROM THE
!                 EXPONENTIAL POWER DISTRIBUTION", JOURNAL OF THE
!                 AMERICAN STATISTICAL ASSOCIATION, SEPTEMBER, 1980,
!                 PAGES 683-686.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION",
!                 WILEY, 1994.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION", WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
                                                                                                                                  
      DOUBLE PRECISION DX,DALPHA,DLNGAM,DPDF
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL ERROR--THE SHAPE PARAMETER FOR THE ERROR')
   16 FORMAT('      PDF FUNCTION IS LESS THAN ONE.')
   46 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.8)
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
!
      IF(ALPHA.EQ.1.0)THEN
        CALL DEXPDF(X,PDF)
        GO TO 9999
      ELSEIF(ALPHA.EQ.2.0)THEN
        CALL NORPDF(X,PDF)
        GO TO 9999
      ENDIF
!
      DPDF=-DABS(DX)**DALPHA-DLOG(2.0D0)-DLNGAM(1.0D0+1.0D0/DALPHA)
      IF(DPDF.LT.-80.D0)THEN
        PDF=0.0
      ELSEIF(DPDF.LT.LOG(CPUMAX))THEN
        PDF=REAL(DEXP(DPDF))
      ELSE
        PDF=LOG(CPUMAX)
        WRITE(ICOUT,105)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
  105 FORMAT('****** WARNING--OVERFLOW IN ERRPDF ROUTINE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ERRPDF
      SUBROUTINE ERRPPF(P,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE ERROR (OR EXPONENTIAL POWER OR
!              GENERAL ERROR OR SUBBOTIN) DISTRIBUTION.  NOTE THAT
!              THERE ARE SEVERAL DIFFERENT PARAMETERIZATIONS OF
!              THIS DISTRIBUTION.  WE USE THE ONE FROM THE
!              TADIKAMALLA PAPER (SEE REFERENCE BELOW).  SPECIFICALLY,
!              THE PPF IS:
!              F(X,ALPHA)=EXP(-|X|**ALPHA)/[2*ALPHA(1+1/ALPHA)]
!                         -INFINITY < X < INFINITY, ALPHA >= 1
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!              AT THE VALUE ALPHA.
!              THE PERCENT POINT FUNCTION IS COMPUTED NUMERICALLY
!              USING A BISECTION METHOD.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                X CAN BE ANY REAL NUMBER
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                ALPHA SHOULD BE >= 1..
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE >= 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--PANDU R. RADIKAMALLA, "RANDOM SAMPLING FROM THE
!                 EXPONENTIAL POWER DISTRIBUTION", JOURNAL OF THE
!                 AMERICAN STATISTICAL ASSOCIATION, SEPTEMBER, 1980,
!                 PAGES 683-686.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION",
!                 WILEY, 1994.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION", WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA,DGAMMA
      EXTERNAL DGAMMA
!
      DATA EPS /0.00001/
      DATA SIG /1.0E-6/
      DATA ZERO /0./
      DATA MAXIT /500/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      ASGN=1.0
      PPF=0.0
      IF(P.LE.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALPHA.LT.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE INPUT ARGUMENT FOR THE ERROR')
    6 FORMAT('      PERCENT POINT FUNCTION IS OUTSIDE THE ALLOWABLE ',   &
             '[0,1] INTERVAL.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE ERROR')
   16 FORMAT('      PERCENT POINT FUNCTION IS LESS THAN ONE.')
   46 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      IF(P.EQ.0.5)THEN
        PPF=0.0
        GO TO 9999
      ELSEIF(ALPHA.LE.1.000005)THEN
        CALL DEXPPF(P,PPF)
        GO TO 9999
      ELSEIF(ALPHA.EQ.2.0)THEN
        CALL NORPPF(P,PPF)
        GO TO 9999
      ENDIF
!
      DALPHA=DBLE(ALPHA)
!
!  P = 0.5 IS ZERO.  USE SYMMETRY TO HANDLE P < 0.5 AND P > 0.5
!  CASES WITH SAME CODE (JUST NEED TO CHANGE SIGN OF FINAL PPF
!  VALUE).
!
      ASGN=1.0
      IF(P.LT.0.5)THEN
        P=1.0 - P
        ASGN=-1.0
      ENDIF
!
!  FIND BRACKETING INTERVAL.  BRACKETED ABOVE BY ZERO.  STANDARD
!  DEVIATION = SQRT(GAMMA(3/ALPHA)/GAMMA(1/ALPHA)).
!
      SD=DSQRT(DGAMMA(3.0D0/DALPHA)/DGAMMA(1.0D0/DALPHA))
      XL=0.0D0
      XINC=SD
      ICOUNT=0
      MAXCNT=200
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0)XL=0.0
      IF(XR.LE.0.0)XR=XL+1.0
      CALL ERRCDF(XL,ALPHA,CDFL)
      CALL ERRCDF(XR,ALPHA,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--ERRPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL ERRCDF(X,ALPHA,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--ERRPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
!
 9999 CONTINUE
      PPF=ASGN*PPF
      RETURN
      END SUBROUTINE ERRPPF
      SUBROUTINE ERRRAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ERROR DISTRIBUTION WITH SINGLE PRECISION SHAPE
!              PARAMETER = ALPHA.  THIS DISTRIBUTION IS ALSO REFERRED
!              TO AS THE SUBBOTIN, EXPONENTIAL POWER, OR GENERAL
!              ERROR DISTRIBUTION.  NOTE THAT
!              THERE ARE SEVERAL DIFFERENT PARAMETERIZATIONS OF
!              THIS DISTRIBUTION.  WE USE THE ONE FROM THE
!              TADIKAMALLA PAPER (SEE REFERENCE BELOW).  SPECIFICALLY,
!              THE PDF IS:
!              F(X,ALPHA)=EXP(-|X|**ALPHA)/[2*ALPHA(1+1/ALPHA)]
!                         -INFINITY < X < INFINITY, ALPHA >= 1
!              WITH ALPHA DENOTING THE SHAPE PARAMETER.
!              AT THE VALUE ALPHA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST  SHAPE PARAMETER.
!                                ALPHA SHOULD BE GREATER THAN 1.0.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ERROR DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = ALPHA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE GREATER THAN
!                   OR EQUAL TO 1.0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GAMRAN, DEXRAN,
!                                         GAMRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--PANDU R. RADIKAMALLA, "RANDOM SAMPLING FROM THE
!                 EXPONENTIAL POWER DISTRIBUTION", JOURNAL OF THE
!                 AMERICAN STATISTICAL ASSOCIATION, SEPTEMBER, 1980,
!                 PAGES 683-686.
!               --JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 2, SECOND EDITION",
!                 WILEY, 1994.
!               --EVANS, HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION", WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLARITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2003.5
!     ORIGINAL VERSION--MAY       2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LT.1.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE NUMBER OF REQUESTED ERROR ',   &
      'RANDOM NUMBERS IS NON-POSITIVE.')
   16 FORMAT('***** FATAL ERROR--THE SHAPE PARAMETER FOR THE ',   &
      'ERROR DISTRIBUTION IS LESS THAN 1.0 *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N ERROR RANDOM NUMBERS USING THE ALGORITHM OF
!     RADIKAMALLA.  THIS IS A FORTRAN IMPLEMENTATION OF THE ROUTINE
!     "gsl_ran_exppow" IN THE GNU GSL SCIENTIFIC LIBRARY.
!
      NTEMP=1
!
!  FIRST, HANDLE SPECIAL CASES (ALPHA = 1, 2 ARE DOUBLE EXPONENTIAL
!  AND NORMAL, RESPECTIVELY).
!
      IF(ALPHA.EQ.1.0)THEN
        CALL DEXRAN(N,ISEED,X)
      ELSEIF(ALPHA.EQ.2.0)THEN
        CALL NORRAN(N,ISEED,X)
!
!  CASE WHERE 1 < ALPHA < 2.  USE DOUBLE EXPONENTIAL DISTRIBUTION
!  FOR REJECTION METHOD.
!
      ELSEIF(ALPHA.GT.1.0 .AND. ALPHA.LT.2.0)THEN
        S=1.4489
        DO 390 I=1,N
  300     CONTINUE
            CALL DEXRAN(NTEMP,ISEED,XTEMP)
            AX=XTEMP(1)
            CALL DEXPDF(AX,AY)
            CALL ERRPDF(AX,ALPHA,AH)
            RATIO=AH/(S*AY)
            CALL UNIRAN(NTEMP,ISEED,XTEMP)
            U=XTEMP(1)
          IF(U.GT.RATIO)GO TO 300
          X(I)=AX
  390   CONTINUE
!
!  CASE WHERE ALPHA > 2.  USE GAUSSIAN FOR FOR REJECTION METHOD.
!
      ELSE
        SIGMA=1.0/1.0/SQRT(2.0)
        S=2.4091
        DO 490 I=1,N
  400     CONTINUE
            CALL NORRAN(NTEMP,ISEED,XTEMP)
            AX=SIGMA*XTEMP(1)
            CALL NORPDF(AX/SIGMA,AY)
            AY=AY/SIGMA
            CALL ERRPDF(AX,ALPHA,AH)
            RATIO=AH/(S*AY)
            CALL UNIRAN(NTEMP,ISEED,XTEMP)
            U=XTEMP(1)
          IF(U.GT.RATIO)GO TO 400
          X(I)=AX
  490   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ERRRAN
      SUBROUTINE ERRORF(IANS1,IANS2,IANS3,IANS4,AMIN,AMAX,DEF,   &
      ANS2,IERROR)
!
!     PURPOSE--ANALYZE FLOATING POINT INPUT TERMINAL RESPONSE DURING
!              EXECUTION OF DATAPLOT AND
!              DETERMINE IF VALID.
!              ALSO, MAKE CONVERSION TO FLOATING POINT.
!     INPUT  ARGUMENTS--IANS1
!                     --IANS2
!                     --IANS3
!                     --IANS4
!                     --AMIN
!                     --AMAX
!                     --DEF
!     OUTPUT ARGUMENTS--ANS2
!                     --IERROR
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--OCTOBER 18, 1976.
!     UPDATED         --OCTOBER   1976.
!     UPDATED         --JULY      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS1
      CHARACTER*4 IANS2
      CHARACTER*4 IANS3
      CHARACTER*4 IANS4
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBUG1
      CHARACTER*4 IBUG2
      CHARACTER*4 IA
!
!---------------------------------------------------------------------
!
      DIMENSION IA(20)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ANS2=0
      IERROR='NO'
      IBUG1='OFF'
      IBUG2='OFF'
!
!               ************************************************************
!               **  DEFINE NUMASC = NUMBER OF ASCII CHARACTERS PER WORD.  **
!               **  THIS IS 4 REGARDLESS OF THE COMPUTER MAKE AND         **
!               **  REGARDLESS OF THE WORD SIZE.                          **
!               ************************************************************
!
      NUMASC=4
      NUMAS2=2*NUMASC
      NUMAS3=3*NUMASC
!
!               *******************************
!               **  STEP 1--                 **
!               **  CHECK FOR BLANK ENTRIES  **
!               *******************************
!
      IF(IANS1.EQ.'    '.AND.IANS2.EQ.'    '.AND.IANS3.EQ.'    '.AND.   &
      IANS4.EQ.'    ')GO TO 105
      GO TO 110
  105 CONTINUE
      ANS2=DEF
      IF(AMIN.LE.ANS2.AND.ANS2.LE.AMAX)GO TO 9000
      GO TO 1750
  110 CONTINUE
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  DECOMPOSE THE INPUT WORDS                        **
!               **  IANS1, IANS2, IANS3, AND IANS4                   **
!               **  INTO 16 NUMBPC-BIT CHUNKS                        **
!               **  WHERE NUMBPC = NUMBER OF BITS PER CHARACTER      **
!               **  FOR THIS COMPUTER.                               **
!               **  EACH NUMBPC-BIT CHUNK WILL (BY CONSTRUCTION)     **
!               **  BE STORED                                        **
!               **  IN A LEFT-JUSTIFIED FASHION IN IA(.)             **
!               **  WITH (BY CONSTRUCTION) BLANK-FILL TO THE RIGHT.  **
!               *******************************************************
!
      DO 150 I=1,16
      IA(I)='    '
  150 CONTINUE
      DO 200 I=1,4
      ISTAR3=NUMBPC*(I-1)
      ISTAR3=IABS(ISTAR3)
      I1=I
      I2=I1+NUMASC
      I3=I1+NUMAS2
      I4=I1+NUMAS3
      CALL DPCHEX(ISTAR3,NUMBPC,IANS1,0,NUMBPC,IA(I1))
      CALL DPCHEX(ISTAR3,NUMBPC,IANS2,0,NUMBPC,IA(I2))
      CALL DPCHEX(ISTAR3,NUMBPC,IANS3,0,NUMBPC,IA(I3))
      CALL DPCHEX(ISTAR3,NUMBPC,IANS4,0,NUMBPC,IA(I4))
  200 CONTINUE
      IF(IBUG1.EQ.'OFF')GO TO 350
      DO 300 I=1,16
      WRITE(ICOUT,305)IA(I)
  305 FORMAT(A4)
      CALL DPWRST('XXX','BUG ')
  300 CONTINUE
  350 CONTINUE
!
!               **********************************************
!               **  STEP 3--                                **
!               **  CHECK FOR AN EXIT, END, STOP, OR TERM.  **
!               **********************************************
!
      DO 500 I=1,16
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IF(IA(I).EQ.'E'.AND.IA(IP1).EQ.'X'.AND.IA(IP2).EQ.'I'   &
      .AND.IA(IP3).EQ.'T')GO TO 510
      IF(IA(I).EQ.'E'.AND.IA(IP1).EQ.'N'.AND.IA(IP2).EQ.'D')   &
      GO TO 510
      IF(IA(I).EQ.'S'.AND.IA(IP1).EQ.'T'.AND.IA(IP2).EQ.'O'   &
      .AND.IA(IP3).EQ.'P')GO TO 510
      IF(IA(I).EQ.'T'.AND.IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'R'   &
      .AND.IA(IP3).EQ.'M')GO TO 510
  500 CONTINUE
      GO TO 550
  510 WRITE(ICOUT,520)
  520 FORMAT('THIS IS AN EXIT FROM DATAPLOT ')
      CALL DPWRST('XXX','BUG ')
      STOP
  550 CONTINUE
!
!               *********************************
!               **  STEP 4--                   **
!               **  CONVERT TO FLOATING POINT  **
!               *********************************
!
!               ************************************************************
!               **  STEP 4.1--                                            **
!               **  FIRST OF ALL, LOCATE THE DECIMAL POINT (IF EXISTENT)  **
!               ************************************************************
!
      ILOC=0
      IDECPT=0
      DO 1000 I=1,16
      IF(IA(I).EQ.'.')ILOC=I
      IF(IA(I).EQ.'.')IDECPT=IDECPT+1
 1000 CONTINUE
      IF(IDECPT.GE.2)GO TO 1530
      IF(IDECPT.EQ.1)GO TO 1150
      DO 1100 I=1,16
      IREV=16-I+1
      IF(IA(IREV).EQ.' ')GO TO 1100
      IF(IA(IREV).EQ.'0')GO TO 1110
      IF(IA(IREV).EQ.'1')GO TO 1110
      IF(IA(IREV).EQ.'2')GO TO 1110
      IF(IA(IREV).EQ.'3')GO TO 1110
      IF(IA(IREV).EQ.'4')GO TO 1110
      IF(IA(IREV).EQ.'5')GO TO 1110
      IF(IA(IREV).EQ.'6')GO TO 1110
      IF(IA(IREV).EQ.'7')GO TO 1110
      IF(IA(IREV).EQ.'8')GO TO 1110
      IF(IA(IREV).EQ.'9')GO TO 1110
      IF(IA(IREV).EQ.'+')GO TO 1530
      IF(IA(IREV).EQ.'-')GO TO 1530
 1100 CONTINUE
      GO TO 1530
 1110 ILOC=IREV+1
 1150 CONTINUE
      IF(IBUG2.EQ.'ON')WRITE(ICOUT,1111)ILOC,IDECPT
 1111 FORMAT('ILOC = ',I8,'    IDECPT = ',I8)
      IF(IBUG2.EQ.'ON')CALL DPWRST('XXX','BUG ')
!
!               *******************************************************
!               **  STEP 4.2--                                       **
!               **  SECONDLY, COMPUTE THE INTEGER PART OF THE VALUE  **
!               *******************************************************
!
      SIGN=1.0
      IDIGI=0
      ISIGN=0
      SUMI=0
      ILOCM1=ILOC-1
      IF(ILOCM1.LT.1)GO TO 1250
      DO 1200 I=1,ILOCM1
      IREV=ILOCM1-I+1
      IF(IA(IREV).EQ.' ')GO TO 1200
      IF(IA(IREV).EQ.'0')GO TO 1210
      IF(IA(IREV).EQ.'1')GO TO 1211
      IF(IA(IREV).EQ.'2')GO TO 1212
      IF(IA(IREV).EQ.'3')GO TO 1213
      IF(IA(IREV).EQ.'4')GO TO 1214
      IF(IA(IREV).EQ.'5')GO TO 1215
      IF(IA(IREV).EQ.'6')GO TO 1216
      IF(IA(IREV).EQ.'7')GO TO 1217
      IF(IA(IREV).EQ.'8')GO TO 1218
      IF(IA(IREV).EQ.'9')GO TO 1219
      IF(IA(IREV).EQ.'+')GO TO 1220
      IF(IA(IREV).EQ.'-')GO TO 1221
      GO TO 1530
 1210 ITERM=0
      GO TO 1225
 1211 ITERM=1
      GO TO 1225
 1212 ITERM=2
      GO TO 1225
 1213 ITERM=3
      GO TO 1225
 1214 ITERM=4
      GO TO 1225
 1215 ITERM=5
      GO TO 1225
 1216 ITERM=6
      GO TO 1225
 1217 ITERM=7
      GO TO 1225
 1218 ITERM=8
      GO TO 1225
 1219 ITERM=9
      GO TO 1225
 1220 ISIGN=ISIGN+1
      GO TO 1200
 1221 ISIGN=ISIGN+1
      SIGN=-SIGN
      GO TO 1200
 1225 IDIGI=IDIGI+1
      TERM=ITERM
      IEXP=IDIGI-1
      SUMI=SUMI+TERM*(10.0**IEXP)
 1200 CONTINUE
 1250 CONTINUE
      IF(ISIGN.GE.2)GO TO 1530
      IF(IBUG2.EQ.'ON')WRITE(ICOUT,1255)IDIGI,SUMI
 1255 FORMAT('IDIGI = ',I8,'    SUMI = ',F20.10)
      IF(IBUG2.EQ.'ON')CALL DPWRST('XXX','BUG ')
!
!               ******************************************************
!               **  STEP 4.3--                                      **
!               **  THIRDLY, COMPUTE THE DECIMAL PART OF THE VALUE  **
!               ******************************************************
!
      IDIGD=0
      SUMD=0.0
      ILOCP1=ILOC+1
      IF(ILOCP1.GT.16)GO TO 1350
      DO 1300 I=ILOCP1,16
      IF(IA(I).EQ.' ')GO TO 1300
      IF(IA(I).EQ.'0')GO TO 1310
      IF(IA(I).EQ.'1')GO TO 1311
      IF(IA(I).EQ.'2')GO TO 1312
      IF(IA(I).EQ.'3')GO TO 1313
      IF(IA(I).EQ.'4')GO TO 1314
      IF(IA(I).EQ.'5')GO TO 1315
      IF(IA(I).EQ.'6')GO TO 1316
      IF(IA(I).EQ.'7')GO TO 1317
      IF(IA(I).EQ.'8')GO TO 1318
      IF(IA(I).EQ.'9')GO TO 1319
      GO TO 1530
 1310 ITERM=0
      GO TO 1325
 1311 ITERM=1
      GO TO 1325
 1312 ITERM=2
      GO TO 1325
 1313 ITERM=3
      GO TO 1325
 1314 ITERM=4
      GO TO 1325
 1315 ITERM=5
      GO TO 1325
 1316 ITERM=6
      GO TO 1325
 1317 ITERM=7
      GO TO 1325
 1318 ITERM=8
      GO TO 1325
 1319 ITERM=9
      GO TO 1325
 1325 IDIGD=IDIGD+1
      TERM=ITERM
      SUMD=SUMD+TERM/(10.0**IDIGD)
 1300 CONTINUE
 1350 CONTINUE
      IF(IBUG2.EQ.'ON')WRITE(ICOUT,1355)IDIGD,SUMD
 1355 FORMAT('IDIGD = ',I8,'    SUMD = ',F20.10)
      IF(IBUG2.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IDIGT=IDIGI+IDIGD
      IF(IDIGT.LE.0)GO TO 1530
      ANS2=SUMI+SUMD
      IF(SIGN.LT.0.0)ANS2=-ANS2
      IF(AMIN.LE.ANS2.AND.ANS2.LE.AMAX)GO TO 9000
      GO TO 1750
!
 1530 CONTINUE
      WRITE(ICOUT,1531)
 1531 FORMAT('***** ERROR IN ERRORF--LAST ENTRY WAS ',   &
      'INVALID ***')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1532)
 1532 FORMAT('      IT SHOULD HAVE BEEN SOME INTEGER OR ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1533)
 1533 FORMAT('      FLOATING POINT NUMBER, BUT WAS NOT.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1534)IANS1,IANS2,IANS3,IANS4
 1534 FORMAT('      THE ENTRY WAS ',4A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1535)
 1535 FORMAT('      REENTER PROPER VALUE NOW--')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1750 CONTINUE
      WRITE(ICOUT,1531)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1752)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1753)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1754)AMIN,AMAX
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1755)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1734)IANS1,IANS2,IANS3,IANS4
 1734 FORMAT('      THE ENTRY WAS ',4A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1735)
 1735 FORMAT('      REENTER PROPER VALUE NOW--')
      CALL DPWRST('XXX','BUG ')
 1752 FORMAT('      IT SHOULD HAVE BEEN SOME INTEGER OR ')
 1753 FORMAT('      FLOATING POINT NUMBER ')
 1754 FORMAT('      BETWEEN ',E15.7,' AND ',E15.7,' (INCLUSIVE),')
 1755 FORMAT('      BUT WAS NOT.')
      IERROR='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ERRORF
      subroutine ess(y,n,len,ideg,njump,userw,rw,ys,res)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n, len, ideg, njump, newnj, nleft, nright, nsh, k, i, j
      real y(n), rw(n), ys(n), res(n), delta
      logical ok, userw
      if(.not.(n .lt. 2))go to 23019
      ys(1) = y(1)
      return
23019 continue
      newnj = min0(njump, n-1)
      if(.not.(len .ge. n))go to 23021
      nleft = 1
      nright = n
      do 23023 i = 1,n,newnj
      call est(y,n,len,ideg,float(i),ys(i),nleft,nright,res,userw,rw,ok)
      if(.not.( .not. ok))go to 23025
      ys(i) = y(i)
23025 continue
23023 continue
      go to 23022
23021 continue
      if(.not.(newnj .eq. 1))go to 23027
      nsh = (len+1)/2
      nleft = 1
      nright = len
      do 23029 i = 1,n
      if(.not.(i .gt. nsh  .and.  nright .ne. n))go to 23031
      nleft = nleft+1
      nright = nright+1
23031 continue
      call est(y,n,len,ideg,float(i),ys(i),nleft,nright,res,userw,rw,ok)
      if(.not.( .not. ok))go to 23033
      ys(i) = y(i)
23033 continue
23029 continue
      go to 23028
23027 continue
      nsh = (len+1)/2
      do 23035 i = 1,n,newnj
      if(.not.(i .lt. nsh))go to 23037
      nleft = 1
      nright = len
      go to 23038
23037 continue
      if(.not.(i .ge. n-nsh+1))go to 23039
      nleft = n-len+1
      nright = n
      go to 23040
23039 continue
      nleft = i-nsh+1
      nright = len+i-nsh
23040 continue
23038 continue
      call est(y,n,len,ideg,float(i),ys(i),nleft,nright,res,userw,rw,ok)
      if(.not.( .not. ok))go to 23041
      ys(i) = y(i)
23041 continue
23035 continue
23028 continue
23022 continue
      if(.not.(newnj .ne. 1))go to 23043
      do 23045 i = 1,n-newnj,newnj
      delta = (ys(i+newnj)-ys(i))/float(newnj)
      do 23047 j = i+1,i+newnj-1
      ys(j) = ys(i)+delta*float(j-i)
23047 continue
23045 continue
      k = ((n-1)/newnj)*newnj+1
      if(.not.(k .ne. n))go to 23049
      call est(y,n,len,ideg,float(n),ys(n),nleft,nright,res,userw,rw,ok)
      if(.not.( .not. ok))go to 23051
      ys(n) = y(n)
23051 continue
      if(.not.(k .ne. n-1))go to 23053
      delta = (ys(n)-ys(k))/float(n-k)
      do 23055 j = k+1,n-1
      ys(j) = ys(k)+delta*float(j-k)
23055 continue
23053 continue
23049 continue
23043 continue
      return
      end
      DOUBLE PRECISION FUNCTION esum(mu,x)
!-----------------------------------------------------------------------
!                    EVALUATION OF EXP(MU + X)
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION x
      INTEGER mu
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION w
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC exp
!     ..
!     .. Executable Statements ..
                                                                                                                                  
      IF (x.GT.0.0D0) GO TO 10
!
      IF (mu.LT.0) GO TO 20
      w = mu + x
      IF (w.GT.0.0D0) GO TO 20
      esum = exp(w)
      RETURN
!
   10 IF (mu.GT.0) GO TO 20
      w = mu + x
      IF (w.LT.0.0D0) GO TO 20
      esum = exp(w)
      RETURN
!
   20 w = mu
      esum = exp(w)*exp(x)
      RETURN
                                                                                                                                  
      END FUNCTION esum
      subroutine est(y,n,len,ideg,xs,ys,nleft,nright,w,userw,rw,ok)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n, len, ideg, nleft, nright, j
      real y(n), w(n), rw(n), xs, ys, range, h, h1, h9, a, b, c, r
      logical userw,ok
      range = float(n)-float(1)
      h = amax1(xs-float(nleft),float(nright)-xs)
      if(.not.(len .gt. n))go to 23057
      h = h+float((len-n)/2)
23057 continue
      h9 = .999*h
      h1 = .001*h
      a = 0.0
      do 23059 j = nleft,nright
      w(j) = 0.
      r = abs(float(j)-xs)
      if(.not.(r .le. h9))go to 23061
      if(.not.(r .le. h1))go to 23063
      w(j) = 1.
      go to 23064
23063 continue
      w(j) = (1.0-(r/h)**3)**3
23064 continue
      if(.not.(userw))go to 23065
      w(j) = rw(j)*w(j)
23065 continue
      a = a+w(j)
23061 continue
23059 continue
      if(.not.(a .le. 0.0))go to 23067
      ok = .false.
      go to 23068
23067 continue
      ok = .true.
      do 23069 j = nleft,nright
      w(j) = w(j)/a
23069 continue
      if(.not.((h .gt. 0.) .and. (ideg .gt. 0)))go to 23071
      a = 0.0
      do 23073 j = nleft,nright
      a = a+w(j)*float(j)
23073 continue
      b = xs-a
      c = 0.0
      do 23075 j = nleft,nright
      c = c+w(j)*(float(j)-a)**2
23075 continue
      if(.not.(sqrt(c) .gt. .001*range))go to 23077
      b = b/c
      do 23079 j = nleft,nright
      w(j) = w(j)*(b*(float(j)-a)+1.0)
23079 continue
23077 continue
23071 continue
      ys = 0.0
      do 23081 j = nleft,nright
      ys = ys+w(j)*y(j)
23081 continue
23068 continue
      return
      end
      SUBROUTINE EV1CDF(X,MINMAX,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!              DISTRIBUTION.
!              THE EXTREME VALUE TYPE 1 DISTRIBUTION USED
!              HEREIN HAS MEAN = EULER'S NUMBER = 0.57721566
!              AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!              FOR THE MINIMUIM ORDER STATISTIC
!              F(X) = (EXP(X)) * (EXP(-(EXP(X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(X-EXP(X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE EXTREME VALUE TYPE 1
!             DISTRIBUTION WITH MEAN = EULER'S NUMBER = 0.57721566
!             AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --JULY      2005. CODE IN DOUBLE PRECIONS FOR
!                                       BETTER ACCURACY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DCDF=0.0D0
      IF(MINMAX.EQ.1)THEN
        DCDF=1.0D0-DEXP(-(DEXP(DX)))
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DCDF=DEXP(-(DEXP(-DX)))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV1CDF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
      CDF=REAL(DCDF)
!
      RETURN
      END SUBROUTINE EV1CDF
