      SUBROUTINE EV1CHA(X,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!              DISTRIBUTION.
!              THE EXTREME VALUE TYPE 1 DISTRIBUTION USED
!              HEREIN HAS MEAN = EULER'S NUMBER = 0.57721566
!              AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!              FOR THE MINIMUIM ORDER STATISTIC
!              F(X) = (EXP(X)) * (EXP(-(EXP(X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!             DISTRIBUTION WITH MEAN = EULER'S NUMBER = 0.57721566
!             AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --JUNE      1999. SIMPLIFY FORMULAS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC DOUBLE PRECISION CDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        HAZ=EXP(X)
!CCCC   CALL EV1CDD(DBLE(X),MINMAX,CDF)
!CCCC   IF(1.0D0-CDF.LE.0.0D0)THEN
!CCCC     WRITE(ICOUT,1100)
!1100     FORMAT('*****ERROR IN EV1CHA--CDF ESSENTIALLY 1.')
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ELSE
!CCCC     HAZ=REAL(-DLOG(1.0D0-CDF))
!CCCC   ENDIF
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DX=DBLE(X)
        DTERM1=DEXP(-DEXP(-DX))
        DTERM2=1.0D0-DTERM1
        IF(DTERM2.GT.0.0D0)THEN
          HAZ=REAL(-DLOG(DTERM2))
        ELSE
          WRITE(ICOUT,1100)
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
        ENDIF
 1100   FORMAT('*****ERROR IN EV1CHA--UNABLE TO COMPUTE CUMULATIVE',   &
               'HAZARD FUNCTION.')
!CCCC   CALL EV1CDD(DBLE(X),MINMAX,CDF)
!CCCC   IF(1.0D0-CDF.LE.0.0D0)THEN
!CCCC     WRITE(ICOUT,1100)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ELSE
!CCCC     HAZ=REAL(-DLOG(1.0D0-CDF))
!CCCC   ENDIF
      ELSE
        HAZ=0.0
        WRITE(ICOUT,1800)
 1800   FORMAT('*****ERROR IN EV1CHA--MINMAX NOT 1 OR 2')
        CALL DPWRST('XXX','BUG ')
      END IF
!
      RETURN
      END SUBROUTINE EV1CHA
      SUBROUTINE EV1EST(X,NOBS,ALOC,SCALE,ALOC2,SCALE2,MINMAX,IERROR)
!
!  COMPUTE MLES FOR SCALE PARAMETER (SCALE) AND LOCATION
!  PARAMETER (ALOC) BY SOLVING THE EQUATION
!     G(SCALE)=0, WHERE G IS
!  A MONOTONICALLY INCREASING FUNCTION OF SCALE.
!  THE INITIAL ESTIMATE IS THE METHOD OF MOMENTS ESTIMATOR
!  AND THE TOLERANCE IS   :   2*RI/(10**6).
!
      DIMENSION X(*)
!
      REAL GFM, GFM2
      REAL SCALEL, SCALEH, SCALEM
      REAL TOL
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IWRITE
      CHARACTER*4 IERROR
!
      IERROR='NO'
      RN=REAL(NOBS)
      SCALEL=0.0
      SCALEH=0.0
!
!  USE METHOD OF MOMENTS TO GET INITAL ESTIMATES OF LOCATION AND SCALE
!
      IBUGA3='OFF'
      IWRITE='OFF'
      CALL MEAN(X,NOBS,IWRITE,XMEAN,IBUGA3,IERROR)
      CALL SD(X,NOBS,IWRITE,XSD,IBUGA3,IERROR)
      SCALEM=SQRT(1.645)*XSD
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        ALOCM=XMEAN-0.5772*XSD
      ELSE
        ALOCM=XMEAN+0.5772*XSD
      ENDIF
      ALOC2=ALOCM
      SCALE2=SCALEM
!
      TOL=2.0*.000001*SCALEM
      CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM,MINMAX)
!
!  IF G(SCALEM) .GE. 0, DIVIDE THE INITIAL ESTIMATE BY 2 UNTIL
!  THE ROOT IS BRACKETED BY SCALEL AND SCALEH.
!
      IF(GFM.GE.0.0D0)THEN
           SCALEH=SCALEM/2.0
           CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM2,MINMAX)
           DCONST=2.0
           IF(GFM2.GT.GFM)DCONST=0.5
           DO 3 J=1,200
                SCALEH=SCALEM
                SCALEM=SCALEM/DCONST
                CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM,MINMAX)
                IF(GFM.LE.0.0)GO TO 4
    3      CONTINUE
           IERROR='YES'
           GO TO 9999
    4      CONTINUE
           SCALEL=SCALEM
!
!  IF G(SCALEM) .LT. 0, MULTIPLY THE INITIAL ESTIMATE BY 2 UNTIL
!  THE ROOT IS BRACKETED BY SCALEL AND SCALEH.
      ELSEIF(GFM.LT.0.0)THEN
           SCALEH=SCALEM/2.0
           CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM2,MINMAX)
           DCONST=2.0
           IF(GFM2.LT.GFM)DCONST=0.5
           DO 7 J=1,2000
                SCALEL=SCALEM
                SCALEM=SCALEM*DCONST
                CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM,MINMAX)
                IF(GFM.GE.0.0D0)GO TO 8
    7      CONTINUE
           IERROR='YES'
           GO TO 9999
    8      CONTINUE
           SCALEH=SCALEM
      ENDIF
!
! SOLVE THE EQUATION G(SCALE)=0 FOR SCALE BY BISECTING THE
!   INTERVAL (SCALEL,SCALEH) UNTIL THE TOLERANCE IS MET
      MAXIT=20000
      NIT=0
   10 CONTINUE
      SCALEM=(SCALEL+SCALEH)/2.0
      CALL EV1FUN(X,NOBS,XMEAN,ALOCM,SCALEM,GFM,MINMAX)
      IF(GFM.GE.0.0)THEN
           SCALEH=SCALEM
      ENDIF
      IF(GFM.LT.0.0)THEN
           SCALEL=SCALEM
      ENDIF
      NIT=NIT+1
!
      IF(NIT.GT.MAXIT)THEN
        IERROR='YES'
        SCALE=(SCALEL+SCALEH)/2.0
        ALOC=ALOCM
        GO TO 9999
      ENDIF
!
      IF(SCALEH-SCALEL.GT.TOL)GO TO 10
!
      SCALE=(SCALEL+SCALEH)/2.0
      ALOC=ALOCM
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE EV1EST
      SUBROUTINE EV1FUN(X,N,XMEAN,ALOC,SCALE,EV1VAL,MINMAX)
!
!   COMPUTE G FUNCTION USED IN ESTIMATING THE SHAPE AND SCALE
!   PARAMETERS FOR EV1 DISTRIBUTION.
!
      DOUBLE PRECISION DN, DSUM1, DSUM2, DTERM1, DX, DSCALE
      DIMENSION X(*)
!
!  CALCULATE SOME INTERMEDIATE VALUES
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DN=DBLE(N)
        DSCALE=DBLE(SCALE)
        DSUM1=0.0
        DSUM2=0.0
        DO 100 I=1,N
          DX=DBLE(X(I))
          DSUM1=DSUM1 + DEXP(-DX/DSCALE)
          DSUM2=DSUM2 + DX*DEXP(-DX/DSCALE)
  100   CONTINUE
!
        ALOC=-SCALE*DLOG(DSUM1/DN)
!
        DTERM1=DBLE(XMEAN) - DSUM2/DSUM1
        EV1VAL=SCALE - REAL(DTERM1)
!
      ELSE
        DN=DBLE(N)
        DSCALE=DBLE(SCALE)
        DSUM1=0.0
        DSUM2=0.0
        DO 200 I=1,N
          DX=DBLE(X(I))
          DSUM1=DSUM1 + DEXP(DX/DSCALE)
          DSUM2=DSUM2 + DX*DEXP(DX/DSCALE)
  200   CONTINUE
!
        ALOC=SCALE*DLOG(DSUM1/DN)
!
        DTERM1=-DBLE(XMEAN) + DSUM2/DSUM1
        EV1VAL=SCALE - REAL(DTERM1)
!
      ENDIF
      RETURN
      END SUBROUTINE EV1FUN
      DOUBLE PRECISION FUNCTION EV1FU2 (SHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE SCALE PARAMETER FOR THE GUMBEL
!              MODEL FOR FULL SAMPLE DATA (NO CENSORING).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!              FOR THE MAXIMUM CASE:
!
!                 SHAT - XBAR + SUM[i=1 to N][X(I)*EXP(-X(I)/SHAT)]/
!                        SUM[i=1 to N][EXP(-X(I)/SHAT)] = 0
!
!              FOR THE MINIMUM CASE:
!
!                 SHAT + XBAR + SUM[i=1 to N][X(I)*EXP(X(I)/SHAT)]/
!                        SUM[i=1 to N][EXP(X(I)/SHAT)] = 0
!
!              WITH
!
!                 SHAT     = CURRENT ESTIMATE OF SCALE PARAMETER
!                 XBAR     = SAMPLE MEAN
!                 N        = SAMPLE SIZE
!                 MINMAX   = SPECIFY WHETHER MAXIMUM OR MINIMUM
!                            CASE IS BEING ESTIMATED
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!              --JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                WILEY, 1994, CHAPTER xx.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      IF(MINMAX.EQ.2)THEN
        DO 100 I=1,N
          DSUM1=DSUM1 + X(I)*DEXP(-X(I)/SHAT)
          DSUM2=DSUM2 + DEXP(-X(I)/SHAT)
  100   CONTINUE
        EV1FU2=SHAT - XBAR + DSUM1/DSUM2
      ELSE
        DO 200 I=1,N
          DSUM1=DSUM1 + X(I)*DEXP(X(I)/SHAT)
          DSUM2=DSUM2 + DEXP(X(I)/SHAT)
  200   CONTINUE
        EV1FU2=SHAT + XBAR - DSUM1/DSUM2
      ENDIF
!
!
      RETURN
      END FUNCTION EV1FU2 
      DOUBLE PRECISION FUNCTION EV1FU3 (SHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVALS FOR THE LOCATION AND SCALE
!              PARAMETERS OF A GUMBEL DISTRIBUTION.
!              THIS FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 2*LL(MU,SIGMA) - 2*LL(M(sigma),sigma)
!                                - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(MU,SIGMA) = -N*LOG(SIGMA) - N*XBAR/SIGMA +
!                                N*MU/SIGMA -
!                                SUM[i=1 to N][EXP(-(X(I)-MU)/SIGMA)]
!
!              GIVEN CURRENT VALUE OF SIGMA (= SHAT),
!
!                 MU(SIGMA) = -SIGMA*LOG(SUM[i=1 to N][EXP(-X(I)/SIGMA)]/N]
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
      DOUBLE PRECISION DK, DLLUS
      COMMON/EV1CO3/DK, DLLUS
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DSUM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!  GIVEN SIGMA, COMPUTE ESTIMATE OF MU
!
      DSUM1=0.0D0
      DN=DBLE(N)
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 100 I=1,N
          DSUM1=DSUM1 + DEXP(-X(I)/SHAT)
  100   CONTINUE
        DMU=-SHAT*DLOG(DSUM1/DN)
      ELSE
        DO 200 I=1,N
          DSUM1=DSUM1 + DEXP(X(I)/SHAT)
  200   CONTINUE
        DMU=SHAT*DLOG(DSUM1/DN)
      ENDIF
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 300 I=1,N
          DSUM1=DSUM1 + DEXP(-(X(I) - DMU)/SHAT)
  300   CONTINUE
        DTERM1=-DN*DLOG(SHAT) - DN*XBAR/SHAT + DN*DMU/SHAT - DSUM1
      ELSE
        DO 400 I=1,N
          DSUM1=DSUM1 + DEXP((X(I) + DMU)/SHAT)
  400   CONTINUE
        DTERM1=-DN*DLOG(SHAT) - DN*XBAR/SHAT + DN*DMU/SHAT - DSUM1
      ENDIF
!
      EV1FU3=2.0D0*DLLUS - 2.0D0*DTERM1 - DK
!
      RETURN
      END FUNCTION EV1FU3 
      DOUBLE PRECISION FUNCTION EV1FU4 (DMU,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVALS FOR THE LOCATION AND SCALE
!              PARAMETERS OF A GUMBEL DISTRIBUTION.
!              THIS FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 2*LL(MU,SIGMA) - 2*LL(mu,sigma(mu))
!                                - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(MU,SIGMA) = -N*LOG(SIGMA) - N*XBAR/SIGMA +
!                                N*MU/SIGMA -
!                                SUM[i=1 to N][EXP(-(X(I)-MU)/SIGMA)]
!
!              GIVEN CURRENT VALUE OF MU (= DMU), SIGMA IS ROOT OF:
!
!                 SIGMA + MU +
!                 SUM[i=1 to n][X(I)*EXP(-(X(I)-MU)/SIGMA]/N -
!                 MU*SUM[i=1 to n][EXP(-(X(I)-MU)/SIGMA]/N -  XBAR
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DMU
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
      DOUBLE PRECISION DLLUS
      DOUBLE PRECISION DK
      COMMON/EV1CO3/DK, DLLUS
      DOUBLE PRECISION SHAT
      COMMON/EV1CO4/SHAT
      DOUBLE PRECISION DMU2
      COMMON/EV1CO5/DMU2
      DOUBLE PRECISION EV1FU5
      EXTERNAL EV1FU5
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION SHAT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF LOCATION PARAMETER (MU), NEED TO COMPUTE
!          THE SCALE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
!
      DMU2=DMU
!
      AE=1.D-7
      RE=1.D-7
      XSTRT=SHAT
      XLOW=XSTRT/2.0D0
      XUP=XSTRT*2.0D0
      CALL DFZER3(EV1FU5,XLOW,XUP,XSTRT,RE,AE,IFLAG,X)
      SHAT2=XLOW
!
      DSUM1=0.0D0
      DN=DBLE(N)
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.2)THEN
        DO 300 I=1,N
          DSUM1=DSUM1 + DEXP(-(X(I) - DMU)/SHAT2)
  300   CONTINUE
        DTERM1=-DN*DLOG(SHAT2) - DN*XBAR/SHAT2 + DN*DMU/SHAT2 - DSUM1
      ELSE
        DO 400 I=1,N
          DSUM1=DSUM1 + DEXP((X(I) + DMU)/SHAT2)
  400   CONTINUE
        DTERM1=-DN*DLOG(SHAT2) - DN*XBAR/SHAT2 + DN*DMU/SHAT2 - DSUM1
      ENDIF
!
      EV1FU4=2.0D0*DLLUS - 2.0D0*DTERM1 - DK
!
      RETURN
      END FUNCTION EV1FU4 
      DOUBLE PRECISION FUNCTION EV1FU5 (SHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVALS FOR THE LOCATION AND SCALE
!              PARAMETERS OF A GUMBEL DISTRIBUTION.
!              THIS CONFIDENCE INTERVAL IS THE ROOT OF THE EQUATION
!
!                 2*LL(MU,SIGMA) - 2*LL(mu,sigma(mu))
!                                - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(MU,SIGMA) = -N*LOG(SIGMA) - N*XBAR/SIGMA +
!                                N*MU/SIGMA -
!                                SUM[i=1 to N][EXP(-(X(I)-MU)/SIGMA)]
!
!              GIVEN CURRENT VALUE OF MU (= DMU), SIGMA IS ROOT OF:
!
!                 SIGMA + MU +
!                 SUM[i=1 to n][X(I)*EXP(-(X(I)-MU)/SIGMA]/N -
!                 MU*SUM[i=1 to n][EXP(-(X(I)-MU)/SIGMA]/N -  XBAR
!
!              EV1FU5 IS USED IN SOLVING FOR THE VALUE OF SIGMA
!              GIVEN MU.
!
!              CALLED BY DFZER3 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
      DOUBLE PRECISION DMU
      COMMON/EV1CO5/DMU
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!  GIVEN MU, FIND ROOT FOR SIGMA
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DN=DBLE(N)
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 100 I=1,N
          DSUM1=DSUM1 + X(I)*DEXP(-(X(I)-DMU)/SHAT)
          DSUM2=DSUM2 + DEXP(-(X(I)-DMU)/SHAT)
  100   CONTINUE
        EV1FU5=SHAT + DMU + DSUM1/DN - DMU*DSUM2/DN - XBAR
      ELSE
        DO 200 I=1,N
          DSUM1=DSUM1 + X(I)*DEXP((X(I)+DMU)/SHAT)
          DSUM2=DSUM2 + DEXP((X(I)+DMU)/SHAT)
  200   CONTINUE
        EV1FU5=SHAT + DMU + DSUM1/DN - DMU*DSUM2/DN - XBAR
      ENDIF
!
!  COMPUTE SOME SUMS
!
!
!
      RETURN
      END FUNCTION EV1FU5 
      DOUBLE PRECISION FUNCTION EV1FU6 (DPPF,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVALS FOR THE LOCATION AND SCALE
!              PARAMETERS OF A GUMBEL DISTRIBUTION.
!              THIS FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 2*LL(MU,SIGMA) - 2*LL(mu(Q),S1(Q)
!                                - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(MU,SIGMA) = -N*LOG(SIGMA) - N*XBAR/SIGMA +
!                                N*MU/SIGMA -
!                                SUM[i=1 to N][EXP(-(X(I)-MU)/SIGMA)]
!
!              GIVEN A VALUE OF Q, EV1FU6 IS CALLED TO DETERMINE A
!              VALUE OF SIGMA.  THEN THE FOLLOWING IS USED TO
!              FIND THE VALUE OF M.
!
!                 MU = Q + LN(LN(1/q))*SHAT
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION X(*)
!
      DOUBLE PRECISION EV1FU7
      EXTERNAL EV1FU7
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
      DOUBLE PRECISION DLLUS
      DOUBLE PRECISION DK
      COMMON/EV1CO3/DK, DLLUS
      DOUBLE PRECISION DQ
      DOUBLE PRECISION SHATML
      COMMON/EV1CO6/DQ,SHATML
      DOUBLE PRECISION DQ2
      DOUBLE PRECISION DPPF2
      COMMON/EV1CO7/DQ2,DPPF2
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DMU
      DOUBLE PRECISION SHAT2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF Q, NEED TO COMPUTE
!          THE SCALE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
!
      DQ2=DQ
      DPPF2=DPPF
!
      AE=1.D-7
      RE=1.D-7
      XSTRT=SHATML
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(EV1FU7,XLOW,XUP,XSTRT,RE,AE,IFLAG,X)
      SHAT2=XLOW
!
!  STEP 2: NOW COMPUTE VALUE OF MU
!
      DMU=DPPF + DLOG(DLOG(1.0D0/DQ))*SHAT2
!
!  COMPUTE SOME SUMS
!
      DN=DBLE(N)
      DSUM1=0.0D0
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 300 I=1,N
          DSUM1=DSUM1 + DEXP(-(X(I) - DMU)/SHAT2)
  300   CONTINUE
        DTERM1=-DN*DLOG(SHAT2) - DN*XBAR/SHAT2 + DN*DMU/SHAT2 - DSUM1
      ELSE
        DO 400 I=1,N
          DSUM1=DSUM1 + DEXP((X(I) + DMU)/SHAT2)
  400   CONTINUE
        DTERM1=-DN*DLOG(SHAT2) - DN*XBAR/SHAT2 + DN*DMU/SHAT2 - DSUM1
      ENDIF
!
      EV1FU6=2.0D0*DLLUS - 2.0D0*DTERM1 - DK
!
      RETURN
      END FUNCTION EV1FU6 
      DOUBLE PRECISION FUNCTION EV1FU7 (SHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVALS FOR A PERCENTILE OF THE
!              GUMBEL DISTRIBUTION.  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!              (N/SIGMA)*{(XBAR - Q)/SIGMA + (LOG(q)/N)*
!              SUM[i=1 to N][EXP(-(X(I)-Q)/SIGMA)*(X(I)-Q)/SIGMA)] - 1
!
!              WITH
!
!                 q       = DESIRED PERCENTILE (E.G., 0.95) (DQ IN CODE)
!                 Q       = POINT ESTIMATE OF PERCENTILE (EV1PPF(q) =
!                           DPPF IN CODE)
!
!              EV1FU7 IS USED IN SOLVING FOR THE VALUE OF SIGMA
!              GIVEN q AND Q.
!
!              CALLED BY DFZER3 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMAX,N
      DOUBLE PRECISION DQ
      DOUBLE PRECISION DPPF
      COMMON/EV1CO7/DQ,DPPF
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!  GIVEN MU, FIND ROOT FOR SIGMA
!
      DSUM1=0.0D0
      DN=DBLE(N)
      DTERM1=(XBAR-DPPF)/SHAT
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 100 I=1,N
          DSUM1=DSUM1 + ((X(I)-DPPF)/SHAT)*DEXP(-(X(I)-DPPF)/SHAT)
  100   CONTINUE
      ELSE
        DO 200 I=1,N
          DSUM1=DSUM1 + ((X(I)-DPPF)/SHAT)*DEXP((X(I)-DPPF)/SHAT)
  200   CONTINUE
      ENDIF
!
      EV1FU7=(DN/SHAT)*(DTERM1 + (DLOG(DQ)/DN)*DSUM1 - 1.0D0)
!
      RETURN
      END FUNCTION EV1FU7 
      SUBROUTINE EV1HAZ(X,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!              DISTRIBUTION.
!              THE EXTREME VALUE TYPE 1 DISTRIBUTION USED
!              HEREIN HAS MEAN = EULER'S NUMBER = 0.57721566
!              AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!              FOR THE MINIMUIM ORDER STATISTIC
!              F(X) = (EXP(X)) * (EXP(-(EXP(X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!              THE HAZARD FUNCTION IS:
!              EXP(-X)/(EXP(EXP(-X)-1))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!             DISTRIBUTION WITH MEAN = EULER'S NUMBER = 0.57721566
!             AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --JUNE      1999. USE SIMPLIFIED FORMULA FOR
!                                       MINIMUM CASE.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
!CCCC DOUBLE PRECISION DCDF
!CCCC DOUBLE PRECISION DPDF
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        IF(X.LE.REAL(I1MACH(15)))THEN
          HAZ=0.0
        ELSEIF(X.LE.REAL(I1MACH(16)))THEN
          HAZ=EXP(X)
        ELSE
          HAZ=0.0
          WRITE(ICOUT,1700)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!CCCC   DX=DBLE(X)
!CCCC   CALL EV1CDD(DX,MINMAX,DCDF)
!CCCC   DCDF=1.0D0-DCDF
!CCCC   IF(DCDF.NE.0.0D0)THEN
!CCCC     DPDF=DEXP(DX-DEXP(DX))
!CCCC     DHAZ=DPDF/DCDF
!CCCC     HAZ=REAL(DHAZ)
!CCCC   ELSE
!CCCC     WRITE(ICOUT,1600)
!1600     FORMAT('*****ERROR IN EV1HAZ--CDF ESSENTIALLY 1.')
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ENDIF
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DX=DBLE(-X)
!CCCC   DTERM1=DEXP(DX)-1.0D0
!CCCC   DHAZ=DEXP(DX-DTERM1)
        DTERM1=DEXP(DX)
        DTERM2=DEXP(DEXP(DX))-1.0D0
        IF(DTERM2.NE.0.0D0)THEN
          DHAZ=DTERM1/DTERM2
          HAZ=REAL(DHAZ)
        ELSE
          HAZ=0.0
          WRITE(ICOUT,1700)
 1700     FORMAT('*****ERROR IN EV1HAZ--UNABLE TO COMPUTE THE ',   &
                'HAZARD FUNCTION.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSE
         HAZ=0.0
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV1HAZ--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
      RETURN
      END SUBROUTINE EV1HAZ
      SUBROUTINE EV1LI1(Y,N,MINMAX,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE GUMBEL (EXTREME VALUE TYPE 1) DISTRIBUTION.  THIS IS
!              FOR THE RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, P. 272.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EV1L'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1LI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EV1LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1LI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=DN*DLOG(DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 1000 I=1,N
          DX=-(DBLE(Y(I)) - DU)/DS
          DTERM1=DEXP(DX - DEXP(DX))
          DSUM1=DSUM1 + DLOG(DTERM1/DS)
 1000   CONTINUE
      ELSE
        DO 2000 I=1,N
          DX=(DBLE(Y(I)) - DU)/DS
          DTERM1=DEXP(DX - DEXP(DX))
          DSUM1=DSUM1 + DLOG(DTERM1/DS)
 2000   CONTINUE
      ENDIF
      DLIK=DSUM1
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1LI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EV1LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EV1LI1
      SUBROUTINE EXPAND(XLAB,N1,XVAL,N2,IWRITE,Y,XLABC,TEMP1,   &
                        MAXOBV,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GIVEN A VECTOR OF LAB-ID'S AND A SET OF VALUES, XVAL,
!              CORRESPONDING TO UNIQUE VALUES OF THE LAB-ID'S, CREATE
!              A VECTOR OF THE SAME LENGTH AS LAB-ID WHERE THE
!              APPROPRIATE VALUE FROM XVAL IS INSERTED.
!
!              FOR EXAMPLE, SUPPOSE WE HAVE 100 LAB-ID'S WHERE THERE ARE
!              10 DISTINCT LAB-ID'S.  THEN XVAL SHOULD HAVE 10 VALUES.
!              THE FIRST VALUE IN XVAL WILL BE INSERTED INTO THE ROWS
!              WITH THE SMALLEST LAB-ID, THE SECOND VALUE IN XVAL WILL
!              BE INSERTED INTO THE ROWS WITH THE SECOND SMALLEST LAB-ID,
!              AND SO ON.
!
!     INPUT  ARGUMENTS--XLAB   = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE LAB-ID'S.
!                     --XVAL   = THE SINGLE PRECISION VECTOR CONTAINING
!                                THE VALUES TO BE INSERTED INTO THE
!                                OUTPUT VECTOR.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR XLAB.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR XVAL.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE CODED VALUES WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR Y
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--CODE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NONE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/1
!     ORIGINAL VERSION--JANUARY   2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION XLAB(*)
      DIMENSION XVAL(*)
      DIMENSION Y(*)
      DIMENSION XLABC(*)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPA'
      ISUBN2='ND  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PAND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXPAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,XLAB(I)
   56     FORMAT('I,XLAB(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,XVAL(I)
   66     FORMAT('I,XVAL(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
      DO 91 I=1,N1
        XLABC(I)=0.0
   91 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN EXPAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE LAB-IDs IS ',   &
               'LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N1
  118   FORMAT('      THE NUMBER OF LAB-IDs IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE GROUP ',   &
               'VALUES IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,128)N2
  128   FORMAT('      THE NUMBER OF GROUP VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               **********************************************************
!               **  STEP 2--                                            **
!               **  PERFORM THE CODING--                                **
!               **  CALL CODE ROUTINE AND THEN LOOP THROUGH VALUES IN   **
!               **  THE XVAL VECTOR.                                    **
!               **  THEN APPLY THE RANKS TO ALL THE VALUES.             **
!               **********************************************************
!
      CALL CODE(XLAB,N1,IWRITE,XLABC,TEMP1,MAXOBV,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL MAXIM(XLABC,N1,IWRITE,XMAX,IBUGA3,IERROR)
      IMAX=INT(XMAX+0.1)
      IF(IMAX.GT.N2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
  201   FORMAT('      THE NUMBER OF UNIQUE VALUES FOR THE LAB-IDs IS ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
  203   FORMAT('      GREATER THAN THE NUMBER OF GROUP VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)IMAX
  205   FORMAT('      THE NUMBER OF UNIQUE LAB-IDs IS ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,208)N2
  208   FORMAT('      THE NUMBER OF GROUP VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 310 I=1,IMAX
        HOLD=XVAL(I)
        DO 320 J=1,N1
          IINDX=INT(XLABC(J)+0.1)
          IF(IINDX.EQ.I)Y(J)=HOLD
  320   CONTINUE
  310 CONTINUE
!
!               ******************************
!               **  STEP 3--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)IMAX
  811   FORMAT('NUMBER OF DISTINCT CODE VALUES = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,812)XVAL(1)
  812   FORMAT('THE MINIMUM LAB-ID HAS CODED VALUE ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)XVAL(IMAX)
  813   FORMAT('THE MAXIMUM LAB-ID HAS CODED VALUE ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PAND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF EXPAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IMAX
 9012   FORMAT('IERROR,IMAX = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N1
          WRITE(ICOUT,9016)I,XLAB(I),XLABC(I),Y(I)
 9016     FORMAT('I,XLAB(I),XLABC(I),Y(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EXPAND
      DOUBLE PRECISION FUNCTION exparg(l)
!--------------------------------------------------------------------
!     IF L = 0 THEN  EXPARG(L) = THE LARGEST POSITIVE W FOR WHICH
!     EXP(W) CAN BE COMPUTED.
!
!     IF L IS NONZERO THEN  EXPARG(L) = THE LARGEST NEGATIVE W FOR
!     WHICH THE COMPUTED VALUE OF EXP(W) IS NONZERO.
!
!     NOTE... ONLY AN APPROXIMATE VALUE FOR EXPARG(L) IS NEEDED.
!--------------------------------------------------------------------
!     .. Scalar Arguments ..
      INTEGER l
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION lnb
      INTEGER b,m
!     ..
!     .. External Functions ..
!CCCC INTEGER ipmpar
!CCCC EXTERNAL ipmpar
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dble,dlog
!
      INCLUDE 'DPCOMC.INC'
!
!     ..
!     .. Executable Statements ..
!
!CCCC b = ipmpar(4)
      b = I1MACH(10)
      IF (b.NE.2) GO TO 10
      lnb = .69314718055995D0
      GO TO 40
                                                                                                                                  
   10 IF (b.NE.8) GO TO 20
      lnb = 2.0794415416798D0
      GO TO 40
                                                                                                                                  
   20 IF (b.NE.16) GO TO 30
      lnb = 2.7725887222398D0
      GO TO 40
                                                                                                                                  
   30 lnb = dlog(dble(b))
!
   40 IF (l.EQ.0) GO TO 50
!CCCC m = ipmpar(9) - 1
      ival = i1mach(12)
      m = ival - 1
      exparg = 0.99999D0* (m*lnb)
      RETURN
                                                                                                                                  
!CC50 m = ipmpar(10)
   50 m = i1mach(13)
      exparg = 0.99999D0* (m*lnb)
      RETURN
                                                                                                                                  
      END FUNCTION exparg
      SUBROUTINE EXPLI1(Y,N,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE EXPONENTIAL DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              NOTE THAT FOR THE 1-PARAMETER MODEL, JUST SET ALOC TO
!              ZERO BEFORE CALLING THIS ROUTINE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, P. 187.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'1EXP')ALOC=0.0
!
!     THE LOG-LIKELIHOOD FUNCTION IS
!
!     SUM[i=1 to N][-(X(i)-U)/S] - N*LOG(S)
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=DN*DLOG(DS)
      DSUM1=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 - (DX-DU)/DS
 1000 CONTINUE
      DLIK=DSUM1 - DTERM1
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'1EXP')DNP=1.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPLI1
      SUBROUTINE EXPLI2(Y,X,N,IR,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE CENSORED EXPONENTIAL DISTRIBUTION.  THIS IS FOR THE
!              RAW DATA CASE (I.E., NO GROUPING).
!
!              NOTE THAT FOR THE 1-PARAMETER MODEL, JUST SET ALOC TO
!              ZERO BEFORE CALLING THIS ROUTINE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, P. 187.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPL'
      ISUBN2='I2  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'1EXP')ALOC=0.0
!
!     THE LOG-LIKELIHOOD FUNCTION IS
!
!     SUM[i=1 to N][-(X(i)-U)/S] - R*LOG(S)   X(i) > U
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DR=DBLE(IR)
      DTERM1=DN*DLOG(DR)
      DSUM1=0.0D0
      DO 1000 I=1,N
        IF(X(I).GT.0.5 .AND. Y(I).GT.ALOC)THEN
          DX=DBLE(Y(I))
          DSUM1=DSUM1 - (DX-DU)/DS
        ENDIF
 1000 CONTINUE
      DLIK=DSUM1 - DTERM1
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'1EXP')DNP=1.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPLI2
      SUBROUTINE EV1ML1(Y,N,MINMAX,IGUMBC,ICASE,   &
                        DTEMP,   &
                        ALOWLO,AUPPLO,ALOWSC,AUPPSC,   &
                        ALOWL2,AUPPL2,ALOWS2,AUPPS2,   &
                        ALPHA,NUMALP,NUMOUT,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOCMO,ASCAMO,ALMOSE,ASMOSE,   &
                        ALOCML,ASCAML,ASC2ML,ALMLSE,ASMLSE,COVSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE EXTREME VALUE TYPE 1 (GUMBEL) DISTRIBUTION FOR
!              THE RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).
!              IT WILL OPTIONALLY RETURN THE CONFIDENCE INTERVALS FOR
!              THE LOCATION AND SCALE PARAMETERS.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMGU1 WILL GENERATE THE OUTPUT
!              FOR THE EXTREME VALUE TYPE 1 MLE COMMAND).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMGU1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION ALOWLO(*)
      DIMENSION AUPPLO(*)
      DIMENSION ALOWSC(*)
      DIMENSION AUPPSC(*)
      DIMENSION ALPHA(*)
      DIMENSION ALOWL2(*)
      DIMENSION AUPPL2(*)
      DIMENSION ALOWS2(*)
      DIMENSION AUPPS2(*)
!
      CHARACTER*4 IGUMBC
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
      INTEGER ICASE
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP(*)
!
      DOUBLE PRECISION EV1FU2
      DOUBLE PRECISION EV1FU3
      DOUBLE PRECISION EV1FU4
      EXTERNAL EV1FU2
      EXTERNAL EV1FU3
      EXTERNAL EV1FU4
!
      INTEGER IN
      DOUBLE PRECISION XBAR
      COMMON/EV1CO2/XBAR,MINMX2,IN
      DOUBLE PRECISION DK
      DOUBLE PRECISION DLLUS
      COMMON/EV1CO3/DK, DLLUS
      DOUBLE PRECISION SHAT
      COMMON/EV1CO4/SHAT
      DOUBLE PRECISION DQ
      DOUBLE PRECISION SHATML
      COMMON/EV1CO6/DQ,SHATML
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EV1M'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1ML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EV1ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT,MINMAX,ICASE
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT,MINMAX,ICASE = ',2(A4,2X),4I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR EXTREME VALUE TYPE 1 MLE ESTIMATE **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='EXTREME VALUE TYPE 1'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
!     MOMENT ESTIMATES ARE:
!
!        MUHAT = XBAR - 0.45006*SD
!        SHAT  = 0.77970*SD
!
!     THE ML ESTIMATE OF THE SCALE PARAMETER IS THE SOLUTION TO
!     THE FOLLOWING EQUATION:
!
!         FOR THE MAXIMUM CASE:
!
!             SHAT - XBAR + SUM[i=1 to N][X(I)*EXP(-X(I)/SHAT)]/
!                    SUM[i=1 to N][EXP(-X(I)/SHAT)] = 0
!
!         FOR THE MINIMUM CASE:
!
!             SHAT - XBAR + SUM[i=1 to N][X(I)*EXP(X(I)/SHAT)]/
!                    SUM[i=1 to N][EXP(X(I)/SHAT)] = 0
!
!         WITH
!
!             SHAT     = CURRENT ESTIMATE OF SCALE PARAMETER
!             XBAR     = SAMPLE MEAN
!             N        = SAMPLE SIZE
!             MINMAX   = SPECIFY WHETHER MAXIMUM OR MINIMUM
!                        CASE IS BEING ESTIMATED
!
!     THE ML ESTIMATE OF LOCATION FOR THE MAXIMUM CASE IS
!
!         MUHAT = -SHAT*LOG(SUM[i=1 to N][EXP(-X(I)/SHAT)]/N)
!
!     THE ML ESTIMATE OF LOCATION FOR THE MINIMUM CASE IS
!
!         MUHAT = -SHAT*LOG(SUM[i=1 to N][EXP(X(I)/SHAT)]/N)
!
      AN=REAL(N)
      DN=DBLE(N)
      IF(MINMAX.EQ.0 .OR. MINMAX.EQ.2)THEN
        ALOCMO=XMEAN - 0.45006*XSD
      ELSE
        ALOCMO=XMEAN + 0.45006*XSD
      ENDIF
      ASCAMO=0.77970*XSD
      ALMOSE=SQRT(1.16781*ASCAMO**2/AN)
      ASMOSE=1.10001*XSD**2/AN
!
      XBAR=DBLE(XMEAN)
      MINMX2=MINMAX
      IN=N
!
      DXSTRT=DBLE(ASCAMO)
      DAE=2.0*0.000001D0*DXSTRT
      DRE=DAE
      IFLAG=0
      DXLOW=DXSTRT/2.0D0
      DXUP=2.0D0*DXSTRT
      ITBRAC=0
      DO 3104 I=1,N
        DTEMP(I)=DBLE(Y(I))
 3104 CONTINUE
!
 3105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZER2(EV1FU2,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
        DXLOW=XLOWSV/2.0D0
        DXUP=2.0D0*XUPSV
        ITBRAC=ITBRAC+1
        GO TO 3105
      ENDIF
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GUMBEL MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF SIGMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GUMBEL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF SCALE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GUMBEL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ASCAML=REAL(DXLOW)
      BN=(1.0 + 2.2/AN**1.13)
      ASC2ML=BN*ASCAML
!
      DSUM1=0.0D0
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 3108 I=1,N
          DX=-DBLE(Y(I))
          DSUM1=DSUM1 + DEXP(DX/DBLE(ASCAML))
 3108   CONTINUE
        DTERM1=-DBLE(ASCAML)*DLOG(DSUM1/DN)
      ELSE
        DO 3109 I=1,N
          DX=DBLE(Y(I))
          DSUM1=DSUM1 + DEXP(DX/DBLE(ASCAML))
 3109   CONTINUE
        DTERM1=DBLE(ASCAML)*DLOG(DSUM1/DN)
      ENDIF
      ALOCML=REAL(DTERM1)
!
      ASMLSE=0.77970*ASCAML/SQRT(AN)
      ALMLSE=1.05293*ASCAML/SQRT(AN)
      COVSE=0.50697*ASCAML/SQRT(AN)
      IF(IGUMBC.EQ.'ON')THEN
        ASMLSE=ASMLSE*BN
        COVSE=COVSE*SQRT(BN)
      ENDIF
!
      IF(ICASE.EQ.0)GO TO 9000
!
      IF(IGUMBC.EQ.'ON')THEN
        SCTEMP=ASC2ML
      ELSE
        SCTEMP=ASCAML
      ENDIF
!
      DSUM1=0.0D0
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DO 3110 I=1,N
          DSUM1=DSUM1 + DEXP(-(Y(I) - DBLE(ALOCML))/DBLE(ASCAML))
 3110   CONTINUE
        DLLUS=-DN*DLOG(DBLE(ASCAML)) - DN*XBAR/DBLE(ASCAML) +   &
               DN*DBLE(ALOCML)/DBLE(ASCAML) - DSUM1
      ELSE
        DO 3115 I=1,N
          DSUM1=DSUM1 + DEXP((Y(I) + DBLE(ALOCML))/DBLE(ASCAML))
 3115   CONTINUE
        DLLUS=-DN*DLOG(DBLE(ASCAML)) - DN*XBAR/DBLE(ASCAML) +   &
               DN*DBLE(ALOCML)/DBLE(ASCAML) - DSUM1
      ENDIF
      SHAT=DBLE(SCTEMP)
!
      DAE=1.D-7
      DRE=1.D-7
      NUTEMP=1
!
      DO 3120 I=1,NUMALP
!
        ALP=ALPHA(I)
        P=1.0-(ALP/2.0)
        CALL NORPPF(P,APPF)
        ALOWSC(I)=SCTEMP - APPF*ASMLSE
        AUPPSC(I)=SCTEMP + APPF*ASMLSE
        ALOWLO(I)=ALOCML - APPF*ALMLSE
        AUPPLO(I)=ALOCML + APPF*ALMLSE
!
        CALL CHSPPF(1.0-ALP,NUTEMP,APPF)
        DK=DBLE(APPF)
!
        DXSTRT=DBLE(ALOWSC(I))
        DXLOW=DXSTRT/5.0D0
        DXUP=DBLE(SCTEMP)
        CALL DFZER2(EV1FU3,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
        ALOWS2(I)=REAL(DXLOW)
!
        DXSTRT=DBLE(AUPPSC(I))
        DXUP=DXSTRT*5.0D0
        DXLOW=DBLE(SCTEMP)
        CALL DFZER2(EV1FU3,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
        AUPPS2(I)=REAL(DXLOW)
!
        DXSTRT=DBLE(ALOWLO(I))
        DXLOW=DXSTRT/2.0D0
        DXUP=DBLE(ALOCML)
        CALL DFZER2(EV1FU4,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
        ALOWL2(I)=REAL(DXLOW)
!
        DXSTRT=DBLE(AUPPLO(I))
        DXUP=DXSTRT*2.0D0
        DXLOW=DBLE(ALOCML)
        CALL DFZER2(EV1FU4,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
        AUPPL2(I)=REAL(DXLOW)
!
 3120 CONTINUE
!
      NUMOUT=NUMALP
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'1ML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EV1ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)ALOCMO,ASCAMO,ALMOSE,ASMOSE
 9056   FORMAT('ALOCMO,ASCAMO,ALMOSE,ASMOSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)ALOCML,ASCAML,ALMLSE,ASMLSE
 9057   FORMAT('ALOCML,ASCAML,ALMLSE,ASMLSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 9060 I=1,NUMALP
          WRITE(ICOUT,9065)I,ALPHA(I),ALOWLO(I),AUPPLO(I),ALOWSC(I),   &
                           AUPPSC(I)
 9065     FORMAT('I,ALPHA(I),ALOWLO(I),AUPPLO(I),ALOWSC(I),AUPPSC(I)=',   &
                 I8,5G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9066)I,ALPHA(I),ALOWL2(I),AUPPL2(I),ALOWS2(I),   &
                           AUPPSC(I)
 9066     FORMAT('I,ALPHA(I),ALOWL2(I),AUPPL2(I),ALOWS2(I),AUPPS2(I)=',   &
                 I8,5G15.7)
          CALL DPWRST('XXX','WRIT')
 9060   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EV1ML1
      SUBROUTINE EV1PDF(X,MINMAX,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!              DISTRIBUTION.
!              THE EXTREME VALUE TYPE 1 DISTRIBUTION USED
!              HEREIN HAS MEAN = EULER'S NUMBER = 0.57721566
!              AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!              FOR THE MINIMUIM ORDER STATISTIC
!              F(X) = (EXP(X)) * (EXP(-(EXP(X))))
!              WHICH SIMPLIFIES TO:
!              F(X) = EXP(-X - EXP(-X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF FOR THE EXTREME VALUE TYPE 1
!             DISTRIBUTION WITH MEAN = EULER'S NUMBER = 0.57721566
!             AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --JULY      2004. CODE IN DOUBLE PRECISION FOR
!                                       BETTER ACCURACY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DPDF=0.0D0
      IF(MINMAX.EQ.1)THEN
        DPDF=DEXP(DX-DEXP(DX))
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DPDF=DEXP(-DX-DEXP(-DX))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV1PDF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
      PDF=REAL(DPDF)
!
      RETURN
      END SUBROUTINE EV1PDF
      SUBROUTINE EV1PPF(P,MINMAX,PPF)
!CCCC MINMAX ADDED TO ABOVE ARGUMENT LIST   MAY 1993
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 1
!              (= GUMBEL)
!              DISTRIBUTION.
!              THERE ARE 2 SUCH EV1 FAMILIES--
!                 ONE FOR THE MIN ORDER STAT AND
!                 ONE FOR THE MAX ORDER STAT (THE USUAL).
!              (SEE SARHAN & GREENBERG, PAGE 69)
!              THE EV1 TYPE IS SPECIFIED VIA   MINMAX
!              FOR MINMAX = 1  (FOR THE MINIMUM)
!                 THE WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = ...
!              FOR MINMAX = 2 (FOR THE DEFAULT MAXIMUM),
!                 THE EV1 DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL X,
!                 HAS MEAN = EULER'S NUMBER = 0.57721566
!                 HAS STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1993. REWRITTEN--ADD EV1/MIN DIST.
!     UPDATED         --JANUARY   1994. ADD MINMAX ERROR MESSAGE
!     UPDATED         --JULY      2004. CODE IN DOUBLE PRECISION
!                                       FOR BETTER ACCURACY.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST  ARGUMENT TO EV1PPF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!CCCC THE FOLLOWING LINE WAS REWRITTEN   MAY 1993
!CCCC PPF=(-(LOG(-LOG(P))))
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN      JANUARY 1994
      DPPF=0.0D0
      DP=DBLE(P)
      IF(MINMAX.EQ.1)THEN
         DPPF=DLOG(DLOG(1.0D0/(1.0D0-DP)))
      ELSE IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
         DPPF=(-(DLOG(DLOG(1.0D0/DP))))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV1PPF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      ENDIF
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV1PPF
      SUBROUTINE EV1RAN(N,MINMAX,ISEED,X)
!CCCC MINMAX WAS ADDED TO THE ABOVE ARGUMENT LIST   MAY 1993
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE EXTREME VALUE TYPE 1 DISTRIBUTION.
!              THE PROTOTYPE EXTREME VALUE TYPE 1 DISTRIBUTION USED
!              HEREIN HAS MEAN = EULER'S NUMBER = 0.57721566
!              AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (EXP(-X)) * (EXP(-(EXP(-X))))
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE EXTREME VALUE TYPE 1 DISTRIBUTION
!             WITH MEAN = EULER'S NUMBER = 0.57721566
!             AND STANDARD DEVIATION = PI/SQRT(6) = 1.28254983.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1993. REWRITTEN--ADD EV1/MIN DIST.
!     UPDATED         --JANUARY   1994. ADD MINMAX ERROR MESSAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'EV1RAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N EXTREME VALUE TYPE 1 RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN   MAY 1993
!CCCC DO100I=1,N
!CCCC X(I)=-LOG(LOG(1.0/X(I)))
!C100 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN      JANUARY 1994
      IF(MINMAX.EQ.1)THEN
         DO 100 I=1,N
         X(I)=LOG(LOG(1.0/(1.0-X(I))))
  100    CONTINUE
      ELSE IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
         DO 200 I=1,N
         X(I)=(-(LOG(LOG(1.0/X(I)))))
  200    CONTINUE
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV1RAN--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE EV1RAN
      SUBROUTINE EV2CDF(X,GAMMA,MINMAX,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              FOR THE MINIMUM ORDER STATISTIC
!              F(X) = GAMMA * ((-X)**(-GAMMA-1)) * EXP(-((-X)**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE EXTREME VALUE TYPE 2
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(X.LT.0.0.AND.(MINMAX.EQ.2 .OR. MINMAX.EQ.0))THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CDF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.GT.0.0.AND.MINMAX.EQ.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CDF IS ',   &
               'POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2CDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF MINMAX IS ',I5)
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        CDF=1.0
        IF(X.GE.0.0)GO TO 9000
        CDF=1.0-EXP(-(-X)**(-GAMMA))
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        CDF=0.0
        IF(X.LE.0.0)GO TO 9000
        CDF=EXP(-(X**(-GAMMA)))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2CDF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2CDF
      SUBROUTINE EV2CDD(X,GAMMA,MINMAX,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              FOR THE MINIMUM ORDER STATISTIC
!              F(X) = GAMMA * ((-X)**(-GAMMA-1)) * EXP(-((-X)**(-GAMMA))).
!     NOTE--THIS IS A DOUBLE PRECISION VERSION OF EV2CDF USED IN
!           CALCULATING HAZARD FUNCTIONS
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE EXTREME VALUE TYPE 2
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION CDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(X.LT.0.0D0.AND.(MINMAX.EQ.2 .OR. MINMAX.EQ.0))THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CDF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.GT.0.0D0.AND.MINMAX.EQ.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CDF IS ',   &
               'POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2CDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF MINMAX IS ',I5)
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        CDF=1.0D0
        IF(X.GE.0.0D0)GO TO 9000
        CDF=1.0D0-DEXP(-(-X)**(-GAMMA))
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        CDF=0.0D0
        IF(X.LE.0.0D0)RETURN
        CDF=DEXP(-(X**(-GAMMA)))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2CDF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2CDD
      SUBROUTINE EV2CHA(X,GAMMA,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              FOR THE MINIMUM ORDER STATISTIC
!              F(X) = GAMMA * ((-X)**(-GAMMA-1)) * EXP(-((-X)**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE HAZ FOR THE EXTREME VALUE TYPE 2
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION CDF
      DOUBLE PRECISION DHAZ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0.AND.(MINMAX.EQ.2 .OR. MINMAX.EQ.0))THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CHA IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.GT.0.0.AND.MINMAX.EQ.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2CHA IS ',   &
               'POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2CHA ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF MINMAX IS ',I5)
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        DGAMMA=DBLE(GAMMA)
        DX=DBLE(X)
        DHAZ=(-DX)**(-DGAMMA)
        HAZ=REAL(DHAZ)
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        CALL EV2CDD(DBLE(X),DBLE(GAMMA),MINMAX,CDF)
        CDF=1.0D0-CDF
        IF(CDF.LE.0.0D0)THEN
          WRITE(ICOUT,1100)
          CALL DPWRST('XXX','BUG ')
 1100     FORMAT('*****ERROR IN EV2CHA--CDF ESSENTIALLY 1.')
        ELSE
          DHAZ=-DLOG(CDF)
          HAZ=REAL(DHAZ)
        ENDIF
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2CHA--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2CHA
      DOUBLE PRECISION FUNCTION EV2FUN (GHAT,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF GAMMA FOR THE 2-PARAMETER FRECHET
!              (EXTREME VALUE TYPE 2)
!              MODEL FOR FULL SAMPLE DATA (NO CENSORING).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 (1/GHAT) +
!                 SUM[i=1 to n][Y(I)**(-GHAT)*LN(Y(I))]/
!                 SUM[i=1 to n][[Y(I)**(-GHAT)] -
!                 (1/N)*SUM[i=1 to n][LN(Y(I))] = 0
!
!              WITH
!
!                 GHAT     = POINT ESTIMATE OF GAMMA (THIS IS THE
!                            PARAMETER WE ARE ITERATING OVER)
!
!              NOTE THAT THE THIRD TERM DOES NOT DEPEND ON GHAT,
!              SO THIS IS A CONSTANT.  FOR EFFICIENCY, SAVE THIS AS
!              A CONSTANT IN A COMMON BLOCK.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--FRECHET MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 16.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/5
!     ORIGINAL VERSION--MAY        2005.
!     UPDATED         --JUNE       2013. CHECK FOR DIVISION BY ZERO
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION GHAT
      DOUBLE PRECISION X(*)
!
      INTEGER IN
      DOUBLE PRECISION DEV2SM
      COMMON/EV2COM/DEV2SM,IN
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DG=GHAT
!
      DTERM1=1.0D0/DG
      DO 100 I=1,IN
        DX1=X(I)
        DSUM1=DSUM1 + (DX1**(-DG))*DLOG(DX1)
        DSUM2=DSUM2 + DX1**(-DG)
  100 CONTINUE
!
!     2013/06/20: IF DSUM2 IS ZERO, THEN SET DTERM2 TO A LARGE NUMBER
      IF(DSUM2.NE.0.0D0)THEN
        DTERM2=DSUM1/DSUM2
      ELSE
        DTERM2=CPUMAX/2.0D0
      ENDIF
!
      EV2FUN=DTERM1 + DTERM2 - DEV2SM
!
      RETURN
      END FUNCTION EV2FUN 
      DOUBLE PRECISION FUNCTION EV2FU2 (DA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVAL FOR THE 2-PARAMETER FRECHET
!              MODEL (FULL SAMPLE).  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!                 2*LL(ALPHA,GAMMA) - 2*LL(S(a),,a) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(ALPHA,GAMMA) = N*LN(GAMMA) + N*GAMMA*LN(ALPHA) -
!                          (GAMMA+1)*SUM[i=1 to n][LN(X(i))] -
!                          ALPHA**GAMMA*SUM[i=1 to n][(X(i)**(-GAMA)]
!                 ALPHA    = POINT ESTIMATE OF SCALE PARAMETER
!                 GAMMA    = POINT ESTIMATE OF SHAPE PARAMETER
!                 A        = PARAMETER WE ARE FINDING ROOT FOR
!                 K        = CHSPPF(ALPHA,1) (HERE, ALPHA IS THE
!                            SIGNIFICANCE LEVEL, NOT THE SCALE PARAMETER)
!
!              NOTE THAT QUANTITIES THAT DO NOT DEPEND ON A ARE
!              COMPUTED ONCE IN DPMLFR AND PASSED VIA COMMON BLOCK.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER2 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--FRECHET MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 16 (SEE
!                EXAMPLE 16.4).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/5
!     ORIGINAL VERSION--MAY        2005.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      COMMON/EV2CO2/DK,DTERM1,DTERM2,N
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DG
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DN=DBLE(N)
      DG=DA
!
      DSUM1=0.0D0
      DO 100 I=1,N
        DSUM1=DSUM1 + DX(I)**(-DG)
  100 CONTINUE
      DSCALE=(DSUM1/DN)**(-1.0D0/DG)
!
      DTERM3=DN*DLOG(DG) + DN*DG*DLOG(DSCALE)
      DTERM4=(DG+1.0D0)*DTERM2
      DTERM5=DSCALE**DG*DSUM1
!
      EV2FU2=DTERM1 - 2.0D0*(DTERM3 - DTERM4 - DTERM5) - DK
!
      RETURN
      END FUNCTION EV2FU2 
      DOUBLE PRECISION FUNCTION EV2FU3 (DB,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SCALE PARAMETER OF A
!              2-PARAMETER FRECHET MODEL (FULL SAMPLE).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 2*LL(ALPHA,GAMMA) - 2*LL(b,I(b)) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(ALPHA,GAMMA) = N*LN(GAMMA) + N*GAMMA*LN(ALPHA) -
!                          (GAMMA+1)*SUM[i=1 to n][LN(X(i))] -
!                          ALPHA**GAMMA*SUM[i=1 to n][(X(i)**(-GAMMA)]
!                 ALPHA    = POINT ESTIMATE OF SCALE PARAMETER
!                 GAMMA    = POINT ESTIMATE OF SHAPE PARAMETER
!                 B        = PARAMETER (SCALE) WE ARE FINDING ROOT FOR
!                 K        = CHSPPF(ALPHA,1) (HERE, ALPHA IS THE
!                            SIGNIFICANCE LEVEL, NOT THE SCALE
!                            PARAMETER)
!
!              NOTE THAT QUANTITIES THAT DO NOT DEPEND ON B ARE
!              COMPUTED ONCE IN DPMLFR AND PASSED VIA COMMON BLOCK.
!
!              GIVEN A VALUE FOR THE SCALE PARAMETER (DB), WE NEED
!              TO CALL A ROOT FINDING ROUTINE TO DETERMINE THE VALUE
!              OF THE SHAPE PARAMETER (A).
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER2 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--FRECHET MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 16 (SEE
!                EXAMPLE 16.4).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/5
!     ORIGINAL VERSION--MAY        2005.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DB
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DTERM7
      DOUBLE PRECISION DGAMMA
      COMMON/EV2CO3/DK,DTERM6,DTERM7,DGAMMA,N
!
      DOUBLE PRECISION DBTEMP
      COMMON/EV2CO4/DBTEMP,N2
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DA
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
      DOUBLE PRECISION EV2FU4
      EXTERNAL EV2FU4
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF SCALE PARAMETER (DB), NEED TO COMPUTE
!          THE SHAPE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
                                                                                                                                  
      N2=N
      DBTEMP=DB
      AE=1.D-7
      RE=1.D-7
      XSTRT=DGAMMA
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(EV2FU4,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DA=XLOW
!
!  COMPUTE SOME SUMS
!
      DN=DBLE(N)
      DG=DA
      DSCALE=DB
!
      DSUM1=0.0D0
      DO 100 I=1,N
        DSUM1=DSUM1 + DX(I)**(-DG)
  100 CONTINUE
!
      DTERM3=DN*DLOG(DG) + DN*DG*DLOG(DSCALE)
      DTERM4=(DG+1.0D0)*DTERM7
      DTERM5=DSCALE**DG*DSUM1
!
      EV2FU3=DTERM6 - 2.0D0*(DTERM3 - DTERM4 - DTERM5) - DK
!
      RETURN
      END FUNCTION EV2FU3 
      DOUBLE PRECISION FUNCTION EV2FU4 (DA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SCALE PARAMETER OF
!              THE 2-PARAMETER FRECHET MODEL (FULL SAMPLE).
!              SPECIFICALLY, IT IS USED TO DETERMINE AN ESTIMATE
!              OF THE SHAPE PARAMETER GIVEN A VALUE OF THE SCALE
!              PARAMETER.  IT FINDS THE ROOT OF THE FOLLOWING
!              EQUATION:
!
!                 (N/A) + N*LOG(B) - SUM[LOG(X)] -
!                       SUM[(B/X)**A*LOG(B/X)]
!
!              WITH A DENOTING THE SHAPE PARAMETER, B THE SCALE
!              PARAMETER, AND THE ROOT IS WITH RESPECT TO A.
!
!              CALLED BY DFZER3 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER3 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--FRECHET MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 16 (SEE
!                EXAMPLE 16.4).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/5
!     ORIGINAL VERSION--MAY        2005.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DB
      COMMON/EV2CO4/DB,N
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DN=DBLE(N)
      DTERM1=(DN/DA) + DN*DLOG(DB)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,N
        DSUM1=DSUM1 + DLOG(DX(I))
        DSUM2=DSUM2 + ((DB/DX(I))**DA)*DLOG(DB/DX(I))
  100 CONTINUE
!
      EV2FU4=DTERM1 - DSUM1 - DSUM2
!
      RETURN
      END FUNCTION EV2FU4 
      SUBROUTINE EV2HAZ(X,GAMMA,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              FOR THE MINIMUM ORDER STATISTIC
!              F(X) = GAMMA * ((-X)**(-GAMMA-1)) * EXP(-((-X)**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE HAZ FOR THE EXTREME VALUE TYPE 2
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION CDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0.AND.(MINMAX.EQ.2 .OR. MINMAX.EQ.0))THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2HAZ IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.GT.0.0.AND.MINMAX.EQ.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2HAZ IS ',   &
               'POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2HAZ ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF MINMAX IS ',I5)
!
!-----START POINT-----------------------------------------------------
!
      DGAMMA=DBLE(GAMMA)
      DX=DBLE(X)
      IF(MINMAX.EQ.1)THEN
        DHAZ=DGAMMA*(-DX)**(-DGAMMA-1.0D0)
        HAZ=REAL(DHAZ)
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        DPDF=DGAMMA*(DX**(-DGAMMA-1.0))*DEXP(-(DX**(-DGAMMA)))
        CALL EV2CDD(DBLE(X),DBLE(GAMMA),MINMAX,CDF)
        IF(1.0D0-CDF.LE.0.0D0)THEN
          WRITE(ICOUT,1100)
          CALL DPWRST('XXX','BUG ')
 1100     FORMAT('*****ERROR IN EV2HAZ--CDF ESSENTIALLY 1, ',   &
                 'HAZARD SET TO 0.')
        ELSE
          HAZ=REAL(DPDF/(1.0D0-CDF))
        ENDIF
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2HAZ--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2HAZ
      SUBROUTINE EV2LI1(Y,N,ICASPL,MINMAX,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE FRECHET DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 16.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/9
!     ORIGINAL VERSION--SEPTEMBER 2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EV2L'
      ISUBN2='I1  '
      IERROR='NO'
!
      DPDF=0.0D0
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(ALOC.EQ.CPUMIN)THEN
        ALOCT=0.0
      ELSE
        ALOCT=ALOC
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2LI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EV2LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2LI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'FREC')ALOC=0.0
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     N*(LOG(SHAPE) - SHAPE*LOG(SCALE)) +
!     (SHAPE-1)*SUM[i=1 to n][LOG(X(i) - LOC] -
!     SUM[i=1 to n][((X(i) - LOC)/SCALE)**SHAPE]
!
!CCCC DN=DBLE(N)
!CCCC DS=DBLE(SCALE)
!CCCC DU=DBLE(ALOC)
!CCCC DG=DBLE(SHAPE)
!CCCC DTERM1=DN*(DLOG(DG) - DG*DLOG(DS))
!CCCC DSUM1=0.0D0
!CCCC DSUM2=0.0D0
!
!CCCC IF(MINMAX.EQ.2)THEN
!CCCC   DO1010I=1,N
!CCCC     DX=DBLE(Y(I))
!CCCC     DSUM1=DSUM1 + DLOG(DU - DX)
!CCCC     DSUM2=DSUM2 + ((DU-DX)/DS)**DG
!C010   CONTINUE
!CCCC ELSE
!CCCC   DO1020I=1,N
!CCCC     DX=DBLE(Y(I))
!CCCC     DSUM1=DSUM1 + DLOG(DX - DU)
!CCCC     DSUM2=DSUM2 + ((DX-DU)/DS)**DG
!C020   CONTINUE
!CCCC ENDIF
!
      DG=DBLE(SHAPE)
      DLOC=DBLE(ALOC)
      DSCALE=DBLE(SCALE)
      DLIK=0.0D0
!
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DX=(DX-DLOC)/DSCALE
!
        IF(MINMAX.EQ.1)THEN
          DPDF=DG*((-DX)**(-DG-1.0D0))*DEXP(-((-DX)**(-DG)))
          DPDF=DPDF/DSCALE
        ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
          DPDF=DG*(DX**(-DG-1.0D0))*DEXP(-(DX**(-DG)))
        ENDIF
        IF(DPDF.LE.0.0D0)THEN
          IERROR='YES'
!CCCC     GO TO 9000
          DTERM1=0.0D0
        ELSE
          DTERM1=DLOG(DPDF)
        ENDIF
        DLIK=DLIK + DTERM1
 1000 CONTINUE
!
      ALIK=REAL(DLIK)
      DN=DBLE(N)
      DNP=2.0D0
      IF(ICASPL.EQ.'3EV2' .OR. ICASPL.EQ.'3FRE')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*DLOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2LI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EV2LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EV2LI1
      SUBROUTINE EV2ML1(Y,N,MINMAX,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XLOGSD,XLOGSM,   &
                        SCALML,SCALSE,SHAPML,SHAPSE,   &
                        SHAPBC,SHABSE,COVSE,COVBSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER EXTREME VALUE TYPE 2 (FRECHET)
!              DISTRIBUTION FOR THE RAW DATA CASE (I.E., NO CENSORING
!              AND NO GROUPING).  THIS ROUTINE RETURNS ONLY THE POINT
!              ESTIMATES (CONFIDENCE INTERVALS WILL BE COMPUTED IN A
!              SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLW1 WILL GENERATE THE OUTPUT
!              FOR THE FRECHET MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 16.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLFR)
!     UPDATED         --JUNE      2013. IMPROVED STARTING VALUES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      CHARACTER*8 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DYT
      DOUBLE PRECISION DYBAR
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
!
      DOUBLE PRECISION EV2FUN
      EXTERNAL EV2FUN
      INTEGER IN
      DOUBLE PRECISION DEV2SM
      COMMON/EV2COM/DEV2SM,IN
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EV2M'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      AN=REAL(N)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EV2ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,MINMAX
   52   FORMAT('IBUGA3,ISUBRO,MINMAX = ',2(A4,2X),I5)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(MINMAX.NE.1)THEN
        DO 1125 I=1,N
          IF(Y(I).LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1122)
 1122       FORMAT('      A NON-POSITIVE VALUE WAS ENCOUNTERED IN ',   &
                   'THE RESPONSE VARIABLE.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1123)I,Y(I)
 1123       FORMAT('      ROW ',I8,' HAS THE VALUE = ',E15.7)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ELSE
            TEMP1(I)=LOG(Y(I))
          ENDIF
 1125   CONTINUE
      ELSE
        DO 1135 I=1,N
          IF(Y(I).GE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1132)
 1132       FORMAT('      A NON-NEGATIVE VALUE WAS ENCOUNTERED IN ',   &
                   'THE RESPONSE VARIABLE.')
            WRITE(ICOUT,1133)I,Y(I)
 1133       FORMAT('      ROW ',I8,' HAS THE VALUE = ',E15.7)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ELSE
            TEMP1(I)=LOG(-Y(I))
          ENDIF
 1135   CONTINUE
      ENDIF
!
      HOLD=Y(1)
      DO 1145 I=2,N
        IF(Y(I).NE.HOLD)GO TO 1149
 1145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1142)HOLD
 1142 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
 1149 CONTINUE
!
!               ******************************************
!               **  STEP 2--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR FRECHET MLE ESTIMATE            **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='FRECHET'
!CCCC IFLAG=2
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      CALL SD(TEMP1,N,IWRITE,XLOGSD,IBUGA3,IERROR)
      CALL SUMDP(TEMP1,N,IWRITE,XLOGSM,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SHAPBC=CPUMIN
      SHAPSE=CPUMIN
      SHABSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
      COVSE=CPUMIN
      COVBSE=CPUMIN
!
!     FOR THE SHAPE PARAMETER, SOLVE THE EQUATION:
!
!         (1/GHAT) +
!         SUM[i=1 to n][Y(I)**(-GHAT)*LN(Y(I))]/
!         SUM[i=1 to n][[Y(I)**(-GHAT)] -
!         (1/N)*SUM[i=1 to n][LN(Y(I))] = 0
!
!     THEN
!
!         SCALE = {((1/N)*SUM[i=1 to n][Y(I)**(-GHAT)])}**(-1/GHAT)
!
!     FOR STARTING VALUE, USE FACT THAT FRECHET = EXPONENTIAL OF
!     GUMBEL DISTRIBUTION.  THEN GHAT = 1/SCALE WITH SCALE DENOTING
!     THE SCALE ESTIMATE OF THE GUMBEL DISTRIBUTION.
!
!     2013/06: BASE STARTING VALUE FOR SHAPE ON "FRECHET" PLOT (SEE
!     PAGE 299 OF BURY).  THE FRECHET PLOT IS
!
!          -LN[LN[p(i)]] versus LN OF ORDERED DATA
!
!     WHERE p(i) = (i - 0.3)/(n + 0.4)
!
!     THEN
!
!           A0 = -GAMMA*LOG(SCALE)
!           A1 = GAMMA
!
!     FOR SIMPLE LINEAR REGRESSION,
!
!           A1 = SUM[X(i) - XBAR]*SUM[Y(i) - YBAR]/SUM[(X(i) - XBAR)**2]
!
!     IN ORDER TO AVOID HAVING TO PASS IN ADDITIONAL SCRATCH ARRAYS, DO
!     IN TWO PASSES.
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2EV2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASE='MAXIMUM'
      IF(MINMAX.EQ.1)THEN
        ICASE='MINIMUM'
        DO 4103 I=1,N
          Y(I)=-Y(I)
 4103   CONTINUE
      ENDIF
!
!     ESTIMATES FOR 2-PARAMETER MODEL.  USE DFZER2 TO FIND ROOT OF
!     THE EQUATION GIVEN ABOVE.
!
      DO 4101 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 4101 CONTINUE
      KFLAG=1
      CALL DSORT(DTEMP1,DTEMP1,N,KFLAG,IERROR)
!
      DEV2SM=DBLE(XLOGSM/AN)
!CCCC DXSTRT=DBLE(SQRT(1.645)*XSD)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DN=DBLE(N)
      DO 3901 I=1,N
        DYT=(DBLE(I) - 0.3D0)/(DN + 0.4D0)
        DYT=-LOG(-LOG(DYT))
        DSUM1=DSUM1 + DYT
        DSUM2=DSUM2 + DLOG(DTEMP1(I))
 3901 CONTINUE
      DYBAR=DSUM1/DN
      DXBAR=DSUM2/DN
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 3903 I=1,N
        DYT=(DBLE(I) - 0.3D0)/(DN + 0.4D0)
        DYT=-LOG(-LOG(DYT))
        DSUM1=DSUM1 + (DLOG(DTEMP1(I)) - DXBAR)*(DYT - DYBAR)
        DSUM2=DSUM2 + (DLOG(DTEMP1(I)) - DXBAR)**2
 3903 CONTINUE
      DXSTRT=DSUM1/DSUM2
!
      DAE=2.0*0.000001D0*DXSTRT
      DRE=DAE
      IN=N
      IFLAG=0
      DXLOW=DXSTRT/3.0D0
      DXUP=3.0D0*DXSTRT
      ITBRAC=0
 4105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZER2(EV2FUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
        DXLOW=XLOWSV/2.0D0
        DXUP=2.0D0*XUPSV
        ITBRAC=ITBRAC+1
        GO TO 4105
      ENDIF
!
      IF(IFLAG.EQ.2)THEN
!
!CCCC   NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM FRECHET MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF SIGMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM FRECHET MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF GAMMA MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1111)
 1111   FORMAT('****** ERROR IN FRECHERT MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      SHAPML=REAL(DXLOW)
      DSUM=0.0D0
      DO 4108 I=1,N
        DSUM=DSUM + DBLE(Y(I)**(-SHAPML))
 4108 CONTINUE
      DSUM=(DSUM/DBLE(N))**(1.0D0/DBLE(-SHAPML))
      SCALML=REAL(DSUM)
      BN=1.0 + 2.2/AN**1.13
      SHAPBC=SHAPML/BN
!
!     COMPUTE STANDARD ERRORS (CAN BASE ON EITHER THE NORMAL BIASED
!     ESTIMATORS OR THE BIAS CORRECTED ESTIMATORS)
!
      SCALSE=1.05293*SCALML/(SHAPML*SQRT(AN))
      SHAPSE=0.77970*SHAPML/SQRT(AN)
      SHABSE=0.77970*SHAPML/(BN*SQRT(AN))
      COVSE=0.50697*SQRT(SCALML/AN)
      COVBSE=0.50697*SQRT(SCALML/(AN*BN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EV2ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)XLOGSD,XLOGSM
 9015   FORMAT('XLOGSD,XLOGSM = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPSE,SCALSE
 9017   FORMAT('SHAPML,SCALML,SHAPSE,SCALSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)SHAPBC,SHABSE,COVSE,COVBSE
 9019   FORMAT('SHAPBC,SHABSE,COVSE,COVBSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EV2ML1
      SUBROUTINE EV2ML3(Y,N,MINMAX,MAXNXT,ISEED,IDFTTY,IGEVML,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,DTEMP1,   &
                        XMOM,NMOM,VARCOV,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSKEW,   &
                        ALOCML,SCALML,SHAPML,   &
                        ALOCLM,SCALLM,SHAPLM,   &
                        ALOCEP,SCALEP,SHAPEP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER FRECHET DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).
!
!              THE DEFAULT IS FOR THE "MAXIMUM" FRECHET.  NOTE
!              THAT THE FOLLOWING ADDITIONAL CASES CAN BE HANDLED:
!
!                 1. THE REVERSE ("MINIMUM") FRECHET.  FOR THIS CASE, WE
!                    TAKE THE NEGATIVE OF THE ORIGINAL DATA AND THEN FIT
!                    THE MAXIMUM FRECHET CASE.  AFTER OBTAINING THE
!                    PARAMETER ESTIMATES, TAKE THE NEGATIVE OF THE
!                    LOCATION PARAMETER.
!
!                 2. NOTE THAT THE "INVERTED WEIBULL" IS REALLY JUST THE
!                    "MAXIMUM" FRECHET.  TREAT INVERTED WEIBULL AND
!                    FRECHET AS SYNONYMS.
!
!              GENERATE ESTIMATES BASED ON:
!
!                 1. MAXIMUM LIKELIHOOD (UNDER DEVELOPMENT)
!                 2. L-MOMENTS
!                 3. ELEMENTAL PERCENTILES
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLF3 WILL GENERATE THE OUTPUT
!              FOR THE 3-PARAMETER FRECHET MLE COMMAND).
!
!              NOTE THAT THE FRECHET CAN BE ESTIMATED IN TERMS OF THE
!              GENERALIZED EXTREME VALUE DISTRIBUTION AS FOLLOWS:
!
!              1. FOR MAXIMUM CASE:
!
!                    LOC    = LOC' + SCALE'/SHAPE'
!                    SCALE  = -SCALE'/SHAPE'
!                    SHAPE  = -1/SHAPE'
!
!              2. FOR MINIMUM CASE:
!
!                    LOC    = LOC' - SCALE'/SHAPE'
!                    SCALE  = -SCALE'/SHAPE'
!                    SHAPE  = -1/SHAPE'
!
!               WHERE LOC', SCALE', AND SHAPE' ARE THE PARAMETERS OF THE
!               3-PARAMETER GENERALIZED EXTREME VALUE DISTRIBUTION.
!
!     REFERENCES--CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY.
!               --FORTRAN CODE WRITTEN FOR INCLUSION IN IBM
!                 RESEARCH REPORT RC20525, 'FORTRAN ROUTINES FOR
!                 USE WITH THE METHOD OF L-MOMENTS, VERSION 3',
!                 J. R. M. HOSKING, IBM RESEARCH DIVISION,
!                 T. J. WATSON RESEARCH CENTER, YORKTOWN HEIGHTS
!                 NEW YORK 10598, U.S.A., VERSION 3     AUGUST 1996
!               --HOSKING, ALGORITHM AS215   APPL. STATIST. (1985)
!                 VOL. 34, NO. 3, Modifications in AS R76 (1989)
!                 have been incorporated.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/5
!     ORIGINAL VERSION--OCTOBER   2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION VARCOV(*)
      DOUBLE PRECISION XMOM(*)
!
      CHARACTER*4 IDFTTY
      CHARACTER*4 IGEVML
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IGEPDF
      CHARACTER*4 ICASPL
!
      LOGICAL MLFLAG
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EV2M'
      ISUBN2='L3  '
!
      ALOCML=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
!
      ALOCEP=CPUMIN
      SCALEP=CPUMIN
      SHAPEP=CPUMIN
!
      ALOCLM=CPUMIN
      SCALLM=CPUMIN
      SHAPLM=CPUMIN
!
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EV2ML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IGEVML,MINMAX
   52   FORMAT('IBUGA3,ISUBRO,IGEVML,MINMAX = ',3(A4,2X),I5)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN 3-PARAMETER FRECHET MAXIMUM ',   &
               'LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)N
  113   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CALL GEVML1 TO OBTAIN GEV PARAMETER **
!               **  ESTIMATES.                          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL STMOM3(Y,N,IWRITE,XSKEW,IBUGA3,IERROR)
!
      MLFLAG=.TRUE.
!CCCC MLFLAG=.FALSE.
      IGEPDF='NULL'
      ICASPL='GEV'
      CALL GEVML1(Y,N,MAXNXT,MINMAX,ICASPL,MLFLAG,IGEPDF,   &
                  ISEED,IDFTTY,IGEVML,   &
                  TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                  DTEMP1,XMOM,NMOM,VARCOV,   &
                  XMEAN,XSD,XVAR,XMIN,XMAX,   &
                  ALOCLZ,SCALLZ,SHAPLZ,   &
                  ALOCEZ,SCALEZ,SHAPEZ,   &
                  ALOCMZ,SCALMZ,SHAPMZ,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML3')THEN
        WRITE(ICOUT,1011)
 1011   FORMAT('**** AFTER CALL GEVML1')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1013)ALOCLZ,SCALLZ,SHAPLZ
 1013   FORMAT('L-MOMENTS: ALOCLZ,SCALLZ,SHAPLZ = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1015)ALOCEZ,SCALEZ,SHAPEZ
 1015   FORMAT('ELEMENTAL PERCENTILES: ALOCEZ,SCALEZ,SHAPEZ = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1021)ALOCMZ,SCALMZ,SHAPMZ
 1021   FORMAT('MLE: ALOCMZ,SCALMZ,SHAPMZ = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  TRANSFORM ESTIMATES TO FRECHET      **
!               **  PARAMETERS                          **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(MINMAX.EQ.0 .OR. MINMAX.EQ.2)THEN
        IF(SHAPMZ.NE.CPUMIN)THEN
          SHAPML=-1.0/SHAPMZ
          SCALML=-SCALMZ/SHAPMZ
          ALOCML=ALOCMZ + SCALMZ/SHAPMZ
        ENDIF
        IF(SHAPLZ.NE.CPUMIN)THEN
          SHAPLM=-1.0/SHAPLZ
          SCALLM=-SCALLZ/SHAPLZ
          ALOCLM=ALOCLZ + SCALLZ/SHAPLZ
        ENDIF
        IF(SHAPEZ.NE.CPUMIN)THEN
          SHAPEP=-1.0/SHAPEZ
          SCALEP=-SCALEZ/SHAPEZ
          ALOCEP=ALOCEZ + SCALEZ/SHAPEZ
        ENDIF
      ELSE
        IF(SHAPMZ.NE.CPUMIN)THEN
          SHAPML=-1.0/SHAPMZ
          SCALML=-SCALMZ/SHAPMZ
          ALOCML=ALOCMZ - SCALMZ/SHAPMZ
        ENDIF
        IF(SHAPLZ.NE.CPUMIN)THEN
          SHAPLM=-1.0/SHAPLZ
          SCALLM=-SCALLZ/SHAPLZ
          ALOCLM=ALOCLZ - SCALLZ/SHAPLZ
        ENDIF
        IF(SHAPEZ.NE.CPUMIN)THEN
          SHAPEP=-1.0/SHAPEZ
          SCALEP=-SCALEZ/SHAPEZ
          ALOCEP=ALOCEZ - SCALEZ/SHAPEZ
        ENDIF
      ENDIF
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'2ML3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EV2ML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)ALOCLM,SCALLM,SHAPLM
 9013   FORMAT('L-MOMENTS: ALOCLM,SCALLM,SHAPLM = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)ALOCEP,SCALEP,SHAPEP
 9015   FORMAT('ELEMENTAL PERCENTILES: ALOCEP,SCALEP,SHAPEP = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9021)ALOCML,SCALML,SHAPML
 9021   FORMAT('MLE: ALOCML,SCALML,SHAPML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EV2ML3
      SUBROUTINE EV2PDF(X,GAMMA,MINMAX,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              FOR THE MAXIMUM ORDER STATISTIC
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              FOR THE MINIMUM ORDER STATISTIC
!              F(X) = GAMMA * ((-X)**(-GAMMA-1)) * EXP(-((-X)**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE EXTREME VALUE TYPE 2
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMOMN---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(X.LT.0.0.AND.(MINMAX.EQ.2 .OR. MINMAX.EQ.0))THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2PDF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.GT.0.0.AND.MINMAX.EQ.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** WARNING--THE FIRST ARGUMENT TO EV2PDF IS ',   &
               'POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)MINMAX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2PDF ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF MINMAX IS ',I5)
!
!-----START POINT-----------------------------------------------------
!
      IF(MINMAX.EQ.1)THEN
        PDF=GAMMA*((-X)**(-GAMMA-1.0))*EXP(-((-X)**(-GAMMA)))
      ELSEIF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        PDF=GAMMA*(X**(-GAMMA-1.0))*EXP(-(X**(-GAMMA)))
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2PDF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      END IF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2PDF
      SUBROUTINE EV2PPF(P,GAMMA,MINMAX,PPF)
!CCCC MINMAX ADDED TO ABOVE ARGUMENT LIST   MAY 1993
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE EXTREME VALUE TYPE 2
!              (= FRECHET)
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THERE ARE 2 SUCH EV2 FAMILIES--
!                 ONE FOR THE MIN ORDER STAT (THE USUAL) AND
!                 ONE FOR THE MAX ORDER STAT.
!              (SEE SARHAN & GREENBERG, PAGE 69)
!              THE EV2 TYPE IS SPECIFIED VIA   MINMAX
!              FOR MINMAX = 1  (FOR THE MINIMUM)
!                 THE EV2 DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL NEGATIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = ...
!              FOR MINMAX = 2 (FOR THE DEFAULT MAXIMUM),
!                 THE EV2 DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!               F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE EXTREME VALUE TYPE 2 DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1993. REWRITTEN--ADD EV2/MAX DIST.
!     UPDATED         --JANUARY   1994. ADD MINMAX ERROR MESSAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO EV2PPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2PPF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!CCCC THE FOLLOWING LINE WAS REWRITTEN    MAY 1993
!CCCC PPF=(-LOG(P))**(-1.0/GAMMA)
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN      JANUARY 1994
      IF(MINMAX.EQ.1)THEN
         PPF= (-(LOG(1.0/(1.0-P)))**(-1.0/GAMMA))
      ELSE IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
         PPF= (LOG(1.0/P))**(-1.0/GAMMA)
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2PPF--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2PPF
      SUBROUTINE EV2RAN(N,GAMMA,MINMAX,ISEED,X)
!CCCC MINMAX WAS ADDED TO THE ABOVE ARGUMENT LIST   MAY 1993
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE EXTREME VALUE TYPE 2 DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!              THE PROTOTYPE EXTREME VALUE TYPE 2 DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**(-GAMMA))).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE EXTREME VALUE TYPE 2 DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 272-295.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1993. MINMAX
!     UPDATED         --JANUARY   1994. ADD MINMAX ERROR MESSAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF RANDON ',   &
               'NUMBERS IN EV2RAN IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO EV2RAN IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N EXTREME VALUE TYPE 2 DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN    MAY 1993
!CCCC DO100I=1,N
!CCCC X(I)=(-LOG(X(I)))**(-1.0/GAMMA)
!C100 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN      JANUARY 1994
      IF(MINMAX.EQ.1)THEN
         DO 100 I=1,N
         X(I)= (-(LOG(1.0/(1.0-X(I))))**(-1.0/GAMMA))
  100    CONTINUE
      ELSE IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
         DO 200 I=1,N
         X(I)= (LOG(1.0/X(I)))**(-1.0/GAMMA)
  200    CONTINUE
      ELSE
         WRITE(ICOUT,1800)
 1800    FORMAT('*****ERROR IN EV2RAN--MINMAX NOT 1 OR 2')
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EV2RAN
      SUBROUTINE EVALM(IW2,IW22,W2,ITYPE,ISTART,ISTOP,IANGLU,ANS,   &
                       SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,SAVE6,SAVE7,SAVE8,   &
                       ILIBC1,ILIBC2,IBUGEV,IERROR)
!
!     PURPOSE--EVALUATE A STRING OF CODE THAT CONTAINS ONLY
!              VALUES, OPERATIONS, AND LIBRARY FUNCTIONS.
!     NOTE--THE DECEMBER UPDATE AUGMENTED THE USUAL MATH LIBRARY WITH
!           ARCSIN, ARCCOS, ARCTAN, OCTAL
!     NOTE--THE UPDATE WHICH ALLOWS 2 ARGUMENTS AND 3 ARGUMENTS
!           AS IN TCDF, CHSCDF, FCDF, ETC. HAS THE FOLLOWING RESTRICTIONS--
!           1) NO EXPRESSIONS FOR ARGUMENTS (MAYBE FOR FIRST)
!           2) NO NEGATIVE ARGUMENTS FOR SECOND AND THIRD ARGUMENTS
!              (FORTUNATELY THIS LAST RESTRICTION IS NO RESTRICTION
!              AT ALL FOR THE T, CHI-SQUARED, AND F DISTRIBUTIONS
!             BECAUSE THEY REQUIRE POSITIVE DEGREES OF FREEDOM ANYWAY.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER 1, 1976.
!     UPDATED--DECEMBER 21, 1977.
!     UPDATED--DECEMBER 28, 1977.
!     UPDATED         --JULY      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --JANUARY   1979.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1989.  SAVE3 ARGUMENT (FOR JULIA SETS)
!     UPDATED         --JUNE      1989.  UNDERFLOW SET TO 0 FOR * AND /
!     UPDATED         --MAY       1994.  SET SAVE2 AND SAVE3 TO -99.9
!                                        TO AVOID FCDF ERROR WITH
!                                        TOO FEW ARGUMENTS.
!     UPDATED         --SEPTEMBER 1994.  ADD SAVE4 ARGUMENT FOR DNFCDF
!     UPDATED         --APRIL     1995.  INITIALIZE SAVE1 ... SAVE4
!                                        (BUG IN HEAVE FUNCTION, WHERE
!                                        ARGUMENTS OPTIONAL)
!                                        ALSO, BUG IN FOLLOWING
!                                        LET A = TPDF(X,2) - TPDF(X,3)
!                                        BOTH USE 2 FOR SECOND ARG.
!     UPDATED         --SEPTEMBER 1997.  WORKAROUND FOR "**" OPERATION
!                                        (BUG IN OLD LAHEY COMPILER)
!     UPDATED         --MAY       1998.  ADD SAVE5
!     UPDATED         --NOVEMBER  1998.  FIX FOR 0**(POSITIVE NUMB)
!     UPDATED         --JUNE      2003.  ADD SAVE6, SAVE7, SAVE8
!     UPDATED         --AUGUST    2020.  FIX BUG FOR (-2)**2
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IW2(*)
      CHARACTER*4 IW22(*)
      CHARACTER*4 ITYPE(*)
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGEV
      CHARACTER*4 IERROR
!
!
!---------------------------------------------------------------------
!
      DIMENSION W2(*)
!
!CCCC FOLLOWING SECTION ADDED APRIL 1995.
      DIMENSION SAVE1(*)
      DIMENSION SAVE2(*)
      DIMENSION SAVE3(*)
      DIMENSION SAVE4(*)
      DIMENSION SAVE5(*)
      DIMENSION SAVE6(*)
      DIMENSION SAVE7(*)
      DIMENSION SAVE8(*)
!
      DIMENSION TERM(80)
      DIMENSION IOP(80)
      CHARACTER*4 IOP
!
!CCCC FOLLOWING LINE FOR LAHEY BUG.  SEPTEMBER 1997.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!     DEFINE THE UPPER LIMIT OF THE NUMBER OF 'TERMS' THAT THIS
!     SUBROUTINE CAN PROCESS.  THIS IS USUALLY THE SAME AS THE MAX
!     NUMBER OF CHARACTERS THAT MAY BE PROCESSED BY THE COMPIM SUBROUTINE
!     IF RESTRICT THE FUNCTIONAL EXPRESSION TO 1 LINE IMAGE, THEN A
!     REASONABLE UPPER BOUND IS 80.  WHATEVER UPPER BOUND IS SET, THE
!     DIMENSIONS OF THE VECTORS TERM(.) AND IOP(.),  USED HEREIN
!     MUST BE EQUAL OR LARGER TO THIS NUMBER.
!
      DATA MAXTER/80/
!
!-----START POINT-----------------------------------------------------
!
      ANS=0.0
      IERROR='NO'
!
      CUTOFF=0.00001
      AIABS2=(-999.0)
      ALCPUM=LOG(CPUMAX)
!
!     CHECK THAT THE INPUT PARAMETERS ISTART AND ISTOP)
!     ARE BOTH AT LEAST 1 AND BOTH AT MOST MAXTER
!     (WHERE MAXTER IS THE INTERNALLY DEFINED VARIABLE
!     WHICH CONTROLS DIMENSION SIZES AND WHICH
!     TYPICALLY HAS THE VALUE 80).
!     ALSO CHECK THAT ISTART DOES NOT EXCEED ISTOP.
!
      IF(ISTART.LT.1.OR.MAXTER.LT.ISTART)GO TO 20
      IF(ISTOP.LT.1.OR.MAXTER.LT.ISTOP)GO TO 20
      IF(ISTOP.LT.ISTART)GO TO 20
      GO TO 39
   20 CONTINUE
      WRITE(ICOUT,21)
   21 FORMAT('***** ERROR IN EVALM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22)
   22 FORMAT('      ILLEGAL VALUES FOR THE INPUT PARAMETERS ISTART ',   &
             'AND/OR ISTOP.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,24)MAXTER
   24 FORMAT('      BOTH ISTART AND ISTOP MUST BE AT LEAST 1 AND AT ',   &
             'MOST ',I5,'.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,28)
   28 FORMAT('      ALSO, ISTART MUST BE LESS THAN OR EQUAL TO ',   &
             'ISTOP.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,30)ISTART
   30 FORMAT('      ISTART = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)ISTOP
   31 FORMAT('      ISTOP  = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   39 CONTINUE
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EVALM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISTART,ISTOP,IBUGEV,IANGLU
   52   FORMAT('ISTART,ISTOP,IBUGEV,IANGLU = ',2I6,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 53 I=ISTART,ISTOP
          WRITE(ICOUT,54)I,IW2(I),IW22(I),W2(I),ITYPE(I)
   54     FORMAT('I,IW2(I),IW22(I),W2(I),ITYPE(I) = ',I8,2(2X,A4),   &
                 F15.7,2X,A4)
          CALL DPWRST('XXX','BUG ')
   53   CONTINUE
        WRITE(ICOUT,58)SAVE1(1),SAVE2(1),SAVE3(1),SAVE4(1)
   58   FORMAT('I=1,SAVE1,SAVE2,SAVE3,SAVE4 = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     BLANK-OUT THE IOP(.) VECTOR AND ZERO-OUT THE TERM(.) VECTOR.
!
      DO 110 I=1,MAXTER
        TERM(I)=0.0
        IOP(I)='    '
  110 CONTINUE
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  OPERATE ON THE VECTORS IW2(.) AND IW22(.).         **
!               **  THEY SHOULD CONTAIN NO PARENTHESES.                **
!               **  THEY SHOULD CONTAIN ONLY--                         **
!               **       NUMBERS                                       **
!               **       X VALUES                                      **
!               **       PARAMETER VALUES                              **
!               **       PREVIOUSLY COMPUTED VALUES                    **
!               **       OPERATIONS (5--+ - * / **)                    **
!               **       LIBRARY FUNCTIONS.                            **
!               **  COPY THE NUMBERS, X VALUES, PARAMETER VALUES, AND  **
!               **  PREVIOUSLY COMPUTED VALUES OVER TO THE TERM VECTOR.**
!               **  COPY THE OPERATIONS OVER TO THE OPERATIONS VECTOR. **
!               **  ELIMINATE THE LIBRARY FUNCTIONS BY EVALUATING THEM **
!               **  WITH THE NEXT POTENTIAL TERM AND PUTTING           **
!               **  THE EVALUATED RESULT INTO THAT NEXT TERM.          **
!               **  OUTPUT THE VECTOR TERMS(.) AND THE VECTOR IOP(.)   **
!               **  WHICH CONTAIN TERMS AND OPERATIONS RESPECTIVELY.   **
!               *********************************************************
!
      IF(ITYPE(ISTOP).EQ.'OP')THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)ITYPE(ISTOP)
  121   FORMAT('      LAST TERM IN AN INTERMEDIATE EXPRESSION = AN ',   &
               'OPERATION = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(ITYPE(ISTOP).EQ.'LF')THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)ITYPE(ISTOP)
  123   FORMAT('      LAST TERM IN AN INTERMEDIATE EXPRESSION = A ',   &
               'LIBRARY FUNCTION = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NOP=0
      NTERM=0
      NUMSAV=0
      I=ISTART
!
  150 CONTINUE
      IDEL=1
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IF(ITYPE(I).EQ.'N'   .OR. ITYPE(I).EQ.'X' .OR.   &
         ITYPE(I).EQ.'PAR' .OR. ITYPE(I).EQ.'V')THEN
        IF(NUMSAV.LT.1)THEN
          NTERM=NTERM+1
          TERM(NTERM)=W2(I)
          IOP(NTERM)='V'
        ELSEIF(NUMSAV.EQ.1)THEN
          SAVE1(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.2)THEN
         SAVE2(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.3)THEN
         SAVE3(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.4)THEN
          SAVE4(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.5)THEN
          SAVE5(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.6)THEN
          SAVE6(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.7)THEN
          SAVE7(ILIBC1)=W2(I)
        ELSEIF(NUMSAV.EQ.8)THEN
          SAVE8(ILIBC1)=W2(I)
        ENDIF
        GO TO 100
      ELSEIF(ITYPE(I).EQ.'OP')THEN
        IF(IW2(I).EQ.'+' .OR. IW2(I).EQ.'-')THEN
          NOP=NOP+1
          IOP(NOP)=IW2(I)
          IF(NTERM.EQ.0)TERM(1)=0.0
          IF(NTERM.EQ.0)NTERM=1
          GO TO 100
        ELSEIF(IW2(I).EQ.'*' .OR. IW2(I).EQ.'/' .OR.   &
               IW2(I).EQ.'**')THEN
          NOP=NOP+1
          IOP(NOP)=IW2(I)
          IF(NTERM.EQ.0)THEN
            WRITE(ICOUT,322)
  322       FORMAT('      *, /, OR ** STARTS AN EXPRESSION')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
          GO TO 100
        ELSE
          WRITE(ICOUT,21)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,305)
  305     FORMAT('      NOT ONE OF THE 5 OPERATIONS:  + - * / **')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,306)I,IW2(I),IW22(I)
  306     FORMAT('      I,IW2(I),IW22(I) = ',I8,2(2X,A4))
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSEIF(   &
        (ITYPE(I).EQ.'LF'.AND.ITYPE(IP1).EQ.'V') .OR.   &
        (ITYPE(I).EQ.'LF'.AND.ITYPE(IP1).EQ.'N') .OR.   &
        (ITYPE(I).EQ.'LF'.AND.ITYPE(IP1).EQ.'X') .OR.   &
        (ITYPE(I).EQ.'LF'.AND.ITYPE(IP1).EQ.'PAR'))THEN
        GO TO 400
      ELSEIF(ITYPE(I).EQ.'COM')THEN
        NUMSAV=NUMSAV+1
        GO TO 100
      ELSE
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)
  105   FORMAT('      UNKNOWN ARGUMENT/OPERATION TYPE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,106)I,ITYPE(I)
  106   FORMAT('      I,ITYPE(I) = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
  400 CONTINUE
!
!     PERFORM A LIBRARY FUNCTION EVALUATION.
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,331)
  331   FORMAT('IN EVALM, BEFORE ENTERING DPLIBF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,332)IW2(I),IW22(I),W2(IP1),IBUGEV
  332   FORMAT('IW2(I),IW22(I),W2(IP1),IBUGEV = ',2(A4,2X),F10.5,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ILIBC2=ILIBC2+1
      IF(ILIBC2.GT.0)THEN
        ASAV1=SAVE1(ILIBC2)
        ASAV2=SAVE2(ILIBC2)
        ASAV3=SAVE3(ILIBC2)
        ASAV4=SAVE4(ILIBC2)
        ASAV5=SAVE5(ILIBC2)
        ASAV6=SAVE6(ILIBC2)
        ASAV7=SAVE7(ILIBC2)
        ASAV8=SAVE8(ILIBC2)
      ELSE
        ASAV1=0.0
        ASAV2=0.0
        ASAV3=0.0
        ASAV4=0.0
        ASAV5=0.0
        ASAV6=0.0
        ASAV7=0.0
        ASAV8=0.0
      ENDIF
      CALL DPLIBF(IW2(I),IW22(I),W2(IP1),ASAV1,ASAV2,ASAV3,ASAV4,   &
                  ASAV5,ASAV6,ASAV7,ASAV8,   &
                  I,   &
                  IANGLU,RESULT,IBUGEV,IERROR)
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,333)
  333   FORMAT('IN EVALM, AFTER RETURNING FROM DPLIBF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,334)RESULT,IERROR
  334   FORMAT('RESULT, IERROR = ',F20.10,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IERROR.EQ.'YES')GO TO 9000
      NTERM=NTERM+1
      TERM(NTERM)=RESULT
!
      IOP(NTERM)='V'
!
!     CHECK THAT NTERM HAS NOT EXCEEDED MAXTER (USUALLY 80)
!
      IF(NTERM.GT.MAXTER)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1902)
 1902   FORMAT('      THE VARIABLE NTERM HAS JUST EXCEEDED THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1903)MAXTER
 1903   FORMAT('      THE MAXIMUM ALLOWABLE LIMIT OF ',I5)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IDEL=2
  100 CONTINUE
      I=I+IDEL
      IF(I.LE.ISTOP)GO TO 150
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,491)
  491   FORMAT('AFTER THE LIBRARY FUNCTIONS HAVE BEEN ',   &
               'EVALUATED AND ELIMINATED--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,492)NTERM,NOP
  492   FORMAT('NTERM,NOP = ',2I6)
        CALL DPWRST('XXX','BUG ')
        DO 493 I=1,NTERM
          WRITE(ICOUT,494)I,TERM(I),IOP(I)
  494     FORMAT('I,TERM(I),IOP(I) = ',I6,E15.7,2X,A4)
          CALL DPWRST('XXX','BUG ')
  493   CONTINUE
      ENDIF
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CHECK TO SEE THAT THE NUMBER OF TERMS =          **
!               **  ONE MORE THAN THE NUMBER OF OPERATIONS.          **
!               **  ALSO CHECK TO SEE IF THE SPECIAL CASE            **
!               **  EXISTS WHERE THERE IS ONLY 1 TERM--              **
!               **  IF SO, SET ANS = TO THIS FIRST TERM AND EXIT.    **
!               *******************************************************
!
      NOPP1=NOP+1
      IF(NTERM.EQ.NOPP1)THEN
        IF(NTERM.EQ.1)THEN
          ANS=TERM(1)
          GO TO 9000
        ELSEIF(NTERM.EQ.0)THEN
          WRITE(ICOUT,21)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,571)
  571     FORMAT('      NUMBER OF TERMS = 0 AT END OF STEP 2 ',   &
                 '(LIBRARY FUNCTIONS ELIMINATED)')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,560)
  560   FORMAT('      NUMBER OF TERMS NOT EQUAL TO NUMBER OF ',   &
               'OPERATIONS + 1')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,566)NTERM,NOPP1
  566   FORMAT('      NTERM,NOPP1 = ',I8,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************************
!               **  STEP 3--                                          **
!               **  OPERATE ON THE TERM(.) AND IOP(.) VECTORS.  AT    **
!               **  THIS POINT WE HAVE ONLY ALTERNATING TERMS AND     **
!               **  OPERATIONS WHERE AN OPERATION IS ANY ONE OF THE   **
!               **  5-- +   -   *   /   **.  EVALUATE AND ELIMINATE   **
!               **  ALL SQUEEZE THE TERM(.) AND IOP(.) VECTORS UNTIL  **
!               **  UNTIL ALL ** ARE GONE.                            **
!               ********************************************************
!
      I=1
 1100 CONTINUE
      IF(IOP(I).NE.'**')THEN
        I=I+1
        IF(I.LE.NOP)GO TO 1100
        GO TO 1500
      ENDIF
!
      IP1=I+1
      T1=TERM(I)
      T2=TERM(IP1)
      T3=ABS(T1)
      T4=ABS(T2)
      T34=0.0
      IF(T3.GT.0.0.AND.T4.GT.0.0)T34=T4*LOG(T3)
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,601)I,IP1
  601   FORMAT('AT 1100: I,IP1 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,603)T1,T2,T3,T4,T34,ALCPUM
  603   FORMAT('T1,T2,T3,T4,T34,ALCPUM = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(T34.GT.ALCPUM)GO TO 8011
      IF(T1.NE.CPUMIN.AND.T1.NE.CPUMAX.AND.   &
         T2.NE.CPUMIN.AND.T2.NE.CPUMAX)GO TO 1219
      IF(T1.EQ.CPUMIN.AND.T4.LE.1.0)GO TO 1219
      IF(T2.EQ.CPUMIN.AND.T3.LE.1.0)GO TO 1219
      IF(T1.EQ.CPUMAX.AND.T4.LE.1.0)GO TO 1219
      IF(T2.EQ.CPUMAX.AND.T3.LE.1.0)GO TO 1219
      GO TO 8011
!
 1219 CONTINUE
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,611)
  611   FORMAT('AT 1219')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(T1.EQ.0.0)THEN
        IF(T2.GT.0.0)THEN
          TERM(I)=0.0
          GO TO 1239
        ENDIF
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1222)
 1222   FORMAT('      ATTEMPT TO RAISE A ZERO NUMBER ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1223)
 1223   FORMAT('      TO A ZERO OR NEGATIVE POWER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1226)T2
 1226   FORMAT('      THE POWER           = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(T1.LT.0.0)THEN
!
        IF(IBUGEV.EQ.'ON')THEN
          WRITE(ICOUT,631)CUTOFF
  631     FORMAT('AT T1 LESS THAN ZERO CASE: CUTOFF = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ABST2=ABS(T2)
        ISIGN=(-1)
        IF(T2.GE.0.0)ISIGN=1
        IABST2=INT(ABST2)
        IABS2=IABST2
!CCCC   2020/08: FIX FOLLOWING LINE
!CCCC   REM=ABST2-AIABS2
        REM=ABST2-REAL(IABS2)
        ABSREM=ABS(REM)
!
        IF(IBUGEV.EQ.'ON')THEN
          WRITE(ICOUT,633)ISIGN,IABST2,IABS2,ABST2,REM,ABSREM
  633     FORMAT('ISIGN,IABST2,IABS2,ABST2,REM,ABSREM = ',3I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ABSREM.GE.CUTOFF)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,21)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1232)
 1232     FORMAT('      ATTEMPT TO RAISE A NEGATIVE NUMBER ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1233)
 1233     FORMAT('      TO A FRACTIONAL POWER.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1235)T1
 1235     FORMAT('      THE NEGATIVE NUMBER = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1236)T2
 1236     FORMAT('      THE POWER           = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IF(IBUGEV.EQ.'ON')THEN
          WRITE(ICOUT,7777)T1,T2,ABST2,ISIGN,IABST2
 7777     FORMAT('T1,T2,ABST2,ISIGN,IABST2 = ',3E15.7,2I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7778)AIABS2,REM,ABSREM,TERM(I)
 7778     FORMAT('AIABS2,REM,ABSREM,TERM(I) = ',4E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        TERM(I)=TERM(I)**(ISIGN*IABST2)
        GO TO 1239
      ENDIF
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,1238)I,TERM(I),TERM(IP1),T1,T2,AIABS2,REM
 1238   FORMAT('I,TERM(I),TERM(IP1),T1,T2,AIABS2,REM = ',I4,6E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC FOLLOWING LINE SEEMS TO SHOW A COMPILER BUG FOR THE OLDER LAHEY
!CCCC COMPILER.  WORKAROUND FOR THIS COMPILER.   SEPTEMBER 1997.
!CCCC TERM(I)=TERM(I)**TERM(IP1)
      IF(ICOMPI.NE.'LAHE')THEN
        TERM(I)=TERM(I)**TERM(IP1)
      ELSE
        ATEMP1=TERM(IP1)*LOG(TERM(I))
        TERM(I)=EXP(ATEMP1)
      ENDIF
!
 1239 CONTINUE
      NOPM1=NOP-1
      IF(I.LT.NOP)THEN
        DO 1400 J=I,NOPM1
          JP1=J+1
          JP2=J+2
          IOP(J)=IOP(JP1)
          TERM(JP1)=TERM(JP2)
 1400   CONTINUE
      ENDIF
      NOP=NOPM1
      IF(I.LE.NOP)GO TO 1100
!
 1500 CONTINUE
      NTERM=NOP+1
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,1991)
 1991   FORMAT('AFTER THE ** HAVE BEEN EVALUATED AND ELIMINATED--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1992)NTERM,NOP
 1992   FORMAT('NTERM,NOP = ',2I6)
        CALL DPWRST('XXX','BUG ')
        DO 1993 I=1,NTERM
          WRITE(ICOUT,1994)I,TERM(I),IOP(I)
 1994     FORMAT('I,TERM(I),IOP(I) = ',I6,E15.7,2X,A4)
          CALL DPWRST('XXX','BUG ')
 1993   CONTINUE
      ENDIF
!
!               ********************************************************
!               **  STEP 4--                                          **
!               **  OPERATE ON THE TERM(.) AND IOP(.) VECTORS. AT     **
!               **  THIS POINT WE HAVE ONLY ALTERNATING TERMS AND     **
!               **  OPERATIONS WHERE AN OPERATION IS ANY ONE OF THE   **
!               **  4-- +   -   *   /   .                             **
!               **  EVALUATE AND ELIMINATE ALL * AND / IN SEQUENCE.   **
!               **  SQUEEZE THE TERM(.) AND IOP(.) VECTORS UNTIL      **
!               **  UNTIL ALL * AND / ARE GONE.                       **
!               ********************************************************
!
      I=1
 2100 CONTINUE
      IF(IOP(I).EQ.'*')THEN
        IP1=I+1
        T1=TERM(I)
        T2=TERM(IP1)
        T3=ABS(T1)
        T4=ABS(T2)
        T34=0.0
        IF(T3.GT.0.0.AND.T4.GT.0.0)T34=LOG(T3)+LOG(T4)
        IF(T34.GT.ALCPUM)GO TO 8011
        IF(T34.LT.-ALCPUM)TERM(I)=0.0
        IF(T34.LT.-ALCPUM)GO TO 2250
        IF(T1.NE.CPUMIN.AND.T1.NE.CPUMAX.AND.   &
           T2.NE.CPUMIN.AND.T2.NE.CPUMAX)GO TO 2219
        IF(T1.EQ.CPUMIN.AND.T4.LE.1.0)GO TO 2219
        IF(T2.EQ.CPUMIN.AND.T3.LE.1.0)GO TO 2219
        IF(T1.EQ.CPUMAX.AND.T4.LE.1.0)GO TO 2219
        IF(T2.EQ.CPUMAX.AND.T3.LE.1.0)GO TO 2219
        GO TO 8011
!
 2219   CONTINUE
        TERM(I)=TERM(I)*TERM(IP1)
        GO TO 2250
      ELSEIF(IOP(I).EQ.'/')THEN
        IP1=I+1
        T1=TERM(I)
        T2=TERM(IP1)
        T3=ABS(T1)
        T4=ABS(T2)
        T34=0.0
        IF(T3.GT.0.0.AND.T4.GT.0.0)T34=LOG(T3)-LOG(T4)
        IF(T34.GT.ALCPUM)GO TO 8011
        IF(T34.LT.-ALCPUM)TERM(I)=0.0
        IF(T34.LT.-ALCPUM)GO TO 2250
        IF(T1.NE.CPUMIN.AND.T1.NE.CPUMAX.AND.   &
           T2.NE.CPUMIN.AND.T2.NE.CPUMAX)GO TO 2229
        IF(T1.EQ.CPUMIN.AND.T4.GE.1.0)GO TO 2229
        IF(T1.EQ.CPUMAX.AND.T4.GE.1.0)GO TO 2229
        GO TO 8011
!
 2229  CONTINUE
        IF(T2.EQ.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,21)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2232)
 2232     FORMAT('      ATTEMPT TO DIVIDE A NUMBER BY ZERO.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2235)T1
 2235     FORMAT('      THE NUMERATOR   = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2236)T2
 2236     FORMAT('      THE DENOMINATOR = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        TERM(I)=TERM(I)/TERM(IP1)
        GO TO 2250
      ELSE
        I=I+1
        GO TO 2350
      ENDIF
!
 2250 CONTINUE
      NOPM1=NOP-1
      IF(I.LT.NOP)THEN
        DO 2400 J=I,NOPM1
          JP1=J+1
          JP2=J+2
          IOP(J)=IOP(JP1)
          TERM(JP1)=TERM(JP2)
 2400   CONTINUE
      ENDIF
      NOP=NOPM1
!
 2350 CONTINUE
      IF(I.LE.NOP)GO TO 2100
      NTERM=NOP+1
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,2991)
 2991   FORMAT('AFTER THE * AND / HAVE BEEN EVALUATED AND ELIMINATED--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2992)NTERM,NOP
 2992   FORMAT('NTERM,NOP = ',2I6)
        CALL DPWRST('XXX','BUG ')
        DO 2993 I=1,NTERM
          WRITE(ICOUT,2994)I,TERM(I),IOP(I)
 2994     FORMAT('I,TERM(I),IOP(I) = ',I6,E15.7,2X,A4)
          CALL DPWRST('XXX','BUG ')
 2993   CONTINUE
      ENDIF
!
!               ********************************************************
!               **  STEP 5--                                          **
!               **  OPERATE ON THE TERM(.) AND IOP(.) VECTORS.  AT    **
!               **  THIS POINT WE HAVE ONLY ALTERNATING TERMS AND     **
!               **  OPERATIONS WHERE AN OPERATION IS ANY ONE OF THE   **
!               **  2-- + OR - .  EVALUATE ALL + OR - OPERATIONS IN   **
!               **  SEQUENCE.  SQUEEZE THE TERM(.) AND IOP(.) VECTORS **
!               **  UNTIL ALL + AND - OPERATIONS ARE GONE.            **
!               ********************************************************
!
      IF(NOP.LT.1)THEN
        ANS=TERM(1)
        GO TO 9000
      ENDIF
      ANS=TERM(1)
      DO 3200 I=1,NOP
        IP1=I+1
        IF(IOP(I).EQ.'-')THEN
          T1=TERM(I)
          T2=TERM(IP1)
          IF(T1.NE.CPUMIN.AND.T1.NE.CPUMAX.AND.   &
             T2.NE.CPUMIN.AND.T2.NE.CPUMAX)GO TO 3229
          IF(T1.EQ.CPUMIN.AND.T2.LE.0.0)GO TO 3229
          IF(T2.EQ.CPUMIN.AND.T1.LE.0.0)GO TO 3229
          IF(T1.EQ.CPUMAX.AND.T2.GE.0.0)GO TO 3229
          IF(T2.EQ.CPUMAX.AND.T1.GE.0.0)GO TO 3229
          GO TO 8011
 3229     CONTINUE
          ANS=ANS-TERM(IP1)
        ELSE
          T1=TERM(I)
          T2=TERM(IP1)
          IF(T1.NE.CPUMIN.AND.T1.NE.CPUMAX.AND.   &
             T2.NE.CPUMIN.AND.T2.NE.CPUMAX)GO TO 3219
          IF(T1.EQ.CPUMIN.AND.T2.GE.0.0)GO TO 3219
          IF(T2.EQ.CPUMIN.AND.T1.GE.0.0)GO TO 3219
          IF(T1.EQ.CPUMAX.AND.T2.LE.0.0)GO TO 3219
          IF(T2.EQ.CPUMAX.AND.T1.LE.0.0)GO TO 3219
          GO TO 8011
 3219     CONTINUE
          ANS=ANS+TERM(IP1)
        ENDIF
!
 3200 CONTINUE
      GO TO 9000
!
 8011 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,21)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8013)
 8013 FORMAT('      ATTEMPT TO CARRY OUT AN OPERATION WHICH RESULTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8014)
 8014 FORMAT('      IN AN OUT-OF-RANGE NUMBER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8015)
 8015 FORMAT('      THE OPERATION      = **')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8016)T1
 8016 FORMAT('      THE FIRST  OPERAND = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8017)T2
 8017 FORMAT('      THE SECOND OPERAND = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EVALM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ANS,IERROR
 9012   FORMAT('ANS,IERROR = ',E15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9113 I=1,5
          WRITE(ICOUT,9013)I,SAVE1(I),SAVE2(I),SAVE3(I),SAVE4(I)
 9013     FORMAT('I,SAVE1,SAVE2,SAVE3,SAVE4 = ',I3,5E15.7)
          CALL DPWRST('XXX','BUG ')
 9113   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EVALM
      SUBROUTINE EWECDF(X,GAMMA,THETA,MINMAX,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA, SHAPE PARAMETER THETA.
!              THERE ARE 2 SUCH EXPONETIATED WEIBULL FAMILIES--
!                 ONE FOR THE MIN ORDER STAT (THE USUAL) AND
!                 ONE FOR THE MAX ORDER STAT.
!              (SEE SARHAN & GREENBERG, PAGE 69)
!              THE EXPONETIATED WEIBULL TYPE IS SPECIFIED VIA   MINMAX
!              FOR MINMAX = 1  (FOR THE DEFAULT MINIMUM)
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (THETA*GAMMA)*(X**(GAMMA-1)) * EXP(-(X**GAMMA))
!                        *(1-EXP(-(X**GAMMA))**(THETA-1)
!              FOR MINMAX = 2 (FOR THE MAXIMUM),
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL NEGATIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = ...
!                 F(X) = GAMMA * (X**(GAMMA-1)) * EXP(-(X**GAMMA)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN EXPONENTIATED WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE EXPONENTIATED WEIBULL DISTRIBUTION
!             WITH TAIL LENGHT PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --MUDHOLKAR AND SRIVASTAVE, "THE EXPONENTIATED WEIBULL
!                 FAMILY: A REANALYSIS OF THE BUS-MOTOR-FAILURE DATA",
!                 TECHNOMETRICS, NOVEMBER, 1995, PP436-437.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DT
      DOUBLE PRECISION DTERM1, DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      MINMSV=MINMAX
      MINMAX=1
      CDF=0.0
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'EWECDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'EWECDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
       IF(X.LE.0.0)THEN
         CDF=0.0
       ELSE
         DX=DBLE(X)
         DG=DBLE(GAMMA)
         DT=DBLE(THETA)
         DTERM1=DLOG(1.0D0-DEXP(-(DX**DG)))
         DTERM2=DT*DTERM1
         DCDF=DEXP(DTERM2)
         CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      MINMAX=MINMSV
      RETURN
      END SUBROUTINE EWECDF
      SUBROUTINE EWECHA(X,GAMMA,THETA,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA, SHAPE PARAMETER THETA.
!              FOR MINMAX = 1  (FOR THE DEFAULT MINIMUM)
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (THETA*GAMMA)*(X**(GAMMA-1)) * EXP(-(X**GAMMA))
!                        *(1-EXP(-(X**GAMMA))**(THETA-1)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN EXPONENTIATED WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER GAMMA, SHAPE PARAMETER THETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE
!                 --GAMMA, THETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MUDHOLKAR AND SRIVASTAVE, "THE EXPONENTIATED WEIBULL
!                 FAMILY: A REANALYSIS OF THE BUS-MOTOR-FAILURE DATA",
!                 TECHNOMETRICS, NOVEMBER, 1995, PP436-437.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DT
      DOUBLE PRECISION DTERM1, DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      MINMSV=MINMAX
      MINMAX=1
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'EWECHA IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'EWECHA IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!
      IF(X.LE.0.0)THEN
        HAZ=0.0
      ELSE
!
        DX=DBLE(X)
        DT=DBLE(THETA)
        DG=DBLE(GAMMA)
        DTERM1=DLOG(1.0D0-DEXP(-(DX**DG)))
        DTERM2=DT*DTERM1
        DCDF=DEXP(DTERM2)
!
        DHAZ=-DLOG(1.0D0-DCDF)
        HAZ=SNGL(DHAZ)
!
      ENDIF
!
 9000 CONTINUE
      MINMAX=MINMSV
      RETURN
      END SUBROUTINE EWECHA
      SUBROUTINE EWEHAZ(X,GAMMA,THETA,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA, SHAPE PARAMETER THETA.
!              FOR MINMAX = 1  (FOR THE DEFAULT MINIMUM)
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (THETA*GAMMA)*(X**(GAMMA-1)) * EXP(-(X**GAMMA))
!                        *(1-EXP(-(X**GAMMA))**(THETA-1)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN EXPONENTIATED WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD FUNCTION
!                                VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER GAMMA, SHAPE PARAMETER THETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE
!                 --GAMMA, THETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MUDHOLKAR AND SRIVASTAVE, "THE EXPONENTIATED WEIBULL
!                 FAMILY: A REANALYSIS OF THE BUS-MOTOR-FAILURE DATA",
!                 TECHNOMETRICS, NOVEMBER, 1995, PP436-437.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DT
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DTERM6, DTERM7
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      MINMSV=MINMAX
      MINMAX=1
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'EWEHAZ IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9000
      ENDIF
      IF(THETA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'EWEHAZ IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9000
      ENDIF
!
      IF(X.LE.0.0)THEN
        HAZ=0.0
      ELSE
        DX=DBLE(X)
        DT=DBLE(THETA)
        DG=DBLE(GAMMA)
!
        DTERM7=DEXP(-(DX**DG))
        DTERM1=DLOG(DG) + DLOG(DT)
        DTERM2=(DT-1.0D0)*DLOG(1.0D0-DTERM7)
        DTERM3=-(DX**DG)
        DTERM4=(DG-1.0D0)*DLOG(DX)
        DTERM5=DLOG(1.0D0 - (1.0D0 - DTERM7)**DT)
        DTERM6=DTERM1+DTERM2+DTERM3+DTERM4-DTERM5
        DHAZ=DEXP(DTERM6)
        HAZ=REAL(DHAZ)
!
      ENDIF
!
 9000 CONTINUE
      MINMAX=MINMSV
      RETURN
      END SUBROUTINE EWEHAZ
      SUBROUTINE EWEPDF(X,GAMMA,THETA,MINMAX,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA, SHAPE PARAMETER THETA.
!              THERE ARE 2 SUCH EXPONETIATED WEIBULL FAMILIES--
!                 ONE FOR THE MIN ORDER STAT (THE USUAL) AND
!                 ONE FOR THE MAX ORDER STAT.
!              (SEE SARHAN & GREENBERG, PAGE 69)
!              THE EXPONETIATED WEIBULL TYPE IS SPECIFIED VIA   MINMAX
!              FOR MINMAX = 1  (FOR THE DEFAULT MINIMUM)
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (THETA*GAMMA)*(X**(GAMMA-1)) * EXP(-(X**GAMMA))
!                        *(1-EXP(-(X**GAMMA))**(THETA-1)
!              FOR MINMAX = 2 (FOR THE MAXIMUM),
!                 THE EXPONETIATED EXPONENTIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL NEGATIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = ...
!                 F(X) = GAMMA * (X**(GAMMA-1)) * EXP(-(X**GAMMA)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN EXPONENTIATED WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE FOR THE EXPONENTIATED WEIBULL DISTRIBUTION
!             WITH TAIL LENGHT PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!                 1962, WILEY, PAGE 69.
!               --MUDHOLKAR AND SRIVASTAVE, "THE EXPONENTIATED WEIBULL
!                 FAMILY: A REANALYSIS OF THE BUS-MOTOR-FAILURE DATA",
!                 TECHNOMETRICS, NOVEMBER, 1995, PP436-437.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DT
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      MINMSV=MINMAX
      MINMAX=1
      PDF=0.0
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'EWEPDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'EWEPDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
       IF(X.LE.0.0)THEN
         PDF=0.0
       ELSE
         DX=DBLE(X)
         IF(DX.LT.0.0000001D0)DX=0.0000001D0
         DG=DBLE(GAMMA)
         DT=DBLE(THETA)
         DTERM1=DLOG(DG) + DLOG(DT)
         DTERM2=(DT-1.0D0)*DLOG(1.0D0-DEXP(-(DX**DG)))
         DTERM3=-(DX**DG)
         DTERM4=(DG-1.0D0)*DLOG(DX)
         DTERM5=DTERM1+DTERM2+DTERM3+DTERM4
         DPDF=DEXP(DTERM5)
         PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      MINMAX=MINMSV
      RETURN
      END SUBROUTINE EWEPDF
      SUBROUTINE EWEPPF(P,GAMMA,THETA,MINMAX,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE EXPONETIATED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA, SHAPE PARAMETER THETA.
!              THERE ARE 2 SUCH EXPONETIATED WEIBULL FAMILIES--
!                 ONE FOR THE MIN ORDER STAT (THE USUAL) AND
!                 ONE FOR THE MAX ORDER STAT.
!              (SEE SARHAN & GREENBERG, PAGE 69)
!              THE EXPONETIATED WEIBULL TYPE IS SPECIFIED VIA   MINMAX
!              FOR MINMAX = 1  (FOR THE DEFAULT MINIMUM)
!                 THE EXPONETIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL POSITIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = (THETA*GAMMA)*(X**(GAMMA-1)) * EXP(-(X**GAMMA))
!                        *(1-EXP(-(X**GAMMA))**(THETA-1)
!              FOR MINMAX = 2 (FOR THE MAXIMUM),
!                 THE EXPONETIATED WEIBULL DISTRIBUTION USED
!                 HEREIN IS DEFINED FOR ALL NEGATIVE X,
!                 AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X) = ...
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN EXPONETIATED WEIBULL DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE EXPONETIATED WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SARHAN & GREENBERG,
!                 CONTRIBUTIONS TO ORDER STATISTICS,
!               --MUDHOLKAR AND SRIVASTAVE, "THE EXPONENTIATED WEIBULL
!                 FAMILY: A REANALYSIS OF THE BUS-MOTOR-FAILURE DATA",
!                 TECHNOMETRICS, NOVEMBER, 1995, PP436-437.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
      DOUBLE PRECISION DT
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      MINMSV=MINMAX
      MINMAX=1
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
               'EWEPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
               'EWEPPF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
               'EWEPPF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!
       IF(P.EQ.0.0)THEN
         PPF=0.0
       ELSE
         DP=DBLE(P)
         DG=DBLE(1.0/GAMMA)
         DT=DBLE(1.0/THETA)
         DTERM1=DG*DLOG(-DLOG(1.0D0-DP**DT))
         DPPF=DEXP(DTERM1)
         PPF=REAL(DPPF)
      ENDIF
!
 9000 CONTINUE
      MINMAX=MINMSV
      RETURN
      END SUBROUTINE EWEPPF
      SUBROUTINE EEWRAN(N,AL,GAMMA1,SCALE1,GAMMA2,SCALE2,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE END EFFECTS WEIBULL DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --AL     = THE SINGLE PRECISION VALUE OF THE
!                                FIBER LENGTH PARAMETER
!                     --GAMMA1 = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE (1) PARAMETER.
!                     --SCALE1 = THE SINGLE PRECISION VALUE OF THE
!                                SCALE (1) PARAMETER.
!                     --GAMMA2 = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE (2) PARAMETER.
!                     --SCALE2 = THE SINGLE PRECISION VALUE OF THE
!                                SCALE (2) PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE END EFFECTS WEIBULL DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --SHAPE PARAMETERS SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.7
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,55)
   55   FORMAT('***** ERROR--THE REQUESTED NUMBER OF END EFFECTS ',   &
               'WEIBULL RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE1.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE1 PARAMETER FOR THE END ',   &
               'EFFECTS WEIBULL RANDOM NUMBERSIS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA1.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA1 PARAMETER FOR THE END ',   &
               'EFFECTS WEIBULL RANDOM NUMBERSIS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(SCALE2.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE2 PARAMETER FOR THE END ',   &
               'EFFECTS WEIBULL RANDOM NUMBERSIS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA2.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA2 PARAMETER FOR THE END ',   &
               'EFFECTS WEIBULL RANDOM NUMBERSIS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE L PARAMETER FOR THE END ',   &
               'EFFECTS WEIBULL RANDOM NUMBERSIS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N END EFFECTS WEIBULL DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL EEWPPF(DBLE(X(I)),DBLE(AL),DBLE(GAMMA1),DBLE(SCALE1),   &
                    DBLE(GAMMA2),DBLE(SCALE2),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EEWRAN
      SUBROUTINE EWERAN(N,GAMMA,THETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE EXPONENTIATED WEIBULL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = GAMMA, THETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --THETA  = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                THETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE EXPONENTIATED WEIBULL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = GAMMA AND THETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NON E.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'EWERAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N EXPONENTIATED WEIBULL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      MINMAX=1
      DO 100 I=1,N
        CALL EWEPPF(X(I),GAMMA,THETA,MINMAX,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EWERAN
      DOUBLE PRECISION FUNCTION EXP3(XVALUE)
!
!   DESCRIPTION
!
!      This function calculates
!
!           EXP3(X) = integral 0 to X  (exp(-t*t*t)) dt
!
!      The code uses Chebyshev expansions, whose coefficients are
!      given to 20 decimal places.
!
!
!   ERROR RETURNS
!
!      If XVALUE < 0, an error message is printed and the function
!      returns the value 0.
!
!
!   MACHINE-DEPENDENT CONSTANTS
!
!      NTERM1 - INTEGER - The no. of terms of the array AEXP3,
!                         The recommended value is such that
!                               AEXP3(NTERM1) < EPS/100.
!
!      NTERM2 - INTEGER - The no. of terms of the array AEXP3A.
!                         The recommended value is such that
!                               AEXP3A(NTERM2) < EPS/100.
!
!      XLOW - DOUBLE PRECISION - The value below which EXP3(X) = X to machine
!                    precision. The recommended value is
!                          cube root(4*EPSNEG)
!
!      XUPPER - DOUBLE PRECISION - The value above which EXP3(X) = 0.89297...
!                      to machine precision. The recommended value is
!                           cube root(-ln(EPSNEG))
!
!      For values of EPS and EPSNEG for various machine/compiler
!      combinations refer to the file MACHCON.TXT.
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED
!
!      EXP, LOG
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR
!
!      DR. ALLAN J. MACLEOD,
!      DEPARTMENT OF MATHEMATICS AND STATISTICS,
!      UNIVERSITY OF PAISLEY,
!      HIGH ST.,
!      PAISLEY
!      SCOTLAND.
!
!      (e-mail  macl_ms0@paisley.ac.uk )
!
!
!   LATEST MODIFICATION:  23 January, 1996
!
!
      INTEGER NTERM1,NTERM2
      DOUBLE PRECISION AEXP3(0:24),AEXP3A(0:24),CHEVAL,   &
            FOUR,FUNINF,HALF,ONE,ONEHUN,SIXTEN,T,THREE,   &
            TWO,X,XLOW,XUPPER,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*14
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'EXP3  '/
!CCCC DATA ERRMSG/'ARGUMENT < 0.0'/
      DATA ZERO,HALF,ONE/0.0D0 , 0.5D0 , 1.0D0/
      DATA TWO,THREE,FOUR/2.0D0 , 3.0D0 , 4.0D0 /
      DATA SIXTEN,ONEHUN/16.0D0 , 100.0D0/
      DATA FUNINF/0.89297951156924921122D0/
      DATA AEXP3(0)/  1.26919841422112601434D0/
      DATA AEXP3(1)/ -0.24884644638414098226D0/
      DATA AEXP3(2)/  0.8052622071723104125D-1/
      DATA AEXP3(3)/ -0.2577273325196832934D-1/
      DATA AEXP3(4)/  0.759987887307377429D-2/
      DATA AEXP3(5)/ -0.203069558194040510D-2/
      DATA AEXP3(6)/  0.49083458669932917D-3/
      DATA AEXP3(7)/ -0.10768223914202077D-3/
      DATA AEXP3(8)/  0.2155172626428984D-4/
      DATA AEXP3(9)/ -0.395670513738429D-5/
      DATA AEXP3(10)/ 0.66992409338956D-6/
      DATA AEXP3(11)/-0.10513218080703D-6/
      DATA AEXP3(12)/ 0.1536258019825D-7/
      DATA AEXP3(13)/-0.209909603636D-8/
      DATA AEXP3(14)/ 0.26921095381D-9/
      DATA AEXP3(15)/-0.3251952422D-10/
      DATA AEXP3(16)/ 0.371148157D-11/
      DATA AEXP3(17)/-0.40136518D-12/
      DATA AEXP3(18)/ 0.4123346D-13/
      DATA AEXP3(19)/-0.403375D-14/
      DATA AEXP3(20)/ 0.37658D-15/
      DATA AEXP3(21)/-0.3362D-16/
      DATA AEXP3(22)/ 0.288D-17/
      DATA AEXP3(23)/-0.24D-18/
      DATA AEXP3(24)/ 0.2D-19/
      DATA AEXP3A(0)/  1.92704649550682737293D0/
      DATA AEXP3A(1)/ -0.3492935652048138054D-1/
      DATA AEXP3A(2)/  0.145033837189830093D-2/
      DATA AEXP3A(3)/ -0.8925336718327903D-4/
      DATA AEXP3A(4)/  0.705423921911838D-5/
      DATA AEXP3A(5)/ -0.66717274547611D-6/
      DATA AEXP3A(6)/  0.7242675899824D-7/
      DATA AEXP3A(7)/ -0.878258256056D-8/
      DATA AEXP3A(8)/  0.116722344278D-8/
      DATA AEXP3A(9)/ -0.16766312812D-9/
      DATA AEXP3A(10)/ 0.2575501577D-10/
      DATA AEXP3A(11)/-0.419578881D-11/
      DATA AEXP3A(12)/ 0.72010412D-12/
      DATA AEXP3A(13)/-0.12949055D-12/
      DATA AEXP3A(14)/ 0.2428703D-13/
      DATA AEXP3A(15)/-0.473311D-14/
      DATA AEXP3A(16)/ 0.95531D-15/
      DATA AEXP3A(17)/-0.19914D-15/
      DATA AEXP3A(18)/ 0.4277D-16/
      DATA AEXP3A(19)/-0.944D-17/
      DATA AEXP3A(20)/ 0.214D-17/
      DATA AEXP3A(21)/-0.50D-18/
      DATA AEXP3A(22)/ 0.12D-18/
      DATA AEXP3A(23)/-0.3D-19/
      DATA AEXP3A(24)/ 0.1D-19/
!
!   Start calculation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         EXP3 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM EXP3--ARGUMENT MUST BE ',   &
             'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(3)
      XLOW = ( FOUR * T ) ** (ONE/THREE)
      XUPPER = ( -LOG ( T ) ) ** (ONE/THREE)
      T = T / ONEHUN
      IF ( X .LE. TWO ) THEN
         DO 10 NTERM1 = 24 , 0 , -1
            IF ( ABS(AEXP3(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      CONTINUE
      ELSE
         DO 40 NTERM2 = 24 , 0 , -1
            IF ( ABS(AEXP3A(NTERM2)) .GT. T ) GO TO  49
 40      CONTINUE
 49      CONTINUE
      ENDIF
!
!   Code for XVALUE < =  2
!
      IF ( X .LE. TWO ) THEN
         IF ( X .LT. XLOW ) THEN
            EXP3 = X
         ELSE
            T =  (  ( X * X * X / FOUR ) - HALF ) - HALF
            EXP3 = X * CHEVAL ( NTERM1,AEXP3,T )
         ENDIF
      ELSE
!
!   Code for XVALUE > 2
!
         IF ( X .GT. XUPPER ) THEN
            EXP3 = FUNINF
         ELSE
            T = ( ( SIXTEN/ ( X * X * X ) ) - HALF ) - HALF
            T = CHEVAL ( NTERM2,AEXP3A,T )
            T = T * EXP ( -X * X * X ) / ( THREE * X * X )
            EXP3 = FUNINF - T
         ENDIF
      ENDIF
      RETURN
      END FUNCTION EXP3
      SUBROUTINE EXPLOS(X,N,ENGLSL,ENGUSL,COSUSL,IWRITE,XEL,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE EXPECTED LOSS FROM THE DATA IN THE INPUT VECTOR X.
!              THIS CALCULATION ASSUMES--
!                 1) A QUADRATIC LOSS FUNCTION
!                 2) A NORMAL DISTRIBUTION
!                 3) WITH MEAN XBAR AND STANDARD DEVIATION S
!                 4) A DOLLAR COST    COSUSL   AT THE UPPER SPEC LIMIT
!                 5) THE TARGET IS MIDWAY BETWEEN ENGUSL AND ENGLSL
!              XEL = INTEGRAL K*(X-TARGET)**2 * NORMALPDF(XBAR,S)
!              WHERE K IS DERIVED FROM THE LOSS FUNCTION
!                 L(X) = K*(X-TARGET)**2
!              EVALUATED AT X = USL
!                 SOLVING     L(USL) = COSUSL
!                             K*(USL-TARGET)**2 = COSUSL
!                             K = COSUSL / (USL-TARGET)**2
!     THE FINAL FORM FOR XEL IS QUITE SIMPLE--
!        XEL = COSUSL * (KSIGMA**2 + KMU**2)
!     WHERE KSIGMA IS DEFINED VIA   SIGMA = KSIGMA * H
!     AND   KMU    IS DEFINED VIA   MU    = TARGET + KMU*H
!     YIELDING KSIGMA = SIGMA / H
!     AND      KMU    = (MU - TARGET) / H
!     IN PRACTICE, WE USE XBAR FOR MU AND S FOR SIGMA.
!     NOTE--XEL IS A MEASURE OF PROCESS COST AND IS
!           SENSITIVE TO LOSS FROM BOTH BIAS AND FROM VARIATION.
!     NOTE--XEL IS A MEASURE WHICH TAKES ON
!           THE VALUES 0 TO INFINITY.
!           A GOOD PROCESS YIELDS VALUES OF
!           EXPECTED LOSS NEAR 0.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ENGLSL = LOWER (ENGINEERING) SPEC LIMIT
!                     --ENGUSL = UPPER (ENGINEERING) SPEC LIMIT
!                     --COSUSL = COST AT UPPER SPEC LIMIT
!     OUTPUT ARGUMENTS--EXPLOS = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE EXPECTED LOSS
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE EXPECTED LOSS (IN XEL)
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--R&M 2000 AIR FORCE MANUAL
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.5
!     ORIGINAL VERSION--MAY       1989.
!     UPDATED         --SEPTEMBER 1990. REVERSE INPUT ARGS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DVAR
      DOUBLE PRECISION DSD
!
      DOUBLE PRECISION DUSL
      DOUBLE PRECISION DLSL
!
      DOUBLE PRECISION DTARG
      DOUBLE PRECISION DH
      DOUBLE PRECISION DKMU
      DOUBLE PRECISION DKSIGM
      DOUBLE PRECISION DEL
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPL'
      ISUBN2='OS  '
      IERROR='NO'
!
      DMEAN=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF EXPLOS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ENGUSL,ENGLSL,COSUSL
   54 FORMAT('ENGUSL,ENGLSL,COSUSL = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE PROCESS CAPABILITY INDEX EXPLOS  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN EXPLOS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE EXPECTED LOSS IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN EXPLOS--',
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC1'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
      XSD=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN EXPLOS--',
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      XSD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***************************************
!               **  STEP 2--                         **
!               **  COMPUTE THE STANDARD DEVIATION.  **
!               ***************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
      DSUM=0.0D0
      DO 300 I=1,N
      DX=X(I)
      DSUM=DSUM+(DX-DMEAN)**2
  300 CONTINUE
      DVAR=DSUM/(DN-1.0D0)
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
      XSD=DSD
!
!               **************************************************
!               **  STEP 3--                                    **
!               **  COMPUTE THE EXPECTED LOSS                   **
!               **************************************************
!
      DUSL=ENGUSL
      DLSL=ENGLSL
!
      DTARG=(DUSL+DLSL)/2.0D0
      DH=(DUSL-DLSL)/2.0D0
!
      IF(DH.EQ.0.0D0)XEL=CPUMAX
      IF(DH.EQ.0.0D0)GO TO 490
!
      DKSIGM=DSD/DH
      DKMU=(DMEAN-DTARG)/DH
!
      DCOSUS=COSUSL
      DEL=DCOSUS*(DKSIGM**2+DKMU**2)
      XEL=DEL
!
  490 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XEL
  811 FORMAT('THE EXPECTED LOSS ($) OF THE ',I8,' OBSERVATIONS = ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF EXPLOS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN
 9014 FORMAT('DMEAN = ',D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)DSD
 9015 FORMAT('DSD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)DUSL,DLSL,DTARG,DH
 9016 FORMAT('DUSL,DLSL,DTARG,DH = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)DKMU,DKSIGM,DEL,XEL
 9017 FORMAT('DKMU,DKSIGM,DEL,XEL = ',3D15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE EXPLOS
      SUBROUTINE EXPAFR(X1,X2,SCALE,AFR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE AVERAGE FAILURE
!              RATE (AFR) FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION.
!              THE AFR IS DEFINED AS:
!
!              AFR(X1,X2,LOC,SCALE) = (H(X2,LOC,SCALE) - H(X1,LOC,SCALE))/(X2-X1)
!
!              WHERE
!
!              H(X,LOC,SCALE) = (X-LOC)/SCALE
!
!              SO
!
!              AFR(X1,X2) = ((X2-LOC)/SCALE) - (X1-LOC)/SCALE)/(X2-X1)
!                         = 1/SCALE
!
!              NOTE THAT THE LOCATION PARAMETER CANCELS OUT, SO
!              WE OMIT THE ARGUMENT.
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VALUE AT
!                                WHICH THE AFR FUNCTION IS TO BE
!                                EVALUATED.
!     INPUT  ARGUMENTS--X2     = THE SINGLE PRECISION VALUE AT
!                                WHICH THE AFR FUNCTION IS TO BE
!                                EVALUATED.
!     OUTPUT ARGUMENTS--AFR    = THE SINGLE PRECISION AVERAGE
!                                FAILURE RATE FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION AVERAGE FAILURE RATE
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X2 AND X1  SHOULD BE NON-NEGATIVE AND NOT EQUAL.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--TOBIAS AND TRINDALE, "APPLIED RELIABILITY", SECOND
!                 EDITION, CHAPMAN AND HALL/CRC, 1995.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      X1MN=MIN(X1,X2)
      X1MX=MAX(X1,X2)
      IF(X1MN.EQ.X1MX)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)X1MN
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)X1MX
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ELSEIF(X1MN.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X1MN
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ELSEIF(SCALE.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO EXPAFR IS NEGATIVE.')
    5 FORMAT('***** ERROR--THE FIRST AND SECOND ARGUMENTS ',   &
             'TO EXPAFR ARE EQUAL')
    6 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO EXPAFR ',   &
             '(THE SCALE) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      AFR=1.0/SCALE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EXPAFR
      SUBROUTINE EXPCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 207-232.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
!CCCC   WRITE(ICOUT,4)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
        CDF=0.0
      ELSE
        CDF=1.0-EXP(-X)
      ENDIF
!
!CCC4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO EXPCDF IS NEGATIVE.')
!CC46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      RETURN
      END SUBROUTINE EXPCDF
      SUBROUTINE EXPCHA(X,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X) AND
!              CUMULATIVE HAZARD FUNCTION
!              H(X)=X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION
!                                CUMULATIVE HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, CHAPTER 19.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
      ELSE
        HAZ=X
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO EXPHAZ IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      RETURN
      END SUBROUTINE EXPCHA
      DOUBLE PRECISION FUNCTION EXPFUN (DA)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVAL FOR THE 1-SAMPLE EXPONENTIAL
!              MODEL WITH TIME CENSORING.  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!                 2*IR*LN(SIGMAHAT) - (2/SIGMAHAT)*2*SUM[i=1 to N][X(i)]
!                 + 2*IR*LN(A) + (2/A)*SUM[i=1 to N][X(i)] - K
!
!              WITH
!
!                 IR       = NUMBER OF FAILURE TIMES
!                 SIGMAHAT = POINT ESTIMATE OF SIGMA
!                 A        = PARAMETER OF INTEREST
!                 K        = CHSPPF(ALPHA,1)
!
!              NOTE THAT THE SUM[X(I)], K, IR ARE COMPUTED IN
!              DPMLE2 AND PASSED VIA COMMON BLOCK.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--EXPONENTIAL MAXIMUM LIKELIHOOD Y CENSOR
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 12 (SEE
!                EXAMPLE 12.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER    2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DA
!
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DR
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION XSUM
      COMMON/EXPCOM/DK,DR,SHAT,XSUM,DC
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      EXPFUN=DC - 2.0D0*(-DR*DLOG(DA) - XSUM/DA) - DK
!
      RETURN
      END FUNCTION EXPFUN 
      REAL FUNCTION EXPFU2 (SIGHAT,X,N)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF SIGMA FOR THE 1-PARAMETER EXPONENTIAL
!              MODEL FOR GROUPED DATA (NO CENSORING).  THIS FUNCTION
!              FINDS THE ROOT OF THE EQUATION:
!
!                 SUM[i=1 to k-1][N(i)*(X(i)-X(i-1))/
!                     (EXP(X(i)-X(I-1))/SIGMAHAT) - 1) -
!                 SUM[I=2 to k][N(i)*X(i-1)] = 0
!
!              WITH
!
!                 X(i)     = UPPER BOUNDARY OF iTH BIN
!                 N(i)     = COUNT FOR iTH INTERVAL
!                 SIGMAHAT = POINT ESTIMATE OF SIGMA (THIS IS THE
!                            PARAMETER WE ARE ITERATING OVER)
!                 K        = NUMBER OF INTERVALS
!
!              FORMULAS GO FROM 0 TO K.  FOR CONVENIENCE WITH
!              FORTRAN, WE WILL GO FROM 1 TO K+1.
!
!              CALLED BY FZEROY ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--EXPONENTIAL GROUPED MAXIMUM LIKELIHOOD Y X
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--Volume 1", SECOND EDITION,
!                WILEY, 1994, PP. 509-510.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER    2004.
!
!---------------------------------------------------------------------
!
      REAL SIGHAT
      REAL X(*)
      REAL N(*)
!
      INTEGER IK
      COMMON/EX2COM/IK
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DNI
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
!  COMPUTE SUM FOR FIRST TERM
!
      DO 100 I=2,IK
        DNI=DBLE(N(I))
        DX1=DBLE(X(I))
        DX2=DBLE(X(I-1))
        DTERM1=DNI*(DX1-DX2)/(DEXP((DX1-DX2)/DBLE(SIGHAT))-1.0D0)
        DSUM1=DSUM1 + DTERM1
  100 CONTINUE
!
!  COMPUTE SUM FOR SECOND TERM
!
      DO 200 I=3,IK+1
        DNI=DBLE(N(I))
        DX2=DBLE(X(I-1))
        DSUM2=DSUM2 + DNI*DX2
  200 CONTINUE
!
      EXPFU2=REAL(DSUM1-DSUM2)
!
      RETURN
      END FUNCTION EXPFU2 
      SUBROUTINE EXPHAZ(X,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X) AND
!              HAZARD FUNCTION
!              H(X)=1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, CHAPTER 19.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
      ELSE
        HAZ=1.0
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO EXPHAZ IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      RETURN
      END SUBROUTINE EXPHAZ
      DOUBLE PRECISION FUNCTION EXPM1(DX)
!***BEGIN PROLOGUE  EXPM1
!***PURPOSE  Evaluate EXP(X)- 1
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
!-----COMMON----------------------------------------------------------
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      A=ABS(DX)
      IF(A.LT.D1MACH(4))THEN
        EXPM1=DX
        GO TO 9000
      ELSEIF(A.GT.0.697)THEN
        EXPM1=EXP(DX) - 1.0D0
        GO TO 9000
      ENDIF
!
      IF(A.GT.1.0D-8)THEN
        Y=EXP(DX) - 1.0D0
      ELSE
        Y=((DX/2.0D0) + 1.0D0)*DX
      ENDIF
      DTERM1=DLNREL(Y)
      EXPM1=Y - (1.0D0 + Y)*(DTERM1 - DX)
!
 9000 CONTINUE
      RETURN
      END FUNCTION EXPM1
      SUBROUTINE EXPML1(Y,N,ICASE,IEXPBC,   &
                        ALOWLO,AUPPLO,ALOWSC,AUPPSC,ALPHA,   &
                        NUMALP,NUMOUT,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCML,ALOCSE,SCALML,SCALSE,   &
                        ALOCBC,ALOBSE,SCABML,SCABSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE EXPONENTIAL DISTRIBUTION FOR THE RAW DATA CASE
!              (I.E., NO CENSORING AND NO GROUPING).  IT WILL ALSO
!              RETURN THE CONFIDENCE INTERVALS FOR THE LOCATION
!              AND SCALE PARAMETERS.  THIS ROUTINE WILL ESTIMATE EITHER
!              THE 2-PARAMETER CASE (I.E., BOTH LOCATION AND SCALE ARE
!              ESTIMATED) OR THE 1-PARAMETER CASE (ONLY SCALE IS
!              ESTIMATED) BASED ON VALUE OF ICASE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLE1 WILL GENERATE THE OUTPUT
!              FOR THE EXPONENTIAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/1
!     ORIGINAL VERSION--JANUARY   2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION ALOWLO(*)
      DIMENSION AUPPLO(*)
      DIMENSION ALOWSC(*)
      DIMENSION AUPPSC(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ICASE
      CHARACTER*4 IEXPBC
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPM'
      ISUBN2='L1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,IEXPBC
   52   FORMAT('IBUGA3,ISUBRO,ICASE,IEXPBC = ',3(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR NORMAL MLE ESTIMATE             **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='EXPONENTIAL'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ALOCML=CPUMIN
      ALOCBC=CPUMIN
      ALOCSE=CPUMIN
      ALOBSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
      SCABML=CPUMIN
      SCABSE=CPUMIN
      AN=REAL(N)
!
      IF(ICASE.EQ.'1')THEN
!
!       ONE-PARAMETER CASE
!
        SCALML=XMEAN
        SCALSE=SCALML/SQRT(AN)
!
        NU=2*N
        DO 1110 I=1,NUMALP
          ALP=ALPHA(I)
          P=1.0-(ALP/2.0)
          CALL CHSPPF(P,NU,PPF1)
          P=ALP/2.0
          CALL CHSPPF(P,NU,PPF2)
          ALOWSC(I)=2.0*AN*SCALML/PPF1
          AUPPSC(I)=2.0*AN*SCALML/PPF2
 1110   CONTINUE
!
      ELSEIF(ICASE.EQ.'2')THEN
!
!       TWO-PARAMETER CASE
!
        ALOCML=XMIN
        ALOCBC=(AN*XMIN - XMEAN)/(AN - 1.0)
        SCALML=XMEAN-XMIN
        SCALSE=SCALML/SQRT(AN - 1.0)
        SCABML=AN*(XMEAN - XMIN)/(AN - 1.0)
        SCABSE=SCABML/SQRT(AN - 1.0)
        ALOCSE=SCALML/SQRT(AN*(AN-1.0))
        ALOBSE=SCABML/SQRT(AN*(AN-1.0))
!
        IF(IEXPBC.EQ.'ON')THEN
          UTEMP=ALOCBC
          SCTEMP=SCABML
        ELSE
          UTEMP=ALOCML
          SCTEMP=SCALML
        ENDIF
!
        NU2=2*(N-1)
        DO 2120 I=1,NUMALP
          ALP=ALPHA(I)
          P=1.0-(ALP/2.0)
          CALL CHSPPF(P,NU2,PPF3)
          P=ALP/2.0
          CALL CHSPPF(P,NU2,PPF4)
          ALOWSC(I)=2.0*AN*SCTEMP/PPF3
          AUPPSC(I)=2.0*AN*SCTEMP/PPF4
          P=1.0-ALP
          ACONS1=(ALP/2.0)**(1.0/(1.0-AN)) - 1.0
          ACONS2=(1.0 - ALP/2.0)**(1.0/(1.0-AN)) - 1.0
          ATEMP1=XMIN - SCTEMP*ACONS1
          ATEMP2=XMIN - SCTEMP*ACONS2
          ALOWLO(I)=MIN(ATEMP1,ATEMP2)
          AUPPLO(I)=MAX(ATEMP1,ATEMP2)
 2120   CONTINUE
      ENDIF
!
      NUMOUT=NUMALP
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCML,SCALML,ALOCSE,SCALSE
 9017   FORMAT('ALOCML,SCALML,ALOCSE,SCALSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)ALOCBC,SCALBC,ALOBSE,SCABSE
 9019   FORMAT('ALOCBC,SCALBC,ALOBSE,SCABSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPML1
      SUBROUTINE EXPML2(Y,TAG,N,ICASPL,ICASE,TEND,TEMP1,MAXNXT,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSUM,   &
                        ALOCML,ALOCSE,SCALML,SCALSE,   &
                        IR,IM,AN,AR,AM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE EXPONENTIAL DISTRIBUTION FOR THE RAW DATA CASE
!              WITH TIME CENSORING.  THIS ROUTINE GENERATES ONLY THE
!              POINT ESTIMATES FOR THE LOCATION AND SCALE PARAMETERS.
!              IT WILL ESTIMATE EITHER THE 2-PARAMETER CASE (I.E.,
!              BOTH LOCATION AND SCALE ARE ESTIMATED) OR THE 1-PARAMETER
!              CASE (ONLY SCALE IS ESTIMATED) BASED ON VALUE OF ICASE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLE2 WILL GENERATE THE OUTPUT
!              FOR THE EXPONENTIAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE2)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPM'
      ISUBN2='L2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL,TEND,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,ICASE,TEND,MAXNST = ',   &
               2(A4,2X),A4,G15.7,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR EXPONENTIAL MLE ESTIMATE        **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='EXPONENTIAL'
      CALL CKCENS(TAG,TEMP1,N,IDIST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IWRITE='OFF'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CALL SUMDP(Y,N,IWRITE,XSUM,IBUGA3,IERROR)
!
      ALOCML=CPUMIN
      ALOCSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
!
      CALL SORTC(Y,TAG,N,Y,TAG)
      IR=0
      DO 2120 I=1,N
        IF(TAG(I).EQ.1.0)IR=IR+1
 2120 CONTINUE
      IM=N-IR
!
      DR=DBLE(IR)
!
      IF(IM.EQ.0)THEN
        ICASE='NONE'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('***** WARNING FROM EXPONENTIAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)
 2133   FORMAT('      NO CENSORING TIMES DETECTED.  IT IS RECOMMENDED')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2135)
 2135   FORMAT('      THAT THE FULL SAMPLE SYNTAX BE USED:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2137)
 2137   FORMAT('      EXPONENTIAL MAXIMUM LIKELIHOOD  Y')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSE
        ICASE='SING'
        AHOLD=Y(IR+1)
        DO 2140 I=IR+1,N
          IF(Y(I).NE.AHOLD)THEN
            ICASE='MULT'
            GO TO 2149
          ENDIF
 2140   CONTINUE
 2149   CONTINUE
      ENDIF
!
!               ************************************
!               **  STEP 41--                     **
!               **  CARRY OUT CALCULATIONS        **
!               **  FOR EXPONENTIAL MLE           **
!               **  ESTIMATE (TIME CENSORED CASE) **
!               ************************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      AN=REAL(N)
      AR=REAL(IR)
      AM=REAL(IM)
!
!     ESTIMATES FOR 1-PARAMETER MODEL
!
      IF(ICASPL.EQ.'1EXP')THEN
        ALOCML=0.0
        SCALML=XSUM/AR
        SCALSE=SCALML/SQRT(AR)
      ELSE
!
!     ESTIMATES FOR 2-PARAMETER MODEL
!
!     NOTE THAT THERE IS NO SIMPLE FORMULA FOR THE STANDARD ERROR
!     OF LOCATION PARAMETER.
!
        ALOCML=XMIN
        ALOCSE=CPUMIN
        DSUM1=0.0D0
        DO 4120 I=1,N
          DSUM1=DSUM1 + DBLE(Y(I) - XMIN)
 4120   CONTINUE
        SCALML=REAL(DSUM1/DBLE(IR))
        SCALSE=SCALML/SQRT(AR)
      ENDIF
!
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCML,SCALML,ALOCSE,SCALSE
 9017   FORMAT('ALOCML,SCALML,ALOCSE,SCALSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPML2
      SUBROUTINE EXPML3(Y,TAG,XTEMP,N,ICASPL,ICASE,TEND,MAXNXT,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSUM,   &
                        ALOCML,ALOCSE,SCALML,SCALSE,   &
                        IR,IM,AN,AR,AM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE EXPONENTIAL DISTRIBUTION FOR THE RAW DATA CASE
!              WITH FAILURE CENSORING.  THIS ROUTINE GENERATES ONLY THE
!              POINT ESTIMATES FOR THE LOCATION AND SCALE PARAMETERS.
!              IT WILL ESTIMATE EITHER THE 2-PARAMETER CASE (I.E.,
!              BOTH LOCATION AND SCALE ARE ESTIMATED) OR THE 1-PARAMETER
!              CASE (ONLY SCALE IS ESTIMATED) BASED ON VALUE OF ICASE.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLE3 WILL GENERATE THE OUTPUT
!              FOR THE EXPONENTIAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE3)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION XTEMP(*)
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPM'
      ISUBN2='L3  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL,TEND,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,ICASE,TEND,MAXNXT = ',   &
               2(A4,2X),A4,G15.7,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR EXPONENTIAL MLE ESTIMATE        **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='EXPONENTIAL'
      CALL CKCENS(TAG,XTEMP,N,IDIST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IWRITE='OFF'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CALL SUMDP(Y,N,IWRITE,XSUM,IBUGA3,IERROR)
!
      ALOCML=CPUMIN
      ALOCSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
!
      CALL SORTC(Y,TAG,N,Y,TAG)
      IR=0
      DO 2120 I=1,N
        IF(TAG(I).EQ.1.0)IR=IR+1
 2120 CONTINUE
      IM=N-IR
!
      DR=DBLE(IR)
!
      IF(IM.EQ.0)THEN
        ICASE='NONE'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('***** WARNING FROM EXPONENTIAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)
 2133   FORMAT('      NO CENSORING TIMES DETECTED.  IT IS RECOMMENDED')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2135)
 2135   FORMAT('      THAT THE FULL SAMPLE SYNTAX BE USED:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2137)
 2137   FORMAT('      EXPONENTIAL MAXIMUM LIKELIHOOD  Y')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSE
        ICASE='SING'
        AHOLD=Y(IR+1)
        DO 2140 I=IR+1,N
          IF(Y(I).NE.AHOLD)THEN
            ICASE='MULT'
            GO TO 2149
          ENDIF
 2140   CONTINUE
 2149   CONTINUE
      ENDIF
!
!               ************************************
!               **  STEP 41--                     **
!               **  CARRY OUT CALCULATIONS        **
!               **  FOR EXPONENTIAL MLE           **
!               **  ESTIMATE (TIME CENSORED CASE) **
!               ************************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      AN=REAL(N)
      AR=REAL(IR)
      AM=REAL(IM)
!
!     ESTIMATES FOR 1-PARAMETER MODEL
!
!     SIGMAHAT = (1/R)*SUM[i=1 to r][(1 + b(i)X(i)]
!
!     WHERE b(i) = NUMBER OF ITEMS CENSORED AT TIME i.
!
      IF(ICASPL.EQ.'1EXP')THEN
        ALOCML=0.0
        DO 4103 I=1,N
          IF(TAG(I).EQ.1.0)THEN
            AHOLD=Y(I)
            NCEN=0
            DO 4105 J=1,N
              IF(J.NE.I .AND. TAG(J).EQ.0.0 .AND. Y(J).EQ.AHOLD)THEN
                NCEN=NCEN+1
              ENDIF
 4105       CONTINUE
            XTEMP(I)=REAL(NCEN)
          ELSE
            XTEMP(I)=0.0
          ENDIF
 4103   CONTINUE
!
        DSUM1=0.0D0
        DO 4107 I=1,N
          IF(TAG(I).EQ.1.0)THEN
            DSUM1=DSUM1 + DBLE(1.0 + XTEMP(I))*DBLE(Y(I))
          ENDIF
 4107   CONTINUE
        SCALML=REAL(DSUM1/DR)
        SCALSE=SCALML/SQRT(AR)
!
      ELSE
!
!     ESTIMATES FOR 2-PARAMETER MODEL
!
        IF(ICASE.EQ.'SING')THEN
          DSUM1=0.0D0
          DO 4145 I=1,IR
            DSUM1=DSUM1 + DBLE(Y(I))
 4145     CONTINUE
          YSUMR=REAL(DSUM1)
!
          ALOCML=(1.0/(AN*(AR-1.0)))*(AN*AR*XMIN - YSUMR + AM*Y(IR))
          SCALML=(1.0/(AR-1.0))*(YSUMR - AN*Y(1) + AM*Y(IR))
          ALOCSE=(SCALML/AN)*SQRT(AR/(AR-1.0))
          SCALSE=SCALML/SQRT(AR-1.0)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCML,SCALML,ALOCSE,SCALSE
 9017   FORMAT('ALOCML,SCALML,ALOCSE,SCALSE = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPML3
      SUBROUTINE EXPML4(Y,X1,X2,N,NUMV,MAXNXT,   &
                        XTEMP,TEMP2,TEMP3,   &
                        XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                        SCALML,SCALSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 1-PARAMETER EXPONENTIAL DISTRIBUTION FOR THE
!              UNCENSORED CASE WITH GROUPED DATA.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.  SPECIFICALLY, THE SAMPLE SIZE AND THE
!              PRESENCE OF NON-NEGATIVE VALUES.
!
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--Volume 1", SECOND EDITION,
!                WILEY, 1994, PP. 509-510.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACT FROM DPMLE4
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
      INTEGER IFLAG1
      INTEGER IFLAG2
!
      COMMON/EX2COM/NK
      REAL     EXPFU2
      EXTERNAL EXPFU2
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION XTEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPM'
      ISUBN2='L4  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF EXPML4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,NUMV
   55   FORMAT('N,NUMV = ',2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,X1(I),X2(I),Y(I)
   57     FORMAT('I,X1(I),X2(I),Y(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE SUMMARY STATISTICS          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMV.EQ.2)THEN
        IFLAG1=1
        IFLAG2=0
        CALL SUMGRP(Y,X1,N,IDIST,IFLAG1,IFLAG2,   &
                    XTEMP,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSEIF(NUMV.EQ.3)THEN
        IFLAG1=1
        IFLAG2=0
        CALL SUMGR2(Y,X1,X2,N,IDIST,IFLAG1,IFLAG2,   &
                    XTEMP,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOT,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSE
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR EXPONENTIAL MLE ESTIMATE        **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      IF(NUMV.EQ.2)THEN
!
!       DEFINE INTERVALS
!
        DELTA=(X1(2)-X1(1))/2.0
        ICNT=1
        X2(ICNT)=0.0
        ICNT=2
        X2(ICNT)=X1(1)+DELTA
        DO 2110 I=2,N
          DELTA=(X1(I)-X1(I-1))/2.0
          ICNT=ICNT+1
          X2(ICNT)=X1(I)+DELTA
 2110   CONTINUE
        NK=ICNT
        ICNT=ICNT+1
        X2(ICNT)=CPUMAX
        Y(NK)=0.0
        DO 2120 I=1,NK
          X1(I)=X2(I)
 2120   CONTINUE
!
      ELSE
!
!       DEFINE INTERVALS
!
        ICNT=0
        DO 2130 I=1,N
          ICNT=ICNT+1
          X1(ICNT)=X2(ICNT)
 2130   CONTINUE
        ICNT=ICNT+1
        X1(ICNT)=CPUMAX
        X2(ICNT)=CPUMAX
        NK=ICNT
        Y(N+1)=0.0
!
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLE4')THEN
        WRITE(ICOUT,2155)NUMV,NK
 2155   FORMAT('NUMV,NK = ',2I8)
        CALL DPWRST('XXX','WRIT')
        DO 2157 I=1,NK+1
          WRITE(ICOUT,2156)I,X1(I),Y(I)
 2156     FORMAT('I,X1(I),Y(I) =',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
 2157   CONTINUE
      ENDIF
!
!     ESTIMATES FOR 1-PARAMETER MODEL.  USE FZEROY TO FIND ROOT OF
!     EQUATION GIVEN IN EXPFU2 (COMMENTS IN THAT ROUTINE GIVE
!     ACTUAL EQUATION).  USE OVERALL MEAN AS STARTING VALUE.
!
      AE=1.E-6
      RE=1.E-6
      IFLAG=0
      XLOW=X1(1)
      XUP=X1(NK-1)
      CALL FZEROY(EXPFU2,XLOW,XUP,XMEAN,RE,AE,IFLAG,X1,Y)
      SCALML=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GROUPED EXPONENTIAL MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF SIGMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GROUPED EXPONENTIAL MAXIMUM ',   &
               'LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF SIGMA MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GROUPED EXPONENTIAL MAXIMUM ',   &
               'LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GROUPED EXPONENTIAL MAXIMUM ',   &
               'LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      AN=REAL(NTOT)
      DSIGMA=DBLE(SCALML)
      DSUM1=0.0D0
      DO 150 I=2,NK
        DX1=DBLE(X1(I))
        DX2=DBLE(X1(I-1))
        DTERM1=(DX1-DX2)**2/(DEXP(DX1/DSIGMA) - DEXP(DX2/DSIGMA))
        DSUM1=DSUM1 + DTERM1
  150 CONTINUE
      SCALSE=SQRT(AN*REAL(DSUM1))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF EXPML4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)XMEAN,XSD,XMIN,XMAX
 9012   FORMAT('XMEAN,XSD,XMIN,XMAX = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)SCALML,SCALSE
 9013   FORMAT('SCALML,SCALSE = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE EXPML4
      SUBROUTINE EXPPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 207-232.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
      ELSE
        PDF=EXP(-X)
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO EXPPDF IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      RETURN
      END SUBROUTINE EXPPDF
      SUBROUTINE EXPPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 207-232.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
      ELSE
        PPF=-LOG(1.0-P)
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO EXPPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      RETURN
      END SUBROUTINE EXPPPF
      SUBROUTINE EXPRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE EXPONENTIAL DISTRIBUTION
!             WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14, 35-36.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 207-232.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 58.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JULY      1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO THE ',   &
             'EXPRAN SUBROUTINE IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N EXPONENTIAL RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        X(I)=-LOG(X(I))
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EXPRAN
      SUBROUTINE EXPSF(P,SF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SPARSITY
!              FUNCTION VALUE FOR THE EXPONENTIAL DISTRIBUTION
!              WITH MEAN = 1 AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(-X).
!              NOTE THAT THE SPARSITY FUNCTION OF A DISTRIBUTION
!              IS THE DERIVATIVE OF THE PERCENT POINT FUNCTION,
!              AND ALSO IS THE RECICOUTOCAL OF THE PROBABILITY
!              DENSITY FUNCTION (BUT IN UNITS OF P RATHER THAN X).
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE SPARSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--SF     = THE SINGLE PRECISION
!                                SPARSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION SPARSITY
!             FUNCTION VALUE SF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 207-232.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
      ELSE
        SF=1.0/(1.0-P)
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO EXPSF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      RETURN
      END SUBROUTINE EXPSF
      SUBROUTINE EXPSMO(X,TEMP,ALPHA,AMSE,NX,IWRITE,Y,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE EXPONETIAL SMOOTH OF AN ARRAY
!              THE ALPHA PARANETER IDENTIFIES THE SMOOTHING PARAMETER
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION DSUM
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION TEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPS'
      ISUBN2='MO  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXPSMO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE,N,ALPHA
   52   FORMAT('IBUGA3,IWRITE,N,ALPHA = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE EXPONENTIAL SMOOTH      **
!               **************************************
!
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR FROM EXPSMO.  SMOOTHING PARAMETER MUST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      BE > 0 AND < 1.  THE ENTERED VALUE WAS ',E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DSUM=0.0D0
      TEMP(1)=X(1)
      DO 200 I=2,NX
        ATEMP=X(I)-TEMP(I-1)
        TEMP(I)=ALPHA*ATEMP + TEMP(I-1)
        DSUM=DSUM + DBLE(ATEMP)**2
  200 CONTINUE
      AMSE=REAL(DSUM)/REAL(NX-1)
!
      DO 300 I=1,NX
        Y(I)=TEMP(I)
  300 CONTINUE
!
      NY=NX
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF EXPSMO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NX,NY
 9013 FORMAT('NX,NY = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NX
      WRITE(ICOUT,9016)I,X(I),Y(I)
 9016 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE EXPSMO
      SUBROUTINE EXPSM2(X,TEMP,ALPHA,AMSE,NX,IWRITE,Y,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE EXPONETIAL SMOOTH OF AN ARRAY
!              THE ALPHA PARANETER IDENTIFIES THE SMOOTHING PARAMETER
!              NOTE: USE THIS VERSION IF ALPHA NOT SPECIFIED.
!                    USE AN ITERATIVE SEARCH TO FIND THE OPTIMAL
!                    VALUE FOR ALPHA.
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/2
!     ORIGINAL VERSION--FEBRUARY  1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION TEMP(*)
!
      REAL AMSEV(20)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXPS'
      ISUBN2='MO  '
      IERROR='NO'
!
      AX=CPUMIN
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF EXPSM2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NX,ALPHA
   53 FORMAT('NX,ALPHA = ',I8,1X,F10.5)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NX
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  COMPUTE EXPONENTIAL SMOOTH      **
!               **************************************
!
!CCCC FIND BEST ALPHA TO FIRST DECIMAL PLACE.
!
      AMNVAL=CPUMAX
      DO 100 I=1,9
        ALPHA=REAL(I)/10.
        CALL EXPSMO(X,TEMP,ALPHA,AMSE,NX,IWRITE,Y,IBUGA3,IERROR)
        AMSEV(I)=AMSE
        IF(AMSEV(I).LT.AMNVAL)THEN
          AX=ALPHA
          AMNVAL=AMSEV(I)
        ENDIF
  100 CONTINUE
      ALPHA=AX
!
!CCCC FIND BEST ALPHA TO FIRST DECIMAL PLACE.
!
      AMNVAL=CPUMAX
      D=0.09
      DINC=0.01
      ASTRT=ALPHA-D
      DO 200 I=1,19
        ALPHA=ASTRT+REAL(I-1)*DINC
        CALL EXPSMO(X,TEMP,ALPHA,AMSE,NX,IWRITE,Y,IBUGA3,IERROR)
        AMSEV(I)=AMSE
        IF(AMSEV(I).LT.AMNVAL)THEN
          AX=ALPHA
          AMNVAL=AMSEV(I)
        ENDIF
  200 CONTINUE
      ALPHA=AX
!
!CCCC FIND BEST ALPHA TO THIRD DECIMAL PLACE.
!
      AMNVAL=CPUMAX
      D=0.009
      DINC=0.001
      ASTRT=ALPHA-D
      DO 300 I=1,19
        ALPHA=ASTRT+REAL(I-1)*DINC
        CALL EXPSMO(X,TEMP,ALPHA,AMSE,NX,IWRITE,Y,IBUGA3,IERROR)
        AMSEV(I)=AMSE
        IF(AMSEV(I).LT.AMNVAL)THEN
          AX=ALPHA
          AMNVAL=AMSEV(I)
        ENDIF
  300 CONTINUE
      ALPHA=AX
!
      IF(IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,510)ALPHA
  510   FORMAT('FOR EXPONENTIAL SMOOTHING, OPTIMAL VALUE OF ALPHA',   &
               '(TO 3 DECIMAL PLACES) = ',F6.3)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF EXPSM2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NX
 9013 FORMAT('NX = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NX
      WRITE(ICOUT,9016)I,X(I),Y(I)
 9016 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE EXPSM2
      SUBROUTINE EXTBOU(ICASPL,IBOUND)
!
!     PURPOSE--CERTAIN OF THE PROBABILITY ROUTINES USE LOWER AND
!              UPPER LIMIT PARAMETERS RATHER THAN LOCATION AND
!              SCALE PARAMETERS.  SET THE VALUE OF IBOUND TO 0
!              IF LOCATION AND SCALE PARAMETERS WILL BE USED AND
!              TO 1 IF LOWER AND UPPER LIMIT PARAMETERS WILL BE USED.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
!
!---------------------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      IBOUND=0
      IF(ICASPL.EQ.'UNIF')IBOUND=1
      IF(ICASPL.EQ.'BETA')IBOUND=1
      IF(ICASPL.EQ.'NCBE')IBOUND=1
      IF(ICASPL.EQ.'TRIA')IBOUND=1
      IF(ICASPL.EQ.'POWF')IBOUND=1
      IF(ICASPL.EQ.'RPOW')IBOUND=1
      IF(ICASPL.EQ.'JOSB')IBOUND=1
      IF(ICASPL.EQ.'TSPO')IBOUND=1
      IF(ICASPL.EQ.'GTOL')IBOUND=1
      IF(ICASPL.EQ.'RGTL')IBOUND=1
      IF(ICASPL.EQ.'SLOP')IBOUND=1
      IF(ICASPL.EQ.'OGIV')IBOUND=1
      IF(ICASPL.EQ.'TSSL')IBOUND=1
      IF(ICASPL.EQ.'TSOG')IBOUND=1
      IF(ICASPL.EQ.'KUMA')IBOUND=1
!
      RETURN
      END SUBROUTINE EXTBOU
      SUBROUTINE EXTDIG(IINPUT,IDIGIT,NDIGIT,IBUGA3,IERROR)
!
!     PURPOSE--EXTRACT THE DIGITS FROM AN INTEGER.
!              PROCEED LEFT TO RIGHT.
!     INPUT  ARGUMENTS--  IINPUT = AN INTEGER
!     OUTPUT ARGUMENTS--  IDIGIT   = VECTOR OF DIGITS
!                         NDIGIT   = NUMBER OF ELEMENTS IN IDIGIT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--89.1
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IDIGIT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      NDIGIT=0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF EXTDIG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IINPUT
   52 FORMAT('IINPUT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IBUGA3
   53 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************************************
!               **  STEP 11--                                   **
!               **  CHECK THE INPUT NUMBER FOR ERRORS           **
!               **************************************************
!
      IF(IINPUT.GE.0)GO TO 1190
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN EXTDIG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      THE INPUT NUMBER WAS NEGATIVE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)IINPUT
 1113 FORMAT('      THE INPUT NUMBER = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1190 CONTINUE
!
!               **************************************************
!               **  STEP 12--                                   **
!               **  DETERMINE THE NUMBER OF DIGITS              **
!               **  IN THE NUMBER                               **
!               **************************************************
!
      MAXDIG=9
      IREM=IINPUT
      DO 1200 I=1,MAXDIG
        IREV=MAXDIG-I+1
        IPOWER=INT(10.0**IREV + 0.0001)
        IRATIO=IREM/IPOWER
        IF(IRATIO.EQ.0)GO TO 1200
        GO TO 1290
 1200 CONTINUE
      IREV=0
 1290 CONTINUE
      NDIGIT=IREV+1
!
!               **************************************************
!               **  STEP 13--                                   **
!               **  EXTRACT THE INDIVIDUAL DIGITS               **
!               **************************************************
!
      IREM=IINPUT
      J=0
      DO 1300 I=1,NDIGIT
      J=J+1
      IREV=NDIGIT-I+1
      IPOWER=INT(10**(IREV-1) + 0.01)
      IDIGIT(I)=IREM/IPOWER
      IREM=IREM-IDIGIT(I)*IPOWER
 1300 CONTINUE
!
!               *******************
!               **   STEP 90--   **
!               **   EXIT        **
!               *******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF EXTDIG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IINPUT
 9012 FORMAT('IINPUT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IBUGA3,IERROR
 9013 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)NDIGIT
 9021 FORMAT('NDIGIT = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(NDIGIT.LE.0)GO TO 9024
      DO 9022 I=1,NDIGIT
      WRITE(ICOUT,9023)I,IDIGIT(I)
 9023 FORMAT('I,IDIGIT(I) = ',2I8)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
 9024 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE EXTDIG
      SUBROUTINE EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                        IDISCS,IDISNM,IDISPR,IFOUND,ILOCV,   &
                        ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--EXTRACT THE NAME OF ONE OF 150+ DISTRIBUTIONS.  THIS
!              IS A COMMON ROUTINE CALLED BY:
!                1) DPPP    = <DIST> PROBABILITY PLOT
!                2) DP1KST  = <DIST> KOLMOGOROV SMIRNOV GOODNESS OF FIT
!                3) DPCHSQ  = <DIST> CHI-SQUARE SMIRNOV GOODNESS OF FIT
!                4) DPPPCC  = <DIST> PPCC PLOT
!                5) DPMLWE  = <DIST> MAXIMUM LIKELIHOOD
!                6) DPLRDI  = <DIST1> <DIST2> DISTRIBUTIONAL LIKELIHOOD
!                                             RATIO
!
!              NOTE THAT NOT ALL COMMANDS MAY SUPPORT ALL DISTRIBUTIONS.
!
!              THE FOLLOWING DISTRIBUTIONS ARE SUPPORTED:
!
!              1 ) UNIFORM
!              2 ) NORMAL
!              3 ) LOGISTIC
!              4 ) DOUBLE EXPONENTIAL
!              5 ) CAUCHY
!              6 ) TUKEY LAMBDA
!              7 ) LOGNORMAL
!              8 ) HALFNORMAL
!              9 ) T
!              10) CHI-SQUARED
!              11) F
!              12) EXPONENTIAL
!              13) GAMMA
!              14) BETA
!              15) WEIBULL---MIN & MAX
!              16) EXTREME VALUE TYPE 1 (GUMBEL)--MIN & MAX
!              17) EXTREME VALUE TYPE 2 (FRECHET)--MIN & MAX
!              18) PARETO
!              19) BINOMIAL
!              20) GEOMETRIC
!              21) POISSON
!              22) NEGATIVE BINOMIAL
!              23) SEMI-CIRCULAR
!              24) TRIANGULAR
!              25) INVERSE GAUUSIAN
!              26) WALD
!              27) RECIPROCAL INVERSE GAUUSIAN
!              28) FAILURE TIME
!              29) GENERALIZED PARETO
!              30) DISCRETE UNIFORM
!              31) NON-CENTRAL T
!              32) NON-CENTRAL F
!              33) NON-CENTRAL CHI-SQUARE
!              34) NON-CENTRAL BETA
!              35) DOUBLY NON-CENTRAL T
!              36) DOUBLY NON-CENTRAL F
!              36) HYPER-GEOMETRIC
!              37) VON-MISES
!              38) POWER NORMAL
!              39) POWER LOGNORMAL
!              40) COSINE
!              41) ALPHA
!              42) POWER FUNCTION
!              43) CHI
!              44) LOGARITMIC SERIES
!              45) LOG LOGISTIC
!              46) GENERALIZED GAMMA
!              47) WARING
!              48) ANGLIT
!              49) ARCSIN
!              50) FOLDED NORMAL
!              51) TRUNCATED NORMAL
!              52) LOG GAMMA
!              53) HYPERBOLIC SECANT
!              54) GOMPERTZ
!              55) PARETO SECOND KIND
!              56) DOUBLE WEIBULL
!              57) WRAPPED-UP CAUCHY
!              58) EXPONENTIAL WEIBULL
!              59) TRUNCATED EXPONENTIAL
!              60) GENERALIZED LOGISTIC
!              61) EXPONENTIAL POWER
