        IH2='    '
        ALOWLM=1.0
        AUPPLM=CPUMAX
        LOWLTY='>=  '
        UPPLTY='<=  '
        GO TO 4100
      ELSEIF(   &
             ICASPL.EQ.'CHIS' .OR. ICASPL.EQ.'CHI' .OR.   &
             ICASPL.EQ.'FT  '   &
            )THEN
        IH='NU  '
        IH2='    '
        ILOWLM=1
        IUPPLM=I1MACH(9)
        LOWLTY='>=  '
        UPPLTY='<=  '
        GO TO 5100
      ELSEIF(ICASPL.EQ.'FPP')THEN
        IH='NU1 '
        IH2='    '
        IDIST='F     '
        ILOWLM=1
        IUPPLM=I1MACH(9)
        LOWLTY='>=  '
        UPPLTY='<=  '
        IH21='NU2 '
        IH22='    '
        ILOWL2=1
        IUPPL2=I1MACH(9)
        LOWLT2='>=  '
