      ELSEIF(   &
         ICASPL.EQ.'GAMM' .OR. ICASPL.EQ.'WEIB' .OR.   &
         ICASPL.EQ.'EV2 ' .OR. ICASPL.EQ.'WALD' .OR.   &
         ICASPL.EQ.'FATL' .OR. ICASPL.EQ.'DWEI' .OR.   &
