        UPPLTY='<   '
        GO TO 4100
      ELSEIF(ICASPL.EQ.'NEBI')THEN
        IH='P   '
        IH2='    '
        ALOWLM=0.0
        AUPPLM=1.0
        LOWLTY='>   '
        UPPLTY='<   '
        IH21='K   '
        IH22='    '
        ALOWL2=0.0
        AUPPL2=CPUMAX
        LOWLT2='>   '
        UPPLT2='<=  '
        GO TO 4200
      ELSEIF(ICASPL.EQ.'INGA' .OR. ICASPL.EQ.'RIGA')THEN
        IH='GAMM'
        IH2='A   '
        ALOWLM=0.
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        IH21='MU  '
        IH22='    '
        ALOWL2=0.
        AUPPL2=CPUMAX
        LOWLT2='>   '
        UPPLT2='<=  '
        GO TO 4200
      ELSEIF(ICASPL.EQ.'TRIA')THEN
!
!       NOTE: FOR TRIANGULAR DISTRIBUTION, THE SHAPE PARAMETER
!             IS BOUNDED BY THE MIN AND MAX OF THE DATA.
!
!             THERE ARE TWO WAYS TO DEAL WITH THIS:
!
!             1) ALLOW THE USER TO SPECIFY LOWER AND UPPER LIMITS
!                (AND SET C BASED ON THESE).
!
!                THE ADVANTAGE OF THIS APPROACH IS THAT C IS
!                GIVEN IN UNITS OF THE DATA.  THE DISADVANTAGE
!                IS THAT WE LOSE THE INVARIANCE OF LOCATION/SCALE
!                OF THE PPCC PLOT.
!
!             2) USE DEFAULT OF A = -1, B = 1 AND THEN RESTRICT
!                VALUE OF C TO (0,1) INTERVAL.  THE ADVANTAGE
!                OF THIS APPROACH IS THAT WE MAINTAIN THE
!                INVARIANCE OF LOCATION/SCALE (I.E., INDEPENDENT
!                ESTIMATES OF A AND B).  THE DISADVANTAGE IS THAT
!                THE OPTIMAL ESTIMATE OF C HAS TO BE SCALED IF THE
!                DATA IS OUTSIDE THE (0,1) INTERVAL.
!
!                USER CAN SPECIFY LOWER/UPPER LIMITS BY ENTERING
!                LET A = <LOWLIM>  AND  LET B = <UPPLIM>.  THESE
!                PARAMETERS WILL BE CHECKED BEFORE THIS ROUTINE
!                IS CALLED.
!
