                  SHAPE1,ALOWLM,AUPPLM,LOWLTY,UPPLTY,   &
                  ISUBN1,ISUBN2,IERROR)
      CALL PARCHR(IH21,IH22,IDIST,   &
                  SHAPE2,ALOWL2,AUPPL2,LOWLT2,UPPLT2,   &
                  ISUBN1,ISUBN2,IERROR)
      CALL PARCHR(IH31,IH32,IDIST,   &
                  SHAPE3,ALOWL3,AUPPL3,LOWLT3,UPPLT3,   &
                  ISUBN1,ISUBN2,IERROR)
      CALL PARCHR(IH41,IH42,IDIST,   &
                  SHAPE4,ALOWL4,AUPPL4,LOWLT4,UPPLT4,   &
                  ISUBN1,ISUBN2,IERROR)
      CALL PARCHR(IH51,IH52,IDIST,   &
                  SHAPE5,ALOWL5,AUPPL5,LOWLT5,UPPLT5,   &
                  ISUBN1,ISUBN2,IERROR)
!
      GO TO 9000
!
 4900 CONTINUE
      CALL PARCHR(IH,IH2,IDIST,   &
                  SHAPE1,ALOWLM,AUPPLM,LOWLTY,UPPLTY,   &
                  ISUBN1,ISUBN2,IERROR)
      CALL PARCHI(IH21,IH22,IDIST,ISHAPE,ILOWL2,IUPPL2,LOWLT2,UPPLT2,   &
                  ISUBN1,ISUBN2,IERROR)
      SHAPE2=REAL(ISHAPE)
      GO TO 9000
!
 5100 CONTINUE
      CALL PARCHI(IH,IH2,IDIST,ISHAPE,ILOWLM,IUPPLM,LOWLTY,UPPLTY,   &
                  ISUBN1,ISUBN2,IERROR)
      SHAPE1=REAL(ISHAPE)
      GO TO 9000
!
 5200 CONTINUE
      CALL PARCHI(IH,IH2,IDIST,ISHAPE,ILOWLM,IUPPLM,LOWLTY,UPPLTY,   &
                  ISUBN1,ISUBN2,IERROR)
      SHAPE1=REAL(ISHAPE)
      CALL PARCHI(IH21,IH22,IDIST,ISHAPE,ILOWL2,IUPPL2,LOWLT2,UPPLT2,   &
                  ISUBN1,ISUBN2,IERROR)
      SHAPE2=REAL(ISHAPE)
      GO TO 9000
!
!6999 CONTINUE
!CCCC CALL PARCHR(IH,IH2,IDIST,
!CCCC1            SHAPE1,ALOWLM,AUPPLM,LOWLTY,UPPLTY,
!CCCC1            ISUBN1,ISUBN2,IERROR)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE EXTPA1
      SUBROUTINE EXTPA2(ICASPL,IDIST,A,B,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        ISUBRO,IBUGG2,IERROR)
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!     UPDATED         --AUGUST    2010. BRITTLE FIBER WEIBULL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*30 IDIST
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IHP11
      CHARACTER*4 IHP12
      CHARACTER*4 IHP21
      CHARACTER*4 IHP22
      CHARACTER*4 IHP31
      CHARACTER*4 IHP32
      CHARACTER*4 IHP41
      CHARACTER*4 IHP42
      CHARACTER*4 LOWLTY
      CHARACTER*4 UPPLTY
      CHARACTER*4 LOWLT2
      CHARACTER*4 UPPLT2
      CHARACTER*4 LOWLT4
      CHARACTER*4 UPPLT4
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
!
!---------------------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!               ***********************************************
!               **  STEP 1--                                 **
!               **  FOR THOSE DISTRIBUTIONS REQUIRING THEM,  **
!               **  DETERMINE IF THE ANALYST                 **
!               **  HAS SPECIFIED PARAMETER VALUES           **
!               ***********************************************
!
      ISUBN1='EXTP'
      ISUBN2='A2  '
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'TPA2')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,55)IDIST
   55   FORMAT('AT BEGINNING OF EXTPA2: IDIST = ',A30)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5
   56   FORMAT('SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)ISKNDF,IBEIDF,IBGEDF,IGEODF,IGEPDF
   57   FORMAT('ISKNDF,IBEIDF,IBGEDF,IGEODF,IGEPDF = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,58)IGIGDF,IGLDDF,IKATDF,ILGADF
   58   FORMAT('IGIGDF,IGLDDF,IKATDF,ILGADF = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER GAMMA
!
      IF(ICASPL.EQ.'WEIB' .OR. ICASPL.EQ.'IWEI' .OR.   &
         ICASPL.EQ.'3WEI' .OR. ICASPL.EQ.'3IWE' .OR.   &
         ICASPL.EQ.'GAMM' .OR. ICASPL.EQ.'IGAM' .OR.   &
         ICASPL.EQ.'3GAM' .OR. ICASPL.EQ.'3IGA' .OR.   &
         ICASPL.EQ.'LGAM' .OR. ICASPL.EQ.'GPAR' .OR.   &
         ICASPL.EQ.'GEEX' .OR. ICASPL.EQ.'FATL' .OR.   &
         ICASPL.EQ.'WALD' .OR. ICASPL.EQ.'EV2 ' .OR.   &
         ICASPL.EQ.'3EV2' .OR.   &
         ICASPL.EQ.'DWEI' .OR. ICASPL.EQ.'GEV ' .OR.   &
         ICASPL.EQ.'GHLO' .OR. ICASPL.EQ.'DGAM' .OR.   &
         ICASPL.EQ.'PEA3' .OR. ICASPL.EQ.'BFWE' .OR.   &
         ICASPL.EQ.'PARE' .OR. ICASPL.EQ.'PAR2'   &
       )THEN
!
        IHP11='GAMM'
        IHP12='A1  '
        IHP21='GAMM'
        IHP22='A2  '
        LOWLTY='>   '
        UPPLTY='<=  '
        ALOWLM=0.
        AUPPLM=CPUMAX
        ADEF1=1.0
        ADEF2=50.0
!
        IF(ICASPL.EQ.'WEIB')THEN
          IDIST='WEIBULL'
        ELSEIF(ICASPL.EQ.'3WEI')THEN
          IDIST='3-PARAMETER WEIBULL'
        ELSEIF(ICASPL.EQ.'GAMM')THEN
          IDIST='GAMMA'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'3GAM')THEN
          IDIST='3-PARAMETER GAMMA'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'IGAM')THEN
          IDIST='INVERTED GAMMA'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'3IGA')THEN
          IDIST='3-PARAMETER INVERTED GAMMA'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'LGAM')THEN
          IDIST='LOG GAMMA'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'IWEI')THEN
          IDIST='INVERTED WEIBULL'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'3IWE')THEN
          IDIST='3-PARAMETER INVERTED WEIBULL'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'GPAR')THEN
          IDIST='GENERALIZED PARETO'
          ALOWLM=CPUMIN
          ADEF1=-3.0
          ADEF2=3.0
        ELSEIF(ICASPL.EQ.'GEEX')THEN
          IDIST='GEOMETRIC EXTREME EXPONENTIAL'
          ADEF1=0.1
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'FATL')THEN
          IDIST='FATIGUE LIFE'
        ELSEIF(ICASPL.EQ.'WALD')THEN
          IDIST='WALD'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'EV2 ')THEN
          IDIST='FRECHET'
          ADEF1=-25.0
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'3EV2')THEN
          IDIST='3-PARAMETER FRECHET'
          ADEF1=0.1
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'PARE' .OR. ICASPL.EQ.'PAR2')THEN
          ADEF1=0.2
          ADEF2=5.0
          IDIST='PARETO'
          IF(ICASPL.EQ.'PAR2')IDIST='PARETO SECOND KIND'
!
!         FOR PARETO, SET VALUE FOR A
!
          IHP31='A   '
          IHP32='    '
          ALOWLM=0.0
          AUPPLM=CPUMAX
          LOWLTY='>   '
          UPPLTY='<=  '
          ADEF3=1.0
          CALL PARCH2(IHP31,IHP32,IDIST,SHAPE2,ADEF3,ALOWLM,AUPPLM,   &
                    LOWLTY,UPPLTY,   &
                    ISUBN1,ISUBN2,IERROR)
          IF(SHAPE2.LE.0.0)SHAPE2=1.0
!
        ELSEIF(ICASPL.EQ.'BFWE')THEN
          IDIST='BRITTLE FIBER WEIBULL'
!
!         FOR BRITTLE FIBER WEIBULL, SET VALUE FOR L
!
          IHP31='L   '
          IHP32='    '
          ALOWLM=0.0
          AUPPLM=CPUMAX
          LOWLTY='>   '
          UPPLTY='<=  '
          ADEF3=1.0
          CALL PARCH2(IHP31,IHP32,IDIST,SHAPE2,ADEF3,ALOWLM,AUPPLM,   &
                    LOWLTY,UPPLTY,   &
                    ISUBN1,ISUBN2,IERROR)
          IF(SHAPE2.LE.0.0)SHAPE2=ADEF3
        ELSEIF(ICASPL.EQ.'DWEI')THEN
          IDIST='DOUBLE WEIBULL'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'DGAM')THEN
          IDIST='DOUBLE GAMMA'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'GEV ')THEN
          IDIST='GENERALIZED EXTREME VALUE'
          ALOWLM=CPUMIN
          ADEF1=-5.0
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'GHLO')THEN
          IDIST='GENERALIZED HALF LOGISTIC'
          AUPPLM=5.0
          ADEF1=0.1
          ADEF2=2.5
        ELSEIF(ICASPL.EQ.'PEA3')THEN
          IDIST='PEARSON TYPE 3'
          ALOWLM=CPUMIN
          AUPPLM=CPUMAX
          ADEF1=-10.0
          ADEF2=10.0
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER SIGMA
!
      ELSEIF(ICASPL.EQ.'LOGN' .OR. ICASPL.EQ.'3LGN')THEN
        IDIST='LOGNORMAL'
        IHP11='SIGM'
        IHP12='A1  '
        IHP21='SIGM'
        IHP22='A2  '
        ALOWLM=0.
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        ADEF1=0.5
        ADEF2=25.0
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER LAMBDA
!
      ELSEIF(ICASPL.EQ.'TULA' .OR. ICASPL.EQ.'SDEX' .OR.   &
             ICASPL.EQ.'SNOR' .OR. ICASPL.EQ.'POIS' .OR.   &
             ICASPL.EQ.'BTAN')THEN
!
        IHP11='LAMB'
        IHP12='DA1 '
        IHP21='LAMB'
        IHP22='DA2 '
        ALOWLM=CPUMIN
        AUPPLM=CPUMAX
        LOWLTY='>=  '
        UPPLTY='<=  '
        IF(ICASPL.EQ.'TULA')THEN
          IDIST='TUKEY-LAMBDA'
          ADEF1=-2.0
          ADEF2=2.0
        ELSEIF(ICASPL.EQ.'SDEX')THEN
          IDIST='SKEW DOUBLE EXPONENTIAL'
          ADEF1=0.0
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'SNOR')THEN
          IDIST='SKEW NORMAL'
          ADEF1=-5.0
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'POIS')THEN
          IDIST='POISSON'
          ADEF1=1.0
          ADEF2=50.0
        ELSEIF(ICASPL.EQ.'BTAN')THEN
          IDIST='BOREL-TANNER'
          IHP21='K   '
          IHP22='    '
          ILOWL2=1
          IUPPL2=I1MACH(9)
          LOWLT2='>=  '
          UPPLT2='<=  '
          CALL PARCHI(IHP21,IHP22,IDIST,K,ILOWL2,IUPPL2,   &
                      LOWLT2,UPPLT2,   &
                      ISUBN1,ISUBN2,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          SHAPE2=REAL(K)
          ALOWLM=0.0
          AUPPLM=1.0
          LOWLTY='>   '
          UPPLTY='<   '
          ADEF1=0.2
          ADEF2=0.95
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER NU
!
      ELSEIF(ICASPL.EQ.'TPP' .OR. ICASPL.EQ.'CHIS' .OR.   &
             ICASPL.EQ.'CHI ' .OR. ICASPL.EQ.'FT  ')THEN
!
        IHP11='NU1 '
        IHP12='    '
        IHP21='NU2 '
        IHP22='    '
        ALOWLM=1.
        AUPPLM=CPUMAX
        LOWLTY='>=  '
        UPPLTY='<=  '
        ADEF1=1.0
        ADEF2=50.0
        IF(ICASPL.EQ.'TPP')IDIST='T'
        IF(ICASPL.EQ.'CHIS')IDIST='CHI-SQUARE'
        IF(ICASPL.EQ.'CHI ')IDIST='CHI'
        IF(ICASPL.EQ.'FT  ')IDIST='FOLDED T'
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER BETA
!
      ELSEIF(ICASPL.EQ.'BRAD' .OR. ICASPL.EQ.'TOPL' .OR.   &
             ICASPL.EQ.'PEXP' .OR. ICASPL.EQ.'MUTH' .OR.   &
             ICASPL.EQ.'LEXP')THEN
        IHP11='BETA'
        IHP12='1   '
        IHP21='BETA'
        IHP22='2   '
        ALOWLM=0.
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        ADEF1=0.1
        ADEF2=10.0
        IF(ICASPL.EQ.'BRAD')THEN
          IDIST='BRADFORD'
          ADEF1=0.5
          ADEF2=25.0
        ELSEIF(ICASPL.EQ.'TOPL')THEN
          IDIST='TOPP AND LEONE'
        ELSEIF(ICASPL.EQ.'PEXP')THEN
          IDIST='EXPONENTIAL POWER'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'MUTH')THEN
          IDIST='MUTH'
          ADEF1=0.0
          ADEF2=1.0
          AUPPLM=1.0
          LOWLTY='>=  '
        ELSEIF(ICASPL.EQ.'LEXP')THEN
          IDIST='LOGISTIC-EXPONENTIAL'
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER B
!
      ELSEIF(ICASPL.EQ.'RECI' .OR. ICASPL.EQ.'VONM')THEN
        IHP11='B1  '
        IHP12='    '
        IHP21='B2  '
        IHP22='    '
        ALOWLM=1.0
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        ADEF1=1.5
        ADEF2=20.0
        IF(ICASPL.EQ.'RECI')THEN
          IDIST='RECIPROCAL'
        ELSEIF(ICASPL.EQ.'VONM')THEN
          IDIST='VON MISES'
          ALOWLM=0.0
          LOWLTY='>=  '
          ADEF1=0.5
          ADEF2=25.0
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER ALPHA
!
      ELSEIF(ICASPL.EQ.'ERRO' .OR. ICASPL.EQ.'LLAP' .OR.   &
             ICASPL.EQ.'GLOG' .OR. ICASPL.EQ.'G2LO' .OR.   &
             ICASPL.EQ.'G3LO' .OR. ICASPL.EQ.'G5LO' .OR.   &
             ICASPL.EQ.'SLOP' .OR. ICASPL.EQ.'ALPH' .OR.   &
             ICASPL.EQ.'MCLE' .OR. ICASPL.EQ.'LDEX' .OR.   &
             ICASPL.EQ.'ZETA' .OR. ICASPL.EQ.'ZIPF')THEN
        IHP11='ALPH'
        IHP12='A1  '
        IHP21='ALPH'
        IHP22='A2  '
        ALOWLM=0.0
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        ADEF1=0.1
        ADEF2=10.0
        IF(ICASPL.EQ.'ERRO')THEN
          IDIST='ERROR'
          ALOWLM=1.
          ADEF1=1.1
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'LLAP' .OR. ICASPL.EQ.'LDEX')THEN
          IDIST='LOG LAPLACE'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'GLOG')THEN
          IDIST='GENERALIZED LOGISTIC'
          ALOWLM=0.1
          ADEF1=0.2
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'G2LO')THEN
          IDIST='GENERALIZED LOGISTIC TYPE 2'
        ELSEIF(ICASPL.EQ.'G3LO')THEN
          IDIST='GENERALIZED LOGISTIC TYPE 3'
        ELSEIF(ICASPL.EQ.'G5LO')THEN
          IDIST='GENERALIZED LOGISTIC TYPE 5'
          ALOWLM=CPUMIN
          ADEF1=-2.0
          ADEF2=2.0
        ELSEIF(ICASPL.EQ.'SLOP')THEN
          IDIST='SLOPE'
          LOWLTY='>=  '
          AUPPLM=2.0
          ADEF1=0.1
          ADEF2=1.99
        ELSEIF(ICASPL.EQ.'ALPH')THEN
          IDIST='ALPHA'
          ADEF1=0.5
          ADEF2=10.0
        ELSEIF(ICASPL.EQ.'MCLE')THEN
          IDIST='MCLEISH'
          ADEF1=1.0
          ADEF2=15.5
        ELSEIF(ICASPL.EQ.'ZETA')THEN
          IDIST='ZETA'
          ALOWLM=1.0
          AUPPLM=CPUMAX
          ADEF1=1.5
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'ZIPF')THEN
          IDIST='ZIPF'
          IHP21='N   '
          IHP22='    '
          ILOWL2=1
          IUPPL2=I1MACH(9)
          LOWLT2='>=  '
          UPPLT2='<=  '
          CALL PARCHI(IHP21,IHP22,IDIST,NU,ILOWL2,IUPPL2,LOWLT2,UPPLT2,   &
                      ISUBN1,ISUBN2,IERROR)
          SHAPE2=REAL(NU)
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER C
!
      ELSEIF(ICASPL.EQ.'TRIA' .OR. ICASPL.EQ.'POWF'.OR.   &
             ICASPL.EQ.'RFPP')THEN
        IHP11='C1  '
        IHP12='    '
        IHP21='C2  '
        IHP22='    '
        ALOWLM=0.0
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        ADEF1=0.5
        ADEF2=25.0
        IF(ICASPL.EQ.'TRIA')THEN
          IDIST='TRIANGULAR'
          ALOWLM=CPUMIN
          AUPPLM=CPUMAX
          LOWLTY='>=  '
          UPPLTY='<=  '
          ADEF1=A
          ADEF2=B
        ELSEIF(ICASPL.EQ.'POWF')THEN
          IDIST='POWER'
        ELSEIF(ICASPL.EQ.'RPOW')THEN
          IDIST='REFLECTED POWER'
        ENDIF
        GO TO 4100
!
!     DISTRIBUTIONS WITH SINGLE SHAPE PARAMETER P
!
      ELSEIF(ICASPL.EQ.'POWN' .OR. ICASPL.EQ.'WCAU' .OR.   &
             ICASPL.EQ.'GEOM' .OR. ICASPL.EQ.'BINO' .OR.   &
             ICASPL.EQ.'YULE' .OR. ICASPL.EQ.'LOST')THEN
        IHP11='P1  '
        IHP12='    '
        IHP21='P2  '
        IHP22='    '
        ALOWLM=0.
        AUPPLM=CPUMAX
        LOWLTY='>   '
        UPPLTY='<=  '
        IF(ICASPL.EQ.'POWN')THEN
          IDIST='POWER NORMAL'
          ADEF1=1.0
          ADEF2=50.0
        ELSEIF(ICASPL.EQ.'WCAU')THEN
          IDIST='WRAPPED CAUCHY'
          AUPPLM=1.0
          ADEF1=0.0
          ADEF2=0.99
          LOWLTY='>=  '
          UPPLTY='<   '
        ELSEIF(ICASPL.EQ.'GEOM')THEN
          IDIST='GEOMETRIC'
          ALOWLM=0.0
          AUPPLM=1.0
          LOWLTY='>   '
          UPPLTY='<   '
          ADEF1=0.01
          ADEF2=0.99
        ELSEIF(ICASPL.EQ.'YULE')THEN
          IDIST='YULE'
          ALOWLM=0.3
          AUPPLM=CPUMAX
          LOWLTY='>   '
          UPPLTY='<   '
          ADEF1=0.5
          ADEF2=5.0
        ELSEIF(ICASPL.EQ.'BINO')THEN
          IDIST='BINOMIAL'
          ALOWLM=0.0
          AUPPLM=1.0
          LOWLTY='>   '
          UPPLTY='<   '
          ADEF1=0.01
          ADEF2=0.99
          IHP21='N   '
          IHP22='    '
          ILOWLM=1
          IUPPLM=I1MACH(9)
          LOWLT2='>=  '
          UPPLT2='<=  '
          CALL PARCHI(IHP21,IHP22,IDIST,NBINOM,ILOWLM,IUPPLM,   &
                      LOWLT2,UPPLT2,   &
                      ISUBN1,ISUBN2,IERROR)
          SHAPE2=REAL(NBINOM)
          IF(IERROR.EQ.'YES')GO TO 9000
        ELSEIF(ICASPL.EQ.'LOST')THEN
          IDIST='LOST GAMES'
          ALOWLM=0.5
          AUPPLM=1.0
          LOWLTY='>   '
