        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IHP31,IHP32,IHP41,IHP42,SHAP21,SHAP22
 9015   FORMAT('IHP31,IHP32,IHP41,IHP42,SHAP21,SHAP22 = ',   &
               2(A4,A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE EXTPA2
      SUBROUTINE EXTREA(IATEMP,NCHAR,AVALUE,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE EXTRACTS A REAL VALUE FROM
!              A CHARACTER STRING.  LOOK FOR FIRST AND LAST
!              NON-BLANK CHARACTERS (IF ENTIRE FIELD IS BLANK,
!              RETURN A 0.).  THE INPUT STRING SHOULD CONTAIN ONLY
!              "+", "-", ".", OR A NUMBER.  IF ANY OTHER CHARACTER
!              ENCOUNTERED, THE REST OF THE STRING WILL BE
!              IGNORED.
!
!              NOTE THAT SOME REAL VALUES MAY CONTAIN A UNIT IDENTIFIER.
!              SO ONLY PROCESS THE CHARACTERS FROM THE FIRST NON-BLANK
!              CHARACTER TO THE FIRST SPACE AFTER THE FIRST NON-BLANK
!              CHARACTER.  ASSUME ANYTHING AFTER THIS IS SIMPLY A
!              UNIT SPECIFICATION.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!               HOST DEPENDENT
!     VERSION NUMBER--2014.10
!     ORIGINAL VERSION--OCTOBER    2014.
!     UPDATED         --JANUARY    2016. IF ENTIRE FIELD IS BLANK, THEN
!                                        RETURN CPUMIN RATHER THAN 0
!
!-----NON-COMMON VARIABLES (GRAPHICS)---------------------------------
!
      CHARACTER*(*) IATEMP
      CHARACTER*4   IBUGS2
      CHARACTER*4   ISUBRO
      CHARACTER*4   IERROR
      CHARACTER*10  IFORMT
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      AVALUE=CPUMIN
      NTOT=0
      NLEFT=0
      NRIGHT=0
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'TREA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)NUMREC,NCHAR
  51    FORMAT('EXTREA: NUMREC,NCHAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF (NCHAR.GT.0) THEN
            WRITE(ICOUT,53)IATEMP(1:MIN(80,NCHAR))
  53        FORMAT('IATEMP(1:NCHAR) = ',A80)
            CALL DPWRST('XXX','BUG ')
         ENDIF
      ENDIF
!
!     FIND FIRST NON-BLANK CHARACTER
!
      IF (NCHAR.LE.0) GO TO 9090
      IF (IATEMP(1:NCHAR).EQ.' ') GO TO 9090
      IF (NCHAR.EQ.1) THEN
         IVAL=ICHAR(IATEMP(1:1))
         IF (IVAL.LE.47 .OR. IVAL.GT.127) GO TO 9090
      ENDIF
!
      ISTRT=0
      DO 100 I=1,NCHAR
         IF (IATEMP(I:I).EQ.' ')GO TO 100
            ISTRT=I
            GO TO 109
  100 CONTINUE
      GO TO 9090
  109 CONTINUE
!
!     FIND FIRST "BLANK" AFTER FIRST NON-BLANK CHARACTER
!
      ILAST=NCHAR
      DO 110 I=ISTRT,NCHAR
         IF (IATEMP(I:I).EQ.' ')THEN
            ILAST=I-1
            GO TO 199
         ENDIF
  110 CONTINUE
  199 CONTINUE
!
!     FIND LAST NON-BLANK CHARACTER
!
!     CHECK FOR "NULL" OR "NAN" TO INDICATE MISSING DATA
!
      IF (ISTRT+3.LE.NCHAR) THEN
         IF (IATEMP(ISTRT:ISTRT+3).EQ.'NULL')THEN
            AVALUE=CPUMIN
            GO TO 9090
         ENDIF
      ELSEIF (ISTRT+2.LE.NCHAR) THEN
         IF (IATEMP(ISTRT:ISTRT+2).EQ.'NAN')THEN
            AVALUE=CPUMIN
            GO TO 9090
         ENDIF
      ELSEIF (ISTRT+2.LE.NCHAR) THEN
         IF (IATEMP(ISTRT:ISTRT+2).EQ.'NaN')THEN
            AVALUE=CPUMIN
            GO TO 9090
         ENDIF
      ELSEIF (ISTRT+2.LE.NCHAR) THEN
         IF (IATEMP(ISTRT:ISTRT+2).EQ.'nan')THEN
            AVALUE=CPUMIN
            GO TO 9090
         ENDIF
      ENDIF
!
!     CHECK FOR AN INTEGER VALUE
!
      IINT=1
      DO 310 I=ISTRT,ILAST
         IF (IATEMP(I:I).EQ.'.') THEN
            IINT=0
            GO TO 319
         ENDIF
  310 CONTINUE
  319 CONTINUE
!
      IF (IINT.EQ.1) THEN
         CALL EXTINT(IATEMP,ILAST,IVALUE,IBUGS2,ISUBRO,IERROR)
         AVALUE=REAL(IVALUE)
         GO TO 9090
      ENDIF
!
!     CHECK FOR "E" FORMAT.  HANDLE THIS BY EXTRACTING
!     THE REAL NUMBER BEFORE "E" AND THEN EXTRACTING
!     THE POWER AFTER THE "E".
!
      IPOSE=0
      IPOWER=0
      DO 400 I=ISTRT,ILAST
         IF (IATEMP(I:I).EQ.'E' .OR. IATEMP(I:I).EQ.'E')THEN
            ICURR=I+1
            ILAST=I-1
            IPOSE=I
            IF (IATEMP(ICURR:ICURR).EQ.'+') THEN
              READ(IATEMP(I+2:I+3),'(I2)')IPOWER
              GO TO 409
            ELSE IF (IATEMP(ICURR:ICURR).EQ.'-') THEN
              READ(IATEMP(I+2:I+3),'(I2)')IPOWER
              IPOWER=-IPOWER
              GO TO 409
            ELSE
              READ(IATEMP(I+1:I+2),'(I2)')IPOWER
              GO TO 409
            ENDIF
         ENDIF
  400 CONTINUE
  409 CONTINUE
!
!     CONVERT TEXT TO REAL NUMBER
!
!     LOOK FOR "+", "-", ".", OR NUMBER.  FIRST CHARACTER THAT
!     IS NOT ONE OF THESE WILL CAUSE THE REST OF THE FIELD TO
!     BE IGNORED (THIS BASICALLY SHOULD STRIP OFF UNITS).
!     ALSO, "+" AND "-" ONLY VALID IF THE FIRST ELEMENT OF THE
!     FIELD.  ONLY ONE "." WILL BE RECOGNIZED.
!
      IFLAG=0
      DO 300 I=ISTRT,ILAST
         IF (IATEMP(I:I).EQ.' ')THEN
            ILAST=I-1
            GO TO 399
         ELSEIF (IATEMP(I:I).EQ.'.')THEN
            IF (IFLAG.EQ.0)THEN
               IFLAG=1
               NTOT=NTOT+1
            ELSE
               ILAST=I-1
               GO TO 399
            ENDIF
         ELSEIF (IATEMP(I:I).EQ.'+')THEN
            IF (NTOT.EQ.0)THEN
               AFACT=1.0
               NTOT=NTOT+1
            ELSE
               ILAST=I-1
               GO TO 399
            ENDIF
         ELSEIF (IATEMP(I:I).EQ.'-')THEN
            IF (NTOT.EQ.0)THEN
               AFACT=-1.0
               NTOT=NTOT+1
            ELSE
               ILAST=I-1
               GO TO 399
            ENDIF
         ELSE
            ITEMP=ICHAR(IATEMP(I:I))
            IF (ITEMP.LT.48 .OR. ITEMP.GT.57)THEN
               ILAST=I-1
               GO TO 399
            ELSE
               IF (IFLAG.EQ.0)THEN
                  NTOT=NTOT+1
                  NLEFT=NLEFT+1
               ELSE
                  NTOT=NTOT+1
                  NRIGHT=NRIGHT+1
               ENDIF
            END IF
         END IF
  300 CONTINUE
  399 CONTINUE
      IFORMT='(F  .  )'
      IF (NRIGHT.GT.12)THEN
         NSUBT=NRIGHT-12
         ILAST=ILAST-NSUBT
         NTOT=NTOT-NSUBT
         NRIGHT=NRIGHT
      ENDIF
      WRITE(IFORMT(3:4),'(I2)')NTOT
      WRITE(IFORMT(6:7),'(I2)')NRIGHT
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'TREA')THEN
        WRITE(ICOUT,1011)IATEMP(ISTRT:ILAST)
 1011   FORMAT('EXTREA: IATEMP(ISTRT:ILAST) = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)NTOT,NLEFT,NRIGHT,IFORMT
 1013   FORMAT('NTOT,LEFT,NRIGHT,IFORMT = ',3G15.7,2X,A10)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      READ(IATEMP(ISTRT:ILAST),IFORMT,ERR=9010)AVALUE
!
!     NOW CHECK FOR EXPONENTIAL POWER
!
      IF (IPOSE.GT.0 .AND. IPOWER.NE.0) THEN
         IF(IPOWER.GT.0)THEN
           AVALUE=AVALUE*10**IPOWER
         ELSEIF(IPOWER.LT.0)THEN
           IPOW2=-IPOWER
           AVALUE=AVALUE/(10**IPOW2)
         ENDIF
      ENDIF
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'TREA')THEN
        WRITE(ICOUT,1091)IPOSE,IPOWER,AVALUE
 1091   FORMAT('EXTREA: IPOSE,IPOWER,AVALUE = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 9090
!
 9010 CONTINUE
      WRITE(ICOUT,9013)
 9013 FORMAT('****** ERROR FROM READ CLIPBOARD (EXTREA)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)
 9015 FORMAT('       UNABLE TO CONVERT STRING TO REAL NUMBER')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9090
!
 9090 CONTINUE
      RETURN
      END SUBROUTINE EXTREA
      SUBROUTINE EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,   &
                        JMIN,JMAX,   &
                        ISTACS,ISTANM,ISTANR,ISTADF,ISTARA,   &
                        IFOUND,ILOCV,ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--EXTRACT THE NAME OF ONE OF 90+ STATISTICS.  THIS
!              IS A COMMON ROUTINE CALLED BY:
!                1) CKSTAT  = LET A = <STAT>
!                2) DPSP    = <STAT> STATISTIC PLOT
!                3) DPMOSP  = <STAT> CUMULATIVE STATISTIC PLOT
!                4) DPMOSP  = <STAT> MOVING STATISTIC PLOT
!                5) DPMOSP  = <STAT> WINDOW STATISTIC PLOT
!                6) DPCRPL  = CROSS TABULATE <STAT> PLOT
!                7) DPFLUC  = FLUCTUATION PLOT <STAT>
!                8) DPTAPL  = TABULATION PLOT <STAT>
!                9) DPBLOC  = <STAT> BLOCK PLOT
!               10) DPJBSP  = BOOTSTRAP <STAT> PLOT
!               11) DPJBSP  = JACKNIFE <STAT> PLOT
!               12) DPDEXP  = DEX <STAT> PLOT
!               13) DPDEXP  = DEX <STAT> EFFECTS PLOT
!               14) DPDEXP  = DEX <STAT> ABSOLUTE EFFECTS PLOT
!               15) DPDEXP  = DEX <STAT> PARETO PLOT
!               16) DPDEXP  = DEX <STAT> PARETO EFFECTS PLOT
!               17) DPDEXP  = DEX <STAT> PARETO ABSOLUTE EFFECTS PLOT
!               18) DPDEXP  = DEX <STAT> YOUDEN PLOT
!               19) DPISP   = <STAT> INTERACTION PLOT
!               20) DPDEXP  = CLASSIFICATION <STAT> PLOT
!               21) DPINCU  = <STAT> INFLUENCE CURVE
!               22) DPCRTA  = CROSS TABULATE <STAT>
!               23) DPPOTA  = POSITIONAL TABULATION <STAT>
!               24) DPPTES  = TWO SAMPLE <STAT> PERMUTATION TEST
!               25) DPPTES  = K SAMPLE <STAT> PERMUTATION TEST
!               26) CKMATH  = MATRIX COLUMN <STAT>
!               27) CKMATH  = MATRIX ROW <STAT>
!               28) CKMATH  = MATRIX GRAND <STAT>
!               29) CKMATH  = MATRIX PARTITION <STAT>
!               30) CKMATH  = GENERATE MATRIX <STAT>
!               31) CKMATH  = LET V = CROSS TABULATE <STAT>
!               32) CKMATH  = LET V = CROSS TABULATE CUMULATIVE <STAT>
!               33) CKMATH  = LET V = SORT BY <STAT>
!               34) CKMATH  = LET V = MOVING <STAT>
!               35) CKMATH  = LET V = CUMULATIVE <STAT>
!               36) CKMATH  = LET V = WINDOW <STAT>
!
!              NOTE THAT THE DEX ... PLOT, ... BLOCK PLOT, AND
!              ... INFLUENCE CURVE, MATRIX <COLUMN/ROW> ONLY SUPPORT
!              STATISTICS COMPUTED FROM A SINGLE RESPONSE VARIABLE.
!              ALSO, SOME COMMANDS MAY NOT SUPPORT ALL STATISTICS IN
!              THIS LIST (OR, LESS FREQUENTLY, A COMMAND MAY SUPPORT
!              SOME ADDITIONAL STATISTICS NOT COMPUTED HERE).
!
!              USING A COMMON ROUTINE MAKES IT EASIER TO ADD
!              A STATISTIC AND INCORPORATE IT INTO ALL THE
!              RELEVANT PLOTS/TABULATIONS.  SHOULD ALSO REDUCE
!              THE LIKELIHOOD OF BUGS, ETC.
!
!              FOLLOWING STATISTICS ARE SUPPORTED:
!
!              CASE 1: ONE RESPONSE VARIABLE
!
!              LOCATION STATISTICS:
!                 BIWEIGHT LOCATION
!                 GEOMETRIC MEAN
!                 H10 LOCATION
!                 H12 LOCATION
!                 H15 LOCATION
!                 H17 LOCATION
!                 H20 LOCATION
!                 HARMONIC MEAN
!                 HODGES-LEHMAN
!                 JSCORE
!                 LP LOCATION
!                 MEAN (OR AVERAGE)
!                 MEDIAN
!                 MIDHINGE
!                 MIDMEAN
!                 MIDRANGE
!                 SHANNON ENTROPY
!                 SHANNON ENTROPY MEAN
!                 SHORTEST HALF MIDMEAN
!                 SHORTEST HALF MIDRANGE
!                 STANDARD DEVIATION OF LP LOCATION
!                 STANDARD DEVIATION OF THE MEAN
!                 TRIMEAN
!                 TRIMMED MEAN
!                 TRIMMED MEAN STANDARD ERROR
!                 VARIANCE OF THE MEAN
!                 VARIANCE OF LP LOCATION
!                 WINSORIZED MEAN
!
!              SCALE STATISTICS:
!                 AVERAGE ABSOLUTE DEVIATION (AAD)
!                 AVERAGE ABSOLUTE DEVIATION FROM THE MEDIAN
!                 BIWEIGHT MIDVARIANCE
!                 BIWEIGHT SCALE
!                 COEFFICIENT OF DISPERSION
!                 COEFFICIENT OF INTERQUARTILE DEVIATION
!                 COEFFICIENT OF VARIATION
!                 GEOMETRIC STANDARD DEVIATION
!                 GINI MEAN DIFFERENCE
!                 H10 SCALE
!                 H12 SCALE
!                 H15 SCALE
!                 H17 SCALE
!                 H20 SCALE
!                 INDEX OF DISPERSION
!                 INTERQUARTILE DEVIATION
!                 INTERQUARTILE RANGE
!                 LOGNORMAL COEFFICIENT OF VARIATION
!                 LOWER SEMI-INTERQUARTILE RANGE
!                 MAD TO MEDIAN
!                 MEDIAN ABSOLUTE DEVIATION (MAD)
!                 PERCENTAGE BEND MIDVARIANCE
!                 PRECISION
!                 QN
!                 Q QUANTILE RANGE
!                 QUARTILE COEFFICIENT OF DISPERSION
!                 RANGE
!                 RELATIVE LABORATORY PERFORMANCE (RLP)
!                 RELATIVE SD
!                 RELATIVE VARIANCE
!                 RESCALED SUM
!                 ROBUST POOLED RANGE
!                 ROBUST POOLED STANDARD DEVIATION
!                 ROOT MEAN SQUARE ERROR (OR RMS)
!                 SCALED MEDIAN ABSOLUTE DEVIATION (MADe)
!                 SHANNON ENTROPY STANDARD DEVIATION
!                 SHANNON ENTROPY VARIANCE
!                 SIGNAL TO NOISE RATIO
!                 SN
!                 STANDARD DEVIATION (OR SD)
!                 SUM OF SQUARES
!                 SUM OF SQUARES FROM MEAN
!                 TRIMMED SD
!                 UNBIASED COEFFICIENT OF VARIATION
!                 UPPER SEMI-INTERQUARTILE RANGE
!                 VARIANCE
!                 WINSORIZED STANDARD DEVIATION
!                 WINSORIZED VARIANCE
!
!              PERCENTILE STATISTICS
!                 FIRST/SECOND/THIRD/FOURTH/FIFTH/SIXTH/SEVENTH/
!                       EIGHTH/NINTH DECILE
!                 DECILE RATIO
!                 EXTREME
!                 INDEX MINIMUM
!                 INDEX MAXIMUM
!                 INDEX EXTREME
!                 LOWER HINGE
!                 LOWER QUARTILE
!                 MINIMUM (MIN)
!                 MAXIMUM (MAX)
!                 <VALUE> PERCENTILE
!                 QUANTILE STANDARD ERROR
!                 UPPER HINGE
!                 UPPER QUARTILE
!
!              HIGHER MOMENTS
!                 GALTON SKEWNESS
!                 KURTOSIS
!                 PEARSON TWO SKEWNESS
!                 SKEWNESS
!
!              TIME SERIES STATISTICS
!                 AUTOCORRELATION
!                 AUTOCOVARIANCE
!                 SINE FREQUENCY
!                 SINE AMPLITUDE
!
!              QUALITY CONTROL STATISTICS
!                 CC
!                 CNP
!                 CNPK
!                 CNPM
!                 CNPMK
!                 CP
!                 CPK
!                 CPL
!                 CPM
!                 CPMK
!                 CPU
!                 EXPECTED LOSS
!                 (ACTUAL) PERCENT DEFECTIVE
!                 (THEORETICAL) PERCENT DEFECTIVE
!                 (ACTUAL) PERCENT ACCEPTABLE
!                 (THEORETICAL) PERCENT ACCEPTABLE
!                 TAGUCHI SIGNAL-TO-NOISE (SN+, SN-, SN0, SN00)
!
!              STATISTICAL TESTS:
!                 A BASIS NORMAL
!                 A BASIS LOGNORMAL
!                 A BASIS WEIBULL
!                 A BASIS NONPARAMETRIC
!                 B BASIS NORMAL
!                 B BASIS LOGNORMAL
!                 B BASIS WEIBULL
!                 B BASIS NONPARAMETRIC
!                 ADJANCENCY RANDOMNESS TEST
!                 ADJANCENCY RANDOMNESS TEST CDF
!                 ADJANCENCY RANDOMNESS TEST PVALUE
!                 BINOMIAL PROPORTIONS
!                 BINOMIAL PROPORTIONS LOWER CONFIDENCE LIMIT
!                 BINOMIAL PROPORTIONS UPPER CONFIDENCE LIMIT
!                 CHI-SQUARE SD TEST
!                 CHI-SQUARE SD TEST CDF
!                 CHI-SQUARE SD TEST PVALUE
!                 CHI-SQUARE SD TEST LOWER TAIL PVALUE
!                 CHI-SQUARE SD TEST UPPER TAIL PVALUE
!                 CUMULATIVE SUM FORWARD TEST
!                 CUMULATIVE SUM FORWARD TEST PVALUE
!                 CUMULATIVE SUM BACKWARD TEST
!                 CUMULATIVE SUM BACKWARD TEST PVALUE
!                 DAVID
!                 DAVID CDF
!                 DAVID CRITICAL VALUE
!                 DAVID MINIMUM INDEX
!                 DAVID MAXIMUM INDEX
!                 DAVID PVALUE
!                 DIXON TEST
!                 DIXON MINIMUM TEST
!                 DIXON MAXIMUM TEST
!                 EXTREME STUDENTIZED DEVIATE
!                 FREQUENCY TEST
!                 FREQUENCY TEST CDF
!                 FREQUENCY WITHIN A BLOCK TEST
!                 FREQUENCY WITHIN A BLOCK TEST CDF
!                 GRUBB
!                 GRUBB CDF
!                 GRUBB DIRECTION
!                 GRUBB INDEX
!                 JARQUE BERA
!                 JARQUE BERA PVALUE
!                 JARQUE BERA CDF
!                 KURTOSIS OUTLIER
!                 KURTOSIS OUTLIER CDF
!                 KURTOSIS OUTLIER CRITICAL VALUE
!                 KURTOSIS OUTLIER INDEX
!                 KURTOSIS OUTLIER PVALUE
!                 LOWER COEFFICIENT OF DISPERSION CONFIDENCE LIMIT
!                 LOWER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMIT
!                 LOWER COEFFICIENT OF VARIATION CONFIDENCE LIMIT
!                 LOWER CONFIDENCE LIMIT
!                 LOWER LOGNORMAL COEFFICIENT OF VARIATION CONFIDENCE LIMIT
!                 LOWER BONETT STANDARD DEVIATION CONFIDENCE LIMIT
!                 LOWER PREDICTION BOUND
!                 LOWER PREDICTION LIMIT
!                 LOWER STANDARD DEVIATION CONFIDENCE LIMIT
!                 LOWER STANDARD DEVIATION PREDICTION LIMIT
!                 LJUNG BOX TEST
!                 MCCOOL WEIBULL LOCATION TEST
!                 MCCOOL WEIBULL LOCATION TEST PVALUE
!                 MCCOOL WEIBULL LOCATION TEST CDF
!                 MCCOOL WEIBULL LOCATION TEST CV50
!                 MCCOOL WEIBULL LOCATION TEST CV90
!                 MCCOOL WEIBULL LOCATION TEST CV95
!                 MEAN SUCCESSIVE DIFFERENCE
!                 MEAN SUCCESSIVE DIFFERENCE NORMALIZED
!                 MEAN SUCCESSIVE DIFFERENCE CDF
!                 MEAN SUCCESSIVE DIFFERENCE PVALUE
!                 NORMAL TOLERANCE K FACTOR
!                 NORMAL TOLERANCE LOWER LIMIT
!                 NORMAL TOLERANCE UPPER LIMIT
!                 NORMAL TOLERANCE ONE SIDED K FACTOR
!                 NORMAL TOLERANCE ONE SIDED LOWER LIMIT
!                 NORMAL TOLERANCE ONE SIDED UPPER LIMIT
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST CDF
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST PVALUE
!                 ONE SAMPLE COEFFICIENT OF VARIATION LOWER PVALUE
!                 ONE SAMPLE COEFFICIENT OF VARIATION UPPER PVALUE
!                 ONE SAMPLE SIGN TEST
!                 ONE SAMPLE SIGN TEST CDF
!                 ONE SAMPLE SIGN TEST PVALUE
!                 ONE SAMPLE SIGN TEST LOWER TAIL PVALUE
!                 ONE SAMPLE SIGN TEST UPPER TAIL PVALUE
