      DATA INLONG(1650)/'RANDOMIZED COMPLETE BLOCK TEST STATISTIC'/
!
      DATA INCASE(1651)/'RCBC'/
      DATA (INAME(1651,J),J=1,MAXSCL)/   &
      'RAND','    ','COMP','BLOC','DESI','CDF ','    ','    '/
      DATA INFLAV(1651)/3/
      DATA INLONG(1651)/'RANDOMIZED COMPLETE BLOCK CDF'/
!
      DATA INCASE(1652)/'RCBP'/
      DATA (INAME(1652,J),J=1,MAXSCL)/   &
      'RAND','    ','COMP','BLOC','DESI','PVAL','    ','    '/
      DATA INFLAV(1652)/3/
      DATA INLONG(1652)/'RANDOMIZED COMPLETE BLOCK P-VALUE'/
!
      DATA INCASE(1653)/'RCBP'/
      DATA (INAME(1653,J),J=1,MAXSCL)/   &
      'RAND','    ','COMP','BLOC','DESI','P   ','VALU','    '/
      DATA INFLAV(1653)/3/
      DATA INLONG(1653)/'RANDOMIZED COMPLETE BLOCK P-VALUE'/
!
      DATA INCASE(1654)/'PVAR'/
      DATA (INAME(1654,J),J=1,MAXSCL)/   &
      'POOL','    ','VARI','    ','    ','    ','    ','    '/
      DATA INFLAV(1654)/2/
      DATA INLONG(1654)/'POOLED VARIANCE'/
!
      DATA INCASE(1655)/'SPVA'/
      DATA (INAME(1655,J),J=1,MAXSCL)/   &
      'SUMM','    ','POOL','VARI','    ','    ','    ','    '/
      DATA INFLAV(1655)/2/
      DATA INLONG(1655)/'SUMMARY POOLED VARIANCE'/
!
      DATA INCASE(1656)/'PSD '/
      DATA (INAME(1656,J),J=1,MAXSCL)/   &
      'POOL','    ','SD  ','    ','    ','    ','    ','    '/
      DATA INFLAV(1656)/2/
      DATA INLONG(1656)/'POOLED STANDARD DEVIATION'/
!
      DATA INCASE(1657)/'SPSD'/
      DATA (INAME(1657,J),J=1,MAXSCL)/   &
      'SUMM','    ','POOL','SD  ','    ','    ','    ','    '/
      DATA INFLAV(1657)/2/
      DATA INLONG(1657)/'SUMMARY POOLED STANDARD DEVIATION'/
!
      DATA INCASE(1658)/'PSD '/
      DATA (INAME(1658,J),J=1,MAXSCL)/   &
      'POOL','    ','STAN','DEVI','    ','    ','    ','    '/
      DATA INFLAV(1658)/2/
      DATA INLONG(1658)/'POOLED STANDARD DEVIATION'/
!
      DATA INCASE(1659)/'SPSD'/
      DATA (INAME(1659,J),J=1,MAXSCL)/   &
      'SUMM','    ','POOL','STAN','DEVI','    ','    ','    '/
      DATA INFLAV(1659)/2/
      DATA INLONG(1659)/'SUMMARY POOLED STANDARD DEVIATION'/
!
      DATA INCASE(1660)/'POSD'/
      DATA (INAME(1660,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','STAN','DEVI','    ','    ','    '/
      DATA INFLAV(1660)/2/
      DATA INLONG(1660)/'POSITION EFFECT STANDARD DEVIATION'/
!
      DATA INCASE(1661)/'POSD'/
      DATA (INAME(1661,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','SD  ','    ','    ','    ','    '/
      DATA INFLAV(1661)/2/
      DATA INLONG(1661)/'POSITION EFFECT STANDARD DEVIATION'/
!
      DATA INCASE(1662)/'POVA'/
      DATA (INAME(1662,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','VARI','    ','    ','    ','    '/
      DATA INFLAV(1662)/2/
      DATA INLONG(1662)/'POSITION EFFECT VARIANCE'/
!
      DATA INCASE(1663)/'POTS'/
      DATA (INAME(1663,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','TEST','STAT','    ','    ','    '/
      DATA INFLAV(1663)/2/
      DATA INLONG(1663)/'POSITION EFFECT TEST STATISTIC'/
!
      DATA INCASE(1664)/'POCD'/
      DATA (INAME(1664,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','CDF ','    ','    ','    ','    '/
      DATA INFLAV(1664)/2/
      DATA INLONG(1664)/'POSITION EFFECT CDF'/
!
      DATA INCASE(1665)/'POPV'/
      DATA (INAME(1665,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','PVAL','    ','    ','    ','    '/
      DATA INFLAV(1665)/2/
      DATA INLONG(1665)/'POSITION EFFECT P-VALUE'/
!
      DATA INCASE(1666)/'IQDV'/
      DATA (INAME(1666,J),J=1,MAXSCL)/   &
      'INTE','    ','DEVI','    ','    ','    ','    ','    '/
      DATA INFLAV(1666)/1/
      DATA INLONG(1666)/'INTERQUARTILE DEVIATION'/
!
      DATA INCASE(1667)/'CIQD'/
      DATA (INAME(1667,J),J=1,MAXSCL)/   &
      'COEF','    ','OF  ','INTE','DEVI','    ','    ','    '/
      DATA INFLAV(1667)/1/
      DATA INLONG(1667)/'COEFFICIENT OF INTERQUARTILE DEVIATION'/
!
      DATA INCASE(1668)/'POSE'/
      DATA (INAME(1668,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','POOL','WITH','STAN','DEVI','    '/
      DATA INFLAV(1668)/2/
      DATA INLONG(1668)/'POSITION EFFECT POOLED WITHIN STANDARD DEVIATION'/
!
      DATA INCASE(1669)/'POSE'/
      DATA (INAME(1669,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','POOL','WITH','SD  ','    ','    '/
      DATA INFLAV(1669)/2/
      DATA INLONG(1669)/'POSITION EFFECT POOLED WITHIN STANDARD DEVIATION'/
!
      DATA INCASE(1670)/'POSM'/
      DATA (INAME(1670,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','POSI','MEAN','SD  ','    ','    '/
      DATA INFLAV(1670)/2/
      DATA INLONG(1670)/'POSITION EFFECT POSITION MEAN STANDARD DEVIATION'/
!
      DATA INCASE(1671)/'POSM'/
      DATA (INAME(1671,J),J=1,MAXSCL)/   &
      'POSI','    ','EFFE','POSI','MEAN','STAN','DEVI','    '/
      DATA INFLAV(1671)/2/
      DATA INLONG(1671)/'POSITION EFFECT POSITION MEAN STANDARD DEVIATION'/
!
      DATA INCASE(1672)/'PERC'/
      DATA (INAME(1672,J),J=1,MAXSCL)/   &
      'PERC','    ','    ','    ','    ','    ','    ','    '/
      DATA INFLAV(1672)/1/
      DATA INLONG(1672)/'PERCENTILE'/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='EXTS'
      ISUBN2='TA  '
      IWRITE='OFF'
      ISUBN1='EXTS'
      ISUBN2='TA  '
      IWRITE='OFF'
      ISTARA='OFF'
      IFOUND='NO'
      IERROR='NO'
      ICNTRA=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXTSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG3,ISUBRO,NUMARG,JMIN,JMAX
   52   FORMAT('IBUGG3,ISUBRO,NUMARG,JMIN,JMAX = ',A4,2X,A4,3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICOM,ICOM2
   53   FORMAT('ICOM,ICOM2 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GE.1)THEN
          DO 60 I=1,NUMARG
            WRITE(ICOUT,61)I,IHARG(I),IHARG2(I)
   61       FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2X,A4,2X,A4)
            CALL DPWRST('XXX','BUG ')
   60     CONTINUE
        ENDIF
        WRITE(ICOUT,63)MAXSTA,MAXSCL
   63   FORMAT('MAXSTA,MAXSCL = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     STEP 1: INITIALIZE THE MATCHING VARIABLE
!
      DO 1010 I=1,MAXSCL
        INTEMP(I)='    '
 1010 CONTINUE
!
!     2023/08: CHECK IF FIRST TWO ARGUMENTS ARE "RATIO OF"
!
      IF(JMIN.EQ.0)THEN
        IF(ICOM.EQ.'RATI' .AND. ICOM2.EQ.'O   ' .AND.   &
           IHARG(1).EQ.'OF  ')THEN
          JMIN=2
          ISTARA='ON'
        ENDIF
      ELSEIF(JMIN.GE.1)THEN
        IF(IHARG(JMIN).EQ.'RATI' .AND. IHARG2(JMIN).EQ.'O   ' .AND.   &
           IHARG(JMIN+1).EQ.'OF  ')THEN
          JMIN=JMIN+2
          ISTARA='ON'
        ENDIF
      ENDIF
!
!     CHECK FOR CONFLICTS WITH PREVIOUSLY IMPLEMENTED COMMANDS
!
!          RATIO OF <MEAN/VARIANCE/SD/STANDARD DEVIATION>
!          RATIO OF <MEAN/VARIANCE/SD/STANDARD DEVIATION>
!                   <LOWWER/UPPER> CONFIDENCE <LIMIT/INTERVAL>
!
      IF(ISTARA.EQ.'ON')THEN
        IF(JMAX.EQ.JMIN+1)THEN
          IF(IHARG(JMAX).EQ.'VARI' .OR. IHARG(JMAX).EQ.'SD  ' .OR.   &
             IHARG(JMAX).EQ.'MEAN')THEN
            ISTARA='OFF'
            JMIN=JMIN-2
            GO TO 199
          ENDIF
        ELSEIF(JMAX.EQ.JMIN+2)THEN
          IF(IHARG(JMIN+1).EQ.'STAN' .AND. IHARG(JMIN+2).EQ.'DEVI')THEN
            ISTARA='OFF'
            JMIN=JMIN-2
            GO TO 199
          ENDIF
        ELSEIF(JMAX.GE.JMIN+4)THEN
          IF((IHARG(JMIN+2).EQ.'LOWE'.OR.IHARG(JMIN+2).EQ.'UPPE') .AND.   &
              IHARG(JMIN+3).EQ.'CONF')THEN
            ISTARA='OFF'
            JMIN=JMIN-2
            GO TO 199
          ELSEIF((IHARG(JMIN+3).EQ.'LOWE'.OR.IHARG(JMIN+3).EQ.'UPPE')   &
              .AND. IHARG(JMIN+4).EQ.'CONF')THEN
            ISTARA='OFF'
            JMIN=JMIN-2
            GO TO 199
          ENDIF
        ENDIF
      ENDIF
!
  199 CONTINUE
!
      IF(JMIN.EQ.0)THEN
        INTEMP(1)=ICOM
        INTEMP(2)=ICOM2
        ICNT=2
        IF(JMIN.LT.JMAX)THEN
          DO 1020 I=JMIN+1,JMAX
            ICNT=ICNT+1
            INTEMP(ICNT)=IHARG(I)
 1020     CONTINUE
        ENDIF
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1021)ICNT
 1021      FORMAT('JMIN = 0 CASE, ICNT = ',I8)
           CALL DPWRST('XXX','BUG ')
           DO 1022 II=1,ICNT
             WRITE(ICOUT,1023)II,INTEMP(II)
 1023        FORMAT('II,INTEMP(II) = ',I8,A4)
             CALL DPWRST('XXX','BUG ')
 1022      CONTINUE
        ENDIF
!
      ELSE
        INTEMP(1)=IHARG(JMIN)
        INTEMP(2)=IHARG2(JMIN)
        ICNT=2
        IF(JMAX.GT.JMIN)THEN
          DO 1030 I=JMIN+1,JMAX
            ICNT=ICNT+1
            INTEMP(ICNT)=IHARG(I)
 1030     CONTINUE
        ENDIF
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1031)ICNT
 1031      FORMAT('JMIN > 0 CASE, ICNT = ',I8)
           CALL DPWRST('XXX','BUG ')
           DO 1032 II=1,ICNT
             WRITE(ICOUT,1033)II,INTEMP(II)
 1033        FORMAT('II,INTEMP(II) = ',I8,A4)
             CALL DPWRST('XXX','BUG ')
 1032      CONTINUE
        ENDIF
!
      ENDIF
!
!     STEP 1A: CHECK FOR "QUANTILE" OR "PERCENTILE" AS SECOND
!              ARGUMENT (INTEMP(3)).  IF SO, SAVE THE PARAMETER
!              NAME IN A COMMON BLOCK (IF ARGUMENT TYPE IS
!              NUMERIC, SAVE THE VALUE).
!
!               CHECK ALSO FOR GROUPED PERCENTILE/QUANTILE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
        WRITE(ICOUT,1042)
 1042   FORMAT('CHECK FOR PERCENTILE/GROUPED PERCENTILE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1043)INTEMP(1)
 1043   FORMAT('INTEMP(1) = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1044)INTEMP(2)
 1044   FORMAT('INTEMP(2) = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1045)INTEMP(3)
 1045   FORMAT('INTEMP(3) = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1046)INTEMP(4)
 1046   FORMAT('INTEMP(4) = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IPNAM1='    '
      IPNAM2='    '
      APVAL=CPUMIN
      IFLAGQ=0
      IF((INTEMP(3).EQ.'QUAN' .OR. INTEMP(3).EQ.'PERC' ).AND.   &
         INTEMP(1).NE.'Q   ' .AND. INTEMP(1).NE.'BOOT' .AND.   &
         INTEMP(1).NE.'JACK' .AND. INTEMP(1).NE.'GROU')THEN
        IF(IARGT(JMIN).EQ.'NUMB')THEN
          APVAL=ARG(JMIN)
        ELSE
          IPNAM1=INTEMP(1)
          IPNAM2=INTEMP(2)
        ENDIF
        INTEMP(1)=INTEMP(3)
        INTEMP(2)='    '
        DO I=3,MAXSCL-1
          INTEMP(I)=INTEMP(I+1)
        ENDDO
        INTEMP(MAXSCL)='    '
        IFLAGQ=1
      ELSEIF(INTEMP(3).EQ.'GROU' .AND.    &
            (INTEMP(4).EQ.'QUAN' .OR. INTEMP(4).EQ.'PERC' ).AND.   &
             INTEMP(1).NE.'Q   ' .AND. INTEMP(1).NE.'BOOT' .AND.   &
             INTEMP(1).NE.'JACK')THEN
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
          WRITE(ICOUT,1052)
 1052     FORMAT('FOUND GROUP PERCENTILE')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IARGT(JMIN).EQ.'NUMB')THEN
          APVAL=ARG(JMIN)
        ELSE
          IPNAM1=INTEMP(1)
          IPNAM2=INTEMP(2)
        ENDIF
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
          WRITE(ICOUT,1054)IPNAM1,IPNAM2
 1054     FORMAT('IPNAM1,IPNAM2 = ',2A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        INTEMP(1)=INTEMP(3)
        INTEMP(2)='    '
        DO I=3,MAXSCL-1
          INTEMP(I)=INTEMP(I+1)
!
          IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
            WRITE(ICOUT,1056)I,INTEMP(I)
 1056       FORMAT('I,INTEMP(I) = ',I6,A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ENDDO
        INTEMP(MAXSCL)='    '
        IFLAGQ=1
      ENDIF
!
!     STEP 2: NOW CHECK IF MATCHING VARIABLE MATCHES AN ENTRY
!             IN THE TABLE.  NOTE THAT WE NEED TO CHECK FOR
!             NAME CONFLICTS IN FIRST 4 CHARACTERS OF FIRST
!             ARGUMENT.
!
      DO 2000 I=1,MAXSTA
        IROW=I
        IF(INAME(I,1).NE.INTEMP(1))GO TO 2000
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,2001)I,INAME(I,1),INTEMP(1)
 2001      FORMAT('I,INAME(I,1),INTEMP(1) = ',I8,2X,A4,2X,A4)
           CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       FIRST 4 CHARACTERS MATCHED.  NEED TO CHECK IF CHARACTERS
!       5-8 MATCH FOR CERTAIN CASES.
!
        IF(INAME(I,2).NE.'    ')THEN
          IF(INAME(I,2).NE.INTEMP(2))GO TO 2000
        ENDIF
!
!       NOW CHECK IF REMAINING ARGUMENTS MATCH
!
        ITEMP=1
        DO 2022 J=3,MAXSCL
          IF(INAME(IROW,J).NE.'    ')GO TO 2022
            ITEMP=J-1
            GO TO 2024
 2022   CONTINUE
        ITEMP=MAXSCL
 2024   CONTINUE
!
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
           WRITE(ICOUT,2027)IROW,ITEMP
 2027      FORMAT('IROW,ITEMP = ',2I8)
           CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ITEMP.GT.2)THEN
          DO 2028 J=3,ITEMP
            IF(INAME(IROW,J).NE.INTEMP(J))GO TO 2000
 2028     CONTINUE
        ENDIF
!
        IFOUND='YES'
        IF(ITEMP.EQ.1)THEN
          ILOCV=JMIN+1
        ELSE
          ILOCV=JMIN+(ITEMP-2)+1
        ENDIF
        IF(IFLAGQ.EQ.1)ILOCV=ILOCV+1
        ISTACS=INCASE(IROW)
        ISTANR=INFLAV(IROW)
        ISTANM=INLONG(IROW)
        ISTADF='OFF'
        IF(INTEMP(1).EQ.'DIFF')ISTADF='ON'
        GO TO 2099
!
 2000 CONTINUE
!
!     2016/08: IF NO MATCH FOUND, CHECK FOR "STATISTIC BLOCK".
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
        WRITE(ICOUT,2101)
 2101   FORMAT('AFTER CHECK PRE-DEFINED STATISTICS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2103)ISBNA1
 2103   FORMAT('ISBNA1 = ',A8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2105)ISBNA2
 2105   FORMAT('ISBNA2 = ',A8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2107)ISBNA3
 2107   FORMAT('ISBNA3 = ',A8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2109)INTEMP(1),INTEMP(2)
 2109   FORMAT('INTEMP(1),INTEMP(2) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(INTEMP(1).EQ.ISBNA1(1:4).AND.INTEMP(2).EQ.ISBNA1(5:8))THEN
        IFOUND='YES'
        ILOCV=JMIN+1
        ISTACS='SBL1'
        ISTANR=ISBCP1
        ISTANM='STATISTIC BLOCK ONE'
        ISTADF='OFF'
      ELSEIF(INTEMP(1).EQ.ISBNA2(1:4).AND.INTEMP(2).EQ.ISBNA2(5:8))THEN
        IFOUND='YES'
        ILOCV=JMIN+1
        ISTACS='SBL2'
        ISTANR=ISBCP1
        ISTANM='STATISTIC BLOCK TWO'
        ISTADF='OFF'
      ELSEIF(INTEMP(1).EQ.ISBNA3(1:4).AND.INTEMP(2).EQ.ISBNA3(5:8))THEN
        IFOUND='YES'
        ILOCV=JMIN+1
        ISTACS='SBL3'
        ISTANR=ISBCP3
        ISTANM='STATISTIC BLOCK THREE'
        ISTADF='OFF'
      ENDIF
!
 2099 CONTINUE
!
!     2023/08: FOR "RATIO OF", CHECK THAT REQUESTED STATISTIC
!              EXPECTS A SINGLE RESPONSE VARIABLE
!
      IF(ISTARA.EQ.'ON' .AND. ISTANR.GT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1400)
 1400   FORMAT('****** ERROR IN EXTSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1401)
 1401   FORMAT('      FOR THE    RATIO OF   CASE, THE SPECIFIED ',   &
               'STATISTIC')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1403)
 1403   FORMAT('      MUST BE ONE THAT EXPECTS A SINGLE RESPONSE ',   &
               'VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1405)ISTANM,ISTANR
 1405   FORMAT('      ',A60,' EXPECTS ',I1,' RESPONSE VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ISTARA.EQ.'ON')ISTANR=2
!
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TSTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EXTSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGG3,ISUBRO,IFOUND
 9012   FORMAT('IBUGG3,ISUBRO,IFOUND = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(IFOUND.EQ.'YES')THEN
          WRITE(ICOUT,9013)ISTACS,ISTADF,ISTANR,ILOCV
 9013     FORMAT('ISTACS,ISTADF,ISTANR,ILOCV = ',A4,2X,A4,2X,2I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9014)ISTANM
 9014     FORMAT('ISTANM = ',A60)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE EXTSTA
      SUBROUTINE EXTSTR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXIND,   &
                        IHNAME,IHNAM2,IUSE,NUMNAM,   &
                        ISTRN1,ISTRN2,NUMSTR,   &
                        IWRITE,IBUGA2,ISUBRO,IERROR)
!
!     PURPOSE--EXAMINE IHARG(.) AND IHARG2(.) FROM JMIN TO JMAX, EXTRACT
!              ALL NAMES (INCLUDING THOSE IMPLIED BY A   TO   KEYWORD)
!              AND PLACE THESE NAMES IN ISTRN1(.) AND ISTRN2(.).
!              NOTE THE NUMBER OF SUCH NAMES AND PLACE IT IN NUMSTR.
!              NUMSTR STANDS FOR NUMBER OF STRINGS.
!     NOTE--JMIN   = START POINT IN IHARG/IHARG2 FOR THE SCAN
!           JMAX   = STOP POINT  IN IHARG/IHARG2 FOR THE SCAN
!           MAXIND = MAXIMUM PERMITTED NUMBER OF STRINGS
!     NOTE--THIS SUBROUTINE ALSO CHECKS TO MAKE SURE THE LIST ITEMS ARE
!           IN FACT STRINGS (AS OPPOSED TO PARAMETERS, VARIABLES,
!           MATRICES, OR UNKNOWNS).
!     OUTPUT--ISTRN1(.), ISTRN2(.), AND NUMSTR.
!     ORIGINAL VERSION--JANUARY   2006.
!     UPDATED         --JULY      2009. ALLOW "Y1 TO Y1" (USEFUL FOR
!                                       MACROS WHERE NUMBER OF STRINGS
!                                       IS NOT KNOWN IN ADVANCE)
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION ISTRN1(*)
      DIMENSION ISTRN2(*)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 ISTRN1
      CHARACTER*4 ISTRN2
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH1
      CHARACTER*4 IH2
      CHARACTER*4 ICASTO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NUMSTR=0
      JM1=0
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TSTR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXTSTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,ISUBRO
   53   FORMAT('IBUGA2,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)JMIN,JMAX,MAXIND,NUMSTR,NUMARG,NUMNAM
   54   FORMAT('JMIN,JMAX,MAXIND,NUMSTR,NUMARG,NUMNAM = ',5I6)
        CALL DPWRST('XXX','BUG ')
        DO 62 I=1,NUMARG
          WRITE(ICOUT,63)I,IHARG(I),IHARG2(I)
   63     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2(2X,A4))
          CALL DPWRST('XXX','BUG ')
   62   CONTINUE
        DO 72 I=1,NUMNAM
          WRITE(ICOUT,73)I,IHNAME(I),IHNAM2(I),IUSE(I)
   73     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I) = ',   &
                 I8,2X,2A4,2X,A4,2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
   72   CONTINUE
      ENDIF
!
      IISKIP=0
!
      DO 1200 J=JMIN,JMAX
!
        IF(IISKIP.EQ.1)THEN
          IISKIP=0
          GO TO 1200
        ENDIF
!
        IH1=IHARG(J)
        IH2=IHARG2(J)
        ICASTO='OFF'
!
        IF(IH1.EQ.'TO  ')THEN
          ICASTO='ON'
          JM1=J-1
          JP1=J+1
          CALL DPEXTL(IHARG(JM1),IHARG2(JM1),IHARG(JP1),IHARG2(JP1),   &
                      KNUMB,IVAL1,IVAL2,IBUGA2,ISUBRO,IERROR)
!
          IF(IVAL1.EQ.IVAL2)THEN
            IISKIP=1
            GO TO 1200
          ENDIF
!
          IVA1P1=IVAL1+1
          IVA2M1=IVAL2-1
          IF(IVA1P1.GT.IVA2M1)GO TO 1200
          IVAL=IVAL1
          IVAL=IVAL+1
          IF(IVAL.GE.IVAL2)GO TO 1200
          CALL DPAPNU(IHARG(JM1),IHARG2(JM1),KNUMB,IVAL,   &
                      IH1,IH2,IBUGA2,ISUBRO,IERROR)
        ENDIF
!
 1215   CONTINUE
!
        DO 1300 I=1,NUMNAM
          I2=I
          IF(IH1.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I))THEN
            IF(IUSE(I).EQ.'V')GO TO 1320
            IF(IUSE(I).EQ.'P')GO TO 1320
            IF(IUSE(I).EQ.'M')GO TO 1320
            IF(IUSE(I).EQ.'F')GO TO 1310
          ENDIF
 1300   CONTINUE
        GO TO 1320
!
 1310   CONTINUE
        NUMSTR=NUMSTR+1
        IF(NUMSTR.GT.MAXIND)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('***** ERROR IN EXTSTR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1332)
 1332     FORMAT('      THE NUMBER OF STRINGS PERMITTED HAS JUST')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1334)MAXIND
 1334     FORMAT('      EXCEEDED THE ALLOWABLE MAXIMUM (',I8,')')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1336)IH1,IH2
 1336     FORMAT('      THE STRING IN QUESTION WAS ',2A4,'   .')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ISTRN1(NUMSTR)=IH1
        ISTRN2(NUMSTR)=IH2
        GO TO 1280
!
 1320   CONTINUE
        IF(IWRITE.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('***** ERROR IN EXTSTR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1312)
 1312     FORMAT('      A NAME IN THE LIST OF STRINGS INCLUDED THE ',   &
                 'NAME OF A')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1315)
 1315     FORMAT('      NON-EXISTENT STRING OR A NON-STRING.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1316)IH1,IH2
 1316     FORMAT('      THE NAME IN QUESTION WAS ',2A4,'   .')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
!
 1280   CONTINUE
        IF(ICASTO.EQ.'ON')THEN
          IVAL=IVAL+1
          IF(IVAL.GE.IVAL2)GO TO 1200
          CALL DPAPNU(IHARG(JM1),IHARG2(JM1),KNUMB,IVAL,   &
                      IH1,IH2,IBUGA2,ISUBRO,IERROR)
          GO TO 1215
        ENDIF
!
 1200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TSTR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EXTSTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,ISTACS,ISTARA,ISTANM
 9013   FORMAT('IERROR,ISTACS,ISTARA,ISTANM = ',3(A4,2X),A60)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)JMIN,JMAX,NUMSTR,ISTANR
 9014   FORMAT('JMIN,JMAX,NUMSTR,ISTANR = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 9042 I=1,NUMSTR
          WRITE(ICOUT,9043)I,ISTRN1(I),ISTRN2(I)
 9043     FORMAT('I,ISTRN1(I),ISTRN2(I) = ',I8,2(2X,A4))
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE EXTSTR
      SUBROUTINE EXTVAR(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXIND,   &
      IHNAME,IHNAM2,IUSE,NUMNAM,   &
      IVARN1,IVARN2,NUMIND,IBUGA2,ISUBRO,IERROR)
!
!     PURPOSE--EXAMINE IHARG(.) AND IHARG2(.) FROM JMIN TO JMAX,
!              EXTRACT ALL NAMES
!              (INCLUDING THOSE IMPLIED BY A   TO   KEYWORD)
!              AND PLACE THESE NAMES IN IVARN1(.) AND IVARN2(.).
!              NOTE THE NUMBER OF SUCH NAMES AND PLACE IT IN NUMIND.
!              NUMIND STANDS FOR NUMBER OF INDEPENDENT VARIABLES
!              (NOT INCLUDING THE IMPLICIT UNITY VARIABLE).
!     NOTE--JMIN   = START POINT IN IHARG/IHARG2 FOR THE SCAN
!           JMAX   = STOP POINT  IN IHARG/IHARG2 FOR THE SCAN
!           MAXIND = MAXIMUM PERMITTED NUMBER OF VARIABLES
!     NOTE--THIS SUBROUTINE IS USED IN CONJUNCTION
!           WITH THE MULTI-LINEAR OPTION OF THE FIT COMMAND;
!           IT IS CALLED BY DPFIT.
!     NOTE--THIS SUBROUTINE ALSO CHECKS TO MAKE SURE THE
!           LIST ITEMS ARE IN FACT VARIABLES (AS OPPOSED
!           TO PARAMETERS, FUNCTIONS, MATRICES, OR
!           UNKNOWNS).
!     OUTPUT--IVARN1(.), IVARN2(.), AND NUMIND.
!     EXAMPLE--FIT Y X1 X2 X3
!              WOULD YIELD NUMIND = 3
!     EXAMPLE--FIT Y X1 TO X15
!              WOULD YIELD NUMIND = 15
!     EXAMPLE--FIT Y R1 R2 X5 TO X11 Z1 Z2
!              WOULD YIELD NUMIND = 11
!     ORIGINAL VERSION--JUNE      1989.
!     UPDATED         --JULY      1989. FIX FORMAT STATEMENT
!     UPDATED         --JULY      2009. ALLOW "Y1 TO Y1" (USEFUL FOR
!                                       MACROS WHERE NUMBER OF VARIABLES
!                                       NOT KNOWN IN ADVANCE)
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IVARN1(*)
      DIMENSION IVARN2(*)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IVARN1
      CHARACTER*4 IVARN2
      CHARACTER*4 IBUGA2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH1
      CHARACTER*4 IH2
      CHARACTER*4 ICASTO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NUMIND=0
      JM1=0
!
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'TVAR')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF EXTVAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IBUGA2,ISUBRO
   53 FORMAT('IBUGA2,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)JMIN,JMAX,MAXIND,NUMIND
   54 FORMAT('JMIN,JMAX,MAXIND,NUMIND = ',4I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)NUMARG
   61 FORMAT('NUMARG = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 62 I=1,NUMARG
      WRITE(ICOUT,63)I,IHARG(I),IHARG2(I)
   63 FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   62 CONTINUE
      WRITE(ICOUT,71)NUMNAM
   71 FORMAT('NUMNAM = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 72 I=1,NUMNAM
      WRITE(ICOUT,73)I,IHNAME(I),IHNAM2(I),IUSE(I)
   73 FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I) = ',   &
      I8,2X,A4,A4,2X,A4,I8,I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   72 CONTINUE
   90 CONTINUE
!
      IISKIP=0
!
      DO 1200 J=JMIN,JMAX
!
      IF(IISKIP.EQ.1)THEN
        IISKIP=0
        GO TO 1200
      ENDIF
!
      IH1=IHARG(J)
      IH2=IHARG2(J)
      ICASTO='OFF'
!
      IF (IH1.EQ.'TO  ')GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      ICASTO='ON'
      JM1=J-1
      JP1=J+1
      CALL DPEXTL(IHARG(JM1),IHARG2(JM1),IHARG(JP1),IHARG2(JP1),   &
      KNUMB,IVAL1,IVAL2,IBUGA2,ISUBRO,IERROR)
!
      IF(IVAL1.EQ.IVAL2)THEN
        IISKIP=1
        GO TO 1200
      ENDIF
!
      IVA1P1=IVAL1+1
      IVA2M1=IVAL2-1
      IF(IVA1P1.GT.IVA2M1)GO TO 1200
      IVAL=IVAL1
!
 1215 CONTINUE
      IVAL=IVAL+1
      IF(IVAL.GE.IVAL2)GO TO 1200
!
      CALL DPAPNU(IHARG(JM1),IHARG2(JM1),KNUMB,IVAL,   &
      IH1,IH2,IBUGA2,ISUBRO,IERROR)
      GO TO 1220
!
 1220 CONTINUE
      DO 1300 I=1,NUMNAM
      I2=I
      IF(IH1.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I))GO TO 1305
      GO TO 1300
 1305 CONTINUE
      IF(IUSE(I).EQ.'V')GO TO 1310
      IF(IUSE(I).EQ.'P')GO TO 1320
      IF(IUSE(I).EQ.'M')GO TO 1320
      IF(IUSE(I).EQ.'F')GO TO 1320
 1300 CONTINUE
      GO TO 1320
!
 1310 CONTINUE
      NUMIND=NUMIND+1
      IF(NUMIND.GT.MAXIND)GO TO 1330
      IVARN1(NUMIND)=IH1
      IVARN2(NUMIND)=IH2
      GO TO 1280
!
 1320 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
 1311 FORMAT('***** ERROR IN EXTVAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1312)
 1312 FORMAT('      A NAME IN THE LIST ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1313)
 1313 FORMAT('      OF VARIABLES TO BE FIT ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1314)
 1314 FORMAT('      INCLUDED THE NAME OF A ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1315)
 1315 FORMAT('      NON-EXISTENT VARIABLE OR A NON-VARIABLE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1316)IH1,IH2
 1316 FORMAT('      THE NAME IN QUESTION WAS ',   &
      2A4,'   .')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1317)
 1317 FORMAT('      NO FIT WAS CARRIED OUT.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1330 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1331)
 1331 FORMAT('***** ERROR IN EXTVAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1332)
 1332 FORMAT('      THE NUMBER OF VARIABLES PERMITTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1333)
 1333 FORMAT('      IN A MULTI-LINEAR FIT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1334)
 1334 FORMAT('      HAS JUST EXCEEDED THE ALLOWABLE MAXIMUM')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1335)MAXIND
 1335 FORMAT('       (',I8,')')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1336)IH1,IH2
 1336 FORMAT('      THE VARIBLE IN QUESTION WAS ',   &
      2A4,'   .')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1337)
 1337 FORMAT('      NO FIT WAS CARRIED OUT.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1280 CONTINUE
      IF(ICASTO.EQ.'ON')GO TO 1215
!
 1200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'OFF'.AND.ISUBRO.NE.'TVAR')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF EXTVAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IBUGA2,ISUBRO
 9013 FORMAT('IBUGA2,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)JMIN,JMAX,NUMIND
 9014 FORMAT('JMIN,JMAX,NUMIND = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)NUMARG
 9021 FORMAT('NUMARG = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,NUMARG
      WRITE(ICOUT,9023)I,IHARG(I),IHARG2(I)
 9023 FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
      WRITE(ICOUT,9031)NUMNAM
 9031 FORMAT('NUMNAM = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9032 I=1,NUMNAM
      WRITE(ICOUT,9033)I,IHNAME(I),IHNAM2(I),IUSE(I)
!CCCC THE FOLLOWING FORMAT STATEMENT WAS FIXED JULY 1989
      CALL DPWRST('XXX','BUG ')
!9033 FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I) = ',
!CCCC1I8,2X,A4,A4,2X,A4,I8,I8,E1901.7)
 9033 FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I) = ',   &
      I8,2X,A4,A4,2X,A4,I8,I8,E15.7)
 9032 CONTINUE
      WRITE(ICOUT,9041)NUMIND
 9041 FORMAT('NUMIND = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9042 I=1,NUMIND
      WRITE(ICOUT,9043)I,IVARN1(I),IVARN2(I)
 9043 FORMAT('I,IVARN1(I),IVARN2(I) = ',I8,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9042 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE EXTVAR
      SUBROUTINE EXTVA2(IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,MAXIND,   &
                        IHNAME,IHNAM2,IUSE,NUMNAM,   &
                        IVARN1,IVARN2,IVARTY,PVAR,NUMIND,   &
                        IFLAGM,IFLAGP,IFLAGT,   &
                        IBUGA2,ISUBRO,IERROR)
!
!     PURPOSE--EXAMINE IHARG(.) AND IHARG2(.) FROM JMIN TO JMAX, EXTRACT
!              ALL NAMES (INCLUDING THOSE IMPLIED BY A   TO   KEYWORD)
!              AND PLACE THESE NAMES IN IVARN1(.) AND IVARN2(.).
!              NOTE THE NUMBER OF SUCH NAMES AND PLACE IT IN NUMIND.
!              NUMIND STANDS FOR NUMBER OF INDEPENDENT VARIABLES
!              (NOT INCLUDING THE IMPLICIT UNITY VARIABLE).
!              THIS ROUTINE IS SIMILAR TO "EXTVAR".  HOWEVER, IT
!              ALSO ALLOWS PARAMETER NAMES, NUMERIC VALUES, AND
!              MATRIX NAMES TO BE EXTRACTED.  THE ARRAY "IVARTY"
!              WILL BE CREATED TO STORE THE NAME TYPE AND PVAR
!              WILL CONTAIN THE VALUE OF ANY NUMERIC VALUES ENTERED.
!              THIS WILL MAKE THE "DPPARS" ROUTINE MORE GENERAL IN
!              THAT IT CAN HANDLE COMMANDS THAT ALLOW MATRICES AND
!              PARAMETER/SCALAR TO BE USED AS ARGUMENTS.
!     NOTE--JMIN   = START POINT IN IHARG/IHARG2 FOR THE SCAN
!           JMAX   = STOP POINT  IN IHARG/IHARG2 FOR THE SCAN
!           MAXIND = MAXIMUM PERMITTED NUMBER OF VARIABLES
!     OUTPUT--IVARN1(.), IVARN2(.), IVARTY(.), PVAR(.) AND NUMIND.
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IHARG2(*)
      CHARACTER*4 IARGT(*)
      CHARACTER*4 IHNAME(*)
      CHARACTER*4 IHNAM2(*)
      CHARACTER*4 IUSE(*)
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
      CHARACTER*4 IVARTY(*)
      REAL        ARG(*)
      REAL        PVAR(*)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH1
      CHARACTER*4 IH2
      CHARACTER*4 IHT
      CHARACTER*4 ICASTO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NUMIND=0
      JM1=0
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TVA2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXTVA2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,ISUBRO,IFLAGM,IFLAGP,IFLAGT
   53   FORMAT('IBUGA2,ISUBRO,IFLAGM,IFLAGP,IFLAGT = ',2(A4,2X),3I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)JMIN,JMAX,MAXIND,NUMIND,NUMARG
   54   FORMAT('JMIN,JMAX,MAXIND,NUMIND,NUMARG = ',5I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GE.1)THEN
          DO 62 I=1,NUMARG
            WRITE(ICOUT,63)I,IHARG(I),IHARG2(I),IARGT(I),ARG(I)
   63       FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),ARG(I) = ',   &
                   I8,2X,3(A4,2X),G15.7)
            CALL DPWRST('XXX','BUG ')
   62     CONTINUE
        ENDIF
        WRITE(ICOUT,71)NUMNAM
   71   FORMAT('NUMNAM = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 72 I=1,NUMNAM
          WRITE(ICOUT,73)I,IHNAME(I),IHNAM2(I),IUSE(I)
   73     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I) = ',   &
                 I8,2X,A4,A4,2X,A4,I8,I8,E15.7)
          CALL DPWRST('XXX','BUG ')
   72   CONTINUE
      ENDIF
!
      IISKIP=0
!
      DO 1200 J=JMIN,JMAX
!
!       CHECK FIRST TO SEE IF THE ARGUMENT IS ACTUALLY
!       A "NUMBER" (AS OPPOSSED TO A VARIABLE OR PARAMETER
!       NAME).
!
!       2010/12: MOVE THIS BELOW.
!
!CCCC   IF(IARGT(J).EQ.'NUMB')THEN
!CCCC     NUMIND=NUMIND+1
!CCCC     IF(NUMIND.GT.MAXIND)GO TO 1330
!CCCC     IVARN1(NUMIND)='    '
!CCCC     IVARN2(NUMIND)='    '
!CCCC     IVARTY(NUMIND)='NUMB'
!CCCC     PVAR(NUMIND)=ARG(J)
!CCCC     GO TO 1200
!CCCC   ENDIF
!
        IF(IISKIP.EQ.1)THEN
          IISKIP=0
          GO TO 1200
        ENDIF
!
        IH1=IHARG(J)
        IH2=IHARG2(J)
        ICASTO='OFF'
!
        IF(IH1.EQ.'TO  ')GO TO 1210
        GO TO 1220
!
 1210   CONTINUE
          ICASTO='ON'
          JM1=J-1
          JP1=J+1
          CALL DPEXTL(IHARG(JM1),IHARG2(JM1),IHARG(JP1),IHARG2(JP1),   &
                      KNUMB,IVAL1,IVAL2,IBUGA2,ISUBRO,IERROR)
!
          IF(IVAL1.EQ.IVAL2)THEN
            IISKIP=1
            GO TO 1200
          ENDIF
!
          IVA1P1=IVAL1+1
          IVA2M1=IVAL2-1
          IF(IVA1P1.GT.IVA2M1)GO TO 1200
          IVAL=IVAL1
!
 1215     CONTINUE
          IVAL=IVAL+1
          IF(IVAL.GE.IVAL2)GO TO 1200
!
          CALL DPAPNU(IHARG(JM1),IHARG2(JM1),KNUMB,IVAL,   &
                      IH1,IH2,IBUGA2,ISUBRO,IERROR)
          GO TO 1220
!
 1220   CONTINUE
        IHT='NONE'
        DO 1300 I=1,NUMNAM
          I2=I
          IF(IH1.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I))THEN
            IHT=IUSE(I)
            IF(IUSE(I).EQ.'V')THEN
              NUMIND=NUMIND+1
              IF(NUMIND.GT.MAXIND)GO TO 1330
              IVARN1(NUMIND)=IH1
              IVARN2(NUMIND)=IH2
              IVARTY(NUMIND)='VARI'
              PVAR(NUMIND)=CPUMIN
              IF(ICASTO.EQ.'ON')GO TO 1215
              GO TO 1200
            ELSEIF(IUSE(I).EQ.'P')THEN
              IF(IFLAGP.EQ.0)GO TO 1320
              NUMIND=NUMIND+1
              IF(NUMIND.GT.MAXIND)GO TO 1330
              IVARN1(NUMIND)=IH1
              IVARN2(NUMIND)=IH2
              IVARTY(NUMIND)='PARA'
              PVAR(NUMIND)=CPUMIN
              IF(ICASTO.EQ.'ON')GO TO 1215
              GO TO 1200
            ELSEIF(IUSE(I).EQ.'M')THEN
              IF(IFLAGM.EQ.0)GO TO 1320
              NUMIND=NUMIND+1
              IF(NUMIND.GT.MAXIND)GO TO 1330
              IVARN1(NUMIND)=IH1
              IVARN2(NUMIND)=IH2
              IVARTY(NUMIND)='MATR'
              PVAR(NUMIND)=CPUMIN
              IF(ICASTO.EQ.'ON')GO TO 1215
              GO TO 1200
            ELSEIF(IUSE(I).EQ.'F')THEN
              IF(IFLAGT.EQ.0)GO TO 1320
              NUMIND=NUMIND+1
              IF(NUMIND.GT.MAXIND)GO TO 1330
              IVARN1(NUMIND)=IH1
              IVARN2(NUMIND)=IH2
              IVARTY(NUMIND)='F   '
              PVAR(NUMIND)=CPUMIN
              IF(ICASTO.EQ.'ON')GO TO 1215
              GO TO 1200
            ENDIF
          ENDIF
 1300   CONTINUE
!
!       2010/12: IF NO NAME FOUND, CHECK IF IT IS A LITERAL
!                NUMBER.
!
        IF(IARGT(J).EQ.'NUMB')THEN
          NUMIND=NUMIND+1
          IF(NUMIND.GT.MAXIND)GO TO 1330
          IVARN1(NUMIND)='    '
          IVARN2(NUMIND)='    '
          IVARTY(NUMIND)='NUMB'
          PVAR(NUMIND)=ARG(J)
          GO TO 1200
        ENDIF
!
        IF(IFLAGT.EQ.1)THEN
          NUMIND=NUMIND+1
          IF(NUMIND.GT.MAXIND)GO TO 1330
          IVARN1(NUMIND)=IH1
          IVARN2(NUMIND)=IH2
          IVARTY(NUMIND)='UNKN'
          PVAR(NUMIND)=CPUMIN
          IF(ICASTO.EQ.'ON')GO TO 1215
          GO TO 1200
        ENDIF
!
 1320   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1311)
 1311   FORMAT('***** ERROR IN EXTVA2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1312)
 1312   FORMAT('      A NAME IN THE LIST OF EXTRACTED NAMES INCLUDED A')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1315)
 1315   FORMAT('      NON-EXISTENT NAME OR A NAME OF THE WRONG TYPE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1316)IH1,IH2,IHT
 1316   FORMAT('      THE NAME IN QUESTION WAS ',A4,A4,' AND IS OF ',   &
               'TYPE ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
!
 1330   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1332)
 1332   FORMAT('      THE NUMBER OF VARIABLES EXTRACTED FROM THIS ',   &
               'COMMAND HAS JUST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1334)MAXIND
 1334   FORMAT('      EXCEEDED THE ALLOWABLE MAXIMUM (',I8,')')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1316)IH1,IH2,IHT
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
!
 1200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TVA2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EXTVA2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IBUGA2,ISUBRO
 9013   FORMAT('IBUGA2,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)JMIN,JMAX,NUMIND,NUMARG
 9014   FORMAT('JMIN,JMAX,NUMIND,NUMARG = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9041)NUMIND
 9041   FORMAT('NUMIND = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMIND.GE.1)THEN
          DO 9042 I=1,NUMIND
            WRITE(ICOUT,9043)I,IVARN1(I),IVARN2(I),IVARTY(I),PVAR(I)
 9043       FORMAT('I,IVARN1(I),IVARN2(I),IVARTY(I),PVAR(I) = ',   &
                   I8,2X,A4,2X,A4,2X,A4,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9042     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE EXTVA2
      SUBROUTINE EXTVA3(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXIND,   &
                        IHNAME,IHNAM2,NUMNAM,   &
                        IVARN1,IVARN2,NUMIND,   &
                        IBUGA2,ISUBRO,IERROR)
!
!     PURPOSE--EXAMINE IHARG(.) AND IHARG2(.) FROM JMIN TO JMAX, EXTRACT
!              ALL NAMES (INCLUDING THOSE IMPLIED BY A   TO   KEYWORD)
!              AND PLACE THESE NAMES IN IVARN1(.) AND IVARN2(.).
!              NOTE THE NUMBER OF SUCH NAMES AND PLACE IT IN NUMIND.
!              NUMIND STANDS FOR NUMBER OF INDEPENDENT VARIABLES
!              (NOT INCLUDING THE IMPLICIT UNITY VARIABLE).
!              THIS ROUTINE IS SIMILAR TO "EXTVAR" AND "EXTVA2".  HOWEVER,
!              THIS ROUTINE SIMPLY RETURNS THE LIST OF NAMES WITHOUT ANY
!              ERROR PROCESSING (I.E., DO NOT CHECK FOR EXISTENCE OR
!              TYPE).
!     NOTE--JMIN   = START POINT IN IHARG/IHARG2 FOR THE SCAN
!           JMAX   = STOP POINT  IN IHARG/IHARG2 FOR THE SCAN
!           MAXIND = MAXIMUM PERMITTED NUMBER OF VARIABLES
!     OUTPUT--IVARN1(.), IVARN2(.), AND NUMIND.
!     ORIGINAL VERSION--SEPTEMBER 2009.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IHARG2(*)
      CHARACTER*4 IHNAME(*)
      CHARACTER*4 IHNAM2(*)
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH1
      CHARACTER*4 IH2
      CHARACTER*4 ICASTO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NUMIND=0
      JM1=0
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TVA3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF EXTVA3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,ISUBRO,JMIN,JMAX,NUMARG,NUMNAM,MAXIND
   53   FORMAT('IBUGA2,ISUBRO,JMIN,JMAX,NUMARG,NUMNAM,MAXIND = ',   &
               2(A4,2X),5I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GE.1)THEN
          DO 62 I=1,NUMARG
            WRITE(ICOUT,63)I,IHARG(I),IHARG2(I)
   63       FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2(2X,A4))
            CALL DPWRST('XXX','BUG ')
   62     CONTINUE
        ENDIF
        DO 72 I=1,NUMNAM
          WRITE(ICOUT,73)I,IHNAME(I),IHNAM2(I)
   73     FORMAT('I,IHNAME(I),IHNAM2(I) = ',I8,2(A4,2X))
          CALL DPWRST('XXX','BUG ')
   72   CONTINUE
      ENDIF
!
      IISKIP=0
!
      DO 1200 J=JMIN,JMAX
!
        IF(IISKIP.EQ.1)THEN
          IISKIP=0
          GO TO 1200
        ENDIF
!
        IH1=IHARG(J)
        IH2=IHARG2(J)
        ICASTO='OFF'
!
        IF(IH1.NE.'TO  ')GO TO 1220
!
          ICASTO='ON'
          JM1=J-1
          JP1=J+1
          CALL DPEXTL(IHARG(JM1),IHARG2(JM1),IHARG(JP1),IHARG2(JP1),   &
                      KNUMB,IVAL1,IVAL2,IBUGA2,ISUBRO,IERROR)
!
          IF(IVAL1.EQ.IVAL2)THEN
            IISKIP=1
            GO TO 1200
          ENDIF
!
          IVA1P1=IVAL1+1
          IVA2M1=IVAL2-1
          IF(IVA1P1.GT.IVA2M1)GO TO 1200
          IVAL=IVAL1
!
 1215     CONTINUE
          IVAL=IVAL+1
          IF(IVAL.GE.IVAL2)GO TO 1200
!
          CALL DPAPNU(IHARG(JM1),IHARG2(JM1),KNUMB,IVAL,   &
                      IH1,IH2,IBUGA2,ISUBRO,IERROR)
!
 1220   CONTINUE
        NUMIND=NUMIND+1
        IVARN1(NUMIND)=IH1
        IVARN2(NUMIND)=IH2
        IF(ICASTO.EQ.'ON')GO TO 1215
!
 1200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TVA2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF EXTVA3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IBUGA2,ISUBRO
 9013   FORMAT('IBUGA2,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)JMIN,JMAX,NUMIND,NUMARG
 9014   FORMAT('JMIN,JMAX,NUMIND,NUMARG = ',4I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMIND.GE.1)THEN
          DO 9042 I=1,NUMIND
            WRITE(ICOUT,9043)I,IVARN1(I),IVARN2(I)
 9043       FORMAT('I,IVARN1(I),IVARN2(I) = ',   &
                   I8,2X,A4,2X,A4,2X,A4,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9042     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE EXTVA3
      SUBROUTINE FALNEG(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROPORTION OF
!              FALSE NEGATIVES BETEEN TWO VARIABLES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  A FALSE NEGATIVE IS DEFINED AS THE
!              ERROR WHERE THE SECOND VARIABLE IS 1 AND THE FIRST
!              VARIABLE IS A 0.
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE SPECIFIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  A FALSE NEGATIVE THEN IS THE CASE WHERE
!              THE DEVICE FAILED TO DETECT THE OBJECT WHEN IT WAS
!              ACTUALY THERE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED FALSE NEGATIVE PROPORTION
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE FALSE NEGATIVE PROPORTION BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FALN'
      ISUBN2='EG  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF FALNEG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE FALSE NEGATIVE PROPORTION')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        NTEMP=N11 + N12 + N21 + N22
        STAT=REAL(N12)/REAL(NTEMP)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSEIF(NDIST.GT.2)THEN
        N11=0
        N12=0
        N21=0
        DO 2510 I=1,N
          IF(Y(I).EQ.X(I))THEN
            N11=N11+1
          ELSEIF(Y(I).LT.X(I))THEN
            N12=N12+1
          ELSEIF(Y(I).GT.X(I))THEN
            N21=N21+1
          ENDIF
 2510   CONTINUE
        STAT=REAL(N12)/REAL(N)
        GO TO 9000
      ELSE
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1201)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2211)
!2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2213)
!2213   FORMAT('      TWO DISTINCT VALUES.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2215)NDIST
!2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
      ENDIF
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSEIF(NDIST.GT.2)THEN
        N11=0
        N12=0
        N21=0
        DO 2520 I=1,N
          IF(Y(I).EQ.X(I))THEN
            N11=N11+1
          ELSEIF(Y(I).LT.X(I))THEN
            N12=N12+1
          ELSEIF(Y(I).GT.X(I))THEN
            N21=N21+1
          ENDIF
 2520   CONTINUE
        STAT=REAL(N12)/REAL(N)
        GO TO 9000
      ELSE
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1201)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2311)
!2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2313)
!2313   FORMAT('      TWO DISTINCT VALUES.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2315)NDIST
!2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N12)/REAL(N)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE FALSE NEGATIVE PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF FALNEG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE FALNEG
      SUBROUTINE FALPOS(X,Y,N,IWRITE,XIDTEM,STAT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROPORTION OF
!              FALSE POSITIVES BETEEN TWO VARIABLES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  A FALSE POSITIVE IS DEFINED AS THE
!              ERROR WHERE THE SECOND VARIABLE IS 1 AND THE FIRST
!              VARIABLE IS A 0.
!
!              A TYPICAL EXAMPLE WOULD BE WHERE VARIABLE ONE
!              DENOTES THE GROUND TRUTH AND A VALUE OF 1
!              INDICATES "PRESENT" AND A VALUE OF 0 INDICATES
!              "NOT PRESENT".  VARIABLE TWO REPRESENTS SOME TYPE
!              OF DETECTION DEVICE WHERE A VALUE OF 1 INDICATES
!              THE DEVICE DETECTED THE SPECIFIED OBJECT WHILE A
!              VALUE OF 0 INDICATES THAT THE OBJECT WAS NOT
!              DETECTED.  A FALSE POSITIVE THEN IS THE CASE WHERE
!              THE DEVICE DETECTED THE OBJECT WHEN IT WAS NOT
!              ACTUALY THERE.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED FALSE POSITIVE PROPORTION
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE FALSE POSITIVE PROPORTION BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FALP'
      ISUBN2='OS  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF FALPOS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE FALSE POSITIVE PROPORTION')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        NTEMP=N11 + N12 + N21 + N22
        STAT=REAL(N21)/REAL(NTEMP)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          X(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(X(I).NE.1.0)X(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(X(I).EQ.ATEMP1)X(I)=0.0
            IF(X(I).EQ.ATEMP2)X(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSEIF(NDIST.GT.2)THEN
!
!       CASE WITH MORE THAN 2 DISTINCT VALUES FOR GROUND
!       TRUTH VARIABLE.  IN THIS CASE, JUST CHECK IF
!
!          X(I) = Y(I)
!          X(I) < Y(I)
!          X(I) > Y(I)
!
        N11=0
        N12=0
        N21=0
        DO 2510 I=1,N
          IF(Y(I).EQ.X(I))THEN
            N11=N11+1
          ELSEIF(Y(I).LT.X(I))THEN
            N12=N12+1
          ELSEIF(Y(I).GT.X(I))THEN
            N21=N21+1
          ENDIF
 2510   CONTINUE
        STAT=REAL(N21)/REAL(N)
        GO TO 9000
      ELSE
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1201)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2211)
!2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2213)
!2213   FORMAT('      TWO DISTINCT VALUES.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2215)NDIST
!2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
      ENDIF
!
      CALL DISTIN(Y,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y(I).NE.1.0)Y(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y(I).EQ.ATEMP1)Y(I)=0.0
            IF(Y(I).EQ.ATEMP2)Y(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSEIF(NDIST.GT.2)THEN
        N11=0
        N12=0
        N21=0
        DO 2520 I=1,N
          IF(Y(I).EQ.X(I))THEN
            N11=N11+1
          ELSEIF(Y(I).LT.X(I))THEN
            N12=N12+1
          ELSEIF(Y(I).GT.X(I))THEN
            N21=N21+1
          ENDIF
 2520   CONTINUE
        STAT=REAL(N21)/REAL(N)
        GO TO 9000
      ELSE
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1201)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2311)
!2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2313)
!2313   FORMAT('      TWO DISTINCT VALUES.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2315)NDIST
!2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
      ENDIF
!
      N11=0
      N12=0
      N21=0
      N22=0
      DO 2410 I=1,N
        IF(X(I).EQ.1.0 .AND. Y(I).EQ.1.0)THEN
          N11=N11+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.0.0)THEN
          N22=N22+1
        ELSEIF(X(I).EQ.1.0 .AND. Y(I).EQ.0.0)THEN
          N12=N12+1
        ELSEIF(X(I).EQ.0.0 .AND. Y(I).EQ.1.0)THEN
          N21=N21+1
        ENDIF
 2410 CONTINUE
!
      STAT=REAL(N21)/REAL(N)
!
 3000 CONTINUE
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE FALSE POSITIVE PROPORTION = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF FALPOS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE FALPOS
      SUBROUTINE FCACDF(X,U,SD,CDF)
!
!     NOTE--FOLDED-CAUCHY PDF IS:
!              FCAPDF(X,U,S)=(1/S)*(CAUPDF((X-U)/S)+CAUPDF((X+U)/S)))
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY   1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO THE FCACDF SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
  201 FORMAT('***** FATAL DIAGNOSTIC--THE THIRD  INPUT ARGUMENT ',   &
      ' TO THE FCACDF SUBROUTINE IS NEGATIVE *****')
!
      TERM1=(X-U)/SD
      CALL CAUCDF(TERM1,TERM2)
      TERM3=(-X-U)/SD
      CALL CAUCDF(TERM3,TERM4)
      CDF=TERM2-TERM4
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FCACDF
      SUBROUTINE FCAPDF(X,U,SD,PDF)
!
!     NOTE--FOLDED-CAUCHY PDF IS:
!              FCAPDF(X,U,S)=(1/S)*(CAUPDF((X-U)/S) + CAUPDF((X+U)/S)))
!           WHERE CAUPDF IS THE PDF OF THE STANDARD CAUCHY DISTRIBUTION
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY   1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO THE FCAPDF SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
  201 FORMAT('***** FATAL DIAGNOSTIC--THE THIRD  INPUT ARGUMENT ',   &
      'TO THE FCAPDF SUBROUTINE IS NON-POSITIVE *****')
!
      TERM1=(X-U)/SD
      CALL CAUPDF(TERM1,TERM2)
      TERM2=TERM2/SD
      TERM3=(X+U)/SD
      CALL CAUPDF(TERM3,TERM4)
      TERM4=TERM4/SD
      PDF=TERM2+TERM4
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FCAPDF
      SUBROUTINE FCAPPF(P,U,SD,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE FOLDED CAUCHY
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--96/1
!     ORIGINAL VERSION--JANUARY 1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DU
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
!CCCC DOUBLE PRECISION DPI
      DOUBLE PRECISION DSDF
!CCCC DOUBLE PRECISION DTERM1, DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA DPI /3.14159265358979D0/
      DATA EPSZ /0.0001/
      DATA SIGZ /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /30000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FCAPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FCAPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!  IF P IS 0, PPF IS ZERO.  HANDLE THIS TRIVIAL CASE.
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
      EPS=EPSZ
      SIG=SIGZ
      DU=DBLE(U)
      DSD=DBLE(SD)
!CCCC DTERM1=DEXP(-DU**2/(2.0D0*DSD**2))
!CCCC DTERM2=DSQRT(2.D0/DPI)
!CCCC TERM3=-U/SD
!CCCC CALL CAUCDF(TERM3,TERM4)
!CCCC DMEAN=DTERM2*DSD*DTERM1 + DU*(1.D0-2.D0*DBLE(TERM4))
!CCCC DSDF=DMEAN**2 + DU*DU + DSD*DSD
      DMEAN=DU
      DSDF=DSD**2
!
      XL=SNGL(DMEAN)
      XINC=SNGL(DSDF)
      IF(XINC.LT.1.0)XINC=1.0
      ICOUNT=0
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0)XL=0.0
      IF(XR.LE.0.0)XR=XL+XINC
      CALL FCACDF(XL,U,SD,CDFL)
      CALL FCACDF(XR,U,SD,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXIT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--FCAPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IF(XR.GT.10000.0)THEN
        EPS=0.001
        SIG=5.0E-2
      ELSEIF(XR.GT.1000.0)THEN
        EPS=0.001
        SIG=5.0E-3
      ELSEIF(XR.GT.500.0)THEN
        EPS=0.0001
        SIG=5.0E-4
      ELSEIF(XR.GT.100.0)THEN
        EPS=0.0001
        SIG=1.0E-4
      ENDIF
!
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL FCACDF(X,U,SD,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** WARNING--FCAPPF ROUTINE DID NOT CONVERGE.')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FCAPPF
      SUBROUTINE FCARAN(N,ALOC,ASCALE,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE FOLDED CAUCHY DISTRIBUTION.  THE FOLDED CAUCHY
!              IS THE ABSOLUTE VALUE OF A CAUCHY DISTRIBUTION.
!              GENERATE FOLDED CAUCHY RANDOM NUMBERS BY FINDING CAUCHY
!              RANDOM NUMBERS AND THEN TAKING ABSOLUTE VALUE.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALOC   = LOCATION PARAMETER OF PARENT CAUCHY
!                                DISTRIBUTION.
!                     --ASCALE = SCALE PARAMETER OF PARENT CAUCHY
!                                DISTRIBUTION.
!                     --ISEED  = SEED FOR UNIFORM RANDOM NUMBER GENERATOR
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FUNCTION VALUE FOR THE FOLDED CAUCHY DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGE 15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGE 231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003/7
!     ORIGINAL VERSION--JULY      2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF FOLDED CAUCHY ',   &
      'RANDON NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      IF(ASCALE.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)ASCALE
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   15 FORMAT('***** FATAL ERROR--THE SCALE PARAMETER FOR THE FOLDED ',   &
      'CAUCHY RANDON NUMBERS IS NON-POSITIVE.')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.7)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N CAUCHY RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!     THEN APPLY LOCATION AND SCALE TRANSFORMATION AND TAKE ABSOLUTE VALUE.
!
      DO 100 I=1,N
        ARG=PI*X(I)
        X(I)=-COS(ARG)/SIN(ARG)
        X(I)=ABS(ALOC + ASCALE*X(I))
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FCARAN
      SUBROUTINE FCDF(X,NU1,NU2,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE F DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM
!              PARAMETERS = NU1 AND NU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU1    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                                NU1 SHOULD BE POSITIVE.
!                     --NU2    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!                                NU2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE F DISTRIBUTION
!             WITH DEGREES OF FREEDOM
!             PARAMETERS = NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU1 SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --NU2 SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF,CHSCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGES 946-947,
!                 FORMULAE 26.6.4, 26.6.5, 26.6.8, AND 26.6.15.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGE 83, FORMULA 20,
!                 AND PAGE 84, THIRD FORMULA.
!               --PAULSON, AN APPROXIMATE NORMAILIZATION
!                 OF THE ANALYSIS OF VARIANCE DISTRIBUTION,
!                 ANNALS OF MATHEMATICAL STATISTICS, 1942,
!                 NUMBER 13, PAGES 233-135.
!               --SCHEFFE AND TUKEY, A FORMULA FOR SAMPLE SIZES
!                 FOR POPULATION TOLERANCE LIMITS, 1944,
!                 NUMBER 15, PAGE 217.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--AUGUST    1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2021. SET PRINT TYPE TO "ERRO" (USER
!                                       CAN SUPPRESS ERROR MESSAGE IF
!                                       "SET ERROR MESSAGE OFF" ENTERED.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,PI,ANU1,ANU2,Z,SUM,TERM,AI,COEF1,COEF2,ARG
      DOUBLE PRECISION COEF
      DOUBLE PRECISION THETA,SINTH,COSTH,A,B
      DOUBLE PRECISION DSQRT,DATAN
      DOUBLE PRECISION DFACT1,DFACT2,DNUM,DDEN
      DOUBLE PRECISION DPOW1,DPOW2
      DOUBLE PRECISION DNU1,DNU2
      DOUBLE PRECISION TERM1,TERM2,TERM3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265358979D0/
!CCCC DATA DPOW1,DPOW2/0.33333333333333D0,0.66666666666667D0/
!     THE FOLLOWING WAS COMMENTED OUT AND CHANGED
!     IN AUGUST OF 1986 DUE TO BOMB ON VAX
!     FOR FCDF(2,400,100)    .
!     CHANGING NUCUT2 FROM 1000 TO 250 WAS SUFFICIENT
!     TO SOLVE THE PROBLEM.
!CCCC DATA NUCUT1,NUCUT2/100,1000/
      DATA NUCUT1,NUCUT2/100,250/
!
!-----START POINT-----------------------------------------------------
!
      B=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(NU1.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,47)NU1
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','ERRO')
        RETURN
      ELSEIF(NU2.LE.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,47)NU2
        CALL DPWRST('XXX','ERRO')
        RETURN
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO FCDF IS NEGATIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.7,'.')
        CALL DPWRST('XXX','ERRO')
        RETURN
      ENDIF
!
      DX=X
      M=NU1
      N=NU2
      ANU1=NU1
      ANU2=NU2
      DNU1=NU1
      DNU2=NU2
!
!     IF X IS NON-POSITIVE, SET CDF = 0.0 AND RETURN.
!     IF NU2 IS 5 THROUGH 9 AND X IS MORE THAN 3000
!     STANDARD DEVIATIONS BELOW THE MEAN,
!     SET CDF = 0.0 AND RETURN.
!     IF NU2 IS 10 OR LARGER AND X IS MORE THAN 150
!     STANDARD DEVIATIONS BELOW THE MEAN,
!     SET CDF = 0.0 AND RETURN.
!     IF NU2 IS 5 THROUGH 9 AND X IS MORE THAN 3000
!     STANDARD DEVIATIONS ABOVE THE MEAN,
!     SET CDF = 1.0 AND RETURN.
!     IF NU2 IS 10 OR LARGER AND X IS MORE THAN 150
!     STANDARD DEVIATIONS ABOVE THE MEAN,
!     SET CDF = 1.0 AND RETURN.
!
      IF(X.LE.0.0)GO TO 105
      IF(NU2.LE.4)GO TO 109
      T1=2.0/ANU1
      T2=ANU2/(ANU2-2.0)
      T3=(ANU1+ANU2-2.0)/(ANU2-4.0)
      AMEAN=T2
      SD=SQRT(T1*T2*T2*T3)
      ZRATIO=(X-AMEAN)/SD
      IF(NU2.LT.10.AND.ZRATIO.LT.-3000.0)GO TO 105
      IF(NU2.GE.10.AND.ZRATIO.LT.-150.0)GO TO 105
      IF(NU2.LT.10.AND.ZRATIO.GT.3000.0)GO TO 107
      IF(NU2.GE.10.AND.ZRATIO.GT.150.0)GO TO 107
      GO TO 109
  105 CDF=0.0
      RETURN
  107 CDF=1.0
      RETURN
  109 CONTINUE
!
!     DISTINGUISH BETWEEN 6 SEPARATE REGIONS
!     OF THE (NU1,NU2) SPACE.
!     BRANCH TO THE PROPER COMPUTATIONAL METHOD
!     DEPENDING ON THE REGION.
!     NUCUT1 HAS THE VALUE 100.
!     NUCUT2 HAS THE VALUE 1000.
!
      IF(NU1.LT.NUCUT2.AND.NU2.LT.NUCUT2)GO TO 1000
      IF(NU1.GE.NUCUT2.AND.NU2.GE.NUCUT2)GO TO 2000
      IF(NU1.LT.NUCUT1.AND.NU2.GE.NUCUT2)GO TO 3000
      IF(NU1.GE.NUCUT1.AND.NU2.GE.NUCUT2)GO TO 2000
      IF(NU1.GE.NUCUT2.AND.NU2.LT.NUCUT1)GO TO 5000
      IF(NU1.GE.NUCUT2.AND.NU2.GE.NUCUT1)GO TO 2000
      IBRAN=5
      WRITE(ICOUT,99)IBRAN
   99 FORMAT('*****INTERNAL ERROR IN   FCDF SUBROUTINE--',   &
      'IMPOSSIBLE BRANCH CONDITION AT BRANCH POINT = ',I8)
      CALL DPWRST('XXX','ERRO')
      RETURN
!
!     TREAT THE CASE WHEN NU1 AND NU2
!     ARE BOTH SMALL OR MODERATE
!     (THAT IS, BOTH ARE SMALLER THAN 1000).
!     METHOD UTILIZED--EXACT FINITE SUM
!     (SEE AMS 55, PAGE 946, FORMULAE 26.6.4, 26.6.5,
!     AND 26.6.8).
!
 1000 CONTINUE
      Z=ANU2/(ANU2+ANU1*DX)
      IFLAG1=NU1-2*(NU1/2)
      IFLAG2=NU2-2*(NU2/2)
      IF(IFLAG1.EQ.0)GO TO 120
      IF(IFLAG2.EQ.0)GO TO 150
      GO TO 250
!
!     DO THE NU1 EVEN AND NU2 EVEN OR ODD CASE
!
  120 SUM=0.0D0
      TERM=1.0D0
      IMAX=(M-2)/2
      IF(IMAX.LE.0)GO TO 110
      DO 100 I=1,IMAX
      AI=I
      COEF1=2.0D0*(AI-1.0D0)
      COEF2=2.0D0*AI
      TERM=TERM*((ANU2+COEF1)/COEF2)*(1.0D0-Z)
      SUM=SUM+TERM
  100 CONTINUE
!
  110 SUM=SUM+1.0D0
      SUM=(Z**(ANU2/2.0D0))*SUM
      CDF=1.0D0-SUM
      RETURN
!
!     DO THE NU1 ODD AND NU2 EVEN CASE
!
  150 SUM=0.0D0
      TERM=1.0D0
      IMAX=(N-2)/2
      IF(IMAX.LE.0)GO TO 210
      DO 200 I=1,IMAX
      AI=I
      COEF1=2.0D0*(AI-1.0D0)
      COEF2=2.0D0*AI
      TERM=TERM*((ANU1+COEF1)/COEF2)*Z
      SUM=SUM+TERM
  200 CONTINUE
!
  210 SUM=SUM+1.0D0
      CDF=((1.0D0-Z)**(ANU1/2.0D0))*SUM
      RETURN
!
!     DO THE NU1 ODD AND NU2 ODD CASE
!
  250 SUM=0.0D0
      TERM=1.0D0
      ARG=DSQRT((ANU1/ANU2)*DX)
      THETA=DATAN(ARG)
      SINTH=ARG/DSQRT(1.0D0+ARG*ARG)
      COSTH=1.0D0/DSQRT(1.0D0+ARG*ARG)
      IF(N.EQ.1)GO TO 320
      IF(N.EQ.3)GO TO 310
      IMAX=N-2
      DO 300 I=3,IMAX,2
      AI=I
      COEF1=AI-1.0D0
      COEF2=AI
      TERM=TERM*(COEF1/COEF2)*(COSTH*COSTH)
      SUM=SUM+TERM
  300 CONTINUE
!
  310 SUM=SUM+1.0D0
      SUM=SUM*SINTH*COSTH
!
  320 CONTINUE
      A=(2.0D0/PI)*(THETA+SUM)
      SUM=0.0D0
      TERM=1.0D0
      IF(M.EQ.1)B=0.0D0
      IF(M.EQ.1)GO TO 450
      IF(M.EQ.3)GO TO 410
      IMAX=M-3
      DO 400 I=1,IMAX,2
      AI=I
      COEF1=AI
      COEF2=AI+2.0D0
      TERM=TERM*((ANU2+COEF1)/COEF2)*(SINTH*SINTH)
      SUM=SUM+TERM
  400 CONTINUE
!
  410 SUM=SUM+1.0D0
      SUM=SUM*SINTH*(COSTH**N)
      COEF=1.0D0
      IEVODD=N-2*(N/2)
      IMIN=3
      IF(IEVODD.EQ.0)IMIN=2
      IF(IMIN.GT.N)GO TO 420
      DO 430 I=IMIN,N,2
      AI=I
      COEF=((AI-1.0D0)/AI)*COEF
  430 CONTINUE
!
  420 COEF=COEF*ANU2
      IF(IEVODD.EQ.0)GO TO 440
      COEF=COEF*(2.0D0/PI)
!
  440 B=COEF*SUM
!
  450 CDF=A-B
      RETURN
!
!     TREAT THE CASE WHEN NU1 AND NU2
!     ARE BOTH LARGE
!     (THAT IS, BOTH ARE EQUAL TO OR LARGER THAN 1000);
!     OR WHEN NU1 IS MODERATE AND NU2 IS LARGE
!     (THAT IS, WHEN NU1 IS EQUAL TO OR GREATER THAN 100
!     BUT SMALLER THAN 1000,
!     AND NU2 IS EQUAL TO OR LARGER THAN 1000);
!     OR WHEN NU2 IS MODERATE AND NU1 IS LARGE
!     (THAT IS WHEN NU2 IS EQUAL TO OR GREATER THAN 100
!     BUT SMALLER THAN 1000,
!     AND NU1 IS EQUAL TO OR LARGER THAN 1000).
!     METHOD UTILIZED--PAULSON APPROXIMATION
!     (SEE AMS 55, PAGE 947, FORMULA 26.6.15).
!
 2000 CONTINUE
      DFACT1=1.0D0/(4.5D0*DNU1)
      DFACT2=1.0D0/(4.5D0*DNU2)
      DPOW1=1.0D0/3.0D0
      DPOW2=2.0D0/3.0D0
      DNUM=((1.0D0-DFACT2)*(DX**DPOW1))-(1.0D0-DFACT1)
      DDEN=DSQRT((DFACT2*(DX**DPOW2))+DFACT1)
      U=DNUM/DDEN
      CALL NORCDF(U,GCDF)
      CDF=GCDF
      RETURN
!
!     TREAT THE CASE WHEN NU1 IS SMALL
!     AND NU2 IS LARGE
!     (THAT IS, WHEN NU1 IS SMALLER THAN 100,
!     AND NU2 IS EQUAL TO OR LARGER THAN 1000).
!     METHOD UTILIZED--SHEFFE-TUKEY APPROXIMATION
!     (SEE JOHNSON AND KOTZ, VOLUME 2, PAGE 84, THIRD FORMULA).
!
 3000 CONTINUE
      TERM1=DNU1
      TERM2=(DNU1/DNU2)*(0.5D0*DNU1-1.0D0)
      TERM3=-(DNU1/DNU2)*0.5D0
      U=(TERM1+TERM2)/((1.0D0/DX)-TERM3)
      CALL CHSCDF(U,NU1,CCDF)
      CDF=CCDF
      RETURN
!
!     TREAT THE CASE WHEN NU2 IS SMALL
!     AND NU1 IS LARGE
!     (THAT IS, WHEN NU2 IS SMALLER THAN 100,
!     AND NU1 IS EQUAL TO OR LARGER THAN 1000).
!     METHOD UTILIZED--SHEFFE-TUKEY APPROXIMATION
!     (SEE JOHNSON AND KOTZ, VOLUME 2, PAGE 84, THIRD FORMULA).
!
 5000 CONTINUE
      TERM1=DNU2
      TERM2=(DNU2/DNU1)*(0.5D0*DNU2-1.0D0)
      TERM3=-(DNU2/DNU1)*0.5D0
      U=(TERM1+TERM2)/(DX-TERM3)
      CALL CHSCDF(U,NU2,CCDF)
      CDF=1.0-CCDF
      RETURN
!
      END SUBROUTINE FCDF
      SUBROUTINE F2CDF(X,ANU1,ANU2,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE F DISTRIBUTION WHERE FRACTIONAL
!              DEGREES OF FREEDOM ARE SUPPORTED.  IT IS BASED ON THE
!              RELATIONSHIP BETWEEN AN F DISTRIBUTION AND A BETA
!              DISTRIBUTION.
!
!                 IF X IS DISTRIBUTED AS F WITH V1 AND V2 DEGREES
!                 OF FREEDOM, THEN
!
!                      (V1*X/V2)/(1 + (V1*X/V2))
!
!                 IS DISTRIBUTED AS A BETA WITH PARAMETERS
!                 V1/2 AND V2/2.
!
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ANU1   = THE REAL DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                                ANU1 SHOULD BE POSITIVE.
!                     --ANU2   = THE REAL DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!                                ANU2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE F DISTRIBUTION WITH DEGREES OF FREEDOM
!             PARAMETERS NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ANU1 SHOULD BE POSITIVE.
!                 --ANU2 SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/06
!     ORIGINAL VERSION--JUNE      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DNU1
      DOUBLE PRECISION DNU2
      DOUBLE PRECISION DTERM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(ANU1.LT.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO F2CDF IS ',   &
               '< 1.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,4)ANU1
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(ANU2.LT.1.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO F2CDF IS ',   &
               '< 1.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,4)ANU2
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FCDF IS NEGATIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ENDIF
!
      DX=DBLE(X)
      DNU1=DBLE(ANU1)
      DNU2=DBLE(ANU2)
      DTERM1=DNU1*DX/DNU2
      DX=DTERM1/(1.0D0 + DTERM1)
!
      DNU1=DNU1/2.0D0
      DNU2=DNU2/2.0D0
      IF(DX.LE.0.0D0)THEN
        CDF=0.0
      ELSEIF(DX.GE.1.0D0)THEN
        CDF=1.0
      ELSE
        DCDF=DBETAI(DX,DNU1,DNU2)
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE F2CDF
      REAL FUNCTION F2FUN(X0)
!
!   COMPUTE F2CDF FUNCTION USED IN F2PDF ROUTINE (I.E.,
!   COMPUTE PDF BY DIFFERENTIATING THE CDF FUNCTION).
!
      COMMON/F2COMM/ANU1,ANU2
!
      CALL F2CDF(X0,ANU1,ANU2,FCDFT)
      F2FUN=FCDFT
!
      RETURN
      END FUNCTION F2FUN
      DOUBLE PRECISION FUNCTION FDM0P5(XVALUE)
!
!   DESCRIPTION:
!
!      This function computes the Fermi-Dirac function of
!      order -1/2, defined as
!
!                     Int{0 to inf} t**(-1/2) / (1+exp(t-x)) dt
!         FDM0P5(x) = -----------------------------------------
!                                 Gamma(1/2)
!
!      The function uses Chebyshev expansions which are given to
!      16 decimal places for x <= 2, but only 10 decimal places
!      for x > 2.
!
!
!   ERROR RETURNS:
!
!      None.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERMS1 - INTEGER - The number of terms used from the array
!                          ARRFD1. The recommended value is such that
!                               ABS(ARRFD1(NTERMS1)) < EPS/10
!                          subject to 1 <= NTERMS1 <= 14.
!
!      NTERMS2 - INTEGER - The number of terms used from the array
!                          ARRFD2. The recommended value is such that
!                               ABS(ARRFD2(NTERMS2)) < EPS/10
!                          subject to 1 <= NTERMS1 <= 23.
!
!      NTERMS3 - INTEGER - The number of terms used from the array
!                          ARRFD3. The recommended value is such that
!                               ABS(ARRFD3(NTERMS3)) < EPS/10
!                          subject to 1 <= NTERMS3 <= 28.
!
!      XMIN1 - REAL - The value of x below which
!                         FDM0P5(x) = exp(x)
!                     to machine precision. The recommended value
!                     is    LN ( SQRT(2) * EPSNEG )
!
!      XMIN2 - REAL - The value of x below which
!                         FDM0P5(x) = 0.0
!                     to machine precision. The recommended value
!                     is    LN ( XMIN )
!
!      XHIGH - REAL - The value of x above which
!                         FDM0P5(x) = 2 sqrt (x/pi)
!                     to machine precision. The recommended value
!                     is    1 / sqrt( 2 * EPSNEG )
!
!      For values of EPS, EPSNEG, and XMIN the user should refer to the
!      paper by Cody in ACM. Trans. Math. Soft. Vol. 14 (1988) p303-311.
!
!      This code is provided with single and double precision values
!      of the machine-dependent parameters, suitable for machines
!      which satisfy the IEEE floating-point standard.
!
!
!   AUTHOR:
!          DR. ALLAN MACLEOD,
!          DEPT. OF MATHEMATICS AND STATISTICS,
!          UNIVERSITY OF PAISLEY,
!          HIGH ST.,
!          PAISLEY,
!          SCOTLAND
!          PA1 2BE
!
!          (e-mail: macl-ms0@paisley.ac.uk )
!
!
!   LATEST UPDATE:
!                 20 NOVEMBER, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3
      DOUBLE PRECISION   &
           ARRFD1(0:14),ARRFD2(0:23),ARRFD3(0:58),   &
           CHEVAL,CHV,EXPX,FIFTY,FORTY2,   &
           GAM1P5,ONE,T,THREE,TWO,TWOE,   &
           X,XHIGH,XMIN1,XMIN2,XSQ,XVALUE,ZERO
      DATA ARRFD1/1.7863596385102264D0,   &
                 -0.999372007632333D-1,   &
                  0.64144652216054D-2,   &
                 -0.4356415371345D-3,   &
                  0.305216700310D-4,   &
                 -0.21810648110D-5,   &
