                  0.47159D-11,   &
                 -0.3530D-12,   &
                  0.265D-13,   &
                 -0.20D-14,   &
                  0.2D-15/
      DATA ARRFD2( 0)/ 1.6877111526052352D0/
      DATA ARRFD2( 1)/ 0.5978360226336983D0/
