      DATA ARRFD2( 1)/ 1.8518290056265751D0/
      DATA ARRFD2( 2)/ 0.4612349102417150D0/
      DATA ARRFD2( 3)/ 0.579303976126881D-1/
      DATA ARRFD2( 4)/ 0.17043790554875D-2/
      DATA ARRFD2( 5)/-0.3970520122496D-3/
