      SUBROUTINE FIBONN(N,X,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES THE FIRST N FIBONNACI NUMBERS--
!              1, 1, 2, 3, 5, 8, 13, 21, ...
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF FIBONNACI NUMBERS
!                                TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                FIBONNACI NUMBERS
!                                WILL BE PLACED.
!     OUTPUT--THE FIRST N FIBONNACI NUMBERS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87.10
!     ORIGINAL VERSION--SEPTEMBER 1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CPUMA3=CPUMAX/3.0
!
!               ******************************************
!               **  TREAT THE FIBONNACCI SEQUENCE CASE  **
!               ******************************************
!
!               *******************************************
!               **  STEP 1--                             **
!               **  TEST THE INPUT ARGUMENTS FOR ERRORS  **
!               *******************************************
!
      IF(N.GE.1)GO TO 190
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
  101 FORMAT('***** ERROR IN GENMS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,102)
  102 FORMAT('      THE LENGTH OF THE DESIRED SEQUENCE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,103)
  103 FORMAT('      OF FIBONNACI NUMBERS MUST BE 1 OR LARGER;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,104)
  104 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,105)N
  105 FORMAT('      N = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  190 CONTINUE
!
!               ******************************
!               **  STEP 2--                **
!               **  GENERATE THE SEQUENCE   **
!               ******************************
!
      X(1)=1.0
      X(2)=1.0
      IF(N.LT.3)GO TO 1190
      DO 1100 I=3,N
      I2=I
      IM2=I-2
      IM1=I-1
      X(I)=X(IM2)+X(IM1)
      IF(X(I).GE.CPUMA3)GO TO 1150
 1100 CONTINUE
      GO TO 1190
!
 1150 CONTINUE
      I2P1=I2+1
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN FIBONN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      A NUMBER IN THE FIBONNACCI SEQUENCE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      HAS JUST EXCEEDED THE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)
 1154 FORMAT('      LARGEST FLOATING POINT NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      ALLOWABLE FOR THIS COMPUTER (',E15.7,').')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)
 1156 FORMAT('      THE VALUE CAUSING THE OVERFLOW WAS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1157)I2P1
 1157 FORMAT('      THE ',I8,'-TH NUMBER IN THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1158)
 1158 FORMAT('      FIBONNACCI SEQUENCE.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FIBONN
      SUBROUTINE FILLHT(IPHORI,ICHORI,AUPPER,ALOWER,XHORIZ,NHORP,ICASEF,   &
      IBUGU2,ISUBRO,IERROR)
!
!     PURPOSE--FILL IN (LINEARLY INTERPOLATE) VALUES IN THE HORIZON
!              TABLES FROM ELEMENTS IPREV TO ICUR, INCLUSIVE.
!     REFERENCE--ROGERS, DAVID F. (1985).  PROCEDURAL
!                ELEMENTS FOR COMPUTER GRAPHICS.
!                MCGRAW-HILL, NEW YORK, PAGE 197-201.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/9
!     ORIGINAL VERSION--AUGUST    1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASEF
!
      CHARACTER*4 IBUGU2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION AUPPER(*)
      DIMENSION ALOWER(*)
      DIMENSION XHORIZ(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FILL'
      ISUBN2='HT  '
!
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'LLHT')GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF FILLHT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGU2,ISUBRO,IERROR
   52 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)ICASEF
   53 FORMAT('ICASEF = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)IPHORI,ICHORI,NHORP
   61 FORMAT('IPHORI,ICHORI,NHORP = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=IPHORI,ICHORI
      WRITE(ICOUT,66)I,AUPPER(I),ALOWER(I),XHORIZ(I)
   66 FORMAT('I,AUPPER(I),ALOWER(I),XHORIZ(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
   90 CONTINUE
!
      YPU=AUPPER(IPHORI)
      YPL=ALOWER(IPHORI)
      XP=XHORIZ(IPHORI)
!
      YCU=AUPPER(ICHORI)
      YCL=ALOWER(ICHORI)
      XC=XHORIZ(ICHORI)
!
!               **************************************************
!               **  STEP 10--                                   **
!               **  BRANCH, BASED ON                            **
!               **  INDEX DIFFERENCE AND SLOPE                  **
!               **************************************************
!
      IDEL=ICHORI-IPHORI
      IF(IDEL.LE.1)GO TO 9000
      IF(XC.EQ.XP)GO TO 6000
      GO TO 7000
!
!               **************************************************
!               **  STEP 60--                                   **
!     ----------**  TREAT THE CASE OF NON-ADJ. HORIZON CELL     **----------
!               **  AND INFINITE SLOPE                          **
!               **  (SHOULD BE IMPOSSIBLE)                      **
!               **************************************************
!
 6000 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6010)
 6010 FORMAT('***** INTERNAL ERROR IN FILLHT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6011)
 6011 FORMAT('      AT BRANCH POINT 4000 (AN IMPOSSIBLE BRANCH)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6012)
 6012 FORMAT('      CONDITION = ADJACENT CELL BUT INFINITE SLOPE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6013)
 6013 FORMAT('      IF HAVE INFINITE SLOPE, THEN NECESSARILY MUST')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6014)
 6014 FORMAT('      BE IN SAME CELL.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6015)IPHORI,ICHORI
 6015 FORMAT('IPHORI,ICHORI = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,6016)XHORIZ(IPHORI),XHORIZ(ICHORI)
 6016 FORMAT('XHORIZ(IPHORI),XHORIZ(ICHORI) = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               **************************************************
!               **  STEP 70--                                   **
!     ----------**  TREAT THE CASE OF NON-ADJ. HORIZON CELL     **----------
!               **  AND FINITE SLOPE                            **
!               **************************************************
!
 7000 CONTINUE
      IF(ICASEF.EQ.'UPPE'.OR.ICASEF.EQ.'BOTH')GO TO 7100
      GO TO 7190
 7100 CONTINUE
      SLOPEU=(YCU-YPU)/(XC-XP)
      IMIN=IPHORI+1
      IMAX=ICHORI-1
      DO 7110 I=IMIN,IMAX
      XTEMP=XHORIZ(I)
      YTEMPU=YPU+(XTEMP-XP)*SLOPEU
      IF(YTEMPU.GT.AUPPER(I))AUPPER(I)=YTEMPU
 7110 CONTINUE
 7190 CONTINUE
!
      IF(ICASEF.EQ.'LOWE'.OR.ICASEF.EQ.'BOTH')GO TO 7200
      GO TO 7290
 7200 CONTINUE
      SLOPEL=(YCL-YPL)/(XC-XP)
      IMIN=IPHORI+1
      IMAX=ICHORI-1
      DO 7210 I=IMIN,IMAX
      XTEMP=XHORIZ(I)
      YTEMPL=YPL+(XTEMP-XP)*SLOPEL
      IF(YTEMPL.LT.ALOWER(I))ALOWER(I)=YTEMPL
 7210 CONTINUE
 7290 CONTINUE
!
!               **************************************************
!               **  STEP 90--                                   **
!               **  EXIT.                                       **
!               **************************************************
!
 9000 CONTINUE
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'LLHT')GO TO 9010
      GO TO 9090
 9010 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF FILLHT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGU2,ISUBRO,IERROR
 9012 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)ICASEF
 9013 FORMAT('ICASEF = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)IPHORI,ICHORI,NHORP
 9021 FORMAT('IPHORI,ICHORI,NHORP = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 9025 I=IPHORI,ICHORI
      WRITE(ICOUT,9026)I,AUPPER(I),ALOWER(I),XHORIZ(I)
 9026 FORMAT('I,AUPPER(I),ALOWER(I),XHORIZ(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE FILLHT
      SUBROUTINE FISHER(X, M, Y, N, TOTAL, POSSIB, P,   &
                        SUMX, SUMY, MEANX, MEANY,   &
                        WS1, WS2, WS3, MAXSAM, MAXNXT,   &
                        IFAULT,IBUGA3)
!
!        ALGORITHM AS 304.1 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Fisher's non-parametric randomization test for two small
!        independent random samples
!
!CCCC INTEGER M, N, TOTAL, POSSIB, IFAULT
!CCCC INTEGER WS3(MAXSAM)
      INTEGER M, N, TOTAL, IFAULT
      INTEGER WS3(*)
      REAL X(*), Y(*), P
!CCCC REAL WS1(MAXSIZ), WS2(MAXSIZ)
      REAL WS1(*), WS2(*)
!
      INTEGER MAXSAM, MAXSIZ, MAXNXT
!CCCC PARAMETER (MAXSAM = 14, MAXSIZ = 3432)
!
!        Important : set MAXSIZ >= COMB(MAXSAM, MAXSAM / 2)
!
!CCCC INTEGER K, SIZE1, SIZE2, COUNT
      INTEGER K, SIZE1, SIZE2
!CCCC REAL SUMX, SUMY, SUMM, POSSIB
      REAL SUMX, SUMY, POSSIB
      REAL MEANX, MEANY
!
      INTEGER TRADES
!CCCC REAL MEAN, SUM
!CCCC EXTERNAL COMB, SUM, TRADES
      REAL BINOM
      EXTERNAL BINOM, TRADES
!
      EXTERNAL CMPLMT, EXCHNG, KTRADE
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IWRITE
      CHARACTER*4 IERROR
!
!CCCC MEAN(SUMM, COUNT) = SUMM / REAL(COUNT)
!
      IWRITE='OFF'
!CCCC IF (COMB(MAXSAM, MAXSAM/2) .GT. MAXSIZ) THEN
      ATEMP=BINOM(MAXSAM,MAXSAM/2)
      MAXSIZ=INT(ATEMP+0.5)
!
      IF (MAXSIZ.GT.MAXNXT) THEN
         IFAULT = 1
      ELSE IF (M .GT. MAXSAM .OR. N .GT. MAXSAM) THEN
              IFAULT = 2
           ELSE
              IFAULT = 0
              CALL SUMDP(X,M,IWRITE,SUMX,IBUGA3,IERROR)
              CALL SUMDP(Y,N,IWRITE,SUMY,IBUGA3,IERROR)
              MEANX=SUMX/REAL(M)
              MEANY=SUMY/REAL(N)
!CCCC         IF (MEAN(SUMX, M) .GT. MEAN(SUMY, N)) THEN
              IF (MEANX.GT.MEANY) THEN
                 CALL EXCHNG(X, M, Y, N, SUMX, SUMY)
           END IF
           TOTAL = 0
           IF (M .EQ. N) THEN
              DO 10 K = 1, (M-1)/2
                 CALL KTRADE(X, M, WS1, SIZE1, WS3, K)
                 CALL KTRADE(Y, N, WS2, SIZE2, WS3, K)
                 TOTAL = TOTAL + TRADES(WS1, SIZE1, WS2, SIZE2)
                 CALL CMPLMT(WS1, SIZE1, SUMX)
                 CALL CMPLMT(WS2, SIZE2, SUMY)
                 TOTAL = TOTAL + TRADES(WS1, SIZE1, WS2, SIZE2)
   10         CONTINUE
              IF (MOD(M, 2) .EQ. 0) THEN
                 CALL KTRADE(X, M, WS1, SIZE1, WS3, K)
                 CALL KTRADE(Y, N, WS2, SIZE2, WS3, K)
                 TOTAL = TOTAL + TRADES(WS1, SIZE1, WS2, SIZE2)
              END IF
         ELSE
            DO 20 K = 1, MIN(M, N)
               CALL KTRADE(X, M, WS1, SIZE1, WS3, K)
               CALL KTRADE(Y, N, WS2, SIZE2, WS3, K)
               TOTAL = TOTAL + TRADES(WS1, SIZE1, WS2, SIZE2)
   20       CONTINUE
         END IF
!CCCC    POSSIB = COMB(M+N, M)
         POSSIB = BINOM(M+N, M)
         P = REAL(TOTAL + 1)/POSSIB
      END IF
!
      RETURN
      END SUBROUTINE FISHER
      SUBROUTINE FLCDF(X,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER = GAMMA
!              AND LOCATION PARAMETER = 1.
!              THE FATIGUE LIFE DISTRIBUTION IS "HALF WAY BETWEEN"
!              THE INVERSE GAUSSIAN DISTRIBUTION AND
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION.
!     NOTE--THE FATIGUE LIFE DISTRIBUTION HAS--
!              FLPDF(X,GAMMA) = (IGPDF(X,GAMMA)+RIGPDF(X,GAMMA)) / 2
!                             = ((1+X)/2)*IGPDF(X,GAMMA)
!              FLCDF(X,GAMMA) = (IGCDF(X,GAMMA)+RIGCDF(X,GAMMA)) / 2
!                             = NORCDF((1/GAMMA)*(SQRT(X)-SQRT(1/X)))
!              FLPPF(P,GAMMA) = (SEE FLPPF.FOR)
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION = MU*GAMMA*SQRT(1+(5/4)*GAMMA**2)
!              HAS SHAPE PARAMETER = GAMMA
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     NOTE--TO OBTAIN THE PPF FOR GENERAL MU,
!           COMPUTE THE PPF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                                (ALSO = COEF. OF VARIATION)
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE FATIGUE LIFE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA
!             AND WITH SCALE PARAMETER = 1
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JUNE      1999. REVERT TO NORCDF VERSION.
!                                       OTHER CODE PRODUCED NONSENSE.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,51)
   51   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FLCDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)GAMMA
   52   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,56)
   56   FORMAT('***** ERROR--THE FIRST  ARGUMENT TO FLCDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(X.EQ.0.0)THEN
        CDF=0.0
      ELSE
!CCCC   CALL IGCDF(X,GAMMA,CDF1)
!CCCC   CALL RIGCDF(X,GAMMA,CDF2)
!CCCC   CDF=(CDF1+CDF2)/2.0
        DX=DBLE(X)
        DGAMMA=DBLE(GAMMA)
        DTERM1=(DSQRT(DX)-DSQRT(1.0D0/DX))/DGAMMA
        CALL NODCDF(DTERM1,DCDF)
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FLCDF
      SUBROUTINE FLCHA(X,GAMMA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER = GAMMA
!              AND LOCATION PARAMETER = 1.
!              THE FATIGUE LIFE DISTRIBUTION IS "HALF WAY BETWEEN"
!              THE INVERSE GAUSSIAN DISTRIBUTION AND
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION.
!     NOTE--THE FATIGUE LIFE DISTRIBUTION HAS--
!              FLPDF(X,GAMMA) = (IGPDF(X,GAMMA)+RIGPDF(X,GAMMA)) / 2
!                             = ((1+X)/2)*IGPDF(X,GAMMA)
!              FLCDF(X,GAMMA) = (IGCDF(X,GAMMA)+RIGCDF(X,GAMMA)) / 2
!                             = NORCDF((1/GAMMA)*(SQRT(X)-SQRT(1/X)))
!              FLPPF(P,GAMMA) = (SEE FLPPF.FOR)
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION = MU*GAMMA*SQRT(1+(5/4)*GAMMA**2)
!              HAS SHAPE PARAMETER = GAMMA
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     NOTE--TO OBTAIN THE PPF FOR GENERAL MU,
!           COMPUTE THE PPF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA
!             AND WITH LOCATION PARAMETER = 1
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --JULY      1999.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)GO TO 50
      IF(X.LT.0.0)GO TO 55
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,51)
   51 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ',   &
      'ARGUMENT TO THE FLCHA SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)GAMMA
   52 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      HAZ=0.0
      GO TO 9000
   55 CONTINUE
      WRITE(ICOUT,56)
   56 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ',   &
      'ARGUMENT TO THE FLCHA SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,57)X
   57 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      HAZ=0.0
      GO TO 9000
   90 CONTINUE
!
      IF(X.EQ.0.0)THEN
        HAZ=0.0
      ELSEIF(X.GT.0.0)THEN
!CCCC    CALL FLCDF(X,GAMMA,CDF)
         DX=DBLE(X)
         DGAMMA=DBLE(GAMMA)
         DTERM1=(DSQRT(DX)-DSQRT(1.0D0/DX))/DGAMMA
         CALL NODCDF(DTERM1,DCDF)
         DCDF=1.0D0-DCDF
         IF(DCDF.GT.0.0D0)THEN
           HAZ=REAL(-DLOG(DCDF))
         ELSE
           WRITE(ICOUT,162)X
  162    FORMAT('***** FOR THE VALUE OF THE ARGUMENT ',   &
         E15.8,' THE CDF IS ESSENTIALLY 1, HAZARD SET TO 0.')
         CALL DPWRST('XXX','BUG ')
         HAZ=0.0
         ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FLCHA
      SUBROUTINE FLHAZ(X,GAMMA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER = GAMMA
!              AND LOCATION PARAMETER = 1.
!              THE FATIGUE LIFE DISTRIBUTION IS "HALF WAY BETWEEN"
!              THE INVERSE GAUSSIAN DISTRIBUTION AND
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION.
!     NOTE--THE FATIGUE LIFE DISTRIBUTION HAS--
!              FLPDF(X,GAMMA) = (IGPDF(X,GAMMA)+RIGPDF(X,GAMMA)) / 2
!                             = ((1+X)/2)*IGPDF(X,GAMMA)
!              FLCDF(X,GAMMA) = (IGCDF(X,GAMMA)+RIGCDF(X,GAMMA)) / 2
!                             = NORCDF((1/GAMMA)*(SQRT(X)-SQRT(1/X)))
!              FLPPF(P,GAMMA) = (SEE FLPPF.FOR)
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION = MU*GAMMA*SQRT(1+(5/4)*GAMMA**2)
!              HAS SHAPE PARAMETER = GAMMA
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     NOTE--TO OBTAIN THE PPF FOR GENERAL MU,
!           COMPUTE THE PPF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                                (ALSO = COEF. OF VARIATION)
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA
!             AND WITH LOCATION PARAMETER = 1
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.4
!     ORIGINAL VERSION--APRIL     1998.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)GO TO 50
      IF(X.LT.0.0)GO TO 55
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,51)
   51 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ',   &
      'ARGUMENT TO THE FLHAZ SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)GAMMA
   52 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      HAZ=0.0
      GO TO 9000
   55 CONTINUE
      WRITE(ICOUT,56)
   56 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ',   &
      'ARGUMENT TO THE FLHAZ SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,57)X
   57 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      HAZ=0.0
      GO TO 9000
   90 CONTINUE
!
      IF(X.EQ.0.0)THEN
        HAZ=0.0
      ELSEIF(X.GT.0.0)THEN
!CCCC    CALL FLCDF(X,GAMMA,CDF)
!CCCC    CDF=1.0-CDF
         DX=DBLE(X)
         DGAMMA=DBLE(GAMMA)
         DTERM1=(DSQRT(DX)-DSQRT(1.0D0/DX))/DGAMMA
         CALL NODCDF(DTERM1,DCDF)
         DCDF=1.0D0-DCDF
         IF(DCDF.GT.0.0D0)THEN
!CCCC      CALL FLPDF(X,GAMMA,PDF)
           DTERM1=DLOG(DSQRT(DX)+DSQRT(1.0D0/DX))
           DTERM2=DLOG(2.0D0*DX*DGAMMA)
           DTERM3=(DSQRT(DX)-DSQRT(1.0D0/DX))/DGAMMA
           CALL NODPDF(DTERM3,DTERM4)
           IF(DTERM4.LE.0.0D0)THEN
             DPDF=0.0D0
           ELSE
             DTERM4=DLOG(DTERM4)
             DPDF=DEXP(DTERM1-DTERM2+DTERM4)
           ENDIF
           HAZ=REAL(DPDF/DCDF)
         ELSE
           WRITE(ICOUT,162)X
  162    FORMAT('***** FOR THE VALUE OF THE ARGUMENT ',   &
         E15.8,' THE CDF IS ESSENTIALLY 1, HAZARD SET TO 0.')
         CALL DPWRST('XXX','BUG ')
         HAZ=0.0
         ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FLHAZ
      SUBROUTINE FLFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              FATIGUE LIFE MAXIMUM LIKELIHOOD EQUATIONS.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATE OF BETA IS THE
!              POSITIVE ROOT OF:
!
!                 BHAT**2 - BHAT*{2*H+K(BHAT)} + H*{TBAR+K(BHAT)}=0
!
!              WITH
!
!                  H=1/[N*SUM[i=1 to N][1/X(i)]
!                  TBAR = SUM[i=1 to N][X(i)]/N
!                  K(BHAT) = 1/[N*SUM[i=1 to N][1/(BHAT+X(i))]
!
!              AND
!
!                  AHAT = 2*SQRT[0.5*(TBAR/BHAT + BHAT/H) - 1]
!
!              FLFUN IS CALLED BY DNSQE ROUTINE FOR SOLVING
!              SIMULTANEOUS NONLINEAR EQUATIONS.  NOTE THAT THE
!              CALLING SEQUENCE DID NOT ACCOMODATE A DATA ARRAY
!              (AND ASSCIATED NUMBER OF OBSERVATIONS), SO THESE WERE
!              ADDED TO THE CALL LIST.
!     EXAMPLE--FATIGUE LIFE MAXIMUM LIKELIHOOD Y
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS: VOLUME 2", SECOND EDITION,
!                JOHN WILEY, PP.  651-658.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION TBAR
      DOUBLE PRECISION H
      DOUBLE PRECISION DK
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=1
      IFLAG=0
!
      DBETA=X(1)
      DN=DBLE(NOBS)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + 1.0D0/DX
        DSUM3=DSUM3 + 1.0D0/(DX + DBETA)
  200 CONTINUE
      TBAR=DSUM1/DN
      H=DN/DSUM2
      DK=DN/DSUM3
      FVEC(1)=DBETA**2 - DBETA*(2.0D0*H + DK) + H*(TBAR+DK)
!
      RETURN
      END SUBROUTINE FLFUN 
      SUBROUTINE FLML1(Y,N,MAXNXT,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        SCALML,SHAPML,SCALMO,SHAPMO,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER FATIGUE LIFE DISTRIBUTION FOR THE
!              RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).  THIS
!              ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLFL WILL GENERATE THE OUTPUT
!              FOR THE FATIGUE LIFE MLE COMMAND).
!
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN.  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS, VOLUME I", SECOND
!                EDITION, WILEY, 1994, PP. 614-619.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DGAMM1
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DALPH2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION TBAR
      DOUBLE PRECISION H
      DOUBLE PRECISION DK
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(1)
      DOUBLE PRECISION FVEC(1)
!
      EXTERNAL FLFUN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FLML'
      ISUBN2='1   '
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF FLML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TEMP1(I)
   57     FORMAT('I,Y(I),TEMP1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *******************************************
!               **  STEP 2--                             **
!               **  CARRY OUT CALCULATIONS               **
!               **  FOR FATIGUE LIFE MLE ESTIMATE        **
!               *******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='FATIGUE LIFE'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SCALML=CPUMIN
      SHAPMO=CPUMIN
      SCALMO=CPUMIN
!
      DN=DBLE(N)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DO 2110 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DSQRT(DX)
        DSUM2=DSUM2 + 1.0D0/DSQRT(DX)
        DSUM3=DSUM3 + DX
        DSUM4=DSUM4 + 1.0D0/DX
 2110 CONTINUE
      DGAMM1=DSUM1/DSUM2
      XPAR(1)=DSQRT(DSUM3/DSUM4)
!
      DSUM1=0.0D0
      DO 2120 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + (DSQRT(DX/DGAMM1) - DSQRT(DGAMM1/DX))**2
 2120 CONTINUE
      DALPHA=DSQRT(DSUM1/DN)
      SCALMO=REAL(DGAMM1)
      SHAPMO=REAL(DALPHA)
!
      XPAR(1)=DGAMM1
!
      IOPT=2
      TOL=1.0D-6
      NVAR=1
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(FLFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 200 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + 1.0D0/DX
        DSUM3=DSUM3 + 1.0D0/(DX + XPAR(1))
  200 CONTINUE
      TBAR=DSUM1/DN
      H=DN/DSUM2
      DK=DN/DSUM3
      DALPH2=2.0D0*DSQRT(0.5D0*((TBAR/XPAR(1)) + XPAR(1)/H) - 1.0D0)
      SCALML=REAL(XPAR(1))
      SHAPML=REAL(DALPH2)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF FLML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPMO,SCALMO
 9017   FORMAT('SHAPML,SCALML,SHAPMO,SCALMO =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE FLML1
      SUBROUTINE FLPDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER = GAMMA
!              AND LOCATION PARAMETER = 1.
!              THE FATIGUE LIFE DISTRIBUTION IS "HALF WAY BETWEEN"
!              THE INVERSE GAUSSIAN DISTRIBUTION AND
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION.
!     NOTE--THE FATIGUE LIFE DISTRIBUTION HAS--
!              FLPDF(X,GAMMA) = (IGPDF(X,GAMMA)+RIGPDF(X,GAMMA)) / 2
!                             = ((1+X)/2)*IGPDF(X,GAMMA)
!              FLCDF(X,GAMMA) = (IGCDF(X,GAMMA)+RIGCDF(X,GAMMA)) / 2
!                             = NORCDF((1/GAMMA)*(SQRT(X)-SQRT(1/X)))
!              FLPPF(P,GAMMA) = (SEE FLPPF.FOR)
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION = MU*GAMMA*SQRT(1+(5/4)*GAMMA**2)
!              HAS SHAPE PARAMETER = GAMMA
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     NOTE--TO OBTAIN THE PPF FOR GENERAL MU,
!           COMPUTE THE PPF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                                (ALSO = COEF. OF VARIATION)
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE FATIGUE LIFE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA
!             AND WITH SCALE PARAMETER = 1
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JULY      1999. USE DIFFERENT FORMULA
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)GO TO 50
      IF(X.LT.0.0)GO TO 55
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,51)
   51 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ',   &
      'ARGUMENT TO THE WFPDF SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)GAMMA
   52 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      PDF=0.0
      GO TO 9000
   55 CONTINUE
      WRITE(ICOUT,56)
   56 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ',   &
      'ARGUMENT TO THE WFPDF SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,57)X
   57 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      PDF=0.0
      GO TO 9000
   90 CONTINUE
!
      IF(X.EQ.0.0)GO TO 1100
      GO TO 1200
!
 1100 CONTINUE
      PDF=0.0
      GO TO 9000
!
 1200 CONTINUE
!
!CCCC JULY 1999.  USE DIFFERENT FORMULA
!CCCC CALL IGPDF(X,GAMMA,PDF1)
!CCCC CALL RIGPDF(X,GAMMA,PDF2)
!
      DX=DBLE(X)
      DGAMMA=DBLE(GAMMA)
      DTERM1=DLOG(DSQRT(DX)+DSQRT(1.0D0/DX))
      DTERM2=DLOG(2.0D0*DX*DGAMMA)
      DTERM3=(DSQRT(DX)-DSQRT(1.0D0/DX))/DGAMMA
      CALL NODPDF(DTERM3,DTERM4)
      IF(DTERM4.LE.0.0D0)THEN
        PDF=0.0
        GO TO 9000
      ENDIF
      DTERM4=DLOG(DTERM4)
      DPDF=DEXP(DTERM1-DTERM2+DTERM4)
      PDF=REAL(DPDF)
!CCCC PDF=(PDF1+PDF2)/2.0
!CCCC ARG1=(X**0.5+X**1.5)/(2.0*GAMMA)
!CCCC ARG2=(1.0/GAMMA)
!CCCC ARG3=SQRT(X)-1.0/SQRT(X)
!CCCC ARG4=ARG2*ARG3
!CCCC CALL NORPDF(ARG4,PDFN)
!CCCC PDF=ARG1*PDFN
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FLPDF
      SUBROUTINE FLPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER = GAMMA
!              AND LOCATION PARAMETER = 1.
!              THE FATIGUE LIFE DISTRIBUTION IS "HALF WAY BETWEEN"
!              THE INVERSE GAUSSIAN DISTRIBUTION AND
!              THE RECIPROCAL INVERSE GAUSSIAN DISTRIBUTION.
!     NOTE--THE FATIGUE LIFE DISTRIBUTION HAS--
!              FLPDF(X,GAMMA) = (IGPDF(X,GAMMA)+RIGPDF(X,GAMMA)) / 2
!                             = ((1+X)/2)*IGPDF(X,GAMMA)
!              FLCDF(X,GAMMA) = (IGCDF(X,GAMMA)+RIGCDF(X,GAMMA)) / 2
!                             = NORCDF((1/GAMMA)*(SQRT(X)-SQRT(1/X)))
!              FLPPF(P,GAMMA) = (SEE BELOW)
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION = MU*GAMMA*SQRT(1+(5/4)*GAMMA**2)
!              HAS SHAPE PARAMETER = GAMMA
!              IS NEAR-SYMMETRIC AND MODERATE-TAILED FOR SMALL GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR LARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES 0
!     NOTE--TO OBTAIN THE PPF FOR GENERAL MU,
!           COMPUTE THE PPF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!                                (ALSO = COEF. OF VARIATION)
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE INVERSE GAUSSIAN DISRIBUTION
!             WITH SHAPE PARAMETER GAMMA
!             AND SCALE PARAMETER 1
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN
!                   0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY).
!                 --GAMMA SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGCDF, NORCDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SAM SAUNDERS TALK, MAY 1990
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)GO TO 50
      IF(P.LT.0.0.OR.P.GE.1.0)GO TO 60
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,51)
   51 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ',   &
      'ARGUMENT TO THE FLPPF SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)GAMMA
   52 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9000
   60 CONTINUE
      WRITE(ICOUT,61)
   61 FORMAT('***** FATAL ERROR--THE FIRST  INPUT ARGUMENT ',   &
      'TO THE FLPPF SUBROUTINE ',   &
      'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)P
   62 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',   &
      E15.8,' *****')
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9000
   90 CONTINUE
!
      CALL NORPPF(P,PPFN)
      C=GAMMA*PPFN
!
      C2=C+SQRT(C*C+4.0)
!CCCC C3=C2/2.0
!CCCC PPF=C3**2
      PPF=0.25*(C2*C2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FLPPF
      SUBROUTINE FLRAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE FATIGUE LIFE DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = GAMMA
!              AND LOCATION PARAMETER MU = 1.
!              THE PROTOTYPE FATIGUE LIFE DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              RIGPDF(X,GAMMA) = ???
!                     WITH MU = 1
!     NOTE--THE FATIGUE LIFE DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU = 1
!              HAS STANDARD DEVIATION =
!              HAS SHAPE PARAMETER = GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR SMALL GAMMA???
!              IS SYMMETRIC AND MODERATE-TAILED FOR LARGE GAMMA???
!              APPROACHES NORMALITY AS GAMMA APPROACHES INFINITY???
!     NOTE--TO OBTAIN THE PDF FOR GENERAL MU,
!           COMPUTE THE PDF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!              F(X) = GAMMA * (X**(GAMMA-1)) * EXP(-(X**GAMMA)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE FATIGUE LIFE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE HEREIN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ
!               --SAM SAUNDERS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      IF(GAMMA.LE.0.0)GO TO 60
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   60 WRITE(ICOUT,15)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)GAMMA
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE FIRST  INPUT ARGUMENT ',   &
      'TO THE FLRAN SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT ',   &
      'TO THE FLRAN SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,   &
      ' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,   &
      ' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N FATIGUE LIFE DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      XTEMP=X(I)
      CALL FLPPF(XTEMP,GAMMA,X(I))
  100 CONTINUE
!
      RETURN
      END SUBROUTINE FLRAN
      REAL FUNCTION FMINDP(AX,BX,F,TOL)
!
!   NOTE: ADDED TO DATAPLOT 12/2003.  USE THIS ROUTINE FOR INTERNAL
!         DATAPLOT USE.  THE DPOPT2 ROUTINE IS ESSENTIALLY A DATAPLOT
!         ADAPTATION OF FMIN THAT IMPLEMENTS "LET A = OPTIMIZE ..."
!         COMMANDS.  IT IS MORE EFFICIENT FOR INTERNAL USE TO USE
!         FMIN EXPLICITLY (AVOID OVERHEAD OF FUNCTION PARSING, ETC.)
!
!   NOTE: MARCH 2005.  RENAME TO FMINDP TO AVOID NAME CONFLICT ON MAC OSX.
!
!***BEGIN PROLOGUE  FMIN
!***DATE WRITTEN   730101  (YYMMDD)
!***REVISION DATE  730101  (YYMMDD)
!***CATEGORY NO.  G1A2
!***KEYWORDS  ONE-DIMENSIONAL MINIMIZATION, UNIMODAL FUNCTION
!***AUTHOR  BRENT, R.
!***PURPOSE  An approximation to the point where F attains a minimum on
!            the interval (AX,BX) is determined as the value of the
!            function FMIN.
!***DESCRIPTION
!
!     From the book, "Numerical Methods and Software" by
!                D. Kahaner, C. Moler, S. Nash
!                Prentice Hall, 1988
!
!     The method used is a combination of golden section search and
!     successive parabolic interpolation.  Convergence is never much
!     slower than that for a Fibonacci search.  If F has a continuous
!     second derivative which is positive at the minimum (which is not
!     at AX or BX), then convergence is superlinear, and usually of the
!     order of about 1.324....
!
!     The function F is never evaluated at two points closer together
!     than EPS*ABS(FMIN) + (TOL/3), where EPS is approximately the
!     square root of the relative machine precision.  If F is a unimodal
!     function and the computed values of F are always unimodal when
!     separated by at least EPS*ABS(XSTAR) + (TOL/3), then FMIN
!     approximates the abcissa of the global minimum of F on the
!     interval AX,BX with an error less than 3*EPS*ABS(FMIN) + TOL.
!     If F is not unimodal, then FMIN may approximate a local, but
!     perhaps non-global, minimum to the same accuracy.
!
!     This function subprogram is a slightly modified version of the
!     ALGOL 60 procedure LOCALMIN given in Richard Brent, Algorithms for
!     Minimization Without Derivatives, Prentice-Hall, Inc. (1973).
!
! INPUT PARAMETERS
!
!  AX    (real)  left endpoint of initial interval
!  BX    (real) right endpoint of initial interval
!  F     Real function of the form REAL FUNCTION F(X) which evaluates
!          F(X)  for any  X in the interval  (AX,BX)
!        Must be declared EXTERNAL in calling routine.
!  TOL   (real) desired length of the interval of uncertainty of the
!        final result ( .ge. 0.0)
!
!
! OUTPUT PARAMETERS
!
! FMIN   abcissa approximating the minimizer of F
! AX     lower bound for minimizer
! BX     upper bound for minimizer
!
!***REFERENCES  RICHARD BRENT, ALGORITHMS FOR MINIMIZATION WITHOUT
!                 DERIVATIVES, PRENTICE-HALL, INC. (1973).
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  FMIN
      REAL  AX,BX,F,TOL
      REAL  A,B,C,D,E,EPS,XM,P,Q,R,TOL1,TOL2,U,V,W
      REAL  FU,FV,FW,FX,X
      REAL  ABS,SQRT,SIGN
!***FIRST EXECUTABLE STATEMENT  FMIN
      C = 0.5*(3. - SQRT(5.0))
!
!  C is the squared inverse of the golden ratio
!
!  EPS is approximately the square root of the relative machine
!  precision.
!
      EPS = 1.0
   10 EPS = EPS/2.0
      TOL1 = 1.0 + EPS
      IF (TOL1 .GT. 1.0) GO TO 10
      EPS = SQRT(EPS)
!
!  initialization
!
      A = AX
      B = BX
      V = A + C*(B - A)
      W = V
      X = V
      E = 0.0
      FX = F(X)
      FV = FX
      FW = FX
      D=0.0
      C=0.0
!
!  main loop starts here
!
   20 XM = 0.5*(A + B)
      TOL1 = EPS*ABS(X) + TOL/3.0
      TOL2 = 2.0*TOL1
!
!  check stopping criterion
!
      IF (ABS(X - XM) .LE. (TOL2 - 0.5*(B - A))) GO TO 90
!
! is golden-section necessary
!
      IF (ABS(E) .LE. TOL1) GO TO 40
!
!  fit parabola
!
      R = (X - W)*(FX - FV)
      Q = (X - V)*(FX - FW)
      P = (X - V)*Q - (X - W)*R
      Q = 2.0*(Q - R)
      IF (Q .GT. 0.0) P = -P
      Q = ABS(Q)
      R = E
      E = D
!
!  is parabola acceptable
!
      IF (ABS(P) .GE. ABS(0.5*Q*R)) GO TO 40
      IF (P .LE. Q*(A - X)) GO TO 40
      IF (P .GE. Q*(B - X)) GO TO 40
!
!  a parabolic interpolation step
!
      D = P/Q
      U = X + D
!
!  F must not be evaluated too close to AX or BX
!
      IF ((U - A) .LT. TOL2) D = SIGN(TOL1, XM - X)
      IF ((B - U) .LT. TOL2) D = SIGN(TOL1, XM - X)
      GO TO 50
!
!  a golden-section step
!
   40 IF (X .GE. XM) E = A - X
      IF (X .LT. XM) E = B - X
      D = C*E
!
!  F must not be evaluated too close to X
!
   50 IF (ABS(D) .GE. TOL1) U = X + D
      IF (ABS(D) .LT. TOL1) U = X + SIGN(TOL1, D)
      FU = F(U)
!
!  update  A, B, V, W, and X
!
      IF (FU .GT. FX) GO TO 60
      IF (U .GE. X) A = X
      IF (U .LT. X) B = X
      V = W
      FV = FW
      W = X
      FW = FX
      X = U
      FX = FU
      GO TO 20
   60 IF (U .LT. X) A = U
      IF (U .GE. X) B = U
      IF (FU .LE. FW) GO TO 70
      IF (W .EQ. X) GO TO 70
      IF (FU .LE. FV) GO TO 80
      IF (V .EQ. X) GO TO 80
      IF (V .EQ. W) GO TO 80
      GO TO 20
   70 V = W
      FV = FW
      W = U
      FW = FU
      GO TO 20
   80 V = U
      FV = FU
      GO TO 20
!
!  end of main loop
!
   90 FMINDP = X
      RETURN
      END FUNCTION FMINDP
      REAL FUNCTION FMIND2(AX,BX,F,DTEMP1,N,TOL)
!
!   NOTE: THIS VERSION OF FMIN ALLOWS PASSING OF ARRAY OF
!         DATA (DTEMP1 AND N TO DENOTE THE SAMPLE SIZE).
!
!***BEGIN PROLOGUE  FMIN
!***DATE WRITTEN   730101  (YYMMDD)
!***REVISION DATE  730101  (YYMMDD)
!***CATEGORY NO.  G1A2
!***KEYWORDS  ONE-DIMENSIONAL MINIMIZATION, UNIMODAL FUNCTION
!***AUTHOR  BRENT, R.
!***PURPOSE  An approximation to the point where F attains a minimum on
!            the interval (AX,BX) is determined as the value of the
!            function FMIN.
!***DESCRIPTION
!
!     From the book, "Numerical Methods and Software" by
!                D. Kahaner, C. Moler, S. Nash
!                Prentice Hall, 1988
!
!     The method used is a combination of golden section search and
!     successive parabolic interpolation.  Convergence is never much
!     slower than that for a Fibonacci search.  If F has a continuous
!     second derivative which is positive at the minimum (which is not
!     at AX or BX), then convergence is superlinear, and usually of the
!     order of about 1.324....
!
!     The function F is never evaluated at two points closer together
!     than EPS*ABS(FMIN) + (TOL/3), where EPS is approximately the
!     square root of the relative machine precision.  If F is a unimodal
!     function and the computed values of F are always unimodal when
!     separated by at least EPS*ABS(XSTAR) + (TOL/3), then FMIN
!     approximates the abcissa of the global minimum of F on the
!     interval AX,BX with an error less than 3*EPS*ABS(FMIN) + TOL.
!     If F is not unimodal, then FMIN may approximate a local, but
!     perhaps non-global, minimum to the same accuracy.
!
!     This function subprogram is a slightly modified version of the
!     ALGOL 60 procedure LOCALMIN given in Richard Brent, Algorithms for
!     Minimization Without Derivatives, Prentice-Hall, Inc. (1973).
!
! INPUT PARAMETERS
!
!  AX    (real)  left endpoint of initial interval
!  BX    (real) right endpoint of initial interval
!  F     Real function of the form REAL FUNCTION F(X) which evaluates
!          F(X)  for any  X in the interval  (AX,BX)
!        Must be declared EXTERNAL in calling routine.
!  TOL   (real) desired length of the interval of uncertainty of the
!        final result ( .ge. 0.0)
!
!
! OUTPUT PARAMETERS
!
! FMIN   abcissa approximating the minimizer of F
! AX     lower bound for minimizer
! BX     upper bound for minimizer
!
!***REFERENCES  RICHARD BRENT, ALGORITHMS FOR MINIMIZATION WITHOUT
!                 DERIVATIVES, PRENTICE-HALL, INC. (1973).
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  FMIN
      REAL  AX,BX,F,TOL
      REAL  A,B,C,D,E,EPS,XM,P,Q,R,TOL1,TOL2,U,V,W
      REAL  FU,FV,FW,FX,X
      REAL  ABS,SQRT,SIGN
      DOUBLE PRECISION DTEMP1(*)
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  FMIN
      FMIND2 = CPUMIN
!
      C = 0.5*(3. - SQRT(5.0))
!
!  C is the squared inverse of the golden ratio
!
!  EPS is approximately the square root of the relative machine
!  precision.
!
      EPS = 1.0
   10 EPS = EPS/2.0
      TOL1 = 1.0 + EPS
      IF (TOL1 .GT. 1.0) GO TO 10
      EPS = SQRT(EPS)
!
!  initialization
!
      A = AX
      B = BX
      V = A + C*(B - A)
      W = V
      X = V
      E = 0.0
      FX = F(X,DTEMP1,N)
      FV = FX
      FW = FX
      D=0.0
      C=0.0
!
!  main loop starts here
!
   20 XM = 0.5*(A + B)
      TOL1 = EPS*ABS(X) + TOL/3.0
      TOL2 = 2.0*TOL1
!
!  check stopping criterion
!
      IF (ABS(X - XM) .LE. (TOL2 - 0.5*(B - A))) GO TO 90
!
! is golden-section necessary
!
      IF (ABS(E) .LE. TOL1) GO TO 40
!
!  fit parabola
!
      R = (X - W)*(FX - FV)
      Q = (X - V)*(FX - FW)
      P = (X - V)*Q - (X - W)*R
      Q = 2.0*(Q - R)
      IF (Q .GT. 0.0) P = -P
      Q = ABS(Q)
      R = E
      E = D
!
!  is parabola acceptable
!
      IF (ABS(P) .GE. ABS(0.5*Q*R)) GO TO 40
      IF (P .LE. Q*(A - X)) GO TO 40
      IF (P .GE. Q*(B - X)) GO TO 40
!
!  a parabolic interpolation step
!
      D = P/Q
      U = X + D
!
!  F must not be evaluated too close to AX or BX
!
      IF ((U - A) .LT. TOL2) D = SIGN(TOL1, XM - X)
      IF ((B - U) .LT. TOL2) D = SIGN(TOL1, XM - X)
      GO TO 50
!
!  a golden-section step
!
   40 IF (X .GE. XM) E = A - X
      IF (X .LT. XM) E = B - X
      D = C*E
!
!  F must not be evaluated too close to X
!
   50 IF (ABS(D) .GE. TOL1) U = X + D
      IF (ABS(D) .LT. TOL1) U = X + SIGN(TOL1, D)
      FU = F(U,DTEMP1,N)
!
!  update  A, B, V, W, and X
!
      IF (FU .GT. FX) GO TO 60
      IF (U .GE. X) A = X
      IF (U .LT. X) B = X
      V = W
      FV = FW
      W = X
      FW = FX
      X = U
      FX = FU
      GO TO 20
   60 IF (U .LT. X) A = U
      IF (U .GE. X) B = U
      IF (FU .LE. FW) GO TO 70
      IF (W .EQ. X) GO TO 70
      IF (FU .LE. FV) GO TO 80
      IF (V .EQ. X) GO TO 80
      IF (V .EQ. W) GO TO 80
      GO TO 20
   70 V = W
      FV = FW
      W = U
      FW = FU
      GO TO 20
   80 V = U
      FV = FU
      GO TO 20
!
!  end of main loop
!
   90 FMIND2 = X
      RETURN
      END FUNCTION FMIND2
      FUNCTION FNALPH(X,NOBS,BETA,XGM)
!
! COMPUTE MLE FOR SCALE PARAMETER (ALPHA)
!    XGM IS THE GEOMETRIC MEAN OF THE X'S
!
      DOUBLE PRECISION SUMZ
      DIMENSION X(*)
!
      RN=FLOAT(NOBS)
!
      SUMZ=0.0D0
      DO 20 I=1,NOBS
        SUMZ=SUMZ+DBLE((X(I)/XGM)**BETA)
   20 CONTINUE
!
      FNALPH=XGM*(SNGL(SUMZ)/RN)**(1./BETA)
!
      RETURN
      END FUNCTION FNALPH
      FUNCTION FNALP2(X,NOBS,IR,GAMMA)
!
!    COMPUTE MLE FOR SCALE PARAMETER (ALPHA)
!    THIS IS FOR THE TYPE 2 CENSORED CASE.
!    XGM IS THE GEOMETRIC MEAN OF THE X'S
!
      DOUBLE PRECISION DG
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      DIMENSION X(*)
!
      DG=DBLE(GAMMA)
!
      DSUM1=0.0D0
      DO 20 I=1,IR
        DSUM1=DSUM1+(DBLE(X(I))**DG)
   20 CONTINUE
      DTERM1=DSUM1/DBLE(IR)
      DTERM2=DBLE(NOBS-IR)*DBLE(X(I))**DG
      DTERM3=(DTERM1 + DTERM2)**(1.0D0/DG)
!
      FNALP2=REAL(DTERM3)
!
      RETURN
      END FUNCTION FNALP2
      DOUBLE PRECISION FUNCTION FNCMVT(N, W)
!
!     Integrand subroutine
!
      INTEGER N, NUIN, INFIN(*), INFIS
      DOUBLE PRECISION W(*), LOWER(*), UPPER(*), CORREL(*), D, E
      INTEGER NL, IJ, I, J, NU
      PARAMETER ( NL = 20 )
      DOUBLE PRECISION COV((NL*(NL+1))/2), A(NL), B(NL), Y(NL)
      INTEGER INFI(NL)
      DOUBLE PRECISION PROD, D1, E1, DI, EI, SUM, STDINV, YD, UI, MVTNIT
      SAVE NU, D1, E1, A, B, INFI, COV
      DI = D1
      EI = E1
      PROD = EI - DI
      IJ = 1
      YD = 1.0D0
      DO 100 I = 1, N
         UI = STDINV( NU+I-1, DI + W(I)*( EI - DI ) )
         Y(I) = UI/YD
         YD = YD/SQRT( 1.0D0 + ( UI - 1.0D0 )*( UI + 1.0D0 )/   &
              DBLE( NU + I ) )
         SUM = 0.0D0
         DO 200 J = 1, I
            IJ = IJ + 1
            SUM = SUM + COV(IJ)*Y(J)
  200    CONTINUE
         IJ = IJ + 1
         CALL MVTLMS( NU+I, ( A(I+1) - SUM )*YD, ( B(I+1) - SUM )*YD,   &
                      INFI(I+1), DI, EI )
         PROD = PROD*( EI - DI )
  100 CONTINUE
      FNCMVT = PROD
      RETURN
!
!     Entry point for intialization
!
      ENTRY MVTNIT( N, NUIN, CORREL, LOWER, UPPER, INFIN, INFIS, D, E )
      MVTNIT = 0.0D0
!
!     Initialization and computation of covariance matrix Cholesky factor
!
      CALL MVTSRT( N, NUIN, LOWER, UPPER, CORREL, INFIN, Y, INFIS,   &
                   A, B, INFI, COV, D, E )
      NU = NUIN
      D1 = D
      E1 = E
!
      RETURN
      END FUNCTION FNCMVT
      SUBROUTINE FNRCDF(X,U,SD,CDF)
!
!     NOTE--FOLDED-NORMAL PDF IS:
!              FNRPDF(X,U,S,P) = NORPDF((X-U)/S) + NORPDF((X+U)/S))
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
      IF(X.LT.0.0)THEN
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FNRCDF (STANDARD ',   &
               'DEVIATION) IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      TERM1=(X-U)/SD
      CALL NORCDF(TERM1,TERM2)
      TERM2=TERM2
      TERM3=(-X-U)/SD
      CALL NORCDF(TERM3,TERM4)
      TERM4=TERM4
      CDF=TERM2-TERM4
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FNRCDF
      SUBROUTINE FNRFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              FOLDED NORMAL MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              MU**2 + SIGMA**2 - SUM[i=1 to n][X(i)**2]/N
!
!              MU - SUM[i=1 to n][X(i)*TANH(LOC*X(i)/SIGMA**2)]/N
!
!              WITH LOC AND SCALE DENOTING THE SHAPE PARAMETERS.
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--FOLDED NORMAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--"CONTINUOUS UNIVARIATE DISTRIBUTIONS-VVOLUME II",
!                SECOND EDITION, JOHNSON, KOTZ, AND BALAKRISHNAN,
!                1994, WILEY, P. 454.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DLOC=X(1)
      DSCALE=X(2)
      DN=DBLE(NOBS)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DSUM1=DSUM1 + DX*DX
        DSUM2=DSUM2 + DX*TANH(DLOC*DX/DSCALE)
  200 CONTINUE
!
      FVEC(1)=DLOC*DLOC + DSCALE - (DSUM1/DN)
      FVEC(2)=DLOC - (DSUM2/DN)
!
      RETURN
      END SUBROUTINE FNRFUN 
      DOUBLE PRECISION FUNCTION FNRFU2 (DX)
!
!     PURPOSE--THIS ROUTINE COMPUTES A FUNCTION NEEDED TO OBTAIN THE
!              PARAMETER COVARIANCE MATRIX FOR THE FOLDED NORMAL MLE.
!
!              SPECIFICALLY, THE INDEFINITE INTEGRAL IS NEEDED FOR
!
!              X**2*EXP(0.5*X**2)*SECH(THETA*X)
!
!              CALLED BY DQAGI.
!     REFERENCE--N. L. JOHNSON (1962), "THE FOLDED NORMAL DISTRIBUTION:
!                ACCURACY OF ESTIMATION BY MAXIMUM LIKELIHOOD",
!                TECHNOMETRICS, VOL. 4, NO. 2, PP. 249-256.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/5
!     ORIGINAL VERSION--MAY       2014.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DARG
!
      DOUBLE PRECISION DTHETA
      COMMON/FNRCOM/DTHETA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DTERM1=DX**2*DEXP(-0.5D0*DX**2)
      DARG=DTHETA*DX
      DTERM2=2.0D0/(DEXP(DARG)+DEXP(-DARG))
      FNRFU2=DTERM1*DTERM2
!
      RETURN
      END FUNCTION FNRFU2 
      SUBROUTINE FNRLI1(Y,N,ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE FOLED NORMAL DISTRIBUTION.  THIS IS FOR THE FULL
!              SAMPLE RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!     REFERENCE--N. L. JOHNSON (1962), "THE FOLDED NORMAL DISTRIBUTION:
!                ACCURACY OF ESTIMATION BY MAXIMUM LIKELIHOOD",
!                TECHNOMETRICS, VOL. 4, NO. 2, PP. 249-256.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/05
!     ORIGINAL VERSION--MAY       2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='NORL'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF FNRLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ALOC,SCALE
   52   FORMAT('IBUGA3,ISUBRO,N,ALOC,SCALE = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     NOTE THAT THE LOG-LIKELIHOOD IS GIVEN IN TERMS OF SIGMA AND
!     THETA = (MU/SIGMA).
!
!     THE LOG-LIKELIHOOD FUNCTION IS THEN:
!
!     -(N/2)*LOG(2*PI) - N*LOG(SIGMA) - N*THETA**2/2 -
!     0.5*SUM[i=1 to N][X(I)**2]/SIGMA)**2 +
!     SUM[i=1 to N][LOG(COSH(THETA*X(I)/SIGMA))]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTHETA=DU/DS
      DTERM1=(DN/2.0D0)*DLOG(2.0D0/DPI) - DN*DLOG(DS) -   &
             DN*DTHETA**2/2.0D0
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + (DX/DS)**2
        DTERM2=DTHETA*DX/DS
        DTERM3=(DEXP(DTERM2)+DEXP(-DTERM2))/2.0D0
        DSUM2=DSUM2 + DLOG(DTERM3)
 1000 CONTINUE
!
      DLIK=DTERM1 - 0.5D0*DSUM1 + DSUM2
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF FNRLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE FNRLI1
      SUBROUTINE FNRML1(Y,N,MAXNXT,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCML,SCALML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER FOLDED NORMAL DISTRIBUTION FOR THE
!              RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).  THIS
!              ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLFN WILL GENERATE THE OUTPUT
!              FOR THE FOLDED NORMAL MLE COMMAND).
!
!     REFERENCE--"CONTINUOUS UNIVARIATE DISTRIBUTIONS-VVOLUME II",
!                SECOND EDITION, JOHNSON, KOTZ, AND BALAKRISHNAN,
!                1994, WILEY, P. 454.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      EXTERNAL FNRFUN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FNRM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF FNRML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TEMP1(I)
   57     FORMAT('I,Y(I),TEMP1((I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR FOLDED NORMAL MLE ESTIMATE                 **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='FOLDED NORMAL'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ALOCML=CPUMIN
      SCALML=CPUMIN
!
      XPAR(1)=DBLE(XMEAN)
      XPAR(2)=DBLE(XSD*XSD)
!
      IOPT=2
      TOL=1.0D-5
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(FNRFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALOCML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
      SCALML=SQRT(SCALML)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF FNRML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCML,SCALML
 9017   FORMAT('ALOCML,SCALML =  ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE FNRML1
      SUBROUTINE FNRPDF(X,U,SD,PDF)
!
!     NOTE--FOLDED-NORMAL PDF IS:
!              FNRPDF(X,U,S)=(1/S)*(NORPDF((X-U)/S) + NORPDF((X+U)/S)))
!           WHERE NORPDF IS THE PDF OF THE STANDARD NORMAL DISTRIBUTION
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO FNRPDF IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
  201 FORMAT('***** ERROR--THE THIRD ARGUMENT TO FNRPDF (STANDARD ',   &
             'DEVIATION) IS NON-POSITIVE.')
!
      TERM1=(X-U)/SD
      CALL NORPDF(TERM1,TERM2)
      TERM2=TERM2/SD
      TERM3=(X+U)/SD
      CALL NORPDF(TERM3,TERM4)
      TERM4=TERM4/SD
      PDF=TERM2+TERM4
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FNRPDF
      SUBROUTINE FNRPPF(P,U,SD,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE FOLDED NORMAL
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DU
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DSDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION XINC
      DOUBLE PRECISION X
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION P1
      DOUBLE PRECISION FCS
      DOUBLE PRECISION XRML
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION CDFL
      DOUBLE PRECISION CDFR
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI /3.14159265358979D0/
      DATA EPS /0.00001D0/
      DATA SIG /1.0D-6/
      DATA ZERO /0.0D0/
      DATA MAXIT /5000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FNRPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(SD.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FNRPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!  NOVEMBER 1995.  IF P IS 0, PPF IS ZERO.  HANDLE THIS TRIVIAL CASE.
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
!  CALCULATE MEAN AND STANDARD DEVIATION OF FOLDED NORMAL
!
      DU=DBLE(U)
      DSD=DBLE(SD)
      DP=DBLE(P)
      DTERM1=DEXP(-DU**2/(2.0D0*DSD**2))
      DTERM2=DSQRT(2.D0/DPI)
      DTERM3=-DU/DSD
      CALL NODCDF(DTERM3,DTERM4)
      DMEAN=DTERM2*DSD*DTERM1 + DU*(1.D0-2.D0*DTERM4)
      DSDF=DMEAN**2 + DU*DU + DSD*DSD
!
      XL=DMEAN
      XINC=DSDF
      IF(XINC.LT.1.0D0)XINC=1.0D0
      ICOUNT=0
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0D0)XL=0.0D0
      IF(XR.LE.0.0D0)XR=XL+1.0D0
!CCCC CALL FNRCDF(XL,U,SD,CDFL)
!
      DTERM1=(XL-DU)/DSD
      CALL NODCDF(DTERM1,DTERM2)
      DTERM3=(-XL-DU)/DSD
      CALL NODCDF(DTERM3,DTERM4)
      CDFL=DTERM2-DTERM4
!
!CCCC CALL FNRCDF(XR,U,SD,CDFR)
!
      DTERM1=(XR-DU)/DSD
      CALL NODCDF(DTERM1,DTERM2)
      DTERM3=(-XR-DU)/DSD
      CALL NODCDF(DTERM3,DTERM4)
      CDFR=DTERM2-DTERM4
!
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXIT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--FNRPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -DP
      FXR = 1.0D0 - DP
  105 CONTINUE
      X = (XL+XR)*0.5D0
!CCCC CALL FNRCDF(X,U,SD,CDF)
!
      DTERM1=(X-DU)/DSD
      CALL NODCDF(DTERM1,DTERM2)
      DTERM3=(-X-DU)/DSD
      CALL NODCDF(DTERM3,DTERM4)
      DCDF=DTERM2-DTERM4
!
      P1=DCDF
      PPF=X
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--FNRPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FNRPPF
      SUBROUTINE FNRRAN(N,U,SD,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE FOLDED NORMAL DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                       U      = MEAN OF PARENT NORMAL DISTRIBUTION
!                       SD     = STANDARD DEVIATION OF PARENT NORMAL
!                                DISTRIBUTION
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE FOLDED-NORMAL DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 53, 59, 81, 83.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!-----COMMOMN---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'FNRRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!     THEN GENERATE 2 ADDITIONAL UNIFORM (0,1) RANDOM NUMBERS
!     (TO BE USED BELOW IN FORMING THE N-TH NORMAL
!     RANDOM NUMBER WHEN THE DESIRED SAMPLE SIZE N
!     HAPPENS TO BE ODD).
!
      CALL UNIRAN(N,ISEED,X)
      CALL UNIRAN(2,ISEED,Y)
!
!     GENERATE N NORMAL RANDOM NUMBERS
!     USING THE BOX-MULLER METHOD.
!
      DO 200 I=1,N,2
      IP1=I+1
      U1=X(I)
      IF(I.EQ.N)GO TO 210
      U2=X(IP1)
      GO TO 220
  210 U2=Y(2)
  220 ARG1=-2.0*LOG(U1)
      ARG2=2.0*PI*U2
      SQRT1=SQRT(ARG1)
      Z1=SQRT1*COS(ARG2)
      Z2=SQRT1*SIN(ARG2)
      X(I)=Z1
      IF(I.EQ.N)GO TO 200
      X(IP1)=Z2
  200 CONTINUE
!
!     GENERATE N FOLDED NORMAL RANDOM NUMBERS
!     USING THE DEFINITION THAT
!     A FOLDED NORMAL VARIATE
!     EQUALS THE ABSOLUTE VALUE OF A NORMAL VARIATE WITH
!     MEAN U AND STANDARD DEVIATION SD.
!
      DO 400 I=1,N
      X(I)=SD*X(I)+U
      IF(X(I).LT.0.0)X(I)=-X(I)
  400 CONTINUE
!
      RETURN
      END SUBROUTINE FNRRAN
      SUBROUTINE FTCDF(X,NU,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE FOLDED T DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X
!              AND IS THE ABSOLUTE VALUE OF THE STUDENT'S T
!              DISTRIBUTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE CORRESPONDING T CDF FUNCTION
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF FOR THE FODLED T DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--TCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS, VOLUME 2, 1994, PAGE 403,
!                 JOHN WILEY.
!                 PAGES 132-134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --OCTOBER   2006. CALL LIST TO TCDF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT')
    5 FORMAT('      TO THE FOLDED T CDF SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE DEGREES OF FREEDOM ARGUMENT ',   &
             'TO THE FOLDED T CDF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      CALL TCDF(X,REAL(NU),CDF)
      CDF=2.0*CDF - 1.0
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FTCDF
