      SUBROUTINE FTPPF(P,NU,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE FOLDED T DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR NON-NEGATIVE X
!              AND IS THE ABSOLUTE VALUE OF THE STUDENT'S T
!              DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS COMPUTED
!              FROM THE CORRESPONDING T PPF FUNCTION
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE (BETWEEN
!                                0.0 AND 1.0) AT WHICH THE PERCENT
!                                POINT FUNCTION IS TO BE EVALUATED.
!                     --NU     = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE FODLED T DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--TPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS, VOLUME 2, 1994, PAGE 403,
!                 JOHN WILEY.
!                 PAGES 132-134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--NOVEMBER  2003.
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT')
    5 FORMAT('      TO THE FOLDED T PPF SUBROUTINE IS OUTSIDE THE ')
    6 FORMAT('      ALLOWABLE (0,1] INTERVAL.')
   15 FORMAT('***** FATAL ERROR--THE DEGREES OF FREEDOM ARGUMENT ',   &
             'TO THE FOLDED T PPF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      ARG=(1.0+P)/2.0
      CALL TPPF(ARG,REAL(NU),PPF)
      IF(PPF.LE.0.0)PPF=0.0
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FTPPF
      SUBROUTINE FTRAN(N,NU,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE FOLDED T DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THE FOLDED T IS THE ABSOLUTE VALUE OF THE
!              STUDENT'S T DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU     = THE INTEGER DEGREES OF FREEDOM
!                                (PARAMETER) FOR THE FOLDED T
!                                DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE FOLDED T DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS, VOLUME 2", 1994,
!                 JOHN WILEY, P. 403.
!                 ALGORITHM IS TO FIND T RANDOM NUMBERS AND THEN
!                 TAKE ABSOLUTE VALUE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003.11
!     ORIGINAL VERSION--NOVEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2),Z(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** FATAL ERROR--FOR THE FOLDED T DISTRIBUTION, THE',   &
      'REQUESTED NUMBER OF RANDOM NUMBERS WAS NON-POSITIVE.')
   15 FORMAT('***** FATAL ERROR--FOR THE FOLDED T DISTRIBUTION, THE',   &
      'SPECIFIED SHAPE PARAMETER WAS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N STUDENT'S T RANDOM NUMBERS
!     USING THE DEFINITION THAT
!     A STUDENT'S T VARIATE WITH NU DEGREES OF FREEDOM
!     EQUALS A NORMAL VARIATE DIVIDED BY
!     A STANDARDIZED CHI VARIATE
!     (WHERE THE LATTER EQUALS SQRT(CHI-SQUARED/NU).
!     FIRST GENERATE A NORMAL RANDOM NUMBER,
!     THEN GENERATE A STANDARDIZED CHI RANDOM NUMBER,
!     THEN FORM THE RATIO OF THE FIRST DIVIDED BY
!     THE SECOND.
!
!     FOR FOLDED T, TAKE THE ABSOLUTE VALUE.
!
      ANU=NU
      DO 100 I=1,N
!
      CALL UNIRAN(2,ISEED,Y)
      ARG1=-2.0*LOG(Y(1))
      ARG2=2.0*PI*Y(2)
      ZNORM=(SQRT(ARG1))*(COS(ARG2))
!
      SUM=0.0
      DO 200 J=1,NU,2
      CALL UNIRAN(2,ISEED,Y)
      ARG1=-2.0*LOG(Y(1))
      ARG2=2.0*PI*Y(2)
      Z(1)=(SQRT(ARG1))*(COS(ARG2))
      Z(2)=(SQRT(ARG1))*(SIN(ARG2))
      SUM=SUM+Z(1)*Z(1)
      IF(J.EQ.NU)GO TO 200
      SUM=SUM+Z(2)*Z(2)
  200 CONTINUE
!
      X(I)=ABS(ZNORM/SQRT(SUM/ANU))
!
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE FTRAN
      SUBROUTINE FORSLV(NR,N,A,X,B)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! SOLVE  AX=B  WHERE A IS LOWER TRIANGULAR MATRIX
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)       --> LOWER TRIANGULAR MATRIX (PRESERVED)
! X(N)        <--  SOLUTION VECTOR
! B(N)         --> RIGHT-HAND SIDE VECTOR
!
! NOTE
! ----
! IF B IS NO LONGER REQUIRED BY CALLING ROUTINE,
! THEN VECTORS B AND X MAY SHARE THE SAME STORAGE.
!
      DIMENSION A(NR,*),X(*),B(*)
!
! SOLVE LX=B. (FOREWARD SOLVE)
!
      X(1)=B(1)/A(1,1)
      IF(N.EQ.1) RETURN
      DO 20 I=2,N
        SUM=0.0D0
        IM1=I-1
        DO 10 J=1,IM1
          SUM=SUM+A(I,J)*X(J)
   10   CONTINUE
        X(I)=(B(I)-SUM)/A(I,I)
   20 CONTINUE
      RETURN
      END SUBROUTINE FORSLV
      SUBROUTINE FOUTRA(Y1,Y2,YC,SCRTCH,N1,ITCASE,IWRITE,Y12,IFTEXP,   &
                        IFTORD,Y3,Y4,N3,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT FOURIER TRANSFORM-TYPE OPERATIONS
!              OF THE COMPLEX DATA IN Y1 AND Y2.
!
!     OPERATIONS--FOURIER TRANSFORM
!                 INVERSE FOURIER TRANSFORM
!                 FFT
!                 INVERSE FFT
!
!     EXAMPLES--LET T1 T2 = FOURIER TRANSFORM Y1 Y2
!               LET Y1 Y2 = INVERSE FOURIER TRANSFORM T1 T2
!               LET T1 T2 = FFT Y1 Y2
!               LET Y1 Y2 = INVERSE FFT T1 T2
!     INPUT  ARGUMENTS--Y1 (REAL PART)       Y2 (IMAGINARY PART)
!     OUTPUT ARGUMENTS--Y3 (REAL PART)       Y4 (IMAGINARY PART)
!
!     NOTE--FOR THE FOURIER TRANSFORM AND THE FFT--
!              Y3(1) = A0 =
!              Y3(2) = A1
!              Y3(3) = A2
!              .
!              .
!              .
!              Y3(N) = A(N-1) =
!
!              Y4(1) = B0 =
!              Y4(2) = B1
!              Y4(3) = B2
!              .
!              .
!              .
!              Y4(N) = B(N-1) =
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT VECTORS Y3(.) AND Y4(.)
!           BEING IDENTICAL TO THE INPUT VECTORS Y1(.) AND Y2(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/5
!     ORIGINAL VERSION--APRIL    1987.
!     UPDATED--SEPTEMBER 1987   (FFT AND INVERSE FFT)
!     UPDATED--AUGUST    1995   REPLACE NUMERICAL RECIPES ROUTINE
!                               WITH CMLIB ROUTINE.  ALSO, GO FROM
!                               1 TO N RATHER THAN -N/2 TO N/2.
!     UPDATED--DECEMBER  2009   MAKE YC REAL RATHER THAN COMPLEX
!                               TO ACCOMODATE INTEL VERSION 11
!                               COMPILER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ITCASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IFTEXP
!CCCC AUGUST 1995.  ADD FOLLOWING LINE
      CHARACTER*4 IFTORD
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      CHARACTER*4 ITCAS2
!
!-----DOUBLE PRECISION STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DN1
      DOUBLE PRECISION DI
      DOUBLE PRECISION DK
      DOUBLE PRECISION DKM1
      DOUBLE PRECISION DOMEGA
      DOUBLE PRECISION DY1K
      DOUBLE PRECISION DY2K
!
      DOUBLE PRECISION DC
      DOUBLE PRECISION DS
      DOUBLE PRECISION DTCR
      DOUBLE PRECISION DTSR
      DOUBLE PRECISION DTCI
      DOUBLE PRECISION DTSI
      DOUBLE PRECISION DSUMCR
      DOUBLE PRECISION DSUMSR
      DOUBLE PRECISION DSUMCI
      DOUBLE PRECISION DSUMSI
!CCCC AUGUST 1995.  ADD FOLLOWING LINE
!CCCC COMPLEX YC
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION Y12(*)
!CCCC AUGUST 1995.  ADD FOLLOWING 2 LINES.
      DIMENSION YC(*)
      DIMENSION SCRTCH(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FOUT'
      ISUBN2='RA  '
      IERROR='NO'
!
      DN1=(-999.0D0)
      ITCAS2='-999'
      DPI=3.14159265358979D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF FOUTRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ITCASE,IWRITE,IFTEXP
   52   FORMAT('IBUGA3,ITCASE,IWRITE,IFTEXP = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)N1
   54   FORMAT('N1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y12(I)
   56     FORMAT('I,Y1(I),Y2(I),Y12(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***************************************************
!               **  CARRY OUT FOURIER TRANSFORM-TYPE OPERATIONS  **
!               ***************************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)GO TO 1100
      GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN FOUTRA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      IF(ITCASE.EQ.'FOUT'.OR.ITCASE.EQ.'FOU1')WRITE(ICOUT,1154)
 1154 FORMAT('      THE FOURIER TRANSFORM IS TO BE ',   &
      'COMPUTED')
      IF(ITCASE.EQ.'FOUT'.OR.ITCASE.EQ.'FOU1')CALL DPWRST('XXX','BUG ')
      IF(ITCASE.EQ.'IFOU'.OR.ITCASE.EQ.'IFO1')WRITE(ICOUT,1155)
 1155 FORMAT('      THE INVERSE FOURIER TRANSFORM IS TO BE ',   &
      'COMPUTED')
      IF(ITCASE.EQ.'IFOU'.OR.ITCASE.EQ.'IFO1')CALL DPWRST('XXX','BUG ')
      IF(ITCASE.EQ.'FFT'.OR.ITCASE.EQ.'FFT1')WRITE(ICOUT,1156)
 1156 FORMAT('      THE FFT IS TO BE ',   &
      'COMPUTED')
      IF(ITCASE.EQ.'FFT'.OR.ITCASE.EQ.'FFT1')CALL DPWRST('XXX','BUG ')
      IF(ITCASE.EQ.'IFFT'.OR.ITCASE.EQ.'IFF1')WRITE(ICOUT,1157)
 1157 FORMAT('      THE INVERSE FFT IS TO BE ',   &
      'COMPUTED')
      IF(ITCASE.EQ.'IFFT'.OR.ITCASE.EQ.'IFF1')CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)
 1182 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1183)N1
 1183 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 12--                  **
!               **  BRANCH TO THE PROPER CASE  **
!               *********************************
!
      IF(ITCASE.EQ.'FOUT')GO TO 2100
      IF(ITCASE.EQ.'FOU1')GO TO 2100
      IF(ITCASE.EQ.'IFOU')GO TO 2100
      IF(ITCASE.EQ.'IFO1')GO TO 2100
      IF(ITCASE.EQ.'FFT')GO TO 2300
      IF(ITCASE.EQ.'FFT1')GO TO 2300
      IF(ITCASE.EQ.'IFFT')GO TO 2300
      IF(ITCASE.EQ.'IFF1')GO TO 2300
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** INTERNAL ERROR IN FOUTRA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      ITCASE NOT EQUAL TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1213)
 1213 FORMAT('      FOUT, FOU1, IFOU, IFO1')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      FFT, FFT1, IFFT, OR IFF1')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      ITCASE = ',A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               ************************************************
!               **  STEP 21--                                 **
!               **  TREAT THE FOURIER TRANSFORM         CASE  **
!               **  TREAT THE INVERSE FOURIER TRANSFORM CASE  **
!               **  BY OPERATING ON THE REAL AND              **
!               **  COMPLEX PARTS,                            **
!               **  BY TAKING                                 **
!               **     COSINE TRANSFORM OF REAL      PART     **
!               **     SINE   TRANSFORM OF REAL      PART     **
!               **     COSINE TRANSFORM OF IMAGINARY PART     **
!               **     SINE   TRANSFORM OF IMAGINARY PART,    **
!               **  AND BY COMBINING PROPERLY.                **
!               ************************************************
!
 2100 CONTINUE
!
      DN1=N1
!CCCC AUGUST 1995.  FOLLOWING DEFINITION FOR FOURIER EXPONENT
!CCCC "+" CASE.  FOURIER EXPONENT "-" CASE USES OPPOSSITE
!CCCC DEFINITIONS.
!CCCC IF(ITCASE.EQ.'FOUT')ITCAS2='FT'
!CCCC IF(ITCASE.EQ.'FOU1')ITCAS2='FT'
!CCCC IF(ITCASE.EQ.'IFOU')ITCAS2='IFT'
!CCCC IF(ITCASE.EQ.'IFO1')ITCAS2='IFT'
      IF(IFTEXP.EQ.'+')THEN
        IF(ITCASE.EQ.'FOUT')ITCAS2='FT'
        IF(ITCASE.EQ.'FOU1')ITCAS2='FT'
        IF(ITCASE.EQ.'IFOU')ITCAS2='IFT'
        IF(ITCASE.EQ.'IFO1')ITCAS2='IFT'
      ELSE
        IF(ITCASE.EQ.'FOUT')ITCAS2='IFT'
        IF(ITCASE.EQ.'FOU1')ITCAS2='IFT'
        IF(ITCASE.EQ.'IFOU')ITCAS2='FT'
        IF(ITCASE.EQ.'IFO1')ITCAS2='FT'
      ENDIF
!
      L=N1/2
      M=0
      DO 2110 IP1=1,N1
      I=IP1-1
      L=L+1
      IF(L.GT.N1)L=1
      M=M+1
      DI=I
      DOMEGA=2.0*DPI*(DI/DN1)
      DSUMCR=0.0
      DSUMSR=0.0
      DSUMCI=0.0
      DSUMSI=0.0
!
!CCCC AUGUST 1995.  FOR 'STANDARD' ORDERING.
      IF(IFTORD.EQ.'STAN')THEN
        M2=0
      ELSE
        IF(ITCAS2.EQ.'FT')M2=0
        IF(ITCAS2.EQ.'IFT')M2=N1/2
      ENDIF
!CCCC END CHANGE
      DO 2120 K=1,N1
      DK=K
      DKM1=DK-1.0D0
      M2=M2+1
      IF(M2.GT.N1)M2=1
      DY1K=Y1(M2)
      DY2K=Y2(M2)
!CCCC DSUMCR=DSUMCR+DY1K*DCOS(DOMEGA*DKM1)
!CCCC DSUMSR=DSUMSR+DY1K*DSIN(DOMEGA*DKM1)
!CCCC DSUMCI=DSUMCI+DY2K*DCOS(DOMEGA*DKM1)
!CCCC DSUMSI=DSUMSI+DY2K*DSIN(DOMEGA*DKM1)
      DC=DCOS(DOMEGA*DKM1)
      DS=DSIN(DOMEGA*DKM1)
      DTCR=DC*DY1K
      DTSR=DS*DY1K
      DTCI=DC*DY2K
      DTSI=DS*DY2K
      DSUMCR=DSUMCR+DTCR
      DSUMSR=DSUMSR+DTSR
      DSUMCI=DSUMCI+DTCI
      DSUMSI=DSUMSI+DTSI
      IF(IBUGA3.EQ.'OFF')GO TO 779
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,774)I,K,M2,DY1K,DY2K
  774 FORMAT('I,K,M2,DY1K,DY2K = ',3I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,775)DKM1,DOMEGA,DC,DS
  775 FORMAT('DKM1,DOMEGA,DC,DS = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,776)DTCR,DTSR,DTCI,DTSI
  776 FORMAT('DTCR,DTSR,DTCI,DTSI = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,778)DSUMCR,DSUMSR,DSUMCI,DSUMSI
  778 FORMAT('DSUMCR,DSUMSR,DSUMCI,DSUMSI = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
  779 CONTINUE
 2120 CONTINUE
!
!     THE FOLLOWING COMMENTED OUT CODE IS APPROPRIATE
!     IF THE FORWARD TRANSFORM IS DEFINED WITH A - IN THE EXPONENT
!     (AS IS THE USUAL CLASSIC DEFINITION)
!
!CCCC IF(ITCAS2.EQ.'FT')Y3(L)=DSUMCR+DSUMSI
!CCCC IF(ITCAS2.EQ.'FT')Y4(L)=DSUMCI-DSUMSR
!CCCC IF(ITCAS2.EQ.'IFT')Y3(M)=(DSUMCR-DSUMSI)/DN1
!CCCC IF(ITCAS2.EQ.'IFT')Y4(M)=(DSUMCI+DSUMSR)/DN1
!
!     THE FOLLOWING CODE IS APPROPRIATE
!     IF THE FORWARD TRANSFORM IS DEFINED WITH A + IN THE EXPONENT
!     (AS DEFINED BY PRESS ET AL (NUMERICAL RECIPES))
!
!CCCC AUGUST 1995.  FIX FOR STANDARD ORDERING
      IF(IFTORD.EQ.'STAN')THEN
        IF(ITCAS2.EQ.'FT')Y3(M)=DSUMCR-DSUMSI
        IF(ITCAS2.EQ.'FT')Y4(M)=DSUMCI+DSUMSR
        IF(ITCAS2.EQ.'IFT')Y3(M)=(DSUMCR+DSUMSI)/DN1
        IF(ITCAS2.EQ.'IFT')Y4(M)=(DSUMCI-DSUMSR)/DN1
      ELSE
        IF(ITCAS2.EQ.'FT')Y3(L)=DSUMCR-DSUMSI
        IF(ITCAS2.EQ.'FT')Y4(L)=DSUMCI+DSUMSR
        IF(ITCAS2.EQ.'IFT')Y3(M)=(DSUMCR+DSUMSI)/DN1
        IF(ITCAS2.EQ.'IFT')Y4(M)=(DSUMCI-DSUMSR)/DN1
      ENDIF
!
      IF(IBUGA3.EQ.'ON')WRITE(ICOUT,2121)I,IP1,L,M,DN1,DI
 2121 FORMAT('I,IP1,L,M,DN1,DI = ',4I8,2D15.7)
      IF(IBUGA3.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IBUGA3.EQ.'ON')WRITE(ICOUT,2122)DSUMCR,DSUMSR,DSUMCI,DSUMSI
 2122 FORMAT('DSUMCR,DSUMSR,DSUMCI,DSUMSI = ',4D15.7)
      IF(IBUGA3.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(IBUGA3.EQ.'ON')WRITE(ICOUT,999)
      IF(IBUGA3.EQ.'ON')CALL DPWRST('XXX','BUG ')
!
 2110 CONTINUE
      N3=N1
      GO TO 9000
!
!               ************************************************
!               **  STEP 23--                                 **
!               **  TREAT THE FFT                       CASE  **
!               **  TREAT THE INVERSE FFT               CASE  **
!               **  (NOTE--N1 IS ASSUMED TO BE A POWER OF 2)  **
!               ************************************************
!
 2300 CONTINUE
!
      AN1=N1
      NN2=2*N1
!
!CCCC AUGUST 1995.  SET ISIGN CORRECTLY
      IF(IFTEXP.EQ.'+')THEN
        ISIGN=1
        IF(ITCASE.EQ.'IFFT')ISIGN=(-1)
        IF(ITCASE.EQ.'IFF1')ISIGN=(-1)
      ELSE
        ISIGN=(-1)
        IF(ITCASE.EQ.'IFFT')ISIGN=1
        IF(ITCASE.EQ.'IFF1')ISIGN=1
      ENDIF
!CCCC IF(ITCASE.EQ.'FFT')GO TO 2310
!CCCC IF(ITCASE.EQ.'FFT1')GO TO 2310
!CCCC AUGUST 1995.  BE CONSISTENT IN SCALING!!!
!CCCC ADD FOLLOWING 2 LINES
!CCCC IF(ITCASE.EQ.'IFFT')GO TO 2310
!CCCC IF(ITCASE.EQ.'IFF1')GO TO 2310
!CCCC GO TO 2319
!2310 CONTINUE
!CCCC J=(-1)
!CCCC DO2311I=1,N1
!CCCC J=J+2
!CCCC JP1=J+1
!CCCC Y12(J)=Y1(I)
!CCCC Y12(JP1)=Y2(I)
!2311 CONTINUE
!2319 CONTINUE
!
!CCCC AUGUST 1995.  BE CONSISTENT IN SCALING!!!
!CCCC COMMENT OUT FOLLOWING 2 LINES
!CCCC IF(ITCASE.EQ.'IFFT')GO TO 2320
!CCCC IF(ITCASE.EQ.'IFF1')GO TO 2320
!CCCC GO TO 2329
!2320 CONTINUE
!CCCC J=N1-1
!CCCC DO2321I=1,N1
!CCCC J=J+2
!CCCC IF(J.GT.NN2)J=1
!CCCC JP1=J+1
!CCCC Y12(J)=Y1(I)
!CCCC Y12(JP1)=Y2(I)
!2321 CONTINUE
!2329 CONTINUE
!
!CCCC AUGUST 1995.  FOR CMLIB ROUTINE, STORE IN A COMPLEX ARRAY.
!CCCC NOTE THAT DATAPLOT ORDER IMPLIES (-N/2,N/2) RATHER THAN
!CCCC (1,N).
!
      IF(IFTORD.EQ.'STAN')THEN
        DO 2360 I=1,N1
          I1=2*(I-1)+1
          I2=I1+1
!CCCC     YC(I)=CMPLX(Y1(I),Y2(I))
          YC(I1)=Y1(I1)
          YC(I2)=Y2(I2)
 2360   CONTINUE
      ELSE
        IF(ISIGN.LT.0)THEN
          J=N1/2
          DO 2363 I=1,N1
            J=J+1
            IF(J.GT.N1)J=1
            I1=2*(I-1)+1
            I2=I1+1
!CCCC       YC(J)=CMPLX(Y1(I),Y2(I))
            YC(I1)=Y1(I1)
            YC(I2)=Y2(I2)
 2363     CONTINUE
        ELSE
          DO 2368 I=1,N1
            I1=2*(I-1)+1
            I2=I1+1
!CCCC       YC(I)=CMPLX(Y1(I),Y2(I))
            YC(I1)=Y1(I1)
            YC(I2)=Y2(I2)
 2368     CONTINUE
        ENDIF
      ENDIF
!
!CCCC AUGUST 1995.  DETERMINE VALUE OF ISIGN BEFORE CREATE INPUT FILE.
!CCCC ISIGN=1
!CCCC IF(ITCASE.EQ.'IFFT')ISIGN=(-1)
!CCCC IF(ITCASE.EQ.'IFF1')ISIGN=(-1)
!CCCC IF(IFTEXP.EQ.'+')ISIGN=(-ISIGN)
!
      IF(IBUGA3.EQ.'OFF')GO TO 2333
      DO 2331 I=1,NN2
!CCCC WRITE(ICOUT,2332)I,NN2,Y12(I)
      I1=2*(I-1)+1
      I2=I1+1
      WRITE(ICOUT,2332)I,NN2,YC(I1),YC(I2)
 2332 FORMAT('I,NN2,YC(I) = ',2I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 2331 CONTINUE
 2333 CONTINUE
!
!CCCC CALL FOUR1(Y12,NN2,ISIGN)
!CCCC AUGUST 1995.  REPLACE NUMERICAL RECIPES ROUTINES WITH
!CCCC CMLIB ROUTINE.
!CCCC CALL FOUR1(Y12,N1,ISIGN)
      CALL CFFTI(N1,SCRTCH)
      IF(ISIGN.LT.0)THEN
        CALL CFFTF(N1,YC,SCRTCH)
      ELSE
        CALL CFFTB(N1,YC,SCRTCH)
      ENDIF
!
      IF(IBUGA3.EQ.'OFF')GO TO 2337
      DO 2335 I=1,NN2
!CCCC WRITE(ICOUT,2336)I,NN2,Y12(I)
      I1=2*(I-1)+1
      I2=I1+1
      WRITE(ICOUT,2336)I,NN2,YC(I1),YC(I2)
 2336 FORMAT('I,NN2,YC(I) = ',2I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 2335 CONTINUE
 2337 CONTINUE
!
!CCCC AUGUST 1995.  BE CONSISTENT IN SCALING!!!
!CCCC COMMENT OUT FOLLOWING 2 LINES
!CCCC IF(ITCASE.EQ.'FFT')GO TO 2340
!CCCC IF(ITCASE.EQ.'FFT1')GO TO 2340
!CCCC GO TO 2349
!2340 CONTINUE
!CCCC J=N1-1
!CCCC DO2341I=1,N1
!CCCC J=J+2
!CCCC IF(J.GT.NN2)J=1
!CCCC JP1=J+1
!CCCC Y3(I)=Y12(J)
!CCCC Y4(I)=Y12(JP1)
!2341 CONTINUE
!2349 CONTINUE
!
!CCCC AUGUST 1995.  BE CONSISTENT IN SCALING!!!
!CCCC ADD FOLLOWING 2 LINES
!CCCC IF(ITCASE.EQ.'FFT')GO TO 2350
!CCCC IF(ITCASE.EQ.'FFT1')GO TO 2350
!CCCC IF(ITCASE.EQ.'IFFT')GO TO 2350
!CCCC IF(ITCASE.EQ.'IFF1')GO TO 2350
!CCCC GO TO 2359
!2350 CONTINUE
!CCCC J=(-1)
!CCCC AUGUST 1995.  RETURN THE DATA IN "STANDARD" ORDER OR IN
!CCCC "DATAPLOT" ORDER.  "STANDARD" ORDER IS WHAT IS RETURNED BY
!CCCC CFFTF AND CFFTB ROUTINES
      IF(IFTORD.EQ.'STAN')THEN
        DO 2351 I=1,N1
!CCCC     J=J+2
!CCCC     JP1=J+1
!CCCC     Y3(I)=Y12(J)/AN1
!CCCC     Y4(I)=Y12(JP1)/AN1
          I1=2*(I-1)+1
          I2=I1+1
!CCCC     Y3(I)=REAL(YC(I))
!CCCC     Y4(I)=AIMAG(YC(I))
          Y3(I)=YC(I1)
          Y4(I)=YC(I2)
 2351   CONTINUE
      ELSE
        IF(ISIGN.GT.0)THEN
          J=N1/2
          DO 2356 I=1,N1
            J=J+1
            IF(J.GT.N1)J=1
            I1=2*(J-1)+1
            I2=I1+1
!CCCCC      Y3(I)=REAL(YC(J))
!CCCCC      Y4(I)=AIMAG(YC(J))
            Y3(I)=YC(I1)
            Y4(I)=YC(I2)
 2356     CONTINUE
        ELSE
          DO 2358 I=1,N1
            I1=2*(I-1)+1
            I2=I1+1
!CCCC       Y3(I)=REAL(YC(I))
!CCCC       Y4(I)=AIMAG(YC(I))
            Y3(I)=YC(I1)
            Y4(I)=YC(I2)
 2358     CONTINUE
        ENDIF
      ENDIF
!2359 CONTINUE
!
!
!CCCC AUGUST 1995.  DIVIDE BY N IF ISIGN IS -1
      IF(ISIGN.LT.0.0)THEN
        DO 2370 I=1,N1
          Y3(I)=Y3(I)/AN1
          Y4(I)=Y4(I)/AN1
 2370   CONTINUE
      ENDIF
!
      N3=N1
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF FOUTRA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ITCASE,IWRITE,IERROR
 9012 FORMAT('IBUGA3,ITCASE,IWRITE,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IFTEXP
 9013 FORMAT('IFTEXP = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)N1,N3,NN2,ISIGN,ITCAS2
 9014 FORMAT('N1,N3,NN2,ISIGN,ITCAS2 = ',4I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,N1
      WRITE(ICOUT,9016)I,Y1(I),Y2(I),Y3(I),Y4(I)
 9016 FORMAT('I,Y1(I),Y2(I),Y3(I),Y4(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
      DO 9025 I=1,NN2
      WRITE(ICOUT,9026)I,NN2,YC(I)
 9026 FORMAT('I,NN2,YC(I) = ',2I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE FOUTRA
      SUBROUTINE FPDF(X,NU1,NU2,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR F DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU1 AND NU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU1    = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU1 SHOULD BE POSITIVE.
!                     --NU2    = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE STUDENT'S T DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NU1 AND NU2 SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHMATICS
!                 SERIES 55, 1964, PAGE 946, FORMULA 26.6.1.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES XXX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--AUGUST    1977.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2021. SET PRINT TYPE TO "ERRO" (USER
!                                       CAN SUPPRESS ERROR MESSAGE IF
!                                       "SET ERROR MESSAGE OFF" ENTERED.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DNU1
      DOUBLE PRECISION DNU2
      DOUBLE PRECISION DNU1H
      DOUBLE PRECISION DNU2H
      DOUBLE PRECISION DNU12H
      DOUBLE PRECISION DGF1
      DOUBLE PRECISION DGF2
      DOUBLE PRECISION DGF12
      DOUBLE PRECISION DTERM
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DCONST
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      PDF=0.0
      IF(NU1.LE.0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,117)NU1
  117   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(NU2.LE.0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,117)NU2
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ENDIF
!
!               ****************************************************************
!               **  STEP 2--
!               **  COMPUTE THE CONSTANT = ((NU1**(NU1/2))*(NU2**(NU2/2))/(BETA(
!               ****************************************************************
!
      DX=X
      DNU1=NU1
      DNU2=NU2
      DNU1H=DNU1/2.0
      DNU2H=DNU2/2.0
!
      DTERM1=DNU1**DNU1H
      DTERM2=DNU2**DNU2H
      CALL DGAMMF(DNU1H,DGF1)
      CALL DGAMMF(DNU2H,DGF2)
      DNU12H=DNU1H+DNU2H
      CALL DGAMMF(DNU12H,DGF12)
      DTERM3=(DGF1*DGF2)/DGF12
      DCONST=(DTERM1*DTERM2)/DTERM3
!
!               ************************************
!               **  STEP 3--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(DX.LE.0.0D0)PDF=0.0
      IF(DX.LE.0.0D0)GO TO 9000
!
      DTERM4=DX**(DNU1H-1.0D0)
      DTERM5=(DNU2+DNU1*DX)**(-DNU1H-DNU2H)
      DTERM=DTERM4*DTERM5
      PDF=DCONST*DTERM
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FPDF
      SUBROUTINE F2PDF(X,ANU1,ANU2,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE F DISTRIBUTION WHERE FRACTIONAL
!              DEGREES OF FREEDOM ARE SUPPORTED.  IT IS BASED ON THE
!              RELATIONSHIP BETWEEN AN F DISTRIBUTION AND A BETA
!              DISTRIBUTION.
!
!                 IF X IS DISTRIBUTED AS F WITH V1 AND V2 DEGREES
!                 OF FREEDOM, THEN
!
!                      (V1*X/V2)/(1 + (V1*X/V2))
!
!                 IS DISTRIBUTED AS A BETA WITH PARAMETERS
!                 V1/2 AND V2/2.
!
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ANU1   = THE REAL DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                                ANU1 SHOULD BE POSITIVE.
!                     --ANU2   = THE REAL DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!                                ANU2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE F DISTRIBUTION WITH DEGREES OF FREEDOM
!             PARAMETERS NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ANU1 SHOULD BE POSITIVE.
!                 --ANU2 SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/06
!     ORIGINAL VERSION--JUNE      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      EXTERNAL F2FUN
      COMMON/F2COMM/ZNU1,ZNU2
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(ANU1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO F2PDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,4)ANU1
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(ANU2.LE.0.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO F2PDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,4)ANU2
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FPDF IS NEGATIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ENDIF
!
      IF(X.EQ.0)GO TO 9000
!
!     CHECK FOR CASES WHERE FRACTIONAL DEGREES OF FREEDOM DON'T MATTER
!
      IDF11=INT(ANU1)
      IDF12=IDF11 + 1
      IDF21=INT(ANU1)
      IDF22=IDF21+1
      IF(IDF11.GE.1 .AND. IDF21.GE.1)THEN
        ICASE1=1
        ICASE2=1
        AVAL1=ANU1-REAL(IDF11)
        IF(ABS(AVAL1).LE.0.000001)ICASE1=0
        AVAL2=ANU2-REAL(IDF21)
        IF(ABS(AVAL2).LE.0.000001)ICASE2=0
        IF(ICASE1.EQ.1 .AND. ICASE2.EQ.1)THEN
!
!         CASE WHERE BOTH DEGREES OF FREEDOM ARE FRACTIONAL
!
          CALL FPDF(X,IDF11,IDF21,FPDF1)
          CALL FPDF(X,IDF12,IDF21,FPDF2)
          CALL FPDF(X,IDF11,IDF22,FPDF3)
          CALL FPDF(X,IDF12,IDF22,FPDF4)
          XLOW=MIN(FPDF1,FPDF2,FPDF3,FPDF4)
          XUPP=MAX(FPDF1,FPDF2,FPDF3,FPDF4)
          XDIFF=XUPP-XLOW
          IF(XDIFF.LE.0.000001)THEN
            PDF=(FPDF1+FPDF2+FPDF3+FPDF4)/4.0
            GO TO 9000
          ENDIF
        ELSEIF(ICASE1.EQ.0 .AND. ICASE2.EQ.1)THEN
!
!         CASE WHERE ANU1 IS INTEGER AND ANU2 IS FRACTIONAL
!
          CALL FPDF(X,IDF11,IDF21,FPDF1)
          CALL FPDF(X,IDF11,IDF22,FPDF3)
          XLOW=MIN(FPDF1,FPDF3)
          XUPP=MAX(FPDF1,FPDF3)
          XDIFF=XUPP-XLOW
          IF(XDIFF.LE.0.000001)THEN
            PDF=(FPDF1+FPDF3)/2.0
            GO TO 9000
          ENDIF
        ELSEIF(ICASE1.EQ.1 .AND. ICASE2.EQ.0)THEN
!
!         CASE WHERE ANU1 IS FRACTIONAL AND ANU2 IS INTEGER
!
          CALL FPDF(X,IDF11,IDF21,FPDF1)
          CALL FPDF(X,IDF12,IDF21,FPDF2)
          XLOW=MIN(FPDF1,FPDF2)
          XUPP=MAX(FPDF1,FPDF2)
          XDIFF=XUPP-XLOW
          IF(XDIFF.LE.0.000001)THEN
            PDF=(FPDF1+FPDF2)/2.0
            GO TO 9000
          ENDIF
        ELSEIF(ICASE1.EQ.0 .AND. ICASE2.EQ.0)THEN
!
!         CASE WHERE BOTH DEGREES OF FREEDOM ARE ESSENTIALLY INTEGER
!
          CALL FPDF(X,IDF11,IDF21,PDF)
          GO TO 9000
        ENDIF
      ENDIF
!
!CCCC TERM1=ANU1*X/ANU2
!CCCC X=TERM1/(1.0 + TERM1)
!
!CCCC ANU1=ANU1/2.0D0
!CCCC ANU2=ANU2/2.0D0
!CCCC CALL BETPDF(X,ANU1,ANU2,PDF)
!
!     COMPUTE PDF FUNCTION BY TAKING DERIVATIVE OF
!     CDF FUNCTION
!
      ZNU1=ANU1
      ZNU2=ANU2
      IORD=1
      EPS=0.0
      ACCUR=0.0
      XMIN=MAX(0.0,X-5.0)
      XMAX=MAX(X,X+5.0)
      CALL DIFF(IORD,X,XMIN,XMAX,F2FUN,EPS,ACCUR,XDER,ERROR,IFAIL)
!
      IF(IFAIL.EQ.0 .OR. IFAIL.EQ.1)THEN
        PDF=XDER
      ELSEIF(IFAIL.EQ.2)THEN
        WRITE(ICOUT,104)
  104   FORMAT('***** ERROR IN FPDF FOR FRACTIONAL DEGREES OF FREEDOM')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,106)
  106   FORMAT('      THE INPUT DATA IS INCORRECT.')
        CALL DPWRST('XXX','ERRO')
      ELSEIF(IFAIL.EQ.3)THEN
        WRITE(ICOUT,104)
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,108)
  108   FORMAT('      UNABLE TO DETERMINE THE DERIVATIVE.')
        CALL DPWRST('XXX','ERRO')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE F2PDF
      SUBROUTINE FPPF(P,NU1,NU2,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FOR THE F DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM
!              PARAMETERS = NU1 AND NU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --NU1    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                                NU1 SHOULD BE POSITIVE.
!                     --NU2    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!                                NU2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE F DISTRIBUTION
!             WITH DEGREES OF FREEDOM
!             PARAMETERS = NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN
!                   0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY).
!                 --NU1 SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --NU2 SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FCDF, NORCDF, CHSCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGES 946-947,
!                 FORMULAE 26.6.4, 26.6.5, 26.6.8, AND 26.6.15.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGE 83, FORMULA 20,
!                 AND PAGE 84, THIRD FORMULA.
!               --PAULSON, AN APPROXIMATE NORMAILIZATION
!                 OF THE ANALYSIS OF VARIANCE DISTRIBUTION,
!                 ANNALS OF MATHEMATICAL STATISTICS, 1942,
!                 NUMBER 13, PAGES 233-135.
!               --SCHEFFE AND TUKEY, A FORMULA FOR SAMPLE SIZES
!                 FOR POPULATION TOLERANCE LIMITS, 1944,
!                 NUMBER 15, PAGE 217.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MAY       1978.
!     UPDATED         --AUGUST    1979.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2021. SET PRINT TYPE TO "ERRO" (USER
!                                       CAN SUPPRESS ERROR MESSAGE IF
!                                       "SET ERROR MESSAGE OFF" ENTERED.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(NU1.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,47)NU1
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(NU2.LE.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,47)NU2
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FPPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
!
!     2023/06: DECREASE THE TOLERANCE AND INCREASE MAX ITERATIONS
!
      IBUG=0
!CCCC TOL=0.000001
      TOL=0.00000001
      MAXIT=500
      XMIN=0.0
      XMAX=10.0**30
      XLOW=XMIN
      XUP=XMAX
!
      ANU1=NU1
      ANU2=NU2
!
      EXPF=0.5*((1.0/ANU2)-(1.0/ANU1))
      SDF=SQRT(0.5*((1.0/ANU2)+(1.0/ANU1)))
      CALL NORPPF(P,ZN)
      XN=EXPF+ZN*SDF
      XMID=EXP(2.0*XN)
      IF(IBUG.EQ.1)THEN
        WRITE(ICOUT,101)XMID
  101   FORMAT('XMID = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICOUNT=0
!
  200 CONTINUE
      X=XMID
      CALL FCDF(X,NU1,NU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.GT.P)GO TO 220
!
  210 CONTINUE
      XLOW=XMID
      X=XMID*2.0
      IF(X.GE.XUP)GO TO 211
      XMID=X
      IF(IBUG.EQ.1)THEN
        WRITE(ICOUT,101)XMID
        CALL DPWRST('XXX','BUG ')
      ENDIF
      CALL FCDF(X,NU1,NU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.LT.P)GO TO 210
      XUP=X
  211 CONTINUE
      XMID=(XLOW+XUP)/2.0
      IF(IBUG.EQ.1)THEN
        WRITE(ICOUT,101)XMID
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 230
!
  220 CONTINUE
      XUP=XMID
      X=XMID/2.0
      IF(X.LE.XLOW)GO TO 221
      XMID=X
      IF(IBUG.EQ.1)THEN
        WRITE(ICOUT,101)XMID
        CALL DPWRST('XXX','BUG ')
      ENDIF
      CALL FCDF(X,NU1,NU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.GT.P)GO TO 220
      XLOW=X
  221 CONTINUE
      XMID=(XLOW+XUP)/2.0
      IF(IBUG.EQ.1)WRITE(ICOUT,101)XMID
      IF(IBUG.EQ.1)CALL DPWRST('XXX','BUG ')
      GO TO 230
!
  230 CONTINUE
      XDEL=ABS(XMID-XLOW)
      ICOUNT=ICOUNT+1
      IF(XDEL.LT.TOL.OR.ICOUNT.GT.MAXIT)GO TO 240
      GO TO 200
!
  240 CONTINUE
      PPF=XMID
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FPPF
      SUBROUTINE F2PPF(P,ANU1,ANU2,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION FOR
!              THE F DISTRIBUTION FOR FRACTIONAL DEGREES OF FREEDOM
!              PARAMETERS = ANU1 AND ANU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ANU1   = THE REAL DEGREES OF FREEDOM (POSITIVE)
!                                FOR THE NUMERATOR OF THE F RATIO.
!                     --ANU2   = THE REAL DEGREES OF FREEDOM (POSITIVE)
!                                FOR THE DENOMINATOR OF THE F RATIO.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION VALUE PPF FOR
!             THE F DISTRIBUTION WITH DEGREES OF FREEDOM PARAMETERS =
!             ANU1 AND ANU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN
!                   0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY).
!                 --ANU1 SHOULD BE >= 1.
!                 --ANU2 SHOULD BE >= 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--F2CDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--xx
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/06
!     ORIGINAL VERSION--JUNE      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(ANU1.LT.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO FPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)ANU1
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(ANU2.LT.1.0)THEN
        WRITE(ICOUT,23)
   23   FORMAT('***** ERROR--THE THIRD ARGUMENT TO FPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)ANU2
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ELSEIF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO FPPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','ERRO')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
!
      TOL=0.0000001
      MAXIT=500
!
!     FIND BOUNDING INTERVAL BY COMPUTING THE INTEGER DEGREES OF
!     FREEDOM FPPF FUNCTION FOR THE NEIGHBORHOOD OF THE FRACTIONAL
!     DEGREES OF FREEDOM.  FRACTIONAL DEGREES OF FREEDOM LESS THAN
!     1 NEED TO BE HANDLED SEPARATELY.
!
      IDF11=INT(ANU1)
      IDF12=IDF11 + 1
      IDF21=INT(ANU1)
      IDF22=IDF21+1
      CALL FPPF(P,IDF11,IDF21,FPPF1)
      CALL FPPF(P,IDF12,IDF21,FPPF2)
      CALL FPPF(P,IDF11,IDF22,FPPF3)
      CALL FPPF(P,IDF12,IDF22,FPPF4)
      XMIN=MIN(FPPF1,FPPF2,FPPF3,FPPF4)
      XMAX=MAX(FPPF1,FPPF2,FPPF3,FPPF4)
      XLOW=XMIN
      XUP=XMAX
      XMID=(XMIN+XMAX)/2.0
!
!     NOW USE BISECTION METHOD
      ICOUNT=0
!
  200 CONTINUE
      X=XMID
      CALL F2CDF(X,ANU1,ANU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.GT.P)GO TO 220
!
  210 CONTINUE
      XLOW=XMID
      X=XMID*2.0
      IF(X.GE.XUP)GO TO 211
      XMID=X
      CALL F2CDF(X,ANU1,ANU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.LT.P)GO TO 210
      XUP=X
  211 CONTINUE
      XMID=(XLOW+XUP)/2.0
      GO TO 230
!
  220 CONTINUE
      XUP=XMID
      X=XMID/2.0
      IF(X.LE.XLOW)GO TO 221
      XMID=X
      CALL F2CDF(X,ANU1,ANU2,PCALC)
      IF(PCALC.EQ.P)GO TO 240
      IF(PCALC.GT.P)GO TO 220
      XLOW=X
  221 CONTINUE
      XMID=(XLOW+XUP)/2.0
      GO TO 230
!
  230 CONTINUE
      XDEL=ABS(XMID-XLOW)
      ICOUNT=ICOUNT+1
      IF(XDEL.LT.TOL.OR.ICOUNT.GT.MAXIT)GO TO 240
      GO TO 200
!
  240 CONTINUE
      PPF=XMID
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE F2PPF
      DOUBLE PRECISION FUNCTION fpser(a,b,x,eps)
!-----------------------------------------------------------------------
!
!                 EVALUATION OF I (A,B)
!                                X
!
!          FOR B .LT. MIN(EPS,EPS*A) AND X .LE. 0.5.
!
!-----------------------------------------------------------------------
!
!                  SET  FPSER = X**A
!
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION an,c,s,t,tol
!     ..
!     .. External Functions ..
      DOUBLE PRECISION exparg
      EXTERNAL exparg
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dlog,exp
!     ..
!     .. Executable Statements ..
                                                                                                                                  
      fpser = 1.0D0
      IF (a.LE.1.D-3*eps) GO TO 10
      fpser = 0.0D0
      t = a*dlog(x)
      IF (t.LT.exparg(1)) RETURN
      fpser = exp(t)
!
!                NOTE THAT 1/B(A,B) = B
!
   10 fpser = (b/a)*fpser
      tol = eps/a
      an = a + 1.0D0
      t = x
      s = t/an
   20 an = an + 1.0D0
      t = x*t
      c = t/an
      s = s + c
      IF (abs(c).GT.tol) GO TO 20
!
      fpser = fpser* (1.0D0+a*s)
      RETURN
                                                                                                                                  
      END FUNCTION fpser
      SUBROUTINE FRACTA(X1,Y1,N1,IWRITE,   &
      X2,Y2,N2,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT FRACTAL GENERATION
!              OF THE DATA IN X1 AND Y1.
!
!     EXAMPLES--LET X1 Y1 = FRACTAL X2 Y2
!     INPUT  ARGUMENTS--X1 (X COOR)       Y1 (Y COOR)
!     OUTPUT ARGUMENTS--X2 (X COOR)       Y2 (Y COOR)
!
!     NOTE--FOR STEP 1 OF THE LOOP
!           (2 POINTS IN AND 5 POINTS OUT)
!           (1 LINE IN AND 4 LINES OUT)--
!
!            X2(1) = X1(1)
!            X2(2) = X1(1) + (1/3)DELX
!            X2(3) = X1(1) + (1/2)DELX - (SQRT(3)/6)DELY
!            X2(4) = X1(1) + (2/3)DELX
!            X2(5) = X1(2)
!
!            Y2(1) = Y1(1)
!            Y2(2) = Y1(1) + (1/3)DELY
!            Y2(3) = Y1(1) + (1/2)DELY + (SQRT(3)/6)DELX
!            Y2(4) = Y1(1) + (2/3)DELY
!            Y2(5) = Y1(2)
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT VECTORS X2(.) AND Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTORS X1(.) AND Y1(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--RUCKER. INFINITY AND THE MIND, PAGE 9.
!     VERSION NUMBER--88/10
!     ORIGINAL VERSION--JULY     1988.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X1(*)
      DIMENSION Y1(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FRAC'
      ISUBN2='TA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF FRACTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE
   52   FORMAT('IBUGA3,IWRITE = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)N1
   54   FORMAT('N1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
        WRITE(ICOUT,56)I,X1(I),Y1(I)
   56   FORMAT('I,X1(I),Y1(I) = ',I8,2E15.7)
        CALL DPWRST('XXX','BUG ')
   55   CONTINUE
   90 CONTINUE
!
!                 *******************************************************
!                 **  CARRY OUT FOURIER FRACTAL-GENERATION OPERATIONS  **
!                 *******************************************************
!
!                 ********************************************
!                 **  STEP 11--                             **
!                 **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!                 ********************************************
!
        IF(N1.LT.2)GO TO 1100
        GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN FRACTA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('        THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('        IN THE VARIABLES FROM WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)
 1154 FORMAT('        THE AUGMENTED FRACTAL VARIABLE IS TO BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('        CREATED, MUST BE 2 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)
 1182 FORMAT('        SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1183)N1
 1183 FORMAT('        THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!                 ************************************************
!                 **  STEP 21--                                 **
!                 **  COMPUTE THE FRACTAL SET OF POINTS         **
!                 ************************************************
!
!2100 CONTINUE
!
      C=SQRT(3.0)/6.0
      N1M1=N1-1
      L=0
      DO 2110 I=1,N1M1
      IP1=I+1
      A1=X1(I)
      B1=Y1(I)
      A5=X1(IP1)
      B5=Y1(IP1)
      DELX=A5-A1
      DELY=B5-B1
      A2=A1+DELX/3
      A3=A1+DELX/2-C*DELY
      A4=A1+2*DELX/3
      B2=B1+DELY/3
      B3=B1+DELY/2+C*DELX
      B4=B1+2*DELY/3
      L=L+1
      X2(L)=A1
      Y2(L)=B1
      L=L+1
      X2(L)=A2
      Y2(L)=B2
      L=L+1
      X2(L)=A3
      Y2(L)=B3
      L=L+1
      X2(L)=A4
      Y2(L)=B4
      L=L+1
      X2(L)=A5
      Y2(L)=B5
 2110 CONTINUE
      N2=L
!
!                 *****************
!                 **  STEP 90--  **
!                 **  EXIT.      **
!                 *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END         OF FRACTA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IWRITE,IERROR
 9012 FORMAT('IBUGA3,IWRITE,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)N1,N2
 9014 FORMAT('N1,N2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,N1
      WRITE(ICOUT,9016)I,X1(I),Y1(I)
 9016 FORMAT('I,X1(I),Y1(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
      DO 9017 I=1,N2
      WRITE(ICOUT,9018)I,X2(I),Y2(I)
 9018 FORMAT('I,X2(I),Y2(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9017 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE FRACTA
      SUBROUTINE FRAN(N,ANU1,ANU2,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE F DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM
!              PARAMETERS = NU1 AND NU2.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU1    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE NUMERATOR OF THE F RATIO.
!                     --NU2    = THE INTEGER DEGREES OF FREEDOM
!                                FOR THE DENOMINATOR OF THE F RATIO.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE F DISTRIBUTION
!             WITH DEGREES OF FREEDOM
!             PARAMETERS = NU1 AND NU2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NU1 SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --NU2 SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOOD AND GRABLE, INTRODUCTION TO THE
!                 THEORY OF STATISTICS, 1963, PAGES 231-232.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 75-93.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 64.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2004. SUPPORT REAL VALUES FOR
!                                       DEGREES OF FREEDOM PARAMETERS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ICASE
!
      DIMENSION X(*)
      DIMENSION Y(2),Z(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
      DATA EPS/0.00001/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ANU1.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU1
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ANU2.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO FRAN ',   &
             'IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO FRAN ',   &
             'IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO FRAN ',   &
              'IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
      NU1=INT(ANU1+0.1)
      ANU12=REAL(NU1)
      NU2=INT(ANU2+0.1)
      ANU22=REAL(NU2)
      IF(ABS(ANU1-ANU12).LE.EPS .AND. ABS(ANU2-ANU22).LE.EPS)THEN
        ICASE='INTE'
        IF(NU1.EQ.0 .OR. NU2.EQ.0)THEN
          ICASE='REAL'
        ENDIF
      ELSE
        ICASE='REAL'
      ENDIF
!
!     CASE 1: INTEGER DEGREES OF FREEDOM
!
      IF(ICASE.EQ.'INTE')THEN
!       GENERATE N F RANDOM NUMBERS
!       USING THE DEFINITION THAT
!       A F VARIATE WITH NU1 AND NU2 DEGREES OF FREEDOM
!       EQUALS (CHS1/NU1)/(CHS2/NU2)
!       WHERE CHS1 IS A CHI-SQUARED VARIATE
!       WITH NU1 DEGREES OF FREEDOM,
!       AND   CHS2 IS A CHI-SQUARED VARIATE
!       WITH NU2 DEGREES OF FREEDOM.
!       FIRST GENERATE UNIFORM (0,1) RANDOM NUMBERS,
!       THEN GENERATE NORMAL RANDOM NUMBERS,
!       THEN CHI-SQUARED RANDOM NUMBERS WITH NU1 DEGREES
!       OF FREEDOM,
!       THEN CHI-SQUARED RANDOM NUMBERS WITH NU2 DEGREES
!       OF FREEDOM,
!       AND THEN FINALLY THE F RANDOM NUMBER.
!
        ANU1=NU1
        ANU2=NU2
        DO 100 I=1,N
!
          SUM=0.0
          DO 200 J=1,NU1,2
            CALL UNIRAN(2,ISEED,Y)
            ARG1=-2.0*LOG(Y(1))
            ARG2=2.0*PI*Y(2)
            Z(1)=(SQRT(ARG1))*(COS(ARG2))
            Z(2)=(SQRT(ARG1))*(SIN(ARG2))
            SUM=SUM+Z(1)*Z(1)
            IF(J.EQ.NU1)GO TO 200
            SUM=SUM+Z(2)*Z(2)
  200     CONTINUE
          CHS1=SUM
!
          SUM=0.0
          DO 300 J=1,NU2,2
            CALL UNIRAN(2,ISEED,Y)
            ARG1=-2.0*LOG(Y(1))
            ARG2=2.0*PI*Y(2)
            Z(1)=(SQRT(ARG1))*(COS(ARG2))
            Z(2)=(SQRT(ARG1))*(SIN(ARG2))
            SUM=SUM+Z(1)*Z(1)
            IF(J.EQ.NU2)GO TO 300
            SUM=SUM+Z(2)*Z(2)
  300     CONTINUE
          CHS2=SUM
!
          X(I)=(CHS1/ANU1)/(CHS2/ANU2)
!
  100   CONTINUE
!
      ELSE
        P=ANU1/2.0
        Q=ANU2/2.0
        CALL BETRAN(N,P,Q,ISEED,X)
        DO 500 I=1,N
          ATEMP=X(I)
          X(I)=ANU2*ATEMP/(ANU1*(1.0-ATEMP))
  500   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE FRAN
      SUBROUTINE FREQUE(X,NX,D,ND,NUMVAR,IWRITE,   &
                        Y,NY,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE FREQUENCIES FOR SPECIFIED VALUES OF A VARIABLE
!              (OR IF NO VALUES SPECIFIED, COMPUTE FREQUENCIES
!              FOR DISTINCT VALUES OF A VARIABLE).
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1979.
!     UPDATED         --APRIL     1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION D(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='FREQ'
      ISUBN2='UE  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF FREQUE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE
   52   FORMAT('IBUGA3,IWRITE = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NX,ND,NUMVAR
   53   FORMAT('NX,ND,NUMVAR = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,ND
          WRITE(ICOUT,61)I,D(I)
   61     FORMAT('I,D(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!               ********************************
!               **  STEP 1--                  **
!               **  COMPUTE DISTINCT VALUES  **
!               **  (IF NECESSARY)            **
!               ********************************
!
      IF(NUMVAR.GE.2)GO TO 190
!
      ND=0
      IF(NX.LT.1)GO TO 150
      DO 100 I=1,NX
      IF(I.EQ.1)GO TO 130
      DO 120 J=1,ND
      IF(X(I).EQ.D(J))GO TO 100
  120 CONTINUE
  130 CONTINUE
      ND=ND+1
      D(ND)=X(I)
  100 CONTINUE
      GO TO 190
!
  150 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,151)
  151 FORMAT('***** ERROR IN FREQUE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,152)
  152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,153)
  153 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,154)
  154 FORMAT('      THE DISTINCT VALUES ARE TO BE FOUND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,155)
  155 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,156)
  156 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,157)NX
  157 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
!
  190 CONTINUE
!
!               ***************************
!               **  STEP 2--             **
!               **  COMPUTE FREQUENCIES  **
!               ***************************
!
      NY=ND
      IF(ND.LT.1)GO TO 250
      DO 210 J=1,ND
      ISUM=0
      DO 220 I=1,NX
      IF(X(I).EQ.D(J))GO TO 230
      GO TO 220
  230 CONTINUE
      ISUM=ISUM+1
  220 CONTINUE
      Y(J)=ISUM
  210 CONTINUE
      GO TO 290
!
  250 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,251)
  251 FORMAT('***** ERROR IN FREQUE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,252)
  252 FORMAT('      THE INPUT NUMBER OF DISTINCT VALUES')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,253)
  253 FORMAT('      OF THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,254)
  254 FORMAT('      FREQUENCIES ARE TO BE FOUND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,255)
  255 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,256)
  256 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,257)ND
  257 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
!
  290 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF FREQUE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NX,ND,NY
 9013   FORMAT('IERROR,NX,ND,NY = ',A4,2X,3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),D(I),Y(I)
 9016     FORMAT('I,X(I),D(I),Y(I) = ',I8,3E15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE FREQUE
      SUBROUTINE FSTOCD (N, X, SX, RNOISE, G)
!CCCC SUBROUTINE FSTOCD (N, X, OPTFCN, SX, RNOISE, G)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
! PURPOSE
! -------
! FIND CENTRAL DIFFERENCE APPROXIMATION G TO THE FIRST DERIVATIVE
! (GRADIENT) OF THE FUNCTION DEFINED BY FCN AT THE POINT X.
!
! PARAMETERS
! ----------
! N            --> DIMENSION OF PROBLEM
! X            --> POINT AT WHICH GRADIENT IS TO BE APPROXIMATED.
! FCN          --> NAME OF SUBROUTINE TO EVALUATE FUNCTION.
! SX           --> DIAGONAL SCALING MATRIX FOR X.
! RNOISE       --> RELATIVE NOISE IN FCN [F(X)].
! G           <--  CENTRAL DIFFERENCE APPROXIMATION TO GRADIENT.
!
!
      DIMENSION X(N)
      DIMENSION SX(N)
      DIMENSION G(N)
      DIMENSION FHAT(1)
!
! FIND I TH  STEPSIZE, EVALUATE TWO NEIGHBORS IN DIRECTION OF I TH
! UNIT VECTOR, AND EVALUATE I TH  COMPONENT OF GRADIENT.
!
      THIRD = 1.0/3.0
      DO 10 I = 1, N
         STEPI = RNOISE**THIRD * MAX(ABS(X(I)), 1.0/SX(I))
         XTEMPI = X(I)
         X(I) = XTEMPI + STEPI
         CALL OPTFCN (N, X, FHAT)
         FPLUS=FHAT(1)
         X(I) = XTEMPI - STEPI
         CALL OPTFCN (N, X, FHAT)
         FMINUS=FHAT(1)
         X(I) = XTEMPI
         G(I) = (FPLUS - FMINUS)/(2.0*STEPI)
   10 CONTINUE
      RETURN
      END SUBROUTINE FSTOCD 
      SUBROUTINE FSTOFD(NR,M,N,XPLS,FPLS,A,SX,RNOISE,FHAT,   &
      ICASE)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
! PURPOSE
! -------
! FIND FIRST ORDER FORWARD FINITE DIFFERENCE APPROXIMATION "A" TO THE
! FIRST DERIVATIVE OF THE FUNCTION DEFINED BY THE SUBPROGRAM "FNAME"
! EVALUATED AT THE NEW ITERATE "XPLS".
!
!
! FOR OPTIMIZATION USE THIS ROUTINE TO ESTIMATE:
! 1) THE FIRST DERIVATIVE (GRADIENT) OF THE OPTIMIZATION FUNCTION "FCN
!    ANALYTIC USER ROUTINE HAS BEEN SUPPLIED;
! 2) THE SECOND DERIVATIVE (HESSIAN) OF THE OPTIMIZATION FUNCTION
!    IF NO ANALYTIC USER ROUTINE HAS BEEN SUPPLIED FOR THE HESSIAN BUT
!    ONE HAS BEEN SUPPLIED FOR THE GRADIENT ("FCN") AND IF THE
!    OPTIMIZATION FUNCTION IS INEXPENSIVE TO EVALUATE
!
! NOTE
! ----
! _M=1 (OPTIMIZATION) ALGORITHM ESTIMATES THE GRADIENT OF THE FUNCTION
!      (FCN).   FCN(X) # F: R(N)-->R(1)
! _M=N (SYSTEMS) ALGORITHM ESTIMATES THE JACOBIAN OF THE FUNCTION
!      FCN(X) # F: R(N)-->R(N).
! _M=N (OPTIMIZATION) ALGORITHM ESTIMATES THE HESSIAN OF THE OPTIMIZATIO
!      FUNCTION, WHERE THE HESSIAN IS THE FIRST DERIVATIVE OF "FCN"
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! M            --> NUMBER OF ROWS IN A
! N            --> NUMBER OF COLUMNS IN A; DIMENSION OF PROBLEM
! XPLS(N)      --> NEW ITERATE:  X[K]
! OPTFCN       --> NAME OF SUBROUTINE TO EVALUATE FUNCTION
! FPLS(M)      --> _M=1 (OPTIMIZATION) FUNCTION VALUE AT NEW ITERATE:
!                       FCN(XPLS)
!                  _M=N (OPTIMIZATION) VALUE OF FIRST DERIVATIVE
!                       (GRADIENT) GIVEN BY USER FUNCTION FCN
!                  _M=N (SYSTEMS)  FUNCTION VALUE OF ASSOCIATED
!                       MINIMIZATION FUNCTION
! A(NR,N)     <--  FINITE DIFFERENCE APPROXIMATION (SEE NOTE).  ONLY
!                  LOWER TRIANGULAR MATRIX AND DIAGONAL ARE RETURNED
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! RNOISE       --> RELATIVE NOISE IN FCN [F(X)]
! FHAT(M)      --> WORKSPACE
! ICASE        --> =1 OPTIMIZATION (GRADIENT)
!                  =2 SYSTEMS
!                  =3 OPTIMIZATION (HESSIAN)
!
! INTERNAL VARIABLES
! ------------------
! STEPSZ - STEPSIZE IN THE J-TH VARIABLE DIRECTION
!
!DPLT DIMENSION XPLS(N),FPLS(M)
!DPLT DIMENSION FHAT(M)
!DPLT DIMENSION SX(N)
      DIMENSION XPLS(*),FPLS(*)
      DIMENSION FHAT(*)
      DIMENSION SX(*)
      DIMENSION A(NR,1)
!DPLT EXTERNAL OPTFCN
!
! FIND J-TH COLUMN OF A
! EACH COLUMN IS DERIVATIVE OF F(FCN) WITH RESPECT TO XPLS(J)
!
      DO 30 J=1,N
        STEPSZ=SQRT(RNOISE)*MAX(ABS(XPLS(J)),1.D0/SX(J))
        XTMPJ=XPLS(J)
        XPLS(J)=XTMPJ+STEPSZ
        CALL OPTFCN(N,XPLS,FHAT)
        XPLS(J)=XTMPJ
        DO 20 I=1,M
          A(I,J)=(FHAT(I)-FPLS(I))/STEPSZ
   20   CONTINUE
   30 CONTINUE
      IF(ICASE.NE.3) RETURN
!
! IF COMPUTING HESSIAN, A MUST BE SYMMETRIC
!
      IF(N.EQ.1) RETURN
      NM1=N-1
      DO 50 J=1,NM1
        JP1=J+1
        DO 40 I=JP1,M
          A(I,J)=(A(I,J)+A(J,I))/2.0D0
   40   CONTINUE
   50 CONTINUE
      RETURN
      END SUBROUTINE FSTOFD
      subroutine fts(x,n,np,trend,work)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n, np
      real x(n), trend(n), work(n)
      call ma(x,n,np,trend)
      call ma(trend,n-np+1,np,work)
      call ma(work,n-2*np+2,3,trend)
      return
      end
      subroutine fexact (nrow, ncol, table, ldtabl, expect, percnt,   &
                         emin, prt, pre,   &
                         rwrk,dwrk,iwrk,iwkmax)
!-----------------------------------------------------------------------
!  Name:       FEXACT
!
!  Purpose:    Computes Fisher's exact test probabilities and a hybrid
!              approximation to Fisher exact test probabilities for a
!              contingency table using the network algorithm.
!
!  Usage:      CALL FEXACT (NROW, NCOL, TABLE, LDTABL, EXPECT, PERCNT,
!                          EMIN, PRT, PRE)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     NCOL   - The number of columns in the table.  (Input)
!     TABLE  - NROW by NCOL matrix containing the contingency table.
!              (Input)
!     LDTABL - Leading dimension of TABLE exactly as specified in the
!              dimension statement in the calling program.  (Input)
!     EXPECT - Expected value used in the hybrid algorithm for
!              deciding when to use asymptotic theory probabilities.
!              (Input)
!              If EXPECT .LE. 0.0 then asymptotic theory probabilities
!              are not used and Fisher exact test probabilities are
!              computed.  Otherwise, if PERCNT or more of the cells in
!              the remaining table have estimated expected values of
!              EXPECT or more, with no remaining cell having expected
!              value less than EMIN, then asymptotic chi-squared
!              probabilities are used.  See the algorithm section of the
!              manual document for details.  Use EXPECT = 5.0 to obtain
!              the 'Cochran' condition.
!     PERCNT - Percentage of remaining cells that must have estimated
!              expected  values greater than EXPECT before asymptotic
!              probabilities can be used.  (Input)
!              See argument EXPECT for details.  Use PERCNT = 80.0 to
!              obtain the 'Cochran' condition.
!     EMIN   - Minimum cell estimated expected value allowed for
!              asymptotic chi-squared probabilities to be used.  (Input)
!              See argument EXPECT for details.  Use EMIN = 1.0 to
!              obtain the 'Cochran' condition.
!     PRT    - Probability of the observed table for fixed marginal
!              totals.  (Output)
!     PRE    - Table p-value.  (Output)
!              PRE is the probability of a more extreme table, where
!              'extreme' is in a probabilistic sense.
!              If EXPECT .LT. 0 then the Fisher exact probability
!              is returned.  Otherwise, an approximation to the
!              Fisher exact probability is computed based upon
!              asymptotic chi-squared probabilities for ``large''
!              table expected values.  The user defines ``large''
!              through the arguments EXPECT, PERCNT, and EMIN.
!
!  Remarks:
!  1. For many problems one megabyte or more of workspace can be
!     required.  If the environment supports it, the user should begin
!     by increasing the workspace used to 200,000 units.
!
!  2. In FEXACT, LDSTP = 30*LDKEY.  The proportion of table space used
!     by STP may be changed by changing the line MULT = 30 below to
!     another value.
!
!  3. FEXACT may be converted to single precision by setting IREAL = 3,
!     and converting all DOUBLE PRECISION specifications (except the
!     specifications for RWRK, IWRK, and DWRK) to REAL.  This will
!     require changing the names and specifications of the intrinsic
!     functions LOG, AMAX1, AMIN1, EXP, and REAL.  In addition, the
!     machine specific constants will need to be changed, and the name
!     DWRK will need to be changed to RWRK in the call to F2XACT.
!
!  4. Machine specific constants are specified and documented in F2XACT.
!     A missing value code is specified in both FEXACT and F2XACT.
!
!  5. Although not a restriction, is is not generally practical to call
!     this routine with large tables which are not sparse and in
!     which the 'hybrid' algorithm has little effect.  For example,
!     although it is feasible to compute exact probabilities for the
!     table
!            1 8 5 4 4 2 2
!            5 3 3 4 3 1 0
!           10 1 4 0 0 0 0,
!     computing exact probabilities for a similar table which has been
!     enlarged by the addition of an extra row (or column) may not be
!     feasible.
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, ncol, ldtabl
      double precision expect, percnt, emin, prt, pre, table(ldtabl,*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, i1, i10, i2, i3, i3a, i3b, i3c, i4, i5, i6, i7,   &
                 i8, i9, i9a, iiwk, ireal, irwk, iwkmax, iwkpt,   &
                 j, k, kk, ldkey, ldstp, mult, nco, nro,   &
                 ntot, numb
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  max0
!cccc integer    max0
!                                  SPECIFICATIONS FOR SUBROUTINES
!cccc external   prterr, f2xact
      external   f2xact
!                                  SPECIFICATIONS FOR FUNCTIONS
      external   iwork
      integer    iwork
!***********************************************************************
!                                  To increase workspace, increase the
!                                  size of of rwrk and set the value of
!                                  IWKMAX to the new dimension
!
!                                  When changing precision, the
!                                  following declarations should not be
!                                  changed.
!***********************************************************************
!cccc real       rwrk(200000)
!cccc double precision dwrk(100000)
!cccc integer    iwrk(100000)
!cccc equivalence (rwrk(1), iwrk(1)), (rwrk(1),dwrk(1))
      real rwrk(*)
      double precision dwrk(*)
      integer iwrk(*)
!                                  Set workspace size
      INCLUDE 'DPCOP2.INC'
!
      RWRK(1)=0.0
!cccc iwkmax = 200000
!
!***********************************************************************
!                                  To increase the length of the table
!                                  of paste path lengths relative to the
!                                  length of the hash table,  increase
!                                  MULT
!***********************************************************************
      mult   = 30
!***********************************************************************
!                                  Set IREAL = 4 for DOUBLE PRECISION
!                                  Set IREAL = 3 for SINGLE PRECISION
!***********************************************************************
      ireal  = 4
!***********************************************************************
!                                  AMISS is a missing value indicator
!                                  which is returned when the
!                                  probability is not defined.
!***********************************************************************
      amiss = -12345.0d0
!
      iwkpt  = 1
!
!CCCC print *,'fexact: nrow,ncol,ldtabl=',nrow,ncol,ldtabl
!CCCC print *,'table(1,1) = ',table(1,1)
!CCCC print *,'table(2,1) = ',table(2,1)
!CCCC print *,'table(1,2) = ',table(1,2)
!CCCC print *,'table(2,2) = ',table(2,2)
!CCCC print *,'expect,percnt,emin=',expect,percnt,emin
!
      if (nrow .gt. ldtabl) then
!CCCC    call prterr (1, 'NROW must be less than or equal to '//
!CCCC&               'LDTABL.')
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** ERROR FROM FEXACT.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)
 9013 FORMAT('      NROW must be less than or equal to LDTABL.')
      CALL DPWRST('XXX','BUG ')
      end if
      ntot = 0
      do 20  i=1, nrow
         do 10  j=1, ncol
            if (table(i,j) .lt. 0) then
!CCCC          call prterr (2, 'All elements of TABLE must '//
!CCCC&                     'be positive.')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9113)
 9113 FORMAT('      All elements of TABLE must be non-negative.')
      CALL DPWRST('XXX','BUG ')
            end if
            ntot = ntot + int(table(i,j))
   10    continue
   20 continue
      if (ntot .eq. 0) then
!cccc    call prterr (3, 'All elements of TABLE are zero.  '//
!cccc&               'PRT and PRE are set to missing values '//
!cccc&               '(NaN, not a number).')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9213)
 9213 FORMAT('      All elements of TABLE are zero.  PRT and PRE are')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9215)
 9215 FORMAT('      set to missing values (NaN, not a number).')
      CALL DPWRST('XXX','BUG ')
         prt = amiss
         pre = amiss
         go to 9000
      end if
!
      nco = max0(nrow,ncol)
      nro = nrow + ncol - nco
      k   = nrow + ncol + 1
      kk  = k*max0(nrow,ncol)
!
      i1   = iwork(iwkmax,iwkpt,ntot+1,ireal)
      i2   = iwork(iwkmax,iwkpt,nco,2)
      i3   = iwork(iwkmax,iwkpt,nco,2)
      i3a  = iwork(iwkmax,iwkpt,nco,2)
      i3b  = iwork(iwkmax,iwkpt,nro,2)
      i3c  = iwork(iwkmax,iwkpt,nro,2)
      iiwk = iwork(iwkmax,iwkpt,max0(5*k+2*kk,800+7*max0(nrow,ncol)),2)
      irwk = iwork(iwkmax,iwkpt,max0(400+max0(nrow,ncol)+1,k),ireal)
!                                  Double precision
      if (ireal .eq. 4) then
         numb  = 18 + 10*mult
         ldkey = (iwkmax-iwkpt+1)/numb
      else
!                                  Real workspace
         numb  = 12 + 8*mult
         ldkey = (iwkmax-iwkpt+1)/numb
      end if
!
      ldstp = mult*ldkey
      i4    = iwork(iwkmax,iwkpt,2*ldkey,2)
      i5    = iwork(iwkmax,iwkpt,2*ldkey,2)
      i6    = iwork(iwkmax,iwkpt,2*ldstp,ireal)
      i7    = iwork(iwkmax,iwkpt,6*ldstp,2)
      i8    = iwork(iwkmax,iwkpt,2*ldkey,ireal)
      i9    = iwork(iwkmax,iwkpt,2*ldkey,ireal)
      i9a   = iwork(iwkmax,iwkpt,2*ldkey,ireal)
      i10   = iwork(iwkmax,iwkpt,2*ldkey,2)
!***********************************************************************
!                                  To convert to double precision,
!                                  change RWRK to WWRK in the next CALL
!***********************************************************************
!
      call f2xact (nrow, ncol, table, ldtabl, expect, percnt, emin,   &
                   prt, pre, dwrk(i1), iwrk(i2), iwrk(i3), iwrk(i3a),   &
                   iwrk(i3b), iwrk(i3c), iwrk(i4), ldkey, iwrk(i5),   &
                   dwrk(i6), ldstp, iwrk(i7), dwrk(i8), dwrk(i9),   &
                   dwrk(i9a), iwrk(i10), iwrk(iiwk), dwrk(irwk))
!
 9000 return
      end
      subroutine f2xact (nrow, ncol, table, ldtabl, expect, percnt,   &
                         emin, prt, pre, fact, ico, iro, kyy, idif,   &
                         irn, key, ldkey, ipoin, stp, ldstp, ifrq,   &
                         dlp, dsp, tm, key2, iwk, rwk)
!-----------------------------------------------------------------------
!  Name:       F2XACT
!
!  Purpose:    Computes Fisher's exact test for a contingency table,
!              routine with workspace variables specified.
!
!  Usage:      CALL F2XACT (NROW, NCOL, TABLE, LDTABL, EXPECT, PERCNT,
!                          EMIN, PRT, PRE, FACT, ICO, IRO, KYY, IDIF,
!                          IRN, KEY, LDKEY, IPOIN, STP, LDSTP, IFRQ,
!                          DLP, DSP, TM, KEY2, IWK, RWK)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, ncol, ldtabl, ldkey, ldstp, ico(*), iro(*),   &
                 kyy(*), idif(*), irn(*), key(*), ipoin(*), ifrq(*),   &
                 key2(*), iwk(*)
      double precision expect, percnt, emin, prt, pre, table(ldtabl,*),   &
                 fact(0:*), stp(*), dlp(*), dsp(*), tm(*), rwk(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, i31, i310, i311, i32, i33, i34, i35, i36, i37,   &
                 i38, i39, i41, i42, i43, i44, i45, i46, i47, i48,   &
                 iflag, ifreq, ii, ikkey, ikstp, ikstp2, ipn, ipo,   &
                 itmp, itop, itp, j, jkey, jstp, jstp2, jstp3, jstp4,   &
                 k, k1, kb, kd, kmax, ks, kval, last, n, ncell, nco,   &
                 nrb, nro, nro2, ntot, ifault, imax
      double precision dd, ddf, df, drn, dro, dspt, emn, obs, obs2,   &
                 obs3, pastp, pv, tmp, tol
      logical    chisq, ipsh
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  dlog, dmax1, dmin1, dexp, max0, min0, mod, nint, dble
!cccc integer    max0, min0, mod, nint
!cccc double precision dlog, dmax1, dmin1, dexp, dble
!                                  SPECIFICATIONS FOR SUBROUTINES
!cccc external   prterr, f3xact, f4xact, f5xact, f6xact, f7xact, isort
      external   f3xact, f4xact, f5xact, f6xact, f7xact, isort
!                                  SPECIFICATIONS FOR FUNCTIONS
      external   f9xact, gammds
      double precision f9xact, gammds
!
      INCLUDE 'DPCOP2.INC'
!
!***********************************************************************
!                                  IMAX is the largest representable
!                                  integer on the machine
!***********************************************************************
      data imax/2147483647/
!***********************************************************************
!                                  AMISS is a missing value indicator
!                                  which is returned when the
!                                  probability is not defined.
!***********************************************************************
      data amiss/-12345.0d0/
!***********************************************************************
!                                  TOL is chosen as the square root of
!                                  the smallest relative spacing
!***********************************************************************
      data tol/3.45254d-07/
!***********************************************************************
!                                  EMX is a large positive value used
!                                  in comparing expected values
!***********************************************************************
      data emx/1.0d30/
!                                  Initialize KEY array
      chisq = .true.
      tmp=0.0d0
!
      do 10  i=1, 2*ldkey
         key(i)  = -9999
         key2(i) = -9999
   10 continue
!                                  Initialize parameters
      pre  = 0.0
      itop = 0
      if (expect .gt. 0.0d0) then
         emn = emin
      else
         emn = emx
      end if
!                                  Initialize pointers for workspace
      k = max0(nrow,ncol)
!                                  f3xact
      i31  = 1
      i32  = i31 + k
      i33  = i32 + k
      i34  = i33 + k
      i35  = i34 + k
      i36  = i35 + k
      i37  = i36 + k
      i38  = i37 + k
      i39  = i38 + 400
      i310 = 1
      i311 = 401
!                                  f4xact
      k   = nrow + ncol + 1
      i41 = 1
      i42 = i41 + k
      i43 = i42 + k
      i44 = i43 + k
      i45 = i44 + k
      i46 = i45 + k
      i47 = i46 + k*max0(nrow,ncol)
      i48 = 1
!                                  Check table dimensions
      if (nrow .gt. ldtabl) then
!CCCC    call prterr (1, 'NROW must be less than or equal to '//
!CCCC&               'LDTABL.')
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
 9011    FORMAT('***** ERROR IN F2XACT--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9013)
 9013    FORMAT('      NROW must be less than or equal to LDTABL.')
         CALL DPWRST('XXX','BUG ')
      end if
      if (ncol .le. 1) then
!cccc    call prterr (4, 'NCOL must be greater than 1.0.')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9113)
 9113    FORMAT('      NCOL must be greater than 1.0.')
         CALL DPWRST('XXX','BUG ')
      end if
!                                  Compute row marginals and total
      ntot = 0
      do 30  i=1, nrow
         iro(i) = 0
         do 20  j=1, ncol
            if (table(i,j) .lt. -0.0001d0) then
!CCCC          call prterr (2, 'All elements of TABLE must be '//
!CCCC&                     'positive.')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9123)
 9123    FORMAT('       All elements of TABLE must be positive.')
         CALL DPWRST('XXX','BUG ')
            end if
            iro(i) = iro(i) + nint(table(i,j))
            ntot   = ntot + nint(table(i,j))
   20    continue
   30 continue
!
      if (ntot .eq. 0) then
!CCCC    call prterr (3, 'All elements of TABLE are zero.  '//
!CCCC&               'PRT and PRE are set to missing values '//
!CCCC&               '(NaN, not a number).')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9133)
 9133    FORMAT('       All elements of TABLE are zero.  PRT and PRE')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9135)
 9135    FORMAT('       are set to missing values (NaN, not a ',   &
                'number).')
         CALL DPWRST('XXX','BUG ')
         prt = amiss
         pre = amiss
         go to 9000
      end if
!                                  Column marginals
      do 50  i=1, ncol
         ico(i) = 0
         do 40  j=1, nrow
            ico(i) = ico(i) + nint(table(j,i))
   40    continue
   50 continue
!                                  sort
      call isort (nrow, iro)
      call isort (ncol, ico)
!                                  Determine row and column marginals
!
      if (nrow .gt. ncol) then
         nro = ncol
         nco = nrow
!                                  Interchange row and column marginals
         do 60  i=1, nrow
            itmp = iro(i)
            if (i .le. ncol) iro(i) = ico(i)
            ico(i) = itmp
   60    continue
      else
         nro = nrow
         nco = ncol
      end if
!
!                                  Get multiplers for stack
      kyy(1) = 1
      do 70  i=2, nro
!                                  Hash table multipliers
         if (iro(i-1)+1 .le. imax/kyy(i-1)) then
            kyy(i) = kyy(i-1)*(iro(i-1)+1)
            j      = j/kyy(i-1)
         else
!CCCC       call prterr (5, 'The hash table key cannot be computed'//
!CCCC&                  ' because the largest key is larger than the'//
!CCCC&                  ' largest representable integer.  The '//
!CCCC&                  'algorithm cannot proceed.')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9143)
 9143    FORMAT('       The hash table key cannot be computed because')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9145)
 9145    FORMAT('       the largest key is larger than the largest')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9147)
 9147    FORMAT('       representable integer.  The algorithm cannot',   &
                ' proceed.')
         CALL DPWRST('XXX','BUG ')
         end if
   70 continue
!                                  Maximum product
      if (iro(nro-1)+1 .le. imax/kyy(nro-1)) then
         kmax = (iro(nro)+1)*kyy(nro-1)
      else
!cccc    call prterr (5, 'The hash table key cannot be computed'//
!cccc&               ' because the largest key is larger than the'//
!cccc&               ' largest representable integer.  The '//
!cccc&               'algorithm cannot proceed.')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9143)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9145)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9147)
         CALL DPWRST('XXX','BUG ')
         go to 9000
      end if
!                                  Compute log factorials
      fact(0) = 0.0d0
      fact(1) = 0.0d0
      fact(2) = dlog(2.0d0)
      do 80  i=3, ntot, 2
         fact(i) = fact(i-1) + dlog(dble(i))
         j       = i + 1
         if (j .le. ntot) fact(j) = fact(i) + fact(2) + fact(j/2) -   &
             fact(j/2-1)
   80 continue
!                                  Compute observed path length: OBS
      obs  = tol
      ntot = 0
      do 100  j=1, nco
         dd = 0.0
         do 90  i=1, nro
            if (nrow .le. ncol) then
               dd   = dd + fact(nint(table(i,j)))
               ntot = ntot + nint(table(i,j))
            else
               dd   = dd + fact(nint(table(j,i)))
               ntot = ntot + nint(table(j,i))
            end if
   90    continue
         obs = obs + fact(ico(j)) - dd
  100 continue
!                                  Denominator of observed table: DRO
      dro = f9xact(nro,ntot,iro,fact)
      prt = dexp(obs-dro)
!                                  Initialize pointers
      k        = nco
      last     = ldkey + 1
      jkey     = ldkey + 1
      jstp     = ldstp + 1
      jstp2    = 3*ldstp + 1
      jstp3    = 4*ldstp + 1
      jstp4    = 5*ldstp + 1
      ikkey    = 0
      ikstp    = 0
      ikstp2   = 2*ldstp
      ipo      = 1
      ipoin(1) = 1
      stp(1)   = 0.0
      ifrq(1)  = 1
      ifrq(ikstp2+1) = -1
!
  110 kb = nco - k + 1
      ks   = 0
      n    = ico(kb)
      kd   = nro + 1
      kmax = nro
!                                  IDIF is the difference in going to th
!                                  daughter
      do 120  i=1, nro
         idif(i) = 0
  120 continue
!                                  Generate the first daughter
  130 kd = kd - 1
      ntot     = min0(n,iro(kd))
      idif(kd) = ntot
      if (idif(kmax) .eq. 0) kmax = kmax - 1
      n = n - ntot
      if (n.gt.0 .and. kd.ne.1) go to 130
      if (n .ne. 0) go to 310
!
      k1   = k - 1
      n    = ico(kb)
      ntot = 0
      do 140  i=kb + 1, nco
         ntot = ntot + ico(i)
  140 continue
!                                  Arc to daughter length=ICO(KB)
  150 do 160  i=1, nro
         irn(i) = iro(i) - idif(i)
  160 continue
!                                  Sort irn
      if (k1 .gt. 1) then
         if (nro .eq. 2) then
            if (irn(1) .gt. irn(2)) then
               ii     = irn(1)
               irn(1) = irn(2)
               irn(2) = ii
            end if
         else if (nro .eq. 3) then
            ii = irn(1)
            if (ii .gt. irn(3)) then
               if (ii .gt. irn(2)) then
                  if (irn(2) .gt. irn(3)) then
                     irn(1) = irn(3)
                     irn(3) = ii
                  else
                     irn(1) = irn(2)
                     irn(2) = irn(3)
                     irn(3) = ii
                  end if
               else
                  irn(1) = irn(3)
                  irn(3) = irn(2)
                  irn(2) = ii
               end if
            else if (ii .gt. irn(2)) then
               irn(1) = irn(2)
               irn(2) = ii
            else if (irn(2) .gt. irn(3)) then
               ii     = irn(2)
               irn(2) = irn(3)
               irn(3) = ii
            end if
         else
            do 180  j=2, nro
               i  = j - 1
               ii = irn(j)
  170          if (ii .lt. irn(i)) then
                  irn(i+1) = irn(i)
                  i        = i - 1
                  if (i .gt. 0) go to 170
               end if
               irn(i+1) = ii
  180       continue
         end if
!                                  Adjust start for zero
         do 190  i=1, nro
            if (irn(i) .ne. 0) go to 200
  190    continue
  200    nrb = i
         nro2 = nro - i + 1
      else
         nrb  = 1
         nro2 = nro
      end if
!                                  Some table values
      ddf = f9xact(nro,n,idif,fact)
      drn = f9xact(nro2,ntot,irn(nrb),fact) - dro + ddf
!                                  Get hash value
      if (k1 .gt. 1) then
         kval = irn(1) + irn(2)*kyy(2)
         do 210  i=3, nro
            kval = kval + irn(i)*kyy(i)
  210    continue
!                                  Get hash table entry
         i = mod(kval,2*ldkey) + 1
!                                  Search for unused location
         do 220  itp=i, 2*ldkey
            ii = key2(itp)
            if (ii .eq. kval) then
               go to 240
            else if (ii .lt. 0) then
               key2(itp) = kval
               dlp(itp)  = 1.0d0
               dsp(itp)  = 1.0d0
               go to 240
            end if
  220    continue
!
         do 230  itp=1, i - 1
            ii = key2(itp)
            if (ii .eq. kval) then
               go to 240
            else if (ii .lt. 0) then
               key2(itp) = kval
               dlp(itp)  = 1.0
               go to 240
            end if
  230    continue
!
!cccc    call prterr (6, 'LDKEY is too small.  It is not possible to '//
!cccc&               'give thevalue of LDKEY required, but you could '//
!cccc&               'try doubling LDKEY (and possibly LDSTP).')
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9153)
 9153    FORMAT('        LDKEY is too small.  It is not possible to ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9155)
 9155    FORMAT('        give the value of LDKEY required, but you')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9157)
 9157    FORMAT('        could try doubling LDKEY (and possibly ',   &
                'LDSTP).')
         CALL DPWRST('XXX','BUG ')
      end if
!
  240 ipsh = .true.
!                                  Recover pastp
      ipn   = ipoin(ipo+ikkey)
      pastp = stp(ipn+ikstp)
      ifreq = ifrq(ipn+ikstp)
!                                  Compute shortest and longest path
      if (k1 .gt. 1) then
         obs2 = obs - fact(ico(kb+1)) - fact(ico(kb+2)) - ddf
         do 250  i=3, k1
            obs2 = obs2 - fact(ico(kb+i))
  250    continue
!
         if (dlp(itp) .gt. 0.0d0) then
            dspt = obs - obs2 - ddf
!                                  Compute longest path
            dlp(itp) = 0.0d0
            call f3xact (nro2, irn(nrb), k1, ico(kb+1), dlp(itp),   &
                         ntot, fact, iwk(i31), iwk(i32), iwk(i33),   &
                         iwk(i34), iwk(i35), iwk(i36), iwk(i37),   &
                         iwk(i38), iwk(i39), rwk(i310), rwk(i311), tol)
            dlp(itp) = dmin1(0.0d0,dlp(itp))
!                                  Compute shortest path
            dsp(itp) = dspt
            call f4xact (nro2, irn(nrb), k1, ico(kb+1), dsp(itp),   &
                         fact, iwk(i47), iwk(i41), iwk(i42), iwk(i43),   &
                         iwk(i44), iwk(i45), iwk(i46), rwk(i48), tol)
            dsp(itp) = dmin1(0.0d0,dsp(itp)-dspt)
!                                  Use chi-squared approximation?
            if (dble(irn(nrb)*ico(kb+1))/dble(ntot) .gt. emn) then
               ncell = 0
               do 270  i=1, nro2
                  do 260  j=1, k1
                     if (irn(nrb+i-1)*ico(kb+j) .ge. ntot*expect) then
                        ncell = ncell + 1
                     end if
  260             continue
  270          continue
               if (ncell*100 .ge. k1*nro2*percnt) then
                  tmp = 0.0
                  do 280  i=1, nro2
                     tmp = tmp + fact(irn(nrb+i-1)) -   &
                           fact(irn(nrb+i-1)-1)
  280             continue
                  tmp = tmp*(k1-1)
                  do 290  j=1, k1
                     tmp = tmp + (nro2-1)*(fact(ico(kb+j))-fact(ico(kb+   &
                           j)-1))
  290             continue
                  df      = (nro2-1)*(k1-1)
                  tmp     = tmp + df*1.83787706640934548356065947281d0
                  tmp     = tmp - (nro2*k1-1)*(fact(ntot)-fact(ntot-1))
                  tm(itp) = -2.0d0*(obs-dro) - tmp
               else
!                                  tm(itp) set to a flag value
                  tm(itp) = -9876.0d0
               end if
            else
               tm(itp) = -9876.0d0
            end if
         end if
         obs3 = obs2 - dlp(itp)
         obs2 = obs2 - dsp(itp)
         if (tm(itp) .eq. -9876.0d0) then
            chisq = .false.
         else
            chisq = .true.
            tmp   = tm(itp)
         end if
      else
         obs2 = obs - drn - dro
         obs3 = obs2
      end if
!                                  Process node with new PASTP
  300 if (pastp .le. obs3) then
!                                  Update pre
         pre = pre + dble(ifreq)*dexp(pastp+drn)
!
      else if (pastp .lt. obs2) then
         if (chisq) then
            df  = (nro2-1)*(k1-1)
            pv  = 1.0 - gammds(dmax1(0.0d0,tmp+2.0d0*(pastp+drn))/   &
                  2.0d0,df/2.0d0,ifault)
            pre = pre + dble(ifreq)*dexp(pastp+drn)*pv
         else
!                                  Put daughter on queue
            call f5xact (pastp+ddf, tol, kval, key(jkey), ldkey,   &
                         ipoin(jkey), stp(jstp), ldstp, ifrq(jstp),   &
                         ifrq(jstp2), ifrq(jstp3), ifrq(jstp4), ifreq,   &
                         itop, ipsh)
            ipsh = .false.
         end if
      end if
!                                  Get next PASTP on chain
      ipn = ifrq(ipn+ikstp2)
      if (ipn .gt. 0) then
         pastp = stp(ipn+ikstp)
         ifreq = ifrq(ipn+ikstp)
         go to 300
      end if
!                                  Generate a new daughter node
      call f7xact (kmax, iro, idif, kd, ks, iflag)
      if (iflag .ne. 1) go to 150
!                                  Go get a new mother from stage K
  310 iflag = 1
      call f6xact (nro, iro, iflag, kyy, key(ikkey+1), ldkey, last,   &
                   ipo)
!                                  Update pointers
      if (iflag .eq. 3) then
         k      = k - 1
         itop   = 0
         ikkey  = jkey - 1
         ikstp  = jstp - 1
         ikstp2 = jstp2 - 1
         jkey   = ldkey - jkey + 2
         jstp   = ldstp - jstp + 2
         jstp2  = 2*ldstp + jstp
         do 320  i=1, 2*ldkey
            key2(i) = -9999
  320    continue
         if (k .ge. 2) go to 310
      else
         go to 110
      end if
!
 9000 return
      end
      subroutine f3xact (nrow, irow, ncol, icol, dlp, mm, fact, ico,   &
                         iro, it, lb, nr, nt, nu, itc, ist, stv, alen,   &
                         tol)
!-----------------------------------------------------------------------
!  Name:       F3XACT
!
!  Purpose:    Computes the shortest path length for a given table.
!
!  Usage:      CALL F3XACT (NROW, IROW, NCOL, ICOL, DLP, MM, FACT, ICO,
!                          IRO, IT, LB, NR, NT, NU, ITC, IST, STV, ALEN,
!                          TOL)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     IROW   - Vector of length NROW containing the row sums for the
!              table.  (Input)
!     NCOL   - The number of columns in the table.  (Input)
!     ICOL   - Vector of length K containing the column sums for the
!              table.  (Input)
!     DLP    - The longest path for the table.  (Output)
!     MM     - The total count in the table.  (Output)
!     FACT   - Vector containing the logarithms of factorials.  (Input)
!     ICO    - Work vector of length MAX(NROW,NCOL).
!     IRO    - Work vector of length MAX(NROW,NCOL).
!     IT     - Work vector of length MAX(NROW,NCOL).
!     LB     - Work vector of length MAX(NROW,NCOL).
!     NR     - Work vector of length MAX(NROW,NCOL).
!     NT     - Work vector of length MAX(NROW,NCOL).
!     NU     - Work vector of length MAX(NROW,NCOL).
!     ITC    - Work vector of length 400.
!     IST    - Work vector of length 400.
!     STV    - Work vector of length 400.
!     ALEN   - Work vector of length MAX(NROW,NCOL).
!     TOL    - Tolerance.  (Input)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, ncol, mm, irow(*), icol(*), ico(*), iro(*),   &
                 it(*), lb(*), nr(*), nt(*), nu(*), itc(*), ist(*)
      double precision dlp, tol, fact(0:*), stv(*), alen(0:*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, ic1, ic2, ii, ipn, irl, itp, k, key, ks, kyy, lev,   &
                 n11, n12, nc1, nc1s, nco, nct, nn, nn1, nr1, nro, nrt
      double precision v, val, vmn
      logical    xmin
!                                  SPECIFICATIONS FOR SAVE VARIABLES
      integer    ldst, nitc, nst
      save       ldst, nitc, nst
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  dmin1, int, mod, dble
!cccc integer    int, mod
!cccc double precision dmin1, dble
!                                  SPECIFICATIONS FOR SUBROUTINES
!cccc external   prterr, f10act, isort
      external   f10act, isort
!
      INCLUDE 'DPCOP2.INC'
!
!***********************************************************************
!
      data ldst/200/, nst/0/, nitc/0/
!
      do 10  i=0, ncol
         alen(i) = 0.0
   10 continue
      do 20  i=1, 400
         ist(i) = -1
   20 continue
!                                  nrow is 1
      if (nrow .le. 1) then
         if (nrow .gt. 0) then
            dlp = dlp - fact(icol(1))
            do 30  i=2, ncol
               dlp = dlp - fact(icol(i))
   30       continue
         end if
         go to 9000
      end if
!                                  ncol is 1
      if (ncol .le. 1) then
         if (ncol .gt. 0) then
            dlp = dlp - fact(irow(1)) - fact(irow(2))
            do 40  i=3, nrow
               dlp = dlp - fact(irow(i))
   40       continue
         end if
         go to 9000
      end if
!                                  2 by 2 table
      if (nrow*ncol .eq. 4) then
         n11 = (irow(1)+1)*(icol(1)+1)/(mm+2)
         n12 = irow(1) - n11
         dlp = dlp - fact(n11) - fact(n12) - fact(icol(1)-n11) -   &
               fact(icol(2)-n12)
         go to 9000
      end if
!                                  Test for optimal table
      val  = 0.0
      xmin = .false.
      if (irow(nrow) .le. irow(1)+ncol) then
         call f10act (nrow, irow, ncol, icol, val, xmin, fact, lb, nu,   &
                      nr)
      end if
      if (.not.xmin) then
         if (icol(ncol) .le. icol(1)+nrow) then
            call f10act (ncol, icol, nrow, irow, val, xmin, fact, lb,   &
                         nu, nr)
         end if
      end if
!
      if (xmin) then
         dlp = dlp - val
         go to 9000
      end if
!                                  Setup for dynamic programming
      nn = mm
!                                  Minimize ncol
      if (nrow .ge. ncol) then
         nro = nrow
         nco = ncol
!
         do 50  i=1, nrow
            iro(i) = irow(i)
   50    continue
!
         ico(1) = icol(1)
         nt(1)  = nn - ico(1)
         do 60  i=2, ncol
            ico(i) = icol(i)
            nt(i)  = nt(i-1) - ico(i)
   60    continue
      else
         nro = ncol
         nco = nrow
!
         ico(1) = irow(1)
         nt(1)  = nn - ico(1)
         do 70  i=2, nrow
            ico(i) = irow(i)
            nt(i)  = nt(i-1) - ico(i)
   70    continue
!
         do 80  i=1, ncol
            iro(i) = icol(i)
   80    continue
      end if
!                                  Initialize pointers
      vmn  = 1.0d10
      nc1s = nco - 1
      irl  = 1
      ks   = 0
      k    = ldst
      kyy  = ico(nco) + 1
      go to 100
!                                  Test for optimality
   90 xmin = .false.
      if (iro(nro) .le. iro(irl)+nco) then
         call f10act (nro, iro(irl), nco, ico, val, xmin, fact, lb,   &
                      nu, nr)
      end if
      if (.not.xmin) then
         if (ico(nco) .le. ico(1)+nro) then
            call f10act (nco, ico, nro, iro(irl), val, xmin, fact, lb,   &
                         nu, nr)
         end if
      end if
!
      if (xmin) then
         if (val .lt. vmn) vmn = val
         go to 200
      end if
!                                  Setup to generate new node
  100 lev = 1
      nr1   = nro - 1
      nrt   = iro(irl)
      nct   = ico(1)
      lb(1) = int(dble((nrt+1)*(nct+1))/dble(nn+nr1*nc1s+1)-tol) - 1
      nu(1) = int(dble((nrt+nc1s)*(nct+nr1))/dble(nn+nr1+nc1s)) -   &
              lb(1) + 1
      nr(1) = nrt - lb(1)
!                                  Generate a node
  110 nu(lev) = nu(lev) - 1
      if (nu(lev) .eq. 0) then
         if (lev .eq. 1) go to 200
         lev = lev - 1
         go to 110
      end if
      lb(lev) = lb(lev) + 1
      nr(lev) = nr(lev) - 1
  120 alen(lev) = alen(lev-1) + fact(lb(lev))
      if (lev .lt. nc1s) then
         nn1     = nt(lev)
         nrt     = nr(lev)
         lev     = lev + 1
         nc1     = nco - lev
         nct     = ico(lev)
         lb(lev) = int(dble((nrt+1)*(nct+1))/dble(nn1+nr1*nc1+1) - tol)
         nu(lev) = int(dble((nrt+nc1)*(nct+nr1))/dble(nn1+nr1+nc1) -   &
                   lb(lev) + 1)
         nr(lev) = nrt - lb(lev)
         go to 120
      end if
      alen(nco) = alen(lev) + fact(nr(lev))
      lb(nco)   = nr(lev)
!
      v = val + alen(nco)
      if (nro .eq. 2) then
!                                  Only 1 row left
         v = v + fact(ico(1)-lb(1)) + fact(ico(2)-lb(2))
         do 130  i=3, nco
            v = v + fact(ico(i)-lb(i))
  130    continue
         if (v .lt. vmn) vmn = v
      else if (nro.eq.3 .and. nco.eq.2) then
!                                  3 rows and 2 columns
         nn1 = nn - iro(irl) + 2
         ic1 = ico(1) - lb(1)
         ic2 = ico(2) - lb(2)
         n11 = (iro(irl+1)+1)*(ic1+1)/nn1
         n12 = iro(irl+1) - n11
         v   = v + fact(n11) + fact(n12) + fact(ic1-n11) +   &
               fact(ic2-n12)
         if (v .lt. vmn) vmn = v
      else
!                                  Column marginals are new node
         do 140  i=1, nco
            it(i) = ico(i) - lb(i)
  140    continue
!                                  Sort column marginals
         if (nco .eq. 2) then
            if (it(1) .gt. it(2)) then
               ii    = it(1)
               it(1) = it(2)
               it(2) = ii
            end if
         else if (nco .eq. 3) then
            ii = it(1)
            if (ii .gt. it(3)) then
               if (ii .gt. it(2)) then
                  if (it(2) .gt. it(3)) then
                     it(1) = it(3)
                     it(3) = ii
                  else
                     it(1) = it(2)
                     it(2) = it(3)
                     it(3) = ii
                  end if
               else
                  it(1) = it(3)
                  it(3) = it(2)
                  it(2) = ii
               end if
            else if (ii .gt. it(2)) then
               it(1) = it(2)
               it(2) = ii
            else if (it(2) .gt. it(3)) then
               ii    = it(2)
               it(2) = it(3)
               it(3) = ii
            end if
         else
            call isort (nco, it)
         end if
!                                  Compute hash value
         key = it(1)*kyy + it(2)
         do 150  i=3, nco
            key = it(i) + key*kyy
  150    continue
!                                  Table index
         ipn = mod(key,ldst) + 1
!                                  Find empty position
         ii = ks + ipn
         do 160  itp=ipn, ldst
            if (ist(ii) .lt. 0) then
               go to 180
            else if (ist(ii) .eq. key) then
               go to 190
            end if
            ii = ii + 1
  160    continue
!
         ii = ks + 1
         do 170  itp=1, ipn - 1
            if (ist(ii) .lt. 0) then
               go to 180
            else if (ist(ii) .eq. key) then
               go to 190
            end if
            ii = ii + 1
  170    continue
!
!CCCC    call prterr (30, 'Stack length exceeded in f3xact.'//
!CCCC&               '  This problem should not occur.')
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
 9011    FORMAT('***** ERROR IN R3XACT--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9013)
 9013    FORMAT('      Stack length exceeded in f3xact.  This ',   &
                'problem should not occur.')
         CALL DPWRST('XXX','BUG ')
!                                  Push onto stack
  180    ist(ii) = key
         stv(ii) = v
         nst     = nst + 1
         ii      = nst + ks
         itc(ii) = itp
         go to 110
!                                  Marginals already on stack
  190    stv(ii) = dmin1(v,stv(ii))
      end if
      go to 110
!                                  Pop item from stack
  200 if (nitc .gt. 0) then
!                                  Stack index
         itp      = itc(nitc+k) + k
         nitc     = nitc - 1
         val      = stv(itp)
         key      = ist(itp)
         ist(itp) = -1
!                                  Compute marginals
         do 210  i=nco, 2, -1
            ico(i) = mod(key,kyy)
            key    = key/kyy
  210    continue
         ico(1) = key
!                                  Set up nt array
         nt(1) = nn - ico(1)
         do 220  i=2, nco
            nt(i) = nt(i-1) - ico(i)
  220    continue
         go to 90
!
      else if (nro.gt.2 .and. nst.gt.0) then
!                                  Go to next level
         nitc = nst
         nst  = 0
         k    = ks
         ks   = ldst - ks
         nn   = nn - iro(irl)
         irl  = irl + 1
         nro  = nro - 1
         go to 200
      end if
!
      dlp = dlp - vmn
 9000 return
      end
      subroutine f4xact (nrow, irow, ncol, icol, dsp, fact, icstk,   &
                         ncstk, lstk, mstk, nstk, nrstk, irstk, ystk,   &
                         tol)
!-----------------------------------------------------------------------
!  Name:       F4XACT
!
!  Purpose:    Computes the longest path length for a given table.
!
!  Usage:      CALL F4XACT (NROW, IROW, NCOL, ICOL, DSP, FACT, ICSTK,
!                          NCSTK, LSTK, MSTK, NSTK, NRSTK, IRSTK, YSTK,
!                          TOL)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     IROW   - Vector of length NROW containing the row sums for the
!              table.  (Input)
!     NCOL   - The number of columns in the table.  (Input)
!     ICOL   - Vector of length K containing the column sums for the
!              table.  (Input)
!     DSP    - The shortest path for the table.  (Output)
!     FACT   - Vector containing the logarithms of factorials.  (Input)
!     ICSTK  - NCOL by NROW+NCOL+1 work array.
!     NCSTK  - Work vector of length NROW+NCOL+1.
!     LSTK   - Work vector of length NROW+NCOL+1.
!     MSTK   - Work vector of length NROW+NCOL+1.
!     NSTK   - Work vector of length NROW+NCOL+1.
!     NRSTK  - Work vector of length NROW+NCOL+1.
!     IRSTK  - NROW by MAX(NROW,NCOL) work array.
!     YSTK   - Work vector of length NROW+NCOL+1.
!     TOL    - Tolerance.  (Input)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, ncol, irow(*), icol(*), icstk(ncol,*),   &
                 ncstk(*), lstk(*), mstk(*), nstk(*), nrstk(*),   &
                 irstk(nrow,*)
      double precision dsp, tol, fact(0:*), ystk(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, ic1, ict, ir1, irt, istk, j, k, l, m, mn, n, nco,   &
                 nro
      double precision amx, y
!                                  SPECIFICATIONS FOR SUBROUTINES
      external   f11act, f8xact
!                                  Take care of the easy cases firstkt
      if (nrow .eq. 1) then
         do 10  i=1, ncol
            dsp = dsp - fact(icol(i))
   10    continue
         go to 9000
      end if
!
      if (ncol .eq. 1) then
         do 20  i=1, nrow
            dsp = dsp - fact(irow(i))
   20    continue
         go to 9000
      end if
!
      if (nrow*ncol .eq. 4) then
         if (irow(2) .le. icol(2)) then
            dsp = dsp - fact(irow(2)) - fact(icol(1)) -   &
                  fact(icol(2)-irow(2))
         else
            dsp = dsp - fact(icol(2)) - fact(irow(1)) -   &
                  fact(irow(2)-icol(2))
         end if
         go to 9000
      end if
!                                  initialization before loop
      do 30  i=1, nrow
         irstk(i,1) = irow(nrow-i+1)
   30 continue
!
      do 40  j=1, ncol
         icstk(j,1) = icol(ncol-j+1)
   40 continue
!
      nro      = nrow
      nco      = ncol
      nrstk(1) = nro
      ncstk(1) = nco
      ystk(1)  = 0.0
      y        = 0.0
      istk     = 1
      l        = 1
      amx      = 0.0
!
   50 ir1 = irstk(1,istk)
      ic1 = icstk(1,istk)
      if (ir1 .gt. ic1) then
         if (nro .ge. nco) then
            m = nco - 1
            n = 2
         else
            m = nro
            n = 1
         end if
      else if (ir1 .lt. ic1) then
         if (nro .le. nco) then
            m = nro - 1
            n = 1
         else
            m = nco
            n = 2
         end if
      else
         if (nro .le. nco) then
            m = nro - 1
            n = 1
         else
            m = nco - 1
            n = 2
         end if
      end if
!
   60 if (n .eq. 1) then
         i = l
         j = 1
      else
         i = 1
         j = l
      end if
!
      irt = irstk(i,istk)
      ict = icstk(j,istk)
      mn  = irt
      if (mn .gt. ict) mn = ict
      y = y + fact(mn)
      if (irt .eq. ict) then
         nro = nro - 1
         nco = nco - 1
         call f11act (irstk(1,istk), i, nro, irstk(1,istk+1))
         call f11act (icstk(1,istk), j, nco, icstk(1,istk+1))
      else if (irt .gt. ict) then
         nco = nco - 1
         call f11act (icstk(1,istk), j, nco, icstk(1,istk+1))
         call f8xact (irstk(1,istk), irt-ict, i, nro, irstk(1,istk+1))
      else
         nro = nro - 1
         call f11act (irstk(1,istk), i, nro, irstk(1,istk+1))
         call f8xact (icstk(1,istk), ict-irt, j, nco, icstk(1,istk+1))
      end if
!
      if (nro .eq. 1) then
         do 70  k=1, nco
            y = y + fact(icstk(k,istk+1))
   70    continue
         go to 90
      end if
!
      if (nco .eq. 1) then
         do 80  k=1, nro
            y = y + fact(irstk(k,istk+1))
   80    continue
         go to 90
      end if
!
      lstk(istk)  = l
      mstk(istk)  = m
      nstk(istk)  = n
      istk        = istk + 1
      nrstk(istk) = nro
      ncstk(istk) = nco
      ystk(istk)  = y
      l           = 1
      go to 50
!
   90 if (y .gt. amx) then
         amx = y
         if (dsp-amx .le. tol) then
            dsp = 0.0
            go to 9000
         end if
      end if
!
  100 istk = istk - 1
      if (istk .eq. 0) then
         dsp = dsp - amx
         if (dsp-amx .le. tol) dsp = 0.0
         go to 9000
      end if
      l = lstk(istk) + 1
!
  110 if (l .gt. mstk(istk)) go to 100
      n   = nstk(istk)
      nro = nrstk(istk)
      nco = ncstk(istk)
      y   = ystk(istk)
      if (n .eq. 1) then
         if (irstk(l,istk) .lt. irstk(l-1,istk)) go to 60
      else if (n .eq. 2) then
         if (icstk(l,istk) .lt. icstk(l-1,istk)) go to 60
      end if
!
      l = l + 1
      go to 110
 9000 return
      end
      subroutine f5xact (pastp, tol, kval, key, ldkey, ipoin, stp,   &
                         ldstp, ifrq, npoin, nr, nl, ifreq, itop, ipsh)
!-----------------------------------------------------------------------
!  Name:       F5XACT
!
!  Purpose:    Put node on stack in network algorithm.
!
!  Usage:      CALL F5XACT (PASTP, TOL, KVAL, KEY, LDKEY, IPOIN, STP,
!                          LDSTP, IFRQ, NPOIN, NR, NL, IFREQ, ITOP,
!                          IPSH)
!
!  Arguments:
!     PASTP  - The past path length.  (Input)
!     TOL    - Tolerance for equivalence of past path lengths.  (Input)
!     KVAL   - Key value.  (Input)
!     KEY    - Vector of length LDKEY containing the key values.
!              (Input/output)
!     LDKEY  - Length of vector KEY.  (Input)
!     IPOIN  - Vector of length LDKEY pointing to the linked list
!              of past path lengths.  (Input/output)
!     STP    - Vector of length LSDTP containing the linked lists
!              of past path lengths.  (Input/output)
!     LDSTP  - Length of vector STP.  (Input)
!     IFRQ   - Vector of length LDSTP containing the past path
!              frequencies.  (Input/output)
!     NPOIN  - Vector of length LDSTP containing the pointers to
!              the next past path length.  (Input/output)
!     NR     - Vector of length LDSTP containing the right object
!              pointers in the tree of past path lengths.
!              (Input/output)
!     NL     - Vector of length LDSTP containing the left object
!              pointers in the tree of past path lengths.
!              (Input/output)
!     IFREQ  - Frequency of the current path length.  (Input)
!     ITOP   - Pointer to the top of STP.  (Input)
!     IPSH   - Option parameter.  (Input)
!              If IPSH is true, the past path length is found in the
!              table KEY.  Otherwise the location of the past path
!              length is assumed known and to have been found in
!              a previous call.
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    kval, ldkey, ldstp, ifreq, itop, key(*), ipoin(*),   &
                 ifrq(*), npoin(*), nr(*), nl(*)
      double precision pastp, tol, stp(*)
      logical    ipsh
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    ipn, irdzz, itmp
      double precision test1, test2
!                                  SPECIFICATIONS FOR SAVE VARIABLES
      integer    itp
      save       itp
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  mod
!cccc integer    mod
!                                  SPECIFICATIONS FOR SUBROUTINES
!cccc external   prterr
!
      INCLUDE 'DPCOP2.INC'
!
      if (ipsh) then
!                                  Convert KVAL to integer in range
!                                  1, ..., LDKEY.
         irdzz = mod(kval,ldkey) + 1
!                                  Search for an unused location
         do 10  itp=irdzz, ldkey
            if (key(itp) .eq. kval) go to 40
            if (key(itp) .lt. 0) go to 30
   10    continue
!
         do 20  itp=1, irdzz - 1
            if (key(itp) .eq. kval) go to 40
            if (key(itp) .lt. 0) go to 30
   20    continue
!                                  Return if KEY array is full
!CCCC    call prterr(6, 'LDKEY is too small for this problem.  It is '//
!CCCC&               'not possible to estimate the value of LDKEY '//
!CCCC&               'required, but twice the current value may be '//
!CCCC&               'sufficient.')
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** ERROR IN FISHER EXACT TEST.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)
 9013 FORMAT('      LDKEY is too small for this proble,.  It is not')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)
 9015 FORMAT('      possible to estimate the value of LDKEY required,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)
 9017 FORMAT('      possible to estimate the value of LDKEY required,')
      CALL DPWRST('XXX','BUG ')
!                                  Update KEY
   30    key(itp) = kval
         itop       = itop + 1
         ipoin(itp) = itop
!                                  Return if STP array full
         if (itop .gt. ldstp) then
!CCCC       call prterr(7, 'LDSTP is too small for this problem.  It '//
!CCCC&                  'is not possible to estimate the value of '//
!CCCC&                  'LDSTP required, but twice the current value '//
!CCCC&                  'may be sufficient.')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9113)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9115)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9117)
            CALL DPWRST('XXX','BUG ')
         end if
 9111 FORMAT('***** ERROR IN FISHER EXACT TEST.')
 9113 FORMAT('      LDSTP is too small for this problem.  It is not')
 9115 FORMAT('      possible to estimate the value of LDSTP required,')
 9117 FORMAT('      but twice the current value may be sufficient.')
!                                  Update STP, etc.
         npoin(itop) = -1
         nr(itop)    = -1
         nl(itop)    = -1
         stp(itop)   = pastp
         ifrq(itop)  = ifreq
         go to 9000
      end if
!                                  Find location, if any, of pastp
   40 ipn = ipoin(itp)
      test1 = pastp - tol
      test2 = pastp + tol
!
   50 if (stp(ipn) .lt. test1) then
         ipn = nl(ipn)
         if (ipn .gt. 0) go to 50
      else if (stp(ipn) .gt. test2) then
         ipn = nr(ipn)
         if (ipn .gt. 0) go to 50
      else
         ifrq(ipn) = ifrq(ipn) + ifreq
         go to 9000
      end if
!                                  Return if STP array full
      itop = itop + 1
      if (itop .gt. ldstp) then
!cccc    call prterr(7, 'LDSTP is too small for this problem.  It is '//
!cccc&               'not possible to estimate the value of LDSTP '//
!cccc&               'rerquired, but twice the current value may be '//
!cccc&               'sufficient.')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9113)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9115)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9117)
            CALL DPWRST('XXX','BUG ')
         go to 9000
      end if
!                                  Find location to add value
      ipn  = ipoin(itp)
      itmp = ipn
   60 if (stp(ipn) .lt. test1) then
         itmp = ipn
         ipn  = nl(ipn)
         if (ipn .gt. 0) then
            go to 60
         else
            nl(itmp) = itop
         end if
      else if (stp(ipn) .gt. test2) then
         itmp = ipn
         ipn  = nr(ipn)
         if (ipn .gt. 0) then
            go to 60
         else
            nr(itmp) = itop
         end if
      end if
!                                  Update STP, etc.
      npoin(itop) = npoin(itmp)
      npoin(itmp) = itop
      stp(itop)   = pastp
      ifrq(itop)  = ifreq
      nl(itop)    = -1
      nr(itop)    = -1
!
 9000 return
      end
      subroutine f6xact (nrow, irow, iflag, kyy, key, ldkey, last, ipn)
!-----------------------------------------------------------------------
!  Name:       F6XACT
!
!  Purpose:    Pop a node off the stack.
!
!  Usage:      CALL F6XACT (NROW, IROW, IFLAG, KYY, KEY, LDKEY, LAST,
!                          IPN)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     IROW   - Vector of length nrow containing the row sums on output.
!              (Output)
!     IFLAG  - Set to 3 if there are no additional nodes to process.
!              (Output)
!     KYY    - Constant mutlipliers used in forming the hash table key.
!              (Input)
!     KEY    - Vector of length LDKEY containing the hash table keys.
!              (Input/output)
!     LDKEY  - Length of vector KEY.  (Input)
!     LAST   - Index of the last key popped off the stack.
!              (Input/output)
!     IPN    - Pointer to the linked list of past path lengths.
!              (Output)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, iflag, ldkey, last, ipn, irow(*), kyy(*), key(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    j, kval
!                                  SPECIFICATIONS FOR SAVE VARIABLES
!
   10 last = last + 1
      if (last .le. ldkey) then
         if (key(last) .lt. 0) go to 10
!                                  Get KVAL from the stack
         kval      = key(last)
         key(last) = -9999
         do 20  j=nrow, 2, -1
            irow(j) = kval/kyy(j)
            kval    = kval - irow(j)*kyy(j)
   20    continue
         irow(1) = kval
         ipn     = last
      else
         last  = 0
         iflag = 3
      end if
      return
      end
      subroutine f7xact (nrow, imax, idif, k, ks, iflag)
!-----------------------------------------------------------------------
!  Name:       F7XACT
!
!  Purpose:    Generate the new nodes for given marinal totals.
!
!  Usage:      CALL F7XACT (NROW, IMAX, IDIF, K, KS, IFLAG)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     IMAX   - The row marginal totals.  (Input)
!     IDIF   - The column counts for the new column.  (Input/output)
!     K      - Indicator for the row to decrement.  (Input/output)
!     KS     - Indicator for the row to increment.  (Input/output)
!     IFLAG  - Status indicator.  (Output)
!              If IFLAG is zero, a new table was generated.  For
!              IFLAG = 1, no additional tables could be generated.
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, k, ks, iflag, imax(*), idif(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, k1, m, mm
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  min0
!cccc integer    min0
!
      iflag = 0
!                                  Find node which can be
!                                  incremented, ks
      if (ks .eq. 0) then
   10    ks = ks + 1
         if (idif(ks) .eq. imax(ks)) go to 10
      end if
!                                 Find node to decrement (>ks)
      if (idif(k).gt.0 .and. k.gt.ks) then
         idif(k) = idif(k) - 1
   30    k = k - 1
         if (imax(k) .eq. 0) go to 30
         m = k
!                                 Find node to increment (>=ks)
   40    if (idif(m) .ge. imax(m)) then
            m = m - 1
            go to 40
         end if
         idif(m) = idif(m) + 1
!                                 Change ks
         if (m .eq. ks) then
            if (idif(m) .eq. imax(m)) ks = k
         end if
      else
!                                 Check for finish
   50    do 60  k1=k + 1, nrow
            if (idif(k1) .gt. 0) go to 70
   60    continue
         iflag = 1
         go to 9000
!                                 Reallocate counts
   70    mm = 1
         do 80  i=1, k
            mm      = mm + idif(i)
            idif(i) = 0
   80    continue
         k = k1
   90    k = k - 1
         m       = min0(mm,imax(k))
         idif(k) = m
         mm      = mm - m
         if (mm.gt.0 .and. k.ne.1) go to 90
!                                 Check that all counts
!                                 reallocated
         if (mm .gt. 0) then
            if (k1 .ne. nrow) then
               k = k1
               go to 50
            end if
            iflag = 1
            go to 9000
         end if
!                                 Get ks
         idif(k1) = idif(k1) - 1
         ks       = 0
  100    ks = ks + 1
         if (ks .gt. k) go to 9000
         if (idif(ks) .ge. imax(ks)) go to 100
      end if
!
 9000 return
      end
      subroutine f8xact (irow, is, i1, izero, new)
!-----------------------------------------------------------------------
!  Name:       F8XACT
!
!  Purpose:    Routine for reducing a vector when there is a zero
!              element.
!
!  Usage:      CALL F8XACT (IROW, IS, I1, IZERO, NEW)
!
!  Arguments:
!     IROW   - Vector containing the row counts.  (Input)
!     IS     - Indicator.  (Input)
!     I1     - Indicator.  (Input)
!     IZERO  - Position of the zero.  (Input)
!     NEW    - Vector of new row counts.  (Output)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    is, i1, izero, irow(*), new(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i
!
      do 10  i=1, i1 - 1
         new(i) = irow(i)
   10 continue
!
      do 20  i=i1, izero - 1
         if (is .ge. irow(i+1)) go to 30
         new(i) = irow(i+1)
   20 continue
!
      i = izero
   30 new(i) = is
   40 i = i + 1
      if (i .gt. izero) return
      new(i) = irow(i)
      go to 40
      end
      double precision function f9xact (n, mm, ir, fact)
!-----------------------------------------------------------------------
!  Name:       F9XACT
!
!  Purpose:    Computes the log of a multinomial coefficient.
!
!  Usage:      F9XACT(N, MM, IR, FACT)
!
!  Arguments:
!     N      - Length of IR.  (Input)
!     MM     - Number for factorial in numerator.  (Input)
!     IR     - Vector of length N containing the numebers for the
!              denominator of the factorial.  (Input)
!     FACT   - Table of log factorials.  (Input)
!     F9XACT  - The log of the multinomal coefficient.  (Output)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    n, mm, ir(*)
      double precision fact(0:*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    k
!
      f9xact = fact(mm)
      do 10  k=1, n
         f9xact = f9xact - fact(ir(k))
   10 continue
!
      return
      end
      subroutine f10act (nrow, irow, ncol, icol, val, xmin, fact, nd,   &
                         ne, m)
!----------------------------------------------------------------------
!  Name:       F10ACT
!
!  Purpose:    Computes the shortest path length for special tables.
!
!  Usage:      CALL F10ACT(NROW, IROW, NCOL, ICOL, VAL, XMIN, FACT, ND,
!                          NE, M)
!
!  Arguments:
!     NROW   - The number of rows in the table.  (Input)
!     IROW   - Vector of length NROW containing the row totals. (Input)
!     NCOL   - The number of columns in the table.  (Input)
!     ICO    - Vector of length NCOL containing the column totals.
!              (Input)
!     VAL    - The shortest path.  (Output)
!     XMIN   - Set to true if shortest path obtained.  (Output)
!     FACT   - Vector containing the logarithms of factorials.
!              (Input)
!     ND     - Workspace vector of length NROW.
!     NE     - Workspace vector of length NCOL.
!     M      - Workspace vector of length NCOL.
!
!  Chapter:    STAT/LIBRARY Categorical and Discrete Data Analysis
!----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    nrow, ncol, irow(*), icol(*), nd(*), ne(*), m(*)
      double precision val, fact(0:*)
      logical    xmin
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, is, ix, nrw1
!
      do 10  i=1, nrow - 1
         nd(i) = 0
   10 continue
!
      is    = icol(1)/nrow
      ne(1) = is
      ix    = icol(1) - nrow*is
      m(1)  = ix
      if (ix .ne. 0) nd(ix) = nd(ix) + 1
!
      do 20  i=2, ncol
         ix    = icol(i)/nrow
         ne(i) = ix
         is    = is + ix
         ix    = icol(i) - nrow*ix
         m(i)  = ix
         if (ix .ne. 0) nd(ix) = nd(ix) + 1
   20 continue
!
      do 30  i=nrow - 2, 1, -1
         nd(i) = nd(i) + nd(i+1)
   30 continue
!
      ix   = 0
      nrw1 = nrow + 1
      do 40  i=nrow, 2, -1
         ix = ix + is + nd(nrw1-i) - irow(i)
         if (ix .lt. 0) return
   40 continue
!
      do 50  i=1, ncol
         ix  = ne(i)
         is  = m(i)
         val = val + is*fact(ix+1) + (nrow-is)*fact(ix)
   50 continue
      xmin = .true.
!
      return
      end
      subroutine f11act (irow, i1, i2, new)
!---------------------------------------------------------------------
!  Name:       F11ACT
!
!  Purpose:    Routine for revising row totals.
!
!  Usage:      CALL F11ACT (IROW, I1, I2, NEW)
!
!  Arguments:
!     IROW   - Vector containing the row totals.  (Input)
!     I1     - Indicator.  (Input)
!     I2     - Indicator.  (Input)
!     NEW    - Vector containing the row totals.  (Input)
!----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    i1, i2, irow(*), new(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i
!
      do 10  i=1, i1 - 1
         new(i) = irow(i)
   10 continue
!
      do 20  i=i1, i2
         new(i) = irow(i+1)
   20 continue
!
      return
      end
      double precision function ff (x)
!
!     NOTE: This subroutine used in computing the consensus mean
!           using the Iyer and Wang generalized tolerance interval
!           approach.
!
!           Modified for Dataplot 3/2006.
!
!           Modified for Dataplot 4/2021.
!
!           1) Allow maximum of 1,000 labs
!
      implicit none
!
      double precision  x
!
      integer kk
!cccc double precision aa, ybar, cc, bb(100), yy(100)
      double precision aa, ybar, cc, bb(1000), yy(1000)
      common /cmn1/ kk
      common /cmn2/ aa, ybar, cc, bb, yy
!
      integer i
      double precision s1, s2, s3, s4, s5, tmp
!
      if (x .le. 0.0d0) then
          ff = aa - cc
          return
      end if
!
      s1 = 0.0d0
      s2 = 0.0d0
      s3 = 0.0d0
      s4 = 0.0d0
      s5 = 0.0d0
!
      do 10 i = 1, kk
         tmp = x + bb(i)
         s1 = s1 + yy(i)**2/tmp
         s2 = s2 + yy(i)/tmp
         s3 = s3 + 1.0d0/tmp
         s4 = s4 + yy(i)*bb(i)/tmp
         s5 = s5 + bb(i)/tmp
   10 continue
!
      ff = s1 - 2.0d0*ybar*s2 + ybar**2 * s3 - (s4 - ybar*s5)**2/   &
           (x * (kk - s5)) - cc
!
      return
      end
      SUBROUTINE FACCUR(H0,H1,FACC,X0,F,TWOINF,F0,F1)
      REAL H0,H1,FACC,A0,A1,F00,F2,DELTAF,T0,T1,X0,F,DF(5),F0,F1   &
              ,TWOINF
      INTEGER J
      EXTERNAL F
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      T0 = 0.
      T1 = 0.
      IF(H0.NE.0.) THEN
          IF(X0+H0.NE.0.) THEN
              F00 = F1
          ELSE
              H0 = 0.875*H0
              F00 = F(X0+H0)
          ENDIF
          IF(ABS(H1) .GE. 32.*TWOINF) H1 = H1/8.
          IF(16.*ABS(H1) .GT. ABS(H0)) H1 = SIGN(H1,1.)*ABS(H0)/16.
          IF(F(X0+H0-H1) .EQ. F00) THEN
              IF(256.*ABS(H1) .LE. ABS(H0)) THEN
                  H1 = 2.*H1
   10             IF(F(X0+H0-H1).NE.F00 .OR. 256.*ABS(H1).GT.ABS(H0))   &
                          GO TO  20
                  H1 = 2.*H1
                  GO TO  10
   20             H1 = 8.*H1
                                                                                                                                  
              ELSE
                  H1 = SIGN(H1,1.)*ABS(H0)/16.
              ENDIF
          ELSE
              IF(256.*TWOINF .LE. ABS(H0)) THEN
   30             IF(F(X0+H0-H1/2.).EQ.F00 .OR. ABS(H1).LT.4.*TWOINF)   &
                      GO TO  40
                  H1 = H1/2.
                  GO TO  30
   40             CONTINUE
                  H1 = 8.*H1
                  IF(16.*ABS(H1) .GT. ABS(H0)) H1 = SIGN(H1,1.)   &
                           *ABS(H0)/16.
              ELSE
                  H1 = SIGN(H1,1.)*ABS(H0)/16.
              ENDIF
          ENDIF
      ELSE
          F00 = F0
      ENDIF
                                                                                                                                  
      DO 50 J = 1,5
          F2 = F(X0+H0-FLOAT(2*J-1)*H1)
          DF(J) = F2 - F00
          T0 = T0+DF(J)
          T1 = T1+FLOAT(2*J-1)*DF(J)
   50 CONTINUE
      A0 = (33.*T0-5.*T1)/73.
      A1 = (-5.*T0+1.2*T1)/73.
      FACC = ABS(A0)
      DO 70 J = 1,5
          DELTAF = ABS(DF(J)-(A0+FLOAT(2*J-1)*A1))
          IF(FACC.LT.DELTAF) FACC = DELTAF
   70 CONTINUE
      FACC = 2.*FACC
      RETURN
      END SUBROUTINE FACCUR
      subroutine fastg(xreal, ximag, n, itype)
!
!       Algorithm AS 83.2 Appl. Statist. (1975) vol.24, no.1
!
!       Radix 4 complex discrete fast Fourier transform without
!       unscrambling, suitable for convolutions or other applications
!       which do not require unscrambling.   Called by subroutine
!       FASTF which also does the unscrambling.
!
        implicit double precision (A-H, O-Z)
      double precision  xreal(n), ximag(n)
      data    zero, half, one, one5, two, four   &
                /0.0D0,  0.5D0, 1.0D0,  1.5D0, 2.0D0,  4.0D0/
!
      sw2=0.0d0
      sw3=0.0d0
      cw3=0.0d0
      cw2=0.0d0
!
      pi = four * atan(one)
      ifaca = n / 4
      if (itype .eq. 0) return
      if (itype .gt. 0) go to 5
!
!       ITYPE < 0 indicates inverse transform required.
!       Calculate conjugate.
!
      do 4 k = 1, n
        ximag(k) = -ximag(k)
    4 continue
!
!       Following code is executed for IFACA = N/4, N/16, N/64, ...
!       until IFACA <= 1.
!
    5   ifcab = ifaca * 4
      z = pi / ifcab
      bcos = -two * sin(z)**2
      bsin = sin(two * z)
      cw1 = one
      sw1 = zero
      do 10 litla = 1, ifaca
        do 8 i0 = litla, n, ifcab
          i1 = i0 + ifaca
          i2 = i1 + ifaca
          i3 = i2 + ifaca
          xs0 = xreal(i0) + xreal(i2)
          xs1 = xreal(i0) - xreal(i2)
          ys0 = ximag(i0) + ximag(i2)
          ys1 = ximag(i0) - ximag(i2)
          xs2 = xreal(i1) + xreal(i3)
          xs3 = xreal(i1) - xreal(i3)
          ys2 = ximag(i1) + ximag(i3)
          ys3 = ximag(i1) - ximag(i3)
          xreal(i0) = xs0 + xs2
          ximag(i0) = ys0 + ys2
          x1 = xs1 + ys3
          y1 = ys1 - xs3
          x2 = xs0 - xs2
          y2 = ys0 - ys2
          x3 = xs1 - ys3
          y3 = ys1 + xs3
          if (litla .eq. 1) then
            xreal(i2) = x1
            ximag(i2) = y1
            xreal(i1) = x2
            ximag(i1) = y2
            xreal(i3) = x3
            ximag(i3) = y3
          else
            xreal(i2) = x1 * cw1 + y1 * sw1
            ximag(i2) = y1 * cw1 - x1 * sw1
            xreal(i1) = x2 * cw2 + y2 * sw2
            ximag(i1) = y2 * cw2 - x2 * sw2
            xreal(i3) = x3 * cw3 + y3 * sw3
            ximag(i3) = y3 * cw3 - x3 * sw3
          end if
    8     continue
!
!       Calculate a new set of twiddle factors.
!
        if (litla .lt. ifaca) then
          z = cw1 * bcos - sw1 * bsin + cw1
          sw1 = bcos * sw1 + bsin * cw1 + sw1
          tempr = one5 - half * (z * z + sw1 * sw1)
          cw1 = z * tempr
          sw1 = sw1 * tempr
          cw2 = cw1 * cw1 - sw1 * sw1
          sw2 = two * cw1 * sw1
          cw3 = cw1 * cw2 - sw1 * sw2
          sw3 = cw1 * sw2 + cw2 * sw1
        end if
   10   continue
      if (ifaca .le. 1) go to 14
!
!       Set up the transform split for the next stage.
!
      ifaca = ifaca / 4
      if (ifaca .gt. 0) go to 5
!
!       Radix 2 calculation, if needed.
!
      if (ifaca .lt. 0) return
      do 13 k = 1, n, 2
        tempr = xreal(k) + xreal(k+1)
        xreal(k+1) = xreal(k) - xreal(k+1)
        xreal(k) = tempr
        tempr = ximag(k) + ximag(k+1)
        ximag(k+1) = ximag(k) - ximag(k+1)
        ximag(k) = tempr
   13   continue
   14   if (itype .lt. 0) then
!
!       Inverse transform; conjugate the result.
!
        do 16 k = 1, n
          ximag(k) = -ximag(k)
   16   continue
        return
      end if
!
!       Forward transform
!
      z = one / n
      do 18 k = 1, n
        xreal(k) = xreal(k) * z
        ximag(k) = ximag(k) * z
   18   continue
!
      return
      end
      SUBROUTINE FORRT(X, M)
!
!     ALGORITHM AS 97  APPL. STATIST. (1976) VOL.25, NO. 2
!
!     Forward discrete Fourier transform in one dimension of real
!     data using complex transform subroutine FASTG.
!
!     X = array of real input data, type real, dimension M.
!     M = length of the transform, must be a power of 2.
!     The minimum length is 8, maximum 2**21.
!
!     The result is placed in X as described in the text of the paper.
!
!     Auxiliary routines required: SCRAG (or SCRAM) & FASTG from AS 83,
!     but with SCRAG modified as described on page 168 of the paper for
!     this algorithm.
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DOUBLE PRECISION X(M)
      DATA ZERO/0.0D0/, QUART/0.25D0/, HALF/0.5D0/, ONE/1.0D0/,   &
        ONE5/1.5D0/, TWO/2.0D0/, FOUR/4.0D0/
!
!     Check for valid transform size.
!
      II = 8
      DO 2 K = 3, 21
      IPOW = K
      IF (II .EQ. M) GO TO 3
      II = II * 2
    2 CONTINUE
!
!     If this point is reached, an illegal size was specified.
!
      RETURN
    3 PIE = FOUR * ATAN(ONE)
!
!     Separate odd and even parts into two halves.
!     First bit reverse the whole array of length M.
!
      CALL SCRAG(X, M, IPOW)
!
!     Next bit reverse the half arrays separately.
!
      N = M / 2
      JPOW = IPOW - 1
      CALL SCRAG(X, N, JPOW)
      CALL SCRAG(X(N+1), N, JPOW)
!
!     Faster alternative to the two lines above to SCRAM.
!           CALL SCRAM(X, X(N+1), N, JPOW)
!
!     Now do the transform.
!
      CALL FASTG(X, X(N+1), N, 1)
!
!     Unscramble the transform results.
!
      CALL SCRAG(X, N, JPOW)
      CALL SCRAG(X(N+1), N, JPOW)
!
!     Faster alternative to the two lines above to SCRAM.
!           CALL SCRAM(X, X(N+1), N, JPOW)
!
      NN = N / 2
!
!     Now unravel the result; first the special cases.
!
      Z = HALF * (X(1) + X(N+1))
      X(N+1) = HALF * (X(1) - X(N+1))
      X(1) = Z
      NN1 = NN + 1
      NN2 = NN1 + N
      X(NN1) = HALF * X(NN1)
      X(NN2) = -HALF * X(NN2)
      Z = PIE / N
      BCOS = -TWO * (SIN(Z / TWO) **2)
      BSIN = SIN(Z)
      UN = ONE
      VN = ZERO
      DO 4 K = 2, NN
      Z = UN * BCOS + VN * BSIN + UN
      VN = VN * BCOS - UN * BSIN + VN
      SAVE1 = ONE5 - HALF * (Z * Z + VN * VN)
      UN = Z * SAVE1
      VN = VN * SAVE1
      KI = N + K
      L = N + 2 - K
      LI = N + L
      AN = QUART * (X(K) + X(L))
      BN = QUART * (X(KI) - X(LI))
      CN = QUART * (X(KI) + X(LI))
      DN = QUART * (X(L) - X(K))
      XN = UN * CN - VN * DN
      YN = UN * DN + VN * CN
      X(K) = AN + XN
      X(KI) = BN + YN
      X(L) = AN - XN
      X(LI) = YN - BN
    4 CONTINUE
      RETURN
      END SUBROUTINE FORRT
      DOUBLE PRECISION FUNCTION FULSUM(S, CENTER, HWIDTH, X, G, F)
!
!***  To compute fully symmetric basic rule sum
!
      EXTERNAL F
      INTEGER S, IXCHNG, LXCHNG, I, L
      DOUBLE PRECISION CENTER(S), HWIDTH(S), X(S), G(S), F
      DOUBLE PRECISION INTSUM, GL, GI
      FULSUM = 0
      LXCHNG = 0
!
!     Compute centrally symmetric sum for permutation of G
!
 10   INTSUM = 0
      DO 100 I = 1,S
         X(I) = CENTER(I) + G(I)*HWIDTH(I)
 100  CONTINUE
 20   INTSUM = INTSUM + F(S,X)
      DO 200 I = 1,S
         G(I) = -G(I)
         X(I) = CENTER(I) + G(I)*HWIDTH(I)
         IF ( G(I) .LT. 0 ) GO TO 20
 200  CONTINUE
      FULSUM = FULSUM + INTSUM
!
!     Find next distinct permuation of G and loop back for next sum
!
      DO 300 I = 2,S
         IF ( G(I-1) .GT. G(I) ) THEN
            GI = G(I)
            IXCHNG = I - 1
            DO 400 L = 1,(I-1)/2
               GL = G(L)
               G(L) = G(I-L)
               G(I-L) = GL
               IF (  GL  .LE. GI ) IXCHNG = IXCHNG - 1
               IF ( G(L) .GT. GI ) LXCHNG = L
  400       CONTINUE
            IF ( G(IXCHNG) .LE. GI ) IXCHNG = LXCHNG
            G(I) = G(IXCHNG)
            G(IXCHNG) = GI
            GO TO 10
         ENDIF
  300 CONTINUE
!
!     End loop for permutations of G and associated sums
!
!     Restore original order to G's
!
      DO 500 I = 1,S/2
         GI = G(I)
         G(I) = G(S+1-I)
         G(S+1-I) = GI
 500  CONTINUE
!
      RETURN
      END FUNCTION FULSUM
      SUBROUTINE FZERO(F,B,C,R,RE,AE,IFLAG)
!
!   ADDED TO DATAPLOT 12/2003.  USE THIS ROUTINE FOR INTERNAL
!   COMPUTATIONS (THE ROOTS COMMAND IMPLEMENTS FOR USER DEFINED
!   FUNCTIONS).  THIS ROUTINE CAN BE MORE EFFICIENT FOR INTERNAL
!   USE SINCE WE CAN AVOID OVERHEAD OF FUNCTION PARSING, ETC.
!
!***BEGIN PROLOGUE  FZERO
!***DATE WRITTEN   700901   (YYMMDD)
!***REVISION DATE  860411   (YYMMDD)
!***CATEGORY NO.  F1B
!***KEYWORDS  BISECTION,NONLINEAR,ROOTS,ZEROS
!***AUTHOR  SHAMPINE,L.F.,SNLA
!           WATTS,H.A.,SNLA
!***PURPOSE  FZERO searches for a zero of a function F(X) in a given
!            interval (B,C).  It is designed primarily for problems
!            where F(B) and F(C) have opposite signs.
!***DESCRIPTION
!
!    From the book "Numerical Methods and Software"
!       by  D. Kahaner, C. Moler, S. Nash
!           Prentice Hall 1988
!
!     Based on a method by T J Dekker
!     written by L F Shampine and H A Watts
!
!            FZERO searches for a zero of a function F(X) between
!            the given values B and C until the width of the interval
!            (B,C) has collapsed to within a tolerance specified by
!            the stopping criterion, ABS(B-C) .LE. 2.*(RW*ABS(B)+AE).
!            The method used is an efficient combination of bisection
!            and the secant rule.
!
!     Description Of Arguments
!
!     F,B,C,R,RE and AE are input parameters
!     B,C and IFLAG are output parameters (flagged by an * below)
!
!        F     - Name of the real valued external function.  This name
!                must be in an EXTERNAL statement in the calling
!                program.  F must be a function of one real argument.
!
!       *B     - One end of the interval (B,C).  The value returned for
!                B usually is the better approximation to a zero of F.
!
!       *C     - The other end of the interval (B,C)
!
!        R     - A (better) guess of a zero of F which could help in
!                speeding up convergence.  If F(B) and F(R) have
!                opposite signs, a root will be found in the interval
!                (B,R); if not, but F(R) and F(C) have opposite
!                signs, a root will be found in the interval (R,C);
!                otherwise, the interval (B,C) will be searched for a
!                possible root.  When no better guess is known, it is
!                recommended that r be set to B or C; because if R is
!                not interior to the interval (B,C), it will be ignored.
!
!        RE    - Relative error used for RW in the stopping criterion.
!                If the requested RE is less than machine precision,
!                then RW is set to approximately machine precision.
!
!        AE    - Absolute error used in the stopping criterion.  If the
!                given interval (B,C) contains the origin, then a
!                nonzero value should be chosen for AE.
!
!       *IFLAG - A status code.  User must check IFLAG after each call.
!                Control returns to the user from FZERO in all cases.
!
!                1  B is within the requested tolerance of a zero.
!                   The interval (B,C) collapsed to the requested
!                   tolerance, the function changes sign in (B,C), and
!                   F(X) decreased in magnitude as (B,C) collapsed.
!
!                2  F(B) = 0.  However, the interval (B,C) may not have
!                   collapsed to the requested tolerance.
!
!                3  B may be near a singular point of F(X).
!                   The interval (B,C) collapsed to the requested tol-
!                   erance and the function changes sign in (B,C), but
!                   F(X) increased in magnitude as (B,C) collapsed,i.e.
!                     abs(F(B out)) .GT. max(abs(F(B in)),abs(F(C in)))
!
!                4  No change in sign of F(X) was found although the
!                   interval (B,C) collapsed to the requested tolerance.
!                   The user must examine this case and decide whether
!                   B is near a local minimum of F(X), or B is near a
!                   zero of even multiplicity, or neither of these.
!
!                5  Too many (.GT. 500) function evaluations used.
!***REFERENCES  L. F. SHAMPINE AND H. A. WATTS, *FZERO, A ROOT-SOLVING
!                 CODE*, SC-TM-70-631, SEPTEMBER 1970.
!               T. J. DEKKER, *FINDING A ZERO BY MEANS OF SUCCESSIVE
!                 LINEAR INTERPOLATION*, 'CONSTRUCTIVE ASPECTS OF THE
!                 FUNDAMENTAL THEOREM OF ALGEBRA', EDITED BY B. DEJON
!                 P. HENRICI, 1969.
!***ROUTINES CALLED  R1MACH
!***END PROLOGUE  FZERO
      REAL A,ACBS,ACMB,AE,AW,B,C,CMB,ER,FA,FB,FC,FX,FZ,P,Q,R
      REAL RE,RW,T,TOL,Z
      INTEGER IC,IFLAG,KOUNT
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!     ER IS TWO TIMES THE COMPUTER UNIT ROUNDOFF VALUE WHICH IS
!     DEFINED HERE BY THE FUNCTION R1MACH.
!
!***FIRST EXECUTABLE STATEMENT  FZERO
      ER = 2.0E0 * R1MACH(4)
!
!     INITIALIZE
!
      Z=R
      IF(R.LE.AMIN1(B,C).OR.R.GE.AMAX1(B,C)) Z=C
      RW=AMAX1(RE,ER)
      AW=AMAX1(AE,0.0)
      IC=0
      T=Z
      FZ=F(T)
      FC=FZ
      T=B
      FB=F(T)
      KOUNT=2
      IF(SIGN(1.0E0,FZ).EQ.SIGN(1.0E0,FB)) GO TO 1
      C=Z
      GO TO 2
    1 IF(Z.EQ.C) GO TO 2
      T=C
      FC=F(T)
      KOUNT=3
      IF(SIGN(1.0E0,FZ).EQ.SIGN(1.0E0,FC)) GO TO 2
      B=Z
      FB=FZ
    2 A=C
      FA=FC
      ACBS=ABS(B-C)
      FX=AMAX1(ABS(FB),ABS(FC))
!
    3 IF (ABS(FC) .GE. ABS(FB)) GO TO 4
!     PERFORM INTERCHANGE
      A=B
      FA=FB
      B=C
      FB=FC
      C=A
      FC=FA
!
    4 CMB=0.5*(C-B)
      ACMB=ABS(CMB)
      TOL=RW*ABS(B)+AW
!
!     TEST STOPPING CRITERION AND FUNCTION COUNT
!
      IF (ACMB .LE. TOL) GO TO 10
      IF(FB.EQ.0.E0) GO TO 11
      IF(KOUNT.GE.500) GO TO 14
!
!     CALCULATE NEW ITERATE IMPLICITLY AS B+P/Q
!     WHERE WE ARRANGE P .GE. 0.
!     THE IMPLICIT FORM IS USED TO PREVENT OVERFLOW.
!
      P=(B-A)*FB
      Q=FA-FB
      IF (P .GE. 0.) GO TO 5
      P=-P
      Q=-Q
!
!     UPDATE A AND CHECK FOR SATISFACTORY REDUCTION
!     IN THE SIZE OF THE BRACKETING INTERVAL.
!     IF NOT, PERFORM BISECTION.
!
    5 A=B
      FA=FB
      IC=IC+1
      IF (IC .LT. 4) GO TO 6
      IF (8.*ACMB .GE. ACBS) GO TO 8
      IC=0
      ACBS=ACMB
!
!     TEST FOR TOO SMALL A CHANGE
!
    6 IF (P .GT. ABS(Q)*TOL) GO TO 7
!
!     INCREMENT BY TOLERANCE
!
      B=B+SIGN(TOL,CMB)
      GO TO 9
!
!     ROOT OUGHT TO BE BETWEEN B AND (C+B)/2.
!
    7 IF (P .GE. CMB*Q) GO TO 8
!
!     USE SECANT RULE
!
      B=B+P/Q
      GO TO 9
!
!     USE BISECTION
!
    8 B=0.5*(C+B)
!
!     HAVE COMPLETED COMPUTATION FOR NEW ITERATE B
!
    9 T=B
      FB=F(T)
      KOUNT=KOUNT+1
!
!     DECIDE WHETHER NEXT STEP IS INTERPOLATION OR EXTRAPOLATION
!
      IF (SIGN(1.0,FB) .NE. SIGN(1.0,FC)) GO TO 3
      C=A
      FC=FA
      GO TO 3
!
!
!     FINISHED. PROCESS RESULTS FOR PROPER SETTING OF IFLAG
!
   10 IF (SIGN(1.0,FB) .EQ. SIGN(1.0,FC)) GO TO 13
      IF (ABS(FB) .GT. FX) GO TO 12
      IFLAG = 1
      RETURN
   11 IFLAG = 2
      RETURN
   12 IFLAG = 3
      RETURN
   13 IFLAG = 4
      RETURN
   14 IFLAG = 5
      RETURN
      END SUBROUTINE FZERO
      SUBROUTINE FZEROY(F,B,C,R,RE,AE,IFLAG,XTEMP,YTEMP)
!
!   ADDED TO DATAPLOT 12/2003.  USE THIS ROUTINE FOR INTERNAL
!   COMPUTATIONS (THE ROOTS COMMAND IMPLEMENTS FOR USER DEFINED
!   FUNCTIONS).  THIS ROUTINE CAN BE MORE EFFICIENT FOR INTERNAL
!   USE SINCE WE CAN AVOID OVERHEAD OF FUNCTION PARSING, ETC.
!
!   COPY OF FZERO.  ADDS XTEMP AND YTEMP TO FUNCTION CALL
!   (NEEDED BY DPMLYU AND DPMLWA).
!
!***BEGIN PROLOGUE  FZERO
!***DATE WRITTEN   700901   (YYMMDD)
!***REVISION DATE  860411   (YYMMDD)
!***CATEGORY NO.  F1B
!***KEYWORDS  BISECTION,NONLINEAR,ROOTS,ZEROS
!***AUTHOR  SHAMPINE,L.F.,SNLA
!           WATTS,H.A.,SNLA
!***PURPOSE  FZERO searches for a zero of a function F(X) in a given
!            interval (B,C).  It is designed primarily for problems
!            where F(B) and F(C) have opposite signs.
!***DESCRIPTION
!
!    From the book "Numerical Methods and Software"
!       by  D. Kahaner, C. Moler, S. Nash
!           Prentice Hall 1988
!
!     Based on a method by T J Dekker
!     written by L F Shampine and H A Watts
!
!            FZERO searches for a zero of a function F(X) between
!            the given values B and C until the width of the interval
!            (B,C) has collapsed to within a tolerance specified by
!            the stopping criterion, ABS(B-C) .LE. 2.*(RW*ABS(B)+AE).
!            The method used is an efficient combination of bisection
!            and the secant rule.
!
!     Description Of Arguments
!
!     F,B,C,R,RE and AE are input parameters
!     B,C and IFLAG are output parameters (flagged by an * below)
!
!        F     - Name of the real valued external function.  This name
!                must be in an EXTERNAL statement in the calling
!                program.  F must be a function of one real argument.
!
!       *B     - One end of the interval (B,C).  The value returned for
!                B usually is the better approximation to a zero of F.
!
!       *C     - The other end of the interval (B,C)
!
!        R     - A (better) guess of a zero of F which could help in
!                speeding up convergence.  If F(B) and F(R) have
!                opposite signs, a root will be found in the interval
!                (B,R); if not, but F(R) and F(C) have opposite
!                signs, a root will be found in the interval (R,C);
!                otherwise, the interval (B,C) will be searched for a
!                possible root.  When no better guess is known, it is
!                recommended that r be set to B or C; because if R is
!                not interior to the interval (B,C), it will be ignored.
!
!        RE    - Relative error used for RW in the stopping criterion.
!                If the requested RE is less than machine precision,
!                then RW is set to approximately machine precision.
!
!        AE    - Absolute error used in the stopping criterion.  If the
!                given interval (B,C) contains the origin, then a
!                nonzero value should be chosen for AE.
!
!       *IFLAG - A status code.  User must check IFLAG after each call.
!                Control returns to the user from FZERO in all cases.
!
!                1  B is within the requested tolerance of a zero.
!                   The interval (B,C) collapsed to the requested
!                   tolerance, the function changes sign in (B,C), and
!                   F(X) decreased in magnitude as (B,C) collapsed.
!
!                2  F(B) = 0.  However, the interval (B,C) may not have
!                   collapsed to the requested tolerance.
!
!                3  B may be near a singular point of F(X).
!                   The interval (B,C) collapsed to the requested tol-
!                   erance and the function changes sign in (B,C), but
!                   F(X) increased in magnitude as (B,C) collapsed,i.e.
!                     abs(F(B out)) .GT. max(abs(F(B in)),abs(F(C in)))
!
!                4  No change in sign of F(X) was found although the
!                   interval (B,C) collapsed to the requested tolerance.
!                   The user must examine this case and decide whether
!                   B is near a local minimum of F(X), or B is near a
!                   zero of even multiplicity, or neither of these.
!
!                5  Too many (.GT. 500) function evaluations used.
!***REFERENCES  L. F. SHAMPINE AND H. A. WATTS, *FZERO, A ROOT-SOLVING
!                 CODE*, SC-TM-70-631, SEPTEMBER 1970.
!               T. J. DEKKER, *FINDING A ZERO BY MEANS OF SUCCESSIVE
!                 LINEAR INTERPOLATION*, 'CONSTRUCTIVE ASPECTS OF THE
!                 FUNDAMENTAL THEOREM OF ALGEBRA', EDITED BY B. DEJON
!                 P. HENRICI, 1969.
!***ROUTINES CALLED  R1MACH
!***END PROLOGUE  FZERO
      REAL A,ACBS,ACMB,AE,AW,B,C,CMB,ER,FA,FB,FC,FX,FZ,P,Q,R
      REAL RE,RW,T,TOL,Z
      INTEGER IC,IFLAG,KOUNT
!
      REAL YTEMP(*)
      REAL XTEMP(*)
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!     ER IS TWO TIMES THE COMPUTER UNIT ROUNDOFF VALUE WHICH IS
!     DEFINED HERE BY THE FUNCTION R1MACH.
!
!***FIRST EXECUTABLE STATEMENT  FZERO
      ER = 2.0E0 * R1MACH(4)
!
!     INITIALIZE
!
      Z=R
      IF(R.LE.AMIN1(B,C).OR.R.GE.AMAX1(B,C)) Z=C
      RW=AMAX1(RE,ER)
      AW=AMAX1(AE,0.0)
      IC=0
      T=Z
      FZ=F(T,XTEMP,YTEMP)
      FC=FZ
      T=B
      FB=F(T,XTEMP,YTEMP)
      KOUNT=2
      IF(SIGN(1.0E0,FZ).EQ.SIGN(1.0E0,FB)) GO TO 1
      C=Z
      GO TO 2
    1 IF(Z.EQ.C) GO TO 2
      T=C
      FC=F(T,XTEMP,YTEMP)
      KOUNT=3
      IF(SIGN(1.0E0,FZ).EQ.SIGN(1.0E0,FC)) GO TO 2
      B=Z
      FB=FZ
    2 A=C
      FA=FC
      ACBS=ABS(B-C)
      FX=AMAX1(ABS(FB),ABS(FC))
!
    3 IF (ABS(FC) .GE. ABS(FB)) GO TO 4
!     PERFORM INTERCHANGE
      A=B
      FA=FB
      B=C
      FB=FC
      C=A
      FC=FA
!
    4 CMB=0.5*(C-B)
      ACMB=ABS(CMB)
      TOL=RW*ABS(B)+AW
!
!     TEST STOPPING CRITERION AND FUNCTION COUNT
!
      IF (ACMB .LE. TOL) GO TO 10
      IF(FB.EQ.0.E0) GO TO 11
      IF(KOUNT.GE.500) GO TO 14
!
!     CALCULATE NEW ITERATE IMPLICITLY AS B+P/Q
!     WHERE WE ARRANGE P .GE. 0.
!     THE IMPLICIT FORM IS USED TO PREVENT OVERFLOW.
!
      P=(B-A)*FB
      Q=FA-FB
      IF (P .GE. 0.) GO TO 5
      P=-P
      Q=-Q
!
!     UPDATE A AND CHECK FOR SATISFACTORY REDUCTION
!     IN THE SIZE OF THE BRACKETING INTERVAL.
!     IF NOT, PERFORM BISECTION.
!
    5 A=B
      FA=FB
      IC=IC+1
      IF (IC .LT. 4) GO TO 6
      IF (8.*ACMB .GE. ACBS) GO TO 8
      IC=0
      ACBS=ACMB
!
!     TEST FOR TOO SMALL A CHANGE
!
    6 IF (P .GT. ABS(Q)*TOL) GO TO 7
!
!     INCREMENT BY TOLERANCE
!
      B=B+SIGN(TOL,CMB)
      GO TO 9
!
!     ROOT OUGHT TO BE BETWEEN B AND (C+B)/2.
!
    7 IF (P .GE. CMB*Q) GO TO 8
!
!     USE SECANT RULE
!
      B=B+P/Q
      GO TO 9
!
!     USE BISECTION
!
    8 B=0.5*(C+B)
!
!     HAVE COMPLETED COMPUTATION FOR NEW ITERATE B
!
    9 T=B
      FB=F(T,XTEMP,YTEMP)
      KOUNT=KOUNT+1
!
!     DECIDE WHETHER NEXT STEP IS INTERPOLATION OR EXTRAPOLATION
!
      IF (SIGN(1.0,FB) .NE. SIGN(1.0,FC)) GO TO 3
      C=A
      FC=FA
      GO TO 3
!
!
!     FINISHED. PROCESS RESULTS FOR PROPER SETTING OF IFLAG
!
   10 IF (SIGN(1.0,FB) .EQ. SIGN(1.0,FC)) GO TO 13
      IF (ABS(FB) .GT. FX) GO TO 12
      IFLAG = 1
      RETURN
   11 IFLAG = 2
      RETURN
   12 IFLAG = 3
      RETURN
   13 IFLAG = 4
      RETURN
   14 IFLAG = 5
      RETURN
      END SUBROUTINE FZEROY
